    /// <summary>
    /// This enumeration contains flags that control how syntax (i.e.
    /// command and subcommand help) data is gathered, formatted, and
    /// returned.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("c327be88-2e49-4252-a46a-497c131ec451")]
    public enum SyntaxDataFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Gather syntax data recursively, descending into nested
        /// subcommands and ensembles.
        /// </summary>
        Recursive = 0x10,
        /// <summary>
        /// Treat an empty result set as an error rather than returning
        /// nothing.
        /// </summary>
        ErrorOnEmpty = 0x20,
        /// <summary>
        /// Stop gathering syntax data as soon as any error is encountered.
        /// </summary>
        StopOnError = 0x40,
        /// <summary>
        /// Include only unique syntax entries, discarding any duplicates.
        /// </summary>
        Unique = 0x80,
        /// <summary>
        /// Return the gathered values formatted as a proper list.
        /// </summary>
        ListValues = 0x100,
        /// <summary>
        /// Remove empty entries from the gathered syntax data.
        /// </summary>
        RemoveEmpty = 0x200,
        /// <summary>
        /// Exclude metadata from the gathered syntax data.
        /// </summary>
        NoMetadata = 0x400,
        /// <summary>
        /// Wrap each value so that it is suitable for inclusion in a list.
        /// </summary>
        WrapValues = 0x800,
        /// <summary>
        /// Escape special characters within each value.
        /// </summary>
        EscapeValues = 0x1000,

        /// <summary>
        /// Combination mask of <see cref="WrapValues" /> and
        /// <see cref="EscapeValues" />.
        /// </summary>
        WrapMask = WrapValues | EscapeValues,
        /// <summary>
        /// Combination mask of <see cref="Recursive" /> and
        /// <see cref="StopOnError" /> used when loading and caching data.
        /// </summary>
        LoadAndCacheDataFrom = Recursive | StopOnError,
        /// <summary>
        /// Combination mask of <see cref="RemoveEmpty" /> and
        /// <see cref="NoMetadata" /> used when loading data.
        /// </summary>
        LoadData = RemoveEmpty | NoMetadata
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines diagnostic message priority levels modeled
    /// after the POSIX syslog(3) priority constants.  They are used to
    /// classify debug and trace messages by severity and to indicate their
    /// origin.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("ab970a48-f5eb-49d6-973b-d5e35e210a99")]
    public enum DebugPriority /* syslog(priority) */ : int /* COMPAT: POSIX */
    {
        /// <summary>
        /// No priority is specified.
        /// </summary>
        None = 0,
        /// <summary>
        /// A base offset added to each POSIX-derived priority value so
        /// that zero can be reserved to mean unspecified.
        /// </summary>
        Offset = 1,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && UNIX
        /// <summary>
        /// The system is unusable; the most severe priority level.
        /// </summary>
        Emergency = UNM.LOG_EMERG + Offset,
        /// <summary>
        /// Action must be taken immediately.
        /// </summary>
        Alert = UNM.LOG_ALERT + Offset,
        /// <summary>
        /// A critical condition has occurred.
        /// </summary>
        Critical = UNM.LOG_CRIT + Offset,
        /// <summary>
        /// An error condition has occurred.
        /// </summary>
        Error = UNM.LOG_ERR + Offset,
        /// <summary>
        /// A warning condition has occurred.
        /// </summary>
        Warning = UNM.LOG_WARNING + Offset,
        /// <summary>
        /// A normal but significant condition has occurred.
        /// </summary>
        Notice = UNM.LOG_NOTICE + Offset,
        /// <summary>
        /// An informational message.
        /// </summary>
        Information = UNM.LOG_INFO + Offset,
        /// <summary>
        /// A debug-level message.
        /// </summary>
        Debug = UNM.LOG_DEBUG + Offset,
#else
        //
        // TODO: Make sure to keep these values compatible
        //       with those from the POSIX standard(s).
        //
        /// <summary>
        /// The system is unusable; the most severe priority level.
        /// </summary>
        Emergency = 0 + Offset,
        /// <summary>
        /// Action must be taken immediately.
        /// </summary>
        Alert = 1 + Offset,
        /// <summary>
        /// A critical condition has occurred.
        /// </summary>
        Critical = 2 + Offset,
        /// <summary>
        /// An error condition has occurred.
        /// </summary>
        Error = 3 + Offset,
        /// <summary>
        /// A warning condition has occurred.
        /// </summary>
        Warning = 4 + Offset,
        /// <summary>
        /// A normal but significant condition has occurred.
        /// </summary>
        Notice = 5 + Offset,
        /// <summary>
        /// An informational message.
        /// </summary>
        Information = 6 + Offset,
        /// <summary>
        /// A debug-level message.
        /// </summary>
        Debug = 7 + Offset,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The message originated from fail-safe handling.
        /// </summary>
        FromFailSafe = 0x1000,
        /// <summary>
        /// The message originated from TclTk itself.
        /// </summary>
        FromSelf = 0x2000,
        /// <summary>
        /// The message originated from a traced exception.
        /// </summary>
        FromTraceException = 0x4000,
        /// <summary>
        /// The message originated from a trace message.
        /// </summary>
        FromTraceMessage = 0x8000,
        /// <summary>
        /// The message originated from the test suite.
        /// </summary>
        FromTest = 0x10000,
        /// <summary>
        /// The message originated from external (non-core) code.
        /// </summary>
        FromExternal = 0x20000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not emit this message via the normal output channel.
        /// </summary>
        NoViaOutput = 0x100000,
        /// <summary>
        /// Do not emit this message via the tracing subsystem.
        /// </summary>
        NoViaTrace = 0x200000,
        /// <summary>
        /// Do not emit this message via the interpreter host.
        /// </summary>
        NoViaHost = 0x400000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the base priority levels
        /// <see cref="Emergency" />, <see cref="Alert" />,
        /// <see cref="Critical" />, <see cref="Error" />,
        /// <see cref="Warning" />, <see cref="Notice" />,
        /// <see cref="Information" />, and <see cref="Debug" />.
        /// </summary>
        BaseMask = Emergency | Alert | Critical | Error |
                   Warning | Notice | Information | Debug,

        /// <summary>
        /// Combination mask of the message-origin flags
        /// <see cref="FromFailSafe" />, <see cref="FromSelf" />,
        /// <see cref="FromTraceException" />,
        /// <see cref="FromTraceMessage" />, <see cref="FromTest" />, and
        /// <see cref="FromExternal" />.
        /// </summary>
        FromMask = FromFailSafe | FromSelf | FromTraceException |
                   FromTraceMessage | FromTest | FromExternal,

        /// <summary>
        /// Combination mask of the output-suppression flags
        /// <see cref="NoViaOutput" />, <see cref="NoViaTrace" />, and
        /// <see cref="NoViaHost" />.
        /// </summary>
        NoViaMask = NoViaOutput | NoViaTrace | NoViaHost,

        /// <summary>
        /// Combination mask of <see cref="FromMask" /> and
        /// <see cref="NoViaMask" />.
        /// </summary>
        NonBaseMask = FromMask | NoViaMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The minimum base priority value, corresponding to
        /// <see cref="Emergency" />.
        /// </summary>
        Minimum = Emergency,
        /// <summary>
        /// The maximum base priority value, corresponding to
        /// <see cref="Debug" />.
        /// </summary>
        Maximum = Debug,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default debug priority used when none is otherwise
        /// specified.
        /// </summary>
        Default = Maximum // COMPAT: TclTk beta.
    }

