#if DATA
    /// <summary>
    /// This enumeration contains flags that control how a bundle of
    /// scripts (and its associated key ring) is loaded and evaluated.  The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("7415026d-5fa5-4561-88b4-088129d9a800")]
    public enum BundleFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Fail if the bundle contains no scripts.
        /// </summary>
        ErrorOnEmpty = 0x100,   /* Fail if there are no scripts in
                                 * the bundle. */
        /// <summary>
        /// Stop immediately if any bundled script raises a script error.
        /// </summary>
        StopOnError = 0x200,    /* Stop immediately if any of the
                                 * bundled scripts raise any script
                                 * error. */
        /// <summary>
        /// Fail if the bundle key ring file (i.e.
        /// <c>keyRing.one.tcltk</c>) cannot be found.
        /// </summary>
        RequireKeyRing = 0x400, /* Fail if the "bundle" key ring
                                 * file (i.e. "keyRing.one.tcltk")
                                 * cannot be found. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x1000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of bundle flags, corresponding to
        /// <see cref="ForDefault" />.
        /// </summary>
        Default = ForDefault
    }
#endif

