#if NETWORK
    /// <summary>
    /// This enumeration contains flags that control how IP address and
    /// port information is resolved, filtered, and returned.  The values
    /// are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("355c6bf7-5f50-4f48-bc37-e070c7362f75")]
    public enum IpFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Include or require IPv4 addresses.
        /// </summary>
        IPv4 = 0x1000,
        /// <summary>
        /// Include or require IPv6 addresses.
        /// </summary>
        IPv6 = 0x2000,

        /// <summary>
        /// Treat an empty result set as an error.
        /// </summary>
        ErrorOnEmpty = 0x10000,
        /// <summary>
        /// Stop processing as soon as an error is encountered.
        /// </summary>
        StopOnError = 0x20000,
        /// <summary>
        /// Retain (rather than discard) per-address errors encountered
        /// during resolution.
        /// </summary>
        KeepErrors = 0x40000,

        /// <summary>
        /// Allow any IP address, including wildcard addresses.
        /// </summary>
        AllowAnyIp = 0x100000,
        /// <summary>
        /// Allow any port number, including the wildcard port.
        /// </summary>
        AllowAnyPort = 0x200000,

        /// <summary>
        /// Do not sort the resulting addresses.
        /// </summary>
        NoSort = 0x400000,

#if NET_40
        /// <summary>
        /// On supported runtimes, optionally include IPv6 addresses;
        /// equivalent to <see cref="IPv6" />.
        /// </summary>
        MaybeIPv6 = IPv6,
#else
        /// <summary>
        /// On runtimes without suitable IPv6 support, this resolves to no
        /// flags.
        /// </summary>
        MaybeIPv6 = None,
#endif

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x80000000,

        /// <summary>
        /// Combination mask of <see cref="IPv4" />,
        /// <see cref="MaybeIPv6" />, <see cref="KeepErrors" />, and
        /// <see cref="ForDefault" /> forming the default flags.
        /// </summary>
        Default = IPv4 | MaybeIPv6 | KeepErrors | ForDefault
    }
#endif

