    /// <summary>
    /// This enumeration defines the security levels that an interpreter or
    /// operation may run under.  The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("7afe0a6e-0eec-4999-bde4-4f72afe537de")]
    public enum SecurityLevel
    {
        /// <summary>
        /// No special security level is requested.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// The safe security level, which restricts access to potentially
        /// dangerous functionality.
        /// </summary>
        Safe = 0x1,
        /// <summary>
        /// The SDK security level.
        /// </summary>
        Sdk = 0x2,

        /// <summary>
        /// The base mask of security levels, currently consisting of
        /// <see cref="Safe" />.
        /// </summary>
        BaseMask = Safe
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration contains flags that govern the security
    /// characteristics of an IScript instance, including read-only and
    /// immutability constraints as well as how certificate data is
    /// imported from a script.  The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("86eaf199-af64-47d9-a546-e9331fa8f2d8")]
    public enum ScriptSecurityFlags
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,      /* No special handling. */
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,   /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The associated <c>IScript</c> instance is logically read-only
        /// and must not be modified; property set accessors should fail
        /// and property get accessors may return deep copies of
        /// non-immutable data.
        /// </summary>
        ReadOnly = 0x2,  /* The associated IScript instance is logically
                          * read-only and must not be modified, e.g.
                          * property set accessors should fail with an
                          * exception.  When using property get accessors
                          * for any non-immutable data types, a deep copy
                          * may be returned.
                          */

        /// <summary>
        /// The associated <c>IScript</c> instance is logically immutable;
        /// this implies <see cref="ReadOnly" /> and additionally forbids
        /// property get accessors that could return non-immutable,
        /// non-copyable data.
        /// </summary>
        Immutable = 0x4, /* The associated IScript instance is logically
                          * immutable.  This implies that the IScript is
                          * read-only and further prohibits usage of
                          * property get accessors that may return any
                          * non-immutable and non-copyable data types,
                          * e.g. arbitrary IClientData.
                          */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// When importing certificate data from a script, ignore the
        /// vendor value from the bundle data.
        /// </summary>
        NoVendor = 0x1000,        /* When importing certificate data from an
                                   * IScript, ignore the Vendor value from the
                                   * IBundleData interface. */

        /// <summary>
        /// When importing certificate data from a script, ignore the hash
        /// algorithm name from the bundle data.
        /// </summary>
        NoHashAlgorithm = 0x2000, /* When importing certificate data from an
                                   * IScript, ignore the HashAlgorithmName
                                   * value from the IBundleData interface. */

        /// <summary>
        /// When importing certificate data from a script, skip setting the
        /// entity type on the certificate data.
        /// </summary>
        NoEntityType = 0x4000,    /* When importing certificate data from an
                                   * IScript, skip setting the EntityType on
                                   * the ICertificateData interface. */

        /// <summary>
        /// When importing certificate data from a script, ignore the name
        /// value from the script data.
        /// </summary>
        NoEntityName = 0x8000,    /* When importing certificate data from an
                                   * IScript, ignore the Name value from the
                                   * IScriptData interface. */

        /// <summary>
        /// When importing certificate data from a script, ignore the
        /// entity value from the script data.
        /// </summary>
        NoEntityValue = 0x10000,  /* When importing certificate data from an
                                   * IScript, ignore the EntityValue value
                                   * from the IScriptData interface. */

        /// <summary>
        /// When importing certificate data from a script, ignore the block
        /// type from the script data.
        /// </summary>
        NoBlockType = 0x20000,    /* When importing certificate data from an
                                   * IScript, ignore the BlockType value from
                                   * the IScriptData interface. */

        /// <summary>
        /// When verifying certificate data from a script, use the hashing
        /// semantics normally used for script files instead of those used
        /// for IScript instances.
        /// </summary>
        TreatAsFile = 0x40000,    /* When verifying certificate data from an
                                   * IScript, use hashing semantics that are
                                   * normally used for "script files" instead
                                   * of those used for IScript instances. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Immutable" />,
        /// <see cref="NoEntityValue" />, <see cref="NoBlockType" />, and
        /// <see cref="TreatAsFile" /> used when importing from a bundle.
        /// </summary>
        BundleMask = Immutable | NoEntityValue | NoBlockType | TreatAsFile,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ReadOnly" /> and
        /// <see cref="Immutable" />.
        /// </summary>
        AnyMask = ReadOnly | Immutable,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default flags, which apply no special handling.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if SHELL && INTERACTIVE_COMMANDS
    /// <summary>
    /// This enumeration contains flags that control how interactive text
    /// output is formatted, including whitespace handling, prefixing, and
    /// escape processing.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("f920d2b3-3757-415d-aa68-d1f6ed4e4e63")]
    public enum TextFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not collapse runs of whitespace into a single space.
        /// </summary>
        NoCollapse = 0x2,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Prefix the text with a newline.
        /// </summary>
        PrefixWithNewLine = 0x100,
        /// <summary>
        /// Prefix the text with a space.
        /// </summary>
        PrefixWithSpace = 0x200,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not preserve any whitespace characters.
        /// </summary>
        KeepNothing = 0x1000,
        /// <summary>
        /// Preserve whitespace characters other than ordinary spaces.
        /// </summary>
        KeepNonSpaces = 0x2000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Preserve horizontal tab characters.
        /// </summary>
        KeepHorizontalTabs = 0x10000,
        /// <summary>
        /// Preserve line feed characters.
        /// </summary>
        KeepLineFeeds = 0x20000,
        /// <summary>
        /// Preserve vertical tab characters.
        /// </summary>
        KeepVerticalTabs = 0x40000,
        /// <summary>
        /// Preserve form feed characters.
        /// </summary>
        KeepFormFeeds = 0x80000,
        /// <summary>
        /// Preserve carriage return characters.
        /// </summary>
        KeepCarriageReturns = 0x100000,
        /// <summary>
        /// Preserve ordinary space characters.
        /// </summary>
        KeepSpaces = 0x200000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow backslash escape sequences within the text.
        /// </summary>
        AllowEscapes = 0x10000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x80000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The legacy formatting behavior; equivalent to
        /// <see cref="KeepNothing" />.
        /// </summary>
        Legacy = KeepNothing,
        /// <summary>
        /// Combination mask of <see cref="PrefixWithNewLine" />,
        /// <see cref="PrefixWithSpace" />, and
        /// <see cref="KeepNonSpaces" /> forming the modern formatting
        /// behavior.
        /// </summary>
        Modern = PrefixWithNewLine | PrefixWithSpace | KeepNonSpaces,
        /// <summary>
        /// Combination mask of <see cref="PrefixWithNewLine" />,
        /// <see cref="PrefixWithSpace" />, and <see cref="NoCollapse" />
        /// forming the future formatting behavior.
        /// </summary>
        Future = PrefixWithNewLine | PrefixWithSpace | NoCollapse,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default formatting behavior, combining
        /// <see cref="Modern" /> with <see cref="ForDefault" />.
        /// </summary>
        Default = Modern | ForDefault /* COMPAT: TclTk beta. */
    }
#endif

