#if NETWORK
    /// <summary>
    /// This enumeration identifies the kind of execution context that a
    /// context identifier refers to, such as a process, application
    /// domain, thread, or interpreter.  The values are bit flags that may
    /// be combined.
    /// </summary>
    [Flags()]
    [ObjectId("b038c8a9-6031-4734-8b42-00e9e6754d29")]
    public enum ContextIdType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// The identifier refers to a global (machine-wide) context.
        /// </summary>
        Global = 0x100,

        /// <summary>
        /// The identifier refers to the parent process.
        /// </summary>
        ParentProcess = 0x1000,
        /// <summary>
        /// The identifier refers to the current process.
        /// </summary>
        Process = 0x2000,

        /// <summary>
        /// The identifier refers to an application domain.
        /// </summary>
        AppDomain = 0x4000,

        /// <summary>
        /// The identifier refers to a thread.
        /// </summary>
        Thread = 0x8000,
        /// <summary>
        /// The identifier refers to an interpreter.
        /// </summary>
        Interpreter = 0x10000,
        /// <summary>
        /// The identifier refers to an interpreter context.
        /// </summary>
        Context = 0x20000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The identifier may be unset (i.e. it is optional).
        /// </summary>
        MaybeUnset = 0x10000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the context-type flags
        /// <see cref="Global" />, <see cref="ParentProcess" />,
        /// <see cref="Process" />, <see cref="AppDomain" />,
        /// <see cref="Thread" />, <see cref="Interpreter" />, and
        /// <see cref="Context" />.
        /// </summary>
        TypeMask = Global | ParentProcess | Process |
                   AppDomain | Thread | Interpreter |
                   Context,

        /// <summary>
        /// Combination mask of the non-type flags, currently consisting of
        /// <see cref="MaybeUnset" />.
        /// </summary>
        FlagMask = MaybeUnset,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default context type, corresponding to
        /// <see cref="Interpreter" />.
        /// </summary>
        Default = Interpreter
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration contains flags that control how automation data
    /// (key/value pairs) is collected and validated.  The values are bit
    /// flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("a86740f6-a243-4a29-ac36-14e2d053db12")]
    public enum AutomationFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Require that all keys be unique.
        /// </summary>
        UniqueKeys = 0x1000,
        /// <summary>
        /// Allow a null value to be associated with a key.
        /// </summary>
        AllowNullValue = 0x2000,
        /// <summary>
        /// Silently ignore duplicate keys instead of failing.
        /// </summary>
        IgnoreDuplicateKey = 0x4000,
        /// <summary>
        /// Ignore errors encountered while processing a value.
        /// </summary>
        IgnoreValueError = 0x8000,

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x100000,

        /// <summary>
        /// Combination mask of <see cref="AllowNullValue" />,
        /// <see cref="IgnoreValueError" />, and <see cref="ForDefault" />
        /// forming the default flags.
        /// </summary>
        Default = AllowNullValue | IgnoreValueError | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL && TCL_THREADS
    /// <summary>
    /// This enumeration contains flags that control how a native Tcl
    /// interpreter is created.  The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("34c95711-5043-4a0c-860c-3c4866c4e296")]
    public enum TclCreateFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Fully initialize the newly created Tcl interpreter.
        /// </summary>
        Initialize = 0x1000,
        /// <summary>
        /// Enable the Tcl memory debugging subsystem for the interpreter.
        /// </summary>
        Memory = 0x2000,
        /// <summary>
        /// Create the Tcl interpreter as a safe interpreter.
        /// </summary>
        Safe = 0x4000
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration contains flags that control how native Tcl
    /// commands are created and deleted.  The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("d15bb599-be36-4b9c-bc58-9fe7a4e6e6a3")]
    public enum TclCommandFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Force deletion of the command even if it is otherwise in use.
        /// </summary>
        ForceDelete = 0x10000,
        /// <summary>
        /// Suppress errors that occur while deleting the command.
        /// </summary>
        NoComplain = 0x20000
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if TCL_THREADS
    /// <summary>
    /// This enumeration contains flags that control the creation,
    /// lifetime, and behavior of native Tcl interpreter threads.  The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("0c2e47bd-3e01-4a51-8392-c1441c40ec78")]
    public enum TclThreadFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A generic Tcl thread with no specialized role.
        /// </summary>
        Generic = 0x1000,
        /// <summary>
        /// Do not yield control while the thread is running.
        /// </summary>
        NoYield = 0x2000,
        /// <summary>
        /// Enable debugging behavior for the thread.
        /// </summary>
        Debug = 0x4000,
        /// <summary>
        /// Suppress errors raised by the thread.
        /// </summary>
        NoComplain = 0x8000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Start the thread immediately upon creation.
        /// </summary>
        Start = 0x10000,
        /// <summary>
        /// Wait for the thread to actually start running before returning.
        /// </summary>
        WaitForStart = 0x20000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The thread hosts a user interface and must pump messages.
        /// </summary>
        UserInterface = 0x100000,
        /// <summary>
        /// Mark the thread as a background thread.
        /// </summary>
        IsBackground = 0x200000,
        /// <summary>
        /// Use the active call stack for the thread.
        /// </summary>
        UseActiveStack = 0x400000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Delete the thread.
        /// </summary>
        Delete = 0x1000000,
        /// <summary>
        /// Treat operations on an already-dead thread as an error.
        /// </summary>
        ErrorOnDead = 0x2000000,
        /// <summary>
        /// Wait for the thread to finish before returning.
        /// </summary>
        WaitForEnd = 0x4000000,
        /// <summary>
        /// Do not forcibly abort the thread.
        /// </summary>
        NoAbort = 0x8000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Start" />,
        /// <see cref="WaitForStart" />, <see cref="UserInterface" />, and
        /// <see cref="UseActiveStack" /> used when creating a thread.
        /// </summary>
        CreateUse = Start | WaitForStart | UserInterface | UseActiveStack,
        /// <summary>
        /// Combination mask of <see cref="Delete" /> and
        /// <see cref="WaitForEnd" /> used when deleting a thread.
        /// </summary>
        DeleteUse = Delete | WaitForEnd,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default thread flags, which request no special behavior.
        /// </summary>
        Default = None
    }
#endif
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration contains flags that control how command and
    /// IExecute sets are swapped in and out of an interpreter.  The values
    /// are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("b8721a6f-56a5-4b2c-8e73-827d5f1685e2")]
    public enum SwapFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,          /* No special behavior. */
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,       /* Do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Swap out the normal set of commands.
        /// </summary>
        Command = 0x1000,        /* Swap out the normal set of commands. */
        /// <summary>
        /// Swap out the hidden set of commands.
        /// </summary>
        HiddenCommand = 0x2000,  /* Swap out the hidden set of commands. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Swap out the normal set of IExecute entries.
        /// </summary>
        IExecute = 0x4000,       /* Swap out the normal set of IExecute. */
        /// <summary>
        /// Swap out the hidden set of IExecute entries.
        /// </summary>
        HiddenIExecute = 0x8000, /* Swap out the hidden set of IExecute. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip adding the rescue command that can restore the previous
        /// command set.
        /// </summary>
        NoRestore = 0x100000,    /* EXTERNAL: Skip adding "rescue" command
                                  * that can restore the previous command
                                  * set. */
        /// <summary>
        /// Skip formally terminating the command within the
        /// RemoveSwapCommand method.
        /// </summary>
        NoTerminate = 0x200000,  /* Skip formally terminating the command
                                  * within the RemoveSwapCommand method. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x80000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Command" /> and
        /// <see cref="HiddenCommand" />.
        /// </summary>
        CommandMask = Command | HiddenCommand,
        /// <summary>
        /// Combination mask of <see cref="IExecute" /> and
        /// <see cref="HiddenIExecute" />.
        /// </summary>
        IExecuteMask = IExecute | HiddenIExecute,
        /// <summary>
        /// Combination mask of <see cref="CommandMask" /> and
        /// <see cref="IExecuteMask" />.
        /// </summary>
        AllMask = CommandMask | IExecuteMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default flags, combining <see cref="Command" /> with
        /// <see cref="ForDefault" />.
        /// </summary>
        Default = Command | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration contains flags that control how work items are
    /// queued to and started on pool threads.  The values are bit flags
    /// that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("0e5fe421-c6aa-4e48-9a0a-801a2b747d19")]
    public enum QueueFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,          /* No special behavior. */
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,       /* Do not use. */
        /// <summary>
        /// A reserved value that must not be used.
        /// </summary>
        Reserved1 = 0x2,     /* Do not use. */
        /// <summary>
        /// A reserved value that must not be used.
        /// </summary>
        Reserved2 = 0x4,     /* Do not use. */

        /// <summary>
        /// Queue the work item asynchronously; for test use only.
        /// </summary>
        Asynchronous = 0x10, /* For test use only. */
        /// <summary>
        /// Wait for the pool thread to actually start running before
        /// returning.
        /// </summary>
        WaitForStart = 0x20, /* Wait for the (pool) thread
                              * to actually start running.
                              */

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x10000000,

        /// <summary>
        /// Combination mask of <see cref="Reserved1" /> and
        /// <see cref="ForDefault" /> forming the default flags.
        /// </summary>
        Default = Reserved1 | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    //
    // WARNING: Do not use this enumeration.  It is
    //          really designed for internal library
    //          use only.
    //
    /// <summary>
    /// This enumeration classifies the broad category of a numeric value,
    /// such as integral, floating-point, or arbitrary-precision.  The
    /// values are bit flags that may be combined.  This enumeration is
    /// intended for internal library use only and should not be used by
    /// external callers.
    /// </summary>
    [Flags()]
    [ObjectId("e0f6093e-4476-47e7-a521-6f991e9c7266")]
    public enum NumberType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// An integral (whole-number) value.
        /// </summary>
        Integral = 0x2,
        /// <summary>
        /// A floating-point value.
        /// </summary>
        FloatingPoint = 0x4,
        /// <summary>
        /// A fixed-point value.
        /// </summary>
        FixedPoint = 0x8,
        /// <summary>
        /// An arbitrary-precision value.
        /// </summary>
        ArbitraryPrecision = 0x10
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration contains flags that control how the
    /// <c>[package ifneeded]</c> machinery locates, verifies, and loads
    /// packages.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("ab44fc6d-0f5b-4fb8-a3ae-7010ed28ff99")]
    public enum PackageIfNeededFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow the operation to proceed on any thread.
        /// </summary>
        AnyThread = 0x1000,
        /// <summary>
        /// Perform the operation while holding the interpreter lock.
        /// </summary>
        Locked = 0x2000,
        /// <summary>
        /// Perform a what-if (dry-run) pass without making any changes.
        /// </summary>
        WhatIf = 0x4000,
        /// <summary>
        /// Suppress diagnostic output.
        /// </summary>
        Silent = 0x8000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Search the configured package path.
        /// </summary>
        UseThePath = 0x10000000,
        /// <summary>
        /// Search the binary (executable) path.
        /// </summary>
        UseBinaryPath = 0x20000000,
        /// <summary>
        /// Search the parent of the binary path.
        /// </summary>
        UseParentPath = 0x40000000,
        /// <summary>
        /// Search the base path.
        /// </summary>
        UseBasePath = 0x80000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Use the built-in package name to file name mappings.
        /// </summary>
        UseBuiltInMappings = 0x100000000,
        /// <summary>
        /// Do not require packages to be trusted.
        /// </summary>
        NoTrusted = 0x200000000,
        /// <summary>
        /// Do not require packages to be verified.
        /// </summary>
        NoVerified = 0x400000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Ignore packages that have been disabled.
        /// </summary>
        IgnoreDisabled = 0x1000000000,
        /// <summary>
        /// Ignore the package file name when matching.
        /// </summary>
        IgnoreFileName = 0x2000000000,
        /// <summary>
        /// Search all subdirectories recursively.
        /// </summary>
        AllDirectories = 0x4000000000,
        /// <summary>
        /// Treat a package that cannot be found as an error.
        /// </summary>
        ErrorOnNotFound = 0x8000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Require that the package provide a managed assembly.
        /// </summary>
        MustHaveAssembly = 0x10000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Sentinel bit included in the default value so that it is never
        /// empty.
        /// </summary>
        ForDefault = 0x100000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if DEBUG
        /// <summary>
        /// In debug builds, do not require packages to be trusted;
        /// equivalent to <see cref="NoTrusted" />.
        /// </summary>
        MaybeNoTrusted = NoTrusted,
#else
        /// <summary>
        /// In non-debug builds, this resolves to no flags.
        /// </summary>
        MaybeNoTrusted = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the behavioral flags
        /// <see cref="AnyThread" />, <see cref="Locked" />,
        /// <see cref="WhatIf" />, <see cref="Silent" />,
        /// <see cref="UseBuiltInMappings" />, <see cref="NoTrusted" />,
        /// <see cref="NoVerified" />, <see cref="IgnoreDisabled" />,
        /// <see cref="IgnoreFileName" />, <see cref="AllDirectories" />,
        /// <see cref="ErrorOnNotFound" />, and
        /// <see cref="MustHaveAssembly" />.
        /// </summary>
        FlagsMask = AnyThread | Locked | WhatIf | Silent | UseBuiltInMappings |
                    NoTrusted | NoVerified | IgnoreDisabled | IgnoreFileName |
                    AllDirectories | ErrorOnNotFound | MustHaveAssembly,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="UseThePath" />,
        /// <see cref="UseBinaryPath" />, <see cref="UseParentPath" />, and
        /// <see cref="UseBasePath" />.
        /// </summary>
        UseAnyPath = UseThePath | UseBinaryPath | UseParentPath | UseBasePath,

        /// <summary>
        /// The default flags, combining <see cref="UseAnyPath" />,
        /// <see cref="MaybeNoTrusted" />, <see cref="MustHaveAssembly" />,
        /// <see cref="AllDirectories" />, and <see cref="ForDefault" />.
        /// </summary>
        Default = UseAnyPath | MaybeNoTrusted | MustHaveAssembly | AllDirectories | ForDefault,
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control the behavior of
    /// TclTk's log file handling.  Being a [Flags] enumeration, its values
    /// may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("05f805c5-7944-4d44-b392-9c18bd39cd33")]
    public enum LogFlags
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Permit the underlying log buffer to grow as needed to
        /// accommodate the data being written.
        /// </summary>
        ExpandBuffer = 0x100,
        /// <summary>
        /// Zero out the contents of the log buffer after it has been used.
        /// </summary>
        ZeroBuffer = 0x200,
        /// <summary>
        /// Keep the underlying log file (or stream) open between
        /// successive write operations instead of reopening it each time.
        /// </summary>
        KeepOpen = 0x400,

        /// <summary>
        /// Marker flag indicating membership in the default set of log
        /// flags.
        /// </summary>
        ForDefault = 0x1000,

        /// <summary>
        /// The default combination of log flags; a combination mask of
        /// <see cref="ExpandBuffer" /> and <see cref="ForDefault" />.
        /// </summary>
        Default = ExpandBuffer | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that influence how TclTk
    /// resolves commands, variables, and other named entities.  Being a
    /// [Flags] enumeration, its values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("4161bb64-1660-4686-a34b-09ad42401c00")]
    public enum ResolveFlags
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Do not consider custom attributes when performing resolution.
        /// </summary>
        NoAttributes = 0x100
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags describing the state, encoding,
    /// and cryptographic processing applied to a piece of secret data, as
    /// well as the protocol revision in use.  Being a [Flags] enumeration
    /// backed by an unsigned 64-bit integer, its values may be combined
    /// using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("6c847327-00db-4cc5-b035-d10cf5e0c810")]
    public enum SecretDataFlags : ulong
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Reserved for future use; callers should not rely on this value.
        /// </summary>
        Reserved1 = 0x2,

        /// <summary>
        /// The secret data is currently in encrypted form.
        /// </summary>
        Encrypted = 0x10,
        /// <summary>
        /// The secret data has already been processed.
        /// </summary>
        Processed = 0x20,
        /// <summary>
        /// The secret data carries a cryptographic signature.
        /// </summary>
        Signed = 0x40,

        /// <summary>
        /// Parse the input portion of the secret data.
        /// </summary>
        ParseInput = 0x100,
        /// <summary>
        /// Parse the auxiliary portion of the secret data.
        /// </summary>
        ParseAuxiliary = 0x200,
        /// <summary>
        /// Parse the output portion of the secret data.
        /// </summary>
        ParseOutput = 0x400,
        /// <summary>
        /// Parse the signature portion of the secret data.
        /// </summary>
        ParseSignature = 0x800,

        /// <summary>
        /// Overwrite the existing input portion of the secret data.
        /// </summary>
        OverwriteInput = 0x1000,
        /// <summary>
        /// Overwrite the existing auxiliary portion of the secret data.
        /// </summary>
        OverwriteAuxiliary = 0x2000,
        /// <summary>
        /// Overwrite the existing output portion of the secret data.
        /// </summary>
        OverwriteOutput = 0x4000,
        /// <summary>
        /// Overwrite the existing signature portion of the secret data.
        /// </summary>
        OverwriteSignature = 0x8000,

        /// <summary>
        /// The input portion of the secret data is encoded using Base64.
        /// </summary>
        InputBase64 = 0x10000,
        /// <summary>
        /// The auxiliary portion of the secret data is encoded using
        /// Base64.
        /// </summary>
        AuxiliaryBase64 = 0x20000,
        /// <summary>
        /// The output portion of the secret data is encoded using Base64.
        /// </summary>
        OutputBase64 = 0x40000,
        /// <summary>
        /// The signature portion of the secret data is encoded using
        /// Base64.
        /// </summary>
        SignatureBase64 = 0x80000,

        /// <summary>
        /// Perform no cryptographic operation on the secret data.
        /// </summary>
        Nop = 0x100000,
        /// <summary>
        /// Apply (or generate) a cryptographic salt for the secret data.
        /// </summary>
        Salt = 0x200000,
        /// <summary>
        /// Compute a cryptographic hash of the secret data.
        /// </summary>
        Hash = 0x400000,
        /// <summary>
        /// Derive a key from the secret data.
        /// </summary>
        Derive = 0x800000,
        /// <summary>
        /// Encrypt the secret data.
        /// </summary>
        Encrypt = 0x1000000,
        /// <summary>
        /// Decrypt the secret data.
        /// </summary>
        Decrypt = 0x2000000,
        /// <summary>
        /// Cryptographically sign the secret data.
        /// </summary>
        Sign = 0x4000000,
        /// <summary>
        /// Verify the cryptographic signature of the secret data.
        /// </summary>
        Verify = 0x8000000,

        /// <summary>
        /// Selects revision 0 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R0 = 0x100000000,
        /// <summary>
        /// Selects revision 1 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R1 = 0x200000000,
        /// <summary>
        /// Selects revision 2 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R2 = 0x400000000,
        /// <summary>
        /// Selects revision 3 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R3 = 0x800000000,
        /// <summary>
        /// Selects revision 4 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R4 = 0x1000000000,
        /// <summary>
        /// Selects revision 5 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R5 = 0x2000000000,
        /// <summary>
        /// Selects revision 6 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R6 = 0x4000000000,
        /// <summary>
        /// Selects revision 7 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R7 = 0x8000000000,
        /// <summary>
        /// Selects revision 8 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R8 = 0x10000000000,
        /// <summary>
        /// Selects revision 9 of version 1 of the secret data protocol.
        /// </summary>
        ProtocolV1R9 = 0x20000000000,

        /// <summary>
        /// Selects revision 0 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R0 = 0x40000000000,
        /// <summary>
        /// Selects revision 1 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R1 = 0x80000000000,
        /// <summary>
        /// Selects revision 2 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R2 = 0x100000000000,
        /// <summary>
        /// Selects revision 3 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R3 = 0x200000000000,
        /// <summary>
        /// Selects revision 4 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R4 = 0x400000000000,
        /// <summary>
        /// Selects revision 5 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R5 = 0x800000000000,
        /// <summary>
        /// Selects revision 6 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R6 = 0x1000000000000,
        /// <summary>
        /// Selects revision 7 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R7 = 0x2000000000000,
        /// <summary>
        /// Selects revision 8 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R8 = 0x4000000000000,
        /// <summary>
        /// Selects revision 9 of version 2 of the secret data protocol.
        /// </summary>
        ProtocolV2R9 = 0x8000000000000,

        /// <summary>
        /// Combination mask of all of the cryptographic operation flags:
        /// <see cref="Nop" />, <see cref="Salt" />, <see cref="Hash" />,
        /// <see cref="Derive" />, <see cref="Encrypt" />, <see
        /// cref="Decrypt" />, <see cref="Sign" />, and <see cref="Verify"
        /// />.
        /// </summary>
        OperationMask = Nop | Salt | Hash | Derive |
                        Encrypt | Decrypt | Sign | Verify,

        /// <summary>
        /// The default set of secret data flags; equal to <see cref="None"
        /// /> (no flags set).
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && WINDOWS
    /// <summary>
    /// This enumeration defines bit flags that control how a simulated
    /// keyboard key event is delivered (Windows native builds only).
    /// Being a [Flags] enumeration backed by an unsigned 64-bit integer,
    /// its values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("5c95f450-817f-4c76-ac58-37fec230f86e")]
    public enum SimulatedKeyFlags : ulong
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Deliver the simulated key directly, bypassing higher-level
        /// handling.
        /// </summary>
        Direct = 0x1000,
        /// <summary>
        /// Set input focus to the target before delivering the simulated
        /// key.
        /// </summary>
        SetFocus = 0x2000,
        /// <summary>
        /// Only perform the operation when it can be done in a safe
        /// manner.
        /// </summary>
        SafeOnly = 0x4000,
        /// <summary>
        /// Do not fall back to an alternate delivery method if the primary
        /// one fails.
        /// </summary>
        NoFallback = 0x8000,
        /// <summary>
        /// Do not reverse (undo) the simulated key state afterward.
        /// </summary>
        NoReverse = 0x10000,

        /// <summary>
        /// Only deliver the simulated key to a console window.
        /// </summary>
        ConsoleOnly = 0x100000,

        /// <summary>
        /// Marker flag indicating membership in the default set of flags.
        /// </summary>
        ForDefault = 0x10000000,

        /// <summary>
        /// The default combination of flags; a combination mask of <see
        /// cref="SetFocus" />, <see cref="SafeOnly" />, and <see
        /// cref="ForDefault" />.
        /// </summary>
        Default = SetFocus | SafeOnly | ForDefault,
    }
#endif

