    /// <summary>
    /// This enumeration defines bit flags that identify the kind and
    /// characteristics of a rule set, including its source format and
    /// sharing semantics.  Being a [Flags] enumeration, its values may be
    /// combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("d57e7013-59af-44c5-8ed7-4e6b9aced427")]
    public enum RuleSetType
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// The rule set is expressed as a nested list.
        /// </summary>
        NestedList = 0x1000,
        /// <summary>
        /// The rule set is loaded from a command file.
        /// </summary>
        CommandFile = 0x2000,
        /// <summary>
        /// The rule set is loaded from a definition file.
        /// </summary>
        DefinitionFile = 0x4000,

        /// <summary>
        /// Permit the rule set to be shared.
        /// </summary>
        AllowShared = 0x10000,
        /// <summary>
        /// Restrict processing to shared rule sets only.
        /// </summary>
        SharedOnly = 0x20000,

        /// <summary>
        /// Marker flag indicating membership in the default set of flags.
        /// </summary>
        ForDefault = 0x1000000,
        /// <summary>
        /// Marker flag indicating the rule set is intended for use with
        /// Kapok.
        /// </summary>
        ForKapok = 0x2000000,

        /// <summary>
        /// Combination mask of the base format flags <see
        /// cref="NestedList" />, <see cref="CommandFile" />, and <see
        /// cref="DefinitionFile" />.
        /// </summary>
        BaseMask = NestedList | CommandFile | DefinitionFile,
        /// <summary>
        /// Combination mask of the behavioral flags <see
        /// cref="AllowShared" />, <see cref="SharedOnly" />, <see
        /// cref="ForDefault" />, and <see cref="ForKapok" />.
        /// </summary>
        FlagsMask = AllowShared | SharedOnly | ForDefault | ForKapok,

        /// <summary>
        /// The default rule set type used by Kapok; a combination mask of
        /// <see cref="ForDefault" /> and <see cref="ForKapok" />.
        /// </summary>
        KapokDefault = ForDefault | ForKapok,

        /// <summary>
        /// The default rule set type; a combination mask of <see
        /// cref="NestedList" /> and <see cref="ForDefault" />.
        /// </summary>
        Default = NestedList | ForDefault
    }

