    /// <summary>
    /// This enumeration defines bit flags describing the outcome and state
    /// associated with creating an interpreter (or similar object) within
    /// the global state.  Being a [Flags] enumeration, its values may be
    /// combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("bae639d0-f35c-42f5-9bf4-d793461801d7")]
    public enum CreateStateFlags
    {
        /// <summary>
        /// No flags are set; no action is taken.
        /// </summary>
        None = 0x0,    /* Do nothing. */
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1, /* Do not use. */

        /// <summary>
        /// Indicates the object was successfully added to the global
        /// state.
        /// </summary>
        Added = 0x2000, /* Successfully added to global state. */
        /// <summary>
        /// Indicates the interpreter has a non-public token set.
        /// </summary>
        Token = 0x8000  /* Interpreter has a "non-public" token set. */
    }

