        MediumLow = 0x3,
        /// <summary>
        /// A medium level of trace formatting detail.
        /// </summary>
        Medium = 0x4,
        /// <summary>
        /// A medium-high level of trace formatting detail.
        /// </summary>
        MediumHigh = 0x5,
        /// <summary>
        /// The maximum level of trace formatting detail.
        /// </summary>
        Maximum = 0x6
    }

