#if THREADING
    /// <summary>
    /// This enumeration defines bit flags representing the timing and
    /// outcome of a status check, along with options controlling its
    /// reporting.  Being a [Flags] enumeration, its values may be combined
    /// using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("a045e89d-0884-4565-9cb7-856a7c5b35db")]
    public enum CheckStatus
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// The check is performed before the associated operation.
        /// </summary>
        Before = 0x10,
        /// <summary>
        /// The check is performed after the associated operation.
        /// </summary>
        After = 0x20,

        /// <summary>
        /// The result of the check is unknown.
        /// </summary>
        Unknown = 0x100,
        /// <summary>
        /// The check completed successfully.
        /// </summary>
        Success = 0x200,
        /// <summary>
        /// The check failed.
        /// </summary>
        Failure = 0x400,

        /// <summary>
        /// Suppress normal output produced by the check.
        /// </summary>
        Quiet = 0x1000,
        /// <summary>
        /// Do not produce a report for the check.
