    [ObjectId("438d2aba-7779-49ee-8924-e300d24aeb84")]
    public enum TraceListenerType
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default trace listener.
        /// </summary>
        Default = 0x1000,
        /// <summary>
        /// A trace listener that writes to the console.
        /// </summary>
        Console = 0x2000,
        /// <summary>
        /// A trace listener that writes via the native (operating system)
        /// debugging facility.
        /// </summary>
        Native = 0x4000,
        /// <summary>
        /// A trace listener that writes to a raw log file.
        /// </summary>
        RawLogFile = 0x8000,
        /// <summary>
        /// A trace listener that writes to the test log file.
        /// </summary>
        TestLogFile = 0x10000,
        /// <summary>
