#if TEST
    /// <summary>
    /// This enumeration defines bit flags identifying the SSL/TLS security
    /// protocol versions that may be selected for secure network
    /// communication.  Being a [Flags] enumeration, its values may be
    /// combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("3b746783-4aa8-4d04-a41c-1b51c7c7164e")]
    public enum SecurityProtocolType
    {
        /// <summary>
        /// No protocol is selected.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Use the system default security protocol selection.
        /// </summary>
        SystemDefault = 0x0000,
        /// <summary>
        /// The (obsolete) SSL 2.0 protocol.
        /// </summary>
        Ssl2 = 0x000C,
        /// <summary>
        /// The (obsolete) SSL 3.0 protocol.
        /// </summary>
        Ssl3 = 0x0030,
        /// <summary>
        /// The TLS protocol; an alias for <see cref="Tls10" />.
        /// </summary>
        Tls = Tls10,
        /// <summary>
        /// The TLS 1.0 protocol.
        /// </summary>
        Tls10 = 0x00C0,
        /// <summary>
        /// The TLS 1.1 protocol.
        /// </summary>
        Tls11 = 0x0300,
        /// <summary>
        /// The TLS 1.2 protocol.
        /// </summary>
        Tls12 = 0x0C00,
        /// <summary>
        /// The TLS 1.3 protocol.
        /// </summary>
        Tls13 = 0x3000,

        //
        // NOTE: These protocols are quite obsolete.
        //
        /// <summary>
        /// Combination mask of the obsolete protocols <see cref="Ssl2" />
        /// and <see cref="Ssl3" />.
        /// </summary>
        Obsolete = Ssl2 | Ssl3,

        //
        // NOTE: These protocols are considered to be
        //       "fail-safe", i.e. they generally work
        //       correctly most (or all?) of the time.
        //
        /// <summary>
        /// The protocol considered fail-safe (generally working correctly
        /// most of the time); equal to <see cref="Tls12" />.
        /// </summary>
        FailSafe = Tls12,

        //
        // HACK: Windows 11 (and probably Windows 10) is
        //       apparently broken for everything except
        //       TLS 1.2; specifically, TLS 1.3 fails on
        //       Windows 11 Enterprise 64-bit.
        //
        /// <summary>
        /// Combination mask of the protocols known to be broken on Windows
        /// 10 or higher: <see cref="Tls10" />, <see cref="Tls11" />, and
        /// <see cref="Tls13" />.
        /// </summary>
        BrokenOnWindows10OrHigher = Tls10 | Tls11 | Tls13
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how delegates are
    /// created from, and dispatched to, managed methods exposed as TclTk
    /// sub-commands.  Being a [Flags] enumeration, its values may be
    /// combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("1d87ea2d-45e0-40e6-a156-deb687245be1")]
    public enum DelegateFlags
    {
        /// <summary>
        /// No flags are set; no special action is taken.
        /// </summary>
        None = 0x0,                 /* Do nothing. */
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,              /* Do not use. */
        /// <summary>
        /// Directly execute the delegate with its parameters, completely
        /// bypassing the core marshaller (legacy behavior).
        /// </summary>
        UseEngine = 0x2,            /* LEGACY: Directly execute the delegate with
                                     * its parameters, while completely avoiding
                                     * core marshaller handling. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include public members when creating sub-commands.
        /// </summary>
        Public = 0x100,             /* Include public members when creating any
                                     * sub-commands. */
        /// <summary>
        /// Include non-public members when creating sub-commands.
        /// </summary>
        NonPublic = 0x200,          /* Include non-public members when creating
                                     * any sub-commands. */
        /// <summary>
        /// Include instance members when creating sub-commands.
        /// </summary>
        Instance = 0x400,           /* Include instance members when creating
                                     * any sub-commands. */
        /// <summary>
        /// Include static members when creating sub-commands.
        /// </summary>
        Static = 0x800,             /* Include static members when creating any
                                     * sub-commands. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not raise an error when a duplicate delegate name is
        /// encountered.
        /// </summary>
        AllowDuplicate = 0x1000,    /* Do not raise an error if any duplicate
                                     * delegate name is seen. */
        /// <summary>
        /// Replace an existing delegate when a duplicate name is
        /// encountered.
        /// </summary>
        OverwriteExisting = 0x2000, /* When a duplicate delegate name is seen,
                                     * replace it. */
        /// <summary>
        /// Fail if no matching methods are available.
        /// </summary>
        FailOnNone = 0x4000,        /* Fail if no methods are available. */
        /// <summary>
        /// Do not stop processing when an error is encountered.
        /// </summary>
        NoComplain = 0x8000,        /* Do not stop when an error is hit. */
        /// <summary>
        /// Enable verbose error reporting while searching for methods.
        /// </summary>
        Verbose = 0x10000,          /* Enable verbose error reporting when
                                     * attempting to find methods. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow the same options permitted by the <c>[library call]</c>
        /// sub-command to be used.
        /// </summary>
        UseCallOptions = 0x20000,   /* Allow the same options permitted by the
                                     * [library call] sub-command to be used. */
        /// <summary>
        /// When the returned value is an opaque object handle, permit it
        /// to use the same options as the <c>[object invoke]</c>
        /// sub-command.
        /// </summary>
        UseReturnOptions = 0x40000, /* If the returned value ends up being an
                                     * opaque object handle, permit it to use
                                     * the same options as the [object invoke]
                                     * sub-command. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Pre-process the sub-command arguments, translating opaque
        /// object handles into the actual delegate parameters.
        /// </summary>
        LookupObjects = 0x100000,   /* Pre-process the sub-command arguments
                                     * looking for (and translating) opaque
                                     * object handles to use as the delegate
                                     * parameters. */
        /// <summary>
        /// When the delegate result type is not directly supported by the
        /// Result class, post-process it into an opaque object handle.
        /// </summary>
        MakeIntoObject = 0x200000,  /* If the type of the delegate result is
                                     * not directly supported by the Result
                                     * class, post-process it to an opaque
                                     * object handle. */
        /// <summary>
        /// When the delegate result type is not directly supported by the
        /// Result class, forcibly wrap it anyway.
        /// </summary>
        WrapReturnType = 0x400000,  /* If the type of the delegate result is
                                     * not directly supported by the Result
                                     * class, forcibly wrap it anyhow. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the legacy option flags <see
        /// cref="UseCallOptions" /> and <see cref="UseReturnOptions" />.
        /// </summary>
        LegacyMask = UseCallOptions | UseReturnOptions,
        /// <summary>
        /// Combination mask of the commonly used flags <see
        /// cref="AllowDuplicate" /> and <see cref="Verbose" />.
        /// </summary>
        CommonMask = AllowDuplicate | Verbose,
        /// <summary>
        /// Combination mask for public instance members: <see
        /// cref="Public" />, <see cref="Instance" />, and <see
        /// cref="CommonMask" />.
        /// </summary>
        PublicInstanceMask = Public | Instance | CommonMask,
        /// <summary>
        /// Combination mask for public static members: <see cref="Public"
        /// />, <see cref="Static" />, and <see cref="CommonMask" />.
        /// </summary>
        PublicStaticMask = Public | Static | CommonMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The mask of flags applied automatically; equal to <see
        /// cref="None" />.
        /// </summary>
        AutomaticMask = None,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default delegate flags; equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if XML
    /// <summary>
    /// This enumeration defines bit flags identifying the categories of
    /// errors that may occur while processing XML, together with the
    /// interpreter contexts and error-handling behaviors that apply.
    /// Being a [Flags] enumeration, its values may be combined using a
    /// bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("13c70899-66d8-40f7-994a-fbbfa0a2d12c")]
    public enum XmlErrorTypes
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The error classification applies to an interpreter context.
        /// </summary>
        ForInterpreter = 0x2,
        /// <summary>
        /// The error classification applies to an unsafe interpreter.
        /// </summary>
        ForUnsafe = 0x4,
        /// <summary>
        /// The error classification applies to a safe interpreter.
        /// </summary>
        ForSafe = 0x8,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not treat the condition as an error.
        /// </summary>
        NoError = 0x10,
        /// <summary>
        /// Do not raise an exception for the condition.
        /// </summary>
        NoException = 0x20,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// An unknown or uncategorized XML error.
        /// </summary>
        Unknown = 0x40,
        /// <summary>
        /// A generic XML error.
        /// </summary>
        Generic = 0x80,

        /// <summary>
        /// An error that occurred while loading XML from a string.
        /// </summary>
        LoadXml = 0x100,
        /// <summary>
        /// An error that occurred while loading XML from a file.
        /// </summary>
        LoadFile = 0x200,

        /// <summary>
        /// An error related to an XML schema.
        /// </summary>
        Schema = 0x400,
        /// <summary>
        /// An error that occurred during XML validation.
        /// </summary>
        Validate = 0x800,

        /// <summary>
        /// An error related to text encoding.
        /// </summary>
        Encoding = 0x1000,
        /// <summary>
        /// An error related to strict text encoding enforcement.
        /// </summary>
        StrictEncoding = 0x2000,
        /// <summary>
        /// An error that occurred while flattening text content.
        /// </summary>
        FlattenText = 0x4000,

        /// <summary>
        /// An error related to an XPath expression.
        /// </summary>
        Xpath = 0x8000,
        /// <summary>
        /// An error related to XML nodes.
        /// </summary>
        Nodes = 0x10000,
        /// <summary>
        /// An error indicating empty or missing XML content.
        /// </summary>
        Empty = 0x20000,

        /// <summary>
        /// An error related to an XSLT transformation.
        /// </summary>
        Xslt = 0x40000,

        /// <summary>
        /// An error that occurred while creating XML.
        /// </summary>
        Create = 0x80000,
        /// <summary>
        /// An error related to an XML policy.
        /// </summary>
        Policy = 0x100000,
        /// <summary>
        /// An error that occurred while reading XML.
        /// </summary>
        Read = 0x200000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the concrete XML error types: <see
        /// cref="Unknown" />, <see cref="Generic" />, <see cref="LoadXml"
        /// />, <see cref="LoadFile" />, <see cref="Schema" />, <see
        /// cref="Validate" />, <see cref="Encoding" />, <see
        /// cref="StrictEncoding" />, <see cref="FlattenText" />, <see
        /// cref="Xpath" />, <see cref="Nodes" />, <see cref="Empty" />,
        /// <see cref="Xslt" />, <see cref="Create" />, <see cref="Policy"
        /// />, and <see cref="Read" />.
        /// </summary>
        All = Unknown | Generic | LoadXml |
              LoadFile | Schema | Validate |
              Encoding | StrictEncoding | FlattenText |
              Xpath | Nodes | Empty | Xslt |
              Create | Policy | Read,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the error types considered safe: <see
        /// cref="LoadXml" />, <see cref="Encoding" />, <see
        /// cref="StrictEncoding" />, <see cref="FlattenText" />, and <see
        /// cref="Empty" />.
        /// </summary>
        SafeTypes = LoadXml | Encoding | StrictEncoding | FlattenText | Empty,
        /// <summary>
        /// The error types permitted in an unsafe interpreter; <see
        /// cref="All" /> excluding <see cref="Validate" />, <see
        /// cref="Policy" />, and <see cref="Read" />.
        /// </summary>
        UnsafeTypes = All & ~(Validate | Policy | Read),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask describing error handling for a safe
        /// interpreter: <see cref="ForInterpreter" />, <see cref="ForSafe"
        /// />, and <see cref="SafeTypes" />.
        /// </summary>
        SafeInterpreter = ForInterpreter | ForSafe | SafeTypes,
        /// <summary>
        /// Combination mask describing error handling for an unsafe
        /// interpreter: <see cref="ForInterpreter" />, <see
        /// cref="ForUnsafe" />, and <see cref="UnsafeTypes" />.
        /// </summary>
        UnsafeInterpreter = ForInterpreter | ForUnsafe | UnsafeTypes,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default XML error types; equal to <see cref="None" />.
        /// </summary>
        Default = None
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how plugins are
    /// loaded into an interpreter.  Being a [Flags] enumeration, its
    /// values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("58693c8e-fbed-4557-a97d-3f889265a07f")]
    public enum PluginLoaderFlags
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Reserved for future use; callers should not rely on this value.
        /// </summary>
        Reserved = 0x2,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Perform plugin setup during loading.
        /// </summary>
        Setup = 0x100,
        /// <summary>
        /// Enable verbose reporting during plugin loading.
        /// </summary>
        Verbose = 0x200,
        /// <summary>
        /// Locate and use the plugin type during loading.
        /// </summary>
        Type = 0x400,

#if APPDOMAINS || ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
        /// <summary>
        /// Load plugin resources during loading.
        /// </summary>
        Resources = 0x800,
#endif

        /// <summary>
        /// Stop loading when an error is encountered.
        /// </summary>
        StopOnError = 0x1000,
        /// <summary>
        /// Ignore empty plugins instead of treating them as errors.
        /// </summary>
        IgnoreEmpty = 0x2000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask used when loading a plugin: <see cref="Setup"
        /// /> and <see cref="Type" />.
        /// </summary>
        Load = Setup | Type,
        /// <summary>
        /// Combination mask used when previewing a plugin: <see
        /// cref="Setup" /> and <see cref="Type" />.
        /// </summary>
        Preview = Setup | Type,

#if APPDOMAINS || ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
        /// <summary>
        /// Combination mask used when loading only plugin resources: <see
        /// cref="Setup" />, <see cref="Resources" />, <see
        /// cref="StopOnError" />, and <see cref="IgnoreEmpty" />.
        /// </summary>
        ResourcesOnly = Setup | Resources | StopOnError | IgnoreEmpty,
#endif

        /// <summary>
        /// The default plugin loader flags; equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

