    /// <summary>
    /// This enumeration defines bit flags identifying the various reasons
    /// or contexts for which TclTk may sleep (yield) the current thread.
    /// Being a [Flags] enumeration, its values may be combined using a
    /// bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("4397666b-2769-4bdb-adef-be837e330fda")]
    public enum SleepType
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Sleep while servicing background work.
        /// </summary>
        Service = 0x2,
        /// <summary>
        /// Sleep while waiting on a variable.
        /// </summary>
        Variable = 0x4,
        /// <summary>
        /// Sleep while waiting on a process.
        /// </summary>
        Process = 0x8,
        /// <summary>
        /// Sleep while waiting on a socket.
        /// </summary>
        Socket = 0x10,
        /// <summary>
        /// Sleep initiated from within a script.
        /// </summary>
        Script = 0x20,
        /// <summary>
        /// Sleep associated with heartbeat processing.
        /// </summary>
        Heartbeat = 0x40,
        /// <summary>
        /// Sleep that occurs during disposal.
        /// </summary>
        Dispose = 0x80,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// Sleep that occurs within the native Tcl integration wrapper.
        /// </summary>
        TclWrapper = 0x100,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 0).
        /// </summary>
        User0 = 0x1000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 1).
        /// </summary>
        User1 = 0x2000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 2).
        /// </summary>
        User2 = 0x4000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 3).
        /// </summary>
        User3 = 0x8000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 4).
        /// </summary>
        User4 = 0x10000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 5).
        /// </summary>
        User5 = 0x20000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 6).
        /// </summary>
        User6 = 0x40000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 7).
        /// </summary>
        User7 = 0x80000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 8).
        /// </summary>
        User8 = 0x100000,
        /// <summary>
        /// A sleep context reserved for application-defined use (user slot
        /// 9).
        /// </summary>
        User9 = 0x200000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default sleep type; equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

