    /// <summary>
    /// This enumeration defines bit flags identifying the phase of command
    /// line argument processing currently in effect.  Being a [Flags]
    /// enumeration, its values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("bdeab90b-2ce1-4af2-8647-b16006c81d43")]
    public enum ArgumentPhase
    {
        /// <summary>
        /// No flags are set; no special handling is performed.
        /// </summary>
        None = 0x0,      /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,   /* Invalid, do not use. */
        /// <summary>
        /// Reserved for future use; callers should not rely on this value.
        /// </summary>
        Reserved = 0x2,  /* Reserved, do not use. */

        /// <summary>
        /// Argument handling used to determine the overall command line
        /// option.
        /// </summary>
        Phase0 = 0x100,  /* Argument handling to determine overall command
                          * line option. */
        /// <summary>
        /// Gathering of the arguments to be passed to the code handling
        /// the current command line option.
        /// </summary>
        Phase1 = 0x200,  /* Gathering of arguments to pass to the code that
                          * is handling the current command line option. */
        /// <summary>
        /// Not yet used.
        /// </summary>
        Phase2 = 0x400,  /* Not yet used.*/
        /// <summary>
        /// Not yet used.
        /// </summary>
        Phase3 = 0x800,  /* Not yet used.*/
        /// <summary>
        /// Not yet used.
        /// </summary>
        Phase4 = 0x1000, /* Not yet used.*/
        /// <summary>
        /// Not yet used.
        /// </summary>
        Phase5 = 0x2000  /* Not yet used.*/
    }

