    /// <summary>
    /// This enumeration defines bit flags that control how framework
    /// members are discovered and selected during testing.  Being a
    /// [Flags] enumeration, its values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("1799ca3f-bf68-4b2f-b22a-5456a3e393db")]
    public enum FrameworkFlags
    {
        /// <summary>
        /// No flags are set; the default behavior applies.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized
        /// value; callers should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Include built-in framework members.
        /// </summary>
        BuiltIn = 0x2,
        /// <summary>
        /// Include external framework members.
        /// </summary>
        External = 0x4,
        /// <summary>
        /// Include test framework members.
        /// </summary>
        Test = 0x8,

        /// <summary>
        /// Include non-public members.
        /// </summary>
        NonPublic = 0x10,
        /// <summary>
        /// Enable verbose reporting.
        /// </summary>
        Verbose = 0x20,

        /// <summary>
        /// Include instance members.
        /// </summary>
        Instance = 0x40,
        /// <summary>
        /// Include static members.
        /// </summary>
        Static = 0x80,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default framework flags; a combination mask of <see
        /// cref="NonPublic" />, <see cref="Verbose" />, and <see
        /// cref="Static" />.
        /// </summary>
        Default = NonPublic | Verbose | Static
    }

