#if TEST
    /// <summary>
    /// This enumeration defines the bit flags that control how a buffered
    /// trace listener accumulates, coalesces, flushes, and disposes of its
    /// pending trace output. Because it is a [Flags] enumeration,
    /// individual values may be combined together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("19b08291-256f-4ca0-beff-4bcaf74f7e23")]
    public enum BufferedTraceFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel value; it is reserved and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Take ownership of the wrapped trace target so that it is
        /// disposed when the buffered listener is closed.
        /// </summary>
        TakeOwnership = 0x2,
        /// <summary>
        /// Empty (discard) any buffered trace output when the listener is
        /// closed.
        /// </summary>
        EmptyOnClose = 0x4,
        /// <summary>
        /// Ignore the empty-on-close request, leaving any buffered output
        /// intact when the listener is closed.
        /// </summary>
        IgnoreEmptyOnClose = 0x8,
        /// <summary>
        /// Never automatically flush buffered trace output.
        /// </summary>
        NeverFlush = 0x10,
        /// <summary>
        /// Flush any buffered trace output when the listener is closed.
        /// </summary>
        FlushOnClose = 0x20,
        /// <summary>
        /// Empty (discard) the buffer after each flush operation.
        /// </summary>
        EmptyOnFlush = 0x40,
        /// <summary>
        /// Flush buffered trace output just before the buffer is emptied.
        /// </summary>
        FlushOnEmpty = 0x80,
        /// <summary>
        /// Disable buffering entirely, passing trace output straight
        /// through.
        /// </summary>
        BufferingDisabled = 0x100,
        /// <summary>
        /// Coalesce duplicate trace messages, regardless of whether they
        /// are consecutive.
        /// </summary>
        CoalesceDuplicates = 0x200,
        /// <summary>
        /// Coalesce only consecutive duplicate trace messages.
        /// </summary>
        ConsecutiveDuplicates = 0x400,
        /// <summary>
        /// Do not include a repeated-occurrence count when coalescing
        /// duplicate messages.
        /// </summary>
        NoRepeatedCount = 0x800,
        /// <summary>
        /// Include the unique identifier when formatting buffered trace
        /// messages.
        /// </summary>
        FormatWithId = 0x1000,
        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Reserved1 = 0x2000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of buffered trace flags; a combination of
        /// <see cref="EmptyOnClose" />, <see cref="FlushOnClose" />,
        /// <see cref="EmptyOnFlush" />, and <see cref="Reserved1" />.
        /// </summary>
        Default = EmptyOnClose | FlushOnClose | EmptyOnFlush |
                  Reserved1
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the priority levels, message categories,
    /// formatting options, and behavioral flags used throughout TclTk's
    /// diagnostic tracing subsystem to classify trace messages and to
    /// decide which of them are emitted. Because it is a [Flags]
    /// enumeration backed by a 64-bit unsigned integer, individual values
    /// may be combined together using a bitwise OR; many of the values
    /// below are themselves predefined combinations (masks) of the simpler
    /// flags.
    /// </summary>
    [Flags()]
    [ObjectId("17219a26-f14b-4643-82a0-b915c73dcd37")]
    public enum TracePriority : ulong
    {
        /// <summary>
        /// No priority flags are set; reserved as a placeholder and not
        /// intended for direct use.
        /// </summary>
        None = 0x0,                                // do not use.
        /// <summary>
        /// A reserved sentinel value; it is reserved and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,                             // reserved, do not use.

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // HACK: It should be noted here that these are always
        //       (currently) treated as flags by this library;
        //       hence, their relative values have no meaning.
        //       Still, keeping them in order is makes it easy
        //       to change this later.
        //
        #region Core Priority Values
        /// <summary>
        /// A pseudo-priority used to mark trace messages that should
        /// effectively never be shown.
        /// </summary>
        Never = 0x2,                               // priority #N
        /// <summary>
        /// The lowest ordinary trace priority (relative priority 9).
        /// </summary>
        Lowest = 0x4,                              // priority #9
        /// <summary>
        /// A very low trace priority (relative priority 8).
        /// </summary>
        Lower = 0x8,                               // priority #8
        /// <summary>
        /// A low trace priority (relative priority 7).
        /// </summary>
        Low = 0x10,                                // priority #7
        /// <summary>
        /// A medium-low trace priority (relative priority 6).
        /// </summary>
        MediumLow = 0x20,                          // priority #6
        /// <summary>
        /// The medium, baseline trace priority (relative priority 5).
        /// </summary>
        Medium = 0x40,                             // priority #5
        /// <summary>
        /// A medium-high trace priority (relative priority 4).
        /// </summary>
        MediumHigh = 0x80,                         // priority #4
        /// <summary>
        /// A high trace priority (relative priority 3).
        /// </summary>
        High = 0x100,                              // priority #3
        /// <summary>
        /// A very high trace priority (relative priority 2).
        /// </summary>
        Higher = 0x200,                            // priority #2
        /// <summary>
        /// The highest ordinary trace priority (relative priority 1).
        /// </summary>
        Highest = 0x400,                           // priority #1
        /// <summary>
        /// A pseudo-priority used to mark trace messages that should
        /// always be shown, regardless of the configured priority
        /// threshold.
        /// </summary>
        Always = 0x800,                            // priority #A
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Core Type Values
        /// <summary>
        /// Security / action audit, alert, etc.
        /// </summary>
        Audit = 0x1000,                            // security / action audit, alert, etc.
        /// <summary>
        /// System error / immediate attention.
        /// </summary>
        Emergency = 0x2000,                        // system error / immediate attention.
        /// <summary>
        /// Unrecoverable error / exception.
        /// </summary>
        Fatal = 0x4000,                            // unrecoverable error / exception.
        /// <summary>
        /// Error / exception message.
        /// </summary>
        Error = 0x8000,                            // error / exception message.
        /// <summary>
        /// Warning / unusual condition message.
        /// </summary>
        Warning = 0x10000,                         // warning / unusual condition message.
        /// <summary>
        /// Informational message.
        /// </summary>
        Inform = 0x20000,                          // informational message.
        /// <summary>
        /// Debug / diagnostic message.
        /// </summary>
        Debug = 0x40000,                           // debug / diagnostic  message.
        /// <summary>
        /// Debug / extra information, noisy.
        /// </summary>
        Verbose = 0x80000,                         // debug / extra information, noisy.
        /// <summary>
        /// On-demand via script command, etc.
        /// </summary>
        Demand = 0x100000,                         // on-demand via script command, etc.
        /// <summary>
        /// Message external to library.
        /// </summary>
        External = 0x200000,                       // message external to library.
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Core Flag Values
        /// <summary>
        /// Extra method call bounce.
        /// </summary>
        ExtraSkipFrame = 0x400000,                 // extra method call bounce.
        /// <summary>
        /// Add DateTime to trace messages.
        /// </summary>
        EnableDateTimeFlag = 0x800000,             // add DateTime to trace messages.
        /// <summary>
        /// Add Priority to trace messages.
        /// </summary>
        EnablePriorityFlag = 0x1000000,            // add Priority to trace messages.
        /// <summary>
        /// Add AppDomain to trace messages.
        /// </summary>
        EnableServerNameFlag = 0x2000000,          // add AppDomain to trace messages.
        /// <summary>
        /// Add test name to trace messages.
        /// </summary>
        EnableTestNameFlag = 0x4000000,            // add test name to trace messages.
        /// <summary>
        /// Add AppDomain to trace messages.
        /// </summary>
        EnableAppDomainFlag = 0x8000000,           // add AppDomain to trace messages.
        /// <summary>
        /// Add Interpreter to trace messages.
        /// </summary>
        EnableInterpreterFlag = 0x10000000,        // add Interpreter to trace messages.
        /// <summary>
        /// Remove Interpreter from trace messages.
        /// </summary>
        DisableInterpreterFlag = 0x20000000,       // remove Interpreter from trace messages.
        /// <summary>
        /// Add ThreadId to trace messages.
        /// </summary>
        EnableThreadIdFlag = 0x40000000,           // add ThreadId to trace messages.
        /// <summary>
        /// Add Method to trace messages.
        /// </summary>
        EnableMethodFlag = 0x80000000,             // add Method to trace messages.
        /// <summary>
        /// Add StackTrace to trace messages.
        /// </summary>
        EnableStackFlag = 0x100000000,             // add StackTrace to trace messages.
        /// <summary>
        /// Surround trace messages with extra new lines.
        /// </summary>
        EnableExtraNewLinesFlag = 0x200000000,     // surround trace messages with new
                                                   // lines.

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Use the minimal trace format string.
        /// </summary>
        EnableMinimumFormatFlag = 0x400000000,     // use the minimal trace format string.
        /// <summary>
        /// Use the medium low trace format string.
        /// </summary>
        EnableMediumLowFormatFlag = 0x800000000,   // use the medium low trace format string.
        /// <summary>
        /// Use the medium trace format string.
        /// </summary>
        EnableMediumFormatFlag = 0x1000000000,     // use the medium trace format string.
        /// <summary>
        /// Use the medium high trace format string.
        /// </summary>
        EnableMediumHighFormatFlag = 0x2000000000, // use the medium high trace format string.
        /// <summary>
        /// Use the maximal trace format string.
        /// </summary>
        EnableMaximumFormatFlag = 0x4000000000,    // use the maximal trace format string.
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Category Flag Values
        /// <summary>
        /// Decrease priority for any listed category.
        /// </summary>
        CategoryPenalty = 0x8000000000,            // decrease priority for any listed category.
        /// <summary>
        /// Increase priority for any listed category.
        /// </summary>
        CategoryBonus = 0x10000000000,             // increase priority for any listed category.

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Deny trace messages with a null category.
        /// </summary>
        DenyNullCategory = 0x20000000000,          // deny trace messages with a null category.
        /// <summary>
        /// Allow trace messages with a null category.
        /// </summary>
        AllowNullCategory = 0x40000000000,         // allow trace messages with a null category.
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Application / User Values (External Use Only)
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User0 = 0x80000000000,                     // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User1 = 0x100000000000,                    // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User2 = 0x200000000000,                    // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User3 = 0x400000000000,                    // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User4 = 0x800000000000,                    // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User5 = 0x1000000000000,                   // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User6 = 0x2000000000000,                   // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User7 = 0x4000000000000,                   // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User8 = 0x8000000000000,                   // reserved for third-party use.
        /// <summary>
        /// Reserved for third-party use.
        /// </summary>
        User9 = 0x10000000000000,                  // reserved for third-party use.
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Other Flag Values
        /// <summary>
        /// Use simpler trace parameter formatting.
        /// </summary>
        SimpleFormatting = 0x20000000000000,       // use simpler trace parameter formatting
        /// <summary>
        /// Truncate overly long values with ellipsis.
        /// </summary>
        UseEllipsis = 0x40000000000000,            // truncate overly long values with ellipsis
        /// <summary>
        /// Do not truncate overly long values with ellipsis.
        /// </summary>
        NoEllipsis = 0x80000000000000,             // do not truncate overly long values with ellipsis

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Caller is an external binary plugin.
        /// </summary>
        FromPlugin = 0x100000000000000,            // caller is an external binary plugin
        /// <summary>
        /// Caller is an external SDK integration.
        /// </summary>
        FromSdk = 0x200000000000000,               // caller is an external SDK integration
        /// <summary>
        /// Caller is a wrapper around <c>DebugTrace</c>, et al.
        /// </summary>
        ViaWrapper = 0x400000000000000,            // caller is a wrapper around DebugTrace, et al.
        /// <summary>
        /// Skip calling into the TraceLimits checks.
        /// </summary>
        NoLimits = 0x800000000000000,              // skip calling into the TraceLimits checks.
        /// <summary>
        /// Attempt to flush all listeners before returning.
        /// </summary>
        ForceFlush = 0x1000000000000000,           // attempt to flush all listeners before returning.

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A special, internal-only flag used to indicate that an engine
        /// exception was caught.
        /// </summary>
        ForException = 0x2000000000000000,         // *SPECIAL* internal-only flag used to indicate
                                                   // an engine exception was caught.
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Conditional Values
        //
        // HACK: For the "Debug" build, enable those messages by default;
        //       otherwise, disable them by default.
        //
#if DEBUG || FORCE_TRACE
        /// <summary>
        /// In debug builds (or when FORCE_TRACE is defined), enables
        /// <see cref="Debug" /> messages by default.
        /// </summary>
        MaybeDebug = Debug,
#else
        /// <summary>
        /// In non-debug builds, disables debug messages by default;
        /// equivalent to <see cref="None" />.
