        /// <see cref="AnyCoreTypeMask" />.
        /// </summary>
        HighPrioritiesMask = Never | Always | HighAndUpMask | AnyCoreTypeMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ExtraSkipFrame" />,
        /// <see cref="EnableDateTimeFlag" />,
        /// <see cref="EnablePriorityFlag" />,
        /// <see cref="EnableServerNameFlag" />,
        /// <see cref="EnableTestNameFlag" />,
        /// <see cref="EnableAppDomainFlag" />,
        /// <see cref="EnableInterpreterFlag" />,
        /// <see cref="DisableInterpreterFlag" />,
        /// <see cref="EnableThreadIdFlag" />,
        /// <see cref="EnableMethodFlag" />,
        /// <see cref="EnableStackFlag" />,
        /// <see cref="EnableExtraNewLinesFlag" />,
        /// <see cref="EnableMinimumFormatFlag" />,
        /// <see cref="EnableMediumLowFormatFlag" />,
        /// <see cref="EnableMediumFormatFlag" />,
        /// <see cref="EnableMediumHighFormatFlag" />, and
        /// <see cref="EnableMaximumFormatFlag" />.
        /// </summary>
        AnyCoreFlagMask = ExtraSkipFrame |
                          EnableDateTimeFlag | EnablePriorityFlag |
                          EnableServerNameFlag | EnableTestNameFlag |
                          EnableAppDomainFlag | EnableInterpreterFlag |
                          DisableInterpreterFlag | EnableThreadIdFlag |
                          EnableMethodFlag | EnableStackFlag |
                          EnableExtraNewLinesFlag | EnableMinimumFormatFlag |
                          EnableMediumLowFormatFlag | EnableMediumFormatFlag |
                          EnableMediumHighFormatFlag | EnableMaximumFormatFlag,

        /// <summary>
        /// Combination mask of <see cref="CategoryPenalty" />,
        /// <see cref="CategoryBonus" />, <see cref="DenyNullCategory" />,
        /// and <see cref="AllowNullCategory" />.
        /// </summary>
        AnyCoreCategoryMask = CategoryPenalty | CategoryBonus |
                              DenyNullCategory | AllowNullCategory,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="User0" />, <see cref="User1" />,
        /// <see cref="User2" />, <see cref="User3" />,
        /// <see cref="User4" />, <see cref="User5" />,
        /// <see cref="User6" />, <see cref="User7" />,
        /// <see cref="User8" />, and <see cref="User9" />.
        /// </summary>
        AnyUserTypeMask = User0 | User1 | User2 |
                          User3 | User4 | User5 |
                          User6 | User7 | User8 |
                          User9,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="MaybeAnyCoreTypeMask" /> and
        /// <see cref="AnyUserTypeMask" />.
        /// </summary>
        MaybeAnyTypeMask = MaybeAnyCoreTypeMask | AnyUserTypeMask,

        /// <summary>
        /// Combination mask of <see cref="AnyCoreTypeMask" /> and
        /// <see cref="AnyUserTypeMask" />.
        /// </summary>
        AnyTypeMask = AnyCoreTypeMask | AnyUserTypeMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AnyPriorityMask" /> and
        /// <see cref="AnyTypeMask" />.
        /// </summary>
        AnyPriorityOrTypeMask = AnyPriorityMask | AnyTypeMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AnyPriorityMask" />,
        /// <see cref="AnyCoreFlagMask" />,
        /// <see cref="AnyCoreCategoryMask" />, and
        /// <see cref="AnyTypeMask" />.
        /// </summary>
        AnyMask = AnyPriorityMask | AnyCoreFlagMask | AnyCoreCategoryMask | AnyTypeMask,
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Suggested Default Priority & Mask Values
        /// <summary>
        /// The default trace priority; equivalent to
        /// <see cref="Medium" />.
        /// </summary>
        Default = Medium,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Default" /> and
        /// <see cref="Debug" />.
        /// </summary>
        DefaultDebug = Default | Debug,
        /// <summary>
        /// Combination mask of <see cref="Default" /> and
        /// <see cref="Warning" />.
        /// </summary>
        DefaultWarning = Default | Warning,
        /// <summary>
        /// Combination mask of <see cref="Default" />,
        /// <see cref="Error" />, <see cref="Fatal" />,
        /// <see cref="Emergency" />, and <see cref="Audit" />.
        /// </summary>
        DefaultError = Default | Error | Fatal | Emergency | Audit,
        /// <summary>
        /// Combination mask of <see cref="Default" /> and
        /// <see cref="Demand" />.
        /// </summary>
        DefaultDemand = Default | Demand,
        /// <summary>
        /// Combination mask of <see cref="Always" /> and
        /// <see cref="Demand" />.
        /// </summary>
        AlwaysDemand = Always | Demand,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// For TraceLimits use only. Equivalent to
        /// <see cref="LowAndDownMask" />.
        /// </summary>
        DefaultLimitMask = LowAndDownMask, /* For TraceLimits use only. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Never" />,
        /// <see cref="Always" />, <see cref="MediumAndUpMask" />, and
        /// <see cref="MaybeAnyTypeMask" />.
        /// </summary>
        DefaultMask = Never | Always | MediumAndUpMask | MaybeAnyTypeMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ViaWrapper" /> and
        /// <see cref="FromPlugin" />.
        /// </summary>
        ViaWrapperFromPlugin = ViaWrapper | FromPlugin,
        #endregion
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration describes the internal configuration state of TclTk's
    /// diagnostic tracing subsystem.  Its values are bit flags that may be
    /// combined to indicate which aspects of trace behavior are currently in
    /// effect, which ones should be reset to their defaults, and how trace
    /// output should be formatted and filtered.
    /// </summary>
    [Flags()]
    [ObjectId("d3362813-f130-471a-ba95-4c562b893c4f")]
    public enum TraceStateType : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized trace
        /// state; callers should not use this value.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The tracing subsystem has been initialized.
        /// </summary>
        Initialized = 0x10,
        /// <summary>
        /// Force trace output to be delivered to the configured trace
        /// listeners.
        /// </summary>
        ForceListeners = 0x20,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Tracing is possible, i.e. the master switch that permits trace
        /// output is set.
        /// </summary>
        Possible = 0x40,
        /// <summary>
        /// Reset the "possible" tracing state to its default value.
        /// </summary>
        ResetPossible = 0x80,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Tracing is enabled and trace messages may actually be emitted.
        /// </summary>
        Enabled = 0x100,
        /// <summary>
        /// Reset the "enabled" tracing state to its default value.
        /// </summary>
        ResetEnabled = 0x200,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A filter callback is used to decide which trace messages are
        /// emitted.
        /// </summary>
        FilterCallback = 0x400,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Trace limits are taken into account when emitting messages.
        /// </summary>
        Limits = 0x800,
        /// <summary>
        /// Reset the trace limits to their default values.
        /// </summary>
        ResetLimits = 0x1000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The set of trace priorities is taken into account when emitting
        /// messages.
        /// </summary>
        Priorities = 0x2000,
        /// <summary>
        /// Reset the set of trace priorities to its default value.
        /// </summary>
        ResetPriorities = 0x4000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The single active trace priority value is taken into account when
        /// emitting messages.
        /// </summary>
        Priority = 0x8000,
        /// <summary>
        /// Reset the single active trace priority value to its default.
        /// </summary>
        ResetPriority = 0x10000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Trace categories are taken into account when emitting messages.
        /// </summary>
        Categories = 0x20000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The set of explicitly enabled trace categories is in effect.
        /// </summary>
        EnabledCategories = 0x40000,
        /// <summary>
        /// The set of explicitly disabled trace categories is in effect.
        /// </summary>
        DisabledCategories = 0x80000,
        /// <summary>
        /// The set of trace categories that receive a priority penalty is in
        /// effect.
        /// </summary>
        PenaltyCategories = 0x100000,
        /// <summary>
        /// The set of trace categories that receive a priority bonus is in
        /// effect.
        /// </summary>
        BonusCategories = 0x200000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The handling of messages without an associated category (i.e. null
        /// categories) is in effect.
        /// </summary>
        NullCategories = 0x400000,
        /// <summary>
        /// Reset the null-category handling state to its default value.
        /// </summary>
        ResetNullCategories = 0x800000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The configured trace message format is in effect.
        /// </summary>
        Format = 0x1000000,
        /// <summary>
        /// Reset the trace message format to its default value.
        /// </summary>
        ResetFormat = 0x2000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The configured trace format string is in effect.
        /// </summary>
        FormatString = 0x4000000,
        /// <summary>
        /// Reset the trace format string to its default value.
        /// </summary>
        ResetFormatString = 0x8000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The configured trace format index is in effect.
        /// </summary>
        FormatIndex = 0x10000000,
        /// <summary>
        /// Reset the trace format index to its default value.
        /// </summary>
        ResetFormatIndex = 0x20000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The configured trace format flags are in effect.
        /// </summary>
        FormatFlags = 0x40000000,
        /// <summary>
        /// Reset the trace format flags to their default values.
        /// </summary>
        ResetFormatFlags = 0x80000000,
        /// <summary>
        /// Verbose trace format flags are in effect, producing more detailed
        /// trace output.
        /// </summary>
        VerboseFlags = 0x100000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The full trace context is included with each emitted message.
        /// </summary>
        FullContext = 0x200000000,
        /// <summary>
        /// Reset the full-context inclusion state to its default value.
        /// </summary>
        ResetFullContext = 0x400000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The fallback trace format, used when no more specific format
        /// applies, is in effect.
        /// </summary>
        FallbackFormat = 0x800000000,
        /// <summary>
        /// Reset the fallback trace format to its default value.
        /// </summary>
        ResetFallbackFormat = 0x1000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Trace indicators (e.g. status markers) are included with emitted
        /// messages.
        /// </summary>
        Indicators = 0x2000000000,
        /// <summary>
        /// Reset the trace indicator state to its default value.
        /// </summary>
        ResetIndicators = 0x4000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Raw, unformatted trace indicators are used.
        /// </summary>
        RawIndicators = 0x8000000000,
        /// <summary>
        /// Trace listeners are consulted (i.e. "seen") when emitting
        /// indicators.
        /// </summary>
        SeeListeners = 0x10000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Trace state derived from environment variables is taken into
        /// account.
        /// </summary>
        Environment = 0x20000000000,
        /// <summary>
        /// Force the requested trace state change to be applied.
        /// </summary>
        Force = 0x40000000000,
        /// <summary>
        /// Reset the affected trace state to its default values.
        /// </summary>
        Reset = 0x80000000000,
        /// <summary>
        /// Allow values supplied explicitly to override those derived from the
        /// environment.
        /// </summary>
        OverrideEnvironment = 0x100000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The trace state is being configured on behalf of a command.
        /// </summary>
        ForCommand = 0x200000000000,
        /// <summary>
        /// The trace state is being configured on behalf of the SDK.
        /// </summary>
        ForSdk = 0x400000000000,
        /// <summary>
        /// The default trace state is being requested.
        /// </summary>
        ForDefault = 0x800000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Possible" /> and
        /// <see cref="ResetPossible" />.
        /// </summary>
        PossibleMask = Possible | ResetPossible,
        /// <summary>
        /// Combination mask of <see cref="Enabled" /> and
        /// <see cref="ResetEnabled" />.
        /// </summary>
        EnabledMask = Enabled | ResetEnabled,
        /// <summary>
        /// Combination mask of <see cref="Limits" /> and
        /// <see cref="ResetLimits" />.
        /// </summary>
        LimitsMask = Limits | ResetLimits,
        /// <summary>
        /// Combination mask of <see cref="Priorities" /> and
        /// <see cref="ResetPriorities" />.
        /// </summary>
        PrioritiesMask = Priorities | ResetPriorities,
        /// <summary>
        /// Combination mask of <see cref="Priority" /> and
        /// <see cref="ResetPriority" />.
        /// </summary>
        PriorityMask = Priority | ResetPriority,
        /// <summary>
        /// Combination mask of <see cref="NullCategories" /> and
        /// <see cref="ResetNullCategories" />.
        /// </summary>
        NullCategoriesMask = NullCategories | ResetNullCategories,
        /// <summary>
        /// Combination mask of <see cref="Format" /> and
        /// <see cref="ResetFormat" />.
        /// </summary>
        FormatMask = Format | ResetFormat,
        /// <summary>
        /// Combination mask of <see cref="FormatString" /> and
        /// <see cref="ResetFormatString" />.
        /// </summary>
        FormatStringMask = FormatString | ResetFormatString,
        /// <summary>
        /// Combination mask of <see cref="FormatIndex" /> and
        /// <see cref="ResetFormatIndex" />.
        /// </summary>
        FormatIndexMask = FormatIndex | ResetFormatIndex,
        /// <summary>
        /// Combination mask of <see cref="FormatFlags" />,
        /// <see cref="ResetFormatFlags" />, and <see cref="VerboseFlags" />.
        /// </summary>
        FormatFlagsMask = FormatFlags | ResetFormatFlags | VerboseFlags,
        /// <summary>
        /// Combination mask of <see cref="FullContext" /> and
        /// <see cref="ResetFullContext" />.
        /// </summary>
        FullContextMask = FullContext | ResetFullContext,
        /// <summary>
        /// Combination mask of <see cref="FallbackFormat" /> and
        /// <see cref="ResetFallbackFormat" />.
        /// </summary>
        FallbackFormatMask = FallbackFormat | ResetFallbackFormat,
        /// <summary>
        /// Combination mask of <see cref="Indicators" />,
        /// <see cref="ResetIndicators" />, <see cref="RawIndicators" />, and
        /// <see cref="SeeListeners" />.
        /// </summary>
        IndicatorsMask = Indicators | ResetIndicators | RawIndicators | SeeListeners,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the category-type flags
        /// <see cref="EnabledCategories" />, <see cref="DisabledCategories" />,
        /// <see cref="PenaltyCategories" />, and <see cref="BonusCategories" />.
        /// </summary>
        CategoryTypeMask = EnabledCategories | DisabledCategories |
                           PenaltyCategories | BonusCategories,

        /// <summary>
        /// Combination mask of all category-related flags, namely
        /// <see cref="Categories" />, <see cref="CategoryTypeMask" />, and
        /// <see cref="NullCategoriesMask" />.
        /// </summary>
        AllCategoriesMask = Categories | CategoryTypeMask |
                            NullCategoriesMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // TODO: Update this value if any other internal state ends
        //       up with an associated environment variable.
        //
        /// <summary>
        /// Combination mask of the trace state flags that have an associated
        /// environment variable, namely <see cref="Enabled" />,
        /// <see cref="Priorities" />, <see cref="Priority" />,
        /// <see cref="Categories" />, and <see cref="CategoryTypeMask" />.
        /// </summary>
        EnvironmentMask = Enabled | Priorities | Priority |
                          Categories | CategoryTypeMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all normal (non-reset, non-special) trace state
        /// flags.
        /// </summary>
        NormalMask = Initialized | ForceListeners | Possible |
                     Enabled | FilterCallback | Limits |
                     Priorities | Priority | Categories |
                     EnabledCategories | DisabledCategories |
                     PenaltyCategories | BonusCategories |
                     NullCategories | Format | FormatString |
                     FormatIndex | FormatFlags | VerboseFlags |
                     FullContext | FallbackFormat | Indicators,

        /// <summary>
        /// Combination mask of all of the "reset" trace state flags.
        /// </summary>
        ResetMask = ResetPossible | ResetEnabled |
                    ResetLimits | ResetPriorities |
                    ResetPriority | ResetNullCategories |
                    ResetFormatString | ResetFormatIndex |
                    ResetFormatFlags | ResetFullContext |
                    ResetFallbackFormat | ResetIndicators,

        /// <summary>
        /// Combination mask of the special control flags
        /// <see cref="Environment" />, <see cref="Force" />,
        /// <see cref="Reset" />, and <see cref="OverrideEnvironment" />.
        /// </summary>
        SpecialMask = Environment | Force | Reset |
                      OverrideEnvironment,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of every trace state flag, namely
        /// <see cref="NormalMask" />, <see cref="ResetMask" />, and
        /// <see cref="SpecialMask" />.
        /// </summary>
        AllMask = NormalMask | ResetMask | SpecialMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags used when enabling tracing for the
        /// core library, i.e. <see cref="AllMask" /> with
        /// <see cref="VerboseFlags" /> and <see cref="ResetMask" /> excluded.
        /// </summary>
        CoreEnableMask = AllMask & ~(VerboseFlags | ResetMask),
        /// <summary>
        /// Combination mask of the flags used when disabling tracing for the
        /// core library, i.e. <see cref="AllMask" /> with
        /// <see cref="VerboseFlags" /> and <see cref="SpecialMask" /> excluded.
        /// </summary>
        CoreDisableMask = AllMask & ~(VerboseFlags | SpecialMask),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="CoreEnableMask" /> together with
        /// <see cref="ForSdk" />.
        /// </summary>
        SdkEnableMask = CoreEnableMask | ForSdk,
        /// <summary>
        /// Combination mask of <see cref="CoreDisableMask" /> together with
        /// <see cref="ForSdk" />.
        /// </summary>
        SdkDisableMask = CoreDisableMask | ForSdk,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the trace state flags that are considered
        /// non-standard, namely <see cref="ForceListeners" />,
        /// <see cref="Priority" />, <see cref="FormatStringMask" />,
        /// <see cref="FormatIndexMask" />, <see cref="FormatFlagsMask" />,
        /// <see cref="FallbackFormatMask" />, and <see cref="SpecialMask" />.
        /// </summary>
        NonStandardMask = ForceListeners | Priority |
                          FormatStringMask | FormatIndexMask |
                          FormatFlagsMask | FallbackFormatMask |
                          SpecialMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the standard trace state flags, i.e.
        /// <see cref="AllMask" /> with <see cref="NonStandardMask" /> excluded.
        /// </summary>
        StandardMask = AllMask & ~NonStandardMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The trace state used by the trace command, i.e. the combination of
        /// <see cref="Default" /> and <see cref="ForCommand" /> with
        /// <see cref="ForDefault" /> excluded.
        /// </summary>
        TraceCommand = (Default | ForCommand) & ~ForDefault,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default trace state, i.e. the combination of
        /// <see cref="PossibleMask" />, <see cref="EnabledMask" />,
        /// <see cref="LimitsMask" />, <see cref="PrioritiesMask" />, and
        /// <see cref="ForDefault" />.
        /// </summary>
        Default = PossibleMask | EnabledMask | LimitsMask |
                  PrioritiesMask | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration describes the type or disposition of a trace category.
    /// Its values are bit flags that may be combined to indicate whether a
    /// category is enabled or disabled and whether it carries a priority
    /// penalty or bonus.
    /// </summary>
    [Flags()]
    [ObjectId("ae23c5f4-34e3-4c0a-9298-c305d861cb00")]
    public enum TraceCategoryType
    {
        /// <summary>
        /// There is no trace category type.
        /// </summary>
        None = 0x0,        /* There is no trace category type. */
        /// <summary>
        /// A reserved sentinel indicating an invalid trace category type;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,     /* Invalid, do not use. */

        /// <summary>
        /// The trace category is enabled.
        /// </summary>
        Enabled = 0x2,     /* Is the trace category enabled? */

        /// <summary>
        /// The trace category is disabled.
        /// </summary>
        Disabled = 0x4,    /* Is the trace category disabled? */

        /// <summary>
        /// The trace category has a penalty applied to its priority.
        /// </summary>
        Penalty = 0x8,     /* Does the trace category have a penalty
                            * on its priority? */

        /// <summary>
        /// The trace category has a bonus applied to its priority.
        /// </summary>
        Bonus = 0x10,      /* Does the trace category have a bonus
                            * on its priority? */

        /// <summary>
        /// The default (legacy) trace category is being used.
        /// </summary>
        ForDefault = 0x20, /* The default (legacy) trace category is
                            * being used. */

        /// <summary>
        /// Combination mask of the base category-type flags
        /// <see cref="Enabled" />, <see cref="Disabled" />,
        /// <see cref="Penalty" />, and <see cref="Bonus" />.
        /// </summary>
        BaseMask = Enabled | Disabled | Penalty | Bonus,

        /// <summary>
        /// The default trace category type, i.e. the combination of
        /// <see cref="Enabled" /> and <see cref="ForDefault" />.
        /// </summary>
        Default = Enabled | ForDefault /* LEGACY: The default category type is
                                        * used to determine if the category is
                                        * enabled. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the various kinds of informational paths
    /// that TclTk is able to report or resolve, such as the locations of native
    /// binaries and the script library.  Its values are bit flags that may be
    /// combined to select a path kind together with options that modify how the
    /// path is computed.
    /// </summary>
    [Flags()]
    [ObjectId("6b85bd1a-f812-476a-bda8-cabbf2c2c7f0")]
    public enum InfoPathType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid path type; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Reserved for future use; callers should not use this value.
        /// </summary>
        Reserved = 0x2,

        /// <summary>
        /// The path of the native host process.
        /// </summary>
        NativeProcess = 0x10,
        /// <summary>
        /// The path of the native binary (i.e. the core library assembly).
        /// </summary>
        NativeBinary = 0x20,
        /// <summary>
        /// The path of the native library used by the core library.
        /// </summary>
        NativeLibrary = 0x40,
        /// <summary>
        /// The path of native external components.
        /// </summary>
        NativeExternals = 0x80,
        /// <summary>
        /// The base path of the managed script library.
        /// </summary>
        ScriptLibraryBase = 0x100,

        /// <summary>
        /// Compute the full (absolute) path.
        /// </summary>
        Full = 0x200,
        /// <summary>
        /// Compute the local path.
        /// </summary>
        Local = 0x400,
        /// <summary>
        /// Omit the processor architecture component from the computed path.
        /// </summary>
        NoProcessor = 0x800,
        /// <summary>
        /// Use the alternate name when computing the path.
        /// </summary>
        AlternateName = 0x1000,

        /// <summary>
        /// Combination mask of the path-kind flags
        /// <see cref="NativeProcess" />, <see cref="NativeBinary" />,
        /// <see cref="NativeLibrary" />, <see cref="NativeExternals" />, and
        /// <see cref="ScriptLibraryBase" />.
        /// </summary>
        TypeMask = NativeProcess | NativeBinary | NativeLibrary |
                   NativeExternals | ScriptLibraryBase,

        /// <summary>
        /// Combination mask of the path-modifier flags <see cref="Full" />,
        /// <see cref="Local" />, <see cref="NoProcessor" />, and
        /// <see cref="AlternateName" />.
        /// </summary>
        FlagsMask = Full | Local | NoProcessor | AlternateName,

        /// <summary>
        /// The default path type, equivalent to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls the emergency (on-demand) management of
    /// TclTk's script debugger.  Its values are bit flags that may be combined
    /// to request that the debugger be created, disposed, enabled, disabled, or
    /// otherwise reconfigured, along with options that govern the associated
    /// behavior.
    /// </summary>
    [Flags()]
    [ObjectId("36aabcbf-061b-4524-bc93-d427b6f62caf")]
    public enum DebugEmergencyLevel : ulong
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,                     /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should not
        /// use this value.
        /// </summary>
        Invalid = 0x1,                  /* Invalid, do not use. */
        /// <summary>
        /// Reserved for future use; callers should not use this value.
        /// </summary>
        Reserved1 = 0x2,                /* Reserved, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Dispose of the existing debugger, if any.
        /// </summary>
        Disposed = 0x10,                /* Dispose existing debugger, if any. */
        /// <summary>
        /// Disable the debugger, if present.
        /// </summary>
        Disabled = 0x20,                /* Disable debugger, if present. */

        /// <summary>
        /// Enable the debugger, if present.
        /// </summary>
        Enabled = 0x40,                 /* Enable debugger, if present. */
        /// <summary>
        /// Create a new debugger, if necessary.
        /// </summary>
        Created = 0x80,                 /* Create new debugger, if necessary. */

        /// <summary>
        /// Reset (some) debugger state to its default.
        /// </summary>
        Reset = 0x100,                  /* Reset (some?) state to its default. */

        /// <summary>
        /// Reset the script cancellation state, if necessary.
        /// </summary>
        ResetCancel = 0x200,            /* Reset script cancellation, if necessary. */
        /// <summary>
        /// Forcibly reset the script cancellation state.
        /// </summary>
        ForceResetCancel = 0x400,       /* Forcibly reset script cancellation. */

        /// <summary>
        /// Reset the halt flag, if necessary.
        /// </summary>
        ResetHalt = 0x800,              /* Reset halt flag, if necessary. */
        /// <summary>
        /// Forcibly reset the halt flag.
        /// </summary>
        ForceResetHalt = 0x1000,        /* Forcibly reset halt flag. */

        /// <summary>
        /// Break into the debugger, if present.
        /// </summary>
        Break = 0x2000,                 /* Break into debugger, if present. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable everything needed to make token breakpoints work.
        /// </summary>
        Tokens = 0x4000,                /* Enable everything needed to make
                                         * token breakpoints work. */
        /// <summary>
        /// Enable everything needed to make nested script argument tracking
        /// work.
        /// </summary>
        ScriptArguments = 0x8000,       /* Enable everything needed to make
                                         * nested script argument tracking
                                         * work. */
        /// <summary>
        /// Enable an isolated interpreter for the new debugger, if applicable.
        /// </summary>
        Isolated = 0x10000,             /* Enable isolated interpreter for new
                                         * debugger, if applicable. */
        /// <summary>
        /// When creating or disposing of the debugger (if necessary), ignore
        /// the immutable flag for the interpreter.
        /// </summary>
        IgnoreModifiable = 0x20000,     /* When creating or disposing of the
                                         * debugger (if necessary), ignore the
                                         * immutable flag for the interpreter. */
        /// <summary>
        /// Enable more diagnostic results.
        /// </summary>
        Verbose = 0x40000,              /* Enable more diagnostic results. */
        /// <summary>
        /// Silence trace output.
        /// </summary>
        Quiet = 0x80000,                /* Silence trace output. */
        /// <summary>
        /// Ignore the debugger enabled status.
        /// </summary>
        IgnoreEnabled = 0x100000,       /* Ignore debugger enabled status. */
        /// <summary>
        /// Force result stack traces to be populated right now.  This will slow
        /// down the library significantly.
        /// </summary>
        PopulateResultStack = 0x200000, /* WARNING: Force result stack traces
                                         *          to be populated right now.
                                         *          This will slow down the
                                         *          library significantly. */
        /// <summary>
        /// Force result stack traces to be included right now.  This will slow
        /// down the library significantly.
        /// </summary>
        IncludeResultStack = 0x400000,  /* WARNING: Force result stack traces
                                         *          to be included right now.
                                         *          This will slow down the
                                         *          library significantly. */
        /// <summary>
        /// Use the <c>-nocomplain</c> option to the <c>[debug break]</c>
        /// sub-command.
        /// </summary>
        NoComplain = 0x800000,          /* Use the -nocomplain option to the
                                         * [debug break] sub-command. */
        /// <summary>
        /// Use the <c>-noerror</c> option to the <c>[debug break]</c>
        /// sub-command.
        /// </summary>
        NoError = 0x1000000,            /* Use the -noerror option to the
                                         * [debug break] sub-command. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates flag values that are commonly used with instances of this
        /// enumeration.
        /// </summary>
        ForCommonUse = 0x2000000,       /* Used to indicate flag values that
                                         * are commonly used with instances
                                         * of this enumeration. */
        /// <summary>
        /// Indicates flag values that are commonly used when enabling the
        /// debugger.
        /// </summary>
        ForEnabledUse = 0x4000000,      /* Used to indicate flag values that
                                         * are commonly used when enabling
                                         * the debugger. */
        /// <summary>
        /// Indicates flag values that are commonly used when disabling the
        /// debugger.
        /// </summary>
        ForDisabledUse = 0x8000000,     /* Used to indicate flag values that
                                         * are commonly used when disabling
                                         * the debugger. */
        /// <summary>
        /// Indicates flag values that are commonly used when debugging a script
        /// on-demand.
        /// </summary>
        ForOverrideUse = 0x10000000,    /* Used to indicate flag values that
                                         * are commonly used when debugging
                                         * a script on-demand. */
        /// <summary>
        /// Indicates flag values that are used by default.
        /// </summary>
        ForDefaultUse = 0x20000000,     /* Used to indicate flag values that
                                         * are used by default. */
        /// <summary>
        /// Indicates flag values that are used with the special "now" value.
        /// </summary>
        ForNowUse = 0x40000000,         /* Used to indicate flag values that
                                         * are used with the special "now"
                                         * value. */
        /// <summary>
        /// Indicates flag values that are used with the special "later" value.
        /// </summary>
        ForLaterUse = 0x80000000,       /* Used to indicate flag values that
                                         * are used with the special "later"
                                         * value. */
        /// <summary>
        /// Indicates flag values that are used with the special "full" value.
        /// </summary>
        ForFullUse = 0x100000000,       /* Used to indicate flag values that
                                         * are used with the special "full"
                                         * value. */
        /// <summary>
        /// Indicates flag values that are used with the special "status" value.
        /// </summary>
        ForStatusUse = 0x200000000,     /* Used to indicate flag values that
                                         * are used with the special "status"
                                         * value. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags that bring the debugger into
        /// existence, namely <see cref="Enabled" /> and <see cref="Created" />.
        /// </summary>
        PositiveMask = Enabled | Created,
        /// <summary>
        /// Combination mask of the flags that tear down the debugger, namely
        /// <see cref="Disposed" /> and <see cref="Disabled" />.
        /// </summary>
        NegativeMask = Disposed | Disabled,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the reset flags <see cref="ResetCancel" /> and
        /// <see cref="ResetHalt" />.
        /// </summary>
        ResetMask = ResetCancel | ResetHalt,
        /// <summary>
        /// Combination mask of the result-stack flags
        /// <see cref="PopulateResultStack" /> and
        /// <see cref="IncludeResultStack" />.
        /// </summary>
        ResultStackMask = PopulateResultStack | IncludeResultStack,
        /// <summary>
        /// Combination mask of the flags used to query debugger status, namely
        /// <see cref="Tokens" />, <see cref="ScriptArguments" />,
        /// <see cref="Verbose" />, and <see cref="ResultStackMask" />.
        /// </summary>
        StatusMask = Tokens | ScriptArguments | Verbose | ResultStackMask,
        /// <summary>
        /// Combination mask of the flags used when breaking into the debugger,
        /// namely <see cref="Break" />, <see cref="IgnoreEnabled" />,
        /// <see cref="NoComplain" />, and <see cref="NoError" />.
        /// </summary>
        BreakMask = Break | IgnoreEnabled | NoComplain | NoError,
        /// <summary>
        /// Combination mask of the flags shared by both enabling and disabling
        /// the debugger, namely <see cref="StatusMask" />,
        /// <see cref="BreakMask" />, and <see cref="IgnoreModifiable" />.
        /// </summary>
        EnableOrDisableMask = StatusMask | BreakMask | IgnoreModifiable,
        /// <summary>
        /// Combination mask of <see cref="PositiveMask" /> and
        /// <see cref="EnableOrDisableMask" />.
        /// </summary>
        EnabledFlagsMask = PositiveMask | EnableOrDisableMask,
        /// <summary>
        /// Combination mask of <see cref="NegativeMask" /> and
        /// <see cref="EnableOrDisableMask" />.
        /// </summary>
        DisabledFlagsMask = NegativeMask | EnableOrDisableMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the recognized flag values, namely
        /// <see cref="EnabledFlagsMask" />, <see cref="DisabledFlagsMask" />,
        /// and <see cref="Isolated" />.
        /// </summary>
        FlagsMask = EnabledFlagsMask | DisabledFlagsMask | Isolated,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags commonly applied to every operation,
        /// namely <see cref="ForCommonUse" />, <see cref="ResetMask" />,
        /// <see cref="IgnoreModifiable" />, and <see cref="Quiet" />.
        /// </summary>
        CommonMask = ForCommonUse | ResetMask | IgnoreModifiable | Quiet,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ForEnabledUse" /> and
        /// <see cref="PositiveMask" />.
        /// </summary>
        EnabledMask = ForEnabledUse | PositiveMask,
        /// <summary>
        /// Combination mask of <see cref="ForDisabledUse" /> and
        /// <see cref="NegativeMask" />.
        /// </summary>
        DisabledMask = ForDisabledUse | NegativeMask,
        /// <summary>
        /// Combination mask of <see cref="ForOverrideUse" />,
        /// <see cref="PositiveMask" />, and <see cref="Break" />.
        /// </summary>
        OverrideMask = ForOverrideUse | PositiveMask | Break,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The flag set used to query debugger status, i.e. the combination of
        /// <see cref="ForStatusUse" /> and <see cref="StatusMask" />.
        /// </summary>
        Status = ForStatusUse | StatusMask,
        /// <summary>
        /// The flag set used to override the debugger on-demand, i.e. the
        /// combination of <see cref="ForOverrideUse" />,
        /// <see cref="CommonMask" />, and <see cref="OverrideMask" />.
        /// </summary>
        Override = ForOverrideUse | CommonMask | OverrideMask,
        /// <summary>
        /// The flag set used for the special "now" value, i.e. the combination
        /// of <see cref="ForNowUse" />, <see cref="CommonMask" />, and
        /// <see cref="EnabledMask" />.
        /// </summary>
        Now = ForNowUse | CommonMask | EnabledMask,
        /// <summary>
        /// The flag set used for the special "later" value, i.e. the
        /// combination of <see cref="ForLaterUse" />, <see cref="CommonMask" />,
        /// and <see cref="DisabledMask" />.
        /// </summary>
        Later = ForLaterUse | CommonMask | DisabledMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The flag set used for the special "full" value, combining
        /// <see cref="ForFullUse" />, <see cref="CommonMask" />,
        /// <see cref="Break" />, and <see cref="IgnoreEnabled" /> with the
        /// enabled flags except those in <see cref="BreakMask" />.
        /// </summary>
        Full = ForFullUse | CommonMask | Break | IgnoreEnabled |
               (EnabledFlagsMask & ~BreakMask),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default flag set, i.e. the combination of
        /// <see cref="ForDefaultUse" /> and <see cref="CommonMask" />.
        /// </summary>
        Default = ForDefaultUse | CommonMask
    }

