    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the various kinds of timeouts used
    /// throughout the TclTk core library, e.g. when acquiring locks, waiting on
    /// threads, evaluating scripts, or performing network operations.  Its
    /// values are bit flags that may be combined to select a timeout kind
    /// together with options that govern how its value is resolved.
    /// </summary>
    [Flags()]
    [ObjectId("c661b7a4-c315-4ed7-b790-ea7a3505ff8a")]
    public enum TimeoutType : ulong
    {
        /// <summary>
        /// No timeout type; this is implicit only and should not be used.
        /// </summary>
        None = 0x0,                   /* None, implicit only, do not use. */
        /// <summary>
        /// A reserved sentinel indicating an explicitly invalid timeout type;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,                /* Explicitly invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The fallback timeout, used when no other type of timeout directly
        /// applies.  Please do not use this in external code.
        /// </summary>
        Fallback = 0x10,              /* Fallback when no other type of
                                       * timeout directly applies. Please
                                       * do not use this in external code. */

        /// <summary>
        /// Used when attempting to acquire a lock on something, e.g. the
        /// interpreter, in a context where failing to acquire the lock will not
        /// result in errors.
        /// </summary>
        SoftLock = 0x20,              /* Used when attempting to acquire
                                       * a lock on something, e.g. the
                                       * interpreter, in a context where
                                       * failing to acquire the lock will
                                       * not result in errors. */

        /// <summary>
        /// Used when attempting to acquire a lock on something, e.g. the
        /// interpreter, in a context where failing to acquire the lock may
        /// result in an error.
        /// </summary>
        FirmLock = 0x40,              /* Used when attempting to acquire
                                       * a lock on something, e.g. the
                                       * interpreter, in a context where
                                       * failing to acquire the lock may
                                       * result in an error. */

        /// <summary>
        /// Used with interpreter readiness checks.
        /// </summary>
        Ready = 0x80,                 /* Used with interpreter readiness
                                       * checks. */

        /// <summary>
        /// Used primarily by the <c>ISynchronize.TryLockWithWait</c> method
        /// implementations.
        /// </summary>
        WaitLock = 0x100,             /* Used primarily by the method
                                       * ISynchronize.TryLockWithWait
                                       * implementations. */

        /// <summary>
        /// Used when attempting to acquire a lock on something, e.g. the
        /// interpreter, in a context where failing to acquire the lock will
        /// result in a serious error.
        /// </summary>
        HardLock = 0x200,             /* Used when attempting to acquire
                                       * a lock on something, e.g. the
                                       * interpreter, in a context where
                                       * failing to acquire the lock will
                                       * result in a serious error. */
        /// <summary>
        /// Used when attempting to acquire a lock on something from inside the
        /// engine.
        /// </summary>
        EngineLock = 0x400,           /* Used when attempting to acquire
                                       * a lock on something from inside
                                       * the engine. */
        /// <summary>
        /// Used when dealing with script events sent to the dedicated script
        /// event thread.  To avoid smashing runaway script errors from a
        /// script, the associated timeout value should be higher than the
        /// script timeout.
        /// </summary>
        Event = 0x800,                /* Used when dealing with script
                                       * events sent to the dedicated
                                       * script event thread.  To avoid
                                       * smashing runaway script errors
                                       * from a script, the associated
                                       * timeout value should be higher
                                       * than the script timeout. */

#if THREADING
        /// <summary>
        /// Used when dealing with the health checking thread.
        /// </summary>
        Health = 0x1000,              /* Used to dealing with the health
                                       * checking thread. */
#endif

        /// <summary>
        /// Used to avoid having runaway scripts.  Script evaluation will be
        /// canceled after the associated timeout value has elapsed.
        /// </summary>
        Script = 0x2000,              /* Used to avoid having runaway
                                       * scripts.  Script evaluation
                                       * will be canceled after the
                                       * associated timeout value has
                                       * elapsed. */

        /// <summary>
        /// Used when making sure a thread or process has been started.
        /// </summary>
        Start = 0x4000,               /* Used when making sure a thread
                                       * -OR- process has been started. */

        /// <summary>
        /// Used when making sure a thread has been interrupted.
        /// </summary>
        Interrupt = 0x8000,           /* Used when making sure a thread
                                       * has been interrupted. */

        /// <summary>
        /// Used when making sure a thread has exited.  Generally, the
        /// associated timeout value need not be too high because any pending
        /// scripts and/or other user-defined code should have already been
        /// canceled.
        /// </summary>
        Join = 0x10000,               /* Used when making sure a thread
                                       * has exited.  Generally, the
                                       * associated timeout value need
                                       * not be too high because any
                                       * pending scripts and/or other
                                       * user-defined code should have
                                       * already been canceled. */

        /// <summary>
        /// Used when making sure a process has exited.
        /// </summary>
        Exit = 0x20000,               /* Used when making sure a process
                                       * has exited. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Variable = 0x200000,          /* This is reserved for future
                                       * use. */

        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Setup = 0x400000,             /* This is reserved for future
                                       * use. */

        /// <summary>
        /// Reserved for future use.
        /// </summary>
        EventManager = 0x800000,      /* This is reserved for future
                                       * use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Used when contacting machines over a network.
        /// </summary>
        Network = 0x8000000,          /* Used when contacting machines
                                       * over a network. */

        /// <summary>
        /// Used for <c>[try]</c> finally script blocks.  The exact value used
        /// will depend on whether the target interpreter is "safe" or "unsafe".
        /// </summary>
        Finally = 0x10000000,         /* Used for [try] finally script
                                       * blocks.  The exact value used
                                       * will depend on whether the
                                       * target interpreter is "safe"
                                       * or "unsafe". */

        /// <summary>
        /// Used for <c>[try]</c> finally script blocks when an interpreter is
        /// "unsafe".
        /// </summary>
        UnsafeFinally = 0x20000000,   /* Used for [try] finally script
                                       * blocks when an interpreter is
                                       * "unsafe". */

        /// <summary>
        /// Used for <c>[try]</c> finally script blocks when an interpreter is
        /// "safe".
        /// </summary>
        SafeFinally = 0x40000000,     /* Used for [try] finally script
                                       * blocks when an interpreter is
                                       * "safe". */

        /// <summary>
        /// Used when disposing a thread or event of some kind.
        /// </summary>
        Dispose = 0x80000000,         /* Used when disposing a thread
                                       * -OR- event of some kind. */

        /// <summary>
        /// Used when the type of timeout is not recognized.
        /// </summary>
        Unknown = 0x100000000,        /* Used when the type of timeout
                                       * is not recognized. */

        /// <summary>
        /// The value of the fallback timeout of the interpreter.  Please do not
        /// use this in external code.
        /// </summary>
        Interpreter = 0x200000000,    /* Value of the fallback timeout
                                       * of interpreter.  Please do not
                                       * use this in external code. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow infinite timeouts.
        /// </summary>
        Infinite = 0x400000000,       /* Allow infinite timeouts. */

        /// <summary>
        /// The timeout value originated from outside of the core library.
        /// </summary>
        External = 0x800000000,       /* Timeout value originated from
                                       * outside of the core library. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Always enable use of the fallback timeout when a more specific one is
        /// not available.
        /// </summary>
        ForceFallback = 0x1000000000, /* Always enable use of the fallback
                                       * timeout when a more specific one
                                       * is not available. */

        /// <summary>
        /// Maybe enable use of the fallback timeout when a more specific one is
        /// not available, i.e. if its value is not null and finite.
        /// </summary>
        MaybeFallback = 0x2000000000, /* Maybe enable use of the fallback
                                       * timeout when a more specific one
                                       * is not available, i.e. -IF- its
                                       * value is not null -AND- finite. */

        /// <summary>
        /// Skip returning an error message.
        /// </summary>
        NoError = 0x4000000000,       /* Skip returning an error message. */

        /// <summary>
        /// Allow attempts to obtain a timeout value to fail, e.g. due to a
        /// locking error, etc.
        /// </summary>
        NoFailSafe = 0x8000000000,    /* Allow attempts to obtain a timeout
                                       * value to fail, e.g. due to a locking
                                       * error, etc. */

        /// <summary>
        /// Do not apply any detected or set multipliers against the resulting
        /// timeout value.
        /// </summary>
        NoMultiplier = 0x10000000000, /* Do not apply any detected or set
                                       * multipliers against the resulting
                                       * timeout value. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Legacy alias for <see cref="SoftLock" />, retained for
        /// compatibility.
        /// </summary>
        Lock = SoftLock,                /* COMPAT: TclTk beta. */
        /// <summary>
        /// Legacy alias for <see cref="UnsafeFinally" />, retained for
        /// compatibility.
        /// </summary>
        DefaultFinally = UnsafeFinally, /* COMPAT: TclTk beta. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the finally-related timeouts
        /// <see cref="Finally" />, <see cref="UnsafeFinally" />, and
        /// <see cref="SafeFinally" />.
        /// </summary>
        FinallyMask = Finally | UnsafeFinally | SafeFinally,
        /// <summary>
        /// Combination mask of the fallback-related flags
        /// <see cref="ForceFallback" /> and <see cref="MaybeFallback" />.
        /// </summary>
        FallbackMask = ForceFallback | MaybeFallback,
        /// <summary>
        /// Combination mask of the option flags that modify timeout resolution,
        /// namely <see cref="Infinite" />, <see cref="External" />,
        /// <see cref="FallbackMask" />, <see cref="NoError" />,
        /// <see cref="NoFailSafe" />, and <see cref="NoMultiplier" />.
        /// </summary>
        FlagsMask = Infinite | External | FallbackMask | NoError | NoFailSafe | NoMultiplier
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the various categories of flags that may
    /// be supplied when an interpreter is created. The values are bit
    /// flags that may be combined; each selects a particular group of
    /// creation, host, initialization, script, interpreter, plugin (and,
    /// optionally, native Tcl find and load) flags that a given operation
    /// should act upon.
    /// </summary>
    [Flags()]
    [ObjectId("99b147d8-cb56-40dc-a7ca-bc6ded108bad")]
    public enum CreationFlagTypes : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Operate on the current interpreter creation flags.
        /// </summary>
        CurrentCreateFlags = 0x10,
        /// <summary>
        /// Operate on the current host creation flags.
        /// </summary>
        CurrentHostCreateFlags = 0x20,
        /// <summary>
        /// Operate on the current initialization flags.
        /// </summary>
        CurrentInitializeFlags = 0x40,
        /// <summary>
        /// Operate on the current script flags.
        /// </summary>
        CurrentScriptFlags = 0x80,
        /// <summary>
        /// Operate on the current interpreter flags.
        /// </summary>
        CurrentInterpreterFlags = 0x100,
        /// <summary>
        /// Operate on the current interpreter test flags.
        /// </summary>
        CurrentInterpreterTestFlags = 0x200,
        /// <summary>
        /// Operate on the current plugin flags.
        /// </summary>
        CurrentPluginFlags = 0x400,

#if NATIVE && TCL
        /// <summary>
        /// Operate on the current native Tcl find flags.
        /// </summary>
        CurrentFindFlags = 0x800,
        /// <summary>
        /// Operate on the current native Tcl load flags.
        /// </summary>
        CurrentLoadFlags = 0x1000,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Operate on the default interpreter creation flags.
        /// </summary>
        DefaultCreateFlags = 0x10000,
        /// <summary>
        /// Operate on the default host creation flags.
        /// </summary>
        DefaultHostCreateFlags = 0x20000,
        /// <summary>
        /// Operate on the default initialization flags.
        /// </summary>
        DefaultInitializeFlags = 0x40000,
        /// <summary>
        /// Operate on the default script flags.
        /// </summary>
        DefaultScriptFlags = 0x80000,
        /// <summary>
        /// Operate on the default interpreter flags.
        /// </summary>
        DefaultInterpreterFlags = 0x100000,
        /// <summary>
        /// Operate on the default interpreter test flags.
        /// </summary>
        DefaultInterpreterTestFlags = 0x200000,
        /// <summary>
        /// Operate on the default plugin flags.
        /// </summary>
        DefaultPluginFlags = 0x400000,

#if NATIVE && TCL
        /// <summary>
        /// Operate on the default native Tcl find flags.
        /// </summary>
        DefaultFindFlags = 0x800000,
        /// <summary>
        /// Operate on the default native Tcl load flags.
        /// </summary>
        DefaultLoadFlags = 0x1000000,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Operate on the fallback interpreter creation flags.
        /// </summary>
        FallbackCreateFlags = 0x1000000,
        /// <summary>
        /// Operate on the fallback host creation flags.
        /// </summary>
        FallbackHostCreateFlags = 0x2000000,
        /// <summary>
        /// Operate on the fallback initialization flags.
        /// </summary>
        FallbackInitializeFlags = 0x4000000,
        /// <summary>
        /// Operate on the fallback script flags.
        /// </summary>
        FallbackScriptFlags = 0x8000000,
        /// <summary>
        /// Operate on the fallback interpreter flags.
        /// </summary>
        FallbackInterpreterFlags = 0x10000000,
        /// <summary>
        /// Operate on the fallback interpreter test flags.
        /// </summary>
        FallbackInterpreterTestFlags = 0x20000000,
        /// <summary>
        /// Operate on the fallback plugin flags.
        /// </summary>
        FallbackPluginFlags = 0x40000000,

#if NATIVE && TCL
        /// <summary>
        /// Operate on the fallback native Tcl find flags.
        /// </summary>
        FallbackFindFlags = 0x80000000,
        /// <summary>
        /// Operate on the fallback native Tcl load flags.
        /// </summary>
        FallbackLoadFlags = 0x100000000,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A flag reserved for future use.
        /// </summary>
        Reserved1 = 0x200000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The flags considered to be persistable settings: the current
        /// and default flag groups (excluding their create and host-create
        /// flags) combined with all of the fallback flags.
        /// </summary>
        SettingsFlags = (AllCurrentFlags & ~(CurrentCreateFlags | CurrentHostCreateFlags)) |
                        (AllDefaultFlags & ~(DefaultCreateFlags | DefaultHostCreateFlags)) |
                        AllFallbackFlags,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// The current native Tcl find flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeCurrentFindFlags = CurrentFindFlags,
        /// <summary>
        /// The current native Tcl load flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeCurrentLoadFlags = CurrentLoadFlags,
        /// <summary>
        /// The default native Tcl find flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeDefaultFindFlags = DefaultFindFlags,
        /// <summary>
        /// The default native Tcl load flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeDefaultLoadFlags = DefaultLoadFlags,
        /// <summary>
        /// The fallback native Tcl find flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeFallbackFindFlags = FallbackFindFlags,
        /// <summary>
        /// The fallback native Tcl load flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeFallbackLoadFlags = FallbackLoadFlags,
#else
        /// <summary>
        /// The current native Tcl find flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeCurrentFindFlags = None,
        /// <summary>
        /// The current native Tcl load flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeCurrentLoadFlags = None,
        /// <summary>
        /// The default native Tcl find flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeDefaultFindFlags = None,
        /// <summary>
        /// The default native Tcl load flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeDefaultLoadFlags = None,
        /// <summary>
        /// The fallback native Tcl find flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeFallbackFindFlags = None,
        /// <summary>
        /// The fallback native Tcl load flags when native Tcl support is
        /// compiled in; otherwise, no flags.
        /// </summary>
        MaybeFallbackLoadFlags = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the "current" flag groups, including
        /// the optional native Tcl find and load flags.
        /// </summary>
        AllCurrentFlags = CurrentCreateFlags | CurrentHostCreateFlags |
                          CurrentInitializeFlags | CurrentScriptFlags |
                          CurrentInterpreterFlags | CurrentInterpreterTestFlags |
                          CurrentPluginFlags | MaybeCurrentFindFlags |
                          MaybeCurrentLoadFlags,

        /// <summary>
        /// Combination mask of all of the "default" flag groups, including
        /// the optional native Tcl find and load flags.
        /// </summary>
        AllDefaultFlags = DefaultCreateFlags | DefaultHostCreateFlags |
                          DefaultInitializeFlags | DefaultScriptFlags |
                          DefaultInterpreterFlags | DefaultInterpreterTestFlags |
                          DefaultPluginFlags | MaybeDefaultFindFlags |
                          MaybeDefaultLoadFlags,

        /// <summary>
        /// Combination mask of all of the "fallback" flag groups,
        /// including the optional native Tcl find and load flags.
        /// </summary>
        AllFallbackFlags = FallbackCreateFlags | FallbackHostCreateFlags |
                           FallbackInitializeFlags | FallbackScriptFlags |
                           FallbackInterpreterFlags | FallbackInterpreterTestFlags |
                           FallbackPluginFlags | MaybeFallbackFindFlags |
                           MaybeFallbackLoadFlags,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default flags, consisting of all default flags together
        /// with <see cref="Reserved1" /> (and, on the .NET Standard 2.0
        /// build, the current host creation flags).
        /// </summary>
        Default = AllDefaultFlags |
#if NET_STANDARD_20
                  CurrentHostCreateFlags | /* HACK: Disable color for children, etc. */
#endif
                  Reserved1
    }

