    [Flags()]
    [ObjectId("9f719570-729f-4234-8282-0face8230536")]
    public enum TypeListFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Include the integer data types.
        /// </summary>
        IntegerTypes = 0x2,
        /// <summary>
        /// Include the floating-point data types.
        /// </summary>
        FloatTypes = 0x4,
        /// <summary>
        /// Include the string data types.
        /// </summary>
        StringTypes = 0x8,
        /// <summary>
        /// Include the numeric data types.
        /// </summary>
        NumberTypes = 0x10,
        /// <summary>
        /// Include the integral data types.
        /// </summary>
        IntegralTypes = 0x20,
        /// <summary>
        /// Include the non-integral data types.
        /// </summary>
        NonIntegralTypes = 0x40,
        /// <summary>
        /// Include any other, uncategorized data types.
        /// </summary>
        OtherTypes = 0x80,
        /// <summary>
        /// Include all available data types.
        /// </summary>
        AllTypes = 0x100
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how whitespace and other (possibly
    /// invisible) characters are detected, classified, or transformed when
    /// processing strings. The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("1bae8baa-330b-459a-a82f-97babf5c8c3f")]
    public enum WhiteSpaceFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Process the basic (ASCII) whitespace characters.
        /// </summary>
        Simple = 0x2,
        /// <summary>
        /// Process the extended (high) ASCII characters.
        /// </summary>
        Extended = 0x4, /* Use "Extended ASCII?" */
        /// <summary>
        /// Process the Unicode whitespace characters.
        /// </summary>
        Unicode = 0x8,
        /// <summary>
        /// Do not use arrow glyphs when representing characters.
        /// </summary>
        NoArrows = 0x10,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The null character.
        /// </summary>
        Null = 0x100,
        /// <summary>
        /// The bell (alert) character.
        /// </summary>
        Bell = 0x200,
        /// <summary>
        /// The backspace character.
        /// </summary>
        Backspace = 0x400,
        /// <summary>
        /// The horizontal tab character.
        /// </summary>
        HorizontalTab = 0x800,
        /// <summary>
        /// The line feed (newline) character.
        /// </summary>
        LineFeed = 0x1000,
        /// <summary>
        /// The vertical tab character.
        /// </summary>
        VerticalTab = 0x2000,
        /// <summary>
        /// The form feed character.
        /// </summary>
        FormFeed = 0x4000,
        /// <summary>
        /// The carriage return character.
        /// </summary>
        CarriageReturn = 0x8000,
        /// <summary>
        /// The space character.
        /// </summary>
        Space = 0x10000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Remove or replace any pre-existing extended and/or Unicode
        /// characters that may be present in the string.
        /// </summary>
        Clean = 0x20000, /* Remove or replace any pre-existing
                          * extended and/or Unicode characters
                          * that may be present in the string.
                          */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Whitespace handling intended for formatted output.
        /// </summary>
        ForFormatted = 0x40000,
        /// <summary>
        /// Whitespace handling intended for variable values.
        /// </summary>
        ForVariable = 0x80000,
        /// <summary>
        /// Whitespace handling intended for box drawing.
        /// </summary>
        ForBox = 0x100000,
        /// <summary>
        /// Whitespace handling intended for the test suite.
        /// </summary>
        ForTest = 0x200000,
        /// <summary>
        /// Whitespace handling intended for log output.
        /// </summary>
        ForLog = 0x400000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the invisible control characters: <see
        /// cref="Null" />, <see cref="Bell" />, <see cref="Backspace" />,
        /// <see cref="HorizontalTab" />, <see cref="LineFeed" />, <see
        /// cref="VerticalTab" />, <see cref="FormFeed" />, and <see
        /// cref="CarriageReturn" />.
        /// </summary>
        InvisibleCharactersMask = Null | Bell | Backspace |
                                  HorizontalTab | LineFeed | VerticalTab |
                                  FormFeed | CarriageReturn,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Technically, the space character is visible.
        //
        /// <summary>
        /// Combination mask of <see cref="InvisibleCharactersMask" /> and
        /// <see cref="Space" />; note that the space character is
        /// technically visible.
        /// </summary>
        AllCharactersMask = InvisibleCharactersMask | Space,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the usage flags <see cref="ForFormatted"
        /// />, <see cref="ForTest" />, <see cref="ForVariable" />, and
        /// <see cref="ForBox" />.
        /// </summary>
        ForMask = ForFormatted | ForTest | ForVariable | ForBox,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="InvisibleCharactersMask" /> and <see
        /// cref="ForFormatted" />, used when formatting output.
        /// </summary>
        FormattedUse = InvisibleCharactersMask | ForFormatted,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Simple" />, <see
        /// cref="InvisibleCharactersMask" />, and <see cref="ForVariable"
        /// />, used when processing variable values.
        /// </summary>
        VariableUse = Simple | InvisibleCharactersMask | ForVariable,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Extended" />, <see cref="Unicode" />,
        /// <see cref="InvisibleCharactersMask" />, and <see cref="ForBox"
        /// />, used when drawing boxes.
        /// </summary>
        BoxUse = Extended | Unicode | InvisibleCharactersMask | ForBox,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Extended" />, <see cref="Unicode" />,
        /// <see cref="AllCharactersMask" />, and <see cref="ForTest" />,
        /// used by the test suite.
        /// </summary>
        TestUse = Extended | Unicode | AllCharactersMask | ForTest,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Extended" />, <see cref="Unicode" />,
        /// <see cref="InvisibleCharactersMask" />, and <see cref="ForLog"
        /// />, used for log output.
        /// </summary>
        LogUse = Extended | Unicode | InvisibleCharactersMask | ForLog
    }

