    /// <summary>
    /// This enumeration controls how the core script library is detected,
    /// selecting which sources and version-numbering schemes are consulted
    /// during the search. The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("37766464-c48b-4fbf-b00f-5239d86c0583")]
    public enum DetectFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,                 /* Nothing. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,              /* Invalid, do not use. */
        /// <summary>
        /// Use the specified assembly as the basis of the core script
        /// library detection.
        /// </summary>
        Assembly = 0x2,             /* Use the specified assembly as the basis of
                                     * the core script library detection. */
        /// <summary>
        /// Use the process environment variables as the basis of the core
        /// script library detection.
        /// </summary>
        Environment = 0x4,          /* Use the process environment variables as the
                                     * basis the core script library detection. */
        /// <summary>
        /// Use the installed instance as the basis of the core script
        /// library detection.
        /// </summary>
        Setup = 0x8,                /* Use the installed instance as the basis of
                                     * the core script library detection. */
        /// <summary>
        /// Use the secondary name for the sub-directory containing the
        /// "lib" sub-directory.
        /// </summary>
        BaseDirectory = 0x10,       /* Use the secondary name for the sub-directory
                                     * containing the "lib" sub-directory. */
        /// <summary>
        /// Use the primary name for the sub-directory containing the "lib"
        /// sub-directory.
        /// </summary>
        Directory = 0x20,           /* Use the primary name for the sub-directory
                                     * containing the "lib" sub-directory. */
        /// <summary>
        /// Use the assembly name version number.
        /// </summary>
        AssemblyNameVersion = 0x40, /* Use the assembly name version number. */
        /// <summary>
        /// Use the assembly version number.
        /// </summary>
        AssemblyVersion = 0x80,     /* Use the assembly version number. */
        /// <summary>
        /// Use the package version number.
        /// </summary>
        PackageVersion = 0x100,     /* Use the package version number. */
        /// <summary>
        /// Try without any version number.
        /// </summary>
        NoVersion = 0x200,          /* Try without any version number. */
        /// <summary>
        /// Perform detection only, without changing any global state.
        /// </summary>
        DetectOnly = 0x400,         /* Do not change any global state. */
        /// <summary>
        /// Provide extra information to the caller upon failure.
        /// </summary>
        Verbose = 0x800,            /* Provide extra information to the caller
                                     * upon failure. */

        /// <summary>
        /// Combination mask of <see cref="Assembly" />, <see
        /// cref="Environment" />, <see cref="Setup" />, <see
        /// cref="BaseDirectory" />, <see cref="Directory" />, <see
        /// cref="AssemblyNameVersion" />, <see cref="AssemblyVersion" />,
        /// <see cref="PackageVersion" />, and <see cref="NoVersion" />.
        /// </summary>
        All = Assembly | Environment | Setup |
              BaseDirectory | Directory | AssemblyNameVersion |
              AssemblyVersion | PackageVersion | NoVersion,

        /// <summary>
        /// The default flags, equivalent to <see cref="All" />.
        /// </summary>
        Default = All
    }

