    /// <summary>
    /// This enumeration identifies the various kinds of packages known to
    /// TclTk. The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("9cb44f96-4dfe-4852-8f61-6046940d1758")]
    public enum PackageType
    {
        /// <summary>
        /// No package.
        /// </summary>
        None = 0x0,        /* No package. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,     /* Invalid, do not use. */
        /// <summary>
        /// The plugin loader package.
        /// </summary>
        Loader = 0x2,      /* The plugin loader package. */
        /// <summary>
        /// The script library package.
        /// </summary>
        Library = 0x4,     /* The script library package. */
        /// <summary>
        /// The test suite package.
        /// </summary>
        Test = 0x8,        /* The test suite package. */
        /// <summary>
        /// The kit packages.
        /// </summary>
        Kit = 0x10,        /* The kit packages. */
        /// <summary>
        /// A host-defined package.
        /// </summary>
        Host = 0x20,       /* Host-defined package. */
        /// <summary>
        /// A bundle-defined package.
        /// </summary>
        Bundle = 0x40,     /* Bundle-defined package. */
        /// <summary>
        /// Attempt to automatically determine the package type.
        /// </summary>
        Automatic = 0x80,  /* Attempt to automatically figure it out. */
        /// <summary>
        /// The default package type, for internal use only.
        /// </summary>
        Default = 0x100,   /* Default package, for internal use only. */

        /// <summary>
        /// Combination mask of <see cref="Loader" />, <see cref="Library"
        /// />, <see cref="Test" />, <see cref="Kit" />, <see cref="Host"
        /// />, <see cref="Bundle" />, and <see cref="Automatic" />.
        /// </summary>
        Mask = Loader | Library | Test | Kit | Host | Bundle | Automatic,

        /// <summary>
        /// Combination matching any known package type: <see cref="Loader"
        /// />, <see cref="Library" />, <see cref="Test" />, <see
        /// cref="Kit" />, <see cref="Host" />, and <see cref="Bundle" />.
        /// </summary>
        Any = Loader | Library | Test | Kit | Host | Bundle /* Any known package type will work. */
    }

