    /// <summary>
    /// This enumeration identifies the well-known character encodings used
    /// by the various subsystems of TclTk. The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("dad4b809-342f-4da3-b533-7acdc54bae9e")]
    public enum EncodingType
    {
        /// <summary>
        /// No encoding; do not use.
        /// </summary>
        None = 0x0,            /* None, do not use. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,         /* Invalid, do not use. */
        /// <summary>
        /// Always a null encoding.
        /// </summary>
        Null = 0x2,            /* Always null. */
        /// <summary>
        /// The system encoding (Unicode).
        /// </summary>
        System = 0x4,          /* Unicode */
        /// <summary>
        /// The default encoding (UTF-8).
        /// </summary>
        Default = 0x8,         /* UTF-8 */
        /// <summary>
        /// The binary encoding (one byte per character).
        /// </summary>
        Binary = 0x10,         /* OneByte */
        /// <summary>
        /// The encoding used by Tcl (ISO-8859-1).
        /// </summary>
        Tcl = 0x20,            /* ISO-8859-1 */
        /// <summary>
        /// The default channel encoding (ISO-8859-1).
        /// </summary>
        Channel = 0x40,        /* ISO-8859-1 */
        /// <summary>
        /// The encoding used for text (UTF-8).
        /// </summary>
        Text = 0x80,           /* UTF-8 */
        /// <summary>
        /// The encoding used for scripts (UTF-8).
        /// </summary>
        Script = 0x100,        /* UTF-8 */
        /// <summary>
        /// The encoding used for XML (UTF-8).
        /// </summary>
        Xml = 0x200,           /* UTF-8 */
        /// <summary>
        /// The encoding used for policies (UTF-8).
        /// </summary>
        Policy = 0x400,        /* UTF-8 */
        /// <summary>
        /// The encoding used for profiles (UTF-8).
        /// </summary>
        Profile = 0x800,       /* UTF-8 */
        /// <summary>
        /// The encoding used for syntax data (UTF-8).
        /// </summary>
        Syntax = 0x1000,       /* UTF-8 */

#if HISTORY
        /// <summary>
        /// The encoding used for command history (UTF-8).
        /// </summary>
        History = 0x10000,     /* UTF-8 */
#endif

        /// <summary>
        /// The encoding used for Base64 data (UTF-8).
        /// </summary>
        Base64 = 0x20000,      /* UTF-8 */
        /// <summary>
        /// The encoding used for remote URIs (UTF-8).
        /// </summary>
        RemoteUri = 0x40000,   /* UTF-8 */
        /// <summary>
        /// The encoding used for URIs of unknown origin (UTF-8).
        /// </summary>
        UnknownUri = 0x80000,  /* UTF-8 */
        /// <summary>
        /// The encoding used for the file system (UTF-8).
        /// </summary>
        FileSystem = 0x100000, /* UTF-8 */
        /// <summary>
        /// The encoding used for snippets (UTF-8).
        /// </summary>
        Snippet = 0x200000     /* UTF-8 */
    }

