    //
    // WARNING: Values may be added, modified, or removed from this enumeration
    //          at any time.
    //
    /// <summary>
    /// This enumeration controls the operations performed on TclTk's
    /// various internal caches, selecting which caches to act upon and
    /// what action (such as trimming, locking, resetting, or clearing) to
    /// take. The values are bit flags that may be combined. Note that
    /// values may be added, modified, or removed from this enumeration at
    /// any time.
    /// </summary>
    [Flags()]
    [ObjectId("7642aad2-c1d7-4ac5-80d0-f5e2d1db9bbf")]
    public enum CacheFlags : ulong
    {
        /// <summary>
        /// Nothing; no flags are set.
        /// </summary>
        None = 0x0,                   /* Nothing. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,                /* Invalid, do not use. */
        /// <summary>
        /// Operate on the Argument object cache.
        /// </summary>
        Argument = 0x2,               /* Operate on the Argument object cache. */
        /// <summary>
        /// Operate on the StringList cache.
        /// </summary>
        StringList = 0x4,             /* Operate on the StringList cache. */
        /// <summary>
        /// Operate on the IParseState cache.
        /// </summary>
        IParseState = 0x8,            /* Operate on the IParseState cache. */
        /// <summary>
        /// Operate on the IExecute cache.
        /// </summary>
        IExecute = 0x10,              /* Operate on the IExecute cache. */
        /// <summary>
        /// Operate on the Type cache.
        /// </summary>
        Type = 0x20,                  /* Operate on the Type cache. */
        /// <summary>
        /// Operate on the COM TypeList cache.
        /// </summary>
        ComTypeList = 0x40,           /* Operate on the COM TypeList cache. */
        /// <summary>
        /// Operate on StringBuilder-related state, per AppDomain.
        /// </summary>
        StringBuilder = 0x80,         /* SPECIAL: Operate on StringBuilder
                                       *          related state, per AppDomain. */
        /// <summary>
        /// Operate on the StringBuilder cache, per AppDomain.
        /// </summary>
        StringBuilderCache = 0x100,   /* SPECIAL: Operate on StringBuilder
                                       *          cache, per AppDomain. */
        /// <summary>
        /// Operate on the StringBuilder factory, per AppDomain.
        /// </summary>
        StringBuilderFactory = 0x200, /* SPECIAL: Operate on StringBuilder
                                       *          factory, per AppDomain. */
        /// <summary>
        /// Operate on other, internal caches.
        /// </summary>
        Miscellaneous = 0x400,        /* Operate on other, internal caches. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A magical hidden flag; do not use.
        /// </summary>
        Hidden = 0x800,          /* Magical hidden flag, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Forcibly trim the specified caches if necessary, ignoring any
        /// limits on how many items may be trimmed at once.
        /// </summary>
        ForceTrim = 0x1000,       /* Forcibly trim the specified caches if necessary,
                                   * ignoring any limits on how many items may be
                                   * trimmed at once. */
        /// <summary>
        /// Unlock the specified caches.
        /// </summary>
        Unlock = 0x2000,          /* Unlock the specified caches. */
        /// <summary>
        /// Lock the specified caches.
        /// </summary>
        Lock = 0x4000,            /* Lock the specified caches. */
        /// <summary>
        /// When locking a cache, disable it as well.
        /// </summary>
        DisableOnLock = 0x8000,   /* When locking a cache, disable it as well. */
        /// <summary>
        /// Create the specified caches if necessary and reset their
        /// settings back to their originally configured values.
        /// </summary>
        Reset = 0x10000,          /* Create the specified caches if necessary -AND-
                                   * reset their settings back to their originally
                                   * configured values. */
        /// <summary>
        /// Empty the specified caches.
        /// </summary>
        Clear = 0x20000,          /* Empty the specified caches. */
        /// <summary>
        /// Initialize the caches, again if necessary.
        /// </summary>
        PreSetup = 0x40000,       /* Initialize the caches, again if need. */
        /// <summary>
        /// Force all subsystems to be fully cleared.
        /// </summary>
        FullClear = 0x80000,      /* Force all subsystems fully cleared. */
        /// <summary>
        /// Do not advance the cache generation counter.
        /// </summary>
        NoGeneration = 0x100000,  /* Force all subsystems fully cleared. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CACHE_DICTIONARY
        /// <summary>
        /// Configure various properties of the caches.
        /// </summary>
        SetProperties = 0x200000, /* Configure various properties of the caches. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CACHE_STATISTICS
        /// <summary>
        /// When resetting the cache, keep its counts.
        /// </summary>
        KeepCounts = 0x400000,    /* When resetting the cache, keep its counts. */
        /// <summary>
        /// When resetting the cache, zero its counts.
        /// </summary>
        ZeroCounts = 0x800000,    /* When resetting the cache, zero its counts. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used to enable more aggressive trimming
        //       of the associated cache, when appropriate (typically when
        //       under heavy load).
        //
        /// <summary>
        /// Aggressively trim the Argument cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ForceTrimArgument = 0x1000000,
        /// <summary>
        /// Aggressively trim the StringList cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ForceTrimStringList = 0x2000000,
        /// <summary>
        /// Aggressively trim the IParseState cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ForceTrimIParseState = 0x4000000,
        /// <summary>
        /// Aggressively trim the IExecute cache when appropriate
        /// (typically under heavy load) (not yet implemented).
        /// </summary>
        ForceTrimIExecute = 0x8000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Aggressively trim the Type cache when appropriate (typically
        /// under heavy load).
        /// </summary>
        ForceTrimType = 0x10000000,
        /// <summary>
        /// Aggressively trim the COM TypeList cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ForceTrimComTypeList = 0x20000000,
        /// <summary>
        /// Aggressively trim the StringBuilder cache when appropriate
        /// (typically under heavy load) (not yet implemented).
        /// </summary>
        ForceTrimStringBuilder = 0x40000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Aggressively trim the miscellaneous caches when appropriate
        /// (typically under heavy load) (not yet implemented).
        /// </summary>
        ForceTrimMiscellaneous = 0x80000000, /* NOT YET IMPLEMENTED */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used to prevent the automatic enabling,
        //       disabling, or clearing of the associated cache, when it
        //       would have been appropriate (typically when under heavy
        //       load).
        //
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// Argument cache when it would otherwise be appropriate.
        /// </summary>
        LockArgument = 0x100000000,
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// StringList cache when it would otherwise be appropriate.
        /// </summary>
        LockStringList = 0x200000000,
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// IParseState cache when it would otherwise be appropriate.
        /// </summary>
        LockIParseState = 0x400000000,
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// IExecute cache when it would otherwise be appropriate (not yet
        /// implemented).
        /// </summary>
        LockIExecute = 0x800000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// Type cache when it would otherwise be appropriate.
        /// </summary>
        LockType = 0x1000000000,
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// COM TypeList cache when it would otherwise be appropriate.
        /// </summary>
        LockComTypeList = 0x2000000000,
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// StringBuilder cache when it would otherwise be appropriate (not
        /// yet implemented).
        /// </summary>
        LockStringBuilder = 0x4000000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Prevent the automatic enabling, disabling, or clearing of the
        /// miscellaneous caches when it would otherwise be appropriate
        /// (not yet implemented).
        /// </summary>
        LockMiscellaneous = 0x8000000000, /* NOT YET IMPLEMENTED */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used to automatically create the
        //       associated cache -AND- reset its settings back to
        //       the originally configured values when appropriate
        //       (typically when under heavy load).
        //
        /// <summary>
        /// Automatically create the Argument cache and reset its settings
        /// back to the originally configured values when appropriate.
        /// </summary>
        ResetArgument = 0x10000000000,
        /// <summary>
        /// Automatically create the StringList cache and reset its
        /// settings back to the originally configured values when
        /// appropriate.
        /// </summary>
        ResetStringList = 0x20000000000,
        /// <summary>
        /// Automatically create the IParseState cache and reset its
        /// settings back to the originally configured values when
        /// appropriate.
        /// </summary>
        ResetIParseState = 0x40000000000,
        /// <summary>
        /// Automatically create the IExecute cache and reset its settings
        /// back to the originally configured values when appropriate.
        /// </summary>
        ResetIExecute = 0x80000000000,
        /// <summary>
        /// Automatically create the Type cache and reset its settings back
        /// to the originally configured values when appropriate.
        /// </summary>
        ResetType = 0x100000000000,
        /// <summary>
        /// Automatically create the COM TypeList cache and reset its
        /// settings back to the originally configured values when
        /// appropriate.
        /// </summary>
        ResetComTypeList = 0x200000000000,
        /// <summary>
        /// Automatically create the StringBuilder cache and reset its
        /// settings back to the originally configured values when
        /// appropriate (not yet implemented).
        /// </summary>
        ResetStringBuilder = 0x400000000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Automatically create the miscellaneous caches and reset its
        /// settings back to the originally configured values when
        /// appropriate (not yet implemented).
        /// </summary>
        ResetMiscellaneous = 0x800000000000, /* NOT YET IMPLEMENTED */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used to automatically clear the
        //       associated cache when appropriate (typically when
        //       under heavy load).
        //
        /// <summary>
        /// Automatically clear the Argument cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ClearArgument = 0x1000000000000,
        /// <summary>
        /// Automatically clear the StringList cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ClearStringList = 0x2000000000000,
        /// <summary>
        /// Automatically clear the IParseState cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ClearIParseState = 0x4000000000000,
        /// <summary>
        /// Automatically clear the IExecute cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ClearIExecute = 0x8000000000000,
        /// <summary>
        /// Automatically clear the Type cache when appropriate (typically
        /// under heavy load).
        /// </summary>
        ClearType = 0x10000000000000,
        /// <summary>
        /// Automatically clear the COM TypeList cache when appropriate
        /// (typically under heavy load).
        /// </summary>
        ClearComTypeList = 0x20000000000000,
        /// <summary>
        /// Automatically clear the StringBuilder cache when appropriate
        /// (typically under heavy load) (not yet implemented).
        /// </summary>
        ClearStringBuilder = 0x40000000000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Automatically clear the miscellaneous caches when appropriate
        /// (typically under heavy load) (not yet implemented).
        /// </summary>
        ClearMiscellaneous = 0x80000000000000, /* NOT YET IMPLEMENTED */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags represent the various origins of the
        //       data used to fetch (or create) cached arguments.
        //       By default, they are currently all enabled.  It
        //       is now possible to disable one or more origins
        //       by changing the cache flags for the interpreter,
        //       which may improve performance in some rare use
        //       cases.
        //
        /// <summary>
        /// Fetch or create cached arguments that originate from a result.
        /// </summary>
        ForResult = 0x100000000000000,
        /// <summary>
        /// Fetch or create cached arguments that originate from a result
        /// with location information.
        /// </summary>
        ForResultWithLocation = 0x200000000000000,
        /// <summary>
        /// Fetch or create cached arguments that originate from a variant.
        /// </summary>
        ForVariant = 0x400000000000000,
        /// <summary>
        /// Fetch or create cached arguments that originate from a
        /// procedure.
        /// </summary>
        ForProcedure = 0x800000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="IExecute" /> and <see cref="Hidden"
        /// />.
        /// </summary>
        HiddenIExecute = IExecute | Hidden,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CACHE_DICTIONARY
        /// <summary>
        /// The cache property-configuration flag when the cache dictionary
        /// is compiled in; otherwise, no flags.
        /// </summary>
        MaybeSetProperties = SetProperties,
#else
        /// <summary>
        /// The cache property-configuration flag when the cache dictionary
        /// is compiled in; otherwise, no flags.
        /// </summary>
        MaybeSetProperties = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CACHE_STATISTICS
        /// <summary>
        /// The keep-counts flag when cache statistics are compiled in;
        /// otherwise, no flags.
        /// </summary>
        MaybeKeepCounts = KeepCounts,
        /// <summary>
        /// The zero-counts flag when cache statistics are compiled in;
        /// otherwise, no flags.
        /// </summary>
        MaybeZeroCounts = ZeroCounts,
#else
        /// <summary>
        /// The keep-counts flag when cache statistics are compiled in;
        /// otherwise, no flags.
        /// </summary>
        MaybeKeepCounts = None,
        /// <summary>
        /// The zero-counts flag when cache statistics are compiled in;
        /// otherwise, no flags.
        /// </summary>
        MaybeZeroCounts = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the object caches: <see cref="Argument" />,
        /// <see cref="StringList" />, <see cref="IParseState" />, <see
        /// cref="IExecute" />, <see cref="Type" />, and <see
        /// cref="ComTypeList" />.
        /// </summary>
        ObjectMask = Argument | StringList | IParseState |
                     IExecute | Type | ComTypeList,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if false
        //
        // TODO: In the future, perhaps make this the default,
        //       which would have the effect of enabling the
        //       StringBuilder cache by default.
        //
        /// <summary>
        /// Combination mask of the non-object caches that also enables the
        /// <see cref="StringBuilder" /> cache; reserved as a possible future
        /// default (see the preceding note).
        /// </summary>
        OtherMask = StringBuilder | Miscellaneous,
#else
        /// <summary>
        /// Combination mask of the other, non-object caches; currently
        /// just <see cref="Miscellaneous" />.
        /// </summary>
        OtherMask = Miscellaneous,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ForResult" />, <see
        /// cref="ForResultWithLocation" />, <see cref="ForVariant" />, and
        /// <see cref="ForProcedure" />.
        /// </summary>
        ForMask = ForResult | ForResultWithLocation | ForVariant |
                  ForProcedure,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the action and behavior flags: <see
        /// cref="Hidden" />, <see cref="ForceTrim" />, <see cref="Unlock"
        /// />, <see cref="Lock" />, <see cref="DisableOnLock" />, <see
        /// cref="Reset" />, <see cref="Clear" />, <see cref="PreSetup" />,
        /// <see cref="MaybeSetProperties" />, <see cref="MaybeKeepCounts"
        /// />, and <see cref="MaybeZeroCounts" />.
        /// </summary>
        FlagMask = Hidden | ForceTrim | Unlock | Lock |
                   DisableOnLock | Reset | Clear | PreSetup |
                   MaybeSetProperties | MaybeKeepCounts | MaybeZeroCounts,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the force-trim flags.
        /// </summary>
        ForceTrimMask = ForceTrimArgument | ForceTrimStringList | ForceTrimIParseState |
                        ForceTrimIExecute | ForceTrimType | ForceTrimComTypeList |
                        ForceTrimStringBuilder | ForceTrimMiscellaneous,

        /// <summary>
        /// Combination mask of all of the lock flags.
        /// </summary>
        LockMask = LockArgument | LockStringList | LockIParseState |
                   LockIExecute | LockType | LockComTypeList |
                   LockStringBuilder | LockMiscellaneous,

        /// <summary>
        /// Combination mask of all of the reset flags.
        /// </summary>
        ResetMask = ResetArgument | ResetStringList | ResetIParseState |
                    ResetIExecute | ResetType | ResetComTypeList |
                    ResetStringBuilder | ResetMiscellaneous,

        /// <summary>
        /// Combination mask of all of the clear flags.
        /// </summary>
        ClearMask = ClearArgument | ClearStringList | ClearIParseState |
                    ClearIExecute | ClearType | ClearComTypeList |
                    ClearStringBuilder | ClearMiscellaneous,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="ForceTrimArgument" />, <see
        /// cref="ForceTrimStringList" />, and <see
        /// cref="ForceTrimIParseState" />; the force-trim flags enabled by
        /// default.
        /// </summary>
        DefaultForceTrimMask = ForceTrimArgument | ForceTrimStringList |
                               ForceTrimIParseState,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // HACK: Do not automatically clear the StringList cache when
        //       under heavy load because it is *very* expensive to
        //       refill.
        //
        /// <summary>
        /// The clear flags enabled by default: <see cref="ClearMask" />
        /// excluding <see cref="ClearStringList" />, because the
        /// StringList cache is very expensive to refill.
        /// </summary>
        DefaultClearMask = ClearMask & ~ClearStringList,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The caches typically operated upon: <see cref="ObjectMask" />
        /// combined with <see cref="OtherMask" />, excluding <see
        /// cref="Miscellaneous" />.
        /// </summary>
        TypicalMask = (ObjectMask | OtherMask) & ~Miscellaneous,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // TODO: Are these good defaults?
        //
        /// <summary>
        /// The default set of cache flags, combining <see
        /// cref="TypicalMask" />, <see cref="Miscellaneous" />, <see
        /// cref="ForMask" />, <see cref="DefaultForceTrimMask" />, <see
        /// cref="ResetMask" />, <see cref="DefaultClearMask" />, <see
        /// cref="MaybeSetProperties" />, and <see cref="MaybeKeepCounts"
        /// />.
        /// </summary>
        Default = TypicalMask | Miscellaneous | ForMask |
                  DefaultForceTrimMask | ResetMask |
                  DefaultClearMask | MaybeSetProperties |
                  MaybeKeepCounts
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how the interpreter host locates and
    /// opens a stream (for example, a script file), selecting which
    /// assemblies and/or the file system are searched, and recording where
    /// a stream was ultimately found. The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("1938facf-a73c-43d6-82d3-95a6d6cd0b63")]
    public enum HostStreamFlags
    {
        /// <summary>
        /// No special handling; no flags are set.
        /// </summary>
        None = 0x0,                  /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */
        /// <summary>
        /// Check the loaded plugins for the stream.
        /// </summary>
        LoadedPlugins = 0x2,         /* Check loaded plugins for the stream. */
        /// <summary>
        /// Check the calling assembly for the stream (not used).
        /// </summary>
        CallingAssembly = 0x4,       /* NOT USED: Check the calling assembly for the stream. */
        /// <summary>
        /// Check the entry assembly for the stream.
        /// </summary>
        EntryAssembly = 0x8,         /* Check the entry assembly for the stream. */
        /// <summary>
        /// Check the executing assembly for the stream.
        /// </summary>
        ExecutingAssembly = 0x10,    /* Check the executing assembly for the stream. */
        /// <summary>
        /// Resolve the file name to a fully qualified path.
        /// </summary>
        ResolveFullPath = 0x20,      /* Resolve the file name to a fully qualified path. */
        /// <summary>
        /// The returned resolved full path should include the assembly
        /// location.
        /// </summary>
        AssemblyQualified = 0x40,    /* The returned resolved full path should include
                                      * the assembly location. */
        /// <summary>
        /// Check the file system before checking any assemblies.
        /// </summary>
        PreferFileSystem = 0x80,     /* Check the file system before checking any
                                      * assemblies. */
        /// <summary>
        /// Skip checking the file system.
        /// </summary>
        SkipFileSystem = 0x100,      /* Skip checking the file system. */
        /// <summary>
        /// The request originates from the script engine.
        /// </summary>
        Script = 0x200,              /* From the script engine, etc. */
        /// <summary>
        /// The request originates from the <c>[open]</c> command.
        /// </summary>
        Open = 0x400,                /* From the [open] command, etc. */
        /// <summary>
        /// The stream was opened from a plugin assembly resource.
        /// </summary>
        FoundViaPlugin = 0x800,      /* Stream was opened from an assembly resource. */
        /// <summary>
        /// The stream was opened from an assembly resource.
        /// </summary>
        FoundViaAssembly = 0x1000,   /* Stream was opened from an assembly resource. */
        /// <summary>
        /// The stream was opened from the file system.
        /// </summary>
        FoundViaFileSystem = 0x2000, /* Stream was opened from the file system. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ResolveFullPath" />, <see
        /// cref="AssemblyQualified" />, <see cref="PreferFileSystem" />,
        /// and <see cref="SkipFileSystem" />.
        /// </summary>
        OptionMask = ResolveFullPath | AssemblyQualified | PreferFileSystem | SkipFileSystem,
        /// <summary>
        /// Combination mask of <see cref="CallingAssembly" />, <see
        /// cref="EntryAssembly" />, and <see cref="ExecutingAssembly" />.
        /// </summary>
        AssemblyMask = CallingAssembly | EntryAssembly | ExecutingAssembly,
        /// <summary>
        /// Combination mask of <see cref="FoundViaPlugin" />, <see
        /// cref="FoundViaAssembly" />, and <see cref="FoundViaFileSystem"
        /// />.
        /// </summary>
        FoundMask = FoundViaPlugin | FoundViaAssembly | FoundViaFileSystem,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default flags, equivalent to <see cref="None" />.
        /// </summary>
        Default = None,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Default" />, <see
        /// cref="ResolveFullPath" />, and <see cref="Script" />, used by
        /// the script engine.
        /// </summary>
        EngineScript = Default | ResolveFullPath | Script,
        /// <summary>
        /// Combination of <see cref="Default" /> and <see cref="Open" />,
        /// used by the <c>[open]</c> command.
        /// </summary>
        OpenCommand = Default | Open
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if NETWORK
    /// <summary>
    /// This enumeration defines the set of bit flags that control how the
    /// integrated web and network helper methods transfer data; the flags
    /// select the HTTP method, the form that the request and response data
    /// should take, and whether the transfer is performed asynchronously.
    /// The values are bit flags and may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("feb7100f-2e62-4f5d-b879-56272ff728cc")]
    public enum WebFlags : ulong
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,             /* No special handling. */
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,          /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates the transfer uses the GET method and that the script
        /// engine intends to read a script file from the response.
        /// </summary>
        Open = 0x100,           /* This flag implies the method is GET
                                 * -AND- that the script engine is going
                                 * to read a script file. */
        /// <summary>
        /// Indicates a download transfer, which implies the GET method.
        /// </summary>
        Download = 0x200,       /* This flag implies the method is GET. */
        /// <summary>
        /// Indicates an upload transfer, which implies the POST method.
        /// </summary>
        Upload = 0x400,         /* This flag implies the method is POST. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The response should be returned as a string.
        /// </summary>
        String = 0x1000,        /* The response should be a String. */
        /// <summary>
        /// The response should be returned as a stream object that the
        /// caller may read from or write to, depending on the operation.
        /// </summary>
        Stream = 0x2000,        /* The response should be a Stream object
                                 * that can be read from -OR- writen to,
                                 * depending on the caller. */
        /// <summary>
        /// The request or response should be a sequence of raw bytes.
        /// </summary>
        Data = 0x4000,          /* The request or response should be a
                                 * sequence of bytes. */
        /// <summary>
        /// The request or response data should be read from or written to
        /// the specified file.
        /// </summary>
        File = 0x8000,          /* The request or response should be
                                 * data written to the specified file. */
        /// <summary>
        /// The request or response should be expressed as a collection of
        /// name/value pairs.
        /// </summary>
        Values = 0x10000,       /* The request or response should be
                                 * name / value pairs. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The transfer should be performed asynchronously.
        /// </summary>
        Asynchronous = 0x100000, /* The transfer(s) should be performed
                                  * asynchronously. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The transfer is being performed through the special MakeRequest
        /// method.
        /// </summary>
        MakeRequest = 0x10000000, /* The transfer is being done via the
                                   * (special) MakeRequest method. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Open" /> and <see cref="Stream" />,
        /// used to read a script file as a stream.
        /// </summary>
        OpenScriptStream = Open | Stream,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Download" /> and <see cref="Data" />,
        /// used to download raw bytes.
        /// </summary>
        DownloadData = Download | Data,
        /// <summary>
        /// Combination of <see cref="Download" />, <see cref="Data" />,
        /// and <see cref="Asynchronous" />, used to download raw bytes
        /// asynchronously.
        /// </summary>
        DownloadDataAsynchronous = Download | Data | Asynchronous,

        /// <summary>
        /// Combination of <see cref="Download" /> and <see cref="File" />,
        /// used to download to a file.
        /// </summary>
        DownloadFile = Download | File,
        /// <summary>
        /// Combination of <see cref="Download" />, <see cref="File" />,
        /// and <see cref="Asynchronous" />, used to download to a file
        /// asynchronously.
        /// </summary>
        DownloadFileAsynchronous = Download | File | Asynchronous,

        /// <summary>
        /// Combination of <see cref="Upload" /> and <see cref="Data" />,
        /// used to upload raw bytes.
        /// </summary>
        UploadData = Upload | Data,
        /// <summary>
        /// Combination of <see cref="Upload" />, <see cref="Data" />, and
        /// <see cref="Asynchronous" />, used to upload raw bytes
        /// asynchronously.
        /// </summary>
        UploadDataAsynchronous = Upload | Data | Asynchronous,

        /// <summary>
        /// Combination of <see cref="Upload" /> and <see cref="Values" />,
        /// used to upload name/value pairs.
        /// </summary>
        UploadValues = Upload | Values,
        /// <summary>
        /// Combination of <see cref="Upload" />, <see cref="Values" />,
        /// and <see cref="Asynchronous" />, used to upload name/value
        /// pairs asynchronously.
        /// </summary>
        UploadValuesAsynchronous = Upload | Values | Asynchronous,

        /// <summary>
        /// Combination of <see cref="Upload" /> and <see cref="File" />,
        /// used to upload a file.
        /// </summary>
        UploadFile = Upload | File,
        /// <summary>
        /// Combination of <see cref="Upload" />, <see cref="File" />, and
        /// <see cref="Asynchronous" />, used to upload a file
        /// asynchronously.
        /// </summary>
        UploadFileAsynchronous = Upload | File | Asynchronous
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the high-level action to be performed by
    /// the update subsystem when checking for, fetching, or applying a new
    /// release of TclTk.
    /// </summary>
    [ObjectId("e24c641b-f0fe-4e52-b5f5-31a80acbbf52")]
    public enum ActionType
    {
        /// <summary>
        /// Take no action.
        /// </summary>
        None = 0x0,                      /* do nothing. */
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,                   /* invalid, do not use. */
        /// <summary>
        /// Check whether an update is available, without downloading it.
        /// </summary>
        CheckForUpdate = 0x2,            /* check for an update; however, do not
                                          * download it. */
        /// <summary>
        /// Check for an update and download it if one is necessary.
        /// </summary>
        FetchUpdate = 0x4,               /* check for an update and download it
                                          * if necessary. */
        /// <summary>
        /// Run the external update tool and then exit the current process.
        /// </summary>
        RunUpdateAndExit = 0x8,          /* run the external update tool and then
                                          * exit. */
        /// <summary>
        /// Download the update and extract it into the specified
        /// directory.
        /// </summary>
        DownloadAndExtractUpdate = 0x10, /* download the update and extract it to
                                          * the specified directory. */

        /// <summary>
        /// The default action, equivalent to <see cref="CheckForUpdate"
        /// />.
        /// </summary>
        Default = CheckForUpdate
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the kind of write operation being
    /// performed against an interpreter host, allowing the host to route
    /// or format the output appropriately.
    /// </summary>
    [ObjectId("fd610430-d4f3-4525-b72a-e5746136884f")]
    public enum HostWriteType
    {
        /// <summary>
        /// No write type is specified.
        /// </summary>
        None = 0,
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 1,
        /// <summary>
        /// A normal output write.
        /// </summary>
        Normal = 2,
        /// <summary>
        /// A write of debugging output.
        /// </summary>
        Debug = 3,
        /// <summary>
        /// A write of error output.
        /// </summary>
        Error = 4,
        /// <summary>
        /// A flush of any buffered output only, with no accompanying
        /// write.
        /// </summary>
        Flush = 5, /* Flush() only, no Write*(). */

        //
        // NOTE: External callers (i.e. those calling from outside of the core
        //       library) must NOT rely on the semantics of the "Default" value
        //       here.
        //
        /// <summary>
        /// The default write type, equivalent to <see cref="Normal" />.
        /// External callers must not rely on the semantics of this value.
        /// </summary>
        Default = Normal
    }

