    /// <summary>
    /// This enumeration provides the reserved sentinel values used when
    /// specifying host console colors.
    /// </summary>
    [ObjectId("07486dfd-5b8b-41f1-ada1-264f908f0a3d")]
    public enum HostColor
    {
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = -2,
        /// <summary>
        /// Indicates that no specific color is selected.
