        None = -1
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that control how base-26
    /// encoded text is formatted.  The values are bit flags and may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("927338b0-c8d2-459d-9188-c85baf807990")]
    public enum Base26FormattingOption
    {
        /// <summary>
        /// No formatting options are applied.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Insert a line break after every 74 characters.
        /// </summary>
        InsertLineBreaks = 0x1, // line break every 74 characters.
        /// <summary>
        /// Insert a single space after every two characters.
        /// </summary>
        InsertSpaces = 0x2,     // insert one space every 2 characters.

        /// <summary>
        /// The default formatting, a combination of <see
        /// cref="InsertLineBreaks" /> and <see cref="InsertSpaces" />.
        /// </summary>
        Default = InsertLineBreaks | InsertSpaces
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that identify the kind of an
    /// interpreter and its relationship within an interpreter hierarchy,
    /// including its scripting language and whether it is a parent, child,
    /// nested, or token interpreter.  The values are bit flags and may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("6a65da98-d7ab-4ebc-a65b-a8db748340ce")]
    public enum InterpreterType
    {
        /// <summary>
        /// No interpreter type is specified.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// An interpreter that evaluates the TclTk scripting language.
        /// </summary>
        TclTk = 0x2,
#if NATIVE && TCL
        /// <summary>
        /// An interpreter that evaluates native Tcl scripts.
        /// </summary>
        Tcl = 0x4,
#if TCL_THREADS
        /// <summary>
        /// A native Tcl interpreter that runs on its own dedicated thread.
        /// </summary>
        TclThread = 0x8,
#endif
#endif

        /// <summary>
        /// An interpreter acting as the parent within an interpreter
        /// hierarchy.
        /// </summary>
        Parent = 0x10,
        /// <summary>
        /// An interpreter acting as a child within an interpreter
        /// hierarchy.
        /// </summary>
        Child = 0x20,
        /// <summary>
        /// An interpreter that is nested within another interpreter.
        /// </summary>
        Nested = 0x40,
        /// <summary>
        /// An interpreter referred to via an opaque token.
        /// </summary>
        Token = 0x80,

        /// <summary>
        /// The default interpreter type, a combination of <see
        /// cref="TclTk" />, <see cref="Parent" />, <see cref="Child" />,
        /// <see cref="Nested" />, and <see cref="Token" />.
        /// </summary>
        Default = TclTk | Parent | Child | Nested | Token
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the kind of event being queued to or
    /// processed by an interpreter, ranging from idle processing and
    /// callbacks to user-interface input and native Tcl interpreter
    /// operations.
    /// </summary>
    [ObjectId("6b5ff78b-3562-4cb3-882b-2cdaf9963184")]
    public enum EventType
    {
        /// <summary>
        /// Do nothing.
        /// </summary>
        None = 0,                /* Do nothing. */
        /// <summary>
        /// Process any pending events.
        /// </summary>
        Idle = 1,                /* Process any pending events. */
        /// <summary>
        /// The event represents an EventCallback delegate to be invoked.
        /// </summary>
        Callback = 2,            /* The event represents an EventCallback
                                  * delegate. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if WINFORMS
        /// <summary>
        /// A WinForms preview-key-down input event.
        /// </summary>
        PreviewKeyDown = 3,
        /// <summary>
        /// A WinForms key-down input event.
        /// </summary>
        KeyDown = 4,
        /// <summary>
        /// A WinForms key-press input event.
        /// </summary>
        KeyPress = 5,
        /// <summary>
        /// A WinForms key-up input event.
        /// </summary>
        KeyUp = 6,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// Create the native Tcl interpreter.
        /// </summary>
        Create = 7,              /* Create the interpreter. */
        /// <summary>
        /// Delete the native Tcl interpreter.
        /// </summary>
        Delete = 8,              /* Delete the interpreter. */
        /// <summary>
        /// Evaluate an expression contained in the event client data.
        /// </summary>
        Expression = 9,          /* Evaluate an expression (contained in the
                                  * ClientData). */
        /// <summary>
        /// Evaluate a script described by the triplet contained in the
        /// event client data.
        /// </summary>
        Evaluate = 10,           /* Evaluate a script (in the triplet contained
                                  * in the ClientData). */
        /// <summary>
        /// Evaluate a script contained in the event client data.
        /// </summary>
        SimpleEvaluate = 11,     /* Evaluate a script (contained in the
                                  * ClientData). */
        /// <summary>
        /// Perform substitutions on a string contained in the event client
        /// data.
        /// </summary>
        Substitute = 12,         /* Perform substitutions on a string (contained
                                  * in the ClientData). */
        /// <summary>
        /// Cancel the script in progress, using the error message
        /// contained in the event client data.
        /// </summary>
        Cancel = 13,             /* Cancel the script in progress (error message
                                  * contained in the ClientData). */
        /// <summary>
        /// Unwind the script in progress, using the error message
        /// contained in the event client data.
        /// </summary>
        Unwind = 14,             /* Unwind the script in progress (error message
                                  * contained in the ClientData). */
        /// <summary>
        /// Reset the cancel and unwind flags for the native Tcl
        /// interpreter.
        /// </summary>
        ResetCancel = 15,        /* Reset the cancel and unwind flags for the Tcl
                                  * interpreter. */
        /// <summary>
        /// Get the value of the variable named in the event client data.
        /// </summary>
        GetVariable = 16,        /* Get the value of a variable (name contained
                                  * in the ClientData). */
        /// <summary>
        /// Set the value of the variable described by the name/value pair
        /// in the event client data.
        /// </summary>
        SetVariable = 17,        /* Set the value of a variable (name/value pair
                                  * contained in the ClientData). */
        /// <summary>
        /// Unset the variable named in the event client data.
        /// </summary>
        UnsetVariable = 18,      /* Unset a variable (name contained in the
                                  * ClientData). */
        /// <summary>
        /// Add an IExecute to the interpreter, using the name and ICommand
        /// pair contained in the event client data.
        /// </summary>
        AddCommand = 19,         /* Add an IExecute to the interpreter
                                  * (name/ICommand pair contained in the
                                  * ClientData). */
        /// <summary>
        /// Add a standard bridge between the TclTk [eval] command and the
        /// Tcl [tcltk] command.
        /// </summary>
        AddStandardCommand = 20, /* Add a standard bridge between the TclTk
                                  * [eval] command and the Tcl [tcltk] command. */
        /// <summary>
        /// Remove an IExecute from the interpreter, using the name
        /// contained in the event client data.
        /// </summary>
        RemoveCommand = 21,      /* Remove an IExecute from the interpreter
                                  * (name contained in the ClientData). */
        /// <summary>
        /// Fetch the current interpreter result, if any.
        /// </summary>
        GetResult = 22,          /* Fetch the interpreter result, if any. */
        /// <summary>
        /// Fully dispose of all native Tcl thread resources.
        /// </summary>
        Dispose = 23             /* Fully dispose of all Tcl thread resources. */
#endif
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that select the mode in
    /// which the script engine operates on its input, such as evaluating
    /// an expression, script, or file, or performing substitutions on a
    /// string or file.  The values are bit flags and may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("ab21fc28-02d8-4401-a88d-faafbedbd5bf")]
    public enum EngineMode
    {
        /// <summary>
        /// No engine mode is specified.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Evaluate the input as an expression.
        /// </summary>
        EvaluateExpression = 0x2,
        /// <summary>
        /// Evaluate the input as a script.
        /// </summary>
        EvaluateScript = 0x4,
        /// <summary>
        /// Evaluate the contents of the input file as a script.
        /// </summary>
        EvaluateFile = 0x8,
        /// <summary>
        /// Perform substitutions on the input string.
        /// </summary>
        SubstituteString = 0x10,
        /// <summary>
        /// Perform substitutions on the contents of the input file.
        /// </summary>
        SubstituteFile = 0x20,
        /// <summary>
        /// The default engine mode, equivalent to <see
        /// cref="EvaluateScript" />.
        /// </summary>
        Default = EvaluateScript
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that control how a thread
    /// (typically one running an interpreter) is shut down, including
    /// whether and how it is interrupted, aborted, or waited upon, as well
    /// as the operational context that is driving the shutdown.  The
    /// values are bit flags and may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("5b186e18-6b14-4f13-a685-6e812e301467")]
    public enum ShutdownFlags
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,         /* No special handling. */
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,      /* Invalid, do not use. */
        /// <summary>
        /// Reserved for internal use and must not be used directly.
        /// </summary>
        Reserved1 = 0x2,    /* Reserved, do not use. */
        /// <summary>
        /// A reserved value that is invalid and must not be used.
        /// </summary>
        IgnoreAlive = 0x4,  /* Invalid, do not use. */
        /// <summary>
        /// Attempt to interrupt the target thread.
        /// </summary>
        Interrupt = 0x8,    /* Attempt to interrupt the thread. */
        /// <summary>
        /// Wait for a short period before taking any other action.
        /// </summary>
        WaitBefore = 0x10,  /* Wait for a bit before doing anything else. */
        /// <summary>
        /// Wait for a short period after attempting an interrupt.
        /// </summary>
        WaitAfter = 0x20,   /* Wait for a bit after attempting an interrupt. */
        /// <summary>
        /// Avoid aborting the thread.
        /// </summary>
        NoAbort = 0x40,     /* Avoid aborting the thread. */
        /// <summary>
        /// Only reset the thread once it has died.
        /// </summary>
        NoReset = 0x80,     /* Only reset thread when it dies. */
        /// <summary>
        /// Reset the thread after aborting it.
        /// </summary>
        ResetAbort = 0x100, /* Reset thread after abort. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates the shutdown relates to script cancellation.
        /// </summary>
        ForCancel = 0x200,          /* Operation related to script cancellation. */
        /// <summary>
        /// Indicates the shutdown relates to the status object.
        /// </summary>
        ForStatus = 0x400,          /* Related to the status object. */
        /// <summary>
        /// Indicates the shutdown relates to an operational timeout.
        /// </summary>
        ForTimeout = 0x800,         /* Related to an operational timeout. */
        /// <summary>
        /// Indicates the shutdown relates to an operational timeout that
        /// also waits.
        /// </summary>
        ForTimeoutAndWait = 0x1000, /* Related to an operational timeout. */
        /// <summary>
        /// Indicates the shutdown relates to scripted event processing.
        /// </summary>
        ForScriptEvent = 0x2000,    /* Related to scripted event processing. */
        /// <summary>
        /// Indicates the shutdown relates to a script timeout.
        /// </summary>
        ForScriptTimeout = 0x4000,  /* Related to a script timeout. */
        /// <summary>
        /// Indicates the shutdown was requested by a caller external to
        /// the library.
        /// </summary>
        ForExternal = 0x8000,       /* Caller is external to the library. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Interrupt" />, <see cref="NoAbort"
        /// />, <see cref="ForCancel" />, and <see cref="Reserved1" />,
        /// used by Interpreter.CancelThread.
        /// </summary>
        Cancel = Interrupt | NoAbort | ForCancel | Reserved1, /* Interpreter.CancelThread */
        /// <summary>
        /// Combination of <see cref="Interrupt" />, <see cref="WaitAfter"
        /// />, <see cref="NoAbort" />, <see cref="NoReset" />, <see
        /// cref="ForStatus" />, and <see cref="Reserved1" />, used by the
        /// status form operations.
        /// </summary>
        Status = Interrupt | WaitAfter | NoAbort | NoReset | ForStatus | Reserved1, /* StatusFormOps */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="ForScriptEvent" /> and <see
        /// cref="Reserved1" />, used by the test script-event thread.
        /// </summary>
        ScriptEvent = ForScriptEvent | Reserved1, /* CodeBrix.Platform.TclTk._Tests.Default+ScriptEventThread */
        /// <summary>
        /// Combination of <see cref="Interrupt" />, <see cref="WaitAfter"
        /// />, <see cref="NoAbort" />, <see cref="ForScriptTimeout" />,
        /// and <see cref="Reserved1" />, used by [debug secureeval].
        /// </summary>
        ScriptTimeout = Interrupt | WaitAfter | NoAbort | ForScriptTimeout | Reserved1, /* [debug secureeval] */
        /// <summary>
        /// Combination of <see cref="ForExternal" /> and <see
        /// cref="Reserved1" />, used by Utility.MaybeShutdownThread.
        /// </summary>
        External = ForExternal | Reserved1, /* Utility.MaybeShutdownThread */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Cancel" />, <see cref="WaitBefore"
        /// />, <see cref="ForTimeout" />, and <see cref="Reserved1" />.
        /// </summary>
        Timeout = Cancel | WaitBefore | ForTimeout | Reserved1, /* NOT USED (?) */
        /// <summary>
        /// Combination of <see cref="Timeout" />, <see cref="WaitAfter"
        /// />, <see cref="ForTimeoutAndWait" />, and <see cref="Reserved1"
        /// />.
        /// </summary>
        TimeoutAndWait = Timeout | WaitAfter | ForTimeoutAndWait | Reserved1, /* NOT USED (?) */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default shutdown flags, a combination of <see
        /// cref="Interrupt" /> and <see cref="Reserved1" />; this value is
        /// reserved and should not be used.
        /// </summary>
        Default = Interrupt | Reserved1 /* WARNING: Do not use. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that control the creation
    /// and behavior of script threads, including interpreter safety,
    /// user-interface support, lifetime and error handling, native Tcl
    /// event processing, and several predefined combinations for common
    /// usage patterns.  The values are bit flags and may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("7ea5444a-0ee3-4b33-bd80-be64722e86fb")]
    public enum ThreadFlags
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,                /* No special handling. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,             /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Throw exceptions when attempting to access a disposed
        /// interpreter.
        /// </summary>
        ThrowOnDisposed = 0x2,     /* Throw exceptions when attempting to access a
                                    * disposed interpreter. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Create the interpreter in safe mode.
        /// </summary>
        Safe = 0x4,                /* Create interpreter as "safe". */
        /// <summary>
        /// Omit unsafe commands entirely instead of hiding them.
        /// </summary>
        NoHidden = 0x8,            /* Omit "unsafe" commands instead of hiding them. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The thread must be able to use WinForms and/or WPF.
        /// </summary>
        UserInterface = 0x10,      /* Thread must be able to use WinForms and/or WPF. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Mark the thread as a background thread so it will not prevent
        /// the process from terminating.
        /// </summary>
        IsBackground = 0x20,       /* Thread will not prevent the process from
                                    * terminating. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The thread will make use of the active interpreter stack.
        /// </summary>
        UseActiveStack = 0x40,     /* Thread will make use of the active interpreter
                                    * stack. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Place the interpreter into quiet mode.
        /// </summary>
        Quiet = 0x80,              /* The interpreter will be set to "quiet" mode. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Disable background error handling for the created interpreter.
        /// </summary>
        NoBackgroundError = 0x100, /* The background error handling for the created
                                    * interpreter will be disabled. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Create an aliased object named "thread" that the contained
        /// interpreter can use to access the ScriptThread object itself.
        /// </summary>
        UseSelf = 0x200,           /* Create an aliased object named "thread" that
                                    * can be used to access the ScriptThread object
                                    * itself from inside the contained interpreter. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Script cancellation will not cause the thread to exit.
        /// </summary>
        NoCancel = 0x400,          /* Script cancellation will not cause the thread
                                    * to exit. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Script errors will cause the thread to exit.
        /// </summary>
        StopOnError = 0x800,       /* Script errors will cause the thread to exit. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// An empty event queue will cause the thread to exit.
        /// </summary>
        ErrorOnEmpty = 0x1000,     /* An empty event queue will cause the thread to
                                    * exit. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// Native Tcl events should be processed by the thread.
        /// </summary>
        TclThread = 0x2000,        /* Should native Tcl events be processed? */
        /// <summary>
        /// Wait for a native Tcl event; this should almost never be used.
        /// </summary>
        TclWaitEvent = 0x4000,     /* Wait for a Tcl event?  This should almost
                                    * never be used. */
        /// <summary>
        /// Process all pending native Tcl events on each iteration.
        /// </summary>
        TclAllEvents = 0x8000,     /* Process all native Tcl events each time? */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Disable popup messages for errors that cannot be reported any
        /// other way; such errors are still logged to the active trace
        /// listeners, if any.
        /// </summary>
        NoComplain = 0x10000,      /* Disable popup messages for errors that cannot
                                    * be reported any other way.  The errors will
                                    * still be logged to the active trace listners,
                                    * if any. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable additional diagnostic output for key lifecycle events,
        /// such as shutdown.
        /// </summary>
        Verbose = 0x20000,         /* Enable more diagnostic output for key lifecycle
                                    * events (e.g. shutdown). */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable debugging mode, which sets the EventFlags.Debug flag for
        /// all events queued through the interpreter event manager.
        /// </summary>
        Debug = 0x40000,           /* Enable debugging mode.  Currently, sets the
                                    * "EventFlags.Debug" flag for all events queued
                                    * via the interpreter event manager (i.e. not
                                    * those events handled directly by the engine). */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Use a thread pool thread instead of creating a dedicated
        /// managed thread; this disables several other flags, including
        /// <see cref="UserInterface" />, <see cref="IsBackground" />, and
        /// <see cref="Start" />.
        /// </summary>
        UsePool = 0x80000,         /* Instead of creating a real managed thread,
                                    * use the thread pool.  This prevents various
                                    * other flags from doing anything, including the
                                    * "UserInterface", "IsBackground", and "Start"
                                    * flags. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Start the thread before returning from the Create method
        /// instead of waiting for the Start method to be called.
        /// </summary>
        Start = 0x100000,          /* Start the thread prior to returning from the
                                    * "Create" method instead of waiting until the
                                    * "Start" method is called. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Disable all use of the Thread.Abort() method.
        /// </summary>
        NoAbort = 0x200000,        /* Disable all use of the Thread.Abort() method. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Use an existing interpreter instead of creating a new one.
        /// </summary>
        Attach = 0x400000,         /* Use an existing interpreter instead of creating
                                    * one. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Purge the global call frame when the script thread is exiting.
        /// </summary>
        PurgeGlobal = 0x800000,    /* Purge the global call frame when the script
                                    * thread is exiting. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable tracing of key events, such as [vwait].
        /// </summary>
        Trace = 0x1000000,         /* Enable tracing of key events, e.g. [vwait], etc. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Follow variable links when using [vwait].
        /// </summary>
        FollowLink = 0x2000000,    /* Follow variable links when using [vwait]. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Permit only the use of the Send() and Queue() methods.
        /// </summary>
        Restricted = 0x4000000,    /* Only permit use of the Send() and Queue() methods. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="NoComplain" />, <see cref="Start" />,
        /// <see cref="UseActiveStack" />, and <see cref="PurgeGlobal" />
        /// common to most usage patterns.
        /// </summary>
        CommonUse = NoComplain | Start | UseActiveStack | PurgeGlobal,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Trace" /> and <see cref="FollowLink"
        /// /> used for variable-oriented operations.
        /// </summary>
        VariableUse = Trace | FollowLink,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="CommonUse" /> and <see
        /// cref="ThrowOnDisposed" /> representing standard usage.
        /// </summary>
        StandardUse = CommonUse | ThrowOnDisposed,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="StandardUse" /> and <see
        /// cref="UserInterface" /> for user-interface threads.
        /// </summary>
        InterfaceUse = StandardUse | UserInterface,
        /// <summary>
        /// Combination of <see cref="StandardUse" /> and <see
        /// cref="NoCancel" /> for service threads.
        /// </summary>
        ServiceUse = StandardUse | NoCancel,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// Combination of <see cref="StandardUse" />, <see
        /// cref="UserInterface" />, <see cref="TclThread" />, and <see
        /// cref="TclAllEvents" /> for native Tcl user-interface threads.
        /// </summary>
        TclInterfaceUse = StandardUse | UserInterface | TclThread | TclAllEvents,
        /// <summary>
        /// Combination of <see cref="StandardUse" />, <see cref="NoCancel"
        /// />, <see cref="TclThread" />, and <see cref="TclAllEvents" />
        /// for native Tcl service threads.
        /// </summary>
        TclServiceUse = StandardUse | NoCancel | TclThread | TclAllEvents,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="StandardUse" /> and <see
        /// cref="UseSelf" /> for task-style threads.
        /// </summary>
        TaskUse = StandardUse | UseSelf,
        /// <summary>
        /// Combination of <see cref="TaskUse" /> and <see cref="Safe" />
        /// for safe task-style threads.
        /// </summary>
        SafeTaskUse = TaskUse | Safe,
        /// <summary>
        /// Combination of <see cref="TaskUse" />, <see cref="Safe" />, and
        /// <see cref="Restricted" /> for restricted task-style threads.
        /// </summary>
        RestrictedTaskUse = TaskUse | Safe | Restricted,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="InterfaceUse" />, <see
        /// cref="ServiceUse" />, and <see cref="TaskUse" />.
        /// </summary>
        AnyUse = InterfaceUse | ServiceUse | TaskUse,
        /// <summary>
        /// Combination of <see cref="InterfaceUse" />, <see
        /// cref="ServiceUse" />, <see cref="TaskUse" />, and <see
        /// cref="Safe" />.
        /// </summary>
        AnySafeUse = InterfaceUse | ServiceUse | TaskUse | Safe,
        /// <summary>
        /// Combination of <see cref="InterfaceUse" />, <see
        /// cref="ServiceUse" />, <see cref="TaskUse" />, <see cref="Safe"
        /// />, and <see cref="Restricted" />.
        /// </summary>
        AnyRestrictedUse = InterfaceUse | ServiceUse | TaskUse | Safe | Restricted,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For use by the ScriptThread.Attach (static) methods only.
        //
        /// <summary>
        /// Based on <see cref="InterfaceUse" /> with <see
        /// cref="PurgeGlobal" /> cleared and <see cref="Attach" /> added;
        /// for use by the ScriptThread.Attach static methods only.
        /// </summary>
        AttachUse = (InterfaceUse & ~PurgeGlobal) | Attach,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default thread flags, a combination of <see
        /// cref="VariableUse" /> and <see cref="InterfaceUse" />.
        /// </summary>
        Default = VariableUse | InterfaceUse // TODO: Good default?
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    // [Flags()]
    /// <summary>
    /// This enumeration defines the relative priority assigned to a queued
    /// event, which controls the order in which pending events are
    /// serviced; it also provides named priorities used by specific
    /// commands and subsystems.
    /// </summary>
    [ObjectId("66f29e4a-2adf-4641-956a-23505d82bbaa")]
    public enum EventPriority
    {
        /// <summary>
        /// Automatically assign the event priority based on the associated
        /// event flags.
        /// </summary>
        Automatic = -1,         /* Automatically assign event priority based on flags. */
        /// <summary>
        /// A reserved value that must not be used.
        /// </summary>
        None = 0x0,             /* Do not use. */
        /// <summary>
        /// A reserved value that must not be used.
        /// </summary>
        Invalid = 0x1,          /* Do not use. */
        /// <summary>
        /// The highest possible event priority.
        /// </summary>
        Highest = 0x2,          /* The highest possible event priority. */
        /// <summary>
        /// A high event priority.
        /// </summary>
        High = 0x4,
        /// <summary>
        /// The standard, medium event priority.
        /// </summary>
        Medium = 0x8,           /* The standard event priority. */
        /// <summary>
        /// A low event priority.
        /// </summary>
        Low = 0x10,
        /// <summary>
        /// The lowest possible event priority.
        /// </summary>
        Lowest = 0x20,          /* The lowest possible event priority. */

        /// <summary>
        /// Equivalent to <see cref="Highest" />; used by events that
        /// should execute even when the event manager is not actively
        /// waiting (so-called engine events).
        /// </summary>
        Immediate = Highest,    /* The priority used by events that should execute
                                 * even if the event manager is not actively in a
                                 * wait operation (a.k.a. "engine events"). */
        /// <summary>
        /// Equivalent to <see cref="Lowest" />; the priority used by
        /// [after idle].
        /// </summary>
        Idle = Lowest,          /* The event priority used by [after idle]. */
        /// <summary>
        /// Equivalent to <see cref="Medium" />; the priority used by
        /// <c>[after XXXX script]</c>.
        /// </summary>
        After = Medium,         /* The event priority used by [after XXXX <script>]. */
        /// <summary>
        /// Equivalent to <see cref="Medium" />; the default priority used
        /// by QueueEvent in auto-detection mode when no other event flags
        /// match.
        /// </summary>
        Normal = Medium,        /* The default event priority used by QueueEvent in
                                 * auto-detection mode when none of the other event
                                 * flags match. */

        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by the
        /// Engine.CheckEvents method.
        /// </summary>
        CheckEvents = Default,  /* The event priority used by by the Engine.CheckEvents
                                 * method. */
        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by
        /// [interp service].
        /// </summary>
        Service = Default,      /* The event priority used by [interp service]. */
        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by
        /// [update].
        /// </summary>
        Update = Default,       /* The event priority used by [update]. */
        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by
        /// [vwait].
        /// </summary>
        WaitVariable = Default, /* The event priority used by [vwait]. */
        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by the
        /// QueueEvent methods.
        /// </summary>
        QueueEvent = Default,   /* The event priority used by the QueueEvent method(s). */
        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by the
        /// QueueScript methods.
        /// </summary>
        QueueScript = Default,  /* The event priority used by the QueueScript method(s). */

#if NATIVE && TCL
        /// <summary>
        /// Equivalent to <see cref="Default" />; the priority used by the
        /// TclThread class.
        /// </summary>
        TclThread = Default,    /* The event priority used by the TclThread class. */
#endif

        /// <summary>
        /// The default event priority, equivalent to <see cref="Automatic"
        /// />.
        /// </summary>
        Default = Automatic     /* The default event priority. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that select which watchdog
    /// threads are being managed, such as the timeout and health
    /// watchdogs.  The values are bit flags and may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("42ababff-a006-48c3-8e9e-38aae6936a02")]
    public enum WatchdogType
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,          /* No special handling. */
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,       /* Invalid, do not use. */

        /// <summary>
        /// Manage the timeout watchdog thread.
        /// </summary>
        Timeout = 0x100,     /* Manage the timeout watchdog thread. */
        /// <summary>
        /// Manage the health watchdog thread.
        /// </summary>
        Health = 0x200,      /* Manage the health watchdog thread. */

        /// <summary>
        /// Indicates that the default watchdog type is being used.
        /// </summary>
        ForDefault = 0x1000, /* The default watchdog type is being
                              * used. */

        /// <summary>
        /// Mask combining <see cref="Timeout" /> and <see cref="Health"
        /// />.
        /// </summary>
        TypeMask = Timeout | Health,

        /// <summary>
        /// The default watchdog type, a combination of <see cref="Timeout"
        /// /> and <see cref="ForDefault" />.
        /// </summary>
        Default = Timeout | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that select the operation to
    /// perform on a watchdog thread together with the modifiers that
    /// govern how that operation behaves.  The values are bit flags and
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("39223dda-bcf9-4d91-af70-7e2c1c59d9b0")]
    public enum WatchdogOperation
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,     /* No special handling. */
        /// <summary>
        /// A reserved sentinel that is invalid and must not be used.
        /// </summary>
        Invalid = 0x1,  /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Determine whether the watchdog thread is active.
        /// </summary>
        Check = 0x2,    /* Is the watchdog thread active? */
        /// <summary>
        /// Fetch the watchdog thread.
        /// </summary>
        Fetch = 0x4,    /* Fetch the watchdog thread. */
        /// <summary>
        /// Start the watchdog thread.
        /// </summary>
        Start = 0x8,    /* Start the watchdog thread. */
        /// <summary>
        /// Stop the watchdog thread.
        /// </summary>
        Stop = 0x10,    /* Stop the watchdog thread. */
        /// <summary>
        /// Restart the watchdog thread.
        /// </summary>
        Restart = 0x20, /* Restart the watchdog thread. */
        /// <summary>
        /// Attach the current thread to the watchdog.
        /// </summary>
        Attach = 0x40,  /* Attach thread to watchdog. */
        /// <summary>
        /// Detach the current thread from the watchdog.
        /// </summary>
        Detach = 0x80,  /* Detach thread from watchdog. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow the watchdog thread to query the interactive user.
        /// </summary>
        InteractiveStart = 0x200, /* Can the watchdog thread query the
                                   * interactive user? */
        /// <summary>
        /// Force the watchdog thread to start even when the timeout is
        /// infinite.
        /// </summary>
        ForceStart = 0x400,       /* Force watchdog thread to start even
                                   * when the timeout is infinite? */
        /// <summary>
        /// Require the IsAlive check to pass before treating an existing
        /// watchdog thread as started.
        /// </summary>
        MustBeAlive = 0x800,      /* Check IsAlive prior to considering
                                   * an existing watchdog thread to be
                                   * started. */
        /// <summary>
        /// Fail the start operation if the watchdog thread is already
        /// running.
        /// </summary>
        StrictStart = 0x1000,     /* Fail starting the watchdog thread
                                   * if it is already running. */
        /// <summary>
        /// Fail the stop operation if the watchdog thread is not running.
        /// </summary>
        StrictStop = 0x2000,      /* Fail stopping the watchdog thread
                                   * if it is not running. */
        /// <summary>
        /// Avoid using the Thread.Abort() method.
        /// </summary>
        NoAbort = 0x4000,         /* Avoid using the Thread.Abort()
                                   * method. */
        /// <summary>
        /// Do not check the name of attached watchdog threads.
        /// </summary>
        NoName = 0x8000,          /* Do not check the name of attached
                                   * watchdog threads. */
        /// <summary>
        /// Retain all result messages.
        /// </summary>
        Verbose = 0x10000,        /* Retain all result messages. */
        /// <summary>
        /// Enable interrupting the primary thread for the target
        /// interpreter.
        /// </summary>
        Interrupt = 0x20000,      /* Enable interrupting the primary
                                   * thread for the target interpreter */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Check" /> and <see cref="MustBeAlive"
        /// />.
        /// </summary>
        CheckAndFlags = Check | MustBeAlive,
        /// <summary>
        /// Combination of <see cref="Start" />, <see cref="ForceStart" />,
        /// <see cref="MustBeAlive" />, and <see cref="StrictStart" />.
        /// </summary>
        StartAndFlags = Start | ForceStart | MustBeAlive | StrictStart,
        /// <summary>
        /// Combination of <see cref="Stop" /> and <see cref="StrictStop"
        /// />.
        /// </summary>
        StopAndFlags = Stop | StrictStop,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Mask combining <see cref="InteractiveStart" />, <see
        /// cref="ForceStart" />, <see cref="MustBeAlive" />, <see
        /// cref="StrictStart" />, <see cref="StrictStop" />, <see
        /// cref="NoAbort" />, <see cref="NoName" />, <see cref="Verbose"
        /// />, and <see cref="Interrupt" />.
        /// </summary>
        FlagsMask = InteractiveStart | ForceStart | MustBeAlive |
                    StrictStart | StrictStop | NoAbort | NoName |
                    Verbose | Interrupt
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies how an event is to be queued, dispatched,
    /// and serviced by the TclTk event manager.  Since these are bit flags,
    /// two or more values may be combined together to describe a single
    /// event and the manner in which it should be handled.
    /// </summary>
    [Flags()]
    [ObjectId("7344c9d6-999e-4730-9aad-0c7aee4502f7")]
    public enum EventFlags
    {
        /// <summary>
        /// No flags are set; the event receives no special handling.
        /// </summary>
        None = 0x0,            /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid event flag; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,         /* Invalid, do not use. */
        /// <summary>
        /// This event is being queued for execution at some later time.
        /// </summary>
        Queued = 0x2,          /* This event is being queued for execution later. */
        /// <summary>
        /// This event is being executed immediately.
        /// </summary>
        Direct = 0x4,          /* This event is being executed immediately. */
        /// <summary>
        /// This event is being handled by an unknown thread, which could be a
        /// worker thread, the main thread, or a thread-pool thread.
        /// </summary>
        UnknownThread = 0x8,   /* This event is being handled by an unknown thread (could be
                                * a worker thread, the main thread, or a thread-pool thread). */
        /// <summary>
        /// This event is being handled by the same thread that created it.
        /// </summary>
        SameThread = 0x10,     /* This event is being handled by the same thread that
                                * created it. */
        /// <summary>
        /// This event is being handled by a thread other than the one that
        /// created it.
        /// </summary>
        InterThread = 0x20,    /* This event is being handled by a thread other than the
                                * one that created it. */
        /// <summary>
        /// This event is directed at the interpreter.
        /// </summary>
        Internal = 0x40,       /* This event is directed at the interpreter. */
        /// <summary>
        /// This event is not directed at the interpreter.
        /// </summary>
        External = 0x80,       /* This event is not directed at the interpreter. */
        /// <summary>
        /// This event originated from the <c>[after]</c> command and must not be
        /// executed until a wait is initiated by a script.
        /// </summary>
        After = 0x100,         /* This event originated from the [after] command and must
                                * not be executed until a wait is initiated by a script. */
        /// <summary>
        /// This event should be executed as soon as the interpreter can safely
        /// do so.
        /// </summary>
        Immediate = 0x200,     /* This event should be executed as soon as the interpreter
                                * can safely do so. */
        /// <summary>
        /// This event should be executed as soon as the interpreter can safely
        /// do so and is idle.
        /// </summary>
        Idle = 0x400,          /* This event should be executed as soon as the interpreter
                                * can safely do so and is idle. */
        /// <summary>
        /// The code that created this event is blocking until it completes.
        /// </summary>
        Synchronous = 0x800,   /* The code that created this event is blocking until it
                                * completes. */
        /// <summary>
        /// The code that created this event queued it and continued executing.
        /// </summary>
        Asynchronous = 0x1000, /* The code that created this event queued it and continued
                                * executing. */
        /// <summary>
        /// This event should produce debugging diagnostics.
        /// </summary>
        Debug = 0x2000,        /* This event should produce debugging diagnostics. */
        /// <summary>
        /// This event should produce timing diagnostics.
        /// </summary>
        Timing = 0x4000,       /* This event should produce timing diagnostics. */
        /// <summary>
        /// Skip executing a callback if one exists.
        /// </summary>
        NoCallback = 0x8000,   /* Skip executing a callback if one exists. */
        /// <summary>
        /// Skip processing idle events.
        /// </summary>
        NoIdle = 0x10000,      /* Skip processing idle events. */
        /// <summary>
        /// Skip notifying the caller of event completion.  This is only used by
        /// the native Tcl integration subsystem.
        /// </summary>
        NoNotify = 0x20000,    /* Skip notifying the caller of event completion.  This is
                                * only used by the native Tcl integration subsystem. */
        /// <summary>
        /// Only process idle events if the queue is otherwise empty.
        /// </summary>
        IdleIfEmpty = 0x40000, /* Only process idle events if the queue is otherwise empty. */
        /// <summary>
        /// For queued scripts only, prefer the event flags from the interpreter
        /// instead of the ones provided with the script itself.
        /// </summary>
        Interpreter = 0x80000, /* For queued scripts only, prefer the event flags from the
                                * interpreter instead of the ones provided with the script
                                * itself. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip invoking the complaint subsystem.
        /// </summary>
        NoComplain = 0x100000,     /* Skip invoking the complaint subsystem. */
        /// <summary>
        /// Skip invoking the background error handler for this event.
        /// </summary>
        NoBgError = 0x200000,      /* Skip invoking background error handler for this event. */
        /// <summary>
        /// The IEvent object may be disposed after the event has been serviced
        /// (i.e. the caller does NOT need to obtain the result).  For now, this
        /// is for core library use only; please do not use it.
        /// </summary>
        FireAndForget = 0x400000,  /* The IEvent object may be disposed after the event has
                                    * been serviced (i.e. the caller does NOT need to obtain
                                    * the result).  For now, this is for core library use
                                    * only.  Please do not use it. */
        /// <summary>
        /// The event was somehow removed from the event queue.
        /// </summary>
        WasDequeued = 0x800000,    /* The event was somehow removed from the event queue. */
        /// <summary>
        /// The event was executed.  This does not imply that it was
        /// "successful".
        /// </summary>
        WasCompleted = 0x1000000,  /* The event was executed.  This does not imply that it
                                    * was "successful". */
        /// <summary>
        /// The event was canceled somehow.  This currently implies that it MAY
        /// have been removed from the event queue as well.
        /// </summary>
        WasCanceled = 0x2000000,   /* The event was canceled somehow.  This currently implies
                                    * that it MAY have been removed from the event queue as
                                    * well. */
        /// <summary>
        /// The event was discarded somehow.  This currently implies that it MAY
        /// have been removed from the event queue as well.
        /// </summary>
        WasDiscarded = 0x4000000,  /* The event was discarded somehow.  This currently implies
                                    * that it MAY have been removed from the event queue as
                                    * well. */
        /// <summary>
        /// The thread local data should be disposed after the event is
        /// complete.
        /// </summary>
        DisposeThread = 0x8000000, /* The thread local data should be disposed after the event
                                    * is complete. */
        /// <summary>
        /// The event should be processed even if it has a non-null thread
        /// identifier and the current call is processing non-thread specific
        /// events (i.e. <c>[vwait]</c> called without a -thread option value).
        /// </summary>
        GreedyThread = 0x10000000, /* The event should be processed even if it has a non-null
                                    * thread identifier -AND- the current call is processing
                                    * non-thread specific events (i.e. [vwait] called without
                                    * a -thread option value). */
        /// <summary>
        /// Do not permit a failed call to Engine.TryQueryAllFlags to cause
        /// overall event processing to fail, e.g. via the ProcessOps class.
        /// </summary>
        FailSafe = 0x20000000,     /* Do not permit a failed call to Engine.TryQueryAllFlags
                                    * to cause overall event processing to fail, e.g. via the
                                    * ProcessOps class, et al. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="After" />, <see cref="Immediate" />,
        /// and <see cref="Idle" />; the flags that modify the event dequeuing
        /// behavior.
        /// </summary>
        DequeueMask = After | Immediate | Idle, /* The flags that modify the event dequeuing
                                                 * behavior. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The types of events that are checked for and executed during script
        /// evaluation and command execution (by the engine).  This flag is for
        /// use by the engine only; the events are NEVER guaranteed to be
        /// serviced on any particular thread.
        /// </summary>
        Engine = Immediate,          /* The types of events that are checked for and executed
                                      * during script evaluation and command execution (by the
                                      * engine).  This flag is designed for use by the engine
                                      * only (i.e. it is not for use by external applications
                                      * and plugins).  These events are NEVER guaranteed to be
                                      * serviced on any particular thread. */
        /// <summary>
        /// The types of events that are checked for and executed during
        /// ServiceEvents and related methods.  These events are NEVER
        /// guaranteed to be serviced on any particular thread.
        /// </summary>
        Service = Immediate,         /* The types of events that are checked for and executed
                                      * during ServiceEvents and related methods.  These events
                                      * are NEVER guaranteed to be serviced on any particular
                                      * thread. */
        /// <summary>
        /// The types of events that are queued, by default, via QueueScript.
        /// These events are NEVER guaranteed to be serviced on any particular
        /// thread.
        /// </summary>
        Queue = Immediate,           /* The types of events that are queued, by default, via
                                      * QueueScript.  These events are NEVER guaranteed to be
                                      * serviced on any particular thread. */
        /// <summary>
        /// Combination of <see cref="After" /> and <see cref="Immediate" />;
        /// the types of events that are checked for and serviced during the
        /// <c>[vwait]</c> and <c>[update]</c> commands.  This flag is for use
        /// by those commands only.
        /// </summary>
        Wait = After | Immediate,    /* The types of events that are checked for and serviced
                                      * during the [vwait] and [update] commands.  This flag
                                      * is designed for use by [vwait] and [update] only (i.e.
                                      * it is not for use by external applications and
                                      * plugins).  Normally, [after] events are guaranteed to
                                      * be serviced on the primary thread for the interpreter;
                                      * however, that guarantee does NOT apply if external
                                      * applications and plugins use this flag. */
        /// <summary>
        /// Combination of <see cref="After" /> and <see cref="Immediate" />;
        /// service all events.  Great care should be used with this flag
        /// because scripts queued by <c>[after]</c> will not necessarily be
        /// serviced at the next <c>[vwait]</c>.
        /// </summary>
        All = After | Immediate,     /* Service all events.  Great care should be used with
                                      * this flag because scripts queued by [after] will not
                                      * necessarily be serviced at the next [vwait].  Also,
                                      * events are not guaranteed to be serviced on any
                                      * particular thread if this flag is used. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Engine" /> and <see cref="FailSafe" />;
        /// the default set of event flags.
        /// </summary>
        Default = Engine | FailSafe
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how a pending script evaluation is to be
    /// canceled (or unwound) and how the associated cancellation state is
    /// checked, set, and reset.  Since these are bit flags, two or more
    /// values may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("8d4d663a-6e43-4ccf-993c-238aebe4a617")]
    public enum CancelFlags : ulong
    {
        /// <summary>
        /// No flags are set; use the default handling.
        /// </summary>
        None = 0x0,                         /* Use default handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid cancel flag; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,                      /* Invalid, do not use. */

#if NOTIFY
        /// <summary>
        /// Enable notification callbacks.
        /// </summary>
        Notify = 0x2,                       /* Enable notification callbacks. */
#endif

        /// <summary>
        /// Cancel the script being evaluated.  This is not currently used.
        /// </summary>
        Cancel = 0x4,                       /* Cancel the script being evaluated.
                                             * This is not currently used. */
        /// <summary>
        /// Completely unwind the script call stack during script
        /// cancellation.
        /// </summary>
        Unwind = 0x8,                       /* Completely unwind the script call
                                             * stack during script cancellation. */
        /// <summary>
        /// Check (or set) the cancellation state globally, for all threads.
        /// </summary>
        Global = 0x10,                      /* Check (or set) state globally, for
                                             * all threads. */
        /// <summary>
        /// Check (or set) the cancellation state locally, for the current
        /// thread only.
        /// </summary>
        Local = 0x20,                       /* Check (or set) state locally, for
                                             * the current thread only. */
        /// <summary>
        /// Check (or set) the cancellation state locally, for the threads
        /// OTHER than the current one only.
        /// </summary>
        Other = 0x40,                       /* Check (or set) state locally, for
                                             * the threads OTHER than the current
                                             * one only. */
        /// <summary>
        /// Reset the global cancel flag(s)?
        /// </summary>
        ResetGlobal = 0x80,                 /* Reset the global cancel flag(s)? */
        /// <summary>
        /// Reset the local cancel flag(s)?
        /// </summary>
        ResetLocal = 0x100,                 /* Reset the local cancel flag(s)? */
        /// <summary>
        /// Reset the global and/or local cancel flags even if one of them has
        /// already been reset.
        /// </summary>
        ResetAll = 0x200,                   /* Reset the global and/or local cancel
                                             * flags even if one of them has already
                                             * been reset. */
        /// <summary>
        /// Update the result parameter sent by the caller to reflect the new
        /// interpreter state.
        /// </summary>
        NeedResult = 0x400,                 /* Update result parameter sent by the
                                             * caller to reflect the new interpreter
                                             * state. */
        /// <summary>
        /// When resetting the script cancellation state, ignore the number of
        /// pending evaluations or interactive loops.
        /// </summary>
        IgnorePending = 0x800,              /* When resetting the script cancellation
                                             * state, ignore the number of pending
                                             * evaluations -OR- interactive loops. */
        /// <summary>
        /// When resetting the script cancellation state, treat pending
        /// evaluations or interactive loops as an error.
        /// </summary>
        FailPending = 0x1000,               /* When resetting the script cancellation
                                             * state, treat pending evaluations -OR-
                                             * interactive loops as an error. */
        /// <summary>
        /// When attempting to cancel more than one script evaluation, stop on
        /// the first error encountered.
        /// </summary>
        StopOnError = 0x2000,               /* When attempting to cancel more than
                                             * one script evaluation, stop on the
                                             * first error encountered. */
        /// <summary>
        /// Also attempt to interrupt the primary thread for the interpreter.
        /// </summary>
        UseThreadInterrupt = 0x4000,        /* Also attempt to interrupt the primary
                                             * thread for the interpreter. */
        /// <summary>
        /// WARNING: *DANGEROUS* Also attempt to abort the primary thread for
        /// the interpreter.
        /// </summary>
        UseThreadAbort = 0x8000,            /* WARNING: *DANGEROUS* Also attempt to
                                             * abort the primary thread for the
                                             * interpreter. */
        /// <summary>
        /// Wait for the thread after attempting to interrupt it.
        /// </summary>
        WaitForThread = 0x10000,            /* Wait for the thread after attempting
                                             * to interrupt it. */

#if SHELL
        /// <summary>
        /// Use the interactive thread, if present, instead of the primary
        /// thread.
        /// </summary>
        UseInteractiveThread = 0x20000,     /* Use the interactive thread, if present,
                                             * instead of the primary thread. */
#endif

#if NATIVE && TCL
        /// <summary>
        /// Skip dealing with any native Tcl interpreters that may be present.
        /// </summary>
        NoNativeTcl = 0x40000,              /* Skip dealing with any native Tcl
                                             * interpreters that may be present. */
#endif

#if DEBUGGER && DEBUGGER_ENGINE
        /// <summary>
        /// Skip checking for any script breakpoints.
        /// </summary>
        NoBreakpoint = 0x80000,             /* Skip checking for any script
                                             * breakpoints. */
#endif

        /// <summary>
        /// Skip complaining about being unable to cancel (e.g. due to
        /// interpreter disposal).
        /// </summary>
        NoComplain = 0x100000,              /* Skip complaining about being unable
                                             * to cancel (e.g. due to interpreter
                                             * disposal). */
        /// <summary>
        /// Ignore the busyness state of the interpreter.
        /// </summary>
        NoBusy = 0x200000,                  /* Ignore the busyness state of the
                                             * interpreter. */
        /// <summary>
        /// Attempt to avoid the need to acquire the interpreter lock.
        /// </summary>
        NoLock = 0x400000,                  /* Attempt to avoid the need to acquire
                                             * the interpreter lock. */
        /// <summary>
        /// Attempt to acquire the interpreter lock via the TryEnter method.
        /// </summary>
        TryLock = 0x800000,                 /* Attempt to acquire the interpreter
                                             * lock via the TryEnter method. */

#if SHELL
        /// <summary>
        /// Forcibly "unpause" the primary interactive loop.
        /// </summary>
        UnpauseInteractiveLoop = 0x1000000, /* Forcibly "unpause" the primary
                                             * interactive loop. */
        /// <summary>
        /// Apply handling to all interactive loops.
        /// </summary>
        AllInteractiveLoops = 0x2000000,    /* Apply handling to all interactive
                                             * loops. */
#endif

        /// <summary>
        /// Attempt to initiate the script cancellation operation on all known
        /// interpreters.
        /// </summary>
        AllInterpreters = 0x4000000,        /* Attempt to initiate the script
                                             * cancellation operation on all
                                             * known interpreters. */

        /// <summary>
        /// Attempt to initiate the script cancellation operation on all known
        /// interpreter contexts.  This flag is not yet implemented.
        /// </summary>
        AllContexts = 0x8000000,            /* Attempt to initiate the script
                                             * cancellation operation on all
                                             * known interpreter contexts.  This
                                             * flag is not yet implemented. */

        /// <summary>
        /// When the interpreter lock is needed, wait a bit before giving up.
        /// </summary>
        WaitForLock = 0x10000000,           /* When the interpreter lock is needed,
                                             * wait a bit before giving up. */
        /// <summary>
        /// Force the creation of the necessary thread context(s), e.g. an
        /// engine context, prior to setting any local script cancellation
        /// flags.
        /// </summary>
        ForceContext = 0x20000000,          /* Force the creation of the necessary
                                             * thread context(s), e.g. an engine
                                             * context, prior to setting any local
                                             * script cancellation flags. */

        /// <summary>
        /// Do not actually cancel anything.  This flag is only used by the
        /// DisposeInterpreters method.
        /// </summary>
        NoCancel = 0x40000000,              /* Do not actually cancel anything.
                                             * This flag is only used by the
                                             * DisposeInterpreters method. */

        /// <summary>
        /// This may result in additional trace output.
        /// </summary>
        Trace = 0x80000000,                 /* This may result in additional trace
                                             * output. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// For use with the <c>[debug]</c> command only.
        /// </summary>
        ForDebug = 0x100000000,             /* For use with the [debug] command
                                             * only. */
        /// <summary>
        /// For use with the <c>[interp]</c> command only.
        /// </summary>
        ForInterp = 0x200000000,            /* For use with the [interp] command
                                             * only. */
        /// <summary>
        /// For use with the <c>[test2]</c> command only.
        /// </summary>
        ForTest2 = 0x400000000,             /* For use with the [test2] command
                                             * only. */
        /// <summary>
        /// For use with the <c>[time]</c> command only.
        /// </summary>
        ForTime = 0x800000000,              /* For use with the [time] command
                                             * only. */
        /// <summary>
        /// For use with the <c>[try]</c> command only.
        /// </summary>
        ForTry = 0x1000000000,              /* For use with the [try] command
                                             * only. */
        /// <summary>
        /// For use with the <c>[catch]</c> command only.
        /// </summary>
        ForCatch = 0x2000000000,            /* For use with the [catch] command
                                             * only. */
        /// <summary>
        /// For use by the Engine class only.
        /// </summary>
        ForEngine = 0x4000000000,           /* For use by the Engine class only. */
        /// <summary>
        /// For use by the Interpreter.Ready method only.
        /// </summary>
        ForReady = 0x8000000000,            /* For use by the Interpreter.Ready
                                             * method only. */
        /// <summary>
        /// For use by the interactive loop only.
        /// </summary>
        ForInteractive = 0x10000000000,     /* For use by the interactive loop
                                             * only. */
        /// <summary>
        /// For use by external (i.e. outside of the core library) components
        /// only.
        /// </summary>
        ForExternal = 0x20000000000,        /* For use by external (i.e. outside
                                             * of the core library) components
                                             * only. */
        /// <summary>
        /// For use by the event manager only.
        /// </summary>
        ForBgError = 0x40000000000,         /* For use by the event manager only. */
        /// <summary>
        /// For use by the CommandCallback class only.
        /// </summary>
        ForCommandCallback = 0x80000000000, /* For use by CommandCallback class
                                             * only. */
        /// <summary>
        /// For use by the RuntimeOps class only.
        /// </summary>
        ForScriptTimeout = 0x100000000000,  /* For use by the RuntimeOps class
                                             * only. */
        /// <summary>
        /// For use by the ScriptEventState class only.
        /// </summary>
        ForScriptEvent = 0x200000000000,    /* For use by the ScriptEventState
                                             * class only. */
        /// <summary>
        /// For use with the ScriptThread class only.
        /// </summary>
        ForScriptThread = 0x400000000000,   /* For use with the ScriptThread
                                             * class only. */
        /// <summary>
        /// For use by the LoadSettingsViaFile method only.
        /// </summary>
        ForSettings = 0x800000000000,       /* For use by the LoadSettingsViaFile
                                             * method only. */
        /// <summary>
        /// For use by the timeout threads.
        /// </summary>
        ForTimeout = 0x1000000000000,       /* For use by the timeout threads. */
        /// <summary>
        /// For use by the <c>[vwait]</c> command only.
        /// </summary>
        ForVwait = 0x2000000000000,         /* For use by the [vwait] command
                                             * only. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if THREADING
        /// <summary>
        /// Combination of <see cref="Global" /> and <see cref="Local" />;
        /// check (or set) the cancellation state both globally and locally.
        /// </summary>
        UseGlobalAndLocal = Global | Local,
        /// <summary>
        /// Check (or set) the cancellation state locally only.
        /// </summary>
        UseGlobalOrLocal = Local,
        /// <summary>
        /// Combination of <see cref="ResetGlobal" /> and
        /// <see cref="ResetLocal" />; reset both the global and local cancel
        /// flags.
        /// </summary>
        ResetGlobalAndLocal = ResetGlobal | ResetLocal,
        /// <summary>
        /// Reset the local cancel flag only.
        /// </summary>
        ResetGlobalOrLocal = ResetLocal,
#else
        /// <summary>
        /// Check (or set) the cancellation state globally.
        /// </summary>
        UseGlobalAndLocal = Global,
        /// <summary>
        /// Check (or set) the cancellation state globally.
        /// </summary>
        UseGlobalOrLocal = Global,
        /// <summary>
        /// Reset the global cancel flag.
        /// </summary>
        ResetGlobalAndLocal = ResetGlobal,
        /// <summary>
        /// Reset the global cancel flag.
        /// </summary>
        ResetGlobalOrLocal = ResetGlobal,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="UseGlobalOrLocal" /> and
        /// <see cref="ResetGlobalOrLocal" />; the flags used to check the
        /// local cancellation state.
        /// </summary>
        CheckLocalState = UseGlobalOrLocal | ResetGlobalOrLocal,
        /// <summary>
        /// Combination of <see cref="UseGlobalAndLocal" /> and
        /// <see cref="ResetGlobalAndLocal" />; the flags used to check the
        /// global cancellation state.
        /// </summary>
        CheckGlobalState = UseGlobalAndLocal | ResetGlobalAndLocal,

#if NOTIFY
        /// <summary>
        /// The set of flags that does not change the cancellation state.
        /// </summary>
        NoState = Notify,
        /// <summary>
        /// Combination used to set the local script cancellation state, with
        /// notification, while ignoring pending evaluations.
        /// </summary>
        SetLocalState = Notify | UseGlobalOrLocal | NeedResult | IgnorePending,
        /// <summary>
        /// Combination used to set the global script cancellation state, with
        /// notification, while ignoring pending evaluations.
        /// </summary>
        SetGlobalState = Notify | UseGlobalAndLocal | NeedResult | IgnorePending,
        /// <summary>
        /// Combination used to reset the local script cancellation state, with
        /// notification.
        /// </summary>
        ResetLocalState = Notify | UseGlobalOrLocal | NeedResult,
        /// <summary>
        /// Combination used to reset the global script cancellation state, with
        /// notification.
        /// </summary>
        ResetGlobalState = Notify | UseGlobalAndLocal | NeedResult,
#else
        /// <summary>
        /// The set of flags that does not change the cancellation state.
        /// </summary>
        NoState = None,
        /// <summary>
        /// Combination used to set the local script cancellation state while
        /// ignoring pending evaluations.
        /// </summary>
        SetLocalState = UseGlobalOrLocal | NeedResult | IgnorePending,
        /// <summary>
        /// Combination used to set the global script cancellation state while
        /// ignoring pending evaluations.
        /// </summary>
        SetGlobalState = UseGlobalAndLocal | NeedResult | IgnorePending,
        /// <summary>
        /// Combination used to reset the local script cancellation state.
        /// </summary>
        ResetLocalState = UseGlobalOrLocal | NeedResult,
        /// <summary>
        /// Combination used to reset the global script cancellation state.
        /// </summary>
        ResetGlobalState = UseGlobalAndLocal | NeedResult,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // WARNING: These two values are for external use only.
        //
        /// <summary>
        /// Combination used by external callers to unwind the call stack and
        /// set the global cancellation state, with notification.
        /// </summary>
        UnwindAndNotify = SetGlobalState | Unwind | TryLock | ForExternal, /* EXEMPT */
        /// <summary>
        /// Combination used by external callers to reset the global
        /// cancellation state, ignoring pending evaluations, with
        /// notification.
        /// </summary>
        IgnorePendingAndNotify = ResetGlobalState | IgnorePending | TryLock | ForExternal, /* EXEMPT */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to halt script evaluation for the <c>[debug]</c>
        /// command.
        /// </summary>
        DebugHalt = SetLocalState | TryLock | ForDebug,
        /// <summary>
        /// Combination used to cancel script evaluation for the <c>[interp]</c>
        /// command.
        /// </summary>
        InterpCancel = SetLocalState | TryLock | ForInterp,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to cancel and unwind script evaluation when a
        /// per-script timeout elapses.
        /// </summary>
        ScriptTimeout = SetLocalState | Unwind | NoComplain | NoLock | ForScriptTimeout,
        /// <summary>
        /// Combination used to cancel and unwind script evaluation when a
        /// timeout elapses.
        /// </summary>
        Timeout = SetLocalState | Unwind | NoComplain | NoLock | ForTimeout,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to reset the cancellation state for the
        /// <c>[interp]</c> command.
        /// </summary>
        InterpResetCancel = ResetLocalState | TryLock | ForInterp,
        /// <summary>
        /// Combination used to reset the cancellation state for the
        /// <c>[test2]</c> command.
        /// </summary>
        Test2 = ResetLocalState | IgnorePending | TryLock | ForTest2,
        /// <summary>
        /// Combination used to reset the cancellation state for the
        /// <c>[time]</c> command.
        /// </summary>
        Time = ResetLocalState | IgnorePending | TryLock | ForTime,
        /// <summary>
        /// Combination used to reset the cancellation state when processing a
        /// background error.
        /// </summary>
        BgError = ResetLocalState | IgnorePending | TryLock | ForBgError,
        /// <summary>
        /// Combination used to reset the cancellation state for a command
        /// callback, failing on pending evaluations.
        /// </summary>
        CommandCallback = ResetLocalState | FailPending | TryLock | ForCommandCallback,
        /// <summary>
        /// Combination used to reset the cancellation state for a secure
        /// evaluation initiated by the <c>[debug]</c> command.
        /// </summary>
        DebugSecureEval = ResetLocalState | IgnorePending | TryLock | ForDebug,
        /// <summary>
        /// Combination used to reset the global cancellation state when
        /// loading settings.
        /// </summary>
        Settings = ResetGlobalState | IgnorePending | TryLock | ForSettings,
        /// <summary>
        /// Combination used to reset both the local and global cancellation
        /// state for the <c>[debug]</c> command, failing on pending
        /// evaluations.
        /// </summary>
        DebugEmergency = ResetLocalState | ResetGlobalState | FailPending | TryLock | ForDebug,
        /// <summary>
        /// Combination used to reset both the local and global cancellation
        /// state for the <c>[vwait]</c> command.
        /// </summary>
        Vwait = ResetLocalState | ResetGlobalState | IgnorePending | TryLock | ForVwait,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to reset the cancellation state when entering a
        /// <c>[try]</c> block.
        /// </summary>
        TryBlock = ResetLocalState | IgnorePending | TryLock | ForTry,
        /// <summary>
        /// Combination used to reset the cancellation state when entering a
        /// <c>[catch]</c> block.
        /// </summary>
        CatchBlock = ResetLocalState | IgnorePending | TryLock | ForCatch,
        /// <summary>
        /// Combination used to set the local cancellation state when entering
        /// a <c>finally</c> block of the <c>[try]</c> command.
        /// </summary>
        FinallyBlock = SetLocalState | TryLock | ForTry,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY
        //
        // NOTE: This is the mask of flags that should NOT be
        //       used in methods that are in the hot paths.
        //
        /// <summary>
        /// The mask of flags that should NOT be used in methods that are in
        /// the hot paths.
        /// </summary>
        NonHotPathMask = Notify,
#else
        /// <summary>
        /// The mask of flags that should NOT be used in methods that are in
        /// the hot paths.
        /// </summary>
        NonHotPathMask = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used by the engine to reset the local cancellation
        /// state, excluding any non-hot-path flags.
        /// </summary>
        Engine = (ResetLocalState & ~NonHotPathMask) | TryLock | ForEngine,
        /// <summary>
        /// Combination used by the Interpreter.Ready method to check the
        /// global cancellation state, excluding any non-hot-path flags.
        /// </summary>
        Ready = (CheckGlobalState & ~NonHotPathMask) | NeedResult | TryLock | ForReady,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to reset the global cancellation state when
        /// servicing a script event.
        /// </summary>
        ScriptEvent = ResetGlobalState | IgnorePending | TryLock | ForScriptEvent,
        /// <summary>
        /// Combination used to reset the global cancellation state for a
        /// script thread.
        /// </summary>
        ScriptThread = ResetGlobalState | IgnorePending | TryLock | ForScriptThread,

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region For Interactive Use Only
        /// <summary>
        /// Combination used to reset the global cancellation state from the
        /// interactive loop.
        /// </summary>
        ShellResetCancel = ResetGlobalState | TryLock | ForInteractive,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to check whether the interactive loop has been
        /// halted.
        /// </summary>
        InteractiveIsHalted = CheckGlobalState | NeedResult | TryLock | ForInteractive,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to manually halt the interactive loop.
        /// </summary>
        InteractiveManualHalt = SetLocalState | IgnorePending | TryLock | ForInteractive,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to manually reset the global cancellation state
        /// from the interactive loop, ignoring pending evaluations.
        /// </summary>
        InteractiveManualResetCancel = ResetGlobalState | IgnorePending | TryLock | ForInteractive,
        /// <summary>
        /// Combination used to manually reset the halted state of the
        /// interactive loop, ignoring pending evaluations.
        /// </summary>
        InteractiveManualResetHalt = ResetGlobalState | IgnorePending | TryLock | ForInteractive,
        /// <summary>
        /// Combination used to automatically reset the halted state of the
        /// interactive loop.
        /// </summary>
        InteractiveAutomaticResetHalt = ResetGlobalState | TryLock | ForInteractive,
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to cancel an event from the interactive loop.
        /// </summary>
        InteractiveCancelEvent = NoState |
#if SHELL
            UnpauseInteractiveLoop |
#endif
            TryLock | ForInteractive,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination used to cancel (and interrupt) the thread from the
        /// interactive loop.
        /// </summary>
        InteractiveCancelThread = NoState |
            UseThreadInterrupt |
#if SHELL
            UseInteractiveThread |
#endif
            TryLock | ForInteractive,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// No flags are set; the default cancel flags.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how TclTk evaluates a script in a
    /// temporarily "trusted" context, including which safety relaxations
    /// are permitted while doing so.  Since these are bit flags, two or
    /// more values may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("70cc84ac-f876-438f-a06e-fa2ef80e3bf8")]
    public enum TrustFlags
    {
        /// <summary>
        /// No flags are set; use the default handling.
        /// </summary>
        None = 0x0,                /* Use default handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid trust flag; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,             /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow other threads to use the interpreter while evaluating the
        /// script (DANGEROUS).  Use with great care, if ever.
        /// </summary>
        Shared = 0x2,               /* Allow other threads to use the interpreter
                                     * while evaluating the script (DANGEROUS).  Use
                                     * with great care, if ever. */
        /// <summary>
        /// Allow asynchronous events to be processed via the event manager
        /// while evaluating the script (DANGEROUS).  Use with great care, if
        /// ever.
        /// </summary>
        WithEvents = 0x4,           /* Allow asynchronous events to be processed via
                                     * the event manger while evaluating the script
                                     * (DANGEROUS).  Use with great care, if ever. */
        /// <summary>
        /// Temporarily mark the interpreter as "trusted".
        /// </summary>
        MarkTrusted = 0x8,          /* Temporarily mark the interpreter as "trusted". */
        /// <summary>
        /// Permit "trusted" evaluation even for "unsafe" interpreters (i.e.
        /// those that are already marked as "trusted").
        /// </summary>
        AllowUnsafe = 0x10,         /* Permit "trusted" evaluation even for "unsafe"
                                     * interpreters (i.e. those that are already marked
                                     * as "trusted"). */
        /// <summary>
        /// Do not enable execution of hidden commands.
        /// </summary>
        NoIgnoreHidden = 0x20,      /* Do not enable execution of hidden commands. */
        /// <summary>
        /// For use by the core library only.
        /// </summary>
        ViaCoreLibrary = 0x40,      /* For use by the core library only. */
        /// <summary>
        /// Increment and decrement the SecurityLevels when evaluating the
        /// script.
        /// </summary>
        UseSecurityLevels = 0x80,   /* Increment/decrement the SecurityLevels when
                                     * evaluating the script. */
        /// <summary>
        /// Wrap the script evaluation in calls to push and pop the script
        /// location (file name).
        /// </summary>
        PushScriptLocation = 0x100, /* Wrap the script evaluation in calls to push and
                                     * pop the script location (file name). */
        /// <summary>
        /// Create and push a new <c>[scope]</c> frame prior to evaluating the
        /// script.
        /// </summary>
        WithScopeFrame = 0x200,     /* Create and push a new [scope] frame prior to
                                     * evaluating the script. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ISOLATED_PLUGINS
        /// <summary>
        /// Prevent plugins from being loaded in isolated application domains.
        /// </summary>
        NoIsolatedPlugins = 0x400, /* Prevent plugins from being loaded in isolated
                                    * application domains. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Temporarily mark the interpreter as "trusted" unless this is
        //       unnecessary because the interpreter is already "trusted".
        //
        /// <summary>
        /// Combination of <see cref="MarkTrusted" /> and
        /// <see cref="AllowUnsafe" />; temporarily mark the interpreter as
        /// "trusted" unless this is unnecessary because it is already
        /// "trusted".
        /// </summary>
        MaybeMarkTrusted = MarkTrusted | AllowUnsafe,
        /// <summary>
        /// Combination of <see cref="MaybeMarkTrusted" /> and
        /// <see cref="PushScriptLocation" />; used when conditionally trusting
        /// the evaluation of a file.
        /// </summary>
        MaybeTrustedFile = MaybeMarkTrusted | PushScriptLocation,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is used when evaluating the Harpy / Badge security
        //       script fragments that are used to enable or disable script
        //       signing policies and core script certificates.  This is only
        //       done in response to the "-security" command line option -OR-
        //       by calling the ScriptOps.EnableOrDisableSecurity method.
        //
        /// <summary>
        /// Combination of <see cref="MaybeMarkTrusted" />,
        /// <see cref="ViaCoreLibrary" />, and <see cref="UseSecurityLevels" />;
        /// used when evaluating the Harpy / Badge security script fragments
        /// that enable or disable script signing policies and core script
        /// certificates.
        /// </summary>
        SecurityPackage = MaybeMarkTrusted | ViaCoreLibrary | UseSecurityLevels,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// No flags are set; the default trust flags.
        /// </summary>
        Default = None         /* WARNING: Do not change this value. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the arity (the number of arguments or
    /// operands accepted) of a function or operator.  Non-negative values
    /// denote an exact count, while the negative values denote special
    /// arity rules.
    /// </summary>
    [ObjectId("15024598-4868-466e-a7cd-f6aa1069b4dc")]
    public enum Arity
    {
        /// <summary>
        /// This function or operator can accept any number of arguments or
        /// operands.
        /// </summary>
        Any = -5,             /* This function or operator can accept any number
                               * of arguments or operands. */
        /// <summary>
        /// Use the value of the ArgumentsAttribute or the OperandsAttribute to
        /// determine the arity of the function or operator, respectively.
        /// </summary>
        Automatic = -4,       /* Use the value of the ArgumentsAttribute or the
                               * OperandsAttribute to determine the arity of the
                               * function or operator, respectively. */
        /// <summary>
        /// This operator can accept one or two operands.
        /// </summary>
        UnaryAndBinary = -3,  /* This operator can accept one or two operands. */
        /// <summary>
        /// This operator can accept zero or one operands.
        /// </summary>
        NullaryAndUnary = -2, /* This operator can accept zero or one operands. */
        /// <summary>
        /// This function or operator can accept any number of arguments or
        /// operands.
        /// </summary>
        None = -1,            /* This function or operator can accept any number
                               * of arguments or operands. */

        /// <summary>
        /// This function or operator accepts zero arguments.
        /// </summary>
        Nullary = 0,
        /// <summary>
        /// This function or operator accepts one argument.
        /// </summary>
        Unary = 1,
        /// <summary>
        /// This function or operator accepts two arguments.
        /// </summary>
        Binary = 2,
        /// <summary>
        /// This function or operator accepts three arguments.
        /// </summary>
        Ternary = 3,
        /// <summary>
        /// This function or operator accepts four arguments.
        /// </summary>
        Quaternary = 4,
        /// <summary>
        /// This function or operator accepts five arguments.
        /// </summary>
        Quinary = 5,
        /// <summary>
        /// This function or operator accepts six arguments.
        /// </summary>
        Senary = 6,
        /// <summary>
        /// This function or operator accepts seven arguments.
        /// </summary>
        Septenary = 7,
        /// <summary>
        /// This function or operator accepts eight arguments.
        /// </summary>
        Octonary = 8,
        /// <summary>
        /// This function or operator accepts nine arguments.
        /// </summary>
        Novenary = 9,

        /// <summary>
        /// The minimum supported exact arity (equal to <see cref="Nullary" />).
        /// </summary>
        Minimum = Nullary,
        /// <summary>
        /// The maximum supported exact arity (equal to <see cref="Novenary" />).
        /// </summary>
        Maximum = Novenary,
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration describes the properties and categories of an
    /// expression operator, including how it is handled by the expression
    /// engine and how it relates to Tcl/Tk compatibility.  Since these are
    /// bit flags, two or more values may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("e609aaf6-8e07-434b-ad07-758ad9e824ec")]
    public enum OperatorFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid operator flag; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,             /* Invalid, do not use. */
        /// <summary>
        /// This operator is part of the core operator set.
        /// </summary>
        Core = 0x2,                /* This operator is part of the core
                                    * operator set. */
        /// <summary>
        /// This operator requires special handling by the expression engine.
        /// </summary>
        Special = 0x4,             /* This operator requires special handling
                                    * by the expression engine. */
        /// <summary>
        /// The expression engine handles this operator directly (i.e. without
        /// using an IOperator class).
        /// </summary>
        Direct = 0x8,              /* The expression engine handles this
                                    * operator directly (i.e. without using an
                                    * IOperator class). */
        /// <summary>
        /// Break into the debugger before execution.
        /// </summary>
        Breakpoint = 0x10,         /* Break into debugger before execution. */
        /// <summary>
        /// The operator may not be executed.
        /// </summary>
        Disabled = 0x20,           /* The operator may not be executed. */
        /// <summary>
        /// By default, the operator will not be visible in the results of
        /// <c>[info operators]</c>.
        /// </summary>
        Hidden = 0x40,             /* By default, the operator will not be
                                    * visible in the results of [info
                                    * operators]. */
        /// <summary>
        /// The operator is largely (or completely) compatible with an
        /// identically named operator from Tcl/Tk 8.4, 8.5, and/or 8.6.
        /// </summary>
        Standard = 0x80,           /* The operator is largely (or completely)
                                    * compatible with an identically named
                                    * operator from Tcl/Tk 8.4, 8.5, and/or
                                    * 8.6. */
        /// <summary>
        /// The operator is not present in Tcl/Tk 8.4, 8.5, and/or 8.6, or it
        /// is completely incompatible with an identically named operator in
        /// Tcl/Tk 8.4, 8.5, and/or 8.6.
        /// </summary>
        NonStandard = 0x100,       /* The operator is not present in Tcl/Tk
                                    * 8.4, 8.5, and/or 8.6 -OR- it is
                                    * completely incompatible with an
                                    * identically named operator in Tcl/Tk 8.4,
                                    * 8.5, and/or 8.6. */
        /// <summary>
        /// The operator will not be returned by the plugin manager.
        /// </summary>
        NoPopulate = 0x200,        /* The operator will not be returned by the
                                    * plugin manager. */
        /// <summary>
        /// Disable adding the command to the "tcl::mathop" namespace.
        /// </summary>
        NoTclMathOperator = 0x400, /* Disable adding the command to the
                                    * "tcl::mathop" namespace. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Addition, subtraction, multiplication, division, exponentiation,
        /// and remainder operators.
        /// </summary>
        Arithmetic = 0x800,        /* Addition, subtraction, multiplication,
                                    * division, exponentiation, remainder. */
        /// <summary>
        /// Equal to, not equal to, less than, greater than, and similar
        /// operators.
        /// </summary>
        Relational = 0x1000,       /* Equal to, not equal to, less than,
                                    * greater than, etc. */
        /// <summary>
        /// If-then-else and similar operators.
        /// </summary>
        Conditional = 0x2000,      /* If-then-else, etc. */
        /// <summary>
        /// Logical "and", "or", "not", "xor", and similar operators.
        /// </summary>
        Logical = 0x4000,          /* Logical "and", "or", "not", "xor",
                                    * etc. */
        /// <summary>
        /// Bitwise "and", "or", "not", "xor", shift, rotate, and similar
        /// operators.
        /// </summary>
        Bitwise = 0x8000,          /* Bitwise "and", "or", "not", "xor",
                                    * shift, rotate, etc. */
        /// <summary>
        /// Variable assignment operators.
        /// </summary>
        Assignment = 0x10000,      /* Variable assignment operators. */
        /// <summary>
        /// All the string-only operators.
        /// </summary>
        String = 0x20000,          /* All the string-only operators. */
        /// <summary>
        /// All the list-only operators.
        /// </summary>
        List = 0x40000,            /* All the list-only operators. */
        /// <summary>
        /// This operator is needed in order to be able to call math
        /// functions.
        /// </summary>
        Functional = 0x80000,      /* This operator is needed in order to be
                                    * able to call math functions. */
        /// <summary>
        /// This operator is needed in order to be able to initialize the
        /// minimal script library, i.e. "init.tcltk".
        /// </summary>
        Initialize = 0x100000,     /* This operator is needed in order to be
                                    * able to initialize the minimal script
                                    * library, i.e. "init.tcltk". */
        /// <summary>
        /// This operator is needed in order to use the baseline security SDK.
        /// </summary>
        SecuritySdk = 0x200000,    /* This operator is needed in order to use
                                    * the baseline security SDK. */
        /// <summary>
        /// Skip querying and combining the flags, etc, from the underlying
        /// managed type.
        /// </summary>
        NoAttributes = 0x400000,   /* Skip querying and combining the flags,
                                    * etc, from the underlying managed type. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Initialize" /> and
        /// <see cref="SecuritySdk" />; the operators required for security
        /// support.
        /// </summary>
        SecurityMask = Initialize | SecuritySdk,

        /// <summary>
        /// Combination of <see cref="Arithmetic" />, <see cref="Relational" />,
        /// <see cref="Conditional" />, <see cref="Logical" />,
        /// <see cref="Bitwise" />, <see cref="Assignment" />,
        /// <see cref="String" />, <see cref="List" />, and
        /// <see cref="Functional" />; the operator category subset.
        /// </summary>
        SubsetMask = Arithmetic | Relational | Conditional |
                     Logical | Bitwise | Assignment | String |
                     List | Functional,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are added to an operator when the parent interpreter
        //       is made "standard".
        //
        /// <summary>
        /// Combination of <see cref="Disabled" /> and <see cref="Hidden" />;
        /// these flags are added to an operator when the parent interpreter is
        /// made "standard".
        /// </summary>
        DisabledAndHidden = Disabled | Hidden
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls which kinds of interpreter entities are
    /// affected (e.g. disabled, hidden, or removed) when transitioning an
    /// interpreter into its "safe" or "standard" mode.  Since these are
    /// bit flags, two or more values may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("506fa37d-c5c2-4eb8-a4e0-27303cb669f0")]
    public enum MakeFlags
    {
        /// <summary>
        /// No flags are set; use the default handling.
        /// </summary>
        None = 0x0,              /* Use default handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid make flag; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,           /* Invalid, do not use. */
        /// <summary>
        /// Disable and/or hide commands.
        /// </summary>
        IncludeCommands = 0x2,   /* Disable and/or hide commands. */
        /// <summary>
        /// Disable and/or hide procedures.
        /// </summary>
        IncludeProcedures = 0x4, /* Disable and/or hide procedures. */
        /// <summary>
        /// Disable and/or hide functions.
        /// </summary>
        IncludeFunctions = 0x8,  /* Disable and/or hide functions. */
        /// <summary>
        /// Disable and/or hide operators.
        /// </summary>
        IncludeOperators = 0x10, /* Disable and/or hide operators. */
        /// <summary>
        /// Disable and/or hide variables.
        /// </summary>
        IncludeVariables = 0x20, /* Disable and/or hide operators. */
        /// <summary>
        /// Evaluate the associated library script, if any.
        /// </summary>
        IncludeLibrary = 0x40,   /* Evaluate the associated library
                                  * script, if any. */
        /// <summary>
        /// Reset the value of all removed variables.
        /// </summary>
        ResetValue = 0x80,       /* Reset the value of all removed
                                  * variables. */
        /// <summary>
        /// Skip "safe" or "unsafe" commands that are not also marked
        /// (flagged) as "critical".
        /// </summary>
        CriticalOnly = 0x100,    /* Skip "safe" or "unsafe" commands
                                  * that are not also marked (flagged)
                                  * as "critical". */

#if !MONO && NATIVE && WINDOWS
        /// <summary>
        /// Enable forcibly zeroing strings that may contain "sensitive" data?
        /// WARNING: THIS IS NOT GUARANTEED TO WORK RELIABLY ON ALL PLATFORMS.
        /// EXTREME CARE SHOULD BE EXERCISED WHEN HANDLING ANY SENSITIVE DATA.
        /// </summary>
        ZeroString = 0x1000,     /* Enable forcibly zeroing strings
                                  * that may contain "sensitive" data?
                                  * WARNING: THIS IS NOT GUARANTEED TO
                                  * WORK RELIABLY ON ALL PLATFORMS.
                                  * EXTREME CARE SHOULD BE EXERCISED
                                  * WHEN HANDLING ANY SENSITIVE DATA,
                                  * INCLUDING TESTING THAT THIS FLAG
                                  * WORKS WITHIN THE SPECIFIC TARGET
                                  * APPLICATION AND ON THE SPECIFIC
                                  * TARGET PLATFORM. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="ResetValue" /> and, where supported,
        /// <see cref="ZeroString" />.
        /// </summary>
        ResetValueAndZeroString = ResetValue |
#if !MONO && NATIVE && WINDOWS
                                  ZeroString,
#else
                                  None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="IncludeCommands" />,
        /// <see cref="IncludeProcedures" />, <see cref="IncludeVariables" />,
        /// <see cref="IncludeLibrary" />, and
        /// <see cref="ResetValueAndZeroString" />; the entities affected when
        /// making the script library "safe".
        /// </summary>
        SafeLibrary = IncludeCommands | IncludeProcedures |
                      IncludeVariables | IncludeLibrary |
                      ResetValueAndZeroString,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="SafeLibrary" /> and
        /// <see cref="IncludeFunctions" />; all entities affected when making
        /// an interpreter "safe".
        /// </summary>
        SafeAll = SafeLibrary | IncludeFunctions,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The entities affected when making the script library "standard"
        /// (equal to <see cref="IncludeCommands" />).
        /// </summary>
        StandardLibrary = IncludeCommands,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="StandardLibrary" />,
        /// <see cref="IncludeFunctions" />, and <see cref="IncludeOperators" />;
        /// all entities affected when making an interpreter "standard".
        /// </summary>
        StandardAll = StandardLibrary | IncludeFunctions |
                      IncludeOperators,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The entities affected when making an interactive shell "safe"
        /// (equal to <see cref="SafeAll" />).
        /// </summary>
        SafeShell = SafeAll,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The entities affected when making an interactive shell "standard"
        /// (equal to <see cref="StandardAll" />).
        /// </summary>
        StandardShell = StandardAll,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination based on <see cref="SafeAll" /> with the variable,
        /// library, and value-reset behavior removed; used when safely
        /// evaluating a script.
        /// </summary>
        SafeEvaluate = SafeAll & ~(IncludeVariables | IncludeLibrary | ResetValueAndZeroString),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// No flags are set; the default make flags.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe the
    /// characteristics and behavior of an expression function within
    /// TclTk.  Because the values are bit flags, they may be combined
    /// together using the bitwise-OR operator.
    /// </summary>
    [Flags()]
    [ObjectId("93f26486-9fd2-4705-9da6-172afd1b77e5")]
    public enum FunctionFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,              /* Invalid, do not use. */
        /// <summary>
        /// The function is part of the built-in core function set.
        /// </summary>
        Core = 0x2,                 /* This function is part of the core
                                     * function set. */
        /// <summary>
        /// The function requires special handling by the expression
        /// engine.
        /// </summary>
        Special = 0x4,              /* This function requires special handling
                                     * by the expression engine. */
        /// <summary>
        /// The function will not be returned by the plugin manager.
        /// </summary>
        NoPopulate = 0x8,           /* The function will not be returned by the
                                     * plugin manager. */
        /// <summary>
        /// The function may not be modified or removed.
        /// </summary>
        ReadOnly = 0x10,            /* The function may not be modified nor
                                     * removed. */
        /// <summary>
        /// Skip handling of the command token via the associated plugin.
        /// </summary>
        NoToken = 0x20,             /* Skip handling of the command token via
                                     * the associated plugin. */
        /// <summary>
        /// Break into the debugger before the function is executed.
        /// </summary>
        Breakpoint = 0x40,          /* Break into debugger before execution. */
        /// <summary>
        /// The function may not be executed.
        /// </summary>
        Disabled = 0x80,            /* The function may not be executed. */
        /// <summary>
        /// By default, the function will not be visible in the results of
        /// <c>[info functions]</c>.
        /// </summary>
        Hidden = 0x100,             /* By default, the function will not be
                                     * visible in the results of [info functions]. */
        /// <summary>
        /// The function is safe to execute for partially trusted or
        /// untrusted scripts.
        /// </summary>
        Safe = 0x200,               /* Function is "safe" to execute for
                                     * partially trusted and/or untrusted
                                     * scripts. */
        /// <summary>
        /// The function is not safe to execute for partially trusted or
        /// untrusted scripts.
        /// </summary>
        Unsafe = 0x400,             /* Function is NOT "safe" to execute for
                                     * partially trusted and/or untrusted
                                     * scripts. */
        /// <summary>
        /// The function is largely (or completely) compatible with an
        /// identically named function from Tcl/Tk 8.4, 8.5, and/or 8.6.
        /// </summary>
        Standard = 0x800,           /* The function is largely (or completely)
                                     * compatible with an identically named
                                     * function from Tcl/Tk 8.4, 8.5, and/or
                                     * 8.6. */
        /// <summary>
        /// The function is not present in Tcl/Tk 8.4, 8.5, and/or 8.6, or
        /// it is completely incompatible with an identically named
        /// function in those versions.
        /// </summary>
        NonStandard = 0x1000,       /* The function is not present in Tcl/Tk
                                     * 8.4, 8.5, and/or 8.6 -OR- it is
                                     * completely incompatible with an
                                     * identically named function in Tcl/Tk
                                     * 8.4, 8.5, and/or 8.6. */
        /// <summary>
        /// The function has been superseded and should not be used for new
        /// development.
        /// </summary>
        Obsolete = 0x2000,          /* The function has been superseded and
                                     * should not be used for new development. */
        /// <summary>
        /// Disable adding the function to the <c>tcl::mathfunc</c>
        /// namespace.
        /// </summary>
        NoTclMathFunction = 0x4000, /* Disable adding the command to the
                                     * "tcl::mathfunc" namespace. */
        /// <summary>
        /// Skip querying and combining the flags, etc, from the underlying
        /// managed type.
        /// </summary>
        NoAttributes = 0x8000,      /* Skip querying and combining the flags,
                                     * etc, from the underlying managed type. */
        /// <summary>
        /// Prevent the function from being renamed.
        /// </summary>
        NoRename = 0x10000,         /* Prevent the function from being renamed. */

        //
        // NOTE: This flag mask is only used for testing the core library.
        //
        /// <summary>
        /// Combination mask of <see cref="Obsolete" /> and
        /// <see cref="NoTclMathFunction" />, used only when testing the
        /// core library.
        /// </summary>
        ForTestUse = Obsolete | NoTclMathFunction,

        //
        // NOTE: These flags are added to a function when the parent interpreter
        //       is made "safe" or "standard".
        //
        /// <summary>
        /// Combination mask of <see cref="Disabled" /> and
        /// <see cref="Hidden" />, applied to a function when the parent
        /// interpreter is made safe or standard.
        /// </summary>
        DisabledAndHidden = Disabled | Hidden
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that control how text is
    /// rendered to an interactive host, including any visual decorations
    /// and the semantic category of the output.  Because the values are
    /// bit flags, they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("a227c466-4785-46ad-9000-9e3e8deff07f")]
    public enum OutputStyle
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = -1,
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Render the text using reversed (inverted) foreground and
        /// background colors.
        /// </summary>
        ReversedText = 0x1,
        /// <summary>
        /// Render the surrounding border using reversed (inverted) colors.
        /// </summary>
        ReversedBorder = 0x2,
        /// <summary>
        /// The output should be formatted before being displayed.
        /// </summary>
        Formatted = 0x4,
        /// <summary>
        /// The output should be enclosed within a box.
        /// </summary>
        Boxed = 0x8,
        /// <summary>
        /// The output represents normal, informational text.
        /// </summary>
        Normal = 0x10,
        /// <summary>
        /// The output represents debugging information.
        /// </summary>
        Debug = 0x20,
        /// <summary>
        /// The output represents an error message.
        /// </summary>
        Error = 0x40,

        /// <summary>
        /// Combination mask of <see cref="ReversedText" /> and
        /// <see cref="ReversedBorder" />.
        /// </summary>
        FlagMask = ReversedText | ReversedBorder,
        /// <summary>
        /// Combination mask of <see cref="Formatted" /> and
        /// <see cref="Boxed" />.
        /// </summary>
        BaseMask = Formatted | Boxed,
        /// <summary>
        /// Combination mask of <see cref="Normal" />,
        /// <see cref="Debug" />, and <see cref="Error" />.
        /// </summary>
        TypeMask = Normal | Debug | Error,

        /// <summary>
        /// Combination mask of <see cref="FlagMask" />,
        /// <see cref="BaseMask" />, and <see cref="TypeMask" />.
        /// </summary>
        All = FlagMask | BaseMask | TypeMask,
        /// <summary>
        /// Combination mask of <see cref="Boxed" /> and
        /// <see cref="Normal" />, representing the default output style.
        /// </summary>
        Default = Boxed | Normal
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that select how a file
    /// system path should be translated between the various supported
    /// platform conventions.  Because the values are bit flags, they may
    /// be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("e15a27e3-8f64-462c-95f5-21690ab6fcd1")]
    public enum PathTranslationType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Translate the path to use Unix-style conventions.
        /// </summary>
        Unix = 0x1,
        /// <summary>
        /// Translate the path to use Windows-style conventions.
        /// </summary>
        Windows = 0x2,
        /// <summary>
        /// Translate the path to use the conventions native to the current
        /// platform.
        /// </summary>
        Native = 0x4,
        /// <summary>
        /// Translate the path to use the conventions that are not native
        /// to the current platform.
        /// </summary>
        NonNative = 0x8,
        /// <summary>
        /// The default translation type, equivalent to
        /// <see cref="Unix" />.
        /// </summary>
        Default = Unix
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that control how the various
    /// library, package, and binary paths used by the TclTk core library
    /// are located and constructed.  Because the values are bit flags,
    /// they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("d26b161b-178c-44b1-a68c-08a4e6a4de94")]
    public enum PathFlags
    {
        /// <summary>
        /// No special handling is requested; this is also the normal
        /// default.
        /// </summary>
        None = 0x0,                  /* No special handling.  This is also the
                                      * normal default. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */
        /// <summary>
        /// Skip checking for the shared path being overridden.  When this
        /// flag is not set, the shared path is only used when it has been
        /// manually set.
        /// </summary>
        NoShared = 0x2,              /* Skip checking for the shared path being
                                      * overridden.  When this flag is not set,
                                      * the shared path is only used when it
                                      * has been manually set (i.e. it defaults
                                      * to null). */
        /// <summary>
        /// Use the root path, which is the <c>lib</c> directory directly
        /// beneath the currently effective base path for the TclTk core
        /// library.
        /// </summary>
        Root = 0x4,                  /* Use the root path, which is the "lib"
                                      * directory right beneath the currently
                                      * effective base path for the TclTk core
                                      * library. */
        /// <summary>
        /// Disable falling back on the path that contains the binary
        /// associated with the current process; the TclTk core library
        /// assembly path is used instead.
        /// </summary>
        NoBinary = 0x8,              /* Disable falling back on the path that
                                      * contains the binary associated with
                                      * the current process.  Normally, this
                                      * flag being set will cause the TclTk
                                      * core library assembly path to be used
                                      * instead. */
        /// <summary>
        /// Used primarily for Unix; prefer the <c>/usr/local/lib</c> path
        /// prefix over the <c>/usr/lib</c> path prefix.
        /// </summary>
        Local = 0x10,                /* Used primary for Unix.  Prefers to use
                                      * the "/usr/local/lib" path prefix over
                                      * the "/usr/lib" path prefix. */
        /// <summary>
        /// Skip modifying the path, e.g. to remove path segments that are
        /// well-known at build time, such as <c>netstandard2.0</c> or
        /// <c>BuildTasks</c>.
        /// </summary>
        Verbatim = 0x20,             /* Skip modifying the path, e.g. to remove
                                      * path segments that are "well-known" at
                                      * build-time.  Examples include the path
                                      * segments like "netstandard2.0",
                                      * "BuildTasks", etc. */
        /// <summary>
        /// Skip attempting to fully normalize the returned path, which may
        /// allow relative paths to be returned.
        /// </summary>
        NoFullPath = 0x40,           /* Skip attempting to fully normalize the
                                      * returned path.  This may allow relative
                                      * paths to be returned. */
        /// <summary>
        /// The non-package-specific portion of the returned path must
        /// actually exist.
        /// </summary>
        LibExists = 0x80,            /* The non-package specific portion of the
                                      * path returned must actually exist. */
        /// <summary>
        /// Do not use the package name and version to construct the final
        /// path unless the parent portion of the path was valid.
        /// </summary>
        Absolute = 0x100,            /* Do not use the package name and version
                                      * to construct the final path unless the
                                      * parent portion of the path was valid. */
        /// <summary>
        /// Do not initialize the shared binary path before querying it.
        /// This flag is for internal use only.
        /// </summary>
        NoInitialize = 0x200,        /* Do not initialize the shared binary
                                      * path before querying it.  This flag is
                                      * for internal use only. */
        /// <summary>
        /// Forcibly initialize the shared binary path before querying it.
        /// This flag is for internal use only.
        /// </summary>
        ForceInitialize = 0x400,     /* Forcibly initialize the shared binary
                                      * path before querying it.  This flag is
                                      * for internal use only. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip hashing the elements of the volume serial number for a
        /// given path.
        /// </summary>
        RawSerialNumber = 0x800,     /* Skip hashing the elements of the volume
                                      * serial number for a given path. */
        /// <summary>
        /// Skip including any volatile portions of the volume serial
        /// number for a given path.
        /// </summary>
        StableSerialNumber = 0x1000, /* Skip including any volatile portions of
                                      * the volume serial number for a given
                                      * path. */
        /// <summary>
        /// Skip including any of the volume serial number information for
        /// a given path.
        /// </summary>
        NoSerialNumber = 0x2000,     /* Skip including any of the volume serial
                                      * number information for a given path. */
        /// <summary>
        /// Use the link itself to calculate the associated serial number.
        /// </summary>
        LinkSerialNumber = 0x4000,   /* Use the link itself to calculate the
                                      * associated serial number. */
        /// <summary>
        /// Attempt to include per-user information when extracting
        /// metadata from candidate paths.
        /// </summary>
        PerUser = 0x8000,            /* Attempt to include per-user information
                                      * when extracting metadata from candidate
                                      * paths. */
        /// <summary>
        /// Include process information when extracting metadata.
        /// </summary>
        PerProcess = 0x10000,        /* Include process information. */
        /// <summary>
        /// Include a unique hash of the process executable code.
        /// </summary>
        ProcessHashCode = 0x20000,   /* Include unique hash of the process
                                      * executable code. */
        /// <summary>
        /// Avoid using the Windows registry.
        /// </summary>
        NoRegistry = 0x40000,        /* Avoid using the Windows registry. */
        /// <summary>
        /// Only use the Windows registry.
        /// </summary>
        RegistryOnly = 0x80000,      /* Only use the Windows registry. */
        /// <summary>
        /// Only use the volume serial number.
        /// </summary>
        SerialNumberOnly = 0x100000, /* Only use the volume serial number. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates that the default options were used to construct the
        /// current flags.
        /// </summary>
        ForDefault = 0x1000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region WARNING: FOR HARPY USE ONLY
        /// <summary>
        /// Reserved for use by Harpy only; see the surrounding region
        /// warning.
        /// </summary>
        ForHarpy = 0x2000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="NoShared" />,
        /// <see cref="Root" />, and <see cref="ForHarpy" />.
        /// </summary>
        RootOnly = NoShared | Root | ForHarpy,
        /// <summary>
        /// Combination mask of <see cref="NoShared" />,
        /// <see cref="NoBinary" />, and <see cref="ForHarpy" />.
        /// </summary>
        AssemblyOnly = NoShared | NoBinary | ForHarpy,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is used by Harpy to calculate the unique identifier
        //       that it will then consider as the current "machine".
        //
        /// <summary>
        /// Combination mask used by Harpy to calculate the unique
        /// identifier it treats as the current machine; it combines
        /// <see cref="PerUser" /> and <see cref="ForHarpy" /> (also
        /// including <see cref="StableSerialNumber" /> in debug builds).
        /// </summary>
        MachineForHarpy = PerUser |
#if DEBUG
                          StableSerialNumber |
#endif
                          ForHarpy,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is used by Harpy when provisioning "machine" locked
        //       license certificates.
        //
        /// <summary>
        /// Combination mask of <see cref="MachineForHarpy" />,
        /// <see cref="NoSerialNumber" />, and <see cref="ForHarpy" />,
        /// used by Harpy when provisioning machine-locked license
        /// certificates.
        /// </summary>
        VerifyForHarpy = MachineForHarpy | NoSerialNumber | ForHarpy,
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default path flags, equivalent to
        /// <see cref="ForDefault" />.
        /// </summary>
        Default = ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    //
    // NOTE: This enumeration type was moved from Harpy.
    //
    /// <summary>
    /// This enumeration defines the bit flags that control how remote
    /// network checking (e.g. for certificate and key pair revocation) is
    /// performed, as well as flags that record the observed state of the
    /// network subsystem.  Because the values are bit flags, they may be
    /// combined together.
    /// </summary>
    [Flags()]
    [ObjectId("fc9b7636-14a6-4512-be4a-dd595c5e7d3d")]
    public enum NetworkFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,                  /* None, do not use. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Used for debugging only; prevents the AlwaysExpires environment
        /// variable from being honored by certificate expiration checking
        /// when the certificate is being checked from within the
        /// certificate renewal process.
        /// </summary>
        ViaRenewal = 0x1000,         /* USED for DEBUG only (?).  Used
                                      * to prevent the AlwaysExpires
                                      * (environment) variable from
                                      * being honored by certificate
                                      * expiration checking when the
                                      * certificate is being checked
                                      * from within the certificate
                                      * renewal process. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Force use of remote checking for certificate and key pair
        /// revocation checks, etc.
        /// </summary>
        Force = 0x2000,              /* Force use of remote checking
                                      * for certificate and key pair
                                      * revocation checks, etc. */
        /// <summary>
        /// Fail the entire operation if remote checking fails for any
        /// reason, e.g. no network.
        /// </summary>
        Strict = 0x4000,             /* Fail the entire operation if
                                      * remote checking fails for any
                                      * reason, e.g. no network, etc.
                                      */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Only check the certificate in use, if any.
        /// </summary>
        CertificateOnly = 0x10000,   /* Only check the certificate in
                                      * use, if any. */
        /// <summary>
        /// Only check the key pair in use, if any.
        /// </summary>
        KeyPairOnly = 0x20000,       /* Only check the key pair in use,
                                      * if any. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Disable use of any caches.
        /// </summary>
        NoCache = 0x100000,          /* Disable use of any caches. */
        /// <summary>
        /// All remote checking should be performed using HTTPS, even when
        /// another option (e.g. NTP) is available.
        /// </summary>
        ViaHttp = 0x200000,          /* All remote checking should be
                                      * performed using HTTPS, even
                                      * when there is another option,
                                      * e.g. NTP. */
        /// <summary>
        /// If remote checking fails, the entire process should abort as
        /// soon as possible.
        /// </summary>
        FailSafe = 0x400000,         /* If remote checking fails, the
                                      * entire process should abort as
                                      * soon as possible. */
        /// <summary>
        /// Do not actually trip fail-safe upon hitting an error, just be
        /// sure to report it.
        /// </summary>
        WhatIf = 0x800000,           /* Do not actually trip fail-safe
                                      * upon hitting an error, just be
                                      * sure to report it. */
        /// <summary>
        /// Remote checking should be done from a thread other than the
        /// primary (calling) thread.
        /// </summary>
        Asynchronous = 0x1000000,    /* Remote checking should be done
                                      * from a thread that is not the
                                      * primary (calling) thread. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates that the network subsystem appears to be able to
        /// contact official time servers via NTP.
        /// </summary>
        NtpOk = 0x10000000,          /* This flag indicates that the
                                      * network subsystem appears to
                                      * be able to contact "official"
                                      * time servers via NTP. */
        /// <summary>
        /// Indicates that the network subsystem appears to be able to
        /// contact official certificate authority servers via HTTPS.
        /// </summary>
        HttpsOk = 0x20000000,        /* This flag indicates that the
                                      * network subsystem appears to
                                      * be able to contact "official"
                                      * certificate authority servers
                                      * via HTTPS. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates that the default options were used to set the current
        /// flags.
        /// </summary>
        ForDefault = 0x80000000,     /* Default options were used to
                                      * set the current flags. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Force" />,
        /// <see cref="Strict" />, <see cref="NoCache" />,
        /// <see cref="ViaHttp" />, <see cref="FailSafe" />,
        /// <see cref="WhatIf" />, and <see cref="Asynchronous" />.
        /// </summary>
        CommandMask = Force | Strict | NoCache | ViaHttp |
                      FailSafe | WhatIf | Asynchronous,

        /// <summary>
        /// Combination mask of <see cref="CertificateOnly" /> and
        /// <see cref="KeyPairOnly" />.
        /// </summary>
        OnlyMask = CertificateOnly | KeyPairOnly,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Force" /> and
        /// <see cref="Strict" />.
        /// </summary>
        ForceMask = Force | Strict,
        /// <summary>
        /// Combination mask of <see cref="FailSafe" /> and
        /// <see cref="Asynchronous" />.
        /// </summary>
        FailSafeMask = FailSafe | Asynchronous,
        /// <summary>
        /// Combination mask of <see cref="ForceMask" /> and
        /// <see cref="FailSafeMask" />.
        /// </summary>
        ForceFailSafeMask = ForceMask | FailSafeMask,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="NtpOk" /> and
        /// <see cref="HttpsOk" />.
        /// </summary>
        StateMask = NtpOk | HttpsOk,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default network flags, equivalent to
        /// <see cref="ForDefault" />.
        /// </summary>
        Default = ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that select the algorithm
    /// used when comparing and sorting file system paths.  Because the
    /// values are bit flags, they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("b0e68899-9337-4d3b-8691-a2f5588cc987")]
    public enum PathComparisonType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Treat paths as plain strings, comparing them with
        /// String.Compare.
        /// </summary>
        String = 0x1,       /* Treat as plain strings with String.Compare. */
        /// <summary>
        /// File names with more path segments sort first; ties are broken
        /// with String.Compare.
        /// </summary>
        DeepestFirst = 0x2, /* File names with more segments sort first.  Ties
                             * are broken with String.Compare. */
        /// <summary>
        /// File names with more path segments sort last; ties are broken
        /// with String.Compare.
        /// </summary>
        DeepestLast = 0x4,  /* File names with more segments sort last.  Ties
                             * are broken with String.Compare. */
        /// <summary>
        /// Use the default .NET Framework sorting.
        /// </summary>
        BuiltIn = 0x8,      /* Use the default .NET Framework sorting. */

        /// <summary>
        /// The default comparison type, equivalent to
        /// <see cref="String" />.
        /// </summary>
        Default = String
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe an
    /// input/output channel and control how it is created, opened, and
    /// managed.  Because the values are bit flags, they may be combined
    /// together.
    /// </summary>
    [Flags()]
    [ObjectId("799013e1-6b95-4586-bde4-4bbfadbc986d")]
    public enum ChannelType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The channel is used for input.
        /// </summary>
        Input = 0x2,
        /// <summary>
        /// The channel is used for output.
        /// </summary>
        Output = 0x4,
        /// <summary>
        /// The channel is used for error output.
        /// </summary>
        Error = 0x8,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow the operation to succeed even if the channel already
        /// exists.
        /// </summary>
        AllowExist = 0x10,
        /// <summary>
        /// Allow the channel to be backed by a proxy.
        /// </summary>
        AllowProxy = 0x20,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Begin a new channel context.
        /// </summary>
        BeginContext = 0x40,
        /// <summary>
        /// End the current channel context.
        /// </summary>
        EndContext = 0x80,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Raise an error if the channel already exists.
        /// </summary>
        ErrorOnExist = 0x100,
        /// <summary>
        /// Raise an error if the channel does not exist.
        /// </summary>
        ErrorOnNotExist = 0x200,
        /// <summary>
        /// Raise an error if the channel is null.
        /// </summary>
        ErrorOnNull = 0x400,
        /// <summary>
        /// Raise an error if the channel is backed by a proxy.
        /// </summary>
        ErrorOnProxy = 0x800,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Use the current channel associated with the interpreter.
        /// </summary>
        UseCurrent = 0x1000,
        /// <summary>
        /// Use the channel provided by the interpreter host.
        /// </summary>
        UseHost = 0x2000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip obtaining the underlying stream for the channel.
        /// </summary>
        SkipGetStream = 0x4000,
        /// <summary>
        /// Close the channel when its context is ended.
        /// </summary>
        CloseOnEndContext = 0x8000,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CONSOLE
        /// <summary>
        /// The channel is associated with the system console.
        /// </summary>
        Console = 0x10000,

        /// <summary>
        /// Combination mask of all of the channel behavior flags,
        /// including <see cref="Console" />.
        /// </summary>
        FlagMask = AllowExist | AllowProxy | BeginContext |
                   EndContext | ErrorOnExist | ErrorOnNotExist |
                   ErrorOnNull | ErrorOnProxy | UseCurrent |
                   UseHost | SkipGetStream | CloseOnEndContext |
                   Console,
#else
        /// <summary>
        /// Combination mask of all of the channel behavior flags.
        /// </summary>
        FlagMask = AllowExist | AllowProxy | BeginContext |
                   EndContext | ErrorOnExist | ErrorOnNotExist |
                   ErrorOnNull | ErrorOnProxy | UseCurrent |
                   UseHost | SkipGetStream | CloseOnEndContext,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Input" />,
        /// <see cref="Output" />, and <see cref="Error" />.
        /// </summary>
        StandardChannels = Input | Output | Error
    }

