    /// <summary>
    /// This enumeration defines the bit flags that describe the
    /// characteristics and behavior of a variable trace.  Because the
    /// values are bit flags, they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("de027927-2975-4c1d-98bb-53036202db09")]
    public enum TraceFlags
    {
        /// <summary>
        /// No flags are set; use default handling.
        /// </summary>
        None = 0x0,          /* unspecified trace type, use default handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,       /* invalid, do not use. */
        /// <summary>
        /// The trace cannot be removed.
        /// </summary>
        ReadOnly = 0x2,      /* The trace cannot be removed. */
        /// <summary>
        /// The trace is disabled and will not be invoked.
        /// </summary>
        Disabled = 0x4,      /* The trace is disabled and will not be invoked. */
        /// <summary>
        /// Skip handling of the trace token via the associated plugin.
        /// </summary>
        NoToken = 0x8,       /* Skip handling of the trace token via the associated plugin. */
        /// <summary>
        /// The trace is interpreter-wide.
        /// </summary>
        Global = 0x10,       /* The trace is interpreter-wide. */
        /// <summary>
        /// Skip querying and combining the flags, etc, from the underlying
        /// managed type.
        /// </summary>
        NoAttributes = 0x20, /* Skip querying and combining the flags, etc, from the underlying
                              * managed type. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that categorize the kind of
    /// entity that a policy is responsible for evaluating.  Because the
    /// values are bit flags, they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("734721a6-0f3d-4379-b80c-394616285bf5")]
    public enum PolicyType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The policy applies to an entity of an unknown kind.
        /// </summary>
        Unknown = 0x2,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The policy applies to a script.
        /// </summary>
        Script = 0x1000,
        /// <summary>
        /// The policy applies to a file.
        /// </summary>
        File = 0x2000,
        /// <summary>
        /// The policy applies to a stream.
        /// </summary>
        Stream = 0x4000,
        /// <summary>
        /// The policy applies to a license.
        /// </summary>
        License = 0x8000,
        /// <summary>
        /// The policy applies to a key pair.
