        KeyPair = 0x10000,
        /// <summary>
        /// The policy applies to a trace.
        /// </summary>
        Trace = 0x20000,
        /// <summary>
        /// The policy applies to some other kind of entity.
        /// </summary>
        Other = 0x40000
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that identify the context in
    /// which a policy decision is being made and the phase of evaluation
    /// it represents.  Because the values are bit flags, they may be
    /// combined together.
    /// </summary>
    [Flags()]
    [ObjectId("b89ec41e-7f22-461f-9363-544b22fcf606")]
    public enum PolicyDecisionType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// A reserved value; callers should not use it.
        /// </summary>
        Reserved = 0x2,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The decision is being made in the context of a command.
        /// </summary>
        Command = 0x10,
        /// <summary>
        /// The decision is being made in the context of a script.
        /// </summary>
        Script = 0x20,
        /// <summary>
        /// The decision is being made in the context of a file.
        /// </summary>
        File = 0x40,
        /// <summary>
        /// The decision is being made in the context of a stream.
        /// </summary>
        Stream = 0x80,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The decision is being made during the initial phase of
        /// evaluation.
        /// </summary>
        Initial = 0x100,
        /// <summary>
        /// The decision is being made during the final phase of
        /// evaluation.
        /// </summary>
        Final = 0x200,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Command" />,
        /// <see cref="Script" />, <see cref="File" />, and
        /// <see cref="Stream" />.
        /// </summary>
        QueryMask = Command | Script | File | Stream,
        /// <summary>
        /// Combination mask of <see cref="Initial" /> and
        /// <see cref="Final" />.
        /// </summary>
        FlagMask = Initial | Final,
        /// <summary>
        /// Combination mask of <see cref="QueryMask" /> and
        /// <see cref="FlagMask" />.
        /// </summary>
        All = QueryMask | FlagMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates that the default options were used to construct the
        /// current flags.
        /// </summary>
        ForDefault = 0x1000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="File" />, <see cref="Final" />,
        /// and <see cref="ForDefault" />, representing the default policy
        /// decision type.
        /// </summary>
        Default = File | Final | ForDefault,
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe the
    /// characteristics of a policy, including when it is invoked, what it
    /// operates on, and how it reaches its decision.  Because the values
    /// are bit flags, they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("1eafc4d0-b42a-401c-a6a9-6c08940df3bf")]
    public enum PolicyFlags
    {
        /// <summary>
        /// No flags are set; use default handling.
        /// </summary>
        None = 0x0,               /* unspecified policy type, use default handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,            /* invalid, do not use. */
        /// <summary>
        /// The policy cannot be removed.
        /// </summary>
        ReadOnly = 0x2,           /* The policy cannot be removed. */
        /// <summary>
        /// The policy is disabled and will not be invoked.
        /// </summary>
        Disabled = 0x4,           /* The policy is disabled and will not be invoked. */
        /// <summary>
        /// Skip handling of the policy token via the associated plugin.
        /// </summary>
        NoToken = 0x8,            /* Skip handling of the policy token via the associated plugin. */
        /// <summary>
        /// The policy is invoked directly by the engine.
        /// </summary>
        ForEngine = 0x10,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The policy is invoked prior to loading a plugin assembly.
        /// </summary>
        BeforePlugin = 0x20,      /* being invoked prior to loading a plugin assembly. */
        /// <summary>
        /// The policy is invoked prior to returning an IScript object
        /// created from an external source.
        /// </summary>
        BeforeScript = 0x40,      /* being invoked prior to returning an IScript object
                                   * created from an external source. */
        /// <summary>
        /// The policy is invoked prior to reading a script file.
        /// </summary>
        BeforeFile = 0x80,        /* being invoked prior to reading a script file. */
        /// <summary>
        /// The policy is invoked prior to reading a script stream.
        /// </summary>
        BeforeStream = 0x100,     /* being invoked prior to reading a script stream. */
        /// <summary>
        /// The policy is invoked prior to the execution of a command.
        /// </summary>
        BeforeCommand = 0x200,    /* being invoked prior to the execution of a command. */
        /// <summary>
        /// The policy is invoked prior to the execution of a sub-command.
        /// </summary>
        BeforeSubCommand = 0x400, /* being invoked prior to the execution of a sub-command. */
        /// <summary>
        /// The policy is invoked prior to the execution of a procedure.
        /// </summary>
        BeforeProcedure = 0x800,  /* being invoked prior to the execution of a procedure. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The policy is invoked after reading a script file.
        /// </summary>
        AfterFile = 0x1000,       /* being invoked after reading a script file. */
        /// <summary>
        /// The policy is invoked after reading a script stream.
        /// </summary>
        AfterStream = 0x2000,     /* being invoked after reading a script stream. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip any hashing of the file and/or stream content during the
        /// before phase.
        /// </summary>
        BeforeNoHash = 0x4000,    /* skip any hashing of the file and/or stream content. */
        /// <summary>
        /// Skip any hashing of the file and/or stream content during the
        /// after phase.
        /// </summary>
        AfterNoHash = 0x8000,     /* skip any hashing of the file and/or stream content. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The policy invokes a user callback.
        /// </summary>
        Callback = 0x10000,       /* invokes a user callback. */
        /// <summary>
        /// The policy checks a directory against a list.
        /// </summary>
        Directory = 0x20000,      /* checks a directory against a list. */
        /// <summary>
        /// The policy evaluates a user script.
        /// </summary>
        Script = 0x40000,         /* evaluates a user script. */
        /// <summary>
        /// The policy checks a sub-command against a list.
        /// </summary>
        SubCommand = 0x80000,     /* checks a sub-command against a list. */
        /// <summary>
        /// The policy checks a type against a list.
        /// </summary>
        Type = 0x100000,          /* checks a type against a list. */
        /// <summary>
        /// The policy checks a URI against a list.
        /// </summary>
        Uri = 0x200000,           /* checks a uri against a list. */
        /// <summary>
        /// The policy script is a list.
        /// </summary>
        SplitList = 0x400000,     /* policy script is a list. */
        /// <summary>
        /// Append the command arguments to the policy script prior to
        /// evaluation.
        /// </summary>
        Arguments = 0x800000,     /* append command arguments to policy script prior to
                                   * evaluation. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip querying and combining the flags, etc, from the underlying
        /// managed type.
        /// </summary>
        NoAttributes = 0x1000000, /* Skip querying and combining the flags, etc,
                                   * from the underlying managed type. */

        /// <summary>
        /// The script policy should create and own a dedicated interpreter
        /// for evaluation.
        /// </summary>
        Isolated = 0x2000000,     /* The script policy should create and own a
                                   * dedicated interpreter for evaluation. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="BeforePlugin" />,
        /// <see cref="BeforeScript" />, <see cref="BeforeFile" />,
        /// <see cref="BeforeStream" />, <see cref="BeforeCommand" />,
        /// <see cref="BeforeSubCommand" />, and
        /// <see cref="BeforeProcedure" />.
        /// </summary>
        BeforeAny = BeforePlugin | BeforeScript | BeforeFile | BeforeStream |
                    BeforeCommand | BeforeSubCommand | BeforeProcedure,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AfterFile" /> and
        /// <see cref="AfterStream" />.
        /// </summary>
        AfterAny = AfterFile | AfterStream,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="BeforeNoHash" /> and
        /// <see cref="AfterNoHash" />.
        /// </summary>
        FlagsMask = BeforeNoHash | AfterNoHash,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="BeforePlugin" />.
        /// </summary>
        EngineBeforePlugin = ForEngine | BeforePlugin,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="BeforeScript" />.
        /// </summary>
        EngineBeforeScript = ForEngine | BeforeScript,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" />,
        /// <see cref="BeforeFile" />, and <see cref="BeforeNoHash" />.
        /// </summary>
        EngineBeforeFile = ForEngine | BeforeFile | BeforeNoHash,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" />,
        /// <see cref="BeforeStream" />, and <see cref="BeforeNoHash" />.
        /// </summary>
        EngineBeforeStream = ForEngine | BeforeStream | BeforeNoHash,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="BeforeCommand" />.
        /// </summary>
        EngineBeforeCommand = ForEngine | BeforeCommand,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="BeforeSubCommand" />.
        /// </summary>
        EngineBeforeSubCommand = ForEngine | BeforeSubCommand,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="BeforeProcedure" />.
        /// </summary>
        EngineBeforeProcedure = ForEngine | BeforeProcedure,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="BeforeFile" /> and
        /// <see cref="BeforeStream" />.
        /// </summary>
        EngineBeforeMask = BeforeFile | BeforeStream,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="AfterFile" />.
        /// </summary>
        EngineAfterFile = ForEngine | AfterFile,
        /// <summary>
        /// Combination mask of <see cref="ForEngine" /> and
        /// <see cref="AfterStream" />.
        /// </summary>
        EngineAfterStream = ForEngine | AfterStream
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the possible outcomes of evaluating a
    /// policy, indicating whether the associated operation should be
    /// allowed to proceed.
    /// </summary>
    [ObjectId("4d68dbeb-d698-4b67-94dd-8e497b3e0e11")]
    public enum PolicyDecision
    {
        /// <summary>
        /// No decision has been made.
        /// </summary>
        None = 0,

        /// <summary>
        /// The policy has not yet reached a decision.
        /// </summary>
        Undecided = 1,
        /// <summary>
        /// The policy denies the associated operation.
        /// </summary>
        Denied = 2,
        /// <summary>
        /// The policy approves the associated operation.
        /// </summary>
        Approved = 3,

        /// <summary>
        /// The policy defers, allowing evaluation to continue with the
        /// next policy.
        /// </summary>
        Continue = 4,
        /// <summary>
        /// The decision is pending and has not yet been finalized.
        /// </summary>
        Pending = 5,
        /// <summary>
        /// The policy halts further evaluation of subsequent policies.
        /// </summary>
        Stop = 6,

        /// <summary>
        /// The policy evaluation completed successfully.
        /// </summary>
        Success = 7,
        /// <summary>
        /// The outcome of the policy evaluation is unknown.
        /// </summary>
        Unknown = 8,
        /// <summary>
        /// The policy evaluation failed.
        /// </summary>
        Failure = 9,

        /// <summary>
        /// The default decision, equivalent to <see cref="Denied" />.
        /// </summary>
        Default = Denied
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe the kind,
    /// format, and intended use of a file system path.  Because the values
    /// are bit flags, they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("333bce33-eb11-4c7b-b7b9-e48bd6a1ac38")]
    public enum PathType : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The kind of path is unknown.
        /// </summary>
        Unknown = 0x2,

        /// <summary>
        /// Force the path to be interpreted using Windows conventions.
        /// </summary>
        ForceWindows = 0x10,
        /// <summary>
        /// Force the path to be interpreted using Unix conventions.
        /// </summary>
        ForceUnix = 0x20,

        /// <summary>
        /// Allow a Win32 drive letter to be present in the path.
        /// </summary>
        AllowDrive = 0x40, /* Win32 */
        /// <summary>
        /// Disallow a Win32 drive letter in the path.
        /// </summary>
        DisallowDrive = 0x80, /* Win32 */

        /// <summary>
        /// Allow a Win32 extended-length path prefix.
        /// </summary>
        AllowExtended = 0x100, /* Win32 */
        /// <summary>
        /// Disallow a Win32 extended-length path prefix.
        /// </summary>
        DisallowExtended = 0x200, /* Win32 */

        /// <summary>
        /// The path is a normal path.
        /// </summary>
        Normal = 0x1000,
        /// <summary>
        /// The path refers to a device.
        /// </summary>
        Device = 0x2000,
        /// <summary>
        /// The path is a Win32 extended-length path.
        /// </summary>
        Extended = 0x4000, /* Win32 */
        /// <summary>
        /// The path is a Win32 UNC path.
        /// </summary>
        Unc = 0x8000, /* Win32 */
        /// <summary>
        /// The path is expressed as a URI.
        /// </summary>
        Uri = 0x10000,

        /// <summary>
        /// The value represents a path.
        /// </summary>
        Path = 0x100000,
        /// <summary>
        /// The value represents a directory.
        /// </summary>
        Directory = 0x200000,
        /// <summary>
        /// The value represents a file.
        /// </summary>
        File = 0x400000,
        /// <summary>
        /// The value represents a single path component only.
        /// </summary>
        Component = 0x800000, /* single part only */

        /// <summary>
        /// The path is relative.
        /// </summary>
        Relative = 0x1000000,
        /// <summary>
        /// The path is Win32 volume-relative.
        /// </summary>
        VolumeRelative = 0x2000000, /* Win32 */
        /// <summary>
        /// The path is absolute.
        /// </summary>
        Absolute = 0x4000000,

        /// <summary>
        /// Verify the path as part of processing it.
        /// </summary>
        Verify = 0x10000000,
        /// <summary>
        /// Allow matching at any level of the path hierarchy.
        /// </summary>
        AnyLevel = 0x20000000,
        /// <summary>
        /// Process the path using more robust handling.
        /// </summary>
        Robust = 0x40000000,

        /// <summary>
        /// The path is being processed for the <c>[file validname]</c>
        /// sub-command.
        /// </summary>
        ForValidName = 0x100000000, /* for [file validname] sub-command */
        /// <summary>
        /// The path is being processed for the <c>[file cleanup]</c>
        /// sub-command.
        /// </summary>
        ForCleanup = 0x200000000,   /* for [file cleanup] sub-command */
        /// <summary>
        /// The path is being processed for the <c>[file under]</c>
        /// sub-command.
        /// </summary>
        ForUnder = 0x400000000,     /* for [file under] sub-command */

        /// <summary>
        /// Combination mask of <see cref="Directory" /> and
        /// <see cref="File" />.
        /// </summary>
        Both = Directory | File,

        /// <summary>
        /// Combination mask of <see cref="File" /> and
        /// <see cref="ForCleanup" />.
        /// </summary>
        Cleanup = File | ForCleanup,
        /// <summary>
        /// Combination mask of <see cref="Both" />, <see cref="Robust" />,
        /// and <see cref="ForUnder" />.
        /// </summary>
        Under = Both | Robust | ForUnder,
        /// <summary>
        /// The default path type, equivalent to
        /// <see cref="ForValidName" />.
        /// </summary>
        Default = ForValidName
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how Uniform Resource
    /// Identifiers (URIs) are recognized, validated, and combined. Because
    /// these are flags, multiple values may be combined together using a
    /// bitwise OR to express a set of options.
    /// </summary>
    [Flags()]
    [ObjectId("e0b341df-fc31-40c9-954a-d84cb8a09217")]
    public enum UriFlags
    {
        /// <summary>
        /// No flags are set; no special handling is performed.
        /// </summary>
        None = 0x0,       /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid flag value; callers
        /// should not use it.
        /// </summary>
        Invalid = 0x1,    /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow URIs that use the FILE scheme.
        /// </summary>
        AllowFile = 0x2,  /* Allow URIs with the FILE scheme. */
        /// <summary>
        /// Allow URIs that use the HTTP scheme.
        /// </summary>
        AllowHttp = 0x4,  /* Allow URIs with the HTTP scheme. */
        /// <summary>
        /// Allow URIs that use the HTTPS scheme.
        /// </summary>
        AllowHttps = 0x8, /* Allow URIs with the HTTPS scheme. */
        /// <summary>
        /// Allow URIs that use the FTP scheme.
        /// </summary>
        AllowFtp = 0x10,  /* Allow URIs with the FTP scheme. */
        /// <summary>
        /// Do not query the host property of the URI.
        /// </summary>
        NoHost = 0x20,    /* Do not query the host property. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates that the URI was found to use the FILE scheme.
        /// </summary>
        WasFile = 0x100,
        /// <summary>
        /// Indicates that the URI was found to use the HTTP scheme.
        /// </summary>
        WasHttp = 0x200,
        /// <summary>
        /// Indicates that the URI was found to use the HTTPS scheme.
        /// </summary>
        WasHttps = 0x400,
        /// <summary>
        /// Indicates that the URI was found to use the FTP scheme.
        /// </summary>
        WasFtp = 0x800,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Reserved1 = 0x1000,
        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Reserved2 = 0x2000,
        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Reserved3 = 0x4000,
        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Reserved4 = 0x8000,
        /// <summary>
        /// Reserved for future use.
        /// </summary>
        Reserved5 = 0x10000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags only work with TryCombineUris.
        //
        /// <summary>
        /// Use the explicitly specified UriFormat when processing the URI.
        /// </summary>
        UseFormat = 0x20000,       /* Use specified UriFormat. */
        /// <summary>
        /// Normalize the path by converting backslashes to forward slashes.
        /// </summary>
        Normalize = 0x40000,       /* Convert path backslash to slash. */
        /// <summary>
        /// Skip using path separators when combining the path portions of
        /// the URIs.
        /// </summary>
        NoSeparators = 0x80000,    /* Skip using path separators when
                                    * combining path portions of the
                                    * URIs. */
        /// <summary>
        /// Trim Unix-style path separators when combining the path portions
        /// of the URIs.
        /// </summary>
        OneSeparator = 0x100000,   /* Trim Unix path separators when
                                    * combining path portions of the
                                    * URIs. */
        /// <summary>
        /// Trim both styles of path separators when combining the path
        /// portions of the URIs.
        /// </summary>
        BothSeparators = 0x200000, /* Trim both path separators when
                                    * combining path portions of the
                                    * URIs. */
        /// <summary>
        /// Only consider the path portion of the base URI, discarding the
        /// path portion of the relative URI.
        /// </summary>
        BasePath = 0x400000,       /* Only consider the path portion
                                    * of the base URI, discarding the
                                    * path portion of the relative
                                    * URI. */
        /// <summary>
        /// Only consider the path portion of the relative URI, discarding
        /// the path portion of the base URI.
        /// </summary>
        RelativePath = 0x800000,   /* Only consider the path portion
                                    * of the relative URI, discarding
                                    * the path portion of the base
                                    * URI. */
        /// <summary>
        /// Prefer the fragment taken from the base URI.
        /// </summary>
        PreferBaseUri = 0x1000000, /* Prefer fragment from baseUri. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllowFile" />, <see
        /// cref="AllowHttp" />, <see cref="AllowHttps" />, and <see
        /// cref="AllowFtp" />.
        /// </summary>
        AllowMask = AllowFile | AllowHttp | AllowHttps | AllowFtp,
        /// <summary>
        /// Combination mask of <see cref="WasFile" />, <see cref="WasHttp"
        /// />, <see cref="WasHttps" />, and <see cref="WasFtp" />.
        /// </summary>
        WasMask = WasFile | WasHttp | WasHttps | WasFtp,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Reserved1" /> and <see
        /// cref="AllowFile" />.
        /// </summary>
        LocalOnlyMask = Reserved1 | AllowFile,
        /// <summary>
        /// Combination mask of <see cref="Reserved1" /> and <see
        /// cref="WasFile" />.
        /// </summary>
        WasLocalMask = Reserved1 | WasFile,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Reserved2" />, <see
        /// cref="AllowHttp" />, and <see cref="AllowHttps" />.
        /// </summary>
        WebOnlyMask = Reserved2 | AllowHttp | AllowHttps,
        /// <summary>
        /// Combination mask of <see cref="Reserved2" />, <see
        /// cref="WasHttp" />, and <see cref="WasHttps" />.
        /// </summary>
        WasWebMask = Reserved2 | WasHttp | WasHttps,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Reserved3" />, <see
        /// cref="AllowHttp" />, and <see cref="AllowFtp" />.
        /// </summary>
        InsecureOnlyMask = Reserved3 | AllowHttp | AllowFtp,
        /// <summary>
        /// Combination mask of <see cref="Reserved3" />, <see
        /// cref="WasHttp" />, and <see cref="WasFtp" />.
        /// </summary>
        WasInsecureMask = Reserved3 | WasHttp | WasFtp,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Reserved4" /> and <see
        /// cref="AllowHttps" />.
        /// </summary>
        SecureOnlyMask = Reserved4 | AllowHttps,
        /// <summary>
        /// Combination mask of <see cref="Reserved4" /> and <see
        /// cref="WasHttps" />.
        /// </summary>
        WasSecureMask = Reserved4 | WasHttps,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of flags, combining <see cref="Reserved5" /> and
        /// <see cref="WebOnlyMask" />.
        /// </summary>
        Default = Reserved5 | WebOnlyMask
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that govern the security policy
    /// decisions made when reading, verifying, and evaluating signed
    /// scripts and assemblies. Because these are flags, multiple values may
    /// be combined together using a bitwise OR to express a complete
    /// policy.
    /// </summary>
    [Flags()]
    [ObjectId("e68f81aa-f0b1-414a-8bab-1bf5626d0727")]
    public enum ExecutionPolicy : ulong
    {
        /// <summary>
        /// No flags are set; the policy check is skipped, effectively the
        /// same as allowing everything.
        /// </summary>
        None = 0x0,                              /* Skip policy check, effectively
                                                  * the same as allowing all. */
        /// <summary>
        /// A reserved sentinel indicating an invalid flag value; callers
        /// should not use it.
        /// </summary>
        Invalid = 0x1,                           /* Invalid, do not use. */
        /// <summary>
        /// The policy has not been explicitly set and is not defined; this
        /// value should not be returned by a public API, nor should it be
        /// included in a value that is explicitly set.
        /// </summary>
        Undefined = 0x2,                         /* The policy has not been explicilty
                                                  * set and is not defined.  This value
                                                  * should not be returned by a public
                                                  * API.  Nor should it be included in
                                                  * a value that is explicitly set. */
        /// <summary>
        /// When dealing with embedded resources inside an assembly, allow
        /// any public key to be used for signing that assembly.
        /// </summary>
        AnyResourcePublicKey = 0x4,              /* When dealing with embedded resources
                                                  * inside of an assembly, allow for any
                                                  * public key to be used for signing
                                                  * that assembly. */
        /// <summary>
        /// No files are allowed to be read and/or evaluated.
        /// </summary>
        AllowNone = 0x8,                         /* No files are allowed to be read
                                                  * and/or evaluated. */
        /// <summary>
        /// Only files that are signed and trusted are allowed to be read
        /// and/or evaluated.
        /// </summary>
        AllowSignedOnly = 0x10,                  /* Only files that are signed and
                                                  * trusted are allowed to be read
                                                  * and/or evaluated. */
        /// <summary>
        /// All files are allowed to be read and/or evaluated.
        /// </summary>
        AllowAny = 0x20,                         /* All files are allowed to be read
                                                  * and/or evaluated. */
        /// <summary>
        /// Bypass all file-exists checking (i.e. for non-URIs).
        /// </summary>
        SkipExists = 0x40,                       /* Bypass all file-exists checking
                                                  * (i.e. for non-URIs). */
        /// <summary>
        /// Validate the XML against the XSD schema.
        /// </summary>
        ValidateXml = 0x80,                      /* Validate the XML against the XSD
                                                  * schema. */
        /// <summary>
        /// Enforce that the certificate subject matches the X509 subject on
        /// the associated assembly.
        /// </summary>
        MatchSubject = 0x100,                    /* Enforce the certificate subject
                                                  * matching the X509 subject on the
                                                  * associated assembly. */
        /// <summary>
        /// The X509 subject and simple (subject) name should also be
        /// matched using prefix semantics.
        /// </summary>
        MatchSubjectPrefix = 0x200,              /* The X509 subject and simple
                                                  * (subject) name should be matched
                                                  * using prefix semantics as well. */
        /// <summary>
        /// The X509 simple (subject) name should also be checked.
        /// </summary>
        MatchSubjectSimpleName = 0x400,          /* The X509 simple (subject) name
                                                  * should also be checked. */
        /// <summary>
        /// Enforce certificate expiration dates.
        /// </summary>
        CheckExpiry = 0x800,                     /* Enforce certificate expiration
                                                  * dates. */
        /// <summary>
        /// Enforce certificate entity types.
        /// </summary>
        CheckEntityType = 0x1000,                /* Enforce certificate entity types. */
        /// <summary>
        /// Treat the content to be verified as a string.
        /// </summary>
        VerifyString = 0x2000,                   /* Treat the content to be verified as
                                                  * a string. */
        /// <summary>
        /// Treat the content to be verified as a file.
        /// </summary>
        VerifyFile = 0x4000,                     /* Treat the content to be verified as
                                                  * a file. */
        /// <summary>
        /// Make sure the public key tokens match.
        /// </summary>
        CheckPublicKeyToken = 0x8000,            /* Make sure the public key tokens
                                                  * match. */
        /// <summary>
        /// The public keys used to sign the assembly may be used.
        /// </summary>
        AllowAssemblyPublicKey = 0x10000,        /* The public keys used to sign the
                                                  * assembly may be used. */
        /// <summary>
        /// Public keys embedded within the assembly as resources may be
        /// used.
        /// </summary>
        AllowEmbeddedPublicKey = 0x20000,        /* Public keys embedded within the
                                                  * assembly as resources may be used.
                                                  */
        /// <summary>
        /// Public keys present on the trusted key ring(s) may be used.
        /// </summary>
        AllowRingPublicKey = 0x40000,            /* Public keys present on the trusted
                                                  * key ring(s) may be used. */
        /// <summary>
        /// Any public key present in the assembly may be used; otherwise,
        /// only the named public key may be used.
        /// </summary>
        AllowAnyPublicKey = 0x80000,             /* Any public key present in the
                                                  * assembly may be used; otherwise,
                                                  * only the named public key may be
                                                  * used. */
        /// <summary>
        /// Files that are signed and trusted are evaluated with full
        /// permissions, even in a "safe" interpreter.
        /// </summary>
        TrustSignedOnly = 0x100000,              /* Files that are signed and trusted
                                                  * are evaluated with full permissions,
                                                  * even in a "safe" interpreter. */
        /// <summary>
        /// Enforce domain restrictions.
        /// </summary>
        CheckDomains = 0x200000,                 /* Enforce domain restrictions. */
        /// <summary>
        /// Enforce certificate quantities.
        /// </summary>
        CheckQuantity = 0x400000,                /* Enforce certificate quantities. */
        /// <summary>
        /// Protect certificate quantities.
        /// </summary>
        ProtectQuantity = 0x800000,              /* Protect certificate quantities. */
        /// <summary>
        /// Protect data on a per-machine basis.
        /// </summary>
        PerMachine = 0x1000000,                  /* Protect data on a per-machine basis.
                                                  */
        /// <summary>
        /// Permit the certificate to be embedded within the data.
        /// </summary>
        AllowEmbedded = 0x2000000,               /* Permit the certificate to be
                                                  * embedded within the data. */
        /// <summary>
        /// Do not check the native file system for certificate data.
        /// </summary>
        SkipFile = 0x4000000,                    /* Do not check the native file system
                                                  * for certificate data. */
        /// <summary>
        /// Do not check the interpreter host for certificate data.
        /// </summary>
        SkipHost = 0x8000000,                    /* Do not check the interpreter host
                                                  * for certificate data. */
        /// <summary>
        /// Do not check the file name based on the hash value of the
        /// contained data for its certificate data as renewed by the
        /// server.
        /// </summary>
        SkipRenewedName = 0x10000000,            /* Do not check the file name based on
                                                  * the hash value of the contained data
                                                  * for its certificate data as renewed
                                                  * by the server. */
        /// <summary>
        /// Do not check the file name based on the hash value of the
        /// contained data for its certificate data.
        /// </summary>
        SkipHashName = 0x20000000,               /* Do not check the file name based on
                                                  * the hash value of the contained data
                                                  * for its certificate data. */
        /// <summary>
        /// Do not check the file name based on the original file name for
        /// its certificate data.
        /// </summary>
        SkipPlainName = 0x40000000,              /* Do not check the file name based on
                                                  * the original file name for its
                                                  * certificate data. */
        /// <summary>
        /// Keep track of the data associated with approved policy checks.
        /// </summary>
        SaveApprovedData = 0x80000000,           /* Keep track of the data associated
                                                  * with approved policy checks. */
        /// <summary>
        /// Make sure that a key is only used in conjunction with its
        /// associated assemblies.
        /// </summary>
        EnforceKeyGroup = 0x100000000,           /* Make sure that a key is only used
                                                  * in conjunction with its associated
                                                  * assemblies. */
        /// <summary>
        /// Make sure that a key is only used in compliance with its
        /// declared key usage.
        /// </summary>
        EnforceKeyUsage = 0x200000000,           /* Make sure that a key is only used
                                                  * in compliance with its declared key
                                                  * usage. */
        /// <summary>
        /// Do not load key rings when running the policy checks.
        /// </summary>
        NoLoadKeyRings = 0x400000000,            /* Do not load key rings when running
                                                  * the policy checks. */
        /// <summary>
        /// Ignore all errors when loading key rings.
        /// </summary>
        IgnoreKeyRingError = 0x800000000,        /* Ignore all errors when loading key
                                                  * rings. */
        /// <summary>
        /// Do not consider any implicit policy data.
        /// </summary>
        ExplicitOnly = 0x1000000000,             /* Do not consider any implicit policy
                                                  * data. */
        /// <summary>
        /// Prefer embedded policy data over external policy data.
        /// </summary>
        PreferEmbedded = 0x2000000000,           /* Prefer embedded policy data over
                                                  * external policy data. */
        /// <summary>
        /// Disable special handling for the license certificate associated
        /// with the Harpy assembly itself.
        /// </summary>
        SkipThisAssembly = 0x4000000000,         /* Disable special handling for the
                                                  * license certificate associated with
                                                  * the Harpy assembly itself. */
        /// <summary>
        /// Disable use of the default stream when searching for available
        /// license certificates.
        /// </summary>
        SkipThisStream = 0x8000000000,           /* Disable use of the default stream
                                                  * when searching for available license
                                                  * certificates. */
        /// <summary>
        /// Disable loading trusted key rings returned by the certificate
        /// renewal server.
        /// </summary>
        NoRenewKeyRings = 0x10000000000,         /* Disable loading trusted key rings
                                                  * returned by the certificate renewal
                                                  * server. */
        /// <summary>
        /// Skip fetching matching key pairs from the trusted key ring.
        /// </summary>
        NoGetKeyPairs = 0x20000000000,           /* Skip fetching matching key pairs
                                                  * from the trusted key ring. */
        /// <summary>
        /// Enforce checking of the revocation list(s).
        /// </summary>
        CheckRevocation = 0x40000000000,         /* Enforce checking of the revocation
                                                  * list(s). */
        /// <summary>
        /// Enable caching of expensive resources when loading key rings.
        /// </summary>
        CacheKeyRings = 0x80000000000,           /* Enable caching expensive resources
                                                  * when loading key rings. */
        /// <summary>
        /// Enable application domain isolation when loading key rings.
        /// </summary>
        IsolateKeyRings = 0x100000000000,        /* Enable application domain isolation
                                                  * when loading key rings. */
        /// <summary>
        /// Enable diagnostic messages when handling policy decisions.
        /// </summary>
        EnableTracing = 0x200000000000,          /* Enable diagnostic messages when
                                                  * handling policy decisions. */
        /// <summary>
        /// Enable appending to the tracing log file, if it already exists.
        /// </summary>
        AppendTracing = 0x400000000000,          /* Enable appending to the tracing log
                                                  * file, if it already exists. */
        /// <summary>
        /// Enable the trace file to be shared by multiple interpreters.
        /// </summary>
        SharedTracing = 0x800000000000,          /* Enable the trace file to be shared
                                                  * by multiple interpreters. */
        /// <summary>
        /// Treat all diagnostic information as high priority.
        /// </summary>
        ForceTracing = 0x1000000000000,          /* Treat all diagnostic information as
                                                  * high priority. */
        /// <summary>
        /// Enable extra diagnostic information when loading key rings,
        /// checking policies, etc.
        /// </summary>
        VerboseTracing = 0x2000000000000,        /* Enable extra diagnostic information
                                                  * when loading key rings, checking
                                                  * policies, etc. */
        /// <summary>
        /// Enable setting up a trace file name automatically.
        /// </summary>
        AutoTraceFile = 0x4000000000000,         /* Enable setting up a trace file name
                                                  * automatically. */
        /// <summary>
        /// Do not shorten (e.g. via ellipsis) any trace information.
        /// </summary>
        FullTracing = 0x8000000000000,           /* Do not shorten (e.g. via ellipsis,
                                                  * etc) any trace information. */
        /// <summary>
        /// Attempt to forcibly reset the tracing subsystem prior to
        /// emitting diagnostic messages.
        /// </summary>
        ResetTracing = 0x10000000000000,         /* Attempt to forcibly reset the tracing
                                                  * subsystem prior to emitting diagnostic
                                                  * messages. */
        /// <summary>
        /// Allow certificates to be loaded from remote URIs.
        /// </summary>
        AllowRemoteUri = 0x20000000000000,       /* Allow certificates to be loaded from
                                                  * remote URIs. */
        /// <summary>
        /// Prior to selecting any certificate, sanity check that it looks
        /// like an XML document.
        /// </summary>
        LooksLikeXml = 0x40000000000000,         /* Prior to selecting any certificate,
                                                  * sanity check that it looks like an
                                                  * XML document. */
        /// <summary>
        /// Prior to selecting any certificate, attempt to validate it
        /// against the XSD schema; this only applies when more than one
        /// certificate is available to choose from.
        /// </summary>
        PreValidateXml = 0x80000000000000,       /* Prior to selecting any certificate,
                                                  * attempt validate it against the XSD
                                                  * schema.  This only applies when more
                                                  * that one certificate is available to
                                                  * choose from. */
        /// <summary>
        /// Only load the primary key script key ring when bootstrapping.
        /// </summary>
        PrimaryKeyRingOnly = 0x100000000000000,  /* Only load the primary key script key
                                                  * ring when bootstrapping. */
        /// <summary>
        /// Skip loading non-specific key rings when bootstrapping.
        /// </summary>
        SpecificKeyRingOnly = 0x200000000000000, /* Skip loading non-specific key rings
                                                  * when bootstrapping. */
        /// <summary>
        /// Allow certificates to be acquired from any available source,
        /// without any interaction.
        /// </summary>
        AutoAcquire = 0x400000000000000,         /* Allow certificates to be acquired
                                                  * from any available source, without
                                                  * any interaction. */
        /// <summary>
        /// Enable caching of expensive resources when acquiring
        /// certificates.
        /// </summary>
        CacheAcquire = 0x800000000000000,        /* Enable caching expensive resources
                                                  * when acquiring certificates. */
        /// <summary>
        /// Enable policy tracing for the key ring loader.
        /// </summary>
        TraceKeyRings = 0x1000000000000000,      /* Enable policy tracing for the key
                                                  * ring loader. */
        /// <summary>
        /// Double-check that a key pair was approved prior to using it.
        /// </summary>
        UseApprovedData = 0x2000000000000000,    /* Double-check that a key pair was
                                                  * approved prior to using it. */
        /// <summary>
        /// Do not search for certificate files; only consider the one
        /// specified, if any.
        /// </summary>
        MaybeNoFileSearch = 0x4000000000000000,  /* Do not search for certificate files,
                                                  * only consider the one specified, if
                                                  * any. */
        /// <summary>
        /// Persistently forbid any further interpreters from being created
        /// in the current process.
        /// </summary>
        DisableCreation = 0x8000000000000000,    /* Persistently forbid any [further]
                                                  * interpreters from being created in
                                                  * the current process. */

        /// <summary>
        /// Combination mask of the "base" policy values <see
        /// cref="AllowNone" />, <see cref="AllowSignedOnly" />, and <see
        /// cref="AllowAny" />.
        /// </summary>
        BasePolicyMask = AllowNone | AllowSignedOnly | AllowAny /* Mask for the "base"
                                                                 * policy values. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how an interpreter
    /// host is created and configured. Because these are flags, multiple
    /// values may be combined together using a bitwise OR to select the
    /// desired host creation behavior.
    /// </summary>
    [Flags()]
    [ObjectId("8f608be1-003c-496b-95c5-9c827a815764")]
    public enum HostCreateFlags : ulong
    {
        /// <summary>
        /// No flags are set; no special creation behavior is requested.
        /// </summary>
        None = 0x0,                   /* No special creation behavior. */
        /// <summary>
        /// A reserved sentinel indicating an invalid flag value; callers
        /// should not use it.
        /// </summary>
        Invalid = 0x1,                /* Invalid, do not use. */
        /// <summary>
        /// Do not create an interpreter host.
        /// </summary>
        Disable = 0x2,                /* Do not create an interpreter host? */
        /// <summary>
        /// Use a Clone(this) of the provided host, not the host itself.
        /// </summary>
        Clone = 0x4,                  /* Use a Clone(this) of the provided
                                       * host, NOT the host itself. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not create a console-based host.
        /// </summary>
        NoConsole = 0x8,              /* Do not create a console-based host? */
        /// <summary>
        /// Do not create a debugging (diagnostic) host.
        /// </summary>
        NoDiagnostic = 0x10,          /* Do not create a debugging host? */
        /// <summary>
        /// Do not create a do-nothing (null) host.
        /// </summary>
        NoNull = 0x20,                /* Do not create a do-nothing host? */
        /// <summary>
        /// Do not create an exception-throwing (fake) host.
        /// </summary>
        NoFake = 0x40,                /* Do not create an exception throwing host? */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Disable use of verbose mode by default.
        /// </summary>
        NoVerbose = 0x80,             /* Disable use of verbose mode by default? */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Put a wrapper around the host used.
        /// </summary>
        UseWrapper = 0x100,           /* Put a wrapper around the host used. */
        /// <summary>
        /// Let the wrapper own the host used.
        /// </summary>
        OwnWrapper = 0x200,           /* Let the wrapper own the host used. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not call Dispose on the host.
        /// </summary>
        NoDispose = 0x400,            /* Do not call Dispose on the host? */
        /// <summary>
        /// Attempt to attach to an existing console, if applicable.
        /// </summary>
        UseAttach = 0x800,            /* Attempt to attach to existing console,
                                       * if applicable. */
        /// <summary>
        /// Forcibly attempt to attach to or open a console.
        /// </summary>
        UseForce = 0x1000,            /* Forcibly attempt to attach or open a
                                       * console. */
        /// <summary>
        /// Limit colors to grayscale, if applicable.
        /// </summary>
        NoColor = 0x2000,             /* Limit colors to grayscale, if
                                       * applicable? */
        /// <summary>
        /// Do not change the console title, if applicable.
        /// </summary>
        NoTitle = 0x4000,             /* Do not change the console title, if
                                       * applicable? */
        /// <summary>
        /// Do not change the console icon, if applicable.
        /// </summary>
        NoIcon = 0x8000,              /* Do not change the console icon, if
                                       * applicable? */
        /// <summary>
        /// Do not load the host profile.
        /// </summary>
        NoProfile = 0x10000,          /* Do not load the host profile? */
        /// <summary>
        /// Do not setup or teardown the script cancellation user interface
        /// (i.e. via key press), if applicable.
        /// </summary>
        NoCancel = 0x20000,           /* Do not setup or teardown the script
                                       * cancellation user interface if
                                       * applicable (i.e. via key press)? */
        /// <summary>
        /// Enable echo for interactive input, if applicable.
        /// </summary>
        Echo = 0x40000,               /* Enable echo for interactive input,
                                       * if applicable. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CONSOLE
        /// <summary>
        /// First, close the console in the current process.
        /// </summary>
        CloseConsole = 0x80000,       /* First, close the console in the current
                                       * process. */
        /// <summary>
        /// Next, open (or attach to) a console in the current process.
        /// </summary>
        OpenConsole = 0x100000,       /* Next, open [or attach?] a console in the
                                       * current process. */
        /// <summary>
        /// Finally, open (or attach to) a console even if it appears to be
        /// open already.
        /// </summary>
        ForceConsole = 0x200000,      /* Finally, open [or attach?] a console even
                                       * if it appears to be open already. */
        /// <summary>
        /// Allow an existing console in the parent process to be attached.
        /// </summary>
        AttachConsole = 0x400000,     /* Allow an existing console in the parent
                                       * process to be attached. */
        /// <summary>
        /// Attempt to make sure that the native console window cannot be
        /// closed.
        /// </summary>
        NoCloseConsole = 0x800000,    /* Attempt to make sure that the native
                                       * console window cannot be closed. */
        /// <summary>
        /// Perform various fixes to the console in order to make it
        /// integrate better with TclTk (e.g. resize the input buffer).
        /// </summary>
        FixConsole = 0x1000000,       /* Perform various fixes to the console in
                                       * order to make it integrate better with
                                       * TclTk (e.g. resize the input buffer). */
        /// <summary>
        /// Greedily open the native console handles when a console-based
        /// interpreter host is created.
        /// </summary>
        HookConsole = 0x2000000,      /* Greedily open the native console handles
                                       * when a console-based interpreter host is
                                       * created. */
        /// <summary>
        /// Before creating the first console-based host for an interpreter,
        /// push its screen buffer onto the stack, saving it for later.
        /// </summary>
        PushConsole = 0x4000000,      /* Before creating the first console-based
                                       * host for an interpreter, push its screen
                                       * buffer onto the stack, thus saving it
                                       * for later. */
        /// <summary>
        /// Configure the console history buffer.
        /// </summary>
        HistoryConsole = 0x8000000,   /* Configure the console history buffer. */
        /// <summary>
        /// Avoid calling into the NativeConsole class during interpreter
        /// creation.
        /// </summary>
        NoNativeConsole = 0x10000000, /* Avoid calling into the NativeConsole
                                       * class during interpreter creation. */
        /// <summary>
        /// Do not complain if NativeConsole methods fail during interpreter
        /// creation.
        /// </summary>
        QuietConsole = 0x20000000,    /* Do not complain if NativeConsole methods
                                       * fail during interpreter creation. */
        /// <summary>
        /// Use the native Win32 API to write to the console window.
        /// </summary>
        WriteConsole = 0x40000000,    /* Use the native Win32 API to write to the
                                       * console window. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable debug-mode for the host (not used).
        /// </summary>
        Debug = 0x80000000,            /* Enable debug-mode for the host (NOT USED). */
        /// <summary>
        /// When displaying a Result object, replace all line-ending
        /// characters with visible placeholder characters.
        /// </summary>
        ReplaceNewLines = 0x100000000, /* When displaying a Result object, replace
                                        * all line-ending characters with visible
                                        * placeholder characters. */
        /// <summary>
        /// When displaying a Result object, truncate it at the default
        /// result formatting limit and append the string "..." to it.
        /// </summary>
        Ellipsis = 0x200000000,        /* When displaying a Result object, truncate
                                        * it as the default result formatting limit,
                                        * and append the string "..." to it. */
        /// <summary>
        /// When displaying a Result object, allow non-standard return codes
        /// and determine whether they represent success or error.
        /// </summary>
        Exceptions = 0x400000000,      /* When displaying a Result object, allow
                                        * non-standard return codes -AND- determine
                                        * if they represent success or error. */
        /// <summary>
        /// When displaying a Result object, make sure that null and empty
        /// strings are represented using a string suitable for display
        /// instead of an empty string.
        /// </summary>
        Display = 0x800000000,         /* When displaying a Result object, make sure
                                        * that null and empty strings are represented
                                        * using a string suitable for display instead
                                        * of an empty string. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Non-zero if the host should allow its associated interpreter to
        /// be flagged as "exited".
        /// </summary>
        CanExit = 0x1000000000,       /* Non-zero if the host should allow for its
                                       * associated interpreter to be flagged as
                                       * "exited". */
        /// <summary>
        /// Non-zero if the host should allow its associated interpreter to
        /// be forcibly flagged as "exited".
        /// </summary>
        CanForceExit = 0x2000000000,  /* Non-zero if the host should allow for its
                                       * associated interpreter to be forcibly
                                       * flagged as "exited". */
        /// <summary>
        /// Non-zero when the associated interpreter is exiting.
        /// </summary>
        Exiting = 0x4000000000,       /* Non-zero when the associated interpreter
                                       * is exiting. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Prefer host scripts over those on the file system (i.e. when an
        /// embedded script library is available); this can be useful if
        /// core library scripts on the file system have been modified and
        /// may contain errors.
        /// </summary>
        UseLibrary = 0x8000000000,    /* Prefer host scripts over those on the
                                       * file system (i.e. when embedded script
                                       * library is available).  This flag can be
                                       * useful if (core library) scripts on the
                                       * file system have been modified and may
                                       * contain errors. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if DEBUGGER
        /// <summary>
        /// Indicates that the script debugger may make use of this host.
        /// </summary>
        Debugger = 0x10000000000,     /* Indicates that the script debugger may
                                       * make use of this host. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The host must be created; if the callback fails, use fallback
        /// semantics.
        /// </summary>
        MustCreate = 0x20000000000,   /* The host must be created.  If the callback
                                       * fails, use fallback semantics. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ISOLATED_PLUGINS
        /// <summary>
        /// The isolated host must be reset after the host is set.
        /// </summary>
        ResetIsolated = 0x40000000000, /* The isolated host mube be reset after the
                                        * host is set. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Initialize various resource managers.
        /// </summary>
        ResourceManager = 0x80000000000,             /* Initialize various resource
                                                      * managers. */
        /// <summary>
        /// Initialize application resource managers.
        /// </summary>
        ApplicationResourceManager = 0x100000000000, /* Initialize application resource
                                                      * managers. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip querying and combining the flags, etc, from the underlying
        /// managed type.
        /// </summary>
        NoAttributes = 0x200000000000, /* Skip querying and combining the flags,
                                        * etc, from the underlying managed type. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Configure the host for use by the interactive shell.
        /// </summary>
        ForShellUse = 0x400000000000,
        /// <summary>
        /// Configure the host for use by the core interactive shell.
        /// </summary>
        ForCoreShellUse = 0x800000000000,

#if NATIVE && TCL && NATIVE_PACKAGE
        /// <summary>
        /// Configure the host for use by the native package.
        /// </summary>
        ForNativeUse = 0x1000000000000,
#endif

        /// <summary>
        /// Configure the host for use by a nested interpreter.
        /// </summary>
        ForNestedUse = 0x2000000000000,

#if NATIVE && TCL
        /// <summary>
        /// Configure the host for use by the Tcl integration manager.
        /// </summary>
        ForTclManagerUse = 0x4000000000000,
#endif

        /// <summary>
        /// Configure the host for use when loading settings.
        /// </summary>
        ForSettingsUse = 0x8000000000000,
        /// <summary>
        /// Configure the host for use when loading settings in a "safe"
        /// interpreter.
        /// </summary>
        ForSafeSettingsUse = 0x10000000000000,

        /// <summary>
        /// Configure the host for use by the test suite.
        /// </summary>
        ForTestUse = 0x20000000000000,

        /// <summary>
        /// Configure the host for use by an embedded interpreter.
        /// </summary>
        ForEmbeddedUse = 0x40000000000000,
        /// <summary>
        /// Configure the host for use by a "safe" embedded interpreter.
        /// </summary>
        ForSafeEmbeddedUse = 0x80000000000000,

        /// <summary>
        /// Configure the host for use by a single-use interpreter.
        /// </summary>
        ForSingleUse = 0x100000000000000,
        /// <summary>
        /// Configure the host for use by a "safe" single-use interpreter.
        /// </summary>
        ForSafeSingleUse = 0x200000000000000,

        /// <summary>
        /// Configure the host for use by a script thread.
        /// </summary>
        ForScriptThreadUse = 0x400000000000000,
        /// <summary>
        /// Configure the host for use by a plugin.
        /// </summary>
        ForPluginUse = 0x800000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags common to all flag sets, currently
        /// equivalent to <see cref="ResourceManager" />.
        /// </summary>
        CommonUse = ResourceManager, /* Included in all flag sets. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the host type flags <see cref="NoConsole"
        /// />, <see cref="NoDiagnostic" />, <see cref="NoNull" />, and <see
        /// cref="NoFake" />.
        /// </summary>
        TypeMask = NoConsole | NoDiagnostic |
                   NoNull | NoFake,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if CONSOLE
        /// <summary>
        /// Combination mask of all the console-related flags.
        /// </summary>
        ConsoleMask = CloseConsole | OpenConsole |
                      ForceConsole | AttachConsole |
                      NoCloseConsole | FixConsole |
                      HookConsole | PushConsole |
                      HistoryConsole | NoNativeConsole |
                      QuietConsole | WriteConsole,

        /// <summary>
        /// The set of console flags used by default.
        /// </summary>
        ConsoleUse = FixConsole | HookConsole | /* NOT USED? */
                     PushConsole,

        /// <summary>
        /// The set of console flags used by default for embedded
        /// interpreters.
        /// </summary>
        EmbeddedConsoleUse = OpenConsole | AttachConsole |
                             FixConsole | HookConsole |
                             QuietConsole,
#else
        /// <summary>
        /// The set of console flags used by default.
        /// </summary>
        ConsoleUse = None,
        /// <summary>
        /// The set of console flags used by default for embedded
        /// interpreters.
        /// </summary>
        EmbeddedConsoleUse = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if DEBUGGER
        /// <summary>
        /// Combination of flags enabling debugger support, equivalent to
        /// <see cref="Debugger" />.
        /// </summary>
        DebuggerUse = Debugger,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for the
        /// interactive shell.
        /// </summary>
        ShellUse = CommonUse |
            ApplicationResourceManager |
#if DEBUGGER
            DebuggerUse |
#endif
            ForShellUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for the core
        /// interactive shell.
        /// </summary>
        CoreShellUse = (ShellUse & ~ForShellUse) | ForCoreShellUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL && NATIVE_PACKAGE
        /// <summary>
        /// Combination of flags used when creating a host for the native
        /// package.
        /// </summary>
        NativeUse = CommonUse | EmbeddedUse |
#if DEBUGGER
            DebuggerUse |
#endif
            ForNativeUse,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for a nested
        /// interpreter.
        /// </summary>
        NestedUse = CommonUse | ForNestedUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// Combination of flags used when creating a host for the Tcl
        /// integration manager.
        /// </summary>
        TclManagerUse = CommonUse | ForTclManagerUse,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for loading
        /// settings.
        /// </summary>
        SettingsUse = CommonUse | ForSettingsUse,
        /// <summary>
        /// Combination of flags used when creating a host for loading
        /// settings in a "safe" interpreter.
        /// </summary>
        SafeSettingsUse = (SettingsUse & ~ForSettingsUse) | ForSafeSettingsUse,

        /// <summary>
        /// Combination of flags used when creating a host for the test
        /// suite.
        /// </summary>
        TestUse = CommonUse | ForTestUse,

        /// <summary>
        /// Combination of flags used when creating a host for an embedded
        /// interpreter.
        /// </summary>
        EmbeddedUse = CommonUse | NoTitle | NoIcon | NoCancel | ForEmbeddedUse,
        /// <summary>
        /// Combination of flags used when creating a host for a "safe"
        /// embedded interpreter.
        /// </summary>
        SafeEmbeddedUse = (EmbeddedUse & ~ForEmbeddedUse) | ForSafeEmbeddedUse,

        /// <summary>
        /// Combination of flags used when creating a host for a single-use
        /// interpreter.
        /// </summary>
        SingleUse = (EmbeddedUse & ~ForEmbeddedUse) | ForSingleUse,
        /// <summary>
        /// Combination of flags used when creating a host for a "safe"
        /// single-use interpreter.
        /// </summary>
        SafeSingleUse = (SingleUse & ~ForSingleUse) | ForSafeSingleUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for an embedded
        /// interpreter without loading the host profile.
        /// </summary>
        FastEmbeddedUse = EmbeddedUse | NoProfile,
        /// <summary>
        /// Combination of flags used when creating a host for a single-use
        /// interpreter without loading the host profile.
        /// </summary>
        FastSingleUse = SingleUse | NoProfile,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for a script
        /// thread.
        /// </summary>
        ScriptThreadUse = CommonUse |
#if DEBUGGER
            DebuggerUse |
#endif
            ForScriptThreadUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when creating a host for a plugin.
        /// </summary>
        PluginUse = (EmbeddedUse & ~ForEmbeddedUse) | NoProfile | ForPluginUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of flags, equivalent to <see cref="ShellUse" />.
        /// </summary>
        Default = ShellUse
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how a feature or
    /// subsystem is disabled. Because these are flags, multiple values may
    /// be combined together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("94812861-d6dd-46fb-b9c0-9ffcce6f8a63")]
    public enum DisableFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid flag value; callers
        /// should not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Override any existing setting.
        /// </summary>
        Override = 0x100,
        /// <summary>
        /// Make the change persistent.
        /// </summary>
        Persistent = 0x200,
        /// <summary>
        /// Suppress diagnostic or error output.
        /// </summary>
        Quiet = 0x400,
        /// <summary>
        /// Allow the operation to be a no-op when appropriate.
        /// </summary>
        AllowNop = 0x800,

        /// <summary>
        /// Use the default disabling behavior.
        /// </summary>
        ForDefault = 0x1000,
        /// <summary>
        /// Use disabling behavior suitable for the SDK.
        /// </summary>
        ForSdk = 0x2000,
        /// <summary>
        /// Use on-demand disabling behavior.
        /// </summary>
        ForDemand = 0x4000,

        /// <summary>
        /// Equivalent to <see cref="ForDemand" />.
        /// </summary>
        Demand = ForDemand,
        /// <summary>
        /// Combination of <see cref="Override" /> and <see cref="ForSdk"
        /// />.
        /// </summary>
        Sdk = Override | ForSdk,
        /// <summary>
        /// Combination of <see cref="Override" />, <see cref="Persistent"
        /// />, <see cref="AllowNop" />, and <see cref="ForSdk" />.
        /// </summary>
        FailSafe = Override | Persistent | AllowNop | ForSdk,

        /// <summary>
        /// The default set of flags, equivalent to <see cref="ForDefault"
        /// />.
        /// </summary>
        Default = ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that control how an TclTk
    /// interpreter is created, governing everything from disposal and
    /// exception behavior to which commands, variables, plugins, and
    /// subsystems are added during creation.  Its values are bit flags
    /// that may be combined; a number of named combinations are provided
    /// for common embedding scenarios.
    /// </summary>
    [Flags()]
    [ObjectId("41dae319-8562-4466-bb7a-3f4ff0f5a620")]
    public enum CreateFlags : ulong
    {
        #region Standard Placeholder Values
        /// <summary>
        /// No flags are set; the interpreter is created without any
        /// special creation behavior.
        /// </summary>
        None = 0x0,                /* No special creation behavior. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of creation
        /// flags; callers should not use this value.
        /// </summary>
        Invalid = 0x1,             /* Invalid, do not use. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Flags Control Values
        /// <summary>
        /// Modify the specified creation flags and host creation flags
        /// using their associated static methods before they are applied.
        /// </summary>
        GetFlags = 0x2,            /* Modify the specified creation flags
                                    * and host creation flags using their
                                    * associated static methods. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Special Access Options
        /// <summary>
        /// Create a new interpreter only if necessary; when set, the first
        /// interpreter already available in the application domain may be
        /// returned instead of creating a new one, taking the "safe" flag
        /// into account when deciding.
        /// </summary>
        IfNecessary = 0x4,         /* WARNING: When this flag is used,
                                    * a new interpreter may not be
                                    * created; instead, the first one
                                    * available in the AppDomain will
                                    * be returned instead.  This flag
                                    * will take into account the "safe"
                                    * flag when deciding whether or not
                                    * to create a new interpreter. */
        /// <summary>
        /// Permit a new interpreter to be created even when <see
        /// cref="IfNecessary" /> is set, in the event that the global
        /// static lock is temporarily unavailable for any reason; this
        /// flag is generally combined with removal of the global tracking
        /// flag.
        /// </summary>
        IfCannotLock = 0x8,        /* WARNING: When this flag is used,
                                    * a new interpreter may be created
                                    * even when the IfNecessary flag is
                                    * used -IF- the global static lock
                                    * is (temporarily?) unavailable for
                                    * ANY reason.  Generally, use of
                                    * this flag will be combined the
                                    * REMOVAL of the GlobalTracking
                                    * flag. */
        /// <summary>
        /// Disable disposal of the newly created interpreter until
        /// disposal is explicitly re-enabled via the SetDisposalEnabled
        /// method.
        /// </summary>
        NoDispose = 0x10,          /* WARNING: Disable disposal of the
                                    * newly created interpreter until
                                    * the SetDisposalEnabled method is
                                    * used to enable it. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Managed Debugging Control
        /// <summary>
        /// Measure the elapsed time taken by the Create() method.
        /// </summary>
        MeasureTime = 0x20,        /* Measure elapsed time for the Create()
                                    * method. */
        /// <summary>
        /// Break into the managed debugger immediately upon entry to the
        /// Create() method.
        /// </summary>
        BreakOnCreate = 0x40,      /* Break into managed debugger immediately
                                    * on Create()? */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region General Mode Control
        /// <summary>
        /// Create the interpreter in "debug" mode.
        /// </summary>
        Debug = 0x80,              /* Interpreter should be created in "debug"
                                    * mode? */
        /// <summary>
        /// Enable verbose mode, which produces additional diagnostic
        /// output, possibly to the system console.
        /// </summary>
        Verbose = 0x100,           /* Verbose mode enabled.  This will result
                                    * in more diagnostic output, possibly to
                                    * the System.Console. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Pre-Setup Control
        /// <summary>
        /// Enable Tcl 8.4+ compatible namespace support for the created
        /// interpreter.
        /// </summary>
        UseNamespaces = 0x200,     /* Enable Tcl 8.4+ compatible namespace
                                    * support for created interpreter. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Post-Setup Control
        /// <summary>
        /// Ensure the "argc" and "argv" global variables are set even when
        /// the supplied managed argument array is null.
        /// </summary>
        SetArguments = 0x400,      /* Make sure the "argc" and "argv" global
                                    * variables are set even if specified
                                    * managed argument array is null. */
        /// <summary>
        /// Process startup options from the environment and other sources
        /// during creation.
        /// </summary>
        Startup = 0x800,           /* Process startup options from environment,
                                    * etc. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Script Library Control
        /// <summary>
        /// Initialize the core script library during creation; without
        /// this flag, all core script library procedures are unavailable.
        /// </summary>
        Initialize = 0x1000,       /* Initialize core script library during
                                    * creation?  Without this flag, all core
                                    * script library procedures will be
                                    * unavailable. */
        /// <summary>
        /// Ignore script library initialization errors; this should
        /// rarely, if ever, be necessary.
        /// </summary>
        IgnoreOnError = 0x2000,    /* Just ignore initialization errors?  This
                                    * should rarely, if ever, be necessary. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Exception Control
        /// <summary>
        /// Throw exceptions when disposed objects are accessed; this
        /// behavior is highly recommended.
        /// </summary>
        ThrowOnDisposed = 0x4000,  /* Throw exceptions when disposed objects
                                    * are accessed?  Highly recommended. */
        /// <summary>
        /// Throw an exception when script library initialization fails;
        /// this behavior is recommended.
        /// </summary>
        ThrowOnError = 0x8000,     /* Throw exception on initialization fail?
                                    * Recommended. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Core Command Set Control
        //
        // NOTE: *WARNING* For embedders, more control over interpreter
        //       creation.  These flags should not be combined with the
        //       "Initialize" flag because using any of these flags will
        //       almost certainly cause script library initialization to
        //       fail.
        //
        /// <summary>
        /// Exclude every command marked as "critical", such as
        /// <c>[debug]</c>, <c>[file]</c>, <c>[host]</c>, <c>[library]</c>,
        /// <c>[load]</c>, <c>[object]</c>, <c>[tcl]</c>, and
        /// <c>[unload]</c>.
        /// </summary>
        NoCritical = 0x10000,           /* Do not include any command that is
                                         * marked as "Critical", e.g. [debug],
                                         * [file], [host], [library], [load],
                                         * [object], [tcl], [unload], etc. */
        /// <summary>
        /// Include only "safe" commands and remove all "unsafe" commands
        /// from the created interpreter.
        /// </summary>
        Safe = 0x20000,                 /* Include only "safe" commands and
                                         * remove all "unsafe" commands from
                                         * the created interpreter. */
        /// <summary>
        /// Hide all "unsafe" commands instead of removing them.
        /// </summary>
        HideUnsafe = 0x40000,           /* Hide all "unsafe" commands instead
                                         * of removing them? */
        /// <summary>
        /// Include only commands that are part of the "Tcl Standard" and
        /// remove those that are not.
        /// </summary>
        Standard = 0x80000,             /* Include only commands that are part
                                         * of the "Tcl Standard" and remove
                                         * those that are not. */
        /// <summary>
        /// Hide commands that are not part of the "Tcl Standard" instead
        /// of removing them.
        /// </summary>
        HideNonStandard = 0x100000,     /* Hide commands that are not part of
                                         * the "Tcl Standard" instead of
                                         * removing them? */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Positive Compile-Time Feature Control (Enable Non-Default)
#if DEBUGGER
        /// <summary>
        /// Create a script debugger for the interpreter.
        /// </summary>
        Debugger = 0x200000,            /* Create script debugger? */
        /// <summary>
        /// Also create an isolated debugger interpreter to accompany the
        /// script debugger.
        /// </summary>
        DebuggerInterpreter = 0x400000, /* Also create an isolated debugger
                                         * interpreter? */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Forbid the loader from being added to the interpreter
        /// dynamically.
        /// </summary>
        NoLoader = 0x800000,            /* Forbid the loader from being added
                                         * to the interpreter dynamically. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ISOLATED_PLUGINS
        /// <summary>
        /// Initially force all plugins to be loaded into isolated
        /// application domains.
        /// </summary>
        IsolatePlugins = 0x2000000,     /* Initially, force all plugins to be
                                         * loaded into isolated application
                                         * domains. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if APPDOMAINS || ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
        /// <summary>
        /// Attempt to probe candidate plugin assemblies in order to
        /// discover the packages they may contain.
        /// </summary>
        ProbePlugins = 0x4000000,       /* Attempt to probe possible plugin
                                         * assemblies to discover packages
                                         * they may contain, etc? */
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Negative Optional Feature Control (Disable Default)
        #region Compile-Time Feature Control (May Be Unavailable)
#if NATIVE && NATIVE_UTILITY
        /// <summary>
        /// Do not load the native utility library; if this flag is
        /// required (for example, to prevent a crash on Mono), it may be
        /// wiser to disable the native utility via its associated
        /// environment variable ("NoNativeUtility") instead.
        /// </summary>
        NoNativeUtility = 0x8000000,          /* Do not load the native utility
                                               * library?  If this creation flag
                                               * is required (e.g. to prevent a
                                               * crash on Mono), it may be wise
                                               * to disable the native utility
                                               * via the associated environment
                                               * variable ("NoNativeUtility")
                                               * instead. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY || NOTIFY_OBJECT
        /// <summary>
        /// Skip adding the static object notify plugin, disabling object
        /// reference counting; use of this flag is not recommended.
        /// </summary>
        NoObjectPlugin = 0x10000000,          /* Skip adding the static object
                                               * notify plugin (i.e. no object
                                               * reference counting)?  Use of
                                               * this flag is NOT recommdned. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if TEST_PLUGIN || DEBUG
        /// <summary>
        /// Skip adding the static test plugin.
        /// </summary>
        NoTestPlugin = 0x20000000,            /* Skip adding the static test
                                               * plugin? */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY && NOTIFY_ARGUMENTS
        /// <summary>
        /// Skip adding the static monitor plugin.
        /// </summary>
        NoMonitorPlugin = 0x40000000,         /* Skip adding the static monitor
                                               * plugin? */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// Skip transferring any "dead" native Tcl resources to the newly
        /// created interpreter.
        /// </summary>
        NoTclTransfer = 0x80000000,           /* Skip transferring any "dead"
                                               * native Tcl resources to the
                                               * newly created interpreter. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if !NET_STANDARD_20
        /// <summary>
        /// Skip asynchronously and fully populating the "osExtra" element
        /// of the "tcl_platform" array.
        /// </summary>
        NoPopulateOsExtra = 0x100000000,      /* Skip asynchronously (fully)
                                               * populating the "osExtra" element
                                               * of the "tcl_platform" array? */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY || NOTIFY_OBJECT
        /// <summary>
        /// Initially disable most "global" notifications.
        /// </summary>
        NoGlobalNotify = 0x200000000,         /* Initially, disable most "global"
                                               * notifications. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if APPDOMAINS && ISOLATED_INTERPRETERS
        /// <summary>
        /// Disable resetting the value of the entry assembly when creating
        /// a new application domain.
        /// </summary>
        NoUseEntryAssembly = 0x400000000,     /* Disable resetting the value of the
                                               * entry assembly when creating a new
                                               * AppDomain. */
        /// <summary>
        /// Ignore exceptions raised while forcibly refreshing the entry
        /// assembly in created application domains.
        /// </summary>
        OptionalEntryAssembly = 0x800000000,  /* Ignore exceptions when forcibly
                                               * refreshing the entry assembly in
                                               * created AppDomains. */
        /// <summary>
        /// Ensure the application domain base directory contains the core
        /// library assembly.
        /// </summary>
        VerifyCoreAssembly = 0x1000000000,    /* Make sure the AppDomain base
                                               * directory contains the core
                                               * library assembly? */
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip core script library initialization.
        /// </summary>
        NoLibrary = 0x2000000000,             /* Skip core script library
                                               * initialization. */
        /// <summary>
        /// Skip shell script library initialization.
        /// </summary>
        NoShellLibrary = 0x4000000000,        /* Skip shell script library
                                               * initialization. */
        /// <summary>
        /// Skip creating the standard channels.
        /// </summary>
        NoChannels = 0x8000000000,            /* Skip creating the standard
                                               * channels? */
        /// <summary>
        /// Skip adding all standard plugins, leaving no commands and no
        /// object support; this flag is for DSL use and very advanced
        /// users only.
        /// </summary>
        NoPlugins = 0x10000000000,            /* Skip adding all standard
                                               * plugins (i.e. no commands,
                                               * no object support)?  This
                                               * flag is for DSL use and/or
                                               * very advanced users only. */
        /// <summary>
        /// Skip adding the static core plugin, leaving no commands; this
        /// flag is for DSL use and very advanced users only.
        /// </summary>
        NoCorePlugin = 0x20000000000,         /* Skip adding static core
                                               * plugin (i.e. no commands)?
                                               * This flag is for DSL use
                                               * and/or very advanced users
                                               * only. */
        /// <summary>
        /// Skip adding commands entirely; this is designed for
        /// applications that supply their own commands and want none of
        /// the core command sets, and it should very rarely be used.
        /// </summary>
        NoCommands = 0x40000000000,           /* Skip adding commands.  This is
                                               * designed for applications that
                                               * add their own commands and do
                                               * not want ANY of the core command
                                               * set(s) in their interpreter(s).
                                               * It should be very rarely used. */
        /// <summary>
        /// Skip adding the standard variables.
        /// </summary>
        NoVariables = 0x80000000000,          /* Skip adding the standard
                                               * variables? */
        /// <summary>
        /// Skip adding platform-related variables.
        /// </summary>
        NoPlatform = 0x100000000000,          /* Skip adding platform-related
                                               * variables? */
        /// <summary>
        /// Skip adding the "objectIds" element to the "tcltk_platform"
        /// array, which can be very large.
        /// </summary>
        NoObjectIds = 0x200000000000,         /* Skip adding the "objectIds"
                                               * element in the "tcltk_platform"
                                               * array (can be very large)? */
        /// <summary>
        /// Skip adding the "env(HOME)" variable when it would otherwise be
        /// needed.
        /// </summary>
        NoHome = 0x400000000000,              /* Skip adding "env(HOME)" variable
                                               * (if needed)? */
        /// <summary>
        /// Skip adding the standard objects.
        /// </summary>
        NoObjects = 0x800000000000,           /* Skip adding standard objects? */
        /// <summary>
        /// Skip adding the standard expression operators; this flag is for
        /// DSL use and very advanced users only.
        /// </summary>
        NoOperators = 0x1000000000000,        /* Skip adding standard expression
                                               * operators?  This flag is for DSL
                                               * use and/or very advanced users
                                               * only. */
        /// <summary>
        /// Skip adding the standard math functions.
        /// </summary>
        NoFunctions = 0x2000000000000,        /* Skip adding standard math
                                               * functions? */
        /// <summary>
        /// Skip creating the random number generators.
        /// </summary>
        NoRandom = 0x4000000000000,           /* Skip creating random number
                                               * generator(s). */
        /// <summary>
        /// Skip adding the built-in policies; this severely limits what is
        /// possible within a "safe" interpreter, since no sub-command will
        /// be allowed to execute (even "safe" ones) if it belongs to a
        /// core ensemble command marked as "unsafe".
        /// </summary>
        NoCorePolicies = 0x8000000000000,     /* Skip adding built-in policies.
                                               * This flag severely limits what
                                               * it is possible to do within a
                                               * "safe" interpreter (i.e. no
                                               * sub-command will be allowed to
                                               * execute, even those that are
                                               * "safe", if they belong to a core
                                               * ensemble command marked as
                                               * "unsafe"). */
        /// <summary>
        /// Skip adding the built-in traces; setting this flag completely
        /// disables opaque object handle reference count tracking, among
        /// other things.
        /// </summary>
        NoCoreTraces = 0x10000000000000,      /* Skip adding built-in traces.
                                               * Please note that setting this
                                               * flag will completely disable
                                               * opaque object handle reference
                                               * count tracking, among other
                                               * things. */
        /// <summary>
        /// Skip using Type.DefaultBinder.
        /// </summary>
        NoDefaultBinder = 0x20000000000000,   /* Skip using Type.DefaultBinder. */
#if APPDOMAINS && ISOLATED_INTERPRETERS
        /// <summary>
        /// Skip copying the static configuration into newly created
        /// application domains.
        /// </summary>
        NoConfiguration = 0x40000000000000,   /* Skip copying static configuration
                                               * into newly created AppDomains. */
#endif
#if ISOLATED_PLUGINS
        /// <summary>
        /// Automatically set the NoPreview flag when initializing plugin
        /// flags for the new interpreter.
        /// </summary>
        NoPluginPreview = 0x80000000000000,   /* Automatic set the NoPreview flag
                                               * when initializing plugin flags
                                               * for the new interpreter. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// For use by the security SDK (i.e. Harpy) only.
        /// </summary>
        SecuritySdk = 0x100000000000000,      /* For use by the security SDK (i.e.
                                               * Harpy) only. */
        /// <summary>
        /// For use by the license SDK (i.e. Harpy) only.
        /// </summary>
        LicenseSdk = 0x200000000000000,       /* For use by the license SDK (i.e.
                                               * Harpy) only. */
        /// <summary>
        /// Set only the variables that are required for proper operation
        /// of the core script library.
        /// </summary>
        MinimumVariables = 0x400000000000000, /* Only setting variables that are
                                               * required for proper operation of
                                               * the core script library. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved value; do not use it.
        /// </summary>
        Reserved = 0x8000000000000000,        /* Reserved value, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Useful Combinations
        //
        // NOTE: If one of these flags is set, some variables may be
        //       missing.
        //
        /// <summary>
        /// Combination mask of <see cref="NoVariables" /> and <see
        /// cref="MinimumVariables" />; when set, some variables may be
        /// missing.
        /// </summary>
        NoVariablesMask = NoVariables | MinimumVariables,
        /// <summary>
        /// Combination mask of <see cref="NoVariablesMask" /> and <see
        /// cref="NoPlatform" />; when set, some variables may be missing.
        /// </summary>
        NoPlatformMask = NoVariablesMask | NoPlatform,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: If one of these flags is set, the interpreter was
        //       created for some kind of SDK-based usage, i.e. it
        //       is not fully general purpose.
        //
        /// <summary>
        /// Combination mask of <see cref="SecuritySdk" /> and <see
        /// cref="LicenseSdk" />, indicating the interpreter was created
        /// for some kind of SDK-based usage and is not fully general
        /// purpose.
        /// </summary>
        SdkMask = SecuritySdk | LicenseSdk,
        /// <summary>
        /// Combination mask of <see cref="Safe" /> and <see cref="SdkMask"
        /// />.
        /// </summary>
        SafeOrSdkMask = Safe | SdkMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are forbidden for use with created "child"
        //       and/or "peer" interpreters.
        //
        /// <summary>
        /// Combination mask of <see cref="ThrowOnError" /> and <see
        /// cref="IfNecessary" />; these flags are forbidden for use with
        /// created "child" interpreters.
        /// </summary>
        NoChildUseMask = ThrowOnError | IfNecessary,
        /// <summary>
        /// Combination mask of <see cref="ThrowOnError" /> and <see
        /// cref="IfNecessary" />; these flags are forbidden for use with
        /// created "peer" interpreters.
        /// </summary>
        NoPeerUseMask = ThrowOnError | IfNecessary,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for "safe" mode.
        //
        /// <summary>
        /// Standard combination of flags for "safe" mode, combining <see
        /// cref="Safe" /> and <see cref="HideUnsafe" />.
        /// </summary>
        SafeAndHideUnsafe = Safe | HideUnsafe,

        //
        // NOTE: Typical flags for "standard" mode.
        //
        /// <summary>
        /// Typical combination of flags for "standard" mode, combining
        /// <see cref="Standard" /> and <see cref="HideNonStandard" />.
        /// </summary>
        StandardAndHideNonStandard = Standard | HideNonStandard,

        //
        // NOTE: For (core) library use only.
        //
        /// <summary>
        /// Combination mask of <see cref="SafeAndHideUnsafe" /> and <see
        /// cref="StandardAndHideNonStandard" />, for core library use
        /// only.
        /// </summary>
        CoreCommandSetMask = SafeAndHideUnsafe | StandardAndHideNonStandard,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Common flags for embedding.
        //
        /// <summary>
        /// Common combination of flags for embedding TclTk, built on <see
        /// cref="ThrowOnDisposed" /> together with several feature-control
        /// flags that vary by compile-time configuration.
        /// </summary>
        CommonUse = ThrowOnDisposed |
#if TEST_PLUGIN && !DEBUG
                    NoTestPlugin |
#endif
#if NOTIFY && NOTIFY_ARGUMENTS
                    NoMonitorPlugin |
#endif
#if USE_NAMESPACES
                    UseNamespaces |
#endif
#if !NET_STANDARD_20
                    NoPopulateOsExtra |
#endif
#if APPDOMAINS && ISOLATED_INTERPRETERS
                    OptionalEntryAssembly |
#endif
                    NoDefaultBinder |
                    None,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Completely disable initialization (and loading) of
        //       the core script library and shell script library.
        //
        /// <summary>
        /// Combination mask of <see cref="NoLibrary" /> and <see
        /// cref="NoShellLibrary" /> that completely disables
        /// initialization and loading of both the core script library and
        /// the shell script library.
        /// </summary>
        NoLibraryUse = NoLibrary | NoShellLibrary,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags severely limit how useful the built-in
        //       [object] command can be.
        //
        /// <summary>
        /// Combination mask of <see cref="NoCoreTraces" />, <see
        /// cref="NoObjects" />, and <see cref="NoObjectPlugin" />; these
        /// flags severely limit how useful the built-in <c>[object]</c>
        /// command can be.
        /// </summary>
        BareObjectUse = NoCoreTraces | NoObjects | NoObjectPlugin,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for "DSL-style" embedding while still
        //       retaining most functionality of the core command set.
        //
        /// <summary>
        /// Standard combination of flags for "DSL-style" embedding while
        /// still retaining most of the functionality of the core command
        /// set, built on <see cref="CommonUse" />.
        /// </summary>
        LeanAndMeanUse = CommonUse |
#if NOTIFY || NOTIFY_OBJECT
                         NoGlobalNotify |
#endif
#if NATIVE && NATIVE_UTILITY
                         NoNativeUtility |
#endif
                         NoObjectIds |
                         NoHome |
#if NATIVE && TCL
                         NoTclTransfer |
#endif
#if APPDOMAINS && ISOLATED_INTERPRETERS
                         NoConfiguration |
#endif
                         None,

        /// <summary>
        /// Combination of <see cref="LeanAndMeanUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeLeanAndMeanUse = LeanAndMeanUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for "DSL-style" embedded without (full)
        //       support for "safe" interpreters, the built-in [object]
        //       command, standard channels, the core / shell script
        //       libraries, and pre-set global variables.  Using this
        //       set of flags is recommended for experts only.
        //
        /// <summary>
        /// Standard combination of flags for "DSL-style" embedding without
        /// full support for "safe" interpreters, the built-in
        /// <c>[object]</c> command, standard channels, the core and shell
        /// script libraries, and pre-set global variables; this set is
        /// recommended for experts only.
        /// </summary>
        SuperLeanAndMeanUse = LeanAndMeanUse | BareObjectUse |
                              NoLibraryUse | MinimumVariables |
                              NoChannels | NoCorePolicies,

        /// <summary>
        /// Combination of <see cref="SuperLeanAndMeanUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeSuperLeanAndMeanUse = SuperLeanAndMeanUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This is the same as SuperLeanAndMeanUse (above) except
        //       that it also omits initialization of the random number
        //       generators.
        //
        /// <summary>
        /// The same as <see cref="SuperLeanAndMeanUse" /> except that it
        /// also omits initialization of the random number generators.
        /// </summary>
        UltraLeanAndMeanUse = SuperLeanAndMeanUse | NoRandom,
        /// <summary>
        /// Combination of <see cref="UltraLeanAndMeanUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeUltraLeanAndMeanUse = UltraLeanAndMeanUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For use by CreateInterpreterForSettings only.
        //
        /// <summary>
        /// Combination of flags for use by the
        /// CreateInterpreterForSettings method only.
        /// </summary>
        StaticDataUse = (UltraLeanAndMeanUse & ~NoCorePolicies) |
#if ISOLATED_PLUGINS
                        NoPluginPreview,
#else
                        None,
#endif

        /// <summary>
        /// Combination of <see cref="StaticDataUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeStaticDataUse = StaticDataUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for "DSL-style" embedding.
        //
        /// <summary>
        /// Standard combination of flags for "DSL-style" embedding,
        /// combining <see cref="CommonUse" />, <see cref="ThrowOnError"
        /// />, and <see cref="NoCorePlugin" />.
        /// </summary>
        BareUse = CommonUse | ThrowOnError | NoCorePlugin,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if DEBUGGER
        //
        // NOTE: Flags used when creating the isolated script debugger
        //       [interpreter].
        //
        /// <summary>
        /// Combination of flags used when creating the isolated script
        /// debugger interpreter.
        /// </summary>
        DebuggerUse = Debugger,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Flags forbidden from being used for isolated script debugger
        //       interpreters.
        //
        /// <summary>
        /// Combination mask of <see cref="Debugger" /> and <see
        /// cref="ThrowOnError" /> that is forbidden from being used for
        /// isolated script debugger interpreters.
        /// </summary>
        NonDebuggerUse = Debugger | ThrowOnError,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for shell.
        //
        /// <summary>
        /// Standard combination of flags for the interactive shell, built
        /// on <see cref="CommonUse" /> together with <see
        /// cref="ThrowOnError" />.
        /// </summary>
        ShellUse = CommonUse |
#if DEBUGGER
                   DebuggerUse |
#endif
                   ThrowOnError,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for the core library shell.
        //
        /// <summary>
        /// Standard combination of flags for the core library shell, equal
        /// to <see cref="ShellUse" /> with <see cref="ThrowOnError" />
        /// removed.
        /// </summary>
        CoreShellUse = ShellUse & ~ThrowOnError,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL && NATIVE_PACKAGE
        //
        // NOTE: Standard flags for the interpreter used with the TclTk Package
        //       for Tcl.  Since we have no control over when, where, and which
        //       thread is used to shutdown TclTk, avoid throwing exceptions
        //       about objects already having been disposed.
        //
        /// <summary>
        /// Standard combination of flags for the interpreter used with the
        /// TclTk Package for Tcl; because there is no control over when or
        /// on which thread TclTk is shut down, exceptions about already-
        /// disposed objects are avoided.
        /// </summary>
        NativeUse = (CommonUse & ~ThrowOnDisposed) |
#if DEBUGGER
                    DebuggerUse |
#endif
                    Initialize |
                    SetArguments,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for nested interps.
        //
        /// <summary>
        /// Standard combination of flags for nested interpreters, built on
        /// <see cref="CommonUse" /> together with <see cref="Initialize"
        /// />.
        /// </summary>
        NestedUse = CommonUse |
#if NATIVE && TCL
                    NoTclTransfer |
#endif
                    Initialize,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        //
        // NOTE: For use with the ITclManager interface.
        //
        /// <summary>
        /// Combination of <see cref="CommonUse" /> and <see
        /// cref="Initialize" /> for use with the ITclManager interface.
        /// </summary>
        TclManagerUse = CommonUse | Initialize,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For use by the ScriptOps.LoadApplicationSettings method only.
        //
        /// <summary>
        /// Combination of <see cref="CommonUse" /> and <see
        /// cref="Initialize" /> for use by the
        /// ScriptOps.LoadApplicationSettings method only.
        /// </summary>
        SettingsUse = CommonUse | Initialize,
        /// <summary>
        /// Combination of <see cref="SettingsUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeSettingsUse = SettingsUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Standard flags for isolated test interps.
        //
        /// <summary>
        /// Standard combination of flags for isolated test interpreters,
        /// combining <see cref="CommonUse" /> and <see cref="Initialize"
        /// />.
        /// </summary>
        TestUse = CommonUse | Initialize,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Default flags for use by extensions (to other systems)
        //       that require an embedded interpreter.
        //
        /// <summary>
        /// Default combination of flags for use by extensions to other
        /// systems that require an embedded interpreter.
        /// </summary>
        EmbeddedUse = CommonUse | Initialize | ThrowOnError,
        /// <summary>
        /// Combination of <see cref="EmbeddedUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeEmbeddedUse = EmbeddedUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Default flags for "single-use" interpreters
        //       created by the engine.
        //
        /// <summary>
        /// Default combination of flags for "single-use" interpreters
        /// created by the engine, equal to <see cref="EmbeddedUse" /> with
        /// <see cref="ThrowOnError" /> removed.
        /// </summary>
        SingleUse = EmbeddedUse & ~ThrowOnError,
        /// <summary>
        /// Combination of <see cref="SingleUse" /> and <see
        /// cref="SafeAndHideUnsafe" />.
        /// </summary>
        SafeSingleUse = SingleUse | SafeAndHideUnsafe,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ISOLATED_PLUGINS
        /// <summary>
        /// Fast combination of flags for "single-use" interpreters, built
        /// on <see cref="LeanAndMeanUse" /> together with <see
        /// cref="Initialize" />.
        /// </summary>
        FastSingleUse = LeanAndMeanUse | Initialize | NoPluginPreview,
        /// <summary>
        /// Fast, "safe" combination of flags for "single-use"
        /// interpreters, built on <see cref="SafeLeanAndMeanUse" />
        /// together with <see cref="Initialize" />.
        /// </summary>
        FastSafeSingleUse = SafeLeanAndMeanUse | Initialize | NoPluginPreview,
#else
        /// <summary>
        /// Fast combination of flags for "single-use" interpreters, built
        /// on <see cref="LeanAndMeanUse" /> together with <see
        /// cref="Initialize" />.
        /// </summary>
        FastSingleUse = LeanAndMeanUse | Initialize,
        /// <summary>
        /// Fast, "safe" combination of flags for "single-use"
        /// interpreters, built on <see cref="SafeLeanAndMeanUse" />
        /// together with <see cref="Initialize" />.
        /// </summary>
        FastSafeSingleUse = SafeLeanAndMeanUse | Initialize,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Default flags for use by ScriptThread objects.
        //
        /// <summary>
        /// Default combination of flags for use by ScriptThread objects,
        /// built on <see cref="CommonUse" /> together with <see
        /// cref="Initialize" />.
        /// </summary>
        ScriptThreadUse = CommonUse |
#if DEBUGGER
                          DebuggerUse |
#endif
                          Initialize,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used to create an interpreter for rule-set
        /// evaluation, disabling nearly all of the standard subsystems.
        /// </summary>
        RuleSetUse = NoPlugins | NoLibrary | NoChannels |
                     NoCommands | NoVariables | NoObjects |
                     NoOperators | NoFunctions | NoRandom |
                     NoCorePolicies | NoCoreTraces |
#if NOTIFY || NOTIFY_OBJECT
                     NoGlobalNotify,
#else
                     None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if APPDOMAINS && ISOLATED_INTERPRETERS
        /// <summary>
        /// Combination mask of <see cref="NoUseEntryAssembly" />, <see
        /// cref="OptionalEntryAssembly" />, <see cref="VerifyCoreAssembly"
        /// />, and <see cref="NoConfiguration" />.
        /// </summary>
        IsolatedMask = NoUseEntryAssembly | OptionalEntryAssembly |
                       VerifyCoreAssembly | NoConfiguration,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Default flags for all applications and plugins.
        //
        /// <summary>
        /// Default combination of flags for all applications and plugins,
        /// combining <see cref="ShellUse" /> and <see cref="Initialize"
        /// />.
        /// </summary>
        Default = ShellUse | Initialize
        #endregion
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the categories of software development
    /// kit (SDK) functionality that may be requested or reported. The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("d6d43ba2-93f9-438d-a837-f6a641479e90")]
    public enum SdkType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// The SDK initialization functionality is involved.
        /// </summary>
        Initialize = 0x1000,
        /// <summary>
        /// The SDK security functionality is involved.
        /// </summary>
        Security = 0x2000,
        /// <summary>
        /// The SDK licensing functionality is involved.
        /// </summary>
        License = 0x4000,
        /// <summary>
        /// The SDK functionality involved is non-critical, i.e. its
        /// failures may be tolerated.
        /// </summary>
        NonCritical = 0x8000,

        /// <summary>
        /// Combination mask of <see cref="Security" />,
        /// <see cref="License" />, and <see cref="NonCritical" />.
        /// </summary>
        AnySdkMask = Security | License | NonCritical,
        /// <summary>
        /// Combination mask of <see cref="Initialize" /> and
        /// <see cref="AnySdkMask" />.
        /// </summary>
        AnyMask = Initialize | AnySdkMask,

        /// <summary>
        /// The default SDK type, equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how an object -- typically a call frame or
    /// a set of variables -- is cloned, selecting which constituent parts
    /// are duplicated and which side effects occur during the operation.
    /// The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("36e6651c-734e-48f9-9a44-aec7bfc6f000")]
    public enum CloneFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Include call frames when cloning.
        /// </summary>
        WithFrames = 0x100,
        /// <summary>
        /// Include scalar variable values when cloning.
        /// </summary>
        WithValues = 0x200,
        /// <summary>
        /// Include array element values when cloning.
        /// </summary>
        WithArrayValues = 0x400,
        /// <summary>
        /// Include variable traces when cloning.
        /// </summary>
        WithTraces = 0x800,
        /// <summary>
        /// Include variable locks when cloning.
        /// </summary>
        WithLocks = 0x1000,

        /// <summary>
        /// Fire any applicable variable traces during the clone operation.
        /// </summary>
        FireTraces = 0x10000,
        /// <summary>
        /// Permit special variables to be included in the clone operation.
        /// </summary>
        AllowSpecial = 0x20000,

        /// <summary>
        /// Combination mask of <see cref="WithValues" />,
        /// <see cref="WithArrayValues" />, <see cref="WithTraces" />, and
        /// <see cref="FireTraces" />.
        /// </summary>
        ScopeMask = WithValues | WithArrayValues | WithTraces |
                    FireTraces,

        /// <summary>
        /// Combination mask of <see cref="WithFrames" />,
        /// <see cref="WithValues" />, <see cref="WithArrayValues" />,
        /// <see cref="WithTraces" />, <see cref="WithLocks" />,
        /// <see cref="FireTraces" />, and <see cref="AllowSpecial" />.
        /// </summary>
        DeepMask = WithFrames | WithValues | WithArrayValues |
                   WithTraces | WithLocks | FireTraces |
                   AllowSpecial,

        /// <summary>
        /// Combination mask of <see cref="WithFrames" />,
        /// <see cref="WithValues" />, <see cref="WithArrayValues" />,
        /// <see cref="WithTraces" />, <see cref="WithLocks" />,
        /// <see cref="FireTraces" />, and <see cref="AllowSpecial" />.
        /// </summary>
        AllMask = WithFrames | WithValues | WithArrayValues |
                  WithTraces | WithLocks | FireTraces |
                  AllowSpecial
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how an interpreter and its associated
    /// script library are initialized, selecting which subsystems are set
    /// up and how the auto-path and related resources are configured. The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("78754dfb-f802-4db2-9782-aaa3e69562a7")]
    public enum InitializeFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// This value is reserved for future use and should not be used.
        /// </summary>
        Reserved = 0x2,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Set up the script loader during initialization.
        /// </summary>
        Loader = 0x100,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Perform the core interpreter initialization.
        /// </summary>
        Initialization = 0x1000,
        /// <summary>
        /// Initialize the interpreter in safe mode.
        /// </summary>
        Safe = 0x2000,
        /// <summary>
        /// Include the test infrastructure during initialization.
        /// </summary>
        Test = 0x4000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Configure the interpreter for embedding within a host
        /// application.
        /// </summary>
        Embedding = 0x10000,
        /// <summary>
        /// Include vendor-specific initialization.
        /// </summary>
        Vendor = 0x20000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Treat remote resources as trusted during initialization.
        /// </summary>
        TrustedRemote = 0x40000,
        /// <summary>
        /// Do not treat remote resources as trusted during initialization.
        /// </summary>
        NoTrustedRemote = 0x80000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Set up well-known objects and values during initialization.
        /// </summary>
        WellKnown = 0x100000,
        /// <summary>
        /// Enable initialization callbacks.
        /// </summary>
        Callback = 0x200000,
        /// <summary>
        /// Scan for available packages and resources during initialization.
        /// </summary>
        Scan = 0x400000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable the security subsystem during initialization.
        /// </summary>
        Security = 0x800000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Perform initialization appropriate for interactive shell use.
        /// </summary>
        Shell = 0x1000000,
        /// <summary>
        /// Include command syntax help during initialization.
        /// </summary>
        SyntaxHelp = 0x2000000,
        /// <summary>
        /// Perform initialization for a shell worker thread.
        /// </summary>
        ShellWorker = 0x4000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Perform the initialization asynchronously.
        /// </summary>
        Asynchronous = 0x8000000,
        /// <summary>
        /// Wait for the initialization to start before returning.
        /// </summary>
        WaitForStart = 0x10000000,
        /// <summary>
        /// Preserve any existing security configuration during
        /// initialization.
        /// </summary>
        KeepSecurity = 0x20000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved for worker thread initialization slot one.
        /// </summary>
        Worker1 = 0x40000000,
        /// <summary>
        /// Reserved for worker thread initialization slot two (not yet
        /// implemented).
        /// </summary>
        Worker2 = 0x80000000,  /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Reserved for worker thread initialization slot three (not yet
        /// implemented).
        /// </summary>
        Worker3 = 0x100000000, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Reserved for worker thread initialization slot four (not yet
        /// implemented).
        /// </summary>
        Worker4 = 0x200000000, /* NOT YET IMPLEMENTED */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved for startup initialization slot one.
        /// </summary>
        Startup1 = 0x400000000,
        /// <summary>
        /// Reserved for startup initialization slot two (not yet
        /// implemented).
        /// </summary>
        Startup2 = 0x800000000,  /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Reserved for startup initialization slot three.
        /// </summary>
        Startup3 = 0x1000000000,
        /// <summary>
        /// Reserved for startup initialization slot four (not yet
        /// implemented).
        /// </summary>
        Startup4 = 0x2000000000, /* NOT YET IMPLEMENTED */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Set the value of the auto-path during initialization.
        /// </summary>
        SetAutoPath = 0x4000000000,
        /// <summary>
        /// Use the global auto-path during initialization.
        /// </summary>
        GlobalAutoPath = 0x8000000000,
        /// <summary>
        /// Disable tracing of auto-path operations during initialization.
        /// </summary>
        NoTraceAutoPath = 0x10000000000,
        /// <summary>
        /// Require that candidate directories for the <c>auto_path</c>
        /// actually exist.
        /// </summary>
        StrictAutoPath = 0x20000000000,  /* Candidate directories for the "auto_path"
                                          * must actually exist? */
        /// <summary>
        /// Show all auto-path search information.
        /// </summary>
        ShowAutoPath = 0x40000000000,    /* Show all auto-path search information? */
        /// <summary>
        /// When used with the <see cref="Scan" /> flag, forces the global
        /// auto-path to be refreshed.
        /// </summary>
        RefreshAutoPath = 0x80000000000, /* When used with the Scan flag, forces the
                                          * global auto-path to be refreshed. */
        /// <summary>
        /// Merge the auto-path values from before and/or after the core
        /// script library initialization process.
        /// </summary>
        MergeAutoPath = 0x100000000000,  /* Merge the auto-path values from before and/or
                                          * after the core script library initialization
                                          * process. */
        /// <summary>
        /// Ignore any errors encountered during initialization.
        /// </summary>
        IgnoreError = 0x200000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Configure the script library path during initialization.
        /// </summary>
        LibraryPath = 0x400000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Perform the initialization directly, i.e. without deferral.
        /// </summary>
        Direct = 0x800000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ISOLATED_PLUGINS
        /// <summary>
        /// Initialize support for isolated plugins (i.e. separate
        /// application domains).
        /// </summary>
        Isolated = 0x1000000000000,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Perform interpreter health checks during initialization.
        /// </summary>
        Health = 0x2000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable global tracking of interpreters during initialization.
        /// </summary>
        GlobalTracking = 0x4000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not use critical sections during initialization.
        /// </summary>
        NoCritical = 0x8000000000000,
        /// <summary>
        /// Disallow unsafe operations during initialization.
        /// </summary>
        NoUnsafe = 0x10000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not use critical sections during shell initialization.
        /// </summary>
        ShellNoCritical = 0x20000000000000,
        /// <summary>
        /// Disallow unsafe operations during shell initialization.
        /// </summary>
        ShellNoUnsafe = 0x40000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Enable unsupported initialization behavior; intended for
        /// advanced use only.
        /// </summary>
        Unsupported = 0x80000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Marker flag indicating that this is part of the default
        /// initialization configuration.
        /// </summary>
        ForDefault = 0x8000000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ENTERPRISE_LOCKDOWN
        /// <summary>
        /// Conditionally enables <see cref="Embedding" />; this is
        /// <see cref="None" /> when enterprise lockdown is in effect and
        /// <see cref="Embedding" /> otherwise.
        /// </summary>
        MaybeEmbedding = None,
#else
        /// <summary>
        /// Conditionally enables <see cref="Embedding" />; this is
        /// <see cref="None" /> when enterprise lockdown is in effect and
        /// <see cref="Embedding" /> otherwise.
        /// </summary>
        MaybeEmbedding = Embedding,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ENTERPRISE_LOCKDOWN
        /// <summary>
        /// Conditionally enables <see cref="Vendor" />; this is
        /// <see cref="None" /> when enterprise lockdown is in effect and
        /// <see cref="Vendor" /> otherwise.
        /// </summary>
        MaybeVendor = None,
#else
        /// <summary>
        /// Conditionally enables <see cref="Vendor" />; this is
        /// <see cref="None" /> when enterprise lockdown is in effect and
        /// <see cref="Vendor" /> otherwise.
        /// </summary>
        MaybeVendor = Vendor,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ENTERPRISE_LOCKDOWN
        /// <summary>
        /// Conditionally enables <see cref="TrustedRemote" />; this is
        /// <see cref="None" /> when enterprise lockdown is in effect and
        /// <see cref="TrustedRemote" /> otherwise.
        /// </summary>
        MaybeTrustedRemote = None,
#else
        /// <summary>
        /// Conditionally enables <see cref="TrustedRemote" />; this is
        /// <see cref="None" /> when enterprise lockdown is in effect and
        /// <see cref="TrustedRemote" /> otherwise.
        /// </summary>
        MaybeTrustedRemote = TrustedRemote,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ENTERPRISE_LOCKDOWN
        /// <summary>
        /// Conditionally enables <see cref="Security" />; this is
        /// <see cref="Security" /> when enterprise lockdown is in effect
        /// and <see cref="None" /> otherwise.
        /// </summary>
        MaybeSecurity = Security,
#else
        /// <summary>
        /// Conditionally enables <see cref="Security" />; this is
        /// <see cref="Security" /> when enterprise lockdown is in effect
        /// and <see cref="None" /> otherwise.
        /// </summary>
        MaybeSecurity = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ENTERPRISE_LOCKDOWN && ISOLATED_PLUGINS
        /// <summary>
        /// Conditionally enables isolated plugin support; this is set only
        /// when both enterprise lockdown and isolated plugins are in
        /// effect, and is otherwise <see cref="None" />.
        /// </summary>
        MaybeIsolated = Isolated,
#else
        /// <summary>
        /// Conditionally enables isolated plugin support; this is set only
        /// when both enterprise lockdown and isolated plugins are in
        /// effect, and is otherwise <see cref="None" />.
        /// </summary>
        MaybeIsolated = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="MaybeEmbedding" /> and
        /// <see cref="MaybeVendor" />.
        /// </summary>
        MaybeEmbeddingVendor = MaybeEmbedding | MaybeVendor,
        /// <summary>
        /// Combination mask of <see cref="MaybeSecurity" /> and
        /// <see cref="MaybeIsolated" />.
        /// </summary>
        MaybeIsolatedSecurity = MaybeSecurity | MaybeIsolated,

        /// <summary>
        /// Combination mask of <see cref="MaybeEmbeddingVendor" /> and
        /// <see cref="MaybeIsolatedSecurity" />.
        /// </summary>
        MaybeEverything = MaybeEmbeddingVendor | MaybeIsolatedSecurity,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Startup1" />,
        /// <see cref="Startup2" />, <see cref="Startup3" />, and
        /// <see cref="Startup4" />.
        /// </summary>
        Startup = Startup1 | Startup2 | Startup3 | Startup4,
        /// <summary>
        /// Combination mask of <see cref="Worker1" />,
        /// <see cref="Worker2" />, <see cref="Worker3" />, and
        /// <see cref="Worker4" />.
        /// </summary>
        Worker = Worker1 | Worker2 | Worker3 | Worker4,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ShellWorker" /> and
        /// <see cref="Worker" />.
        /// </summary>
        AnyShellWorker = ShellWorker | Worker,
        /// <summary>
        /// Combination mask of <see cref="AnyShellWorker" />,
        /// <see cref="Shell" />, <see cref="SyntaxHelp" />, and
        /// <see cref="Startup" />.
        /// </summary>
        ShellOrStartup = AnyShellWorker | Shell | SyntaxHelp | Startup,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Loader" />,
        /// <see cref="Initialization" />, <see cref="Safe" />,
        /// <see cref="Test" />, <see cref="Embedding" />,
        /// <see cref="Vendor" />, <see cref="Startup" />, and
        /// <see cref="Worker" />.
        /// </summary>
        Library = Loader | Initialization | Safe | Test |
                  Embedding | Vendor | Startup | Worker,

        /// <summary>
        /// Combination mask of <see cref="Shell" />,
        /// <see cref="SyntaxHelp" />, <see cref="ShellWorker" />,
        /// <see cref="Startup" />, and <see cref="Worker" />.
        /// </summary>
        ShellLibrary = Shell | SyntaxHelp | ShellWorker | Startup | Worker,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="SetAutoPath" />,
        /// <see cref="GlobalAutoPath" />, <see cref="StrictAutoPath" />,
        /// and <see cref="MergeAutoPath" />.
        /// </summary>
        AutoPath = SetAutoPath | GlobalAutoPath | StrictAutoPath | MergeAutoPath,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Loader" />,
        /// <see cref="Initialization" />, and
        /// <see cref="MaybeIsolatedSecurity" />.
        /// </summary>
        Minimal = Loader | Initialization | MaybeIsolatedSecurity,

        /// <summary>
        /// Combination mask of <see cref="Safe" /> and
        /// <see cref="MaybeIsolatedSecurity" />.
        /// </summary>
        SafeMinimal = Safe | MaybeIsolatedSecurity,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Loader" />,
        /// <see cref="Initialization" />,
        /// <see cref="MaybeEmbeddingVendor" />, <see cref="LibraryPath" />,
        /// and <see cref="Callback" />.
        /// </summary>
        SdkUse = Loader | Initialization | MaybeEmbeddingVendor |
                 LibraryPath | Callback,

        /// <summary>
        /// Combination mask of <see cref="Safe" />,
        /// <see cref="MaybeEmbeddingVendor" />, <see cref="LibraryPath" />,
        /// and <see cref="Callback" />.
        /// </summary>
        SafeSdkUse = Safe | MaybeEmbeddingVendor | LibraryPath | Callback,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Loader" />,
        /// <see cref="Initialization" />, <see cref="MaybeEverything" />,
        /// <see cref="AutoPath" />, <see cref="LibraryPath" />,
        /// <see cref="GlobalTracking" />, and <see cref="Callback" />.
        /// </summary>
        CoreLibraryUse = Loader | Initialization | MaybeEverything |
                         AutoPath | LibraryPath | GlobalTracking |
                         Callback,

        /// <summary>
        /// Combination mask of <see cref="Loader" />, <see cref="Safe" />,
        /// <see cref="MaybeEverything" />, <see cref="AutoPath" />,
        /// <see cref="LibraryPath" />, <see cref="GlobalTracking" />, and
        /// <see cref="Callback" />.
        /// </summary>
        SafeCoreLibraryUse = Loader | Safe | MaybeEverything |
                             AutoPath | LibraryPath | GlobalTracking |
                             Callback,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="CoreLibraryUse" /> and
        /// <see cref="ShellOrStartup" />.
        /// </summary>
        CoreShellUse = CoreLibraryUse | ShellOrStartup,

        /// <summary>
        /// Combination mask of <see cref="SafeCoreLibraryUse" /> and
        /// <see cref="ShellOrStartup" />.
        /// </summary>
        SafeCoreShellUse = SafeCoreLibraryUse | ShellOrStartup,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default initialization configuration; the combination of
        /// <see cref="CoreLibraryUse" /> and <see cref="ForDefault" />.
        /// </summary>
        Default = CoreLibraryUse | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the operation to perform on the set of
    /// runtime options associated with an interpreter. The values are bit
    /// flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("33e3eecb-1fe4-4d05-9642-fb5e187a5219")]
    public enum RuntimeOptionOperation
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Test whether a particular runtime option is present.
        /// </summary>
        Has = 0x2,
        /// <summary>
        /// Retrieve the current set of runtime options.
        /// </summary>
        Get = 0x4,
        /// <summary>
        /// Remove all runtime options.
        /// </summary>
        Clear = 0x8,
        /// <summary>
        /// Add one or more runtime options.
        /// </summary>
        Add = 0x10,
        /// <summary>
        /// Remove one or more runtime options.
        /// </summary>
        Remove = 0x20,
        /// <summary>
        /// Replace the runtime options with an entirely new set.
        /// </summary>
        Set = 0x40
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies a specific attribute of the TclTk engine
    /// that may be queried, for example via the engine introspection
    /// facilities. The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("6271c3cb-0599-4c92-9d3e-916ba0a35536")]
    public enum EngineAttribute : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The name of the engine.
        /// </summary>
        Name = 0x2,
        /// <summary>
        /// The culture associated with the engine.
        /// </summary>
        Culture = 0x4,
        /// <summary>
        /// The version number of the engine.
        /// </summary>
        Version = 0x8,
        /// <summary>
        /// The patch level of the engine.
        /// </summary>
        PatchLevel = 0x10,
        /// <summary>
        /// The release designation of the engine.
        /// </summary>
        Release = 0x20,
        /// <summary>
        /// The source control identifier for the engine build.
        /// </summary>
        SourceId = 0x40,
        /// <summary>
        /// The source control time stamp for the engine build.
        /// </summary>
        SourceTimeStamp = 0x80,
        /// <summary>
        /// The build configuration of the engine.
        /// </summary>
        Configuration = 0x100,
        /// <summary>
        /// The source control tag for the engine build.
        /// </summary>
        Tag = 0x200,
        /// <summary>
        /// The descriptive text associated with the engine.
        /// </summary>
        Text = 0x400,
        /// <summary>
        /// The build time stamp of the engine.
        /// </summary>
        TimeStamp = 0x800,
        /// <summary>
        /// The set of compile-time options used to build the engine.
        /// </summary>
        CompileOptions = 0x1000,
        /// <summary>
        /// The set of C# compiler options used to build the engine.
        /// </summary>
        CSharpOptions = 0x2000,
        /// <summary>
        /// The primary URI associated with the engine.
        /// </summary>
        Uri = 0x4000,
        /// <summary>
        /// The public key of the engine assembly.
        /// </summary>
        PublicKey = 0x8000,
        /// <summary>
        /// The public key token of the engine assembly.
        /// </summary>
        PublicKeyToken = 0x10000,
        /// <summary>
        /// The module version identifier (MVID) of the engine assembly.
        /// </summary>
        ModuleVersionId = 0x20000,
        /// <summary>
        /// The runtime options compiled into the engine.
        /// </summary>
        RuntimeOptions = 0x40000,
        /// <summary>
        /// The object identifiers associated with the engine.
        /// </summary>
        ObjectIds = 0x80000,
        /// <summary>
        /// The runtime version of the engine assembly image.
        /// </summary>
        ImageRuntimeVersion = 0x100000,
        /// <summary>
        /// The strong name of the engine assembly.
        /// </summary>
        StrongName = 0x200000,
        /// <summary>
        /// The strong name tag of the engine assembly.
        /// </summary>
        StrongNameTag = 0x400000,
        /// <summary>
        /// The cryptographic hash of the engine assembly.
        /// </summary>
        Hash = 0x800000,
        /// <summary>
        /// The certificate used to sign the engine assembly.
        /// </summary>
        Certificate = 0x1000000,
        /// <summary>
        /// The base URI used when checking for engine updates.
        /// </summary>
        UpdateBaseUri = 0x2000000,
        /// <summary>
        /// The path-and-query portion of the engine update URI.
        /// </summary>
        UpdatePathAndQuery = 0x4000000,
        /// <summary>
        /// The base URI used when downloading engine updates.
        /// </summary>
        DownloadBaseUri = 0x8000000,
        /// <summary>
        /// The base URI used when locating scripts.
        /// </summary>
        ScriptBaseUri = 0x10000000,
        /// <summary>
        /// The base URI used for auxiliary resources.
        /// </summary>
        AuxiliaryBaseUri = 0x20000000,
        /// <summary>
        /// The target framework of the engine assembly.
        /// </summary>
        TargetFramework = 0x40000000,
        /// <summary>
        /// The native utility library associated with the engine.
        /// </summary>
        NativeUtility = 0x80000000,
        /// <summary>
        /// The time stamp recorded when the interpreter was created.
        /// </summary>
        InterpreterTimeStamp = 0x100000000,
        /// <summary>
        /// The vendor associated with the engine.
        /// </summary>
        Vendor = 0x200000000,
        /// <summary>
        /// The suffix appended to the engine version information.
        /// </summary>
        Suffix = 0x400000000,
        /// <summary>
        /// The engine text or, when it is unavailable, the version suffix.
        /// </summary>
        TextOrSuffix = 0x800000000,
        /// <summary>
        /// The general operation timeout configured for the engine.
        /// </summary>
        Timeout = 0x1000000000,
        /// <summary>
        /// The network operation timeout configured for the engine.
        /// </summary>
        NetworkTimeout = 0x2000000000,
        /// <summary>
        /// The default engine attribute, equal to <see cref="Name" />.
        /// </summary>
        Default = Name,
        /// <summary>
        /// This value is reserved for future use and should not be used.
        /// </summary>
        Reserved = 0x8000000000000000
    }

