    /// <summary>
    /// This enumeration specifies which components of two pairs, each
    /// having an X and a Y member, are compared against one another. The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("03316c9c-7871-4250-b28c-dc91412800ec")]
    public enum PairComparison
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Compare the left pair's X component to the right pair's X
        /// component.
        /// </summary>
        LXRX = 0x2,
        /// <summary>
        /// Compare the left pair's X component to the right pair's Y
        /// component.
        /// </summary>
        LXRY = 0x4,
        /// <summary>
        /// Compare the left pair's Y component to the right pair's X
        /// component.
        /// </summary>
        LYRX = 0x8,
        /// <summary>
        /// Compare the left pair's Y component to the right pair's Y
        /// component.
        /// </summary>
        LYRY = 0x10
    }

