        Lowest = -2,
        /// <summary>
        /// Indicates that no priority is assigned.
        /// </summary>
        None = -1,
        /// <summary>
        /// The highest predefined priority level.
        /// </summary>
        Highest = 0,
        /// <summary>
        /// The default priority, equal to <see cref="Highest" />.
        /// </summary>
        Default = Highest
    }

