        /// </summary>
        None = 0,

        /// <summary>
        /// The first position in the sequence.
        /// </summary>
        First = 1,
        /// <summary>
        /// The second position in the sequence.
        /// </summary>
        Second = 2,
        /// <summary>
        /// The third position in the sequence.
        /// </summary>
        Third = 3,
        /// <summary>
        /// The fourth position in the sequence.
        /// </summary>
        Fourth = 4,
        /// <summary>
        /// The fifth position in the sequence.
        /// </summary>
        Fifth = 5,
        /// <summary>
        /// The sixth position in the sequence.
        /// </summary>
        Sixth = 6,
        /// <summary>
        /// The seventh position in the sequence.
        /// </summary>
        Seventh = 7,
        /// <summary>
        /// The eighth position in the sequence.
        /// </summary>
        Eighth = 8,
        /// <summary>
        /// The ninth position in the sequence.
        /// </summary>
        Nine = 9,
        /// <summary>
        /// The tenth position in the sequence.
        /// </summary>
        Tenth = 10
    }

