    /// <summary>
    /// This enumeration identifies the set of options associated with a
    /// particular <c>[object]</c> (or related) sub-command, used by the
    /// marshalling subsystem to select the appropriate option handling. The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("7a592738-e87b-4a8e-a0e5-730a71691f16")]
    public enum ObjectOptionType : ulong
    {
        /// <summary>
        /// No options are specified.
        /// </summary>
        None = 0x0,                      /* No options. */
        /// <summary>
        /// A reserved sentinel indicating an invalid option type; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,                   /* Invalid, do not use. */
        /// <summary>
        /// Options for the <c>[object alias]</c> sub-command.
        /// </summary>
        Alias = 0x2,                     /* For [object alias]. */
        /// <summary>
        /// Options for the <c>[library call]</c> sub-command.
        /// </summary>
        Call = 0x4,                      /* For [library call]. */
        /// <summary>
        /// Options for the <c>ConversionOps.ToCommandCallback</c> method.
        /// </summary>
        Callback = 0x8,                  /* For ConversionOps.ToCommandCallback method. */
        /// <summary>
        /// Options for the <c>[library certificate]</c> and
        /// <c>[object certificate]</c> sub-commands.
        /// </summary>
        Certificate = 0x10,              /* For [library certificate] and [object certificate]. */
        /// <summary>
        /// Options for the <c>[object cleanup]</c> sub-command.
        /// </summary>
        Cleanup = 0x20,                  /* For [object cleanup]. */
        /// <summary>
        /// Options for the <c>[object create]</c> sub-command.
        /// </summary>
        Create = 0x40,                   /* For [object create]. */
        /// <summary>
        /// Options for the <c>[object declare]</c> sub-command.
        /// </summary>
        Declare = 0x80,                  /* For [object declare]. */
        /// <summary>
        /// Options for the <c>ObjectOps.InvokeDelegate</c> method.
        /// </summary>
        Delegate = 0x100,                /* For the ObjectOps.InvokeDelegate method. */

#if CALLBACK_QUEUE
        /// <summary>
        /// Options for the <c>[callback dequeue]</c> sub-command.
        /// </summary>
        Dequeue = 0x200,                 /* For [callback dequeue]. */
#endif

#if XML && SERIALIZATION
        /// <summary>
        /// Options for the <c>[xml deserialize]</c> sub-command.
        /// </summary>
        Deserialize = 0x400,             /* For [xml deserialize]. */
#endif

        /// <summary>
        /// Options for the <c>[object dispose]</c> sub-command.
        /// </summary>
        Dispose = 0x800,                 /* For [object dispose]. */

#if NATIVE && TCL
        /// <summary>
        /// Options for the <c>[tcl eval]</c> sub-command.
        /// </summary>
        Evaluate = 0x1000,               /* For [tcl eval]. */
#endif

#if PREVIOUS_RESULT
        /// <summary>
        /// Options for the <c>[debug exception]</c> sub-command.
        /// </summary>
        Exception = 0x2000,              /* For [debug exception]. */
#endif

#if DATA
        /// <summary>
        /// Options for the <c>[sql execute]</c> sub-command.
        /// </summary>
        SqlExecute = 0x4000,             /* For [sql execute]. */
#endif

        /// <summary>
        /// Options for the <c>[exec]</c> command.
        /// </summary>
        Exec = 0x8000,                   /* For [exec]. */
        /// <summary>
        /// Options for the <c>CommandCallback</c> class.
        /// </summary>
        FireCallback = 0x10000,          /* For the CommandCallback class. */
        /// <summary>
        /// Options for the <c>MarshalOps.FixupReturnValue</c> method(s).
        /// </summary>
        FixupReturnValue = 0x20000,      /* For the MarshalOps.FixupReturnValue method(s). */
        /// <summary>
        /// Options for the <c>[object foreach]</c> sub-command.
        /// </summary>
        ForEach = 0x40000,               /* For [object foreach]. */
        /// <summary>
        /// Options for the <c>[object get]</c> sub-command.
        /// </summary>
        Get = 0x80000,                   /* For [object get]. */
        /// <summary>
        /// Options for the <c>[object import]</c> sub-command.
        /// </summary>
        Import = 0x100000,               /* For [object import]. */
        /// <summary>
        /// Options for the <c>[object invoke]</c> sub-command.
        /// </summary>
        Invoke = 0x200000,               /* For [object invoke]. */
        /// <summary>
        /// Options exclusive to the <c>[object invoke]</c> sub-command.
        /// </summary>
        InvokeOnly = 0x400000,           /* For [object invoke]. */
        /// <summary>
        /// Options for the <c>[object invokeraw]</c> sub-command.
        /// </summary>
        InvokeRaw = 0x800000,            /* For [object invokeraw]. */
        /// <summary>
        /// Options exclusive to the <c>[object invokeraw]</c> sub-command.
        /// </summary>
        InvokeRawOnly = 0x1000000,       /* For [object invokeraw]. */
        /// <summary>
        /// Options for the <c>[object invokeall]</c> sub-command.
        /// </summary>
        InvokeAll = 0x2000000,           /* For [object invokeall]. */
        /// <summary>
        /// Options shared by the <c>[object invoke]</c> and
        /// <c>[object invokeraw]</c> sub-commands.
        /// </summary>
        InvokeShared = 0x4000000,        /* For [object invoke] / [object invokeraw]. */
        /// <summary>
        /// Options used only by the shared <c>[object invoke]</c> and
        /// <c>[object invokeraw]</c> handling.
        /// </summary>
        InvokeSharedOnly = 0x8000000,    /* For [object invoke] / [object invokeraw]. */
        /// <summary>
        /// Options for the <c>[object isdisposed]</c> sub-command.
        /// </summary>
        IsDisposed = 0x10000000,         /* For [object isdisposed]. */
        /// <summary>
        /// Options for the <c>[object isnull]</c> sub-command.
        /// </summary>
        IsNull = 0x20000000,             /* For [object isnull]. */
        /// <summary>
        /// Options for the <c>[object isoftype]</c> sub-command.
        /// </summary>
        IsOfType = 0x40000000,           /* For [object isoftype]. */
        /// <summary>
        /// Options for the <c>[object load]</c> sub-command.
        /// </summary>
        Load = 0x80000000,               /* For [object load]. */
        /// <summary>
        /// Options for the <c>[object members]</c> sub-command.
        /// </summary>
        Members = 0x100000000,           /* For [object members]. */
        /// <summary>
        /// Options for the <c>[read]</c> command.
        /// </summary>
        Read = 0x200000000,              /* For [read]. */
        /// <summary>
        /// Options exclusive to the <c>[read]</c> command.
        /// </summary>
        ReadOnly = 0x400000000,          /* For [read]. */
        /// <summary>
        /// Options for the <c>[object search]</c> sub-command.
        /// </summary>
        Search = 0x800000000,            /* For [object search]. */

#if XML && SERIALIZATION
        /// <summary>
        /// Options for the <c>[xml serialize]</c> sub-command.
        /// </summary>
        Serialize = 0x1000000000,        /* For [xml serialize]. */
#endif

        /// <summary>
        /// Options for the simplified form of the
        /// <c>ConversionOps.ToCommandCallback</c> method.
        /// </summary>
        SimpleCallback = 0x2000000000,   /* For ConversionOps.ToCommandCallback method. */
        /// <summary>
        /// Options for the <c>[object type]</c> sub-command.
        /// </summary>
        Type = 0x4000000000,             /* For [object type]. */
        /// <summary>
        /// Options for the <c>[object unaliasnamespace]</c> sub-command.
        /// </summary>
        UnaliasNamespace = 0x8000000000, /* For [object unaliasnamespace]. */
        /// <summary>
        /// Options for the <c>[object undeclare]</c> sub-command.
        /// </summary>
        Undeclare = 0x10000000000,       /* For [object undeclare]. */
        /// <summary>
        /// Options for the <c>[object unimport]</c> sub-command.
        /// </summary>
        Unimport = 0x20000000000,        /* For [object unimport]. */
        /// <summary>
        /// Options for the <c>[object untype]</c> sub-command.
        /// </summary>
        Untype = 0x40000000000,          /* For [object untype]. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For the [object invoke*] sub-commands only.
        //
        /// <summary>
        /// Combination mask of <see cref="Invoke" />,
        /// <see cref="InvokeRaw" />, and <see cref="InvokeAll" />.
        /// </summary>
        ObjectInvokeOptionMask = Invoke | InvokeRaw | InvokeAll,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For the [library call] and [object invoke*]
        //       sub-commands only.
        //
        /// <summary>
        /// Combination mask of <see cref="Call" /> and
        /// <see cref="ObjectInvokeOptionMask" />.
        /// </summary>
        InvokeOptionMask = Call | ObjectInvokeOptionMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For all the [object] related sub-commands that are
        //       designed primarily to create object instances AS
        //       WELL AS their associated opaque object handles.
        //       The resulting opaque object handles may be disposed
        //       automatically (i.e. their IDispose.Dispose() method
        //       may be called just prior to their associated opaque
        //       object handles being removed from the containing
        //       interpreter context).  It should be noted here that
        //       using the "-create" flag to any of the [object]
        //       related sub-commands will trigger the automatic
        //       disposal behavior, even if that sub-command is not
        //       listed here.
        //
        /// <summary>
        /// Combination mask of the option types -- including
        /// <see cref="Create" />, <see cref="Get" />, and
        /// <see cref="Load" /> -- whose sub-commands create object
        /// instances together with their associated opaque object handles.
        /// </summary>
        CreateOptionMask = Create |
#if XML && SERIALIZATION
                           Deserialize |
#endif
                           Get |
                           Load,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For the [object] sub-commands only.
        //
        /// <summary>
        /// Combination mask of all option types corresponding to the
        /// <c>[object]</c> sub-commands.
        /// </summary>
        SubCommandMask = Alias | Certificate | Cleanup | Create |
                         Declare | Dispose | ForEach | Get |
                         Import | Invoke | InvokeRaw | InvokeAll |
                         IsDisposed | IsNull | IsOfType | Load | Members |
                         Search | Type | UnaliasNamespace | Undeclare |
                         Unimport | Untype,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For the non-[object] commands / sub-commands only.
        //
        /// <summary>
        /// Combination mask of the option types corresponding to commands
        /// and sub-commands other than the <c>[object]</c> sub-commands.
        /// </summary>
        OtherCommandMask = Call |
            Certificate | // [library certificate]
            Exec |
#if CALLBACK_QUEUE
            Dequeue |
#endif
#if XML && SERIALIZATION
            Deserialize |
#endif
#if NATIVE && TCL
            Evaluate |
#endif
#if PREVIOUS_RESULT
            Exception |
#endif
#if DATA
            SqlExecute |
#endif
            Read |
#if XML && SERIALIZATION
            Serialize |
#endif
            None,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: All core marshaller related options.
        //
        /// <summary>
        /// Combination mask of <see cref="SubCommandMask" />,
        /// <see cref="FixupReturnValue" />, and
        /// <see cref="InvokeShared" />.
        /// </summary>
        ObjectMask = SubCommandMask | FixupReturnValue | InvokeShared,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: The default option type (i.e. [object invoke]).
        //
        /// <summary>
        /// The default option type, equal to <see cref="Invoke" /> (i.e.
        /// <c>[object invoke]</c>).
        /// </summary>
        Default = Invoke
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the origin(s) from which option values
    /// may be obtained, together with flags that control how those values
    /// are gathered and merged.  The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("242b38e9-3f23-4fbf-90a4-fbde0ad758af")]
    public enum OptionOriginFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid option origin;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Option values may originate from interactive user input.
        /// </summary>
        Interactive = 0x2,
        /// <summary>
        /// Option values may originate from the command line.
        /// </summary>
        CommandLine = 0x4,
        /// <summary>
        /// Option values may originate from environment variables.
        /// </summary>
        Environment = 0x8,
        /// <summary>
        /// Option values may originate from the configuration subsystem.
        /// </summary>
        Configuration = 0x10,
        /// <summary>
        /// Option values may originate from the system registry.
        /// </summary>
        Registry = 0x20,
        /// <summary>
        /// Option values may originate from a built-in default.
        /// </summary>
        Default = 0x40,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow an existing option value to be overridden.
        /// </summary>
        Override = 0x80,
        /// <summary>
        /// Allow an existing option value to be removed.
        /// </summary>
        Remove = 0x100,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The option is optional and need not be present.
        /// </summary>
        Optional = 0x10000,
        /// <summary>
        /// Merge newly gathered option values with any existing ones.
        /// </summary>
        Merge = 0x20000,
        /// <summary>
        /// Expand option values during processing.
        /// </summary>
        Expand = 0x40000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Interactive" />,
        /// <see cref="CommandLine" />, <see cref="Environment" />,
        /// <see cref="Configuration" />, <see cref="Registry" />, and
        /// <see cref="Default" />.
        /// </summary>
        Any = Interactive | CommandLine | Environment |
              Configuration | Registry | Default,

        /// <summary>
        /// Combination of <see cref="Any" /> together with
        /// <see cref="Override" />.
        /// </summary>
        AnyOrOverride = Any | Override,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The set of option origins used when creating options;
        /// equivalent to <see cref="AnyOrOverride" />.
        /// </summary>
        Create = AnyOrOverride,
        /// <summary>
        /// The standard set of option origins; equivalent to
        /// <see cref="AnyOrOverride" />.
        /// </summary>
        Standard = AnyOrOverride,
        /// <summary>
        /// The set of option origins used for plugins; equivalent to
        /// <see cref="AnyOrOverride" />.
        /// </summary>
        Plugin = AnyOrOverride,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="AnyOrOverride" />,
        /// <see cref="Optional" />, <see cref="Merge" />, and
        /// <see cref="Expand" /> used by the interactive shell.
        /// </summary>
        Shell = AnyOrOverride | Optional | Merge | Expand,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL && NATIVE_PACKAGE
        /// <summary>
        /// Combination of <see cref="AnyOrOverride" /> and
        /// <see cref="Remove" /> used for the native package subsystem.
        /// </summary>
        NativePackage = AnyOrOverride | Remove,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved flag bit; callers should not use this value.
        /// </summary>
        Reserved = unchecked((int)0x80000000)
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
    /// <summary>
    /// This enumeration controls how the native Tcl library is located on
    /// disk, including which search locations are consulted, which name
    /// and version patterns are used, and how verbose the search process
    /// is.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("a3cceec2-cbd8-4a84-ae6c-fe2a8e0a334d")]
    public enum FindFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid set of find flags;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if TCL_WRAPPER
        //
        // HACK: This only belongs here because it is related to the
        //       native Tcl integration subsystem.  It was moved from
        //       the CreateFlags enumeration.  It is only used by the
        //       Interpreter.FindTclInterpreterThreadId method and in
        //       that case, only when compiled with TCL_WRAPPER.
        //
        /// <summary>
        /// Enable Tcl wrapper mode, in which all Tcl interpreters are
        /// assumed to have been created on the main thread.  This is
        /// intended for a very narrow use case and should generally not be
        /// used.
        /// </summary>
        TclWrapper = 0x2, /* Enable Tcl wrapper mode.  All Tcl
                           * interpreters will be assumed to have
                           * been created on the main thread.
                           * This is designed for a very narrow
                           * use case and should generally not be
                           * used.  If you need it, you will know
                           * for certain that you need it. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Consult the pre-find callback when locating the native Tcl
        /// library.
        /// </summary>
        PreCallback = 0x4,
        /// <summary>
        /// Consult the post-find callback when locating the native Tcl
        /// library.
        /// </summary>
        PostCallback = 0x8,
        /// <summary>
        /// Search a specific, caller-supplied path.
        /// </summary>
        SpecificPath = 0x10,
        /// <summary>
        /// Search the path associated with the current script.
        /// </summary>
        ScriptPath = 0x20,
        /// <summary>
        /// Search locations specified via environment variables.
        /// </summary>
        Environment = 0x40,
        /// <summary>
        /// Search the directories on the Tcl auto-path.
        /// </summary>
        AutoPath = 0x80,
        /// <summary>
        /// Search the package binary path.
        /// </summary>
        PackageBinaryPath = 0x100,
        /// <summary>
        /// Search the package library path.
        /// </summary>
        PackageLibraryPath = 0x200,
        /// <summary>
        /// Search the general package path.
        /// </summary>
        PackagePath = 0x400,
        /// <summary>
        /// Search the directory containing the entry assembly.
        /// </summary>
        EntryAssembly = 0x800,
        /// <summary>
        /// Search the directory containing the executing assembly.
        /// </summary>
        ExecutingAssembly = 0x1000,
        /// <summary>
        /// Search the application binary path.
        /// </summary>
        BinaryPath = 0x2000,
        /// <summary>
        /// Search locations recorded in the system registry.
        /// </summary>
        Registry = 0x4000,
        /// <summary>
        /// Search the operating system search path.
        /// </summary>
        SearchPath = 0x8000,
        /// <summary>
        /// Search the externals path.
        /// </summary>
        ExternalsPath = 0x10000,
        /// <summary>
        /// Search peer directories.
        /// </summary>
        PeerPath = 0x20000,

#if UNIX
        /// <summary>
        /// Search the system library path (Unix only).
        /// </summary>
        LibraryPath = 0x40000,
        /// <summary>
        /// Search the local library path (Unix only).
        /// </summary>
        LocalLibraryPath = 0x80000,
        /// <summary>
        /// Search the Homebrew library path (Unix only).
        /// </summary>
        HomebrewLibraryPath = 0x100000,
#endif

        /// <summary>
        /// Evaluate a script to help locate the native Tcl library.
        /// </summary>
        EvaluateScript = 0x200000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not consult operating-system-provided locations.
        /// </summary>
        NoOperatingSystem = 0x400000,
        /// <summary>
        /// Attempt to find the processor architecture.
        /// </summary>
        FindArchitecture = 0x800000,
        /// <summary>
        /// Attempt to get the processor architecture.
        /// </summary>
        GetArchitecture = 0x1000000,
        /// <summary>
        /// Require the processor architecture to match.
        /// </summary>
        MatchArchitecture = 0x2000000,
        /// <summary>
        /// Search the candidate paths recursively.
        /// </summary>
        RecursivePaths = 0x4000000,
        /// <summary>
        /// Allow path components to be zeroed during the search.
        /// </summary>
        ZeroComponents = 0x8000000,
        /// <summary>
        /// Refresh the Tcl auto-path before searching.
        /// </summary>
        RefreshAutoPath = 0x10000000,
        /// <summary>
        /// Allow previously discovered builds to be overwritten.
        /// </summary>
        OverwriteBuilds = 0x20000000,
        /// <summary>
        /// Consider only trusted (signed) native libraries.
        /// </summary>
        TrustedOnly = 0x40000000,
        /// <summary>
        /// Treat located native libraries as trusted.
        /// </summary>
        Trusted = 0x80000000,
        /// <summary>
        /// Use file version information when evaluating candidates.
        /// </summary>
        FileVersion = 0x100000000,
        /// <summary>
        /// Also consider alternate library names.
        /// </summary>
        AlternateName = 0x200000000,
        /// <summary>
        /// Refresh the evaluated script before searching.
        /// </summary>
        RefreshEvaluateScript = 0x400000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include the list of extra name patterns when matching.
        /// </summary>
        ExtraNamePatternList = 0x800000000,
        /// <summary>
        /// Include the list of primary name patterns when matching.
        /// </summary>
        PrimaryNamePatternList = 0x1000000000,
        /// <summary>
        /// Include the list of secondary name patterns when matching.
        /// </summary>
        SecondaryNamePatternList = 0x2000000000,
        /// <summary>
        /// Include the list of other name patterns when matching.
        /// </summary>
        OtherNamePatternList = 0x4000000000,

        /// <summary>
        /// Include the list of extra version patterns when matching.
        /// </summary>
        ExtraVersionPatternList = 0x8000000000,
        /// <summary>
        /// Include the list of primary version patterns when matching.
        /// </summary>
        PrimaryVersionPatternList = 0x10000000000,
        /// <summary>
        /// Include the list of secondary version patterns when matching.
        /// This value is reportedly not currently used.
        /// </summary>
        SecondaryVersionPatternList = 0x20000000000, /* NOT USED? */
        /// <summary>
        /// Include the list of other version patterns when matching.  This
        /// value is reportedly not currently used.
        /// </summary>
        OtherVersionPatternList = 0x40000000000, /* NOT USED? */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved search sub-component flag bit zero.
        /// </summary>
        Part0 = 0x80000000000,
        /// <summary>
        /// Reserved search sub-component flag bit one.
        /// </summary>
        Part1 = 0x100000000000,
        /// <summary>
        /// Reserved search sub-component flag bit two.
        /// </summary>
        Part2 = 0x200000000000,
        /// <summary>
        /// Reserved search sub-component flag bit three.
        /// </summary>
        Part3 = 0x400000000000,
        /// <summary>
        /// Reserved search sub-component flag bit four.
        /// </summary>
        Part4 = 0x800000000000,
        /// <summary>
        /// Reserved search sub-component flag bit five.
        /// </summary>
        Part5 = 0x1000000000000,
        /// <summary>
        /// Reserved search sub-component flag bit six.
        /// </summary>
        Part6 = 0x2000000000000,
        /// <summary>
        /// Reserved search sub-component flag bit seven.
        /// </summary>
        Part7 = 0x4000000000000,
        /// <summary>
        /// Reserved search sub-component flag bit eight.
        /// </summary>
        Part8 = 0x8000000000000,
        /// <summary>
        /// Reserved search sub-component flag bit nine.
        /// </summary>
        Part9 = 0x10000000000000,
        /// <summary>
        /// Reserved search sub-component overflow flag bit.
        /// </summary>
        PartX = 0x20000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Emit verbose diagnostics about candidate detection heuristics.
        /// </summary>
        VerboseLooksLike = 0x40000000000000,
        /// <summary>
        /// Emit verbose diagnostics while extracting build information.
        /// </summary>
        VerboseExtractBuild = 0x80000000000000,
        /// <summary>
        /// Emit verbose diagnostics about registry-based searches.
        /// </summary>
        VerboseRegistry = 0x100000000000000,
        /// <summary>
        /// Emit verbose diagnostics about candidate selection.
        /// </summary>
        VerboseSelect = 0x200000000000000,
        /// <summary>
        /// Emit verbose diagnostics about searched paths.
        /// </summary>
        VerbosePath = 0x400000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of every search-location flag, namely
        /// <see cref="PreCallback" />, <see cref="PostCallback" />,
        /// <see cref="SpecificPath" />, <see cref="ScriptPath" />,
        /// <see cref="Environment" />, <see cref="AutoPath" />,
        /// <see cref="PackageBinaryPath" />,
        /// <see cref="PackageLibraryPath" />, <see cref="PackagePath" />,
        /// <see cref="EntryAssembly" />, <see cref="ExecutingAssembly" />,
        /// <see cref="BinaryPath" />, <see cref="Registry" />,
        /// <see cref="SearchPath" />, <see cref="ExternalsPath" />,
        /// <see cref="PeerPath" />, and <see cref="EvaluateScript" />,
        /// together with the Unix-only library path flags when applicable.
        /// </summary>
        LocationMask = PreCallback | PostCallback | SpecificPath |
                       ScriptPath | Environment | AutoPath |
                       PackageBinaryPath | PackageLibraryPath | PackagePath |
                       EntryAssembly | ExecutingAssembly | BinaryPath |
                       Registry | SearchPath | ExternalsPath | PeerPath |
#if UNIX
                       LibraryPath | LocalLibraryPath | HomebrewLibraryPath |
#endif
                       EvaluateScript,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="FindArchitecture" />,
        /// <see cref="GetArchitecture" />, and
        /// <see cref="MatchArchitecture" />.
        /// </summary>
        Architecture = FindArchitecture | GetArchitecture | MatchArchitecture,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the behavioral search flags, including
        /// <see cref="NoOperatingSystem" />, <see cref="Architecture" />,
        /// <see cref="RecursivePaths" />, <see cref="ZeroComponents" />,
        /// <see cref="RefreshAutoPath" />, <see cref="OverwriteBuilds" />,
        /// <see cref="TrustedOnly" />, <see cref="Trusted" />,
        /// <see cref="FileVersion" />, <see cref="AlternateName" />,
        /// <see cref="RefreshEvaluateScript" />, and the reserved part
        /// flags.
        /// </summary>
        FlagsMask = NoOperatingSystem | Architecture |
                    RecursivePaths | ZeroComponents |
                    RefreshAutoPath | OverwriteBuilds |
                    TrustedOnly | Trusted | FileVersion |
                    AlternateName | RefreshEvaluateScript |
                    Part0 | Part1 | Part2 | Part3 |
                    Part4 | Part5 | Part6 | Part7 |
                    Part8 | Part9 | PartX,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of every name and version pattern-list flag,
        /// namely <see cref="ExtraNamePatternList" />,
        /// <see cref="PrimaryNamePatternList" />,
        /// <see cref="SecondaryNamePatternList" />,
        /// <see cref="OtherNamePatternList" />,
        /// <see cref="ExtraVersionPatternList" />,
        /// <see cref="PrimaryVersionPatternList" />,
        /// <see cref="SecondaryVersionPatternList" />, and
        /// <see cref="OtherVersionPatternList" />.
        /// </summary>
        PatternMask = ExtraNamePatternList | PrimaryNamePatternList |
                      SecondaryNamePatternList | OtherNamePatternList |
                      ExtraVersionPatternList | PrimaryVersionPatternList |
                      SecondaryVersionPatternList | OtherVersionPatternList,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="VerboseLooksLike" />,
        /// <see cref="VerboseExtractBuild" />,
        /// <see cref="VerboseRegistry" />, <see cref="VerboseSelect" />,
        /// and <see cref="VerbosePath" />.
        /// </summary>
        VerboseMask = VerboseLooksLike | VerboseExtractBuild | VerboseRegistry |
                      VerboseSelect | VerbosePath,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="PreCallback" /> and
        /// <see cref="PostCallback" />.
        /// </summary>
        Callback = PreCallback | PostCallback,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="LocationMask" /> and
        /// <see cref="PatternMask" />.
        /// </summary>
        All = LocationMask | PatternMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The typical set of find flags, equal to <see cref="All" /> with
        /// <see cref="EvaluateScript" />,
        /// <see cref="OtherNamePatternList" />, and
        /// <see cref="OtherVersionPatternList" /> removed.
        /// </summary>
        Typical = All & ~(EvaluateScript | OtherNamePatternList | OtherVersionPatternList),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The standard set of find flags, namely <see cref="Typical" />
        /// combined with <see cref="Architecture" /> and
        /// <see cref="TrustedOnly" />.
        /// </summary>
        Standard = Typical | Architecture | TrustedOnly,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of find flags; equivalent to
        /// <see cref="Typical" />.
        /// </summary>
        Default = Typical
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how the native Tcl integration subsystem
    /// loads the native Tcl library.  The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("8b71bb91-aa6b-45e6-97ea-d9e702b3ce92")]
    public enum LoadFlags : ulong
    {
        /// <summary>
        /// No special load flags are set.
        /// </summary>
        None = 0x0,            /* no special unload flags. */
        /// <summary>
        /// A reserved flag bit; callers should not use this value.
        /// </summary>
        Reserved = 0x1,        /* reserved, do not use. */
        /// <summary>
        /// Call the operating system SetDllDirectory function prior to
        /// loading the native library.
        /// </summary>
        SetDllDirectory = 0x2, /* call SetDllDirectory prior to loading. */

#if TCL_THREADED
        /// <summary>
        /// Allow a non-threaded build of the native Tcl library to be
        /// loaded.
        /// </summary>
        IgnoreThreaded = 0x4,  /* allow non-threaded builds to be loaded. */
#endif

        /// <summary>
        /// Initially place the entire native Tcl integration subsystem
        /// into read-only mode.
        /// </summary>
        ReadOnly = 0x8,        /* initially place the entire native Tcl
                                * integration subsystem into read-only
                                * mode. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Marker flag included in the default load flag set.
        /// </summary>
        ForDefault = 0x10000000,
        /// <summary>
        /// Marker flag included in the native package load flag set.
        /// </summary>
        ForNativePackage = 0x20000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="ReadOnly" /> and
        /// <see cref="ForNativePackage" /> used when loading for a native
        /// package.
        /// </summary>
        NativePackage = ReadOnly | ForNativePackage,
        /// <summary>
        /// Combination of <see cref="None" /> and
        /// <see cref="ForDefault" /> representing the default load flags.
        /// </summary>
        Default = None | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how the native Tcl integration subsystem
    /// unloads the native Tcl library.  The values are bit flags that may
    /// be combined.
    /// </summary>
    [Flags()]
    [ObjectId("473819a9-4470-410c-b5d2-14b690e64c83")]
    public enum UnloadFlags
    {
        /// <summary>
        /// No special unload flags are set.
        /// </summary>
        None = 0x0,           /* no special unload flags. */
        /// <summary>
        /// A reserved flag bit; callers should not use this value.
        /// </summary>
        Reserved = 0x1,       /* reserved, do not use. */
        /// <summary>
        /// Skip validation of the Tcl interpreter thread during unload.
        /// </summary>
        NoInterpThread = 0x2, /* skip Tcl interpreter thread validation. */
        /// <summary>
        /// Skip checking whether the Tcl interpreter is currently active.
        /// </summary>
        NoInterpActive = 0x4, /* skip checking if the Tcl interpreter is
                               * active. */
        /// <summary>
        /// Release the module reference for the native Tcl library.
        /// </summary>
        ReleaseModule = 0x8,  /* release the module reference for the Tcl
                               * library. */
        /// <summary>
        /// Delete the exit handler during unload.
        /// </summary>
        ExitHandler = 0x10,   /* delete the exit handler. */
        /// <summary>
        /// Call the Tcl_Finalize delegate if possible.
        /// </summary>
        Finalize = 0x20,      /* call the Tcl_Finalize delegate if possible. */
        /// <summary>
        /// Free the operating system module handle once its reference
        /// count reaches zero.
        /// </summary>
        FreeLibrary = 0x40,   /* free the operating system module handle if the
                               * reference count reaches zero. */

        //
        // NOTE: The following composite flag values are used as
        //       specific points in the TclWrapper code.
        //
        /// <summary>
        /// Composite flag value used when unloading from the exit handler;
        /// equal to <see cref="ReleaseModule" /> combined with
        /// <see cref="ExitHandler" />.
        /// </summary>
        FromExitHandler = ReleaseModule | ExitHandler,

        /// <summary>
        /// Composite flag value used when unloading from the event loop;
        /// combination of <see cref="ExitHandler" />,
        /// <see cref="Finalize" />, and <see cref="FreeLibrary" />.
        /// </summary>
        FromDoOneEvent = ExitHandler | Finalize | FreeLibrary,

        /// <summary>
        /// Composite flag value used when unloading from the load path;
        /// combination of <see cref="NoInterpActive" />,
        /// <see cref="ReleaseModule" />, <see cref="ExitHandler" />,
        /// <see cref="Finalize" />, and <see cref="FreeLibrary" />.
        /// </summary>
        FromLoad = NoInterpActive | ReleaseModule | ExitHandler |
                   Finalize | FreeLibrary,

        /// <summary>
        /// Composite flag value used when unloading from a thread;
        /// equivalent to <see cref="Default" />.
        /// </summary>
        FromThread = Default,

        //
        // NOTE: About 99.9% of all external callers should use
        //       this composite flag value [and no other values].
        //
        /// <summary>
        /// The default composite unload flags that nearly all external
        /// callers should use; combination of
        /// <see cref="ReleaseModule" />, <see cref="ExitHandler" />,
        /// <see cref="Finalize" />, and <see cref="FreeLibrary" />.
        /// </summary>
        Default = ReleaseModule | ExitHandler | Finalize | FreeLibrary
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if EMIT && NATIVE && LIBRARY
    /// <summary>
    /// This enumeration controls how a native module is loaded and managed
    /// by the interpreter.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("fd1eb082-ecbd-48c6-80d5-2ed2e06ce130")]
    public enum ModuleFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Do not call FreeLibrary when the module reference count reaches
        /// zero.
        /// </summary>
        NoUnload = 0x1,    /* Do not call FreeLibrary when the reference
                            * count reaches zero. */
        /// <summary>
        /// Do not allow the module to be removed from the interpreter.
        /// </summary>
        NoRemove = 0x2,    /* Do not allow the module to be removed from
                            * the interpreter. */
        /// <summary>
        /// The module file must be signed and trusted.
        /// </summary>
        TrustedOnly = 0x4, /* The module file must be signed and trusted. */
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the mechanism used to load a managed
    /// assembly via the <c>[object load]</c> command and its <c>-type</c>
    /// option.
    /// </summary>
    [Flags()]
    [ObjectId("ba60001b-81d5-4e38-8dec-3fcb1b80e39d")]
    public enum LoadType /* Used with the [object load] -type option. */
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid load type; callers
        /// should not use this value.
        /// </summary>
        Invalid = -1,         /* Reserved, do not use. */
        /// <summary>
        /// Does not actually load anything.
        /// </summary>
        None = 0x0,           /* Does not actually load anything. */
        /// <summary>
        /// Load the assembly via Assembly.Load using a partial name.
        /// </summary>
        PartialName = 0x1,    /* Assembly.Load using a partial name. */
        /// <summary>
        /// Load the assembly via Assembly.Load using its full name.
        /// </summary>
        FullName = 0x2,       /* Assembly.Load using the full name. */
        /// <summary>
        /// Load the assembly via Assembly.LoadFrom using a path and file
        /// name.
        /// </summary>
        File = 0x4,           /* Assembly.LoadFrom using a path and file name. */
        /// <summary>
        /// Load the assembly via Assembly.Load using an array of bytes
        /// (base64 encoded).
        /// </summary>
        Bytes = 0x8,          /* Assembly.Load using an array of bytes (base64 encoded). */
        /// <summary>
        /// Load the assembly via Assembly.Load using an array of bytes
        /// read from a stream.
        /// </summary>
        Stream = 0x10,        /* Assembly.Load using an array of bytes (from stream). */

        /// <summary>
        /// The default load type, currently loading by partial name;
        /// equivalent to <see cref="PartialName" />.
        /// </summary>
        Default = PartialName /* Default load type, currently by name. */
    }

