    /// </summary>
    [ObjectId("95df58aa-6b4b-4fbb-98bf-948b034f912e")]
    public enum PromptType
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid prompt type; callers
        /// should not use this value.
        /// </summary>
        Invalid = -1, /* invalid, do not use. */
        /// <summary>
        /// No prompt will be displayed.
        /// </summary>
        None = 0,     /* no prompt will be displayed. */
        /// <summary>
        /// The prompt type for a normal (initial) prompt.
        /// </summary>
        Start = 1,    /* this is the type for a normal prompt. */
        /// <summary>
        /// The prompt type for a continued prompt, shown when additional
        /// input is required to complete a script.
