    /// <summary>
    /// This enumeration provides additional control over how interactive
    /// prompts are displayed by the host.  The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("f76751ef-752b-4a0b-adf6-fe26384d6686")]
    public enum PromptFlags
    {
        /// <summary>
        /// No special handling; an ordinary start or continue prompt.
        /// </summary>
        None = 0x0,           /* no special handling, normal start or continue
                               * prompt. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of prompt flags;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,        /* invalid, do not use. */
        /// <summary>
        /// The prompt is for the interactive debugger.
        /// </summary>
        Debug = 0x8,          /* when set, this prompt is for the interactive
                               * debugger. */
        /// <summary>
        /// The prompt is for queued (asynchronous) input mode.
        /// </summary>
        Queue = 0x10,         /* when set, this prompt is for queued (async)
                               * input mode. */

        /// <summary>
        /// Ensure the total interactive command count is shown in the
        /// prompt.
        /// </summary>
        CommandCount = 0x20,  /* when set, make sure the total interactive
                               * command count is shown. */
        /// <summary>
        /// Ensure the number of active interactive loops is shown in the
        /// prompt.
        /// </summary>
        ActiveLoops = 0x40,   /* when set, make sure the number of active
                               * interactive loops is shown. */

        /// <summary>
        /// Ensure the interpreter identifier is shown in the prompt.
        /// </summary>
        Interpreter = 0x80,   /* when set, make sure the interpreter Id is
                               * shown. */
        /// <summary>
        /// Indicates that the host successfully displayed a prompt.
        /// </summary>
        Done = 0x100,         /* when set, it means that the host successfully
                               * displayed a prompt. */

        /// <summary>
        /// Indicates that the host successfully displayed part of a
        /// prompt.
        /// </summary>
        Partial = 0x200,      /* when set, it means that the host successfully
                               * displayed part of a prompt. */
        /// <summary>
        /// Emit some trace output while handling the prompt.
        /// </summary>
        Trace = 0x400,        /* when set, emit some trace output. */

        /// <summary>
        /// Marker flag included in the default prompt flag set.
        /// </summary>
        ForDefault = 0x10000, /* for use with the default flag set. */

        /// <summary>
        /// The default prompt flags; equivalent to
        /// <see cref="ForDefault" />.
        /// </summary>
        Default = ForDefault
    }

