#if CACHE_STATISTICS
    /// <summary>
    /// This enumeration identifies the various per-operation counters that are
    /// maintained for an TclTk cache when cache statistics tracking has been
    /// enabled.  Each value names a distinct event whose occurrences are
    /// tallied so that cache behavior and effectiveness can be analyzed.
    /// </summary>
    [ObjectId("e87b3a0a-6559-4222-aad5-c2a4b6312392")]
    public enum CacheCountType
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized counter
        /// identifier; callers should not use this value.
        /// </summary>
        Invalid = -1,
        /// <summary>
        /// No counter is specified.
        /// </summary>
        None = 0,
        /// <summary>
        /// Counts the number of cache lookups that successfully located the
        /// requested entry.
        /// </summary>
        Hit = 1,
        /// <summary>
        /// Counts the number of cache lookups that failed to locate the
        /// requested entry.
        /// </summary>
        Miss = 2,
        /// <summary>
        /// Counts the number of times a cache operation was deliberately
        /// skipped (i.e. bypassed).
        /// </summary>
        Skip = 3,
        /// <summary>
        /// Counts the number of hash collisions encountered while accessing
        /// the cache.
        /// </summary>
        Collide = 4,
        /// <summary>
        /// Counts the number of times an entry was found to already exist in
        /// the cache.
        /// </summary>
        Found = 5,
        /// <summary>
        /// Counts the number of times an entry was found to be absent from
        /// the cache.
        /// </summary>
        NotFound = 6,
        /// <summary>
        /// Counts the number of entries added to the cache.
        /// </summary>
        Add = 7,
        /// <summary>
        /// Counts the number of existing cache entries that were modified.
        /// </summary>
        Change = 8,
        /// <summary>
        /// Counts the number of entries removed from the cache.
        /// </summary>
        Remove = 9,
        /// <summary>
        /// Counts the number of times an entry removal was requested but did
        /// not actually occur.
        /// </summary>
        NoRemove = 10,
        /// <summary>
        /// Counts the number of times the entire cache was cleared.
        /// </summary>
        Clear = 11,
        /// <summary>
        /// Counts the number of times the cache was trimmed to reduce its
        /// size.
        /// </summary>
        Trim = 12,
        /// <summary>
        /// The total number of counter types being tracked; this also serves
        /// as the size of the backing counter array.
        /// </summary>
        SizeOf = 13
    }
#endif

