    /// <summary>
    /// This enumeration identifies the individual pieces of test information
    /// and per-run statistics that may be recorded for, or queried from, the
    /// TclTk test framework.  Negative values generally name descriptive
    /// information about the test run while non-negative values name counters.
    /// </summary>
    [ObjectId("cacfb749-6c82-44b7-bf4c-e98b86621291")]
    public enum TestInformationType
    {
        /// <summary>
        /// Special value, for use by the <c>TestOps.RecordInformation</c>
        /// method only, that sets both the previous and current test names.
        /// </summary>
        PreviousAndCurrentName = -17, // SPECIAL: For use by the TestOps.RecordInformation
                                      // method only.  Set the previous and current test
                                      // names.
        /// <summary>
        /// The name of the previous test, if any.
        /// </summary>
        PreviousName = -16,           // The name of the previous test, if any.
        /// <summary>
        /// The name of the current test, if any.
        /// </summary>
        CurrentName = -15,            // The name of the current test, if any.
        /// <summary>
        /// The parent interpreter of the one running the test.
        /// </summary>
        Interpreter = -14,            // The parent interpreter of the one running the test.
        /// <summary>
        /// The number of times a given test should be repeated.
        /// </summary>
        RepeatCount = -13,            // The number of times a given test should be repeated.
        /// <summary>
        /// The test output verbosity flags (i.e. the <c>tcltest -verbose</c>
        /// settings).
        /// </summary>
        Verbose = -12,                // The test output flags (tcltest -verbose).
        /// <summary>
        /// The names of the tests that were run with <c>knownBug</c>
        /// constraints.
        /// </summary>
        KnownBugs = -11,              // The names of tests ran with knownBug constraints.
        /// <summary>
        /// The active test constraints.
        /// </summary>
        Constraints = -10,            // The active test constraints.
#if DEBUGGER
        /// <summary>
        /// The active test breakpoints.
        /// </summary>
        Breakpoints = -9,             // The active test breakpoints.
#endif
        /// <summary>
        /// The active test hooks.
        /// </summary>
        Hooks = -8,                   // The active test hooks.
        /// <summary>
        /// The number of times a given test has been run.
        /// </summary>
        Counts = -7,                  // The number of times a given test has been run.
        /// <summary>
        /// The names of the tests that passed.
        /// </summary>
        PassedNames = -6,             // The names of the failing tests.
        /// <summary>
        /// The names of the tests that were skipped.
        /// </summary>
        SkippedNames = -5,            // The names of the skipped tests.
        /// <summary>
        /// The names of the tests that failed.
        /// </summary>
        FailedNames = -4,             // The names of the failing tests.
        /// <summary>
        /// The patterns matching the tests that should be skipped.
        /// </summary>
        SkipNames = -3,               // The patterns of tests to skip.
        /// <summary>
        /// The patterns matching the tests that should be run.
        /// </summary>
        MatchNames = -2,              // The patterns of tests to run.
        /// <summary>
        /// The test nesting level.
        /// </summary>
        Level = -1,                   // The test nesting level.
        /// <summary>
        /// The total number of tests encountered.
        /// </summary>
        Total = 0,                    // Total number of tests encountered.
        /// <summary>
        /// The total number of tests that were skipped.
        /// </summary>
        Skipped = 1,                  // Total number of tests that were skipped.
        /// <summary>
        /// The total number of tests that were disabled.
        /// </summary>
        Disabled = 2,                 // Total number of tests that were disabled.
        /// <summary>
        /// The total number of tests that passed.
        /// </summary>
        Passed = 3,                   // Total number of tests that passed.
        /// <summary>
        /// The total number of tests that failed.
        /// </summary>
        Failed = 4,                   // Total number of tests that failed.
        /// <summary>
        /// The total number of tests that were skipped and were also marked
        /// as a <c>knownBug</c>.
        /// </summary>
        SkippedBug = 5,               // Total number of tests that were skipped -AND- marked
                                      // as "knownBug".
        /// <summary>
        /// The total number of tests that were disabled and were also marked
        /// as a <c>knownBug</c>.
        /// </summary>
        DisabledBug = 6,              // Total number of tests that were disabled -AND- marked
                                      // as "knownBug".
        /// <summary>
        /// The total number of tests that passed and were also marked as a
        /// <c>knownBug</c>.
        /// </summary>
        PassedBug = 7,                // Total number of tests that passed -AND- marked as
                                      // "knownBug".
        /// <summary>
        /// The total number of tests that failed and were also marked as a
        /// <c>knownBug</c>.
        /// </summary>
        FailedBug = 8,                // Total number of tests that failed -AND- marked as
                                      // "knownBug".
        /// <summary>
        /// The total number of statistics being tracked; this also serves as
        /// the size of the backing statistics array.
        /// </summary>
        SizeOf = 9                    // Total number of statistics that we are keeping track
                                      // of.
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies which dimension of an interpreter host's
    /// input/output area a sizing operation applies to.  The values are bit
    /// flags that may be combined to select a particular buffer or window
    /// measurement.
    /// </summary>
    [Flags()]
    [ObjectId("a43b5860-1ad6-433f-940e-ef8d5cd399c2")]
    public enum HostSizeType
    {
        /// <summary>
        /// No flags are set; the host size type is unspecified.
        /// </summary>
        None = 0x0,     /* The host size type is unspecified. */
        /// <summary>
        /// Reserved as invalid; this value should not be used.
        /// </summary>
        Invalid = 0x1,  /* Invalid, do not use. */
        /// <summary>
        /// The current or maximum size of the host input/output buffer or
        /// window, leaving the choice up to the underlying host.  All hosts
        /// that implement the <c>ResetSize</c>, <c>GetSize</c>, or
        /// <c>SetSize</c> methods should support this flag.
        /// </summary>
        Any = 0x2,      /* The current -OR- maximum size of the host input/output
                         * buffer -OR- window, leaving these choices up to the
                         * underlying host.  All hosts that implement the
                         * ResetSize, GetSize, or SetSize methods should support
                         * this flag. */
        /// <summary>
        /// The size of the host input/output buffer.  All hosts that
        /// implement the <c>ResetSize</c>, <c>GetSize</c>, or
        /// <c>SetSize</c> methods should support this flag.
        /// </summary>
        Buffer = 0x4,   /* The size of the host input/output buffer.  All hosts
                         * that implement the ResetSize, GetSize, or SetSize
                         * methods should support this flag. */
        /// <summary>
        /// The size of the host input/output window, if any.  Not all hosts
        /// will support this flag, even if they implement the
        /// <c>ResetSize</c>, <c>GetSize</c>, or <c>SetSize</c> methods.
        /// </summary>
        Window = 0x8,   /* The size of the host input/output window, if any.
                         * Not all hosts will support this flag, even if they
                         * implement the ResetSize, GetSize or SetSize methods.
                         */
        /// <summary>
        /// The current size (i.e. as opposed to the maximum size) of the
        /// host input/output buffer or window.  All hosts that implement
        /// the <c>ResetSize</c>, <c>GetSize</c>, or <c>SetSize</c> methods
        /// should support this flag.
        /// </summary>
        Current = 0x10, /* The current size (i.e. as opposed to the maximum
                         * size) of the host input/output buffer -OR- window.
                         * All hosts that implement the ResetSize, GetSize, or
                         * SetSize methods should support this flag. */
        /// <summary>
        /// The maximum size (i.e. as opposed to the current size) of the
        /// host input/output buffer or window.  Not all hosts will support
        /// this flag, even if they implement the <c>ResetSize</c>,
        /// <c>GetSize</c>, or <c>SetSize</c> methods.
        /// </summary>
        Maximum = 0x20, /* The maximum size (i.e. as opposed to the current
                         * size) of the host input/output buffer -OR- window.
                         * Not all hosts will support this flag, even if they
                         * implement the ResetSize, GetSize, or SetSize methods.
                         */

        /// <summary>
        /// Combination mask of <see cref="Buffer" /> and
        /// <see cref="Current" />.
        /// </summary>
        BufferCurrent = Buffer | Current,
        /// <summary>
        /// Combination mask of <see cref="Buffer" /> and
        /// <see cref="Maximum" />.
        /// </summary>
        BufferMaximum = Buffer | Maximum,

        /// <summary>
        /// Combination mask of <see cref="Window" /> and
        /// <see cref="Current" />.
        /// </summary>
        WindowCurrent = Window | Current,
        /// <summary>
        /// Combination mask of <see cref="Window" /> and
        /// <see cref="Maximum" />.
        /// </summary>
        WindowMaximum = Window | Maximum,

        /// <summary>
        /// The default host size type, which is equivalent to
        /// <see cref="Any" />.
        /// </summary>
        Default = Any
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration describes the capabilities and behavioral preferences
    /// of an interpreter host implementation.  The values are bit flags that
    /// may be combined to advertise which optional features a given host
    /// supports and how it should be treated by the rest of the system.
    /// </summary>
    [Flags()]
    [ObjectId("3496ebd1-6e02-44b0-8527-28ae79ea403b")]
    public enum HostFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,                                /* The host has no flags set. */
        /// <summary>
        /// Reserved as invalid; this value should not be used.
        /// </summary>
        Invalid = 0x1,                             /* Invalid, do not use. */
#if ISOLATED_PLUGINS
        /// <summary>
        /// The host is apparently running in an isolated application domain
        /// (i.e. it is not from the same application domain as the parent
        /// interpreter).
        /// </summary>
        Isolated = 0x2,                            /* The host is apparently running in an isolated
                                                    * application domain (i.e. it is not from the
                                                    * same application domain as the parent
                                                    * interpreter). */
#endif
        /// <summary>
        /// The host may be used by <c>DebugOps.Complain()</c>.
        /// </summary>
        Complain = 0x4,                            /* The host may be used by DebugOps.Complain(). */
        /// <summary>
        /// <c>DebugOps.Complain()</c> should be used to emit error messages
        /// from the internal console support subsystems.
        /// </summary>
        Verbose = 0x8,                             /* DebugOps.Complain() should be used to emit
                                                    * error messages from the internal console
                                                    * support subsystems. */
        /// <summary>
        /// The host may be used by <c>DebugOps.Write()</c>.
        /// </summary>
        Debug = 0x10,                              /* The host may be used by DebugOps.Write(). */
        /// <summary>
        /// The host is operating in test mode (i.e. additional diagnostic
        /// code may be executed during each method call).
        /// </summary>
        Test = 0x20,                               /* The host is operating in test mode (i.e.
                                                    * additional diagnostic code may be executed
                                                    * during each method call). */
        /// <summary>
        /// The host supports the <c>Prompt</c> method.
        /// </summary>
        Prompt = 0x40,                             /* The host supports the Prompt method. */
        /// <summary>
        /// The host wishes to display the prompt even when input has been
        /// redirected.
        /// </summary>
        ForcePrompt = 0x80,                        /* The host wishes to display the prompt even
                                                    * when input has been redirected. */
        /// <summary>
        /// The host supports the <c>DefaultTitle</c> property and its
        /// associated subsystem.
        /// </summary>
        Title = 0x100,                             /* The host supports the DefaultTitle property
                                                    * and its associated subsystem. */
        /// <summary>
        /// The host supports thread creation.
        /// </summary>
        Thread = 0x200,                            /* The host supports thread creation. */
        /// <summary>
        /// The host supports the <c>CanExit</c>, <c>CanForceExit</c>, and
        /// <c>Exiting</c> properties.
        /// </summary>
        Exit = 0x400,                              /* The host supports the CanExit, CanForceExit,
                                                    * and Exiting properties. */
        /// <summary>
        /// The host supports the queueing of work items.
        /// </summary>
        WorkItem = 0x800,                          /* The host supports the queueing of work items. */
        /// <summary>
        /// The host supports the <c>GetStream</c> method.
        /// </summary>
        Stream = 0x1000,                           /* The host supports the GetStream method. */
        /// <summary>
        /// The host supports the <c>GetData</c> method.
        /// </summary>
        Data = 0x2000,                             /* The host supports the GetData method. */
        /// <summary>
        /// The host supports the loading of profiles.
        /// </summary>
        Profile = 0x4000,                          /* The host supports the loading of profiles. */
        /// <summary>
        /// The host supports the <c>Sleep</c> method.
        /// </summary>
        Sleep = 0x8000,                            /* The host supports the Sleep method. */
        /// <summary>
        /// The host supports the <c>Yield</c> method.
        /// </summary>
        Yield = 0x10000,                           /* The host supports the Yield method. */
        /// <summary>
        /// The host supports the display of custom information via the
        /// <c>WriteCustomInfo</c> method.
        /// </summary>
        CustomInfo = 0x20000,                      /* The host supports the display of custom
                                                    * information via the WriteCustomInfo method. */
        /// <summary>
        /// The host has a resizable input/output area.
        /// </summary>
        Resizable = 0x40000,                       /* The host has a resizable input/output area. */
        /// <summary>
        /// The host has a high latency (i.e. it may be performing
        /// input/output over a poor quality remote connection).
        /// </summary>
        HighLatency = 0x80000,                     /* The host has a high latency (i.e. it may be
                                                    * performing input/output over a poor quality
                                                    * remote connection). */
        /// <summary>
        /// The host has low bandwidth (i.e. it may be performing
        /// input/output over a poor quality remote connection).
        /// </summary>
        LowBandwidth = 0x100000,                   /* The host has low bandwidth (i.e. it may be
                                                    * performing input/output over a poor quality
                                                    * remote connection). */
        /// <summary>
        /// The host input/output area only supports two colors.
        /// </summary>
        Monochrome = 0x200000,                     /* The host input/output area only supports two
                                                    * colors. */
        /// <summary>
        /// The host input/output area supports at least the "standard"
        /// colors (i.e. the ones from the <c>ConsoleColor</c>
        /// enumeration).
        /// </summary>
        Color = 0x400000,                          /* The host input/output area supports at least
                                                    * the "standard" colors (i.e. the ones from the
                                                    * ConsoleColor enumeration). */
        /// <summary>
        /// The host input/output area supports at least 24-bits of color.
        /// </summary>
        TrueColor = 0x800000,                      /* The host input/output area supports at least
                                                    * 24-bits of color. */
        /// <summary>
        /// The host input/output area supports reversing the foreground and
        /// background colors.
        /// </summary>
        ReversedColor = 0x1000000,                 /* The host input/output area supports reversing
                                                    * the foreground and background colors. */
        /// <summary>
        /// The host is text-based (i.e. hosted in a console window).
        /// </summary>
        Text = 0x2000000,                          /* The host is text-based (i.e. hosted in a
                                                    * console window). */
        /// <summary>
        /// The host is graphical (i.e. hosted in a window that may or may
        /// not look and behave like a console).
        /// </summary>
        Graphical = 0x4000000,                     /* The host is graphical (i.e. hosted in a window
                                                    * that may or may not look and behave like a
                                                    * console). */
        /// <summary>
        /// The host is "virtual", meaning that it may not have any
        /// interactive input/output area (i.e. all the input and output
        /// may be simulated).
        /// </summary>
        Virtual = 0x8000000,                       /* The host is "virtual", meaning that it may not
                                                    * have any interactive input/output area (i.e.
                                                    * all the input and output may be simulated). */
        /// <summary>
        /// The host supports getting and setting the size of its content
        /// area.  This does not necessarily have anything to do with the
        /// width and height of the host [window] itself.
        /// </summary>
        Sizing = 0x10000000,                       /* The host supports getting and setting the size
                                                    * of its content area.  This does not necessarily
                                                    * have anything to do with the width and height
                                                    * of the host [window] itself. */
        /// <summary>
        /// The host supports getting and setting positions within it.
        /// </summary>
        Positioning = 0x20000000,                  /* The host supports getting and setting positions
                                                    * within it. */
        /// <summary>
        /// The host supports recording commands, including interactive
        /// commands (i.e. "demo" mode).
        /// </summary>
        Recording = 0x40000000,                    /* The host supports recording commands, including
                                                    * interactive commands (i.e. "demo" mode). */
        /// <summary>
        /// The host supports playing back commands, including interactive
        /// commands (i.e. "demo" mode).
        /// </summary>
        Playback = 0x80000000,                     /* The host supports playing back commands,
                                                    * including interactive commands (i.e. "demo"
                                                    * mode). */
        /// <summary>
        /// There is no input/output area, or it is so small that it is
        /// unusable.
        /// </summary>
        ZeroSize = 0x100000000,                    /* There is no input/output area OR it is so small
                                                    * that is unusable. */
        /// <summary>
        /// The input/output area is minimal.  It may not be large enough to
        /// display all of the "vital" header information at once.
        /// </summary>
        MinimumSize = 0x200000000,                 /* The input/output area is minimal.  It may not
                                                    * be large enough to display all of the "vital"
                                                    * header information at once. */
        /// <summary>
        /// The input/output area is at least large enough to display all of
        /// the "vital" header information at once.
        /// </summary>
        CompactSize = 0x400000000,                 /* The input/output area is at least large enough
                                                    * to display all of the "vital" header information
                                                    * at once. */
        /// <summary>
        /// The input/output area is at least large enough to display all of
        /// the "standard" header information at once.
        /// </summary>
        FullSize = 0x800000000,                    /* The input/output area is at least large enough
                                                    * to display all of the "standard" header
                                                    * information at once. */
        /// <summary>
        /// The input/output area is at least large enough to display all of
        /// the "standard" header information at once.
        /// </summary>
        SuperFullSize = 0x1000000000,              /* The input/output area is at least large enough
                                                    * to display all of the "standard" header
                                                    * information at once. */
        /// <summary>
        /// The input/output area is at least large enough to display all of
        /// the "standard" header information and some of the "extra"
        /// header information at once.
        /// </summary>
        JumboSize = 0x2000000000,                  /* The input/output area is at least large enough
                                                    * to display all of the "standard" header
                                                    * information and some of the "extra"
                                                    * header information at once. */
        /// <summary>
        /// The input/output area is at least large enough to display all of
        /// the "standard" header information and all of the "extra"
        /// header information at once.
        /// </summary>
        SuperJumboSize = 0x4000000000,             /* The input/output area is at least large enough
                                                    * to display all of the "standard" header
                                                    * information and all of the "extra" header
                                                    * information at once. */
        /// <summary>
        /// The input/output area should be considered to have an infinite
        /// size.
        /// </summary>
        UnlimitedSize = 0x8000000000,              /* The input/output area should be considered to
                                                    * have an infinite size. */
        /// <summary>
        /// The input area supports multiple lines of input at the same
        /// time.
        /// </summary>
        MultipleLineInput = 0x10000000000,         /* The input area supports multiple lines of input
                                                    * at the same time. */
        /// <summary>
        /// Automatically flush from within <c>WriteCore</c> methods.
        /// </summary>
        AutoFlushHost = 0x20000000000,             /* Automatically flush from within WriteCore
                                                    * methods. */
        /// <summary>
        /// Automatically flush created stream writers.
        /// </summary>
        AutoFlushWriter = 0x40000000000,           /* Automatically flush created stream writers. */
        /// <summary>
        /// Automatically flush the host output stream after <c>[puts]</c>.
        /// </summary>
        AutoFlushOutput = 0x80000000000,           /* Automatically flush the host output stream
                                                    * after [puts]. */
        /// <summary>
        /// Automatically flush the host error stream after <c>[puts]</c>.
        /// </summary>
        AutoFlushError = 0x100000000000,           /* Automatically flush the host error stream
                                                    * after [puts]. */
        /// <summary>
        /// Adjust (i.e. "fine-tune") the foreground and background colors.
        /// </summary>
        AdjustColor = 0x200000000000,              /* Adjust (i.e. "fine-tune") the foreground and
                                                    * background colors. */
        /// <summary>
        /// The host supports the <c>QueryState</c> method.
        /// </summary>
        QueryState = 0x400000000000,               /* The host supports the QueryState method. */
        /// <summary>
        /// An exception was thrown when reading.
        /// </summary>
        ReadException = 0x800000000000,            /* An exception was thrown when reading. */
        /// <summary>
        /// An exception was thrown when writing.
        /// </summary>
        WriteException = 0x1000000000000,          /* An exception was thrown when writing. */
        /// <summary>
        /// Do not write a new line while the color is set to a non-default
        /// value.
        /// </summary>
        NoColorNewLine = 0x2000000000000,          /* Do not write a new line while the color is set
                                                    * to a non-default value. */
        /// <summary>
        /// Always make use of a foreground and/or background color when
        /// writing to the host, even when the caller uses the color
        /// "None".  Normally, for the "None" color, the originally saved
        /// color (i.e. foreground or background) will be used.
        /// </summary>
        SavedColorForNone = 0x4000000000000,       /* Always make use of a foreground and/or background
                                                    * color when writing to the host, even when the
                                                    * caller uses the color "None".  Normally, for the
                                                    * "None" color, the originally saved color (i.e.
                                                    * foreground or background) will be used. */
        /// <summary>
        /// After writing something in color, restore the initially saved
        /// colors instead of previously active colors.
        /// </summary>
        RestoreColorAfterWrite = 0x8000000000000,  /* After writing something in color, restore the
                                                    * initially saved colors instead of previously
                                                    * active colors. */
        /// <summary>
        /// When restoring colors, forcibly reset to those internally saved
        /// by the Console if either of the saved colors is not valid.
        /// </summary>
        ResetColorForRestore = 0x10000000000000,   /* When restoring colors, forcibly reset to those
                                                    * internally saved by the Console if either of
                                                    * the saved colors is not valid. */
        /// <summary>
        /// When setting colors, use reset instead if they would be set back
        /// to the saved foreground and background colors.
        /// </summary>
        MaybeResetColorForSet = 0x20000000000000,  /* When setting colors, use reset instead of they
                                                    * would be set back to the saved foreground and
                                                    * background colors. */
        /// <summary>
        /// Emit trace messages when the foreground and/or background colors
        /// were not actually changed.
        /// </summary>
        TraceColorNotChanged = 0x40000000000000,   /* Emit trace messages when the foreground and/or
                                                    * background colors were not actually changed. */
        /// <summary>
        /// Non-zero when error messages should be treated as though they
        /// are unrecoverable.
        /// </summary>
        TreatAsFatalError = 0x80000000000000,      /* Non-zero when error messages should be treated
                                                    * as though they are unrecoverable. */
        /// <summary>
        /// Disable setting of the foreground color.
        /// </summary>
        NoSetForegroundColor = 0x100000000000000,  /* Disable setting of the foreground color. */
        /// <summary>
        /// Disable setting of the background color.
        /// </summary>
        NoSetBackgroundColor = 0x200000000000000,  /* Disable setting of the background color. */
        /// <summary>
        /// Change "\r\n" line-endings to new-line "\n" only.
        /// </summary>
        NormalizeToNewLine = 0x400000000000000,    /* Change "\r\n" line-endings to new-line "\n"
                                                    * only. */
        /// <summary>
        /// If a line cannot be read from the host, treat that condition as
        /// end-of-file (no more input, so exit the interactive loop, etc).
        /// In most use cases, this flag should NOT be needed.
        /// </summary>
        TreatMissingLineAsEof = 0x800000000000000, /* If a line cannot be read from the host, treat
                                                    * that condition as end-of-file (no more input,
                                                    * so exit the interactive loop, etc).  In most
                                                    * use cases, this flag should NOT be needed. */
#if NATIVE && WINDOWS
        /// <summary>
        /// Use the <c>WriteConsoleW</c> Win32 API to write to the
        /// interpreter host.
        /// </summary>
        NativeWindows = 0x1000000000000000,        /* Use the WriteConsoleW Win32 API to write to
                                                    * the interpreter host. */
#endif

        /// <summary>
        /// Combination mask of <see cref="ReadException" /> and
        /// <see cref="WriteException" />.
        /// </summary>
        ExceptionMask = ReadException | WriteException,

        /// <summary>
        /// Combination mask of <see cref="Color" /> and
        /// <see cref="TrueColor" />.
        /// </summary>
        NonMonochromeMask = Color | TrueColor,

        /// <summary>
        /// Combination mask of <see cref="Monochrome" /> and
        /// <see cref="NonMonochromeMask" />.
        /// </summary>
        AllColors = Monochrome | NonMonochromeMask,

        /// <summary>
        /// Combination mask of all of the host input/output area size
        /// flags: <see cref="ZeroSize" />, <see cref="MinimumSize" />,
        /// <see cref="CompactSize" />, <see cref="FullSize" />,
        /// <see cref="SuperFullSize" />, <see cref="JumboSize" />,
        /// <see cref="SuperJumboSize" />, and
        /// <see cref="UnlimitedSize" />.
        /// </summary>
        AllSizes = ZeroSize | MinimumSize | CompactSize |
                   FullSize | SuperFullSize | JumboSize |
                   SuperJumboSize | UnlimitedSize,

        /// <summary>
        /// Reserved for future use; this value should not be used.
        /// </summary>
        Reserved = 0x8000000000000000 // NOTE: Reserved, do not use.
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration selects which interpreter host features should be
    /// exercised while the host is being tested.  The values are bit flags
    /// that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("9f0e7e9d-6801-4fd3-a48b-ef062d8b2b8f")]
    public enum HostTestFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,          /* The host has no flags set. */
        /// <summary>
        /// Reserved as invalid; this value should not be used.
        /// </summary>
        Invalid = 0x1,       /* Invalid, do not use. */
        /// <summary>
        /// Test the custom information method.
        /// </summary>
        CustomInfo = 0x2     /* Test the custom information method. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration selects which informational sections and prompts are
    /// written by the interpreter host when it displays its diagnostic header
    /// (e.g. for the script debugger).  The values are bit flags that may be
    /// combined; several composite values group the individual sections into
    /// convenient levels and masks.
    /// </summary>
    [Flags()]
    [ObjectId("d607b21a-e810-4d11-8a2a-f8a09aa178f7")]
    public enum HeaderFlags : ulong
    {
        /// <summary>
        /// No flags are set; nothing is displayed.
        /// </summary>
        None = 0x0,                    /* Displays nothing. */
        /// <summary>
        /// This value indicates that the header flags have not yet been
        /// explicitly set by the user.
        /// </summary>
        Invalid = 0x1,                 /* This value indicates that the header flags have not yet
                                        * been explicitly set by the user. */
        /// <summary>
        /// Display debugger "[Stop]" prompts.
        /// </summary>
        StopPrompt = 0x2,              /* Display debugger "[Stop]" prompts. */
        /// <summary>
        /// Display debugger "[Go]" prompts.
        /// </summary>
        GoPrompt = 0x4,                /* Display debugger "[Go]" prompts. */
        /// <summary>
        /// Displays the debugger banner (e.g. "TclTk Debugger").
        /// </summary>
        AnnouncementInfo = 0x8,        /* Displays debugger banner (e.g. "TclTk Debugger"). */

#if DEBUGGER
        /// <summary>
        /// Displays properties of the active debugger.
        /// </summary>
        DebuggerInfo = 0x10,           /* Displays properties of the active debugger. */
#endif

        /// <summary>
        /// Displays engine related properties of the active interpreter.
        /// </summary>
        EngineInfo = 0x20,             /* Displays engine related properties of the active
                                        * interpreter. */
        /// <summary>
        /// Displays control related properties of the active interpreter.
        /// </summary>
        ControlInfo = 0x40,            /* Displays control related properties of the active
                                        * interpreter. */
        /// <summary>
        /// Displays per-type entity counts for the active interpreter.
        /// </summary>
        EntityInfo = 0x80,             /* Displays per-type entity counts for the active
                                        * interpreter. */
        /// <summary>
        /// Displays native stack space information.
        /// </summary>
        StackInfo = 0x100,             /* Displays native stack space information. */
        /// <summary>
        /// Displays engine, substitution, notification, and other flags
        /// for the active interpreter.
        /// </summary>
        FlagInfo = 0x200,              /* Displays engine, substitution, notification, and other
                                        * flags for the active interpreter. */
        /// <summary>
        /// Displays the "reason" for breaking into the debugger.  This is
        /// typically only used for breakpoints.
        /// </summary>
        ArgumentInfo = 0x400,          /* Displays the "reason" for breaking into the debugger.
                                        * This is typically only used for breakpoints. */
        /// <summary>
        /// Displays the specified token information.  This is typically
        /// only used for token-based breakpoints.
        /// </summary>
        TokenInfo = 0x800,             /* Displays the specified token information.  This is
                                        * typically only used for token-based breakpoints. */
        /// <summary>
        /// Displays the specified variable trace information.  This is
        /// typically only used for variable watches and traces.
        /// </summary>
        TraceInfo = 0x1000,            /* Displays the specified variable trace information.
                                        * This is typically only used for variable watches and
                                        * traces. */
        /// <summary>
        /// Displays the state information for the active interpreter that
        /// does not fit neatly into the other categories.
        /// </summary>
        InterpreterInfo = 0x2000,      /* Displays the state information for the active
                                        * interpreter that does not fit neatly into the other
                                        * categories. */
        /// <summary>
        /// Displays the call stack (i.e. the "evaluation stack") for the
        /// active interpreter (current thread only).
        /// </summary>
        CallStack = 0x4000,            /* Displays the call stack (i.e. the "evaluation stack")
                                        * for the active interpreter (current thread only). */
        /// <summary>
        /// Displays the call stack (i.e. the "evaluation stack") for the
        /// active interpreter (current thread only) using the "boxed"
        /// style.
        /// </summary>
        CallStackInfo = 0x8000,        /* Displays the call stack (i.e. the "evaluation stack")
                                        * for the active interpreter (current thread only)
                                        * using the "boxed" style. */
        /// <summary>
        /// Displays properties of the specified variable.
        /// </summary>
        VariableInfo = 0x10000,        /* Displays properties of the specified variable. */
        /// <summary>
        /// Displays properties of the specified object.
        /// </summary>
        ObjectInfo = 0x20000,          /* Displays properties of the specified object. */
        /// <summary>
        /// Displays properties of the host for the active interpreter.
        /// </summary>
        HostInfo = 0x40000,            /* Displays properties of the host for the active
                                        * interpreter. */
        /// <summary>
        /// Displays test properties and statistics for the active
        /// interpreter.
        /// </summary>
        TestInfo = 0x80000,            /* Displays test properties and statistics for the
                                        * active interpreter. */
        /// <summary>
        /// Displays properties of the specified call frame.
        /// </summary>
        CallFrameInfo = 0x100000,      /* Displays properties of the specified call frame. */
        /// <summary>
        /// Displays the return code, string result, and error line number
        /// for the current and previous results, if any.
        /// </summary>
        ResultInfo = 0x200000,         /* Displays the return code, string result, and error
                                        * line number for the current and previous results,
                                        * if any. */

#if PREVIOUS_RESULT
        /// <summary>
        /// Displays the return code, string result, and error line number
        /// for the current and previous results, if any.
        /// </summary>
        PreviousResultInfo = 0x400000, /* Displays the return code, string result, and error
                                        * line number for the current and previous results,
                                        * if any. */
#endif

        /// <summary>
        /// Displays the previously stored "complaint" for the active
        /// interpreter, if any.
        /// </summary>
        ComplaintInfo = 0x800000,      /* Displays the previously stored "complaint" for the
                                        * active interpreter, if any. */

#if HISTORY
        /// <summary>
        /// Displays the command history for the active interpreter, if any
        /// has been recorded.
        /// </summary>
        HistoryInfo = 0x1000000,       /* Displays the command history for the active
                                        * interpreter, if any has been recorded. */
#endif

        /// <summary>
        /// Reserved for future use.
        /// </summary>
        OtherInfo = 0x2000000,         /* Reserved for future use. */
        /// <summary>
        /// Displays custom information provided by the underlying host
        /// implementation, if any.
        /// </summary>
        CustomInfo = 0x4000000,        /* Displays custom information provided by the
                                        * underlying host implementation, if any. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates that the header flags have been explicitly set by the
        /// user.
        /// </summary>
        User = 0x8000000,              /* Indicates that the header flags have been explicitly
                                        * set by the user. */
        /// <summary>
        /// Selectively displays information based on host style (i.e.
        /// "Compact", "Full", or "Jumbo") as returned by
        /// <c>GetFlags()</c>.
        /// </summary>
        AutoSize = 0x10000000,         /* selectively displays information based on host style
                                        * (i.e. "Compact", "Full", or "Jumbo") as returned by
                                        * GetFlags(). */
        /// <summary>
        /// If a call to <c>WriteBox</c> fails, retry it again inside of a
        /// new section.
        /// </summary>
        AutoRetry = 0x20000000,        /* If a call to WriteBox fails, retry it again inside
                                        * of a new section. */
        /// <summary>
        /// Display all the selected sections even if they contain no
        /// meaningful content.  Typically, this flag is only set when
        /// debugging <c>IHost</c> implementations.
        /// </summary>
        EmptySection = 0x40000000,     /* Display all the selected sections even if they
                                        * contain no meaningful content.  Typically, this flag
                                        * is only set when debugging IHost implementations. */
        /// <summary>
        /// Display all the content in the selected sections, even default
        /// and empty values.
        /// </summary>
        EmptyContent = 0x80000000,     /* Display all the content in the selected sections,
                                        * even default and empty values. */
        /// <summary>
        /// Display all the selected sections even if they contain only
        /// verbose content.  Typically, this flag is only set when
        /// debugging <c>IHost</c> implementations.
        /// </summary>
        VerboseSection = 0x100000000,  /* Display all the selected sections even if they
                                        * contain only verbose content.  Typically, this flag
                                        * is only set when debugging IHost implementations. */
        /// <summary>
        /// Display all the content in the selected sections, even verbose
        /// content.
        /// </summary>
        VerboseContent = 0x200000000,  /* Display all the content in the selected sections,
                                        * even verbose content. */
        /// <summary>
        /// The debugger is active in the parent interactive loop.
        /// </summary>
        Debug = 0x400000000,           /* The debugger is active in the parent interactive
                                        * loop. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Display all call frames, not just those accessible via scripts.
        /// </summary>
        CallStackAllFrames = 0x800000000,   /* Display all call frames, not just those accessible
                                             * via scripts. */
        /// <summary>
        /// Display debugger breakpoint information, if any.
        /// </summary>
        DebuggerBreakpoints = 0x1000000000, /* Display debugger breakpoint information, if any. */
        /// <summary>
        /// Display <c>[engine]</c> native integration information, if any.
        /// </summary>
        EngineNative = 0x2000000000,        /* Display [engine] native integration information, if
                                             * any. */
        /// <summary>
        /// Display interpreter host dimension information, if any.
        /// </summary>
        HostDimensions = 0x4000000000,      /* Display interpreter host dimension information, if
                                             * any. */
        /// <summary>
        /// Display interpreter host formatting information, if any.
        /// </summary>
        HostFormatting = 0x8000000000,      /* Display interpreter host formatting information, if
                                             * any. */
        /// <summary>
        /// Display interpreter host color information, if any.
        /// </summary>
        HostColors = 0x10000000000,         /* Display interpreter host color information, if any.
                                             */
        /// <summary>
        /// Display interpreter host named theme information, if any.
        /// </summary>
        HostNames = 0x20000000000,          /* Display interpreter host named theme information, if
                                             * any. */
        /// <summary>
        /// Display interpreter trace information instead of the specified
        /// trace information.
        /// </summary>
        TraceCached = 0x40000000000,        /* Display interpreter trace information instead of the
                                             * specified trace information. */
        /// <summary>
        /// Display variable link information, if any.
        /// </summary>
        VariableLinks = 0x80000000000,      /* Display variable link information, if any. */
        /// <summary>
        /// Display variable search information, if any.
        /// </summary>
        VariableSearches = 0x100000000000,  /* Display variable search information, if any. */
        /// <summary>
        /// Display variable array element information, if any.
        /// </summary>
        VariableElements = 0x200000000000,  /* Display variable array element information, if any.
                                             */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These sections are considered "vital" information when the
        //       script debugger calls the default host WriteHeader method.
        //
        /// <summary>
        /// Combination mask of the header sections considered "vital"
        /// information when the script debugger calls the default host
        /// <c>WriteHeader</c> method, namely the announcement, debugger,
        /// and result information sections.
        /// </summary>
        Level1 = AnnouncementInfo |
#if DEBUGGER
                 DebuggerInfo |
#endif
                 ResultInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These sections are considered useful information when the
        //       script debugger calls the default host WriteHeader method.
        //
        /// <summary>
        /// Combination mask of the header sections considered useful
        /// information when the script debugger calls the default host
        /// <c>WriteHeader</c> method, namely <see cref="ControlInfo" />
        /// and <see cref="OtherInfo" />.
        /// </summary>
        Level2 = ControlInfo | OtherInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These sections may not actually be written by the default
        //       host WriteHeader method (e.g. if the associated data is
        //       null or otherwise
        //       unavailable from the current context.
        //
        /// <summary>
        /// Combination mask of the header sections that may not actually
        /// be written by the default host <c>WriteHeader</c> method (e.g.
        /// if the associated data is null or otherwise unavailable from
        /// the current context); these include
        /// <see cref="ArgumentInfo" />, <see cref="TokenInfo" />,
        /// <see cref="TraceInfo" />, <see cref="VariableInfo" />,
        /// <see cref="ObjectInfo" />, <see cref="CallFrameInfo" />,
        /// <see cref="ComplaintInfo" />, and <see cref="CustomInfo" />.
        /// </summary>
        Level3 = ArgumentInfo | TokenInfo | TraceInfo |
                 VariableInfo | ObjectInfo | CallFrameInfo |
#if PREVIOUS_RESULT
                 PreviousResultInfo |
#endif
                 ComplaintInfo | CustomInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These sections are written by the default host WriteHeader
        //       method, unless the interpreter is null -OR- from a different
        //       application domain.
        //
        /// <summary>
        /// Combination mask of the header sections written by the default
        /// host <c>WriteHeader</c> method unless the interpreter is null
        /// or from a different application domain, namely
        /// <see cref="InterpreterInfo" /> and
        /// <see cref="CallStackInfo" />.
        /// </summary>
        Level4 = InterpreterInfo | CallStackInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These sections contain a lot of useful data; however, they
        //       are typically more useful for debugging TclTk itself rather
        //       than scripts.
        //
        /// <summary>
        /// Combination mask of the header sections that contain a lot of
        /// useful data but are typically more useful for debugging TclTk
        /// itself rather than scripts, namely <see cref="EngineInfo" />
        /// and <see cref="FlagInfo" />.
        /// </summary>
        Level5 = EngineInfo | FlagInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is specifically for use with the default host
        //       WriteHeader method when it is invoked due to the "#show"
        //       interactive command.
        //
        /// <summary>
        /// Combination mask, specifically for use with the default host
        /// <c>WriteHeader</c> method when it is invoked due to the
        /// "#show" interactive command, of <see cref="Level1" />,
        /// <see cref="Level2" />, <see cref="Level3" />,
        /// <see cref="Level4" />, and <see cref="Level5" />.
        /// </summary>
        Show = Level1 | Level2 | Level3 | Level4 | Level5,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="StopPrompt" /> and
        /// <see cref="GoPrompt" />.
        /// </summary>
        AllPrompt = StopPrompt | GoPrompt,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the individual informational header
        /// sections.
        /// </summary>
        AllInfo = AnnouncementInfo |
#if DEBUGGER
                  DebuggerInfo |
#endif
                  EngineInfo | ControlInfo | EntityInfo |
                  StackInfo | FlagInfo | ArgumentInfo |
                  TokenInfo | TraceInfo | InterpreterInfo |
                  CallStackInfo | VariableInfo |
                  ObjectInfo | HostInfo | TestInfo |
                  CallFrameInfo | ResultInfo |
#if PREVIOUS_RESULT
                  PreviousResultInfo |
#endif
                  ComplaintInfo |
#if HISTORY
                  HistoryInfo |
#endif
                  OtherInfo | CustomInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="EmptySection" /> and
        /// <see cref="EmptyContent" />.
        /// </summary>
        AllEmptyFlags = EmptySection | EmptyContent,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="VerboseSection" /> and
        /// <see cref="VerboseContent" />.
        /// </summary>
        AllVerboseFlags = VerboseSection | VerboseContent,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="HostDimensions" />,
        /// <see cref="HostFormatting" />, <see cref="HostColors" />,
        /// and <see cref="HostNames" />.
        /// </summary>
        AllHostFlags = HostDimensions | HostFormatting | HostColors |
                       HostNames,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AutoSize" /> and
        /// <see cref="AutoRetry" />.
        /// </summary>
        AllAutoFlags = AutoSize | AutoRetry,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="CallStackAllFrames" />,
        /// <see cref="DebuggerBreakpoints" />,
        /// <see cref="EngineNative" />, <see cref="AllHostFlags" />,
        /// <see cref="TraceCached" />, <see cref="VariableLinks" />,
        /// <see cref="VariableSearches" />, and
        /// <see cref="VariableElements" />.
        /// </summary>
        AllContentFlags = CallStackAllFrames | DebuggerBreakpoints | EngineNative |
                          AllHostFlags | TraceCached | VariableLinks |
                          VariableSearches | VariableElements,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="User" />,
        /// <see cref="AllAutoFlags" />, <see cref="AllEmptyFlags" />,
        /// <see cref="AllVerboseFlags" />, <see cref="Debug" />, and
        /// <see cref="AllContentFlags" />.
        /// </summary>
        AllFlags = User | AllAutoFlags | AllEmptyFlags | AllVerboseFlags | Debug |
                   AllContentFlags,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllPrompt" />,
        /// <see cref="CallStack" />, <see cref="AllInfo" />,
        /// <see cref="AllContentFlags" />, and
        /// <see cref="AllAutoFlags" />.
        /// </summary>
        All = AllPrompt | CallStack | AllInfo | AllContentFlags | AllAutoFlags,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="All" /> and
        /// <see cref="AllEmptyFlags" /> with <see cref="AutoSize" />
        /// cleared, for use when testing.
        /// </summary>
        AllForTest = (All | AllEmptyFlags) & ~AutoSize,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllPrompt" />,
        /// <see cref="ArgumentInfo" />, and <see cref="TokenInfo" />,
        /// suitable for display when a breakpoint is hit.
        /// </summary>
        Breakpoint = AllPrompt | ArgumentInfo | TokenInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllPrompt" />,
        /// <see cref="TraceInfo" />, and <see cref="VariableInfo" />,
        /// suitable for display when a variable watch is triggered.
        /// </summary>
        Watchpoint = AllPrompt | TraceInfo | VariableInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The maximum set of header flags, equivalent to
        /// <see cref="All" /> with <see cref="AutoSize" /> cleared and
        /// <see cref="AutoRetry" /> set.
        /// </summary>
        Maximum = All & ~AutoSize | AutoRetry,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Equivalent to <see cref="Maximum" /> with
        /// <see cref="CallStack" /> cleared.
        /// </summary>
        Full = Maximum & ~CallStack,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of header flags, a combination of
        /// <see cref="AllAutoFlags" />, <see cref="Level1" />, and
        /// <see cref="Level3" />.
        /// </summary>
        Default = AllAutoFlags | Level1 | Level3
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if HISTORY
    /// <summary>
    /// This enumeration describes how a command was added to the interpreter's
    /// command history.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("21773a14-5704-467e-8df8-9137d5197404")]
    public enum HistoryFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,        /* no flags. */
        /// <summary>
        /// Reserved as invalid; this value should not be used.
        /// </summary>
        Invalid = 0x1,     /* invalid, do not use. */
        /// <summary>
        /// The script command was added via the engine.
        /// </summary>
        Engine = 0x2,      /* script command added via Engine. */
        /// <summary>
        /// The interactive-only command was added via the REPL.
        /// </summary>
        Interactive = 0x4, /* interactive-only command added via REPL. */

        /// <summary>
        /// Combination mask of <see cref="Engine" /> and
        /// <see cref="Interactive" />.
        /// </summary>
        InstanceMask = Engine | Interactive
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && WINDOWS
    /// <summary>
    /// This enumeration mirrors the Win32 file sharing mode flags that control
    /// what concurrent access other openers are granted to a file.  The values
    /// are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("f70a8497-05dd-40a5-9b9d-93e2950aa095")]
    public enum FileShareMode /* COMPAT: Win32. */
    {
        /// <summary>
        /// No sharing is permitted; the file cannot be opened again until
        /// it is closed.
        /// </summary>
        FILE_SHARE_NONE = 0x0,
        /// <summary>
        /// Subsequent open operations that request read access will
        /// succeed.
        /// </summary>
        FILE_SHARE_READ = 0x1,
        /// <summary>
        /// Subsequent open operations that request write access will
        /// succeed.
        /// </summary>
        FILE_SHARE_WRITE = 0x2,
        /// <summary>
        /// Subsequent open operations that request delete access will
        /// succeed.
        /// </summary>
        FILE_SHARE_DELETE = 0x4,
        /// <summary>
        /// Combination mask of <see cref="FILE_SHARE_READ" /> and
        /// <see cref="FILE_SHARE_WRITE" />.
        /// </summary>
        FILE_SHARE_READ_WRITE = FILE_SHARE_READ |
                                FILE_SHARE_WRITE,
        /// <summary>
        /// Combination mask of <see cref="FILE_SHARE_READ" />,
        /// <see cref="FILE_SHARE_WRITE" />, and
        /// <see cref="FILE_SHARE_DELETE" />.
        /// </summary>
        FILE_SHARE_ALL = FILE_SHARE_READ |
                         FILE_SHARE_WRITE |
                         FILE_SHARE_DELETE
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration mirrors the Win32 creation disposition values that
    /// specify what action to take when opening a file, depending on whether
    /// or not it already exists.
    /// </summary>
    [ObjectId("ca9e0cd3-9bd3-47db-9952-79a3c132a53d")]
    public enum FileCreationDisposition /* COMPAT: Win32. */
    {
        /// <summary>
        /// No creation disposition is specified.
        /// </summary>
        NONE = 0,
        /// <summary>
        /// Create a new file, failing if it already exists.
        /// </summary>
        CREATE_NEW = 1,
        /// <summary>
        /// Create a new file, overwriting it if it already exists.
        /// </summary>
        CREATE_ALWAYS = 2,
        /// <summary>
        /// Open the file, failing if it does not already exist.
        /// </summary>
        OPEN_EXISTING = 3,
        /// <summary>
        /// Open the file, creating it if it does not already exist.
        /// </summary>
        OPEN_ALWAYS = 4,
        /// <summary>
        /// Open the file and truncate it to zero length, failing if it
        /// does not already exist.
        /// </summary>
        TRUNCATE_EXISTING = 5
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the Win32 file attribute, security quality of
    /// service, and file creation flag values understood by the native
    /// CreateFile API.  These are bit flags that may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("5e06f9b4-0a39-452e-ac2d-0e6448f0863e")]
    public enum FileFlagsAndAttributes /* COMPAT: Win32. */
    {
        //
        // File attributes used with CreateFile
        //

        /// <summary>
        /// No file attributes are set.
        /// </summary>
        FILE_ATTRIBUTE_NONE = 0x0,
        /// <summary>
        /// The file is read-only; applications can read it but cannot write to
        /// it or delete it.
        /// </summary>
        FILE_ATTRIBUTE_READONLY = 0x1,
        /// <summary>
        /// The file is hidden and is not included in an ordinary directory
        /// listing.
        /// </summary>
        FILE_ATTRIBUTE_HIDDEN = 0x2,
        /// <summary>
        /// The file is part of, or is used exclusively by, the operating
        /// system.
        /// </summary>
        FILE_ATTRIBUTE_SYSTEM = 0x4,
        /// <summary>
        /// The handle identifies a directory rather than an ordinary file.
        /// </summary>
        FILE_ATTRIBUTE_DIRECTORY = 0x10,
        /// <summary>
        /// The file is an archive file; applications typically use this flag to
        /// mark files for backup or removal.
        /// </summary>
        FILE_ATTRIBUTE_ARCHIVE = 0x20,
        /// <summary>
        /// The handle identifies a device rather than an ordinary file.
        /// </summary>
        FILE_ATTRIBUTE_DEVICE = 0x40,
        /// <summary>
        /// The file is a normal file that has no other attributes set; this
        /// value is only valid when used alone.
        /// </summary>
        FILE_ATTRIBUTE_NORMAL = 0x80,
        /// <summary>
        /// The file is being used for temporary storage and may be kept in
        /// memory rather than flushed to disk.
        /// </summary>
        FILE_ATTRIBUTE_TEMPORARY = 0x100,
        /// <summary>
        /// The file is a sparse file, whose unwritten regions do not consume
        /// physical disk space.
        /// </summary>
        FILE_ATTRIBUTE_SPARSE_FILE = 0x200,
        /// <summary>
        /// The file or directory has an associated reparse point, such as a
        /// symbolic link or junction.
        /// </summary>
        FILE_ATTRIBUTE_REPARSE_POINT = 0x400,
        /// <summary>
        /// The file or directory is compressed; its data is stored in a
        /// compressed form on disk.
        /// </summary>
        FILE_ATTRIBUTE_COMPRESSED = 0x800,
        /// <summary>
        /// The data of the file is not immediately available; its contents have
        /// been physically moved to offline storage.
        /// </summary>
        FILE_ATTRIBUTE_OFFLINE = 0x1000,
        /// <summary>
        /// The file or directory is excluded from the content indexing service.
        /// </summary>
        FILE_ATTRIBUTE_NOT_CONTENT_INDEXED = 0x2000,
        /// <summary>
        /// The file or directory is encrypted; for a file this means
        /// transparent per-file encryption, for a directory it means newly
        /// created files and subdirectories are encrypted by default.
        /// </summary>
        FILE_ATTRIBUTE_ENCRYPTED = 0x4000,

        //
        // Define the Security Quality of Service bits to be passed
        // into CreateFile
        //

        /// <summary>
        /// Impersonate a client at the anonymous impersonation level; no
        /// security quality of service bits are set.
        /// </summary>
        SECURITY_ANONYMOUS = 0x0,
        /// <summary>
        /// Impersonate a client at the identification impersonation level,
        /// allowing the server to obtain the client's identity only.
        /// </summary>
        SECURITY_IDENTIFICATION = 0x10000,
        /// <summary>
        /// Impersonate a client at the impersonation level, allowing the server
        /// to act on the client's behalf on the local system.
        /// </summary>
        SECURITY_IMPERSONATION = 0x20000,
        /// <summary>
        /// Impersonate a client at the delegation level, allowing the server to
        /// act on the client's behalf on both local and remote systems.
        /// </summary>
        SECURITY_DELEGATION = 0x30000,
        /// <summary>
        /// The security tracking mode is dynamic; the impersonation level
        /// follows changes in the client's security context.
        /// </summary>
        SECURITY_CONTEXT_TRACKING = 0x40000,
        /// <summary>
        /// Only the enabled aspects of the client's security context are
        /// available to the server.
        /// </summary>
        SECURITY_EFFECTIVE_ONLY = 0x80000,
        /// <summary>
        /// Indicates that security quality of service information is present in
        /// the request.
        /// </summary>
        SECURITY_SQOS_PRESENT = 0x100000,

        //
        // File creation flags must start at the high end since they
        // are combined with the attributes
        //

        /// <summary>
        /// The file being opened is the first instance of a named pipe.
        /// </summary>
        FILE_FLAG_FIRST_PIPE_INSTANCE = 0x80000,
        /// <summary>
        /// Open the file without recalling its data from remote (offline)
        /// storage.
        /// </summary>
        FILE_FLAG_OPEN_NO_RECALL = 0x100000,
        /// <summary>
        /// Open the reparse point itself rather than following it to its
        /// target.
        /// </summary>
        FILE_FLAG_OPEN_REPARSE_POINT = 0x200000,
        /// <summary>
        /// Access the file using POSIX semantics, including case-sensitive file
        /// name matching.
        /// </summary>
        FILE_FLAG_POSIX_SEMANTICS = 0x1000000,
        /// <summary>
        /// Open or create the file with backup or restore semantics, bypassing
        /// normal file security checks for privileged callers.
        /// </summary>
        FILE_FLAG_BACKUP_SEMANTICS = 0x2000000,
        /// <summary>
        /// The file is to be deleted automatically once its last open handle is
        /// closed.
        /// </summary>
        FILE_FLAG_DELETE_ON_CLOSE = 0x4000000,
        /// <summary>
        /// The file is to be accessed sequentially from beginning to end,
        /// allowing the system to optimize caching accordingly.
        /// </summary>
        FILE_FLAG_SEQUENTIAL_SCAN = 0x8000000,
        /// <summary>
        /// The file is to be accessed randomly, allowing the system to optimize
        /// caching accordingly.
        /// </summary>
        FILE_FLAG_RANDOM_ACCESS = 0x10000000,
        /// <summary>
        /// The file is to be opened with no system caching of its data;
        /// reads and writes must satisfy strict alignment requirements.
        /// </summary>
        FILE_FLAG_NO_BUFFERING = 0x20000000,
        /// <summary>
        /// The file is to be opened for asynchronous (overlapped) input and
        /// output.
        /// </summary>
        FILE_FLAG_OVERLAPPED = 0x40000000,
        /// <summary>
        /// Write operations bypass any intermediate cache and go directly to
        /// disk.
        /// </summary>
        FILE_FLAG_WRITE_THROUGH = unchecked((int)0x80000000)
    }
#endif

