#if NATIVE && (WINDOWS || UNIX)
    /// <summary>
    /// This enumeration defines the POSIX-style file mode bits used to describe
    /// the type of a file and its permission settings.  These are bit flags
    /// that may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("7f34cb91-54db-4bb1-9d11-63afd74bedb7")]
    public enum FileStatusModes : uint /* COMPAT: POSIX (?), Linux. */
    {
        /// <summary>
        /// No file mode bits are set.
        /// </summary>
        S_INONE = 0x0000,

        /// <summary>
        /// The execute (or, for a directory, search) permission bit.
        /// </summary>
        S_IEXEC = 0x0040,
        /// <summary>
        /// The write permission bit.
        /// </summary>
        S_IWRITE = 0x0080,
        /// <summary>
        /// The read permission bit.
        /// </summary>
        S_IREAD = 0x0100,

        /// <summary>
        /// The file type bit indicating a directory.
        /// </summary>
        S_IFDIR = 0x4000,
        /// <summary>
        /// The file type bit indicating an ordinary (regular) file.
        /// </summary>
        S_IFREG = 0x8000,
        /// <summary>
        /// The file type bit indicating a symbolic link.
        /// </summary>
        S_IFLNK = 0xA000,

        /// <summary>
        /// The bit mask used to extract the file type portion of the mode.
        /// </summary>
        S_IFMT = 0xF000,

        /// <summary>
        /// Combination mask of the recognized "normal" file types,
        /// <see cref="S_IFDIR" />, <see cref="S_IFREG" />, and
        /// <see cref="S_IFLNK" />.
        /// </summary>
        S_IFNRML = S_IFDIR | S_IFREG | S_IFLNK,

        /// <summary>
        /// Combination mask of all permission bits, <see cref="S_IREAD" />,
        /// <see cref="S_IWRITE" />, and <see cref="S_IEXEC" />.
        /// </summary>
        S_IRWX = S_IREAD | S_IWRITE | S_IEXEC
    }
#endif

