    /// <summary>
    /// This enumeration defines the process exit code values that may be
    /// returned by the TclTk shell and related host applications.
    /// </summary>
    [ObjectId("687b2526-63ad-4367-8a80-40441fe9396d")]
    public enum ExitCode
    {
        /// <summary>
        /// An unknown or uninitialized exit code; reserved for internal use
        /// only.
        /// </summary>
        Unknown = -1,  /* For internal use only. */
        /// <summary>
        /// The process completed successfully.
        /// </summary>
        Success = 0,   /* COMPAT: Unix. */
        /// <summary>
        /// The process terminated with a generic failure.
        /// </summary>
        Failure = 1,   /* COMPAT: Unix. */
        /// <summary>
        /// The process terminated due to an unhandled exception.
        /// </summary>
        Exception = 2, /* COMPAT: ??? */
        /// <summary>
        /// The process terminated with a fatal error.
        /// </summary>
        Fatal = 255,   /* COMPAT: Win32? */
        /// <summary>
        /// A distinctive sentinel exit code intended for use by scripts on
        /// demand.
        /// </summary>
        Demand = unchecked((int)0xDEADC0DE),  /* For script use only. */
        /// <summary>
        /// A distinctive fail-safe sentinel exit code used when the process
        /// must terminate abnormally.
        /// </summary>
        FailSafe = unchecked((int)0xDEADDEAD) /* Extra dead. */
    }

