    /// <summary>
    /// This enumeration defines flags that control how data is located,
    /// retrieved, and verified by the GetData family of methods.  These are bit
    /// flags that may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("6c55d49e-b4c3-4159-a608-214802e850fb")]
    public enum DataFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Invalid; this value is reserved and should not be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The data is to be treated as raw bytes.
        /// </summary>
        Bytes = 0x2,
        /// <summary>
        /// The data is to be treated as text.
        /// </summary>
        Text = 0x4,

        /// <summary>
        /// Emit trace diagnostics from within the GetData related method(s).
        /// </summary>
        Trace = 0x10,   /* emit trace diagnostics from within the
                         * GetData related method(s). */
        /// <summary>
        /// Return only normal error information if some data cannot be found.
        /// </summary>
        Quiet = 0x20,   /* return normal error information if some
                         * data cannot be found. */
        /// <summary>
        /// Return maximum error information if some data cannot be found.
        /// </summary>
        Verbose = 0x40, /* return maximum error information if some
                         * data cannot be found. */

        /// <summary>
        /// Only data that has been verified should be considered.
        /// </summary>
        VerifiedOnly = 0x80,
        /// <summary>
        /// Only data from a trusted source should be considered.
        /// </summary>
        TrustedOnly = 0x100,

        /// <summary>
        /// The requested name is a reserved name.
        /// </summary>
        ReservedName = 0x200,
        /// <summary>
        /// The requested name is a reserved name to be matched on its tail
        /// (last component) only.
        /// </summary>
        ReservedTailOnlyName = 0x400,
        /// <summary>
        /// The requested name is a reserved absolute name.
        /// </summary>
        ReservedAbsoluteName = 0x800,

        /// <summary>
        /// Do not attempt to satisfy the request using a stream.
        /// </summary>
        NoStream = 0x1000,
        /// <summary>
        /// Do not attempt to satisfy the request using a string.
        /// </summary>
        NoString = 0x2000,

        /// <summary>
        /// Do not attempt to satisfy the request using a plugin-provided
        /// stream.
        /// </summary>
        NoPluginStream = 0x100000,
        /// <summary>
        /// Do not attempt to satisfy the request using a plugin-provided
        /// string.
        /// </summary>
        NoPluginString = 0x200000,

        /// <summary>
        /// Search parent scopes when looking for the requested data.
        /// </summary>
        SearchParents = 0x400000,
        /// <summary>
        /// Do not search parent scopes when looking for the requested data.
        /// </summary>
        NoSearchParents = 0x800000,

        /// <summary>
        /// Do not attempt to satisfy the request using a resource manager
        /// stream.
        /// </summary>
        NoResourceManagerStream = 0x10000000,
        /// <summary>
        /// Do not attempt to satisfy the request using a resource manager
        /// string.
        /// </summary>
        NoResourceManagerString = 0x20000000,

        /// <summary>
        /// Do not attempt to satisfy the request using an assembly manifest
        /// stream.
        /// </summary>
        NoAssemblyManifestStream = 0x1000000000,
        /// <summary>
        /// Do not attempt to satisfy the request using an assembly manifest
        /// string.
        /// </summary>
        NoAssemblyManifestString = 0x2000000000,

        /// <summary>
        /// Combination mask suitable for fetching script data; combination of
        /// <see cref="Text" /> and <see cref="NoResourceManagerStream" />.
        /// </summary>
        Script = Text | NoResourceManagerStream,
        /// <summary>
        /// Combination mask suitable for fetching plugin data; combination of
        /// <see cref="Bytes" /> and <see cref="NoString" />.
        /// </summary>
        Plugin = Bytes | NoString,

        /// <summary>
        /// Combination mask of the flags considered safe to expose, combining
        /// <see cref="Trace" />, <see cref="Quiet" />, and
        /// <see cref="Verbose" />.
        /// </summary>
        SafeMask = Trace| Quiet| Verbose,

        /// <summary>
        /// The default data flags, equivalent to <see cref="None" />.
        /// </summary>
        Default = None
    }

