    /// <summary>
    /// This enumeration defines flags that control how the engine and core host
    /// locate, load, and validate scripts (including library scripts) across
    /// the file system, resources, plugins, and resource managers.  These are
    /// bit flags that may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("9eb389ed-2d2a-4be1-823f-17717116e9cf")]
    public enum ScriptFlags : ulong
    {
        /// <summary>
        /// No special flags are set.
        /// </summary>
        None = 0x0,                                        /* no special flags. */
        /// <summary>
        /// Invalid; this value is reserved and should not be used.
        /// </summary>
        Invalid = 0x1,                                     /* invalid, do not use. */
        /// <summary>
        /// The engine should also use the default flags when searching for a
        /// script that cannot be found on the file system.
        /// </summary>
        UseDefault = 0x2,                                  /* the engine should [also] use the default
                                                            * flags when searching for a script that
                                                            * cannot be found on the file system. */
        /// <summary>
        /// Reserved for system use; this value should not be used.
        /// </summary>
        System = 0x4,                                      /* reserved, do not use */
        /// <summary>
        /// The script is part of the core language distribution.
        /// </summary>
        Core = 0x8,                                        /* script is part of the core language
                                                            * distribution. */
        /// <summary>
        /// The script is only used by the interactive shell.
        /// </summary>
        Interactive = 0x10,                                /* script is only used by the interactive
                                                            * shell. */
        /// <summary>
        /// The script is part of a user package.
        /// </summary>
        Package = 0x20,                                    /* script is part of a user package. */
        /// <summary>
        /// The script is part of a user application.
        /// </summary>
        Application = 0x40,                                /* script is part of a user application. */
        /// <summary>
        /// The script is part of a vendor package.
        /// </summary>
        Vendor = 0x80,                                     /* script is part of a vendor package. */
        /// <summary>
        /// The script is user customizable.
        /// </summary>
        User = 0x100,                                      /* script is user customizable. */
        /// <summary>
        /// The name should be checked verbatim if it is a fully qualified path.
        /// </summary>
        SpecificPath = 0x200,                              /* the name should be checked verbatim if it is
                                                            * a fully qualified path. */
        /// <summary>
        /// Allow script location resolution via the tcltk_paths script
        /// variable.
        /// </summary>
        Mapped = 0x400,                                    /* allow script location resolution via the
                                                            * tcltk_paths script variable. */
        /// <summary>
        /// Allow script location resolution via the auto_source_path script
        /// variable.
        /// </summary>
        AutoSourcePath = 0x800,                            /* allow script location resolution via the
                                                            * auto_source_path script variable. */
        /// <summary>
        /// The script has library semantics, including searching the package
        /// directory and the auto_path to find it.
        /// </summary>
        Library = 0x1000,                                  /* script has library semantics, including
                                                            * searching the package directory and the
                                                            * auto_path to find it. */
        /// <summary>
        /// The script is really a data file and not strictly a script.
        /// </summary>
        Data = 0x2000,                                     /* script is really a data file (not strictly
                                                            * a script). */
        /// <summary>
        /// The script is required for proper operation.
        /// </summary>
        Required = 0x4000,                                 /* script is required for proper operation. */
        /// <summary>
        /// The script is not required for proper operation.
        /// </summary>
        Optional = 0x8000,                                 /* script not required for proper operation. */
        /// <summary>
        /// The script resides in the specified file.
        /// </summary>
        File = 0x10000,                                    /* script resides in the specified file. */
        /// <summary>
        /// Check the file system before using the IHost.GetData method for
        /// library scripts.
        /// </summary>
        PreferFileSystem = 0x20000,                        /* check the file system before using the
                                                            * IHost.GetData method for library scripts. */
        /// <summary>
        /// Do not try to find the script along the auto_path.
        /// </summary>
        NoAutoPath = 0x40000,                              /* do not try to find the script along the
                                                            * auto_path. */
        /// <summary>
        /// The IHost.GetData method should not be used for this request.
        /// </summary>
        NoHost = 0x80000,                                  /* the IHost.GetData method should not be used
                                                            * for this request. */
        /// <summary>
        /// The core host should not look for the script on the native file
        /// system.
        /// </summary>
        NoFileSystem = 0x100000,                           /* the core host should not look for the script
                                                            * on the native file system. */
        /// <summary>
        /// The core host should not look for the script via resources, embedded
        /// or otherwise.
        /// </summary>
        NoResources = 0x200000,                            /* the core host should not look for the script
                                                            * via resources, embedded or otherwise. */
        /// <summary>
        /// The core host should not look for the script via plugin resource
        /// strings.
        /// </summary>
        NoPlugins = 0x400000,                              /* the core host should not look for the script
                                                            * via plugin resource strings. */
        /// <summary>
        /// The core host should not look for the script via the interpreter or
        /// host resource managers.
        /// </summary>
        NoResourceManager = 0x800000,                      /* the core host should not look for the script
                                                            * via the interpreter or host resource managers.
                                                            */
#if XML
        /// <summary>
        /// The core host should not attempt to interpret the file as an XML
        /// script.
        /// </summary>
        NoXml = 0x1000000,                                 /* the core host should not attempt to interpret
                                                            * the file as an XML script. */
#endif
        /// <summary>
        /// The core host should skip using the qualified name as the basis for
        /// a resource name.
        /// </summary>
        SkipQualified = 0x2000000,                         /* the core host should skip using the qualfied
                                                            * name as the basis for a resource name. */
        /// <summary>
        /// The core host should skip using the non-qualified name as the basis
        /// for a resource name.
        /// </summary>
        SkipNonQualified = 0x4000000,                      /* the core host should skip using the
                                                            * non-qualified name as the basis for a resource
                                                            * name. */
        /// <summary>
        /// The core host should skip using the relative name as the basis for a
        /// resource name.
        /// </summary>
        SkipRelative = 0x8000000,                          /* the core host should skip using the relative
                                                            * name as the basis for a resource name. */
        /// <summary>
        /// The core host should skip treating the name as the raw resource name
        /// itself during the search.
        /// </summary>
        SkipRawName = 0x10000000,                          /* the core host should skip treating the name
                                                            * as the raw resource name itself during the
                                                            * search. */
        /// <summary>
        /// The core host should skip treating the name as a file name during
        /// the search.
        /// </summary>
        SkipFileName = 0x20000000,                         /* the core host should skip treating the name
                                                            * as a file name during the search. */
        /// <summary>
        /// The core host should skip file names that ignore the package type
        /// during the search.
        /// </summary>
        SkipFileNameOnly = 0x40000000,                     /* the core host should skip file names that
                                                            * ignore the package type during the search. */
        /// <summary>
        /// The core host should skip file names that do not ignore the package
        /// type during the search.
        /// </summary>
        SkipNonFileNameOnly = 0x80000000,                  /* the core host should skip file names that
                                                            * do not ignore the package type during the
                                                            * search. */
        /// <summary>
        /// The core host should skip fixing up the "Library" path portion to
        /// "lib" during the search.
        /// </summary>
        SkipLibraryToLib = 0x100000000,                    /* the core host should skip fixing up the
                                                            * "Library" path portion to "lib" during the
                                                            * search. */
        /// <summary>
        /// The core host should skip fixing up the "Tests" path portion to
        /// "lib/Tests" during the search.
        /// </summary>
        SkipTestsToLib = 0x200000000,                      /* the core host should skip fixing up the
                                                            * "Tests" path portion to "lib/Tests" during
                                                            * the search. */
        /// <summary>
        /// Null must be returned if the script file is not found on the file
        /// system.
        /// </summary>
        NullOnNotFound = 0x400000000,                      /* null must be returned if the script file is
                                                            * not found on the file system */
        /// <summary>
        /// Forbid null and empty script values even upon success, unless they
        /// are flagged as optional and not flagged as required.
        /// </summary>
        ErrorOnEmpty = 0x800000000,                        /* forbid null and empty script values even upon
                                                            * success unless they are flagged as optional
                                                            * and NOT flagged as required. */
        /// <summary>
        /// Unexpected exceptions should cause the remainder of the script
        /// search to be canceled and an error to be returned.
        /// </summary>
        FailOnException = 0x1000000000,                    /* unexpected exceptions should cause the
                                                            * remainder of the script search to be canceled
                                                            * and an error to be returned. */
        /// <summary>
        /// Unexpected exceptions should cause the remainder of the script
        /// search to be canceled.
        /// </summary>
        StopOnException = 0x2000000000,                    /* unexpected exceptions should cause the
                                                            * remainder of the script search to be canceled.
                                                            */
        /// <summary>
        /// Unexpected errors should cause the remainder of the script search to
        /// be canceled and an error to be returned.
        /// </summary>
        FailOnError = 0x4000000000,                        /* unexpected errors should cause the remainder
                                                            * of the script search to be canceled and an
                                                            * error to be returned. */
        /// <summary>
        /// Ignore the canRetry value returned by the script engine for reading
        /// script streams, etc.
        /// </summary>
        IgnoreCanRetry = 0x8000000000,                     /* ignore the canRetry value returned by the
                                                            * script engine for reading script streams, etc. */
        /// <summary>
        /// Unexpected errors should cause the remainder of the script search to
        /// be canceled.
        /// </summary>
        StopOnError = 0x10000000000,                       /* unexpected errors should cause the remainder
                                                            * of the script search to be canceled. */
        /// <summary>
        /// Prefer file names that are longer.
        /// </summary>
        PreferDeepFileNames = 0x20000000000,               /* prefer file names that are longer. */
        /// <summary>
        /// Prefer resource names that are longer.
        /// </summary>
        PreferDeepResourceNames = 0x40000000000,           /* prefer resource names that are longer. */
        /// <summary>
        /// When searching for a script on the file system, consider candidate
        /// locations that represent a directory.
        /// </summary>
        SearchDirectory = 0x80000000000,                   /* when searching for a script on the file
                                                            * system, consider candidate locations that
                                                            * represent a directory. */
        /// <summary>
        /// When searching for a script on the file system, consider candidate
        /// locations that represent a file.
        /// </summary>
        SearchFile = 0x100000000000,                       /* when searching for a script on the file
                                                            * system, consider candidate locations that
                                                            * represent a file. */
        /// <summary>
        /// The file system should be disallowed when searching for the core
        /// script library.
        /// </summary>
        NoLibraryFile = 0x200000000000,                    /* the file system should be disallowed when
                                                            * searching for the core script library. */
        /// <summary>
        /// The IClientData has been filled in with auxiliary data, such as the
        /// associated plugin file name.
        /// </summary>
        ClientData = 0x400000000000,                       /* the IClientData has been filled in with
                                                            * auxiliary data (e.g. the associated plugin
                                                            * file name). */
        /// <summary>
        /// The script is part of the core binary plugin loader library package.
        /// </summary>
        LoaderPackage = 0x800000000000,                    /* the script is part of the core binary
                                                            * plugin loader library package. */
        /// <summary>
        /// The script is part of the core script library package.
        /// </summary>
        LibraryPackage = 0x1000000000000,                  /* the script is part of the core script
                                                            * library package. */
        /// <summary>
        /// The script is part of the core test library package.
        /// </summary>
        TestPackage = 0x2000000000000,                     /* the script is part of the core test
                                                            * library package. */
        /// <summary>
        /// The script is part of the core kit library package.
        /// </summary>
        KitPackage = 0x4000000000000,                      /* the script is part of the core kit
                                                            * library package. */
        /// <summary>
        /// The script is part of the core script library, test, or kit
        /// packages.
        /// </summary>
        AutomaticPackage = 0x8000000000000,                /* the script is part of the core script
                                                            * library, test, or kit packages. */
        /// <summary>
        /// Avoid checking resource names that do not fit within the suffix of
        /// the specified name.
        /// </summary>
        FilterOnSuffixMatch = 0x10000000000000,            /* avoid checking resource names that do not
                                                            * fit within the suffix of the specified
                                                            * name. */
        /// <summary>
        /// Disable policy execution when looking up the script.
        /// </summary>
        NoPolicy = 0x20000000000000,                       /* Disable policy execution when looking up
                                                            * the script? */
        /// <summary>
        /// The core host should not look for the script via manifest assembly
        /// resources.
        /// </summary>
        NoAssemblyManifest = 0x40000000000000,             /* the core host should not look for the
                                                            * script via manifest assembly resources.
                                                            */
        /// <summary>
        /// Do not check the file system for just the file name portion of the
        /// requested library script.
        /// </summary>
        NoLibraryFileNameOnly = 0x80000000000000,          /* do not check the file system for just the
                                                            * file name portion of the requested library
                                                            * script. */
        /// <summary>
        /// Skip calling the IPlugin.GetString method for the plugin-name
        /// decorated resource name.
        /// </summary>
        NoPluginResourceName = 0x100000000000000,          /* skip calling the IPlugin.GetString method
                                                            * for the plugin-name decorated resource
                                                            * name. */
        /// <summary>
        /// Skip calling the IPlugin.GetString method for the raw, undecorated
        /// resource name.
        /// </summary>
        NoRawResourceName = 0x200000000000000,             /* skip calling the IPlugin.GetString method
                                                            * for the raw, undecorated resource name. */
        /// <summary>
        /// The core host should not look for the script via the host resource
        /// manager.
        /// </summary>
        NoHostResourceManager = 0x400000000000000,         /* the core host should not look for the script
                                                            * via the host resource manager.
                                                            */
        /// <summary>
        /// The core host should not look for the script via the application
        /// resource manager.
        /// </summary>
        NoApplicationResourceManager = 0x800000000000000,  /* the core host should not look for the script
                                                            * via the application resource manager.
                                                            */
        /// <summary>
        /// The core host should not look for the script via the core library
        /// resource manager.
        /// </summary>
        NoLibraryResourceManager = 0x1000000000000000,     /* the core host should not look for the script
                                                            * via the core library resource manager.
                                                            */
        /// <summary>
        /// The core host should not look for the script via the core packages
        /// resource manager.
        /// </summary>
        NoPackagesResourceManager = 0x2000000000000000,    /* the core host should not look for the script
                                                            * via the core packages resource manager.
                                                            */
        /// <summary>
        /// The core host should not look for the script via the core kit
        /// resource manager.
        /// </summary>
        NoKitResourceManager = 0x4000000000000000,         /* the core host should not look for the script
                                                            * via the core kit resource manager.
                                                            */
        /// <summary>
        /// The script will be evaluated asynchronously from the main thread for
        /// the interpreter.
        /// </summary>
        Asynchronous = 0x8000000000000000,                 /* the script will be evaluated asynchronously
                                                            * from the main thread for the interpreter. */

        //
        // HACK: Do not use this, it is for internal core library use
        //       by the ViaGetScriptFlag method family only.
        //
        /// <summary>
        /// Reserved for internal core library use by the ViaGetScriptFlag
        /// method family only; combination of <see cref="Invalid" /> and
        /// <see cref="System" />.  Do not use.
        /// </summary>
        ViaGetScript = Invalid | System,

        //
        // NOTE: When using resource names, forbid all names that are
        //       not an exact match.
        //
        /// <summary>
        /// Combination mask that forbids all resource names that are not an
        /// exact match, combining <see cref="SkipLibraryToLib" />,
        /// <see cref="SkipTestsToLib" />, <see cref="SkipFileName" />,
        /// <see cref="SkipRelative" />, and <see cref="SkipNonQualified" />.
        /// </summary>
        ExactNameOnly = SkipLibraryToLib | SkipTestsToLib | SkipFileName |
                        SkipRelative | SkipNonQualified,

        //
        // NOTE: Only consider library resources from the core library
        //       assembly.
        //
        /// <summary>
        /// Combination mask that considers library resources only from the core
        /// library assembly, combining <see cref="NoFileSystem" />,
        /// <see cref="NoPlugins" />, <see cref="NoHostResourceManager" />,
        /// <see cref="NoApplicationResourceManager" />,
        /// <see cref="NoLibraryFile" />, <see cref="NoAssemblyManifest" />, and
        /// <see cref="NoLibraryFileNameOnly" />.
        /// </summary>
        CoreAssemblyOnly = NoFileSystem | NoPlugins | NoHostResourceManager |
                           NoApplicationResourceManager | NoLibraryFile |
                           NoAssemblyManifest | NoLibraryFileNameOnly,

        //
        // NOTE: For plugin binaries, do not consult the file system -AND-
        //       only allow exact name matching.
        //
        /// <summary>
        /// Combination mask for plugin binaries that avoids the file system and
        /// allows only exact name matching, combining
        /// <see cref="NoFileSystem" /> and <see cref="ExactNameOnly" />.
        /// </summary>
        PluginBinaryOnly = NoFileSystem | ExactNameOnly,

        //
        // NOTE: If the "locked down" build configuration is in use, force
        //       all scripts to be fetched from the core library assembly.
        //
#if ENTERPRISE_LOCKDOWN
        /// <summary>
        /// In the "locked down" build configuration, forces all scripts to be
        /// fetched from the core library assembly; equivalent to
        /// <see cref="CoreAssemblyOnly" />.
        /// </summary>
        MaybeCoreAssemblyOnly = CoreAssemblyOnly,
#else
        //
        // WARNING: This value cannot be the same as "None".  Do not modify
        //          or various things may break.
        //
        /// <summary>
        /// Outside the "locked down" build configuration this value carries no
        /// core-assembly restriction; it is mapped to <see cref="Invalid" /> so
        /// that it cannot be equal to <see cref="None" />.
        /// </summary>
        MaybeCoreAssemblyOnly = Invalid,
#endif

        //
        // NOTE: Even if this module has been built with an embedded
        //       script library, we still want to allow the application
        //       (or the user) to override the various embedded library
        //       scripts by placing the correct file(s) in the proper
        //       location(s) on the native file system.  This flag has
        //       no effect unless the "Library" flag is also specified.
        //
#if EMBEDDED_LIBRARY
        /// <summary>
        /// When built with an embedded script library, prefers the file system
        /// so the application or user may override embedded library scripts;
        /// combination of <see cref="PreferFileSystem" /> and
        /// <see cref="AutomaticPackage" />.
        /// </summary>
        EmbeddedLibrary = PreferFileSystem | AutomaticPackage,
#else
        /// <summary>
        /// When not built with an embedded script library, this value is
        /// equivalent to <see cref="AutomaticPackage" />.
        /// </summary>
        EmbeddedLibrary = AutomaticPackage,
#endif

        /// <summary>
        /// Combination mask of the search location flags, combining
        /// <see cref="SpecificPath" />, <see cref="SearchDirectory" />, and
        /// <see cref="SearchFile" />.
        /// </summary>
        SearchAny = SpecificPath | SearchDirectory | SearchFile,

        /// <summary>
        /// Combination mask describing a required file, combining
        /// <see cref="Required" />, <see cref="NullOnNotFound" />, and
        /// <see cref="SearchAny" />.
        /// </summary>
        RequiredFile = Required | NullOnNotFound | SearchAny,
        /// <summary>
        /// Combination mask describing an optional file, combining
        /// <see cref="Optional" />, <see cref="NullOnNotFound" />, and
        /// <see cref="SearchAny" />.
        /// </summary>
        OptionalFile = Optional | NullOnNotFound | SearchAny,

        /// <summary>
        /// Combination mask describing a required core file, combining
        /// <see cref="Core" />, <see cref="RequiredFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        CoreRequiredFile = Core | RequiredFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing a required core library file, combining
        /// <see cref="CoreRequiredFile" />, <see cref="Library" />, and
        /// <see cref="MaybeCoreAssemblyOnly" />.
        /// </summary>
        CoreLibraryRequiredFile = CoreRequiredFile | Library | MaybeCoreAssemblyOnly,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask describing a required core library file fetched
        /// under security constraints, combining
        /// <see cref="CoreRequiredFile" /> and <see cref="Library" /> (plus
        /// <see cref="NoXml" /> when XML support is built in) with either
        /// <see cref="CoreAssemblyOnly" /> or <see cref="None" /> depending on
        /// whether an embedded library is present.
        /// </summary>
        CoreLibrarySecurityRequiredFile =
#if XML
            NoXml |
#endif
            CoreRequiredFile | Library |
#if EMBEDDED_LIBRARY
            CoreAssemblyOnly,
#else
            None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask describing an optional core file, combining
        /// <see cref="Core" />, <see cref="OptionalFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        CoreOptionalFile = Core | OptionalFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing an optional core library file, combining
        /// <see cref="CoreOptionalFile" /> and <see cref="Library" />.
        /// </summary>
        CoreLibraryOptionalFile = CoreOptionalFile | Library,

        /// <summary>
        /// Combination mask describing an optional package file, combining
        /// <see cref="Package" />, <see cref="OptionalFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        PackageOptionalFile = Package | OptionalFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing an optional package library file,
        /// combining <see cref="PackageOptionalFile" /> and
        /// <see cref="Library" />.
        /// </summary>
        PackageLibraryOptionalFile = PackageOptionalFile | Library,

        /// <summary>
        /// Combination mask describing a required package file, combining
        /// <see cref="Package" />, <see cref="RequiredFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        PackageRequiredFile = Package | RequiredFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing a required package library file,
        /// combining <see cref="PackageRequiredFile" /> and
        /// <see cref="Library" />.
        /// </summary>
        PackageLibraryRequiredFile = PackageRequiredFile | Library,

        /// <summary>
        /// Combination mask describing a required application file, combining
        /// <see cref="Application" />, <see cref="RequiredFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        ApplicationRequiredFile = Application | RequiredFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing a required application library file,
        /// combining <see cref="ApplicationRequiredFile" /> and
        /// <see cref="Library" />.
        /// </summary>
        ApplicationLibraryRequiredFile = ApplicationRequiredFile | Library,

        /// <summary>
        /// Combination mask describing an optional application file, combining
        /// <see cref="Application" />, <see cref="OptionalFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        ApplicationOptionalFile = Application | OptionalFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing an optional application library file,
        /// combining <see cref="ApplicationOptionalFile" /> and
        /// <see cref="Library" />.
        /// </summary>
        ApplicationLibraryOptionalFile = ApplicationOptionalFile | Library,

        /// <summary>
        /// Combination mask describing a required vendor file, combining
        /// <see cref="Vendor" />, <see cref="RequiredFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        VendorRequiredFile = Vendor | RequiredFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing a required vendor library file,
        /// combining <see cref="VendorRequiredFile" /> and
        /// <see cref="Library" />.
        /// </summary>
        VendorLibraryRequiredFile = VendorRequiredFile | Library,

        /// <summary>
        /// Combination mask describing an optional vendor file, combining
        /// <see cref="Vendor" />, <see cref="OptionalFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        VendorOptionalFile = Vendor | OptionalFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing an optional vendor library file,
        /// combining <see cref="VendorOptionalFile" /> and
        /// <see cref="Library" />.
        /// </summary>
        VendorLibraryOptionalFile = VendorOptionalFile | Library,

        /// <summary>
        /// Combination mask describing a required user file, combining
        /// <see cref="User" />, <see cref="RequiredFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        UserRequiredFile = User | RequiredFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing a required user library file, combining
        /// <see cref="UserRequiredFile" /> and <see cref="Library" />.
        /// </summary>
        UserLibraryRequiredFile = UserRequiredFile | Library,

        /// <summary>
        /// Combination mask describing an optional user file, combining
        /// <see cref="User" />, <see cref="OptionalFile" />,
        /// <see cref="IgnoreCanRetry" />, and <see cref="EmbeddedLibrary" />.
        /// </summary>
        UserOptionalFile = User | OptionalFile | IgnoreCanRetry | EmbeddedLibrary,
        /// <summary>
        /// Combination mask describing an optional user library file, combining
        /// <see cref="UserOptionalFile" /> and <see cref="Library" />.
        /// </summary>
        UserLibraryOptionalFile = UserOptionalFile | Library,

        /// <summary>
        /// Legacy combination used as the default for the GetData file lookup,
        /// combining <see cref="ApplicationRequiredFile" /> and
        /// <see cref="IgnoreCanRetry" />.
        /// </summary>
        UseDefaultGetDataFile = ApplicationRequiredFile | IgnoreCanRetry, // COMPAT: TclTk (legacy).

        /// <summary>
        /// The default script flags, equivalent to <see cref="UseDefault" />.
        /// </summary>
        Default = UseDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines flags that control how the result of a script
    /// block is processed, including which return codes are considered
    /// successful and how errors and failures are reported.  These are bit
    /// flags that may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("7349287b-88d3-40d1-9c63-1100774aff17")]
    public enum ScriptBlockFlags
    {
        /// <summary>
        /// No special handling is performed.
        /// </summary>
        None = 0x0,            /* no special handling. */
        /// <summary>
        /// Invalid; this value is reserved and should not be used.
        /// </summary>
        Invalid = 0x1,         /* invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Only "Ok" and "Return" will be considered as successful return
        /// codes.
        /// </summary>
        OkOrReturnOnly = 0x2,  /* only "Ok" And "Return" will be considered
                                * as successful return codes.
                                */
        /// <summary>
        /// Allow exceptional return codes; this has no effect if the
        /// <see cref="OkOrReturnOnly" /> flag is used.
        /// </summary>
        AllowExceptions = 0x4, /* allow exceptional return codes.  this has
                                * no effect if the OkOrReturnOnly flag is
                                * used.
                                */
        /// <summary>
        /// Trim all surrounding whitespace from all successful script block
        /// results.
        /// </summary>
        TrimSpace = 0x8,       /* trim all surrounding whitespace from all
                                * successful script block results.
                                */
        /// <summary>
        /// Include any script block errors in the generated output; these are
        /// errors from the script evaluation itself.
        /// </summary>
        EmitErrors = 0x10,     /* include any script block errors in the
                                * generated output.  these are errors from
                                * the script evaluation itself.
                                */
        /// <summary>
        /// Stop further processing if a script block results in an error.
        /// </summary>
        StopOnError = 0x20,    /* stop further processing if a script block
                                * results in an error.
                                */
        /// <summary>
        /// Include any script block failures in the generated output; these are
        /// errors that prevent the script block from actually being processed,
        /// such as parsing issues.
        /// </summary>
        EmitFailures = 0x40,   /* include any script block failures in the
                                * generated output.  these are errors that
                                * prevent the script block from actually
                                * being processed, e.g. parsing issues.
                                */
        /// <summary>
        /// Stop further processing if a script block cannot be processed, such
        /// as due to a parse failure.
        /// </summary>
        StopOnFailure = 0x80,  /* stop further processing if a script block
                                * cannot be processed, e.g. due to a parse
                                * failure.
                                */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved for future use; this value should not be used.
        /// </summary>
        Reserved = unchecked((int)0x80000000), /* reserved, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Under normal conditions, this is the combination of flags
        //       that should be used.
        //
        /// <summary>
        /// The standard combination of flags that should be used under normal
        /// conditions, combining <see cref="OkOrReturnOnly" />,
        /// <see cref="AllowExceptions" />, <see cref="TrimSpace" />,
        /// <see cref="EmitErrors" />, <see cref="StopOnError" />,
        /// <see cref="EmitFailures" />, and <see cref="StopOnFailure" />.
        /// </summary>
        Standard = OkOrReturnOnly | AllowExceptions | TrimSpace |
                   EmitErrors | StopOnError | EmitFailures |
                   StopOnFailure,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This is the combination of flags that can be used to force
        //       processing to continue even if script evaluation errors or
        //       parsing failures are encountered.
        //
        /// <summary>
        /// Like <see cref="Standard" /> but forces processing to continue even
        /// when script evaluation errors or parsing failures are encountered;
        /// it clears <see cref="StopOnError" /> and <see cref="StopOnFailure" />.
        /// </summary>
        Relaxed = Standard & ~(StopOnError | StopOnFailure),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default script block flags, equivalent to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the recognized boolean keyword values that may
    /// be used interchangeably to represent the true and false states (e.g.
    /// yes/no, on/off, enable/disable).
    /// </summary>
    [ObjectId("cb195945-70af-4c06-8e81-dc694ed4182a")]
    public enum Boolean : byte /* COMPAT: Tcl. */
    {
        /// <summary>
        /// The false (logically off) value.
        /// </summary>
        False = 0,
        /// <summary>
        /// The true (logically on) value.
        /// </summary>
        True = 1,
        /// <summary>
        /// A synonym for the false value.
        /// </summary>
        No = 0,
        /// <summary>
        /// A synonym for the true value.
        /// </summary>
        Yes = 1,
        /// <summary>
        /// A synonym for the false value.
        /// </summary>
        Off = 0,
        /// <summary>
        /// A synonym for the true value.
        /// </summary>
        On = 1,
        /// <summary>
        /// A synonym for the false value.
        /// </summary>
        Disable = 0,
        /// <summary>
        /// A synonym for the true value.
        /// </summary>
        Enable = 1,
        /// <summary>
        /// A synonym for the false value.
        /// </summary>
        Disabled = 0,
        /// <summary>
        /// A synonym for the true value.
        /// </summary>
        Enabled = 1
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the categories of diagnostic output that the
    /// test harness may emit, including categories compatible with tcltest as
    /// well as TclTk-specific extensions.  Many members have a single-letter
    /// alias.  These are bit flags that may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("435e1a60-3960-4512-9cb9-eecb0439c4da")]
    public enum TestOutputType
    {
        /// <summary>
        /// No test output is emitted.
        /// </summary>
        None = 0x0,            /* nothing. */
        /// <summary>
        /// Invalid; this value is reserved and should not be used.
        /// </summary>
        Invalid = 0x1,         /* invalid, do not use. */
        /// <summary>
        /// Interpreter: automatic handling of the test output to write.
        /// </summary>
        AutomaticWrite = 0x2,  /* Interpreter: automatic handling of the test output
                                * to write. */
        /// <summary>
        /// Interpreter: automatic handling of the test output to return.
        /// </summary>
        AutomaticReturn = 0x4, /* Interpreter: automatic handling of the test output
                                * to return. */
        /// <summary>
        /// Interpreter: automatic handling of the test output to log.
        /// </summary>
        AutomaticLog = 0x8,    /* Interpreter: automatic handling of the test output
                                * to log. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Emit the body of failed tests (tcltest compatible).
        /// </summary>
        Body = 0x10,           /* COMPAT: tcltest (body of failed tests). */
        /// <summary>
        /// A single-letter alias for <see cref="Body" />.
        /// </summary>
        B = Body,              /* Same as "Body". */
        /// <summary>
        /// Emit output when a test passes (tcltest compatible).
        /// </summary>
        Pass = 0x20,           /* COMPAT: tcltest (when a test passes). */
        /// <summary>
        /// A single-letter alias for <see cref="Pass" />.
        /// </summary>
        P = Pass,              /* Same as "Pass". */
        /// <summary>
        /// Emit output when a test is skipped (tcltest compatible).
        /// </summary>
        Skip = 0x40,           /* COMPAT: tcltest (when a test is skipped). */
        /// <summary>
        /// A single-letter alias for <see cref="Skip" />.
        /// </summary>
        S = Skip,              /* Same as "Skip". */
        /// <summary>
        /// Emit output when a test starts (tcltest compatible).
        /// </summary>
        Start = 0x80,          /* COMPAT: tcltest (when a test starts). */
        /// <summary>
        /// A single-letter alias for <see cref="Start" />.
        /// </summary>
        T = Start,             /* Same as "Start". */
        /// <summary>
        /// Emit the errorCode and errorInfo on failure (tcltest compatible).
        /// </summary>
        Error = 0x100,         /* COMPAT: tcltest (errorCode/errorInfo on
                                * failure). */
        /// <summary>
        /// A single-letter alias for <see cref="Error" />.
        /// </summary>
        E = Error,             /* Same as "Error". */
        /// <summary>
        /// Emit source file line information on failure (tcltest compatible).
        /// </summary>
        Line = 0x200,          /* COMPAT: tcltest (source file line info on
                                * failure). */
        /// <summary>
        /// A single-letter alias for <see cref="Line" />.
        /// </summary>
        L = Line,              /* Same as "Line". */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// TclTk: emit output when a test fails.
        /// </summary>
        Fail = 0x400,          /* TclTk: when a test fails. */
        /// <summary>
        /// A single-letter alias for <see cref="Fail" />.
        /// </summary>
        F = Fail,              /* Same as "Fail". */
        /// <summary>
        /// TclTk: emit the failure mode and details, such as a code mismatch,
        /// result mismatch, or output mismatch.
        /// </summary>
        Reason = 0x800,        /* TclTk: failure mode and details (code
                                * mismatch, result mismatch, output mismatch,
                                * etc). */
        /// <summary>
        /// A single-letter alias for <see cref="Reason" />.
        /// </summary>
        R = Reason,            /* Same as "Reason". */
        /// <summary>
        /// TclTk: emit setup, body, and cleanup timing information.
        /// </summary>
        Time = 0x1000,         /* TclTk: setup/body/cleanup timing. */
        /// <summary>
        /// A single-letter alias for <see cref="Time" />.
        /// </summary>
        I = Time,              /* Same as "Time". */
        /// <summary>
        /// TclTk: emit the exit code detail of an isolated process.
        /// </summary>
        Exit = 0x2000,         /* TclTk: isolated process exit code detail. */
        /// <summary>
        /// A single-letter alias for <see cref="Exit" />.
        /// </summary>
        X = Exit,              /* Same as "Exit". */
        /// <summary>
        /// TclTk: emit the standard output of an isolated process.
        /// </summary>
        StdOut = 0x4000,       /* TclTk: isolated process standard output. */
        /// <summary>
        /// A single-letter alias for <see cref="StdOut" />.
        /// </summary>
        O = StdOut,            /* Same as "StdOut". */
        /// <summary>
        /// TclTk: emit the standard error of an isolated process.
        /// </summary>
        StdErr = 0x8000,       /* TclTk: isolated process standard error. */
        /// <summary>
        /// A single-letter alias for <see cref="StdErr" />.
        /// </summary>
        D = StdErr,            /* Same as "StdErr". */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// TclTk: for use with "Debug", emit a message upon entering into a
        /// script evaluation.
        /// </summary>
        Enter = 0x10000,       /* TclTk: for use with "Debug", emit message
                                * upon entering into a script evaluation. */
        /// <summary>
        /// A single-letter alias for <see cref="Enter" />.
        /// </summary>
        N = Enter,             /* Same as "Enter". */
        /// <summary>
        /// TclTk: for use with "Debug", emit a message upon leaving a script
        /// evaluation.
        /// </summary>
        Leave = 0x20000,       /* TclTk: for use with "Debug", emit message
                                * upon leaving into a script evaluation. */
        /// <summary>
        /// A single-letter alias for <see cref="Leave" />.
        /// </summary>
        A = Leave,             /* Same as "Leave". */
        /// <summary>
        /// TclTk: emit to the attached debugger, if any.  This flag never has
        /// an effect on the test results.
        /// </summary>
        Track = 0x40000,       /* TclTk: emit to the attached debugger, if
                                * any.  This flag never has an effect on the
                                * test results. */
        /// <summary>
        /// A single-letter alias for <see cref="Track" />.
        /// </summary>
        G = Track,             /* Same as "Track". */
        /// <summary>
        /// TclTk: indicates that a test hook was invoked.
        /// </summary>
        Hook = 0x80000,        /* TclTk: A test hook was invoked. */
        /// <summary>
        /// A single-letter alias for <see cref="Hook" />.
        /// </summary>
        H = Hook,              /* Same as "Hook". */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the automatic handling flags, combining
        /// <see cref="AutomaticWrite" />, <see cref="AutomaticReturn" />, and
        /// <see cref="AutomaticLog" />.
        /// </summary>
        Automatic = AutomaticWrite | AutomaticReturn | AutomaticLog,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The legacy combination of output categories, combining
        /// <see cref="Pass" />, <see cref="Body" />, <see cref="Skip" />,
        /// <see cref="Start" />, and <see cref="Error" />.
        /// </summary>
        Legacy = Pass | Body | Skip |
                 Start | Error, /* pbste */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The standard combination of output categories, combining
        /// <see cref="Pass" />, <see cref="Body" />, <see cref="Skip" />,
        /// <see cref="Start" />, <see cref="Error" />, and <see cref="Line" />.
        /// </summary>
        Standard = Pass | Body | Skip |
                   Start | Error | Line, /* pbstel */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all output categories, combining
        /// <see cref="Standard" />, <see cref="Fail" />, <see cref="Reason" />,
        /// <see cref="Time" />, <see cref="Exit" />, <see cref="StdOut" />,
        /// <see cref="StdErr" />, <see cref="Enter" />, <see cref="Leave" />,
        /// <see cref="Track" />, and <see cref="Hook" />.
        /// </summary>
        All = Standard | Fail | Reason |
              Time | Exit | StdOut |
              StdErr | Enter | Leave |
              Track | Hook,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default test output categories, equivalent to the combination of
        /// <see cref="Automatic" /> and <see cref="All" /> with
        /// <see cref="Start" /> cleared.
        /// </summary>
        Default = (Automatic | All) & ~Start
    }

