    /// <summary>
    /// This enumeration defines the categories of test path locations that may
    /// be searched when running tests.
    /// </summary>
    [ObjectId("da180459-c94a-4a04-9753-d6f1448964fa")]
    public enum TestPathType
    {
        /// <summary>
        /// No test path type is specified.
        /// </summary>
        None = 0x0,    /* unspecified. */
        /// <summary>
        /// Invalid; this value is reserved and should not be used.
        /// </summary>
        Invalid = 0x1, /* invalid, do not use. */
        /// <summary>
        /// Core library specific tests.
        /// </summary>
        Library = 0x2, /* core library specific tests? */
        /// <summary>
        /// Plugin specific tests.
        /// </summary>
        Plugins = 0x4, /* run plugin specific tests? */
        /// <summary>
        /// Generic tests.
        /// </summary>
        Tests = 0x8,   /* generic tests */

        /// <summary>
        /// The default test path type, equivalent to <see cref="None" />.
        /// </summary>
        Default = None
    }

