    /// <summary>
    /// This enumeration defines the relative degree of isolation requested for
    /// an operation, ranging from lowest to highest.  These are bit flags that
    /// may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("5f9a351b-67bb-48e1-ae17-15c4dd6e1c41")]
    public enum IsolationDetail
    {
        /// <summary>
        /// No isolation is requested.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Invalid; this value is reserved and should not be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The lowest degree of isolation.
        /// </summary>
        Lowest = 0x2,
        /// <summary>
        /// A low degree of isolation.
        /// </summary>
        Low = 0x4,
        /// <summary>
        /// A medium degree of isolation.
        /// </summary>
        Medium = 0x8,
        /// <summary>
        /// A high degree of isolation.
        /// </summary>
        High = 0x10,
        /// <summary>
        /// The highest degree of isolation.
        /// </summary>
        Highest = 0x20,

        /// <summary>
        /// The default isolation detail, equivalent to <see cref="Medium" />.
        /// </summary>
        Default = Medium
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the level of isolation used when
    /// creating a child or sub-interpreter.  The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("b60aaf1f-b159-4c6e-8e95-fe10eb40da0f")]
    public enum IsolationLevel
    {
        /// <summary>
        /// No isolation flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid isolation level;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// Isolate using a separate interpreter within the same
        /// application domain.
        /// </summary>
        Interpreter = 0x2,
        /// <summary>
        /// Isolate by creating a separate application domain.
        /// </summary>
        AppDomain = 0x4,
        /// <summary>
        /// Isolate using a separate application domain when available,
        /// falling back to a separate interpreter otherwise.
        /// </summary>
        AppDomainOrInterpreter = 0x8,

        /// <summary>
        /// Isolate using a separate operating system process; not yet
        /// implemented.
        /// </summary>
        Process = 0x100, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Isolate using a separate login session; not yet implemented.
        /// </summary>
        Session = 0x200, /* NOT YET IMPLEMENTED */
        /// <summary>
        /// Isolate using a separate physical or virtual machine; not yet
        /// implemented.
        /// </summary>
        Machine = 0x400, /* NOT YET IMPLEMENTED */

#if ISOLATED_INTERPRETERS
        /// <summary>
        /// The maximum supported isolation level, equal to <see cref="AppDomain" /> when
        /// isolated interpreters are enabled.
        /// </summary>
        Maximum = AppDomain,
#else
        /// <summary>
        /// The maximum supported isolation level, equal to <see cref="AppDomainOrInterpreter" /> when
        /// isolated interpreters are not enabled.
        /// </summary>
        Maximum = AppDomainOrInterpreter,
#endif

        /// <summary>
        /// Marks an interpreter as isolated; for internal use only.
        /// </summary>
        Isolated = 0x10000, /* INTERNAL USE ONLY */

        /// <summary>
        /// Combination mask of <see cref="Interpreter" />, <see cref="AppDomain" />, and <see cref="AppDomainOrInterpreter" />.
        /// </summary>
        BaseMask = Interpreter | AppDomain | AppDomainOrInterpreter,

        /// <summary>
        /// The default isolation level, equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how command and procedure option parsing
    /// behaves when various special or unexpected conditions are
    /// encountered.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("879a3ffc-59dc-43ae-9bad-8c58ada1206b")]
    public enum OptionBehaviorFlags
    {
        /// <summary>
        /// No special option behavior is requested.
        /// </summary>
        None = 0x0,                       /* No special option behavior. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,                    /* Invalid, do not use. */
        /// <summary>
        /// Use the Validate flag for all entity lookups performed while
        /// processing options.
        /// </summary>
        ValidateLookups = 0x2,            /* Use the Validate flag for all entity
                                           * lookups. */
        /// <summary>
        /// Use the Strict flag for all entity lookups performed while
        /// processing options.
        /// </summary>
        StrictLookups = 0x4,              /* Use the Strict flag for all entity
                                           * lookups. */
        /// <summary>
        /// Raise an error if an end-of-options indicator is encountered
        /// when it is not expected.
        /// </summary>
        ErrorOnEndOfOptions = 0x8,        /* Raise an error if an end-of-options
                                           * indicator is encountered when
                                           * unexpected. */
        /// <summary>
        /// Stop processing options if an end-of-options indicator is
        /// encountered when it is not expected.
        /// </summary>
        StopOnEndOfOptions = 0x10,        /* Stop processing options if an
                                           * end-of-options indicator is encountered
                                           * when unexpected. */
        /// <summary>
        /// Ignore an end-of-options indicator if it is encountered when
        /// not expected.
        /// </summary>
        IgnoreOnEndOfOptions = 0x20,      /* Ignore end-of-options indicator if
                                           * encountered when unexpected. */
        /// <summary>
        /// Skip to the next argument after an unexpected end-of-options
        /// indicator (i.e. assume a name/value pair); has no effect unless
        /// <see cref="IgnoreOnEndOfOptions" /> is also set.
        /// </summary>
        SkipOnEndOfOptions = 0x40,        /* Skip to the next argument after an
                                           * unexpected end-of-options indicator
                                           * (i.e. assume a name/value pair).  This
                                           * flag has no effect unless the
                                           * IgnoreOnEndOfOptions flag is also set. */
        /// <summary>
        /// Raise an error if a list-of-options indicator is encountered
        /// when it is not expected.
        /// </summary>
        ErrorOnListOfOptions = 0x80,      /* Raise an error if an list-of-options
                                           * indicator is encountered when
                                           * unexpected. */
        /// <summary>
        /// Stop processing options if a list-of-options indicator is
        /// encountered when it is not expected.
        /// </summary>
        StopOnListOfOptions = 0x100,      /* Stop processing options if an
                                           * list-of-options indicator is encountered
                                           * when unexpected. */
        /// <summary>
        /// Ignore a list-of-options indicator if it is encountered when
        /// not expected.
        /// </summary>
        IgnoreOnListOfOptions = 0x200,    /* Ignore list-of-options indicator if
                                           * encountered when unexpected. */
        /// <summary>
        /// Skip to the next argument after an unexpected list-of-options
        /// indicator (i.e. assume a name/value pair); has no effect unless
        /// <see cref="IgnoreOnListOfOptions" /> is also set.
        /// </summary>
        SkipOnListOfOptions = 0x400,      /* Skip to the next argument after an
                                           * unexpected list-of-options indicator
                                           * (i.e. assume a name/value pair).  This
                                           * flag has no effect unless the
                                           * IgnoreOnListOfOptions flag is also set. */
        /// <summary>
        /// Raise an error if an ambiguous option is encountered.
        /// </summary>
        ErrorOnAmbiguousOption = 0x800,   /* Raise an error if an Ambiguous option is
                                           * encountered. */
        /// <summary>
        /// Stop processing options if an ambiguous option is encountered.
        /// </summary>
        StopOnAmbiguousOption = 0x1000,   /* Stop processing options if an Ambiguous
                                           * one is encountered. */
        /// <summary>
        /// Ignore ambiguous options when they are encountered.
        /// </summary>
        IgnoreOnAmbiguousOption = 0x2000, /* Ignore Ambiguous options if they are
                                           * encountered. */
        /// <summary>
        /// Skip the next argument after an ambiguous option (i.e. assume a
        /// name/value pair); has no effect unless the corresponding ignore
        /// flag is also set.
        /// </summary>
        SkipOnAmbiguousOption = 0x4000,   /* Skip the next argument after an unknown
                                           * option (i.e. assume a name/value pair).
                                           * This flag has no effect unless the
                                           * IgnoreOnAmbiguous flag is also set. */
        /// <summary>
        /// Raise an error if an unknown option is encountered.
        /// </summary>
        ErrorOnUnknownOption = 0x8000,    /* Raise an error if an unknown option is
                                           * encountered. */
        /// <summary>
        /// Stop processing options if an unknown option is encountered.
        /// </summary>
        StopOnUnknownOption = 0x10000,    /* Stop processing options if an unknown
                                           * one is encountered. */
        /// <summary>
        /// Ignore unknown options when they are encountered.
        /// </summary>
        IgnoreOnUnknownOption = 0x20000,  /* Ignore unknown options if they are
                                           * encountered. */
        /// <summary>
        /// Skip the next argument after an unknown option (i.e. assume a
        /// name/value pair); has no effect unless <see cref="IgnoreOnUnknownOption" /> is also set.
        /// </summary>
        SkipOnUnknownOption = 0x40000,    /* Skip the next argument after an unknown
                                           * option (i.e. assume a name/value pair).
                                           * This flag has no effect unless the
                                           * IgnoreOnUnknown flag is also set. */
        /// <summary>
        /// Raise an error if a non-option is encountered when unexpected
        /// (i.e. it is not simply an option value).
        /// </summary>
        ErrorOnNonOption = 0x80000,       /* Raise an error if a non-option is
                                           * encountered when unexpected (i.e. it
                                           * is not simply an option value). */
        /// <summary>
        /// Stop processing options if a non-option is encountered when
        /// unexpected (i.e. it is not simply an option value).
        /// </summary>
        StopOnNonOption = 0x100000,       /* Stop processing options if a non-option
                                           * is encountered when unexpected (i.e. it
                                           * is not simply an option value). */
        /// <summary>
        /// Ignore the argument if a non-option is encountered when
        /// unexpected (i.e. it is not simply an option value).
        /// </summary>
        IgnoreOnNonOption = 0x200000,     /* Ignore the argument if a non-option
                                           * is encountered when unexpected (i.e. it
                                           * is not simply an option value). */
        /// <summary>
        /// Skip to the next argument after an unexpected non-option; has
        /// no effect unless <see cref="IgnoreOnNonOption" /> is also set.
        /// </summary>
        SkipOnNonOption = 0x400000,       /* Skip to the next argument after a
                                           * non-option is encountered when
                                           * unexpected (i.e. it is not simply an
                                           * option value).  This flag has no effect
                                           * unless the IgnoreOnNonOption flag is
                                           * also set. */
        /// <summary>
        /// The last argument cannot be an option; therefore always stop if
        /// it is reached before stopping for another reason.
        /// </summary>
        LastIsNonOption = 0x800000,       /* The last argument cannot be an option;
                                           * therefore, always stop if it is hit
                                           * prior to stopping for another reason. */
        /// <summary>
        /// Do not resolve option values via any IObject instances.
        /// </summary>
        NoObject = 0x1000000,             /* Do not resolve values via any IObject
                                           * instances. */
        /// <summary>
        /// If the interpreter cannot be locked for any reason, return an
        /// error immediately.
        /// </summary>
        FailOnLocked = 0x2000000,         /* If the interpreter cannot be locked for
                                           * any reason, return an error immediately. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This is the behavior needed by the CheckOptions method.
        //
        /// <summary>
        /// Combination mask of <see cref="StopOnEndOfOptions" />, <see cref="StopOnListOfOptions" />, <see cref="IgnoreOnUnknownOption" />, <see cref="IgnoreOnAmbiguousOption" />, <see cref="IgnoreOnNonOption" />, and <see cref="IgnoreOnListOfOptions" />,
        /// representing the behavior needed by the CheckOptions method.
        /// </summary>
        CheckOptions = StopOnEndOfOptions | StopOnListOfOptions |
                       IgnoreOnUnknownOption | IgnoreOnAmbiguousOption |
                       IgnoreOnNonOption | IgnoreOnListOfOptions,

        //
        // NOTE: This is the value for the old "strict" mode behavior.
        //
        /// <summary>
        /// Combination mask representing the legacy "strict" mode
        /// behavior, combining <see cref="ErrorOnEndOfOptions" />, <see cref="ErrorOnUnknownOption" />, <see cref="ErrorOnAmbiguousOption" />, and <see cref="StopOnNonOption" />.
        /// </summary>
        Strict = ErrorOnEndOfOptions | ErrorOnUnknownOption |
                 ErrorOnAmbiguousOption | StopOnNonOption,

        //
        // NOTE: This is the value for the old "non-strict" mode behavior.
        //
        /// <summary>
        /// The default behavior; a combination mask representing the
        /// legacy "non-strict" mode, combining <see cref="StopOnEndOfOptions" />, <see cref="StopOnListOfOptions" />, <see cref="StopOnUnknownOption" />, <see cref="StopOnAmbiguousOption" />, and
        /// <see cref="StopOnNonOption" />.
        /// </summary>
        Default = StopOnEndOfOptions | StopOnListOfOptions |
                  StopOnUnknownOption | StopOnAmbiguousOption |
                  StopOnNonOption
    }

