        Category63 = 0x4000000000000000, /* NOTE: For (third-party) applications. */
        /// <summary>
        /// Option category slot 64; reserved for third-party applications.
        /// </summary>
        Category64 = 0x8000000000000000, /* NOTE: For (third-party) applications. */

        /// <summary>
        /// Combination mask of option categories 1 through 16, reserved
        /// for core library use.
        /// </summary>
        ReservedMask = Category01 | Category02 | Category03 | Category04 |
                       Category05 | Category06 | Category07 | Category08 |
                       Category09 | Category10 | Category11 | Category12 |
                       Category13 | Category14 | Category15 | Category16,

        /// <summary>
        /// Combination mask of option categories 17 through 32, reserved
        /// for external plugin use.
        /// </summary>
        PluginMask = Category17 | Category18 | Category19 | Category20 |
                     Category21 | Category22 | Category23 | Category24 |
                     Category25 | Category26 | Category27 | Category28 |
                     Category29 | Category30 | Category31 | Category32,

        /// <summary>
        /// Combination mask of option categories 33 through 48, available
        /// for general use.
        /// </summary>
        GeneralMask = Category33 | Category34 | Category35 | Category36 |
                      Category37 | Category38 | Category39 | Category40 |
                      Category41 | Category42 | Category43 | Category44 |
                      Category45 | Category46 | Category47 | Category48,

        /// <summary>
        /// Combination mask of option categories 49 through 64, reserved
        /// for third-party applications.
        /// </summary>
        UserMask = Category49 | Category50 | Category51 | Category52 |
                   Category53 | Category54 | Category55 | Category56 |
                   Category57 | Category58 | Category59 | Category60 |
                   Category61 | Category62 | Category63 | Category64,

        /// <summary>
        /// Combination mask of <see cref="ReservedMask" />, <see cref="PluginMask" />, <see cref="GeneralMask" />, and <see cref="UserMask" />.
        /// </summary>
        AllMask = ReservedMask | PluginMask | GeneralMask | UserMask
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration describes the characteristics of a command or
    /// procedure option, including how its value (if any) must be parsed
    /// and converted.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("64fb0580-d2c6-4e7e-a6f4-300144472520")]
    public enum OptionFlags : ulong
    {
        /// <summary>
        /// A regular name-only option with no special handling.
        /// </summary>
        None = 0x0,                              /* Regular name-only option, no special
                                                  * handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,                           /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The option was found while parsing arguments.
        /// </summary>
        Present = 0x2,                           /* Option was found while parsing
                                                  * arguments. */
        /// <summary>
        /// Use strict option value processing semantics.
        /// </summary>
        Strict = 0x4,                            /* Use strict option value processing
                                                  * semantics? */
        /// <summary>
        /// Error messages for this option should contain more details.
        /// </summary>
        Verbose = 0x8,                           /* Error messages should contain more
                                                  * details? */
        /// <summary>
        /// The option name is not case-sensitive.
        /// </summary>
        NoCase = 0x10,                           /* Option is not case-sensitive. */
        /// <summary>
        /// The option is not allowed in "safe" interpreters.
        /// </summary>
        Unsafe = 0x20,                           /* Option is not allowed in "safe"
                                                  * interpreters. */
        /// <summary>
        /// The option is not allowed in interpreters that do not have the
        /// "AllowRestricted" interpreter flag set.
        /// </summary>
        Restricted = 0x40,                       /* Option is not allowed in interpreters
                                                  * that do not have the "AllowRestricted"
                                                  * interpreter flag set. */
        /// <summary>
        /// The option was added automatically by the system.
        /// </summary>
        System = 0x80,                           /* Option was added automatically by the
                                                  * system. */
        /// <summary>
        /// Integers are allowed for an enumeration option.
        /// </summary>
        AllowInteger = 0x100,                    /* Integers are allowed for an enumeration
                                                  * option. */
        /// <summary>
        /// The option value is nullable even though it is a value type
        /// (e.g. DateTime, bool, etc).
        /// </summary>
        Nullable = 0x200,                        /* The option value is nullable even though
                                                  * it is a value type, e.g. DateTime, bool,
                                                  * etc. */
        /// <summary>
        /// Disable use of object handle values for this option.
        /// </summary>
        NoObject = 0x400,                        /* disable use of object handle values. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The option must have a value following its name (string, int,
        /// etc).
        /// </summary>
        MustHaveValue = 0x800,                    /* Value must have value after name (string, int, etc). */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The value must convert to a bool via GetBoolean.
        /// </summary>
        MustBeBoolean = 0x1000,                   /* Value must convert to bool via GetBoolean. */
        /// <summary>
        /// The value must convert to a signed byte via GetSignedByte2.
        /// </summary>
        MustBeSignedByte = 0x2000,                /* Value must convert to int via GetSignedByte2. */
        /// <summary>
        /// The value must convert to a byte via GetByte2.
        /// </summary>
        MustBeByte = 0x4000,                      /* Value must convert to int via GetByte2. */
        /// <summary>
        /// The value must convert to a narrow integer via GetInteger2.
        /// </summary>
        MustBeNarrowInteger = 0x8000,             /* Value must convert to int via GetInteger2. */
        /// <summary>
        /// The value must convert to an unsigned narrow integer via
        /// GetUnsignedInteger2.
        /// </summary>
        MustBeUnsignedNarrowInteger = 0x10000,    /* Value must convert to int via GetUnsignedInteger2. */
        /// <summary>
        /// The value must convert to an int via GetInteger2.
        /// </summary>
        MustBeInteger = 0x20000,                  /* Value must convert to int via GetInteger2. */
        /// <summary>
        /// The value must convert to an unsigned int via
        /// GetUnsignedInteger2.
        /// </summary>
        MustBeUnsignedInteger = 0x40000,          /* Value must convert to int via GetUnsignedInteger2. */
        /// <summary>
        /// The value must convert to a wide integer (long) via
        /// GetWideInteger2.
        /// </summary>
        MustBeWideInteger = 0x80000,              /* Value must convert to wideInt (long) via GetWideInteger2. */
        /// <summary>
        /// The value must convert to an unsigned wide integer (long) via
        /// GetWideInteger2.
        /// </summary>
        MustBeUnsignedWideInteger = 0x100000,     /* Value must convert to wideInt (long) via GetWideInteger2. */

#if NET_40
        /// <summary>
        /// The value must convert to an entier (BigInteger) via
        /// GetBigInteger2.
        /// </summary>
        MustBeBigInteger = 0x200000,              /* Value must convert to entier (BigInteger) via GetBigInteger2. */
#endif

        /// <summary>
        /// The value must convert to a decimal via GetDecimal.
        /// </summary>
        MustBeDecimal = 0x400000,                 /* Value must convert to decimal via GetDecimal. */
        /// <summary>
        /// The value must convert to a double via GetDouble.
        /// </summary>
        MustBeDouble = 0x800000,                  /* Value must convert to double via GetDouble. */
        /// <summary>
        /// The value must be an int or an <c>end[+/-int]</c> index
        /// expression.
        /// </summary>
        MustBeIndex = 0x1000000,                  /* Value must be an int or end[<+|-><int>]. */
        /// <summary>
        /// The value must be an int or a <c>#int</c> level specification.
        /// </summary>
        MustBeLevel = 0x2000000,                  /* Value must be an int or #<int>. */
        /// <summary>
        /// The value must be a ReturnCode or int.
        /// </summary>
        MustBeReturnCode = 0x4000000,             /* Value must be a ReturnCode or int. */
        /// <summary>
        /// The value must convert to the specified Enum type.
        /// </summary>
        MustBeEnum = 0x8000000,                   /* Value must convert to the specified Enum type. */
        /// <summary>
        /// The value must be an EnumList object.
        /// </summary>
        MustBeEnumList = 0x10000000,              /* Value must be an EnumList object. */
        /// <summary>
        /// The value must convert to a System.Guid.
        /// </summary>
        MustBeGuid = 0x20000000,                  /* Value must convert to System.Guid. */
        /// <summary>
        /// The value must convert to a System.DateTime.
        /// </summary>
        MustBeDateTime = 0x40000000,              /* Value must convert to System.DateTime. */
        /// <summary>
        /// The value must convert to a System.TimeSpan.
        /// </summary>
        MustBeTimeSpan = 0x80000000,              /* Value must convert to System.TimeSpan. */
        /// <summary>
        /// SplitList on the value must succeed.
        /// </summary>
        MustBeList = 0x100000000,                 /* SplitList on value must succeed. */
        /// <summary>
        /// The value must have an even number of list elements.
        /// </summary>
        MustBeDictionary = 0x200000000,           /* Must have an even number of list elements. */
        /// <summary>
        /// The value must be "exact", "glob", or "regexp".
        /// </summary>
        MustBeMatchMode = 0x400000000,            /* Value must be "exact", "glob", or "regexp". */
        /// <summary>
        /// The value must convert to some value via GetValue.
        /// </summary>
        MustBeValue = 0x800000000,                /* Value must convert to some value via GetValue. */
        /// <summary>
        /// The value must be an opaque object handle.
        /// </summary>
        MustBeObject = 0x1000000000,              /* Value must be an opaque object handle. */
        /// <summary>
        /// The value must be an opaque interpreter handle.
        /// </summary>
        MustBeInterpreter = 0x2000000000,         /* Value must be an opaque interpreter handle. */
        /// <summary>
        /// The value must be a System.Type object.
        /// </summary>
        MustBeType = 0x4000000000,                /* Value must be a System.Type object. */
        /// <summary>
        /// The value must be a TypeList object.
        /// </summary>
        MustBeTypeList = 0x8000000000,            /* Value must be a TypeList object. */
        /// <summary>
        /// The value must be an (absolute) System.Uri object.
        /// </summary>
        MustBeAbsoluteUri = 0x10000000000,        /* Value must be a System.Uri object. */
        /// <summary>
        /// The value must be a System.Version object.
        /// </summary>
        MustBeVersion = 0x20000000000,            /* Value must be a System.Version object. */
        /// <summary>
        /// The value must be a ReturnCodeList object.
        /// </summary>
        MustBeReturnCodeList = 0x40000000000,     /* Value must be a ReturnCodeList object. */
        /// <summary>
        /// The value must be an IIdentifier object.
        /// </summary>
        MustBeIdentifier = 0x80000000000,         /* Value must be an IIdentifier object. */
        /// <summary>
        /// The value must be an IAlias object.
        /// </summary>
        MustBeAlias = 0x100000000000,             /* Value must be an IAlias object. */
        /// <summary>
        /// The value must be an IOption object.
        /// </summary>
        MustBeOption = 0x200000000000,            /* Value must be an IOption object. */
        /// <summary>
        /// The value must be an (absolute) INamespace object.
        /// </summary>
        MustBeAbsoluteNamespace = 0x400000000000, /* Value must be an INamespace object. */
        /// <summary>
        /// The value must be a (relative) INamespace object.
        /// </summary>
        MustBeRelativeNamespace = 0x800000000000, /* Value must be an INamespace object. */
        /// <summary>
        /// The value must be a CultureInfo object.
        /// </summary>
        MustBeCultureInfo = 0x1000000000000,      /* Value must be a CultureInfo object. */
        /// <summary>
        /// The value must be an array of byte(s).
        /// </summary>
        MustBeByteArray = 0x2000000000000,        /* Value must be an array of byte(s). */

#if NATIVE && TCL
        /// <summary>
        /// The value must be a Tcl interpreter.
        /// </summary>
        MustBeTclInterpreter = 0x4000000000000,   /* Value must be a Tcl interpreter. */
#endif

        /// <summary>
        /// The value must be a SecureString object.
        /// </summary>
        MustBeSecureString = 0x8000000000000,     /* Value must be a SecureString object. */
        /// <summary>
        /// The value must be an Encoding object.
        /// </summary>
        MustBeEncoding = 0x10000000000000,        /* Value must be an Encoding object. */
        /// <summary>
        /// The value must be an IPlugin object.
        /// </summary>
        MustBePlugin = 0x20000000000000,          /* Value must be an IPlugin object. */
        /// <summary>
        /// The value must be an IExecute object.
        /// </summary>
        MustBeExecute = 0x40000000000000,         /* Value must be an IExecute object. */
        /// <summary>
        /// The value must be an ICallback object.
        /// </summary>
        MustBeCallback = 0x80000000000000,        /* Value must be an ICallback object. */
        /// <summary>
        /// The value must be an IRuleSet object.
        /// </summary>
        MustBeRuleSet = 0x100000000000000,        /* value must be an IRuleSet object. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Special option flags.
        //
        /// <summary>
        /// The end-of-options marker; stop and do not process further
        /// options.
        /// </summary>
        EndOfOptions = 0x200000000000000,         /* This is the end-of-options marker, stop and do not process. */
        /// <summary>
        /// The list-of-options marker; stop, show the available options,
        /// and return an error.
        /// </summary>
        ListOfOptions = 0x400000000000000,        /* This is the list-of-options marker, stop and show the
                                                  /* available options, returning an error. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="MustBeEnum" /> and <see cref="MustBeEnumList" />.
