        MustBeMask = MustBeBoolean | MustBeSignedByte | MustBeByte |
                     MustBeNarrowInteger | MustBeUnsignedNarrowInteger | MustBeInteger |
                     MustBeUnsignedInteger | MustBeWideInteger | MustBeUnsignedWideInteger |
#if NET_40
                     MustBeBigInteger |
#endif
                     MustBeIndex | MustBeLevel | MustBeReturnCode |
                     MustBeEnum | MustBeEnumList | MustBeGuid |
                     MustBeDateTime | MustBeTimeSpan | MustBeList |
                     MustBeDictionary | MustBeMatchMode | MustBeValue |
                     MustBeObject | MustBeInterpreter | MustBeType |
                     MustBeTypeList | MustBeAbsoluteUri | MustBeVersion |
                     MustBeReturnCodeList | MustBeIdentifier | MustBeAlias |
                     MustBeOption | MustBeAbsoluteNamespace | MustBeRelativeNamespace |
                     MustBeCultureInfo | MustBeByteArray |
#if NATIVE && TCL
                     MustBeTclInterpreter |
#endif
                     MustBeSecureString | MustBeEncoding | MustBePlugin |
                     MustBeExecute | MustBeCallback | MustBeRuleSet,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: Composite flags provided for shorthand.
        //
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeCallback" />.
        /// </summary>
        MustHaveCallbackValue = MustHaveValue | MustBeCallback,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeExecute" />.
        /// </summary>
        MustHaveExecuteValue = MustHaveValue | MustBeExecute,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBePlugin" />.
        /// </summary>
        MustHavePluginValue = MustHaveValue | MustBePlugin,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeEncoding" />.
        /// </summary>
        MustHaveEncodingValue = MustHaveValue | MustBeEncoding,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeSecureString" />.
        /// </summary>
        MustHaveSecureStringValue = MustHaveValue | MustBeSecureString,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeBoolean" />.
        /// </summary>
        MustHaveBooleanValue = MustHaveValue | MustBeBoolean,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeSignedByte" />.
        /// </summary>
        MustHaveSignedByteValue = MustHaveValue | MustBeSignedByte,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeByte" />.
        /// </summary>
        MustHaveByteValue = MustHaveValue | MustBeByte,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeNarrowInteger" />.
        /// </summary>
        MustHaveNarrowIntegerValue = MustHaveValue | MustBeNarrowInteger,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeUnsignedNarrowInteger" />.
        /// </summary>
        MustHaveUnsignedNarrowIntegerValue = MustHaveValue | MustBeUnsignedNarrowInteger,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeInteger" />.
        /// </summary>
        MustHaveIntegerValue = MustHaveValue | MustBeInteger,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeUnsignedInteger" />.
        /// </summary>
        MustHaveUnsignedIntegerValue = MustHaveValue | MustBeUnsignedInteger,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeWideInteger" />.
        /// </summary>
        MustHaveWideIntegerValue = MustHaveValue | MustBeWideInteger,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeUnsignedWideInteger" />.
        /// </summary>
        MustHaveUnsignedWideIntegerValue = MustHaveValue | MustBeUnsignedWideInteger,

#if NET_40
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeBigInteger" />.
        /// </summary>
        MustHaveBigIntegerValue = MustHaveValue | MustBeBigInteger,
#endif

        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeLevel" />.
        /// </summary>
        MustHaveLevelValue = MustHaveValue | MustBeLevel,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeReturnCode" />.
        /// </summary>
        MustHaveReturnCodeValue = MustHaveValue | MustBeReturnCode,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeDateTime" />.
        /// </summary>
        MustHaveDateTimeValue = MustHaveValue | MustBeDateTime,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeTimeSpan" />.
        /// </summary>
        MustHaveTimeSpanValue = MustHaveValue | MustBeTimeSpan,
        /// <summary>
        /// Combination mask of <see cref="AllowInteger" />, <see cref="MustHaveValue" />, and <see cref="MustBeEnum" />.
        /// </summary>
        MustHaveEnumValue = AllowInteger /* COMPAT: TclTk beta. */ | MustHaveValue | MustBeEnum,
        /// <summary>
        /// Combination mask of <see cref="AllowInteger" />, <see cref="MustHaveValue" />, and <see cref="MustBeEnumList" />.
        /// </summary>
        MustHaveEnumListValue = AllowInteger | MustHaveValue | MustBeEnumList,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeList" />.
        /// </summary>
        MustHaveListValue = MustHaveValue | MustBeList,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeDictionary" />.
        /// </summary>
        MustHaveDictionaryValue = MustHaveValue | MustBeDictionary,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeMatchMode" />.
        /// </summary>
        MustHaveMatchModeValue = MustHaveValue | MustBeMatchMode,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeValue" />.
        /// </summary>
        MustHaveAnyValue = MustHaveValue | MustBeValue,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeObject" />.
        /// </summary>
        MustHaveObjectValue = MustHaveValue | MustBeObject,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeInterpreter" />.
        /// </summary>
        MustHaveInterpreterValue = MustHaveValue | MustBeInterpreter,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeType" />.
        /// </summary>
        MustHaveTypeValue = MustHaveValue | MustBeType,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeTypeList" />.
        /// </summary>
        MustHaveTypeListValue = MustHaveValue | MustBeTypeList,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeAbsoluteUri" />.
        /// </summary>
        MustHaveAbsoluteUriValue = MustHaveValue | MustBeAbsoluteUri,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeVersion" />.
        /// </summary>
        MustHaveVersionValue = MustHaveValue | MustBeVersion,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeReturnCodeList" />.
        /// </summary>
        MustHaveReturnCodeListValue = MustHaveValue | MustBeReturnCodeList,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeIdentifier" />.
        /// </summary>
        MustHaveIdentifierValue = MustHaveValue | MustBeIdentifier,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeAlias" />.
        /// </summary>
        MustHaveAliasValue = MustHaveValue | MustBeAlias,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeOption" />.
        /// </summary>
        MustHaveOptionValue = MustHaveValue | MustBeOption,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeAbsoluteNamespace" />.
        /// </summary>
        MustHaveAbsoluteNamespaceValue = MustHaveValue | MustBeAbsoluteNamespace,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeRelativeNamespace" />.
        /// </summary>
        MustHaveRelativeNamespaceValue = MustHaveValue | MustBeRelativeNamespace,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeCultureInfo" />.
        /// </summary>
        MustHaveCultureInfoValue = MustHaveValue | MustBeCultureInfo,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeByteArray" />.
        /// </summary>
        MustHaveByteArrayValue = MustHaveValue | MustBeByteArray,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeGuid" />.
        /// </summary>
        MustHaveGuidValue = MustHaveValue | MustBeGuid,
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeIndex" />.
        /// </summary>
        MustHaveIndexValue = MustHaveValue | MustBeIndex,

#if NATIVE && TCL
        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeTclInterpreter" />.
        /// </summary>
        MustHaveTclInterpreterValue = MustHaveValue | MustBeTclInterpreter,
#endif

        /// <summary>
        /// Combination mask of <see cref="MustHaveValue" /> and <see cref="MustBeRuleSet" />.
        /// </summary>
        MustHaveRuleSetValue = MustHaveValue | MustBeRuleSet,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The value may be a path, which could then point to a file or
        /// directory.
        /// </summary>
        CouldBePath = 0x400000000000000,          /* Value may be a path, which could then point
                                                   * to a file or directory. */
        /// <summary>
        /// The old option value must be a string or enum.
        /// </summary>
        MatchOldValueType = 0x800000000000000,    /* Old option value must be string or enum. */
        /// <summary>
        /// This option should not be processed.
        /// </summary>
        Ignored = 0x1000000000000000,             /* This option should not be processed. */
        /// <summary>
        /// This option is currently disabled (an error results if used).
        /// </summary>
        Disabled = 0x2000000000000000,            /* This option is currently disabled (error). */
        /// <summary>
        /// This option is not supported by this engine.
        /// </summary>
        Unsupported = 0x4000000000000000,         /* This option is not supported by this engine. */
        /// <summary>
        /// Reserved; do not use.
        /// </summary>
        Reserved = 0x8000000000000000,            /* Reserved, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the core option flags: <see cref="Present" />, <see cref="Strict" />, <see cref="Verbose" />, <see cref="NoCase" />,
        /// <see cref="Unsafe" />, <see cref="Restricted" />, <see cref="System" />, <see cref="AllowInteger" />, and <see cref="MustHaveValue" />.
        /// </summary>
        CoreFlagsMask = Present | Strict | Verbose | NoCase | Unsafe |
                        Restricted | System | AllowInteger | MustHaveValue,

        /// <summary>
        /// Combination mask of <see cref="EndOfOptions" /> and <see cref="ListOfOptions" />.
        /// </summary>
        ScanFlagsMask = EndOfOptions | ListOfOptions,

        /// <summary>
        /// Combination mask of <see cref="CouldBePath" />, <see cref="MatchOldValueType" />, <see cref="Ignored" />, <see cref="Disabled" />, <see cref="Unsupported" />, and <see cref="Reserved" />.
        /// </summary>
        ExtraFlagsMask = CouldBePath | MatchOldValueType | Ignored |
                         Disabled | Unsupported | Reserved,

        /// <summary>
        /// Combination mask of <see cref="CoreFlagsMask" />, <see cref="ScanFlagsMask" />, and <see cref="ExtraFlagsMask" />.
        /// </summary>
        FlagsMask = CoreFlagsMask | ScanFlagsMask | ExtraFlagsMask
    }

