    /// <summary>
    /// This enumeration identifies the kind of interrupt detected or
    /// requested during script execution.  The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("c0fea691-2825-4dc4-940e-adfd35aed8ce")]
    public enum InterruptType
    {
        /// <summary>
        /// No interrupt flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// A script cancellation interrupt.
        /// </summary>
        Canceled = 0x2,
        /// <summary>
        /// A stack-unwinding interrupt.
        /// </summary>
        Unwound = 0x4,
        /// <summary>
        /// A halt interrupt.
        /// </summary>
        Halted = 0x8,
        /// <summary>
        /// The interrupt applies globally, to all interpreters.
        /// </summary>
        Global = 0x10,
        /// <summary>
        /// The interrupt applies locally, to a single interpreter.
        /// </summary>
        Local = 0x20,
        /// <summary>
        /// The interpreter has been (or is being) deleted.
        /// </summary>
        Deleted = 0x40
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the kinds of script-engine events that
    /// can trigger a breakpoint or debugger callback.  The values are bit
    /// flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("7067e9bb-8903-4fc0-b712-83eb26fa5a02")]
    public enum BreakpointType : ulong
    {
        /// <summary>
        /// No breakpoint flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// A reserved bit, used as part of <see cref="EngineCancel" />.
        /// </summary>
        Reserved1 = 0x2,
        /// <summary>
        /// A reserved bit, used as part of <see cref="EngineCode" />.
        /// </summary>
        Reserved2 = 0x4,
        /// <summary>
        /// A reserved bit, used as part of <see cref="EngineTest" />.
        /// </summary>
        Reserved3 = 0x8,
        /// <summary>
        /// A reserved bit, used as part of <see cref="EngineExit" />.
        /// </summary>
        Reserved4 = 0x10,

        /// <summary>
        /// Break for single-stepping execution.
        /// </summary>
        SingleStep = 0x20,
        /// <summary>
        /// Break for multiple-stepping execution.
        /// </summary>
        MultipleStep = 0x40,

        /// <summary>
        /// Break on demand, when explicitly requested.
        /// </summary>
        Demand = 0x80,
        /// <summary>
        /// Break in order to intercept execution.
        /// </summary>
        Intercept = 0x100,
        /// <summary>
        /// Break on token processing.
        /// </summary>
        Token = 0x200,
        /// <summary>
        /// Break on identifier processing.
        /// </summary>
        Identifier = 0x400,

        /// <summary>
        /// Break on cancellation; special due to Interpreter.Ready().
        /// </summary>
        Cancel = 0x800, /* NOTE: Special due to Interpreter.Ready(). */
        /// <summary>
        /// Break on stack unwinding; special due to Interpreter.Ready().
        /// </summary>
        Unwind = 0x1000, /* NOTE: Special due to Interpreter.Ready(). */

        /// <summary>
        /// Break on an error.
        /// </summary>
        Error = 0x2000,
        /// <summary>
        /// Break on a return.
        /// </summary>
        Return = 0x4000,
        /// <summary>
        /// Break on a test.
        /// </summary>
        Test = 0x8000,
        /// <summary>
        /// Break on exit.
        /// </summary>
        Exit = 0x10000,

        /// <summary>
        /// Break on evaluation; only used together with <see cref="Exit" />.
        /// </summary>
        Evaluate = 0x20000,   /* NOTE: Only used together with "Exit". */
        /// <summary>
        /// Break on substitution; only used together with <see cref="Exit" />.
        /// </summary>
        Substitute = 0x40000, /* NOTE: Only used together with "Exit". */

        /// <summary>
        /// Break before text processing.
        /// </summary>
        BeforeText = 0x80000,
        /// <summary>
        /// Break after text processing.
        /// </summary>
        AfterText = 0x100000,
        /// <summary>
        /// Break before backslash-sequence processing.
        /// </summary>
        BeforeBackslash = 0x200000,
        /// <summary>
        /// Break after backslash-sequence processing.
        /// </summary>
        AfterBackslash = 0x400000,
        /// <summary>
        /// Break before unknown-command handling.
        /// </summary>
        BeforeUnknown = 0x800000,
        /// <summary>
        /// Break after unknown-command handling.
        /// </summary>
        AfterUnknown = 0x1000000,

        /// <summary>
        /// Break before expression evaluation.
        /// </summary>
        BeforeExpression = 0x2000000,
        /// <summary>
        /// Break after expression evaluation.
        /// </summary>
        AfterExpression = 0x4000000,
        /// <summary>
        /// Break before an IExecute is invoked.
        /// </summary>
        BeforeIExecute = 0x8000000,
        /// <summary>
        /// Break after an IExecute is invoked.
        /// </summary>
        AfterIExecute = 0x10000000,
        /// <summary>
        /// Break before a command is executed.
        /// </summary>
        BeforeCommand = 0x20000000,
        /// <summary>
        /// Break after a command is executed.
        /// </summary>
        AfterCommand = 0x40000000,
        /// <summary>
        /// Break before a sub-command is executed.
        /// </summary>
        BeforeSubCommand = 0x80000000,
        /// <summary>
        /// Break after a sub-command is executed.
        /// </summary>
        AfterSubCommand = 0x100000000,
        /// <summary>
        /// Break before an operator is evaluated.
        /// </summary>
        BeforeOperator = 0x200000000,
        /// <summary>
        /// Break after an operator is evaluated.
        /// </summary>
        AfterOperator = 0x400000000,
        /// <summary>
        /// Break before a function is evaluated.
        /// </summary>
        BeforeFunction = 0x800000000,
        /// <summary>
        /// Break after a function is evaluated.
        /// </summary>
        AfterFunction = 0x1000000000,
        /// <summary>
        /// Break before a procedure is invoked.
        /// </summary>
        BeforeProcedure = 0x2000000000,
        /// <summary>
        /// Break after a procedure is invoked.
        /// </summary>
        AfterProcedure = 0x4000000000,
        /// <summary>
        /// Break before a procedure body is executed.
        /// </summary>
        BeforeProcedureBody = 0x8000000000,
        /// <summary>
        /// Break after a procedure body is executed.
        /// </summary>
        AfterProcedureBody = 0x10000000000,
        /// <summary>
        /// Break before a lambda body is executed.
        /// </summary>
        BeforeLambdaBody = 0x20000000000,
        /// <summary>
        /// Break after a lambda body is executed.
        /// </summary>
        AfterLambdaBody = 0x40000000000,
        /// <summary>
        /// Break before a variable existence check; not yet implemented.
        /// </summary>
        BeforeVariableExist = 0x80000000000,         /* NOTE: Not yet implemented. */
        /// <summary>
        /// Break before a variable count operation; not yet implemented.
        /// </summary>
        BeforeVariableCount = 0x100000000000,        /* NOTE: Not yet implemented. */
        /// <summary>
        /// Break before a variable value is read.
        /// </summary>
        BeforeVariableGet = 0x200000000000,
        /// <summary>
        /// Break before a variable value is set.
        /// </summary>
        BeforeVariableSet = 0x400000000000,
        /// <summary>
        /// Break before a variable is reset.
        /// </summary>
        BeforeVariableReset = 0x800000000000,
        /// <summary>
        /// Break before a variable is unset.
        /// </summary>
        BeforeVariableUnset = 0x1000000000000,
        /// <summary>
        /// Break before a variable is added.
        /// </summary>
        BeforeVariableAdd = 0x2000000000000,
        /// <summary>
        /// Break before array element names are retrieved; not yet
        /// implemented.
        /// </summary>
        BeforeVariableArrayNames = 0x4000000000000,  /* NOTE: Not yet implemented. */
        /// <summary>
        /// Break before array element values are retrieved; not yet
        /// implemented.
        /// </summary>
        BeforeVariableArrayValues = 0x8000000000000, /* NOTE: Not yet implemented. */
        /// <summary>
        /// Break before an array element is retrieved; not yet
        /// implemented.
        /// </summary>
        BeforeVariableArrayGet = 0x10000000000000, /* NOTE: Not yet implemented. */

        /// <summary>
        /// Break before the interactive loop runs.
        /// </summary>
        BeforeInteractiveLoop = 0x20000000000000,
        /// <summary>
        /// Break after the interactive loop runs.
        /// </summary>
        AfterInteractiveLoop = 0x40000000000000,

        /// <summary>
        /// Combination mask of <see cref="BeforeVariableGet" />, <see cref="BeforeVariableSet" />, and <see cref="BeforeVariableUnset" />.
        /// </summary>
        BeforeVariableCommon = BeforeVariableGet | BeforeVariableSet | BeforeVariableUnset,

        /// <summary>
        /// Combination mask of <see cref="BeforeVariableExist" /> and <see cref="BeforeVariableCount" />.
        /// </summary>
        BeforeVariableMeta = BeforeVariableExist | BeforeVariableCount,

        /// <summary>
        /// Combination mask of <see cref="BeforeVariableArrayNames" />, <see cref="BeforeVariableArrayValues" />, and <see cref="BeforeVariableArrayGet" />.
        /// </summary>
        BeforeVariableArray = BeforeVariableArrayNames | BeforeVariableArrayValues |
                              BeforeVariableArrayGet,

        /// <summary>
        /// Combination mask of <see cref="BeforeVariableCommon" /> and <see cref="BeforeVariableMeta" />.
        /// </summary>
        BeforeVariableScalar = BeforeVariableCommon | BeforeVariableMeta,

        /// <summary>
        /// Combination mask of <see cref="BeforeVariableExist" /> and <see cref="BeforeVariableCount" />.
        /// </summary>
        BeforeVariableSpecialRead = BeforeVariableExist | BeforeVariableCount,
        /// <summary>
        /// Combination mask of <see cref="BeforeVariableReset" /> and <see cref="BeforeVariableAdd" />.
        /// </summary>
        BeforeVariableSpecialWrite = BeforeVariableReset | BeforeVariableAdd,
        /// <summary>
        /// Combination mask of <see cref="BeforeVariableSpecialRead" /> and <see cref="BeforeVariableSpecialWrite" />.
        /// </summary>
        BeforeVariableSpecialAny = BeforeVariableSpecialRead | BeforeVariableSpecialWrite,

        /// <summary>
        /// Combination mask of <see cref="BeforeVariableCommon" />, <see cref="BeforeVariableArray" />, <see cref="BeforeVariableMeta" />, and <see cref="BeforeVariableSpecialAny" />.
        /// </summary>
        BeforeVariable = BeforeVariableCommon | BeforeVariableArray | BeforeVariableMeta |
                         BeforeVariableSpecialAny,

        /// <summary>
        /// Combination mask of <see cref="Reserved1" />, <see cref="Cancel" />, and <see cref="Unwind" />.
        /// </summary>
        EngineCancel = Reserved1 | Cancel | Unwind,
        /// <summary>
        /// Combination mask of <see cref="Reserved2" />, <see cref="Error" />, and <see cref="Return" />.
        /// </summary>
        EngineCode = Reserved2 | Error | Return,
        /// <summary>
        /// Combination mask of <see cref="Reserved3" /> and <see cref="Test" />.
        /// </summary>
        EngineTest = Reserved3 | Test,
        /// <summary>
        /// Combination mask of <see cref="Reserved4" />, <see cref="Exit" />, <see cref="Evaluate" />, and <see cref="Substitute" />.
        /// </summary>
        EngineExit = Reserved4 | Exit | Evaluate | Substitute,

        /// <summary>
        /// Combination mask of <see cref="BeforeText" /> and <see cref="AfterText" />.
        /// </summary>
        Text = BeforeText | AfterText,
        /// <summary>
        /// Combination mask of <see cref="BeforeBackslash" /> and <see cref="AfterBackslash" />.
        /// </summary>
        Backslash = BeforeBackslash | AfterBackslash,
        /// <summary>
        /// Combination mask of <see cref="BeforeUnknown" /> and <see cref="AfterUnknown" />.
        /// </summary>
        Unknown = BeforeUnknown | AfterUnknown,
        /// <summary>
        /// Combination mask of <see cref="BeforeExpression" /> and <see cref="AfterExpression" />.
        /// </summary>
        Expression = BeforeExpression | AfterExpression,
        /// <summary>
        /// Combination mask of <see cref="BeforeIExecute" /> and <see cref="AfterIExecute" />.
        /// </summary>
        IExecute = BeforeIExecute | AfterIExecute,
        /// <summary>
        /// Combination mask of <see cref="BeforeCommand" /> and <see cref="AfterCommand" />.
        /// </summary>
        Command = BeforeCommand | AfterCommand,
        /// <summary>
        /// Combination mask of <see cref="BeforeOperator" /> and <see cref="AfterOperator" />.
        /// </summary>
        Operator = BeforeOperator | AfterOperator,
        /// <summary>
        /// Combination mask of <see cref="BeforeFunction" /> and <see cref="AfterFunction" />.
        /// </summary>
        Function = BeforeFunction | AfterFunction,
        /// <summary>
        /// Combination mask of <see cref="BeforeProcedure" /> and <see cref="AfterProcedure" />.
        /// </summary>
        Procedure = BeforeProcedure | AfterProcedure,
        /// <summary>
        /// Combination mask of <see cref="BeforeProcedureBody" /> and <see cref="AfterProcedureBody" />.
        /// </summary>
        ProcedureBody = BeforeProcedureBody | AfterProcedureBody,
        /// <summary>
        /// Combination mask of <see cref="BeforeLambdaBody" /> and <see cref="AfterLambdaBody" />.
        /// </summary>
        Lambda = BeforeLambdaBody | AfterLambdaBody,

        /// <summary>
        /// Combination mask of all of the "Before" stepping breakpoint
        /// types.
        /// </summary>
        BeforeStep = BeforeText | BeforeBackslash | BeforeUnknown |
                     BeforeExpression | BeforeIExecute | BeforeCommand |
                     BeforeSubCommand | BeforeOperator | BeforeFunction |
                     BeforeProcedure | BeforeLambdaBody,

        /// <summary>
        /// Combination mask of all of the "After" stepping breakpoint
        /// types.
        /// </summary>
        AfterStep = AfterText | AfterBackslash | AfterUnknown |
                    AfterExpression | AfterIExecute | AfterCommand |
                    AfterSubCommand | AfterOperator | AfterFunction |
                    AfterProcedure | AfterLambdaBody,

        /// <summary>
        /// Combination mask of the variable-related stepping breakpoint
        /// types.
        /// </summary>
        VariableStep = BeforeVariableExist | BeforeVariableGet | BeforeVariableSet |
                       BeforeVariableReset | BeforeVariableUnset | BeforeVariableAdd |
                       BeforeVariableArrayNames | BeforeVariableArrayValues,

        /// <summary>
        /// Combination mask of the commonly used breakpoint types.
        /// </summary>
        Common = Demand | Identifier | EngineCancel |
                 EngineTest | EngineExit | BeforeStep |
                 VariableStep,

        /// <summary>
        /// Combination mask of <see cref="Common" /> and <see cref="Token" />.
        /// </summary>
        Standard = Common | Token,

        /// <summary>
        /// Combination mask of <see cref="Cancel" /> and <see cref="Unwind" />.
        /// </summary>
        Ready = Cancel | Unwind,

        /// <summary>
        /// Combination mask of <see cref="Intercept" /> and <see cref="Exit" />.
        /// </summary>
        InterceptExit = Intercept | Exit,

        //
        // NOTE: No tokens, no expressions (too noisy).
        //
        /// <summary>
        /// The express breakpoint set: <see cref="Common" /> with expression, operator, and
        /// function breakpoints removed because they are too noisy.
        /// </summary>
        Express = Common & ~(Expression | Operator | Function),

        //
        // NOTE: The default breakpoint types.
        //
        /// <summary>
        /// The default breakpoint types, equal to <see cref="Express" />.
        /// </summary>
        Default = Express,

        //
        // NOTE: All possible breakpoint types.
        //
        /// <summary>
        /// Combination mask of all possible breakpoint types.
        /// </summary>
        All = SingleStep | MultipleStep | Demand |
              Token | Identifier | EngineCancel |
              EngineCode | EngineTest | EngineExit |
              BeforeStep | AfterStep | VariableStep
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the matching strategy and the modifier
    /// flags used when comparing values against patterns throughout TclTk
    /// (for example, in <c>[switch]</c>, <c>[string match]</c>,
    /// <c>[regexp]</c>, and list filtering operations).  The values are
    /// bit flags that may be combined to select a mode together with case
    /// sensitivity and other behavioral options.
    /// </summary>
    [Flags()]
    [ObjectId("9b351955-a5dd-4306-b6c2-d510d332c353")]
    public enum MatchMode : ulong
    {
        /// <summary>
        /// No flags are set; the matcher does nothing.
        /// </summary>
        None = 0x0,                 /* Do nothing. */
        /// <summary>
        /// A reserved sentinel indicating an invalid mode; callers should
        /// not use this value.
        /// </summary>
        Invalid = 0x1,              /* Invalid, do not use. */

        /// <summary>
        /// Matching is performed by an application- or plugin-defined
        /// callback.
        /// </summary>
        Callback = 0x2,             /* (application/plugin defined) */
        /// <summary>
        /// Matching uses exact string equality (e.g.
        /// <c>[string equal]</c>).
        /// </summary>
        Exact = 0x4,                /* (e.g. [string equal], etc) */
        /// <summary>
        /// Matching succeeds when the value begins with the pattern (e.g.
        /// a "starts with" comparison).
        /// </summary>
        SubString = 0x8,            /* (e.g. "starts with", etc) */
        /// <summary>
        /// Matching uses glob-style patterns (e.g. <c>[string match]</c>).
        /// </summary>
        Glob = 0x10,                /* (e.g. [string match], etc) */
        /// <summary>
        /// Matching uses regular expressions (e.g. <c>[regexp]</c>).
        /// </summary>
        RegExp = 0x20,              /* (e.g. [regexp], etc) */
        /// <summary>
        /// Matching compares integer values (e.g. <c>[switch]</c>).
        /// </summary>
        Integer = 0x40,             /* (e.g. [switch], etc) */
        /// <summary>
        /// Matching compares floating-point values within DoubleEpsilon.
        /// </summary>
        Double = 0x80,              /* within DoubleEpsilon. */
        /// <summary>
        /// Matching compares decimal values within DecimalEpsilon.
        /// </summary>
        Decimal = 0x100,            /* within DecimalEpsilon. */
        /// <summary>
        /// Matching compares network addresses using CIDR notation (e.g.
        /// SocketOps.MatchViaCIDR).
        /// </summary>
        CIDR = 0x200,               /* (e.g. SocketOps.MatchViaCIDR) */

        // ...

        /// <summary>
        /// Matching performs substitution on the pattern (e.g.
        /// <c>[switch]</c>).
        /// </summary>
        Substitute = 0x1000,        /* (e.g. [switch], etc) */
        /// <summary>
        /// Matching evaluates the pattern as an expression (e.g.
        /// <c>[test1]</c>, <c>[test2]</c>).
        /// </summary>
        Expression = 0x2000,        /* (e.g. [test1], [test2], etc) */
        /// <summary>
        /// Matching evaluates the pattern as a script (e.g.
        /// <c>[string map]</c>).
        /// </summary>
        Evaluate = 0x4000,          /* (e.g. [string map], etc) */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Ignore case sensitivity while matching.
        /// </summary>
        NoCase = 0x10000,           /* Ignore case-sensitivity. */
        /// <summary>
        /// Force case sensitivity while matching.
        /// </summary>
        ForceCase = 0x20000,        /* Force case-sensitivity. */
        /// <summary>
        /// Enable sub-pattern syntax (e.g. the <c>{a,b,c}</c> form).
        /// </summary>
        SubPattern = 0x40000,       /* (e.g. {a,b,c} syntax) */
        /// <summary>
        /// Permit empty sub-patterns.
        /// </summary>
        EmptySubPattern = 0x80000,  /* Permit empty sub-patterns. */
        /// <summary>
        /// Compare strings using ordinal (system string) semantics.
        /// </summary>
        SystemString = 0x100000,    /* Compare using ordinals. */
        /// <summary>
        /// Compare values as file system paths.
        /// </summary>
        PathString = 0x200000,      /* Compare as file paths. */
        /// <summary>
        /// Replace a text token within the pattern.
        /// </summary>
        TextToken = 0x400000,       /* Replace text token in pattern. */
        /// <summary>
        /// Treat the pattern as a list (of patterns or items).
        /// </summary>
        ListPattern = 0x800000,     /* Treat pattern as a list (of something). */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Replace the text token verbatim.
        /// </summary>
        TextTokenRaw = 0x1000000,   /* Replace text token verbatim. */
        /// <summary>
        /// Replace the text token with a list-quoted string.
        /// </summary>
        TextTokenQuote = 0x2000000, /* Replace text token with (list) quoted string. */
        /// <summary>
        /// Replace the text token with the string as the sole list
        /// element.
        /// </summary>
        TextTokenList = 0x4000000,  /* Replace text token with string as (sole) list element. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Meta flag: stop on the first matching hit, if any.
        /// </summary>
        StopOnMatch = 0x10000000,   /* Meta: Stop on the first match hit, if any. */
        /// <summary>
        /// Meta flag: stop on the first error encountered, if any.
        /// </summary>
        StopOnError = 0x20000000,   /* Meta: Stop on the first error hit, if any. */
        /// <summary>
        /// Meta flag: a match of any one pattern is sufficient, not all.
        /// </summary>
        Any = 0x40000000,           /* Meta: Must match one, not all. */
        /// <summary>
        /// Meta flag: every pattern must match, not just one.
        /// </summary>
        All = 0x80000000,           /* Meta: Must match all, not just one. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Meta flag: used when including an item in a collection.
        /// </summary>
        Include = 0x100000000,      /* Meta: Used for including item in collection. */
        /// <summary>
        /// Meta flag: used when excluding an item from a collection.
        /// </summary>
        Exclude = 0x200000000,      /* Meta: Used for excluding item in collection. */

        /// <summary>
        /// Meta flag: used when showing items in a collection.
        /// </summary>
        Show = 0x4000000000,        /* Meta: Used for showing items in collection. */
        /// <summary>
        /// Meta flag: used when hiding items in a collection.
        /// </summary>
        Hide = 0x8000000000,        /* Meta: Used for hiding items in collection. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="TextTokenRaw" />,
        /// <see cref="TextTokenQuote" />, and
        /// <see cref="TextTokenList" />.
        /// </summary>
        TextTokenFlagsMask = TextTokenRaw | TextTokenQuote | TextTokenList,

        /// <summary>
        /// Combination mask of <see cref="StopOnError" />,
        /// <see cref="Any" />, and <see cref="All" />.
        /// </summary>
        MetaFlagsMask = StopOnError | Any | All,

        /// <summary>
        /// Combination mask of <see cref="Include" />,
        /// <see cref="Exclude" />, <see cref="Show" />, and
        /// <see cref="Hide" />.
        /// </summary>
        ActionFlagsMask = Include | Exclude | Show | Hide,

        /// <summary>
        /// Combination mask of <see cref="StopOnError" /> and
        /// <see cref="All" />.
        /// </summary>
        RuleSetMask = StopOnError | All,

        /// <summary>
        /// Combination mask of <see cref="RuleSetMask" /> and
        /// <see cref="Include" />.
        /// </summary>
        IncludeRuleSetMask = RuleSetMask | Include,
        /// <summary>
        /// Combination mask of <see cref="RuleSetMask" /> and
        /// <see cref="Exclude" />.
        /// </summary>
        ExcludeRuleSetMask = RuleSetMask | Exclude,

        /// <summary>
        /// Combination mask of <see cref="RuleSetMask" /> and
        /// <see cref="Show" />.
        /// </summary>
        ShowRuleSetMask = RuleSetMask | Show,
        /// <summary>
        /// Combination mask of <see cref="RuleSetMask" /> and
        /// <see cref="Hide" />.
        /// </summary>
        HideRuleSetMask = RuleSetMask | Hide,

        /// <summary>
        /// Combination mask of the simple matching modes:
        /// <see cref="Callback" />, <see cref="Exact" />,
        /// <see cref="SubString" />, <see cref="Glob" />,
        /// <see cref="RegExp" />, <see cref="Integer" />,
        /// <see cref="Decimal" />, and <see cref="Double" />.
        /// </summary>
        SimpleModeMask = Callback | Exact | SubString |
                         Glob | RegExp | Integer |
                         Decimal | Double,

        /// <summary>
        /// Combination mask of the complex matching modes:
        /// <see cref="Substitute" />, <see cref="Expression" />, and
        /// <see cref="Evaluate" />.
        /// </summary>
        ComplexModeMask = Substitute | Expression | Evaluate,

        /// <summary>
        /// Combination mask of <see cref="SimpleModeMask" /> and
        /// <see cref="ComplexModeMask" />.
        /// </summary>
        ModeMask = SimpleModeMask | ComplexModeMask,

        /// <summary>
        /// Combination mask of the matching modifier flags, including
        /// <see cref="NoCase" />, <see cref="ForceCase" />,
        /// <see cref="SubPattern" />, <see cref="EmptySubPattern" />,
        /// <see cref="PathString" />, <see cref="SystemString" />,
        /// <see cref="TextTokenFlagsMask" />, <see cref="ListPattern" />,
        /// <see cref="MetaFlagsMask" />, and
        /// <see cref="ActionFlagsMask" />.
        /// </summary>
        FlagsMask = NoCase | ForceCase | SubPattern |
                    EmptySubPattern | PathString |
                    SystemString | TextTokenFlagsMask |
                    ListPattern | MetaFlagsMask |
                    ActionFlagsMask
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how call frame levels are interpreted and
    /// searched when locating a stack frame.  The values are bit flags
    /// that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("040e4c44-a268-4d36-99d0-cc3c80373681")]
    public enum LevelFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Allow levels counted from the global call frame inward.
        /// </summary>
        Absolute = 0x2,  /* allow levels from the global frame inward. */
        /// <summary>
        /// Allow levels counted from the current call frame outward.
        /// </summary>
        Relative = 0x4,  /* allow levels from the current frame outward. */
        /// <summary>
        /// Include otherwise invisible call frames in the search.
        /// </summary>
        Invisible = 0x8, /* include otherwise invisible call frames. */

        //
        // NOTE: Tcl compatible call frame search semantics.
        //
        /// <summary>
        /// Combination mask of <see cref="Absolute" /> and
        /// <see cref="Relative" />, providing Tcl-compatible call frame
        /// search semantics.
        /// </summary>
        Default = Absolute | Relative,

        //
        // NOTE: Tcl compatible call frame search semantics
        //       with TclTk extensions (allows "invisible"
        //       call frames to be seen).
        //
        /// <summary>
        /// Combination mask of <see cref="Absolute" />,
        /// <see cref="Relative" />, and <see cref="Invisible" /> (the Tcl
        /// semantics plus the TclTk extension permitting invisible call
        /// frames to be seen).
        /// </summary>
        All = Absolute | Relative | Invisible
    }

