        /// </summary>
        RawArray = 0x4,
        /// <summary>
        /// Return the results as a raw list.
        /// </summary>
        RawList = 0x8,
        /// <summary>
        /// Return the results as an array.
        /// </summary>
        Array = 0x10,
        /// <summary>
        /// Return the results as a list.
