        /// <see cref="NestedDictionary" />, <see cref="DataReader" />,
        /// <see cref="DataRecord" />, and <see cref="DataTable" />.
        /// </summary>
        FormatMask = RawArray | RawList | Array |
                     List | Dictionary | NestedList |
                     NestedDictionary | DataReader |
                     DataRecord | DataTable,

        /// <summary>
        /// Combination mask of <see cref="Reserved" /> and
        /// <see cref="Array" />, used as the default result format.
        /// </summary>
        Default = Reserved | Array /* TODO: Good default? */
    }

