    /// <summary>
    /// This enumeration selects how a date/time value is represented when
    /// it is converted to its external form.
    /// </summary>
    [ObjectId("8e169a10-f996-4ccf-add2-219e330ae1c4")]
    public enum DateTimeBehavior
    {
        /// <summary>
        /// No specific behavior is selected.
        /// </summary>
        None = 0,
        /// <summary>
        /// Represent the value as the number of 100-nanosecond units
        /// elapsed since the start of time, 00:00:00.0000000 January 1st,
        /// 0001.
        /// </summary>
        Ticks = 1,         /* Number of 100-nanosecond units since the start-of-time,
                            * 00:00:00.0000000 January 1st, 0001. */
        /// <summary>
        /// Represent the value as the number of seconds elapsed since the
        /// standard Unix epoch, 00:00:00.0000000 January 1st, 1970.
        /// </summary>
        Seconds = 2,       /* Number of seconds since the standard Unix epoch,
                            * 00:00:00.0000000 January 1st, 1970. */
        /// <summary>
        /// Convert the value to a string using the specified or default
        /// format.
        /// </summary>
        ToString = 3,      /* Convert to a string using the specified or default
                            * format. */
        /// <summary>
        /// The default behavior; equivalent to <see cref="ToString" />.
        /// </summary>
        Default = ToString /* TODO: Good default? */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration selects how a binary large object (BLOB) value is
    /// represented or rendered.
    /// </summary>
    [ObjectId("3dc48f23-466b-4157-937a-d8a1177f9066")]
    public enum BlobBehavior
    {
        /// <summary>
        /// No specific behavior is selected.
        /// </summary>
        None = 0,
        /// <summary>
        /// Render the value as a list (retained for TclTk beta
        /// compatibility).
        /// </summary>
        List = 0x1, /* COMPAT: TclTk beta. */
        /// <summary>
        /// Render the value as a formatted hexadecimal/character dump.
        /// </summary>
        Dump = 0x2,
        /// <summary>
        /// Represent the value as an opaque object.
        /// </summary>
        Object = 0x4,
        /// <summary>
        /// Render the value as Base64-encoded text.
        /// </summary>
        Base64 = 0x8,
        /// <summary>
        /// Render the value as hexadecimal text.
        /// </summary>
        Hexadecimal = 0x10,
        /// <summary>
        /// Use the raw bytes of the value verbatim.
        /// </summary>
        Raw = 0x20,
        /// <summary>
        /// The representation of the value is unknown.
        /// </summary>
        Unknown = 0x40,
        /// <summary>
        /// The default behavior; equivalent to <see cref="List" />.
        /// </summary>
        Default = List
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies which database operations are permitted
    /// for a bound variable in TclTk's optional data access support.  The
    /// values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("21275a46-4292-4c42-ac70-9875dd6c2b2f")]
    public enum DbVariableFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Permit access even when no specific operation is requested.
        /// </summary>
        AllowNone = 0x2,
        /// <summary>
        /// Permit SELECT operations.
        /// </summary>
        AllowSelect = 0x4,
        /// <summary>
        /// Permit INSERT operations.
        /// </summary>
        AllowInsert = 0x8,
        /// <summary>
        /// Permit UPDATE operations.
        /// </summary>
        AllowUpdate = 0x10,
        /// <summary>
        /// Permit DELETE operations.
        /// </summary>
        AllowDelete = 0x20,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllowNone" /> and
        /// <see cref="AllowSelect" />, permitting read access.
        /// </summary>
        AllowRead = AllowNone | AllowSelect,

        /// <summary>
        /// Combination mask of <see cref="AllowNone" />,
        /// <see cref="AllowInsert" />, <see cref="AllowUpdate" />, and
        /// <see cref="AllowDelete" />, permitting write access.
        /// </summary>
        AllowWrite = AllowNone | AllowInsert | AllowUpdate |
                     AllowDelete,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllowRead" /> and
        /// <see cref="AllowWrite" />.
        /// </summary>
        AllowAll = AllowRead | AllowWrite,
        /// <summary>
        /// The default flags; equivalent to <see cref="AllowAll" />.
        /// </summary>
        Default = AllowAll
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration selects how a database command is executed and
    /// what kind of result it produces.  The values are bit flags that may
    /// be combined.
    /// </summary>
    [Flags()]
    [ObjectId("f517d99f-5f81-4663-8aec-0e071568d36d")]
    public enum DbExecuteType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Reserved for internal use.
        /// </summary>
        Reserved = 0x2,

        /// <summary>
        /// Execute the command as a non-query (no result set).
        /// </summary>
        NonQuery = 0x4,
        /// <summary>
        /// Execute the command and return a single scalar value.
        /// </summary>
        Scalar = 0x8,
        /// <summary>
        /// Execute the command and return a data reader.
        /// </summary>
        Reader = 0x10,
        /// <summary>
        /// Execute the command and return a data reader together with a
        /// row count.
        /// </summary>
        ReaderAndCount = 0x20,
        /// <summary>
        /// Execute the command and return a data table.
        /// </summary>
        DataTable = 0x40,

        /// <summary>
        /// Combination mask of all execution types:
        /// <see cref="NonQuery" />, <see cref="Scalar" />,
        /// <see cref="Reader" />, <see cref="ReaderAndCount" />, and
        /// <see cref="DataTable" />.
        /// </summary>
        TypeMask = NonQuery | Scalar | Reader |
                   ReaderAndCount | DataTable,

        /// <summary>
        /// Combination mask of <see cref="Reserved" /> and
        /// <see cref="NonQuery" />, used as the default execution type.
        /// </summary>
        Default = Reserved | NonQuery /* TODO: Good default? */
    }

