    [Flags()]
    [ObjectId("5c7e322d-2044-42f0-9545-7f05b80f14dc")]
    public enum DbConnectionType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Reserved for internal use.
        /// </summary>
        Reserved = 0x2,

        /// <summary>
        /// Connect using an ODBC provider.
        /// </summary>
        Odbc = 0x4,
        /// <summary>
        /// Connect using an OLE DB provider.
        /// </summary>
        OleDb = 0x8,
        /// <summary>
        /// Connect to an Oracle database.
        /// </summary>
        Oracle = 0x10,
        /// <summary>
        /// Connect to Microsoft SQL Server.
        /// </summary>
        Sql = 0x20,
        /// <summary>
        /// Connect to SQL Server Compact Edition.
        /// </summary>
        SqlCe = 0x40,

        /// <summary>
        /// Connect to a SQLite database.
        /// </summary>
        SQLite = 0x80,            /* COMPAT: Branding. */
        /// <summary>
        /// Connect to a SQLite Enterprise database.
        /// </summary>
        SQLiteEnterprise = 0x100, /* COMPAT: Branding. */

        /// <summary>
        /// Connect using some other, unspecified backend.
        /// </summary>
        Other = 0x1000,

        /// <summary>
        /// Combination mask of all supported backends:
        /// <see cref="Odbc" />, <see cref="OleDb" />,
        /// <see cref="Oracle" />, <see cref="Sql" />,
        /// <see cref="SqlCe" />, <see cref="SQLite" />,
        /// <see cref="SQLiteEnterprise" />, and <see cref="Other" />.
        /// </summary>
        TypeMask = Odbc | OleDb | Oracle |
                   Sql | SqlCe | SQLite |
                   SQLiteEnterprise | Other,

        /// <summary>
        /// Combination mask of <see cref="Reserved" /> and
        /// <see cref="Sql" />, used as the default connection type.
        /// </summary>
        Default = Reserved | Sql /* TODO: Good default? */
    }
