    /// <summary>
    /// This enumeration identifies the kind of entity that a given
    /// identifier names within an interpreter (for example, a command,
    /// procedure, variable, or namespace).  The values are bit flags that
    /// may be combined to qualify an entity kind with additional
    /// attributes.
    /// </summary>
    [Flags()]
    [ObjectId("753458ab-2ef9-4934-83d7-f8a96effc9cc")]
    public enum IdentifierKind : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The identifier names an interpreter.
        /// </summary>
        Interpreter = 0x2,
        /// <summary>
        /// The identifier names a policy.
        /// </summary>
        Policy = 0x4,
        /// <summary>
        /// The identifier names a trace.
        /// </summary>
        Trace = 0x8,
        /// <summary>
        /// The identifier names a command.
        /// </summary>
        Command = 0x10,
        /// <summary>
        /// The identifier names a sub-command.
        /// </summary>
        SubCommand = 0x20,
        /// <summary>
        /// The identifier names a procedure.
        /// </summary>
        Procedure = 0x40,
        /// <summary>
        /// The identifier names an object implementing IExecute.
        /// </summary>
        IExecute = 0x80,
        /// <summary>
        /// The identifier names a lambda (anonymous procedure).
        /// </summary>
        Lambda = 0x100,
        /// <summary>
        /// The identifier names an expression operator.
        /// </summary>
        Operator = 0x200,
        /// <summary>
        /// The identifier names an expression function.
        /// </summary>
        Function = 0x400,
        /// <summary>
        /// The identifier names an ensemble command.
        /// </summary>
        Ensemble = 0x800,
        /// <summary>
        /// The identifier names a variable.
        /// </summary>
        Variable = 0x1000,
        /// <summary>
        /// The identifier names a call frame.
        /// </summary>
        CallFrame = 0x2000,
        /// <summary>
        /// The identifier names a package.
        /// </summary>
        Package = 0x4000,
        /// <summary>
        /// The identifier names a plugin.
        /// </summary>
        Plugin = 0x8000,
        /// <summary>
        /// The identifier names an opaque object handle.
        /// </summary>
        Object = 0x10000,
        /// <summary>
        /// The identifier names an object type.
        /// </summary>
        ObjectType = 0x20000,
        /// <summary>
        /// The identifier names an option.
        /// </summary>
        Option = 0x40000,
        /// <summary>
        /// The identifier names a (native) module.
        /// </summary>
        Module = 0x80000,
        /// <summary>
        /// The identifier names an interpreter host.
        /// </summary>
        Host = 0x100000,
        /// <summary>
        /// The identifier names an alias.
        /// </summary>
        Alias = 0x200000,
        /// <summary>
        /// The identifier names a delegate.
        /// </summary>
        Delegate = 0x400000,
        /// <summary>
        /// The identifier names a sub-delegate.
        /// </summary>
        SubDelegate = 0x800000,
        /// <summary>
        /// The identifier was generated automatically.
        /// </summary>
        Automatic = 0x1000000,
        /// <summary>
        /// The identifier names a callback.
        /// </summary>
        Callback = 0x2000000,
        /// <summary>
        /// The identifier names a resolver.
        /// </summary>
        Resolve = 0x4000000,
        /// <summary>
        /// The identifier names a clock.
        /// </summary>
        Clock = 0x8000000,
        /// <summary>
        /// The identifier names a script.
        /// </summary>
        Script = 0x10000000,
        /// <summary>
        /// The identifier names a script builder.
        /// </summary>
        ScriptBuilder = 0x20000000,
        /// <summary>
        /// The identifier names a namespace.
        /// </summary>
        Namespace = 0x40000000,
        /// <summary>
        /// The identifier names an interactive loop.
        /// </summary>
        InteractiveLoop = 0x80000000,
        /// <summary>
        /// The identifier names a shell callback.
        /// </summary>
        ShellCallback = 0x100000000,
        /// <summary>
        /// The identifier names an update.
        /// </summary>
        Update = 0x200000000,
        /// <summary>
        /// The identifier names a cryptographic key pair.
        /// </summary>
        KeyPair = 0x400000000,
        /// <summary>
        /// The identifier names a certificate.
        /// </summary>
        Certificate = 0x800000000,
        /// <summary>
        /// The identifier names a key ring.
        /// </summary>
        KeyRing = 0x1000000000,
        /// <summary>
        /// The identifier names an I/O channel.
        /// </summary>
        Channel = 0x2000000000,
        /// <summary>
        /// The identifier names a file system path.
        /// </summary>
        Path = 0x4000000000,
        /// <summary>
        /// The identifier names a URI.
        /// </summary>
        Uri = 0x8000000000,
        /// <summary>
        /// The identifier names a (managed) type.
        /// </summary>
        Type = 0x10000000000,
        /// <summary>
        /// The identifier names a hash.
        /// </summary>
        Hash = 0x20000000000,
        /// <summary>
        /// The identifier names a context.
        /// </summary>
        Context = 0x40000000000,
        /// <summary>
        /// The identifier names a secret.
        /// </summary>
        Secret = 0x80000000000,
        /// <summary>
        /// The identifier names a script snippet.
        /// </summary>
        Snippet = 0x100000000000,
        /// <summary>
        /// The identifier names a scope.
        /// </summary>
        Scope = 0x200000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The identifier names a database connection.
        /// </summary>
        DbConnection = 0x400000000000,
        /// <summary>
        /// The identifier names a database transaction.
        /// </summary>
        DbTransaction = 0x800000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Meta flag: matches any kind of identifier.
        /// </summary>
        Any = 0x400000000000000,
        /// <summary>
        /// Meta flag: the identifier carries associated data.
        /// </summary>
        Data = 0x800000000000000,
        /// <summary>
