        /// </summary>
        Saved = 0x8000000000000000,

        /// <summary>
        /// Combination mask of <see cref="Any" />, <see cref="Data" />,
        /// <see cref="Hidden" />, <see cref="Native" />,
        /// <see cref="Trusted" />, and <see cref="Saved" />.
        /// </summary>
        FlagsMask = Any | Data | Hidden | Native | Trusted | Saved,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Any" /> and
        /// <see cref="IExecute" />.
        /// </summary>
        AnyIExecute = Any | IExecute,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Policy" /> and
        /// <see cref="Data" />.
        /// </summary>
        PolicyData = Policy | Data,
        /// <summary>
        /// Combination mask of <see cref="Trace" /> and
        /// <see cref="Data" />.
        /// </summary>
        TraceData = Trace | Data,
        /// <summary>
        /// Combination mask of <see cref="Command" /> and
