        /// </summary>
        CommandData = Command | Data,
        /// <summary>
        /// Combination mask of <see cref="SubCommand" /> and
        /// <see cref="Data" />.
        /// </summary>
        SubCommandData = SubCommand | Data,
        /// <summary>
        /// Combination mask of <see cref="Procedure" /> and
        /// <see cref="Data" />.
        /// </summary>
        ProcedureData = Procedure | Data,
        /// <summary>
        /// Combination mask of <see cref="Lambda" /> and
        /// <see cref="Data" />.
        /// </summary>
        LambdaData = Lambda | Data,
        /// <summary>
        /// Combination mask of <see cref="Operator" /> and
        /// <see cref="Data" />.
        /// </summary>
        OperatorData = Operator | Data,
        /// <summary>
        /// Combination mask of <see cref="Function" /> and
        /// <see cref="Data" />.
        /// </summary>
        FunctionData = Function | Data,
        /// <summary>
        /// Combination mask of <see cref="Ensemble" /> and
