        /// Combination mask of <see cref="Path" /> and
        /// <see cref="Trusted" />.
        /// </summary>
        TrustedPath = Path | Trusted,
        /// <summary>
        /// Combination mask of <see cref="Uri" /> and
        /// <see cref="Trusted" />.
        /// </summary>
        TrustedUri = Uri | Trusted,
        /// <summary>
        /// Combination mask of <see cref="Type" /> and
        /// <see cref="Trusted" />.
        /// </summary>
        TrustedType = Type | Trusted,
        /// <summary>
        /// Combination mask of <see cref="Hash" /> and
        /// <see cref="Trusted" />.
        /// </summary>
        TrustedHash = Hash | Trusted
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the state and behavioral options
    /// associated with an TclTk stream or channel, including end-of-line
    /// processing and socket characteristics.  The values are bit flags
    /// that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("a7a543b2-f7a1-408a-84ec-06bcf541c6c8")]
    public enum StreamFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */
        /// <summary>
        /// When set, reject all Close and Dispose requests.
        /// </summary>
        PreventClose = 0x2,          /* When set, reject all Close and Dispose requests. */
        /// <summary>
        /// A carriage-return has been seen while processing input.
        /// </summary>
        SawCarriageReturn = 0x4,     /* A carriage-return has been seen while processing input. */
        /// <summary>
        /// A line-feed is needed while processing input.
        /// </summary>
        NeedLineFeed = 0x8,          /* A line-feed is needed while processing input. */
        /// <summary>
        /// An extra carriage-return has been seen while processing input.
        /// </summary>
        ExtraCarriageReturn = 0x10,  /* A carriage-return has been seen while processing input. */
        /// <summary>
        /// A line-feed was seen without a preceding carriage-return.
        /// </summary>
        ExtraLineFeed = 0x20,        /* A line-feed was seen without a carriage-return. */
        /// <summary>
        /// Any end-of-line character may terminate an input line.
        /// </summary>
        UseAnyEndOfLineChar = 0x40,  /* Any end-of-line character can terminate an input line. */
        /// <summary>
        /// Keep the end-of-line characters from the input line.
        /// </summary>
        KeepEndOfLineChars = 0x80,   /* Keep end-of-line characters from input line. */
        /// <summary>
        /// The stream is a socket.
        /// </summary>
        Socket = 0x100,              /* The stream is a socket. */
        /// <summary>
        /// The stream contains a client socket.
        /// </summary>
        Client = 0x200,              /* The stream contains a client socket. */
        /// <summary>
        /// The stream contains a server socket.
        /// </summary>
        Server = 0x400,              /* The stream contains a server socket. */
        /// <summary>
        /// The stream contains a listening socket.
        /// </summary>
        Listen = 0x800,              /* The stream contains a listen socket. */
        /// <summary>
        /// Enable buffering when adding channels.
        /// </summary>
        NeedBuffer = 0x1000,         /* Enable buffering when adding channels. */
        /// <summary>
        /// Enable tracing of end-of-lines for reads.
        /// </summary>
        TraceReadLines = 0x2000,     /* Enable tracing of end-of-lines for reads. */
        /// <summary>
        /// A carriage-return was seen as the last input character.
        /// </summary>
        LastCarriageReturn = 0x4000, /* A carriage-return was seen as the last input character. */
        /// <summary>
        /// Not used: a line-feed was seen as the first input character.
        /// </summary>
        FirstLineFeed = 0x8000,      /* NOT USED: A line-feed was seen as the first input character. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ExtraCarriageReturn" />,
        /// <see cref="ExtraLineFeed" />,
        /// <see cref="LastCarriageReturn" />, and
        /// <see cref="FirstLineFeed" />.
        /// </summary>
        ExtraLineEndingMask = ExtraCarriageReturn | ExtraLineFeed |
                              LastCarriageReturn | FirstLineFeed,

        /// <summary>
        /// Combination mask of <see cref="SawCarriageReturn" /> and
        /// <see cref="NeedLineFeed" />.
        /// </summary>
        LineEndingMask = SawCarriageReturn | NeedLineFeed,
        /// <summary>
        /// Combination mask of <see cref="LineEndingMask" /> and
        /// <see cref="ExtraLineEndingMask" />.
        /// </summary>
        AnyLineEndingMask = LineEndingMask | ExtraLineEndingMask,

        /// <summary>
        /// Combination mask of <see cref="Socket" /> and
        /// <see cref="Listen" />.
        /// </summary>
        ListenSocket = Socket | Listen,
        /// <summary>
        /// Combination mask of <see cref="Socket" /> and
        /// <see cref="Client" />.
        /// </summary>
        ClientSocket = Socket | Client,
        /// <summary>
        /// Combination mask of <see cref="PreventClose" />,
        /// <see cref="Socket" />, and <see cref="Server" />.
        /// </summary>
        ServerSocket = PreventClose | Socket | Server
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how TclTk searches for a file across its
    /// various candidate locations and how the resulting path is formed.
    /// The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("0e36e577-a722-4a9b-bbe0-08340cab5bd3")]
    public enum FileSearchFlags
    {
        /// <summary>
        /// No special handling is performed.
        /// </summary>
        None = 0x0,                 /* no special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,              /* invalid, do not use. */
        /// <summary>
        /// Check the specified name verbatim (this applies only when the
        /// name is fully qualified).
        /// </summary>
        SpecificPath = 0x2,         /* check the specified name verbatim (this only
                                     * applies if the name is fully qualified). */
        /// <summary>
        /// Search the interpreter path map (checked first).
        /// </summary>
        Mapped = 0x4,               /* search interpreter path map (first). */
        /// <summary>
        /// Search the <c>auto_source_path</c> (checked second).
        /// </summary>
        AutoSourcePath = 0x8,       /* search the auto_source_path (second). */
        /// <summary>
        /// Search the current directory (checked third).
        /// </summary>
        Current = 0x10,             /* search the current directory (third). */
        /// <summary>
        /// Search user-specific locations.
        /// </summary>
        User = 0x20,                /* search user-specific locations. */
        /// <summary>
        /// Search the externals directory.
        /// </summary>
        Externals = 0x40,           /* search the externals directory. */
        /// <summary>
        /// Search application-specific locations.
        /// </summary>
        Application = 0x80,         /* search application-specific locations. */
        /// <summary>
        /// Search application base directory locations.
        /// </summary>
        ApplicationBase = 0x100,    /* search application base directory locations. */
        /// <summary>
        /// Also search vendor-specific locations.
        /// </summary>
        Vendor = 0x200,             /* also search vendor locations. */
        /// <summary>
        /// Return null if no existing file is found.
        /// </summary>
        NullOnNotFound = 0x400,     /* return null if no existing file is found. */
        /// <summary>
        /// Normalize directory separators in the resulting path.
        /// </summary>
        DirectorySeparator = 0x800, /* normalize directory separators. */
        /// <summary>
        /// Use Unix-style directory separators.
        /// </summary>
        Unix = 0x1000,              /* use Unix directory separators. */
        /// <summary>
        /// Allow a candidate location to be a directory.
        /// </summary>
        DirectoryLocation = 0x2000, /* allow candidate location to be a directory. */
        /// <summary>
        /// Allow a candidate location to be a file.
        /// </summary>
        FileLocation = 0x4000,      /* allow candidate location to be a file. */
        /// <summary>
        /// Search using the path with its directory information intact; if
        /// an absolute path is specified, all candidate locations are
        /// rejected unless <see cref="StripBasePath" /> or
        /// <see cref="TailOnly" /> is also used.
        /// </summary>
        FullPath = 0x8000,          /* search using the path with its directory
                                     * information intact.  if an absolute path
                                     * specified, all candidate locations will be
                                     * rejected unless one of the following flags
                                     * is also used: StripBasePath FileNameOnly */
        /// <summary>
        /// When an absolute path is specified, attempt to remove the base
        /// path portion from the candidate location being searched; this
        /// flag has no effect on non-absolute paths.
        /// </summary>
        StripBasePath = 0x10000,    /* when an absolute path is specified, attempt
                                     * to remove the base path portion for the
                                     * candidate location being searched.  this
                                     * flag has absolutely, positively no effect
                                     * on non-absolute paths. */
        /// <summary>
        /// Search using only the tail portion of the specified path; this
        /// flag is legal for all path types and removes all non-tail parts
        /// before checking a candidate location.
        /// </summary>
        TailOnly = 0x20000,         /* search using only the tail portion of the
                                     * specified path.  this flag is legal for all
                                     * path types and permits all non-tail parts
                                     * of the path to be removed before checking a
                                     * candidate location. */
        /// <summary>
        /// Show each directory and file that is checked.
        /// </summary>
        Verbose = 0x40000,          /* show each directory / file checked. */
        /// <summary>
        /// The search is being conducted from an isolated AppDomain
        /// relative to the host interpreter; this may have no effect.
        /// </summary>
        Isolated = 0x80000,         /* search is being conducted from an isolated
                                     * AppDomain from the perspective of the host
                                     * interpreter.  this may have no effect. */

        /// <summary>
        /// Combination mask of <see cref="FullPath" />,
        /// <see cref="StripBasePath" />, and <see cref="TailOnly" />.
        /// </summary>
        PathMask = FullPath | StripBasePath | TailOnly,

        /// <summary>
        /// Combination mask of the standard search locations together with
        /// <see cref="PathMask" />, including <see cref="SpecificPath" />,
        /// <see cref="Mapped" />, <see cref="AutoSourcePath" />,
        /// <see cref="User" />, <see cref="Externals" />,
        /// <see cref="Application" />, <see cref="ApplicationBase" />,
        /// <see cref="Vendor" />, <see cref="DirectoryLocation" />, and
        /// <see cref="FileLocation" />.
        /// </summary>
        Standard = SpecificPath | Mapped | AutoSourcePath |
                   User | Externals | Application |
                   ApplicationBase | Vendor | DirectoryLocation |
                   FileLocation | PathMask,

        /// <summary>
        /// Combination mask of <see cref="Standard" /> and
        /// <see cref="NullOnNotFound" />.
        /// </summary>
        StandardNullOnNotFound = Standard | NullOnNotFound,

        /// <summary>
        /// The default flags; equivalent to <see cref="PathMask" />.
        /// </summary>
        Default = PathMask
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the direction of data flow for a stream
    /// together with related processing options.  The values are bit flags
    /// that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("021d5251-a399-4275-98c8-14d543020237")]
    public enum StreamDirection
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The stream is used for input.
        /// </summary>
        Input = 0x100,
        /// <summary>
        /// The stream is used for output.
        /// </summary>
        Output = 0x200,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Ignore the other flags during processing.
        /// </summary>
        IgnoreFlags = 0x1000,
        /// <summary>
        /// The end of the stream has been reached.
        /// </summary>
        EndOfStream = 0x2000,
        /// <summary>
        /// Any end-of-line convention is accepted.
        /// </summary>
        AnyEndOfLine = 0x4000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Input" /> and
        /// <see cref="IgnoreFlags" />.
        /// </summary>
        InputEolOnly = Input | IgnoreFlags,
        /// <summary>
        /// Combination mask of <see cref="Input" /> and
        /// <see cref="Output" />.
        /// </summary>
        BaseMask = Input | Output,
        /// <summary>
        /// Combination mask of <see cref="IgnoreFlags" />,
        /// <see cref="EndOfStream" />, and <see cref="AnyEndOfLine" />.
        /// </summary>
        FlagsMask = IgnoreFlags | EndOfStream | AnyEndOfLine,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Both input and output; equivalent to <see cref="BaseMask" />.
        /// </summary>
        Both = BaseMask
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the end-of-line translation mode applied
    /// to a stream or channel.  These names are referred to directly from
    /// scripts.
    /// </summary>
    [ObjectId("dcc9ce82-31c2-4366-bcbd-be8e049d0c47")]
    public enum StreamTranslation
    {
        //
        // NOTE: These names are referred to directly from scripts, please do not change.
        //
        /// <summary>
        /// No translation is performed; bytes are passed through
        /// unchanged.
        /// </summary>
        binary = 0,
        /// <summary>
        /// Use a line-feed as the end-of-line sequence.
        /// </summary>
        lf = 1,
        /// <summary>
        /// Use a carriage-return as the end-of-line sequence.
        /// </summary>
        cr = 2,
        /// <summary>
        /// Use a carriage-return/line-feed pair as the end-of-line
        /// sequence.
        /// </summary>
        crlf = 3,
        /// <summary>
        /// Use the native end-of-line convention of the current platform.
        /// </summary>
        platform = 4,
        /// <summary>
        /// Automatically detect the end-of-line convention in use.
        /// </summary>
        auto = 5,
        /// <summary>
        /// Use the end-of-line convention dictated by the environment.
        /// </summary>
        environment = 6,
        /// <summary>
        /// Use a carriage-return/line-feed pair, as required by numerous
        /// Internet protocols.
        /// </summary>
        protocol = 7 /* cr/lf is required by numerous Internet protocols */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration describes the attributes of a namespace name and
    /// controls how such a name is parsed and resolved.  The values are
    /// bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("721b5d85-d2de-42df-9f66-440f9efe2c97")]
    public enum NamespaceFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; callers should
        /// not use it.
        /// </summary>
        Invalid = 0x1,

        /// <summary>
        /// The name is qualified.
        /// </summary>
        Qualified = 0x2,
        /// <summary>
        /// The name is absolute (rooted at the global namespace).
        /// </summary>
        Absolute = 0x4,
        /// <summary>
        /// The name refers to the global namespace.
        /// </summary>
        Global = 0x8,

        /// <summary>
        /// The name contains wildcard pattern characters.
        /// </summary>
        Wildcard = 0x10,

        /// <summary>
        /// The name refers to a command.
        /// </summary>
        Command = 0x20,
        /// <summary>
        /// The name refers to a variable.
        /// </summary>
        Variable = 0x40,

        /// <summary>
        /// Combination mask of <see cref="Qualified" />,
        /// <see cref="Absolute" />, and <see cref="Global" />.
        /// </summary>
        QualifierMask = Qualified | Absolute | Global,
        /// <summary>
        /// Combination mask consisting of <see cref="Wildcard" />.
        /// </summary>
        PatternMask = Wildcard,
        /// <summary>
        /// Combination mask of <see cref="Command" /> and
        /// <see cref="Variable" />.
        /// </summary>
        EntityMask = Command | Variable,

        /// <summary>
        /// Combination mask of <see cref="QualifierMask" />,
        /// <see cref="PatternMask" />, and <see cref="EntityMask" />.
        /// </summary>
        SplitNameMask = QualifierMask | PatternMask | EntityMask
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how a settings
    /// ("script data") file is loaded and how its contents are merged into
    /// the resulting dictionary.  Because it is marked with
    /// <see cref="FlagsAttribute" />, individual values may be combined
    /// together to select multiple behaviors at once.
    /// </summary>
    [Flags()]
    [ObjectId("ba1fcf45-9ce8-4d7a-9158-fb5c4f345bd2")]
    public enum ScriptDataFlags : ulong
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,                         /* No special handling. */
        /// <summary>
        /// Reserved invalid value; it should never be used.
        /// </summary>
        Invalid = 0x1,                      /* Invalid, do not use. */
        /// <summary>
        /// Create and/or use a "safe" interpreter when loading the settings.
        /// </summary>
        UseSafeInterpreter = 0x2,           /* Create and/or use a "safe"
                                             * interpreter. */
        /// <summary>
        /// Create and/or use an interpreter that runs in its own application
        /// domain (i.e. an isolated interpreter).
        /// </summary>
        UseIsolatedInterpreter = 0x4,       /* Create and/or use an interpreter
                                             * in its own application domain. */
        /// <summary>
        /// The script only contains static data assigned via the <c>[set]</c>
        /// command.
        /// </summary>
        UseStaticDataOnly = 0x8,            /* The script only contains static
                                             * data that uses the [set] command.
                                             */
        /// <summary>
        /// Loading is being performed in a time-critical context, so shortcuts
        /// should be taken wherever they are available.
        /// </summary>
        FastStaticDataOnly = 0x10,          /* Loading is being done in a time
                                             * critical context and shortcuts
                                             * should be taken as needed. */
        /// <summary>
        /// Scalar variables should be copied into the resulting dictionary.
        /// </summary>
        CopyScalars = 0x20,                 /* Scalar variables should be copied
                                             * to the resulting dictionary. */
        /// <summary>
        /// Array variables should be copied into the resulting dictionary.
        /// </summary>
        CopyArrays = 0x40,                  /* Array variables should be copied
                                             * to the resulting dictionary. */
        /// <summary>
        /// When merging the settings, only consider those that already existed.
        /// </summary>
        ExistingOnly = 0x80,                /* When merging the settings, only
                                             * consider those that already
                                             * existed. */
        /// <summary>
        /// When set and the associated "copy" flag is not set, an error is
        /// returned if a scalar variable is encountered.
        /// </summary>
        ErrorOnScalar = 0x100,              /* When this flag is set and the
                                             * associated "copy" flag is not set,
                                             * an error will be returned if a
                                             * scalar variable is found.
                                             */
        /// <summary>
        /// When set and the associated "copy" flag is not set, an error is
        /// returned if an array variable is encountered.
        /// </summary>
        ErrorOnArray = 0x200,               /* When this flag is set and the
                                             * associated "copy" flag is not set,
                                             * an error will be returned if an
                                             * array variable is found. */
        /// <summary>
        /// Prevent the "Security" flag from being set in the interpreter
        /// initialization flags.
        /// </summary>
        DisableSecurity = 0x400,            /* Prevent the "Security" flag from
                                             * being set in the interpreter
                                             * initialization flags. */
        /// <summary>
        /// Set the "Security" initialization flag when creating a new (cached)
        /// interpreter for use by the settings subsystem.
        /// </summary>
        EnableSecurity = 0x800,             /* Set the "Security" initialization
                                             * flag when creating a new (cached)
                                             * interpreter for use by settings.
                                             */
        /// <summary>
        /// Make sure to trust the public key(s) associated with the software
        /// update SSL certificate(s) prior to evaluating the settings file,
        /// using save/restore semantics on the associated trust state.
        /// </summary>
        ForceTrustedUri = 0x1000,           /* Make sure to trust the public
                                             * key(s) that are associated with
                                             * the software update SSL
                                             * certificate(s) prior to attempting
                                             * to evaluate the settings file.
                                             * This will use save/restore
                                             * semantics on the associated trust
                                             * state. */
        /// <summary>
        /// Use an existing interpreter; do not create a new one.
        /// </summary>
        NoCreateInterpreter = 0x2000,       /* Use an existing interpreter, do
                                             * not create a new one. */
        /// <summary>
        /// Use an existing cached "safe" interpreter, if any, creating and
        /// storing it when needed.
        /// </summary>
        CacheSafeInterpreter = 0x4000,      /* Use existing cached "safe"
                                             * interpreter, if any, creating and
                                             * storing it when needed. */
        /// <summary>
        /// Not implemented: use an existing cached isolated interpreter, if any,
        /// creating and storing it when needed.
        /// </summary>
        CacheIsolatedInterpreter = 0x8000,  /* NOT IMPLEMENTED: Use existing cached
                                             * "safe" interpreter, if any, creating
                                             * and storing it when needed. */
        /// <summary>
        /// Skip creating an interpreter host.
        /// </summary>
        DisableHost = 0x10000,              /* Skip creating an interpreter host.
                                             */
        /// <summary>
        /// Do not use the console host.
        /// </summary>
        NoConsoleHost = 0x20000,            /* Do not use the console host. */
#if ISOLATED_PLUGINS
        /// <summary>
        /// Prevent plugins from being loaded into isolated application domains.
        /// </summary>
        NoIsolatedPlugins = 0x40000,        /* Prevent plugins from being loaded
                                             * in isolated application domains. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if SHELL
        /// <summary>
        /// Skip update checks when loading plugins.
        /// </summary>
        NoPluginUpdateCheck = 0x80000,      /* Skip update checks when loading
                                             * plugins. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Prevent plugins from setting the <c>IsolatedOnly</c> plugin flag.
        /// </summary>
        NoPluginIsolatedOnly = 0x100000,    /* Prevent plugins from setting the
                                             * IsolatedOnly plugin flag. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip evaluating "startup" scripts when creating an interpreter.
        /// </summary>
        NoStartup = 0x200000,               /* Skip evaluating "startup" scripts
                                             * when creating an interpreter. */
        /// <summary>
        /// Disallow any implicit use of the <c>Thread.Abort()</c> method.
        /// </summary>
        NoThreadAbort = 0x400000,           /* Disallow any implicit use of the
                                             * Thread.Abort() method. */
        /// <summary>
        /// For created interpreters, skip forbidding use of
        /// <c>[package unknown]</c>.
        /// </summary>
        AllowPackageUnknown = 0x800000,     /* For created interpreters, skip
                                             * forbidding use of [package unknown]. */
        /// <summary>
        /// For created interpreters, allow the temporary packages flag to be
        /// set.
        /// </summary>
        AllowTemporaryPackages = 0x1000000, /* For created interpreters, allow
                                             * the temporary packages flag to be
                                             * set. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The settings are being loaded using the default semantics.
        /// </summary>
        ForDefault = 0x2000000,             /* The settings are being loaded using
                                             * the default semantics. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Reserved value; it should not be used.
        /// </summary>
        Reserved1 = 0x40000000,             /* Reserved value, do not use. */
        /// <summary>
        /// Reserved value; it should not be used.
        /// </summary>
        Reserved2 = 0x80000000,             /* Reserved value, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="CopyScalars" /> and
        /// <see cref="CopyArrays" />.
        /// </summary>
        CopyVariables = CopyScalars | CopyArrays,
        /// <summary>
        /// Combination of <see cref="CopyVariables" /> and
        /// <see cref="ExistingOnly" />.
        /// </summary>
        CopyPreExistingVariablesOnly = CopyVariables | ExistingOnly,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="UseSafeInterpreter" /> and
        /// <see cref="UseStaticDataOnly" />.
        /// </summary>
        SafeInterpreterAndStaticDataOnly = UseSafeInterpreter | UseStaticDataOnly,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="NoCreateInterpreter" />,
        /// <see cref="UseSafeInterpreter" />, and
        /// <see cref="CacheSafeInterpreter" /> used for fast loading.
        /// </summary>
        FastUseMask = NoCreateInterpreter |
                      UseSafeInterpreter |
                      CacheSafeInterpreter,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask suitable for use when embedding, disabling the
        /// console host, isolated plugins, plugin update checks, and implicit
        /// thread aborts as applicable.
        /// </summary>
        EmbeddedUseMask = NoConsoleHost |
#if ISOLATED_PLUGINS
                          NoIsolatedPlugins |
#if SHELL
                          NoPluginUpdateCheck |
#endif
                          NoPluginIsolatedOnly |
#endif
                          NoThreadAbort,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ENTERPRISE_LOCKDOWN
        /// <summary>
        /// When enterprise lockdown is in effect, security is enabled by
        /// default; equivalent to <see cref="EnableSecurity" />.
        /// </summary>
        MaybeEnableSecurity = EnableSecurity,
#else
        /// <summary>
        /// When enterprise lockdown is not in effect, security is not enabled by
        /// default; equivalent to <see cref="None" />.
        /// </summary>
        MaybeEnableSecurity = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="DisableSecurity" /> and
        /// <see cref="EmbeddedUseMask" /> used by the security package.
        /// </summary>
        SecurityPackage = DisableSecurity | EmbeddedUseMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="CopyPreExistingVariablesOnly" />,
        /// <see cref="SafeInterpreterAndStaticDataOnly" />, and
        /// <see cref="SecurityPackage" /> used by the key ring loader.
        /// </summary>
        ForKeyRingLoader = CopyPreExistingVariablesOnly |
                           SafeInterpreterAndStaticDataOnly |
                           SecurityPackage,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The lowest trust level; combination of <see cref="Reserved1" /> and
        /// <see cref="CopyVariables" />.
        /// </summary>
        Lowest = Reserved1 | CopyVariables,
        /// <summary>
        /// A low trust level building on <see cref="Lowest" /> with additional
        /// restrictions.
        /// </summary>
        Low = Lowest | ExistingOnly | NoStartup | NoThreadAbort,
        /// <summary>
        /// A medium trust level building on <see cref="Low" /> using a safe
        /// interpreter.
        /// </summary>
        Medium = Low | UseSafeInterpreter,
        /// <summary>
        /// A high trust level building on <see cref="Medium" /> restricting to
        /// static data only.
        /// </summary>
        High = Medium | UseStaticDataOnly,
        /// <summary>
        /// The highest trust level building on <see cref="High" /> using an
        /// isolated interpreter.
        /// </summary>
        Highest = High | UseIsolatedInterpreter,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The minimum supported combination; combination of
        /// <see cref="Reserved2" /> and <see cref="Low" />.
        /// </summary>
        Minimum = Reserved2 | Low,  /* COMPAT: TclTk beta. */
        /// <summary>
        /// The maximum supported combination; combination of
        /// <see cref="Reserved2" /> and <see cref="High" />.
        /// </summary>
        Maximum = Reserved2 | High, /* COMPAT: TclTk beta. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of flags used when loading settings.
        /// </summary>
        Default = (High & ~ExistingOnly) | MaybeEnableSecurity |
                  FastUseMask | EmbeddedUseMask | ForDefault,

        /// <summary>
        /// The default set of flags with security explicitly enabled;
        /// combination of <see cref="Default" /> and
        /// <see cref="EnableSecurity" />.
        /// </summary>
        DefaultAndEnableSecurity = Default | EnableSecurity
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /* [Flags()] */
    /// <summary>
    /// This enumeration defines the result status codes returned by virtually
    /// every executable operation in TclTk -- commands, functions, operators,
    /// and the engine itself.  It is the foundation of TclTk's error-handling
    /// model: an operation returns one of these codes and reports any
    /// accompanying detail through a <see cref="Result" /> (typically a
    /// <c>ref Result</c> parameter).  The five standard values
    /// (<see cref="Ok" />, <see cref="Error" />, <see cref="Return" />,
    /// <see cref="Break" />, and <see cref="Continue" />) mirror Tcl's return
    /// codes; TclTk adds a small number of additional codes.  See
    /// <c>error_handling.md</c> for usage patterns.
    /// </summary>
    [ObjectId("747766b6-abe9-4c44-890e-94585ea3cbd2")]
    public enum ReturnCode : int /* COMPAT: Tcl. */
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized return
        /// code; callers should not use this value.
        /// </summary>
        Invalid = -16, /* NOTE: This return code is reserved as "invalid",
                        *       please do not use it. */

        ///////////////////////////////////////////////////////////////////////

#if false
        /// <summary>
        /// A Tcl compatibility code, returned by <c>Tcl_ExternalToUtf</c> and
        /// <c>Tcl_UtfToExternal</c>, indicating the output buffer had no space
        /// remaining for the converted data.
        /// </summary>
        ConvertNoSpace = -4,   /* COMPAT: Tcl, these values can be returned by */
        /// <summary>
        /// A Tcl compatibility code indicating a character could not be
        /// represented in the target encoding during conversion.
        /// </summary>
        ConvertUnknown = -3,   /*         Tcl_ExternalToUtf and Tcl_UtfToExternal in */
        /// <summary>
        /// A Tcl compatibility code indicating an invalid byte sequence
        /// (a syntax error) was encountered in the input during conversion.
        /// </summary>
        ConvertSyntax = -2,    /*         addition to TCL_OK. */
        /// <summary>
        /// A Tcl compatibility code indicating the input ended in the middle
        /// of a multi-byte character sequence during conversion.
        /// </summary>
        ConvertMultiByte = -1,
#endif

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The operation completed successfully.
        /// </summary>
        Ok = 0,        /* COMPAT: Tcl, these five "standard" return code values */

        /// <summary>
        /// The operation failed; the accompanying result contains an error
        /// message.
        /// </summary>
        Error = 1,     /*         are straight from "generic/tcl.h" and are used */

        /// <summary>
        /// The operation requested an early return from the enclosing
        /// procedure or script, as produced by the <c>return</c> command.
        /// </summary>
        Return = 2,    /*         by the TclWrapper as well as script engine */

        /// <summary>
        /// The operation requested termination of the innermost enclosing
        /// loop, as produced by the <c>break</c> command.
        /// </summary>
        Break = 3,     /*         itself, please do not change them. */

        /// <summary>
        /// The operation requested that the innermost enclosing loop advance
        /// to its next iteration, as produced by the <c>continue</c> command.
        /// </summary>
        Continue = 4,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates a "what-if" (simulated) execution outcome, where an
        /// operation reports what it would do without performing it; available
        /// in TclTk beta 45 and later.
        /// </summary>
        WhatIf = 5,    /* COMPAT: TclTk beta 45+ only. */

        /// <summary>
        /// Indicates the operation terminated because of an exception;
        /// available in TclTk beta 46 and later.
        /// </summary>
        Exception = 6, /* COMPAT: TclTk beta 46+ only. */

        ///////////////////////////////////////////////////////////////////////

        //
        // NOTE: If either of these bits are set, it indicates a custom
        //       return code is being provided by the user command.
        //
        /// <summary>
        /// When this bit is set, the command is supplying a custom success
        /// return code in the remaining bits.
        /// </summary>
        CustomOk = 0x20000000,    /* COMPAT: HRESULT. */

        /// <summary>
        /// When this bit is set, the command is supplying a custom failure
        /// return code in the remaining bits.
        /// </summary>
        CustomError = 0x40000000, /* COMPAT: HRESULT. */

        ///////////////////////////////////////////////////////////////////////

        //
        // NOTE: The high-bit is reserved, please do not use it.
        //
        /// <summary>
        /// The high bit is reserved for future use and should not be set by
        /// callers.
        /// </summary>
        Reserved = unchecked((int)0x80000000) /* COMPAT: HRESULT. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags describing the permissions and
    /// existence/type characteristics of a file system entry, modeled after
    /// the traditional Unix access bits.  Because it is marked with
    /// <see cref="FlagsAttribute" />, values may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("f185d6de-8e60-4c80-90e8-7569d5f02b23")]
    public enum FilePermission
    {
        /// <summary>
        /// No permissions or attributes are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// The entry is executable.
        /// </summary>
        Execute = 0x1, /* COMPAT: Unix. */
        /// <summary>
        /// The entry is writable.
        /// </summary>
        Write = 0x2,   /* COMPAT: Unix. */
        /// <summary>
        /// The entry is readable.
        /// </summary>
        Read = 0x4,    /* COMPAT: Unix. */
        /// <summary>
        /// Reserved invalid value; it should not be used.
        /// </summary>
        Invalid = 0x4000000,
        /// <summary>
        /// The entry exists.
        /// </summary>
        Exists = 0x8000000,
        /// <summary>
        /// The entry does not exist.
        /// </summary>
        NotExists = 0x10000000,
        /// <summary>
        /// The entry is a directory.
        /// </summary>
        Directory = 0x20000000,
        /// <summary>
        /// The entry is a regular file.
        /// </summary>
        File = 0x40000000,
        /// <summary>
        /// Reserved high bit; it should not be used.
        /// </summary>
        Reserved = unchecked((int)0x80000000)
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags describing the access mode used
    /// when opening a file, modeled after the C and POSIX <c>open()</c>
    /// flags and the Tcl channel access modes.  Because it is marked with
    /// <see cref="FlagsAttribute" />, values may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("2752be1d-e3a3-42c7-992a-ea249b0161a6")]
    public enum MapOpenAccess /* COMPAT: C + POSIX */
    {
        //
        // NOTE: These names are referred to directly from scripts, please do not change.
        //
        /// <summary>
        /// The default access mode; equivalent to <see cref="RdOnly" />.
        /// </summary>
        Default = RdOnly,                 /* default handling */
        /// <summary>
        /// Open the file for reading only.
        /// </summary>
        RdOnly = 0x0,                     /* open for reading only */
        /// <summary>
        /// Open the file for writing only.
        /// </summary>
        WrOnly = 0x1,                     /* open for writing only */
        /// <summary>
        /// Open the file for both reading and writing.
        /// </summary>
        RdWr = 0x2,                       /* open for reading and writing */
        /// <summary>
        /// All writes are performed at the end of the file (append mode).
        /// </summary>
        Append = 0x8,                     /* writes done at eof */
        /// <summary>
        /// Seek to the end of the file immediately after opening.
        /// </summary>
        SeekToEof = 0x10,                 /* seek to eof at open */
        /// <summary>
        /// Create the file and open it.
        /// </summary>
        Creat = 0x100,                    /* create and open file */
        /// <summary>
        /// Open the file and truncate it to zero length.
        /// </summary>
        Trunc = 0x200,                    /* open and truncate */
        /// <summary>
        /// Open only if the file does not already exist.
        /// </summary>
        Excl = 0x400,                     /* open only if file doesn't already exist */
        /// <summary>
        /// Open for reading only; the file must already exist.  This is the
        /// default; equivalent to <see cref="RdOnly" />.
        /// </summary>
        R = RdOnly,                       /* open for reading only; file must already exist; this is
                                           * the default */
        /// <summary>
        /// Open for reading and writing; the file must already exist;
        /// equivalent to <see cref="RdWr" />.
        /// </summary>
        RPlus = RdWr,                     /* open for reading and writing; file must already exist */
        /// <summary>
        /// Open for writing only, truncating the file if it exists or otherwise
        /// creating a new one.
        /// </summary>
        W = WrOnly | Creat | Trunc,       /* open for writing only; truncate if it exists, otherwise,
                                           * create new file */
        /// <summary>
        /// Open for reading and writing, truncating the file if it exists or
        /// otherwise creating a new one.
        /// </summary>
        WPlus = RdWr | Creat | Trunc,     /* open for reading and writing; truncate if it exists;
                                           * otherwise, create new file */
        /// <summary>
        /// Open for writing only, creating the file if it does not exist, with
        /// writes performed at the end of the file.
        /// </summary>
        A = WrOnly | Creat | Append,      /* open for writing only; if it doesn't exist, create new
                                           * file, writes done at eof */
        /// <summary>
        /// Open for reading and writing, creating the file if it does not exist,
        /// with the initial position at the end of the file.
        /// </summary>
        APlus = RdWr | Creat | SeekToEof, /* open for reading and writing; if it doesn't exist, create
                                           * new file, initial position is eof */
        /// <summary>
        /// Mask of the possible read/write modes.
        /// </summary>
        RdWrMask = RdOnly | WrOnly | RdWr /* mask of possible read/write modes */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the reference points from which a seek
    /// offset is measured, mapping TclTk's channel seek origins onto the
    /// standard <see cref="SeekOrigin" /> values.
    /// </summary>
    [ObjectId("6fad8db8-ecf0-4662-a6a1-c2930ff3acea")]
    public enum MapSeekOrigin
    {
        //
        // NOTE: These names are referred to directly from scripts, please do not change.
        //
        /// <summary>
        /// Seek relative to the beginning of the stream.
        /// </summary>
        Begin = SeekOrigin.Begin,
        /// <summary>
        /// Seek relative to the beginning of the stream; an alias of
        /// <see cref="Begin" />.
        /// </summary>
        Start = SeekOrigin.Begin,
        /// <summary>
        /// Seek relative to the current position within the stream.
        /// </summary>
        Current = SeekOrigin.Current,
        /// <summary>
        /// Seek relative to the end of the stream.
        /// </summary>
        End = SeekOrigin.End
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags controlling how persisted
    /// settings are read and written, including which scope (per-user or
    /// per-machine) and which security group is consulted.  Because it is
    /// marked with <see cref="FlagsAttribute" />, values may be combined
    /// together.
    /// </summary>
    [Flags()]
    [ObjectId("f83e7bd1-a0b2-4f5c-99d3-a5a315735031")]
    public enum SettingFlags
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,          /* No special handling. */
        /// <summary>
        /// Reserved invalid value; it should not be used.
        /// </summary>
        Invalid = 0x1,       /* Invalid, do not use. */
        /// <summary>
        /// Enable reading and writing of per-user settings.
        /// </summary>
        CurrentUser = 0x2,   /* Enable reading and writing of per-user
                              * settings. */
        /// <summary>
        /// Enable reading and writing of per-machine settings.
        /// </summary>
        LocalMachine = 0x4,  /* Enable reading and writing of per-machine
                              * settings. */
        /// <summary>
        /// Search all groups of settings, even those that may not be applicable
        /// to the current user.
        /// </summary>
        AnySecurity = 0x8,   /* Search all groups of settings, even when they
                              * may not be applicable to the current user. */
        /// <summary>
        /// Check the permissions of the current user to select which group of
        /// settings is read or written by the current operation.
        /// </summary>
        UserSecurity = 0x10, /* Check the permissions of the current user to
                              * select which group of settings will be read
                              * or written by the current operation. */
        /// <summary>
        /// Only read and/or write setting values within the group of settings
        /// that are writable by all users.
        /// </summary>
        LowSecurity = 0x20,  /* Only read and/or write setting values within
                              * the group of settings that are writable by
                              * all users. */
        /// <summary>
        /// Only read and/or write setting values within the group of settings
        /// that are writable by users with administrator access.
        /// </summary>
        HighSecurity = 0x40, /* Only read and/or write setting values within
                              * the group of settings that are writable by
                              * users with administrator access. */
        /// <summary>
        /// Enable detailed error messages.
        /// </summary>
        Verbose = 0x80,      /* Enable detailed error messages. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="CurrentUser" />,
        /// <see cref="LocalMachine" />, <see cref="AnySecurity" />,
        /// <see cref="UserSecurity" />, <see cref="LowSecurity" />, and
        /// <see cref="HighSecurity" />.
        /// </summary>
        All = CurrentUser | LocalMachine | AnySecurity |
              UserSecurity | LowSecurity | HighSecurity,

        /// <summary>
        /// The legacy combination of <see cref="CurrentUser" />,
        /// <see cref="LocalMachine" />, and <see cref="HighSecurity" />.
        /// </summary>
        Legacy = CurrentUser | LocalMachine | HighSecurity,

        /// <summary>
        /// The default set of flags; equivalent to <see cref="Legacy" />.
        /// </summary>
        Default = Legacy
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control the behavior of the
    /// <see cref="Value" /> class when it attempts to interpret a given
    /// string as a number (or another supported type), including which
    /// number bases, types, and conversion options are permitted.  Because
    /// it is marked with <see cref="FlagsAttribute" />, values may be
    /// combined together; many entries below are convenience combinations
    /// of the primitive flags.
    /// </summary>
    [Flags()]
    [ObjectId("12692407-91a1-44ce-af30-5d29bdd8a265")]
    public enum ValueFlags : ulong
    {
        //
        // NOTE: The various flags in this enumeration
        //       control the behavior of the Value class
        //       when it attempts to interpret a given
        //       string as a number (or other supported
        //       type).
        //
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,

        // Invalid = 0x1,
        /// <summary>
        /// Only trusted input should be processed.
        /// </summary>
        TrustedOnly = 0x1,

        //
        // NOTE: The available number bases.
        //
        /// <summary>
        /// Allow values expressed in binary (base 2).
        /// </summary>
        BinaryRadix = 0x2,
        /// <summary>
        /// Allow values expressed in octal (base 8).
        /// </summary>
        OctalRadix = 0x4,
        /// <summary>
        /// Allow values expressed in decimal (base 10).
        /// </summary>
        DecimalRadix = 0x8,
        /// <summary>
        /// Allow values expressed in hexadecimal (base 16).
        /// </summary>
        HexadecimalRadix = 0x10,

        //
        // NOTE: The available integral types.
        //
        /// <summary>
        /// Allow conversion to a boolean value.
        /// </summary>
        Boolean = 0x20,
        /// <summary>
        /// Allow conversion to a byte value.
        /// </summary>
        Byte = 0x40,
        /// <summary>
        /// Allow conversion to a character value.
        /// </summary>
        Character = 0x80,
        /// <summary>
        /// Allow conversion to a string value.
        /// </summary>
        String = 0x100,
        /// <summary>
        /// Allow conversion to a list value.
        /// </summary>
        List = 0x200,
        /// <summary>
        /// Allow conversion to a narrow (16-bit) integer value.
        /// </summary>
        NarrowInteger = 0x400,
        /// <summary>
        /// Allow conversion to an integer (32-bit) value.
        /// </summary>
        Integer = 0x800,
        /// <summary>
        /// Allow conversion to a wide (64-bit) integer value.
        /// </summary>
        WideInteger = 0x1000,

#if NET_40
        /// <summary>
        /// Allow conversion to a big integer value (arbitrary precision).
        /// </summary>
        BigInteger = 0x2000,
#endif

        //
        // NOTE: The available enumerated types.  These
        //       are considered to be distinct and are
        //       treated specially from the [integral]
        //       types above, even though they actually
        //       are integral types (primarily because
        //       the "fallback" semantics of the Value
        //       class functions are not designed to
        //       automatically convert a string to a
        //       value of an enumerated type, e.g. via
        //       GetNumber).
        //
        /// <summary>
        /// Allow conversion to a <see cref="Result" /> return code value.
        /// </summary>
        ReturnCode = 0x4000,
        /// <summary>
        /// Allow conversion to a match mode value.
        /// </summary>
        MatchMode = 0x8000,

        //
        // NOTE: The available fixed-point types.
        //
        /// <summary>
        /// Allow conversion to a fixed-point decimal value.
        /// </summary>
        Decimal = 0x10000,

        //
        // NOTE: The available floating-point types.
        //
        /// <summary>
        /// Allow conversion to a single-precision floating-point value.
        /// </summary>
        Single = 0x20000,
        /// <summary>
        /// Allow conversion to a double-precision floating-point value.
        /// </summary>
        Double = 0x40000,

        //
        // NOTE: Some kind of basic numeric value.  This
        //       includes all booleans, integers (both signed
        //       and/or unsigned), fixed-point, and floating
        //       point.
        //
        /// <summary>
        /// Indicates some kind of basic numeric value, including booleans,
        /// signed and/or unsigned integers, fixed-point, and floating point.
        /// </summary>
        Number = 0x80000,

        //
        // NOTE: The available miscellaneous types.
        //
        /// <summary>
        /// Allow conversion to a date/time value.
        /// </summary>
        DateTime = 0x100000,
        /// <summary>
        /// Allow fixing up a date/time format string.
        /// </summary>
        DateTimeFormat = 0x200000, /* fixup DateTime format string */
        /// <summary>
        /// Allow conversion to a time span value.
        /// </summary>
        TimeSpan = 0x400000,
        /// <summary>
        /// Allow conversion to a GUID value.
        /// </summary>
        Guid = 0x800000,
        /// <summary>
        /// Allow conversion to an opaque object handle.
        /// </summary>
        Object = 0x1000000, /* opaque object handle */

        //
        // NOTE: For use by Value.GetIndex only.
        //
        /// <summary>
        /// For use by <c>Value.GetIndex</c> only: allow named index values.
        /// </summary>
        NamedIndex = 0x2000000,
        /// <summary>
        /// For use by <c>Value.GetIndex</c> only: allow an index with an
        /// offset.
        /// </summary>
        WithOffset = 0x4000000,

        //
        // NOTE: For use with Value.GetNestedObject and Value.GetNestedMember only.
        //
        /// <summary>
        /// For use with <c>Value.GetNestedObject</c> and
        /// <c>Value.GetNestedMember</c>: stop on a null type.
        /// </summary>
        StopOnNullType = 0x8000000,
        /// <summary>
        /// For use with <c>Value.GetNestedObject</c> and
        /// <c>Value.GetNestedMember</c>: stop on a null object.
        /// </summary>
        StopOnNullObject = 0x10000000,
        /// <summary>
        /// For use with <c>Value.GetNestedObject</c> and
        /// <c>Value.GetNestedMember</c>: stop on a null member.
        /// </summary>
        StopOnNullMember = 0x20000000,

        /// <summary>
        /// Combination mask of <see cref="StopOnNullType" />,
        /// <see cref="StopOnNullObject" />, and
        /// <see cref="StopOnNullMember" />.
        /// </summary>
        StopOnNullMask = StopOnNullType | StopOnNullObject | StopOnNullMember,

        //
        // NOTE: Extra flags to control the type conversion
        //       behavior of various methods of the Value
        //       class.
        //
        /// <summary>
        /// Use the fast conversion code path.
        /// </summary>
        Fast = 0x40000000,
        /// <summary>
        /// Allow an integer value to be used.
        /// </summary>
        AllowInteger = 0x80000000,
        /// <summary>
        /// Ignore leading characters (not currently used).
        /// </summary>
        IgnoreLeading = 0x100000000, /* NOT USED */
        /// <summary>
        /// Ignore trailing characters (not currently used).
        /// </summary>
        IgnoreTrailing = 0x200000000, /* NOT USED */
        /// <summary>
        /// Use strict conversion semantics.
        /// </summary>
        Strict = 0x400000000,
        /// <summary>
        /// Enable verbose error reporting.
        /// </summary>
        Verbose = 0x800000000,
        /// <summary>
        /// Show the simple name when reporting a type.
        /// </summary>
        ShowName = 0x1000000000,
        /// <summary>
        /// Show the full name when reporting a type.
        /// </summary>
        FullName = 0x2000000000,
        /// <summary>
        /// Perform case-insensitive matching.
        /// </summary>
        NoCase = 0x4000000000,
        /// <summary>
        /// Disallow nested member resolution.
        /// </summary>
        NoNested = 0x8000000000,
        /// <summary>
        /// Disallow namespace qualification when resolving a type.
        /// </summary>
        NoNamespace = 0x10000000000,
        /// <summary>
        /// Disallow assembly qualification when resolving a type.
        /// </summary>
        NoAssembly = 0x20000000000,
        /// <summary>
        /// Suppress exceptions during conversion.
        /// </summary>
        NoException = 0x40000000000,
        /// <summary>
        /// Disallow COM object handles.
        /// </summary>
        NoComObject = 0x80000000000,
        /// <summary>
        /// Do not fall back to the default <c>GetType</c> behavior.
        /// </summary>
        NoDefaultGetType = 0x100000000000,
        /// <summary>
        /// Allow textual boolean strings (e.g. "true" and "false").
        /// </summary>
        AllowBooleanString = 0x200000000000,
        /// <summary>
        /// Allow a null value.
        /// </summary>
        AllowNull = 0x400000000000,
        /// <summary>
        /// Allow an empty value.
        /// </summary>
        AllowEmpty = 0x800000000000,
        /// <summary>
        /// Allow an open (unbounded) value.
        /// </summary>
        AllowOpen = 0x1000000000000,
        /// <summary>
        /// Skip the <c>Type.GetType</c> step when resolving a type.
        /// </summary>
        SkipTypeGetType = 0x2000000000000,
        /// <summary>
        /// Allow the proxy-aware <c>GetType</c> behavior.
        /// </summary>
        AllowProxyGetType = 0x4000000000000,
        /// <summary>
        /// Force the proxy-aware <c>GetType</c> behavior.
        /// </summary>
        ForceProxyGetType = 0x8000000000000,
        /// <summary>
        /// Use manual proxy handling for <c>GetType</c>.
        /// </summary>
        ManualProxyGetType = 0x10000000000000,
        /// <summary>
        /// Return null for a proxy type.
        /// </summary>
        NullForProxyType = 0x20000000000000,
        /// <summary>
        /// Report all <c>GetType</c> errors.
        /// </summary>
        AllGetTypeErrors = 0x40000000000000,
        /// <summary>
        /// Use the single-parameter form of <c>GetType</c>.
        /// </summary>
        OneParameterGetType = 0x80000000000000,

        //
        // NOTE: Extra informational flags to indicate when a signed
        //       or unsigned integral number is being parsed.  These
        //       flags are not used in calls to parse the "default"
        //       signedness for a base integral type.
        //
        /// <summary>
        /// Informational flag indicating a signed integral number is being
        /// parsed.
        /// </summary>
        Signed = 0x100000000000000,
        /// <summary>
        /// Informational flag indicating an unsigned integral number is being
        /// parsed.
        /// </summary>
        Unsigned = 0x200000000000000,

        //
        // NOTE: Extra flags to control whether signed and/or
        //       unsigned variations are allowed when processing
        //       integral numbers in the decimal radix.
        //
        /// <summary>
        /// Allow the default signedness for the decimal radix only.
        /// </summary>
        DefaultSignedness = 0x400000000000000, /* decimal radix only */
        /// <summary>
        /// Allow a non-default signedness for the decimal radix only.
        /// </summary>
        NonDefaultSignedness = 0x800000000000000, /* decimal radix only */

        /// <summary>
        /// Allow a radix sign prefix in any radix.
        /// </summary>
        AllowRadixSign = 0x1000000000000000, /* any radix w/prefix */
        /// <summary>
        /// Allow signed values in the decimal radix only.
        /// </summary>
        AllowSigned = 0x2000000000000000, /* decimal radix only */
        /// <summary>
        /// Allow unsigned values in the decimal radix only.
        /// </summary>
        AllowUnsigned = 0x4000000000000000, /* decimal radix only */

        //
        // NOTE: When dealing with integer values, allow use of
        //       the sign bit (e.g. 4294967295 would be allowed
        //       for a 32-bit integer value).
        //
        /// <summary>
        /// When dealing with integer values, allow use of the sign bit (e.g.
        /// 4294967295 is allowed for a 32-bit integer value).
        /// </summary>
        WidenToUnsigned = 0x8000000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="DefaultSignedness" />,
        /// <see cref="AllowSigned" />, and <see cref="AllowUnsigned" />.
        /// </summary>
        SignednessMask = DefaultSignedness | AllowSigned | AllowUnsigned,

        //
        // NOTE: The default value flags used by [object search]
        //       when calling GetType.
        //
        /// <summary>
        /// The default value flags used by <c>[object search]</c> when calling
        /// <c>GetType</c>; equivalent to <see cref="ShowName" />.
        /// </summary>
        ObjectSearch = ShowName,

        //
        // NOTE: Either an integer or a wide integer.
        //
        /// <summary>
        /// Either an integer or a wide integer; combination of
        /// <see cref="Integer" /> and <see cref="WideInteger" />.
        /// </summary>
        IntegerOrWideInteger = Integer | WideInteger,

        //
        // NOTE: Used to mask off characters.
        //
        /// <summary>
        /// Mask used to clear the <see cref="Character" /> flag.
        /// </summary>
        NonCharacterMask = ~Character,

        //
        // NOTE: Used to mask off things that are not to be
        //       considered as "real numbers".
        //
        /// <summary>
        /// Mask used to clear the flags that are not considered "real numbers"
        /// (<see cref="Boolean" /> and <see cref="Character" />).
        /// </summary>
        NonRealMask = ~(Boolean | Character),

        //
        // NOTE: Allow booleans and their textual strings.
        //
        /// <summary>
        /// Allow booleans and their textual strings; combination of
        /// <see cref="Boolean" /> and <see cref="AllowBooleanString" />.
        /// </summary>
        TclBoolean = Boolean | AllowBooleanString,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These are the types (more-or-less) handled
        //       by the GetNumeric method.
        //
        /// <summary>
        /// Mask of the types (more-or-less) handled by the <c>GetNumeric</c>
        /// method.
        /// </summary>
        NumericMask = TclBoolean | Byte |
                      NarrowInteger | Integer | WideInteger |
#if NET_40
                      BigInteger |
#endif
                      Decimal | Single | Double | Number,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used with the GetVersionRange
        //       method.
        //
        /// <summary>
        /// Mask of the flags used with the <c>GetVersionRange</c> method.
        /// </summary>
        VersionRangeMask = AllowNull | AllowEmpty | AllowOpen,

        //
        // NOTE: Useful combinations of the above flags,
        //       some are used by the engine and some are
        //       provided for convenience.
        //
        /// <summary>
        /// Combination mask of every supported radix.
        /// </summary>
        AnyRadix = BinaryRadix | OctalRadix | DecimalRadix |
                   HexadecimalRadix,

        /// <summary>
        /// Combination of <see cref="AnyRadix" /> and
        /// <see cref="AllowRadixSign" />.
        /// </summary>
        AnyRadixAnySign = AnyRadix | AllowRadixSign,

        /// <summary>
        /// Combination of <see cref="AllowSigned" /> and
        /// <see cref="AllowUnsigned" />.
        /// </summary>
        AnySignedness = AllowSigned | AllowUnsigned,

        /// <summary>
        /// Combination mask of every supported integral type.
        /// </summary>
        AnyIntegral = TclBoolean | Byte | Character |
                      NarrowInteger | Integer | WideInteger |
#if NET_40
                      BigInteger,
#else
                      None,
#endif

        /// <summary>
        /// Combination of <see cref="AnyIntegral" /> masked by
        /// <see cref="NonCharacterMask" />.
        /// </summary>
        AnyIntegralNonCharacter = AnyIntegral & NonCharacterMask,

        /// <summary>
        /// Flags allowing any boolean; equivalent to
        /// <see cref="AnyIntegralAnyRadix" />.
        /// </summary>
        AnyBoolean = AnyIntegralAnyRadix,
        /// <summary>
        /// Flags allowing any boolean using strict semantics.
        /// </summary>
        AnyStrictBoolean = AnyIntegralAnyRadix | Strict,

        /// <summary>
        /// Flags allowing any byte; equivalent to
        /// <see cref="AnyIntegralAnyRadix" />.
        /// </summary>
        AnyByte = AnyIntegralAnyRadix,

        /// <summary>
        /// Flags allowing any character; equivalent to
        /// <see cref="AnyIntegralAnyRadix" />.
        /// </summary>
        AnyCharacter = AnyIntegralAnyRadix,

        /// <summary>
        /// Flags allowing any narrow integer; equivalent to
        /// <see cref="AnyIntegralAnyRadix" />.
        /// </summary>
        AnyNarrowInteger = AnyIntegralAnyRadix,

        /// <summary>
        /// Flags allowing any integer; equivalent to
        /// <see cref="AnyIntegralAnyRadix" />.
        /// </summary>
        AnyInteger = AnyIntegralAnyRadix,

        /// <summary>
        /// Flags allowing any wide integer; equivalent to
        /// <see cref="AnyIntegralAnyRadix" />.
        /// </summary>
        AnyWideInteger = AnyIntegralAnyRadix,

        /// <summary>
        /// Flags allowing any fixed-point value; equivalent to
        /// <see cref="AnyDecimal" />.
        /// </summary>
        AnyFixedPoint = AnyDecimal,

        /// <summary>
        /// Combination of <see cref="Decimal" /> and
        /// <see cref="AnyRadixAnySign" />.
        /// </summary>
        AnyDecimal = Decimal | AnyRadixAnySign,

        /// <summary>
        /// Combination of <see cref="Double" /> and
        /// <see cref="AnyRadixAnySign" />.
        /// </summary>
        AnyDouble = Double | AnyRadixAnySign,

        /// <summary>
        /// Combination of <see cref="Single" /> and <see cref="Double" />.
        /// </summary>
        AnyFloatingPoint = Single | Double,

        /// <summary>
        /// Combination of <see cref="AnyNumber" /> masked by
        /// <see cref="NonRealMask" />.
        /// </summary>
        AnyReal = AnyNumber & NonRealMask,

        /// <summary>
        /// Combination mask of <see cref="AnyIntegral" />,
        /// <see cref="AnyFixedPoint" />, <see cref="AnyFloatingPoint" />, and
        /// <see cref="Number" />.
        /// </summary>
        AnyNumber = AnyIntegral | AnyFixedPoint | AnyFloatingPoint | Number,

        /// <summary>
        /// Combination of <see cref="AnyRadixAnySign" />,
        /// <see cref="AnyIntegral" />, and <see cref="DefaultSignedness" />.
        /// </summary>
        AnyIntegralAnyRadix = AnyRadixAnySign | AnyIntegral | DefaultSignedness,
        /// <summary>
        /// Like <see cref="AnyIntegralAnyRadix" /> but using
        /// <see cref="AnySignedness" /> instead of
        /// <see cref="DefaultSignedness" />.
        /// </summary>
        AnyIntegralAnyRadixAnySignedness = AnyRadixAnySign | AnyIntegral | AnySignedness,

        /// <summary>
        /// Combination of <see cref="AnyRadixAnySign" />,
        /// <see cref="AnyReal" />, and <see cref="DefaultSignedness" />.
        /// </summary>
        AnyRealAnyRadix = AnyRadixAnySign | AnyReal | DefaultSignedness,
        /// <summary>
        /// Like <see cref="AnyRealAnyRadix" /> but using
        /// <see cref="AnySignedness" />.
        /// </summary>
        AnyRealAnyRadixAnySignedness = AnyRadixAnySign | AnyReal | AnySignedness,

        /// <summary>
        /// Combination of <see cref="AnyRadixAnySign" />,
        /// <see cref="AnyNumber" />, and <see cref="DefaultSignedness" />.
        /// </summary>
        AnyNumberAnyRadix = AnyRadixAnySign | AnyNumber | DefaultSignedness,
        /// <summary>
        /// Like <see cref="AnyNumberAnyRadix" /> but using
        /// <see cref="AnySignedness" />.
        /// </summary>
        AnyNumberAnyRadixAnySignedness = AnyRadixAnySign | AnyNumber | AnySignedness,
        /// <summary>
        /// Combination of <see cref="AnyNumberAnyRadix" /> and
        /// <see cref="Fast" />.
        /// </summary>
        AnyNumberAnyRadixFast = AnyNumberAnyRadix | Fast,

        /// <summary>
        /// Combination of <see cref="AnyIntegralAnyRadix" />,
        /// <see cref="DateTime" />, and <see cref="DateTimeFormat" />.
        /// </summary>
        AnyDateTime = AnyIntegralAnyRadix | DateTime | DateTimeFormat,
        /// <summary>
        /// Combination of <see cref="AnyDateTime" /> and
        /// <see cref="Strict" />.
        /// </summary>
        AnyStrictDateTime = AnyDateTime | Strict,

        /// <summary>
        /// Combination of <see cref="AnyIntegralAnyRadix" /> and
        /// <see cref="TimeSpan" />.
        /// </summary>
        AnyTimeSpan = AnyIntegralAnyRadix | TimeSpan,
        /// <summary>
        /// Combination of <see cref="AnyTimeSpan" /> and
        /// <see cref="Strict" />.
        /// </summary>
        AnyStrictTimeSpan = AnyTimeSpan | Strict,

        /// <summary>
        /// Combination of <see cref="AnyIntegralAnyRadix" /> and
        /// <see cref="ReturnCode" />.
        /// </summary>
        AnyReturnCode = AnyIntegralAnyRadix | ReturnCode,

        /// <summary>
        /// Combination of <see cref="AnyIntegralAnyRadix" /> and
        /// <see cref="MatchMode" />.
        /// </summary>
        AnyMatchMode = AnyIntegralAnyRadix | MatchMode,
        /// <summary>
        /// Combination of <see cref="AnyMatchMode" /> and
        /// <see cref="Strict" />.
        /// </summary>
        AnyStrictMatchMode = AnyMatchMode | Strict,

        /// <summary>
        /// Combination mask permitting any numeric, date/time, time span, or
        /// object value with the default signedness.
        /// </summary>
        AnyVariant = AnyRadixAnySign | AnyNumber | DateTime |
                     DateTimeFormat | TimeSpan | Object |
                     DefaultSignedness,

        /// <summary>
        /// Like <see cref="AnyVariant" /> but using
        /// <see cref="AnySignedness" />.
        /// </summary>
        AnyVariantAnySignedness = AnyRadixAnySign | AnyNumber | DateTime |
                                  DateTimeFormat | TimeSpan | AnySignedness,

        /// <summary>
        /// Combination mask permitting any index value with the default
        /// signedness.
        /// </summary>
        AnyIndex = AnyRadixAnySign | TclBoolean | Integer |
                   NamedIndex | WithOffset | DefaultSignedness,

        /// <summary>
        /// Like <see cref="AnyIndex" /> but using
        /// <see cref="AnySignedness" />.
        /// </summary>
        AnyIndexAnySignedness = AnyRadixAnySign | TclBoolean | Integer |
                                NamedIndex | WithOffset | AnySignedness,

        /// <summary>
        /// Combination of <see cref="Any" /> masked by
        /// <see cref="NonCharacterMask" />.
        /// </summary>
        AnyNonCharacter = Any & NonCharacterMask,

        /// <summary>
        /// Flags permitting any version range; equivalent to
        /// <see cref="VersionRangeMask" />.
        /// </summary>
        AnyVersionRange = VersionRangeMask,

        /// <summary>
        /// Combination mask permitting any supported value type;
        /// combination of <see cref="AnyVariant" />, <see cref="String" />,
        /// and <see cref="Guid" />.
        /// </summary>
        Any = AnyVariant | String | Guid,
        /// <summary>
        /// Combination of <see cref="Any" /> and <see cref="Strict" /> using
        /// strict semantics.
        /// </summary>
        AnyStrict = Any | Strict
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the specific kind of failure
    /// encountered while parsing a Tcl/TclTk script, command, or
    /// expression.  The success value indicates that no error occurred;
    /// the remaining values describe the syntactic problem that was
    /// detected.
    /// </summary>
    [ObjectId("19c16abe-025f-44cb-af23-10cb924f024d")]
    public enum ParseError
    {
        /// <summary>
        /// Parsing completed successfully with no syntax error
        /// detected.
        /// </summary>
        Success = 0,
        /// <summary>
        /// Extra, unexpected characters were found immediately
        /// following a closing double-quote.
        /// </summary>
        ExtraAfterCloseQuote = 1,
        /// <summary>
        /// Extra, unexpected characters were found immediately
        /// following a closing brace.
        /// </summary>
        ExtraAfterCloseBrace = 2,
        /// <summary>
        /// A required closing brace was missing from the input.
        /// </summary>
        MissingBrace = 3,
        /// <summary>
        /// A required closing bracket for a command substitution was
        /// missing from the input.
        /// </summary>
        MissingBracket = 4,
        /// <summary>
        /// A required closing parenthesis (e.g. for an array variable
        /// name) was missing from the input.
        /// </summary>
        MissingParenthesis = 5,
        /// <summary>
        /// A required closing double-quote was missing from the input.
        /// </summary>
        MissingQuote = 6,
        /// <summary>
        /// A required closing brace for a braced variable name was
        /// missing from the input.
        /// </summary>
        MissingVariableBrace = 7,
        /// <summary>
        /// A general syntax error was encountered that does not fall
        /// into one of the more specific categories.
        /// </summary>
        Syntax = 8,
        /// <summary>
        /// A malformed or otherwise invalid numeric literal was
        /// encountered.
        /// </summary>
        BadNumber = 9
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the kind of parse token produced
    /// when a script, command, word, or expression is parsed.  The
    /// values are bit flags so that multiple characteristics may be
    /// combined for a single token.
    /// </summary>
    [Flags()]
    [ObjectId("120473c9-ca35-4446-99a8-f7b5c1be6e31")]
    public enum TokenType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// An invalid or uninitialized token type; this value is
        /// reserved and should not be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The token represents a complete command word that may
        /// require further substitution.
        /// </summary>
        Word = 0x2,
        /// <summary>
        /// The token represents a simple word that requires no further
        /// substitution.
        /// </summary>
        SimpleWord = 0x4,
        /// <summary>
        /// The token represents a span of literal text.
        /// </summary>
        Text = 0x8,
        /// <summary>
        /// The token represents a backslash substitution sequence.
        /// </summary>
        Backslash = 0x10,
        /// <summary>
        /// The token represents a nested command substitution (i.e. one
        /// surrounded by brackets).
        /// </summary>
        Command = 0x20,
        /// <summary>
        /// The token represents a variable substitution.
        /// </summary>
        Variable = 0x40,
        /// <summary>
        /// The token represents a sub-expression within an
        /// <c>[expr]</c> expression.
        /// </summary>
        SubExpression = 0x80,
        /// <summary>
        /// The token represents an operator within an <c>[expr]</c>
        /// expression.
        /// </summary>
        Operator = 0x100,
        /// <summary>
        /// The token represents a function call within an <c>[expr]</c>
        /// expression.
        /// </summary>
        Function = 0x200,
        /// <summary>
        /// The token represents a separator between words or arguments.
        /// </summary>
        Separator = 0x400,
        /// <summary>
        /// The token represents only a name, without any associated
        /// value or further processing.
        /// </summary>
        NameOnly = 0x800,

        /// <summary>
        /// Combination of <see cref="Variable" /> and
        /// <see cref="NameOnly" />, representing a variable token
        /// consisting of its name only.
        /// </summary>
        VariableNameOnly = Variable | NameOnly
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines additional, modifying flags that may be
    /// associated with a parse token.  The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("4acc4d6d-ab07-498c-b7db-07781da4e427")]
    public enum TokenFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// An invalid or uninitialized flag value; this value is
        /// reserved and should not be used.
        /// </summary>
        Invalid = 0x1,

#if DEBUGGER
        /// <summary>
        /// A script breakpoint is associated with this token (available
        /// only when debugger support is compiled in).
        /// </summary>
        Breakpoint = 0x2,
#endif

        /// <summary>
        /// A reserved flag bit; this value is reserved for future use
        /// and should not be used.
        /// </summary>
        Reserved = unchecked((int)0x80000000)
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration classifies the syntactic role a parse token
    /// plays within a script or expression, primarily for use by syntax
    /// highlighting and related tooling.  The values are bit flags that
    /// may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("2ca81723-b85d-4bec-96f9-817c21e5cec0")]
    public enum TokenSyntaxType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// An invalid or uninitialized value; this value is reserved
        /// and should not be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// The token is whitespace.  This classification is not
        /// currently supported by the parser.
        /// </summary>
        WhiteSpace = 0x2,       /* the token is whitespace.  not currently supported by the parser. */
        /// <summary>
        /// The token is a comment.  This classification is not
        /// currently supported by the parser.
        /// </summary>
        Comment = 0x4,          /* the token is a comment.  not currently supported by the parser. */
        /// <summary>
        /// The token is the first argument to a command (i.e. the
        /// command name).
        /// </summary>
        CommandName = 0x8,      /* the token is the first argument to a command (i.e. the command name). */
        /// <summary>
        /// The token is an argument to a command.
        /// </summary>
        Argument = 0x10,        /* the token is an argument to a command. */
        /// <summary>
        /// The token is a backslash substitution.
        /// </summary>
        Backslash = 0x20,       /* the token is a backslash substitution. */
        /// <summary>
        /// The token is a nested command substitution.
        /// </summary>
        Command = 0x40,         /* the token is a nested command substitution. */
        /// <summary>
        /// The token is a variable substitution.
        /// </summary>
        Variable = 0x80,        /* the token is a variable substitution. */
        /// <summary>
        /// The token is a block surrounded by braces.
        /// </summary>
        Block = 0x100,          /* the token is a block surrounded by braces. */
        /// <summary>
        /// The token is a quoted string.
        /// </summary>
        StringLiteral = 0x200,  /* the token is a quoted string. */
        /// <summary>
        /// The token is a numeric literal.
        /// </summary>
        NumericLiteral = 0x400, /* the token is a numeric literal. */
        /// <summary>
        /// The token is an <c>[expr]</c> expression.
        /// </summary>
        Expression = 0x800,     /* the token is an [expr] expression. */
        /// <summary>
        /// The token is an <c>[expr]</c> operator.
        /// </summary>
        Operator = 0x1000,      /* the token is an [expr] operator. */
        /// <summary>
        /// The token is an <c>[expr]</c> function.
        /// </summary>
        Function = 0x2000       /* the token is an [expr] function. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how individual list elements are
    /// quoted and escaped when converting between strings and lists.
    /// The values are bit flags that may be combined; some are shared
    /// with Tcl while others are specific to TclTk.
    /// </summary>
    [Flags()]
    [ObjectId("fa80583c-ff5a-487a-b874-f577ab6e4c53")]
    public enum ListElementFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// An invalid or uninitialized value; this value is reserved
        /// and should not be used.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////
        // SHARED BY TCL AND TCLTK
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Prevents using braces for quoting list elements.
        /// </summary>
        DontUseBraces = 0x2,   /* Prevents using braces for quoting list
                                * elements. */
        /// <summary>
        /// Allows using braces for quoting list elements (unless
        /// <see cref="DontUseBraces" /> is also set).
        /// </summary>
        UseBraces = 0x4,       /* Allows using braces for quoting list
                                * elements (unless DontUseBraces). */
        /// <summary>
        /// Indicates that there are unmatched braces in the string
        /// being converted.
        /// </summary>
        BracesUnmatched = 0x8, /* Indicates that there are unmatched braces
                                * in the string to convert. */
        /// <summary>
        /// Preserves backward compatibility from prior to fixing the
        /// quoting of (leading) '#' characters.
        /// </summary>
        DontQuoteHash = 0x10,  /* Backward compatibility prior to fixing
                                * the quoting of (leading?) '#' characters.
                                */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // TCLTK ONLY
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Use simple brute-force escaping of the specified "special"
        /// character set with backslashes.
        /// </summary>
        UseBackslashes = 0x10000,  /* Use simple brute-force escaping of the
                                    * specified "special" character set with
                                    * backslashes. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Escape horizontal and vertical tab characters.
        /// </summary>
        BackslashTab = 0x100000,   /* Escape horizontal and vertical tab
                                    * characters. */
        /// <summary>
        /// Escape line-ending characters.
        /// </summary>
        BackslashLine = 0x200000,  /* Escape line-ending characters. */
        /// <summary>
        /// Escape form-feed characters.
        /// </summary>
        BackslashForm = 0x400000,  /* Escape form-feed characters. */
        /// <summary>
        /// Escape space characters.
        /// </summary>
        BackslashSpace = 0x800000, /* Escape space characters. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="BackslashTab" />,
        /// <see cref="BackslashLine" />, <see cref="BackslashForm" />,
        /// and <see cref="BackslashSpace" />.
        /// </summary>
        BackslashAllMask = BackslashTab | BackslashLine |
                           BackslashForm | BackslashSpace,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="DontUseBraces" /> and
        /// <see cref="BracesUnmatched" />.
        /// </summary>
        NoBracesMask = DontUseBraces | BracesUnmatched
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how interpreter readiness checks are
    /// performed, e.g. when verifying that an interpreter is in a
    /// usable state and that sufficient native stack space is
    /// available.  The values are bit flags that may be combined; the
    /// various "Via*" values provide convenient presets for specific
    /// subsystems.
    /// </summary>
    [Flags()]
    [ObjectId("0b70b6d4-8cff-4650-9fac-ba1fa68725b1")]
    public enum ReadyFlags
    {
        /// <summary>
        /// No special handling is requested; using this value is not
        /// recommended.
        /// </summary>
        None = 0x0,                    /* No special handling, not
                                        * recommended. */
        /// <summary>
        /// An invalid value; this value is reserved and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,                 /* Invalid, do not use. */
        /// <summary>
        /// A reserved value; this value should not be used.
        /// </summary>
        Reserved = 0x2,                /* Reserved, do not use. */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip all interpreter readiness checks.
        /// </summary>
        Disabled = 0x4,                /* Skip all interpreter readiness
                                        * checks. */
        /// <summary>
        /// Skip adding readiness flags from the interpreter.
        /// </summary>
        NoFlags = 0x8,                 /* Skip adding readiness flags from
                                        * interpreter. */
        /// <summary>
        /// Perform a full check only once every N checks.
        /// </summary>
        Limited = 0x10,                /* Perform full check only every N
                                        * checks. */
        /// <summary>
        /// Return success even if the interpreter has exited.
        /// </summary>
        ExitedOk = 0x20,               /* Return 'Ok' even if interpreter
                                        * has exited. */
        /// <summary>
        /// Return success even if the interpreter has been deleted.
        /// </summary>
        DeletedOk = 0x40,              /* Return 'Ok' even if interpreter
                                        * is deleted. */
        /// <summary>
        /// Skip invoking the user-defined readiness callback.
        /// </summary>
        NoCallback = 0x80,             /* Skip user-defined callback. */
        /// <summary>
        /// Skip native stack space checks.
        /// </summary>
        NoStack = 0x100,               /* Skip native stack space checks. */
        /// <summary>
        /// Skip native stack space checks for thread pool threads.
        /// </summary>
        NoPoolStack = 0x200,           /* Skip native stack space checks
                                        * for thread pool threads. */
        /// <summary>
        /// Check native stack space.
        /// </summary>
        CheckStack = 0x400,            /* Check native stack space. */
        /// <summary>
        /// Force checking of native stack space.
        /// </summary>
        ForceStack = 0x800,            /* Force checking native stack
                                        * space. */
        /// <summary>
        /// Check native stack space for thread pool threads as well.
        /// </summary>
        ForcePoolStack = 0x1000,       /* Check native stack space for
                                        * thread pool threads as well. */
        /// <summary>
        /// Consider the maximum number of evaluation levels seen.
        /// </summary>
        CheckLevels = 0x2000,          /* Consider the maximum levels
                                        * seen. */
        /// <summary>
        /// Skip all checks except for native stack space.
        /// </summary>
        StackOnly = 0x4000,            /* Skip all checks except native
                                        * stack space. */
        /// <summary>
        /// Skip script cancellation checking.
        /// </summary>
        NoCancel = 0x8000,             /* Skip script cancellation
                                        * checking. */
        /// <summary>
        /// Consider only the thread-local script cancellation flags.
        /// </summary>
        NoGlobalCancel = 0x10000,      /* Only consider the thread-local
                                        * script cancellation flags. */
        /// <summary>
        /// Do not reset the global script cancellation flag when it is
        /// tripped by the current thread.
        /// </summary>
        NoGlobalResetCancel = 0x20000, /* Do not reset the global script
                                        * cancellation flag when it is
                                        * tripped by the current thread.
                                        */
        /// <summary>
        /// Skip halt checking.
        /// </summary>
        NoHalt = 0x40000,              /* Skip halt checking. */

#if DEBUGGER
        /// <summary>
        /// Skip checking for any script breakpoints (available only
        /// when debugger support is compiled in).
        /// </summary>
        NoBreakpoint = 0x80000,        /* Skip checking for any script
                                        * breakpoints. */
#endif

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates the check is being performed on behalf of a public
        /// method.
        /// </summary>
        ForPublic = 0x100000,          /* Being called from the public
                                        * method. */
        /// <summary>
        /// Indicates the check is being performed on behalf of the
        /// parser.
        /// </summary>
        ForParser = 0x200000,          /* Being called from the parser. */
        /// <summary>
        /// Indicates the check is being performed on behalf of the
        /// engine.
        /// </summary>
        ForEngine = 0x400000,          /* Being called from the engine. */
        /// <summary>
        /// Indicates the check is being performed on behalf of the
        /// event manager.
        /// </summary>
        ForEventManager = 0x800000,    /* Being called from the event
                                        * manager. */

#if NATIVE && TCL
        /// <summary>
        /// Indicates the check is being performed on behalf of the
        /// native Tcl wrapper.
        /// </summary>
        ForTclWrapper = 0x1000000,     /* Being called from the Tcl
                                        * wrapper. */
#endif

#if DEBUGGER
        /// <summary>
        /// Indicates the check is being performed on behalf of the
        /// script debugger.
        /// </summary>
        ForDebugger = 0x2000000,       /* Being called from the script
                                        * debugger. */
#endif

        /// <summary>
        /// Indicates the check is being performed on behalf of the test
        /// suite.
        /// </summary>
        ForTest = 0x4000000,           /* Being called by the test suite. */
        /// <summary>
        /// Indicates the check is being performed on behalf of the
        /// opaque object handle management subsystem.
        /// </summary>
        ForObject = 0x8000000,         /* Being called from within the opaque
                                        * object handle management subsystem. */

        ///////////////////////////////////////////////////////////////////////

        //
        // NOTE: These are the default flags used to enable native stack
        //       space checking.
        //
        /// <summary>
        /// Combination of <see cref="CheckStack" />,
        /// <see cref="ForcePoolStack" />, and
        /// <see cref="CheckLevels" />, representing the default flags
        /// used to enable native stack space checking.
        /// </summary>
        ForStack = CheckStack | ForcePoolStack | CheckLevels,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="Default" />,
        /// <see cref="ForPublic" />, <see cref="ForStack" />, and
        /// <see cref="ForceStack" />, used when entering from a public
        /// method.
        /// </summary>
        ViaPublic = Default | ForPublic | ForStack | ForceStack,
        /// <summary>
        /// Combination of <see cref="Default" />,
        /// <see cref="ForParser" />, <see cref="ForStack" />, and
        /// <see cref="Limited" />, used when entering from the parser.
        /// </summary>
        ViaParser = Default | ForParser | ForStack | Limited,
        /// <summary>
        /// Combination of <see cref="Default" />,
        /// <see cref="ForEngine" />, and <see cref="Limited" />, used
        /// when entering from the engine.
        /// </summary>
        ViaEngine = Default | ForEngine | Limited,
        /// <summary>
        /// Combination of <see cref="Default" /> and
        /// <see cref="ForEventManager" />, used when entering from the
        /// event manager.
        /// </summary>
        ViaEventManager = Default | ForEventManager,

#if NATIVE && TCL
        /// <summary>
        /// Combination of <see cref="Default" />,
        /// <see cref="ForTclWrapper" />, and <see cref="ForStack" />,
        /// used when entering from the native Tcl wrapper.
        /// </summary>
        ViaTclWrapper = Default | ForTclWrapper | ForStack,
#endif

#if DEBUGGER
        /// <summary>
        /// Combination of <see cref="Default" /> and
        /// <see cref="ForDebugger" />, used when entering from the
        /// script debugger.
        /// </summary>
        ViaDebugger = Default | ForDebugger,
#endif

        /// <summary>
        /// Combination of <see cref="Default" /> and
        /// <see cref="ForTest" />, used when entering from the test
        /// suite.
        /// </summary>
        ViaTest = Default | ForTest,
        /// <summary>
        /// Combination of <see cref="Default" /> and
        /// <see cref="ForObject" />, used when entering from the opaque
        /// object handle management subsystem.
        /// </summary>
        ViaObject = Default | ForObject,

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The value used when the ready flags cannot be obtained from
        /// the interpreter for some reason (e.g. a locking failure);
        /// equal to <see cref="None" />.
        /// </summary>
        Unknown = None, /* This is the value used when the ready flags
                         * cannot be obtained from the interpreter for
                         * some reason (e.g. locking failure). */

        ///////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The flags that are always used by most callers (i.e. see the
        /// various "Via*" values above); equal to <see cref="None" />.
        /// </summary>
        Default = None  /* These are the flags that are always used by
                         * most callers (i.e. see the "Via*" values
                         * above). */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration provides per-interpreter flags that control the
    /// behavior of the test framework, e.g. the <c>[test1]</c> and
    /// <c>[test2]</c> commands.  The values are bit flags that may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("96eb5967-3f03-4e15-83e5-38713b95cb6a")]
    public enum InterpreterTestFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,                  /* No flags. */
        /// <summary>
        /// An invalid value; this value is reserved and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// For <c>[test1]</c> and <c>[test2]</c>, write the test data
        /// to the host.
        /// </summary>
        WriteData = 0x100,           /* For [test1]/[test2], write the test
                                      * data to the host. */
        /// <summary>
        /// For <c>[test1]</c> and <c>[test2]</c>, do not return the
        /// test data.
        /// </summary>
        NoReturnData = 0x200,        /* For [test1]/[test2], do not return
                                      * the test data. */
        /// <summary>
        /// For <c>[test1]</c> and <c>[test2]</c>, do not log the test
        /// data.
        /// </summary>
        NoLogData = 0x400,           /* For [test1]/[test2], do not log
                                      * the test data. */
        /// <summary>
        /// For <c>[test1]</c> and <c>[test2]</c>, do not emit the test
        /// data to the attached debugger.
        /// </summary>
        NoTrackData = 0x800,         /* For [test1]/[test2], do not emit
                                      * the test data to the attached
                                      * debugger. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// For <c>[test1]</c> and <c>[test2]</c>, do not modify the
        /// overall return code based on other conditions, e.g. whether
        /// the test was skipped, ignored, etc.
        /// </summary>
        NoChangeReturnCode = 0x1000, /* For [test1]/[test2], do not modify
                                      * the overall return code based on
                                      * other conditions, e.g. whether the
                                      * test was skipped, ignored, etc. */
        /// <summary>
        /// Treat null results from the test command bodies the same as
        /// an empty string.
        /// </summary>
        NullIsEmpty = 0x2000,        /* Treat null results from the [test?]
                                      * command bodies the same as an empty
                                      * string. */
        /// <summary>
        /// Enable emitting diagnostics when a test evaluates a script
        /// for setup, body, or cleanup.
        /// </summary>
        TrackScripts = 0x4000,       /* Enable emitting diagnostics when a
                                      * test evaluates a script for setup,
                                      * body, or cleanup. */
#if TEST
        /// <summary>
        /// When running a test via the <c>[test1]</c> or <c>[test2]</c>
        /// command, capture all of its trace output into a temporary
        /// log file.
        /// </summary>
        CaptureTraces = 0x8000,      /* When running a test via the [test1]
                                      * or [test2] command, capture all of
                                      * its trace output into a temporary
                                      * log file. */
#endif
        /// <summary>
        /// Skip evaluation of test scripts.
        /// </summary>
        ScriptWhatIf = 0x10000,      /* Skip evaluation of test scripts. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// WARNING: Setting this flag will skip evaluation of all test
        /// cleanup scripts.
        /// </summary>
        NoCleanup = 0x100000,        /* WARNING: Setting this flag will
                                      * skip evaluation of all test cleanup
                                      * scripts. */
        /// <summary>
        /// WARNING: Setting this flag will completely ignore all
        /// isolation level settings that call for a new application
        /// domain.
        /// </summary>
        NoAppDomain = 0x200000,      /* WARNING: Setting this flag will
                                      * completely ignore all isolation
                                      * level settings that call for a
                                      * new AppDomain. */
        /// <summary>
        /// If a hook script raises a script error, stop evaluating
        /// further test hooks and raise an error.
        /// </summary>
        StopOnHookError = 0x400000,  /* If a hook script raises a script
                                      * error, stop evaluating further
                                      * test hooks and raise an error.
                                      */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if TEST && NETWORK
        /// <summary>
        /// When set, causes the associated interpreter to use the
        /// script-based web client class for all of its web requests.
        /// </summary>
        UseScriptWebClient = 0x800000, /* When set, this flag will cause the
                                        * associated interpreter to use the
                                        * _Tests.Default.ScriptWebClient
                                        * class for all its web requests. */

        /// <summary>
        /// When set, causes a script exception to be thrown when the
        /// script-based web client returns a non-Ok return code.
        /// </summary>
        ThrowOnScriptWebClientError = 0x1000000, /* When set, this flag will
                                                  * cause a ScriptException
                                                  * to be thrown when the
                                                  * ScriptWebClient script
                                                  * returns a non-Ok return
                                                  * code. */

        /// <summary>
        /// Combination of <see cref="UseScriptWebClient" /> and
        /// <see cref="ThrowOnScriptWebClientError" />.
        /// </summary>
        ScriptWebClientMask = UseScriptWebClient | ThrowOnScriptWebClientError,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if SHELL
        /// <summary>
        /// Indicates this interpreter was created for use by the shell
        /// and possibly for use by the interactive user.
        /// </summary>
        ForShellUse = 0x80000000,    /* This interpreter was created for use by
                                      * the shell and possibly for use by the
                                      * interactive user. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These are disallowed when creating "safe"
        //       interpreters.
        //
        /// <summary>
        /// Combination mask of the flags that are disallowed when
        /// creating "safe" interpreters; equal to
        /// <see cref="TrackScripts" />.
        /// </summary>
        UnsafeMask = TrackScripts,

        //
        // NOTE: These are the default test flags for newly
        //       created interpreters.
        //
        /// <summary>
        /// Combination of <see cref="NullIsEmpty" /> and
        /// <see cref="TrackScripts" />, representing the default test
        /// flags for newly created interpreters.
        /// </summary>
        Default = NullIsEmpty | TrackScripts
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration provides a large set of per-interpreter flags
    /// that fine-tune the behavior of an interpreter, covering error
    /// handling, expression parsing, command behavior, security, and
    /// more.  The values are bit flags that may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("85f9cb1e-c237-4a3d-8775-3b5a0700bc8c")]
    public enum InterpreterFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,                                /* No flags. */
        /// <summary>
        /// An invalid value; this value is reserved and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,                             /* Invalid, do not use. */
        /// <summary>
        /// Disable the default background error handling.
        /// </summary>
        NoBackgroundError = 0x2,                   /* Disable the default background error
                                                    * handling. */
        /// <summary>
        /// Skip post-processing of returned variable values.
        /// </summary>
        NoPostProcess = 0x4,                       /* Skip post-processing of returned
                                                    * variable values. */
        /// <summary>
        /// Enable scanning for temporary packages automatically when
        /// using the EvaluateFile method overloads to evaluate a script
        /// file.
        /// </summary>
        TemporaryPackages = 0x8,                   /* Enable scanning for temporary
                                                    * packages automatically when
                                                    * using the EvaluateFile method
                                                    * overloads to evaluate a script
                                                    * file. */
        /// <summary>
        /// Trace engine result processing.
        /// </summary>
        TraceResult = 0x10,                        /* Trace engine result processing. */
        /// <summary>
        /// Redirect trace listener output to the interpreter host;
        /// currently this is used by external plugins only.
        /// </summary>
        TraceToHost = 0x20,                        /* Redirect trace listener output to
                                                    * the interpreter host.  Currently,
                                                    * this is used by external plugins
                                                    * only. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Attempt to emit a full stack trace when the
        /// DebugOps.Complain method is called.
        /// </summary>
        TraceStack = 0x40,                         /* Attempt to emit a full stack trace
                                                    * if the DebugOps.Complain method is
                                                    * called.  In the future, other trace
                                                    * listener output may be impacted by
                                                    * this flag as well.
                                                    *
                                                    * BUGBUG: It is highly likely that
                                                    *         this should actually be
                                                    *         part of the default
                                                    *         interpreter flags because
                                                    *         any "complaints" issued by
                                                    *         this library should be very
                                                    *         rare in normal usage.
                                                    */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow a "safe" interpreter to use options flagged as
        /// "unsafe".
        /// </summary>
        AllowUnsafeOptions = 0x80,                 /* Allow a "safe" interpreter to use
                                                    * options flagged as "unsafe". */
        /// <summary>
        /// Disable all trace limits for this interpreter while it is
        /// considered active.
        /// </summary>
        NoTraceLimits = 0x100,                     /* Disable all trace limits for this
                                                    * interpreter, when it is considered
                                                    * active. */
        /// <summary>
        /// Prevent any implicit use of the Thread.Abort() method.
        /// </summary>
        NoThreadAbort = 0x200,                     /* Prevent any implicit use of the
                                                    * Thread.Abort() method. */
#if NET_40
        /// <summary>
        /// Allow the BigInteger class and its values to be used during
        /// expression parsing.
        /// </summary>
        AllowBigIntegers = 0x400,                  /* allow the BigInteger class and
                                                    * values to be used by expression
                                                    * parsing. */
#endif
        /// <summary>
        /// Force interactive mode upon creation; the
        /// <c>[debug break]</c> sub-command will not break into the
        /// interactive loop without this flag being set.
        /// </summary>
        Interactive = 0x1000,                      /* Force interactive mode (upon its
                                                    * creation, etc)?
                                                    * The [debug break] sub-command will
                                                    * not break into the interactive loop
                                                    * without this flag being set. */
        /// <summary>
        /// Call Engine.ResetCancel prior to evaluating finally blocks
        /// in the <c>[try]</c> command.
        /// </summary>
        FinallyResetCancel = 0x4000,               /* Call Engine.ResetCancel prior to
                                                    * evaluating finally blocks in the
                                                    * [try] command. */
        /// <summary>
        /// Call Engine.CancelEvaluate after evaluating the finally
        /// block in the <c>[try]</c> command, if necessary.
        /// </summary>
        FinallyRestoreCancel = 0x8000,             /* Call Engine.CancelEvaluate after
                                                    * evaluating the finally block in the
                                                    * [try] command, if necessary. */
        /// <summary>
        /// Save and reset the Exit property prior to evaluating finally
        /// blocks in the <c>[try]</c> command.
        /// </summary>
        FinallyResetExit = 0x10000,                /* Save/reset the Exit property prior
                                                    * to evaluating finally blocks in the
                                                    * [try] command. */
        /// <summary>
        /// Restore the Exit property after evaluating the finally block
        /// in the <c>[try]</c> command, if necessary.
        /// </summary>
        FinallyRestoreExit = 0x20000,              /* Restore the Exit property after
                                                    * evaluating the finally block in the
                                                    * [try] command, if necessary. */
        /// <summary>
        /// Skip using the configured package fallback delegate to
        /// locate any packages that fail to load using the standard
        /// "ifneeded" mechanism.
        /// </summary>
        NoPackageFallback = 0x40000,               /* Skip using the configured package
                                                    * fallback delegate to locate any
                                                    * packages that fail to load using
                                                    * the standard "ifneeded" mechanism.
                                                    */
        /// <summary>
        /// Skip using the configured <c>[package unknown]</c> command
        /// to locate any packages that fail to load using the standard
        /// "ifneeded" mechanism.
        /// </summary>
        NoPackageUnknown = 0x80000,                /* Skip using the configured [package
                                                    * unknown] command to locate any
                                                    * packages that fail to load using
                                                    * the standard "ifneeded" mechanism.
                                                    * It should also be noted that using
                                                    * this flag, which is enabled by
                                                    * default, breaks automatic [package
                                                    * unknown] handling provided by the
                                                    * TclTk Package Repository Client.
                                                    */
#if !MONO && NATIVE && WINDOWS
        /// <summary>
        /// Enable forcibly zeroing strings that may contain "sensitive"
        /// data.  WARNING: This is not guaranteed to work reliably on
        /// all platforms.
        /// </summary>
        ZeroString = 0x100000,                     /* Enable forcibly zeroing strings
                                                    * that may contain "sensitive" data?
                                                    * WARNING: THIS IS NOT GUARANTEED TO
                                                    * WORK RELIABLY ON ALL PLATFORMS.
                                                    * EXTREME CARE SHOULD BE EXERCISED
                                                    * WHEN HANDLING ANY SENSITIVE DATA,
                                                    * INCLUDING TESTING THAT THIS FLAG
                                                    * WORKS WITHIN THE SPECIFIC TARGET
                                                    * APPLICATION AND ON THE SPECIFIC
                                                    * TARGET PLATFORM. */
#endif
        /// <summary>
        /// The <c>[lreplace]</c> command should permit an empty list to
        /// be used, ignoring any indexes specified.
        /// </summary>
        ReplaceEmptyListOk = 0x200000,             /* The [lreplace] command should permit
                                                    * an empty list to be used, and ignore
                                                    * any indexes specified. */
        /// <summary>
        /// Allow the standard channel streams provided by the
        /// interpreter host to be transparent proxies even when the
        /// host itself is not a transparent proxy.
        /// </summary>
        AllowProxyStream = 0x400000,               /* The standard channel streams that are
                                                    * provided by the interpreter host are
                                                    * allowed to be transparent proxies even
                                                    * when the interpreter host itself is not
                                                    * a transparent proxy.  Use of this flag
                                                    * should be extremely rare, if ever. */
        /// <summary>
        /// Failures encountered when trying to handle a background
        /// error should be silently ignored.
        /// </summary>
        IgnoreBgErrorFailure = 0x800000,           /* Failures encountered when trying to
                                                    * handle a background error should be
                                                    * silently ignored. */
        /// <summary>
        /// Call Engine.ResetCancel just before executing the configured
        /// background error handler.
        /// </summary>
        BgErrorResetCancel = 0x1000000,            /* Call Engine.ResetCancel just before
                                                    * executing the configured background
                                                    * error handler. */
        /// <summary>
        /// Call Engine.ResetCancel just after evaluating scripts for
        /// the <c>[catch]</c> command.
        /// </summary>
        CatchResetCancel = 0x2000000,              /* Call Engine.ResetCancel just after
                                                    * evaluating scripts for the [catch]
                                                    * command. */
        /// <summary>
        /// Also reset the global flags for script cancellation just
        /// after evaluating scripts for the <c>[catch]</c> command.
        /// </summary>
        CatchResetGlobalCancel = 0x4000000,        /* Also reset the global flags for
                                                    * script cancellation just after
                                                    * evaluating scripts for the [catch]
                                                    * command. */
        /// <summary>
        /// Reset the Exit property just after evaluating scripts for
        /// the <c>[catch]</c> command.
        /// </summary>
        CatchResetExit = 0x8000000,                /* Reset the Exit property just after
                                                    * evaluating scripts for the [catch]
                                                    * command. */
        /// <summary>
        /// Include global variables in the list returned by
        /// <c>[info vars]</c> when executed in a namespace call frame.
        /// </summary>
        InfoVarsMayHaveGlobal = 0x20000000,        /* Includes global variables in the
                                                    * list returned by [info vars] when
                                                    * executed in a namespace call frame. */
        /// <summary>
        /// Send complaints to the test suite (log, etc).
        /// </summary>
        ComplainViaTest = 0x40000000,              /* Send complaints to the test suite
                                                    * (log, etc).  EXEMPT: Since this is
                                                    * used by the DebugOps class (i.e.
                                                    * and not the TestOps class), it is
                                                    * housed here instead of
                                                    * InterpreterTestFlags. */
        /// <summary>
        /// Send complaints to the diagnostic Trace/Debug listeners.
        /// </summary>
        ComplainViaTrace = 0x80000000,             /* Send complaints to the diagnostic
                                                    * Trace/Debug listeners. */
        /// <summary>
        /// Ensure that all library scripts are evaluated in the global
        /// context.
        /// </summary>
        ForceGlobalLibrary = 0x100000000,          /* Make sure that all library scripts
                                                    * are evaluated in the global context.
                                                    */
        /// <summary>
        /// Restricted options are allowed.
        /// </summary>
        AllowRestricted = 0x200000000,             /* Restricted options are allowed. */
        /// <summary>
        /// Enable adding a command for each operator into the
        /// "tcl::mathop" namespace.
        /// </summary>
        TclMathOperators = 0x400000000,            /* Enable adding a command for each
                                                    * operator into the "tcl::mathop"
                                                    * namespace. */
        /// <summary>
        /// Enable adding a command for each function into the
        /// "tcl::mathfunc" namespace.
        /// </summary>
        TclMathFunctions = 0x800000000,            /* Enable adding a command for each
                                                    * operator into the "tcl::mathfunc"
                                                    * namespace. */
        /// <summary>
        /// Use legacy octal support (i.e. a leading zero means octal).
        /// </summary>
        LegacyOctal = 0x1000000000,                /* Use legacy octal support (i.e. leading
                                                    * zero means octal). */
        /// <summary>
        /// Skip cleaning up temporary object references when exiting
        /// the engine back to level zero.
        /// </summary>
        NoCleanupObjectReferences = 0x2000000000,  /* Skip cleaning up [temporary]
                                                    * object references when exiting
                                                    * the engine back to level zero. */
        /// <summary>
        /// When parsing an expression, failing to convert an
        /// integer-like string into an actual integer should result in
        /// a script error rather than falling back to a floating point
        /// value.
        /// </summary>
        StrictExpressionInteger = 0x4000000000,    /* When parsing an expression, failing to
                                                    * convert an integer-like string into an
                                                    * actual integer should result in a script
                                                    * error; otherwise, an attempt will be
                                                    * made to convert it into a floating point
                                                    * value. */
        /// <summary>
        /// For asynchronous script evaluation, use a new EngineThread
        /// instead of the thread pool.
        /// </summary>
        UseNewEngineThread = 0x10000000000,        /* For asynchronous script evaluation, use
                                                    * a new EngineThread instead of the thread
                                                    * pool. */
        /// <summary>
        /// String comparison operators should take the currently
        /// configured culture into account; this is the legacy behavior
        /// and is no longer enabled by default.
        /// </summary>
        UseCultureForOperators = 0x80000000000,    /* String comparison operators should take
                                                    * into account the currently configured
                                                    * culture.  This is the legacy behavior;
                                                    * however, it is no longer enabled by
                                                    * default. */
        /// <summary>
        /// Before doing any recursive processing of a
        /// <c>[string match]</c> pattern, make sure there is sufficient
        /// native stack space.
        /// </summary>
        StringMatchStackChecking = 0x100000000000, /* Before doing any recursive processing of
                                                    * a [string match] pattern, make sure there
                                                    * is sufficient native stack space. */
        /// <summary>
        /// Fix the <c>[string match]</c> range issue found in native
        /// Tcl ticket 219233; off by default to avoid breaking older
        /// scripts that may rely on the previous behavior.
        /// </summary>
        FixFor219233 = 0x200000000000,             /* Fix the [string match] range issue found
                                                    * in the native Tcl ticket:
                                                    *
                                                    *     https://core.tcl.tk/tcl/info/219233
                                                    *
                                                    * From the ticket, the following should be
                                                    * false:
                                                    *
                                                    *     string match {[a-z0-9_/-]} \\
                                                    *
                                                    * Since this "bugfix" has the potential to
                                                    * break older scripts that may rely on it,
                                                    * it is off by default and gated behind
                                                    * this feature flag.
                                                    */
        /// <summary>
        /// Use a variant of the native printf() from the C runtime
        /// library to process the 'E', 'e', 'F', 'f', 'G', and 'g'
        /// format specifiers for the <c>[format]</c> command; ignored
        /// when native code support is unavailable.
        /// </summary>
        UsePrintfForDouble = 0x400000000000,       /* Use a variant of native printf() from the
                                                    * C Runtime Library to process the 'E', 'e',
                                                    * 'F', 'f', 'G', and 'g' format specifiers
                                                    * to the [format] command.  This flag is
                                                    * ignored when support for native code is
                                                    * not available (e.g. was disabled at
                                                    * build-time, etc).  This is the legacy
                                                    * default behavior. */
        /// <summary>
        /// Enable evaluation of scripts from within the configured
        /// pre-dispose callbacks, if any.
        /// </summary>
        PreDisposeScripts = 0x1000000000000,       /* Enable evaluation of scripts from within
                                                    * the configured pre-dispose callbacks, if
                                                    * any. */
        /// <summary>
        /// Attempt to prevent timing side-channel information from
        /// leaking into "safe" interpreters.
        /// </summary>
        SafeTiming = 0x2000000000000,              /* Attempt to prevent timing side-channel
                                                    * information from leaking into "safe"
                                                    * interpreters. */
        /// <summary>
        /// Do not use null command results to create arguments to pass
        /// to subsequent commands.
        /// </summary>
        NoNullArgument = 0x10000000000000,         /* Do not use null command results to create
                                                    * arguments to pass to subsequent commands.
                                                    */
        /// <summary>
        /// For <c>[object resolve]</c>, search the loaded assemblies in
        /// the application domain directly.
        /// </summary>
        ResolveAssemblySearch = 0x20000000000000,  /* For [object resolve], search the loaded
                                                    * assemblies in the AppDomain directly. */
        /// <summary>
        /// For <c>[debug break]</c>, by default, do not complain when
        /// unable to actually enter the debugger.
        /// </summary>
        DebugBreakNoComplain = 0x40000000000000,   /* For [debug break], by default, do not
                                                    * complain when unable to actually enter
                                                    * the debugger. */
        /// <summary>
        /// When waiting for a variable, e.g. via a <c>[vwait]</c>
        /// command, process events for the current thread only.
        /// </summary>
        EventThreadAffinity = 0x80000000000000,    /* When waiting for a variable, e.g. via a
                                                    * [vwait] command, etc, process events for
                                                    * the current thread only. */
        /// <summary>
        /// When adding new commands, etc, check to be sure that no
        /// other executable entity exists first.
        /// </summary>
        DoesAnythingExist = 0x200000000000000,     /* When adding new commands, etc, check to
                                                    * be sure that no other executable entity
                                                    * exists first. */
        /// <summary>
        /// When adding new procedures, check to be sure that no other
        /// executable entity exists first.
        /// </summary>
        DoesNonProcedureExist = 0x400000000000000, /* When adding new procedures, check to be
                                                    * sure that no other executable entity
                                                    * exists first. */
        /// <summary>
        /// When adding opaque object handles, include the runtime hash
        /// code for the underlying object in the handle name.
        /// </summary>
        HashCodeAsHandle = 0x800000000000000,      /* When adding opaque object handles, the
                                                    * name of the opaque object handle will
                                                    * contain the runtime hash code for the
                                                    * underlying object. */
        /// <summary>
        /// Allow transparent proxies to be used for callbacks, e.g. the
        /// interactive command callback.
        /// </summary>
        AllowProxyCallback = 0x1000000000000000,   /* Allow transparent proxies to be used for
                                                    * callbacks, e.g. the interactive command
                                                    * callback. */
        /// <summary>
        /// Attempt to cache and use IExecute and/or ISubCommand
        /// instances based on the first and second arguments,
        /// respectively.
        /// </summary>
        CacheViaArgument = 0x2000000000000000,     /* Attempt to cache and use IExecute and/or
                                                    * ISubCommand instances based on the first
                                                    * and second arguments, respectively. */
#if HISTORY
        /// <summary>
        /// Prevent the history enabled/disabled state from being
        /// changed, e.g. via the <c>[debug history]</c> sub-command.
        /// </summary>
        LockHistory = 0x4000000000000000,          /* Prevent the history enabled / disabled
                                                    * from being changed, e.g. via things like
                                                    * the [debug history] sub-command. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if SHELL
        /// <summary>
        /// Indicates this interpreter was created for use by the shell
        /// and possibly for use by the interactive user.
        /// </summary>
        ForShellUse = 0x8000000000000000,          /* This interpreter was created for use by
                                                    * the shell and possibly for use by the
                                                    * interactive user. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="TclMathOperators" /> and
        /// <see cref="TclMathFunctions" />.
        /// </summary>
        TclMathMask = TclMathOperators | TclMathFunctions,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the complaint-related flags
        /// (<see cref="ComplainViaTest" /> and
        /// <see cref="ComplainViaTrace" />) that are cleared as part of
        /// the default flags.
        /// </summary>
        QuietUnsetMask = (ComplainViaTest | ComplainViaTrace) & Default,
        /// <summary>
        /// Mask of flags set to suppress diagnostics; equal to
        /// <see cref="NoBackgroundError" />.
        /// </summary>
        QuietSetMask = NoBackgroundError,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These are disallowed when creating "safe" interpreters.
        //
        /// <summary>
        /// Combination mask of the flags that are disallowed when
        /// creating "safe" interpreters.
        /// </summary>
        UnsafeMask = TemporaryPackages |
#if NET_40
                     AllowBigIntegers |
#endif
                     ReplaceEmptyListOk |
                     ComplainViaTest |
                     AllowRestricted |
                     TclMathOperators |
                     TclMathFunctions |
                     LegacyOctal |
                     UsePrintfForDouble |
                     PreDisposeScripts,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags used by default for newly created
        /// interpreters that enable bits of "legacy" functionality.
        /// </summary>
        DefaultLegacyOnly = ReplaceEmptyListOk | LegacyOctal,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags used by default for newly created
        /// interpreters, excluding those that require features gated by the
        /// NATIVE compile-time define(s) -AND- excluding those that enable
        /// "legacy" features or functionality.
        /// </summary>
        DefaultManagedOnly = TemporaryPackages |
#if NET_40
                             AllowBigIntegers |
#endif
                             FinallyResetCancel | FinallyRestoreCancel |
                             FinallyResetExit | FinallyRestoreExit |
                             NoPackageUnknown | ComplainViaTest |
                             AllowRestricted | TclMathOperators |
                             TclMathFunctions | StrictExpressionInteger |
                             PreDisposeScripts | SafeTiming |
                             NoNullArgument | DebugBreakNoComplain |
                             DoesAnythingExist | AllowProxyCallback |
                             CacheViaArgument,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags used by default for newly created
        /// interpreters.
        /// </summary>
        Default = DefaultLegacyOnly | DefaultManagedOnly | UsePrintfForDouble
    }

