    /// <summary>
    /// This enumeration specifies the bit flags that control how a command
    /// callback is created, configured, and invoked.  Because it is a
    /// [Flags] enumeration, its values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("e617a055-a7bd-468e-a5fb-052f57251323")]
    public enum CallbackFlags
    {
        /// <summary>
        /// No special handling is requested; none of the callback flags
        /// are set.
        /// </summary>
        None = 0x0,                    /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of flags; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,                 /* Invalid, do not use. */
        /// <summary>
        /// The callback may not be modified nor removed once it has been
        /// created.
        /// </summary>
        ReadOnly = 0x2,                /* The callback may not be modified nor removed. */

        //
        // NOTE: Callback argument handling.
        //

        /// <summary>
        /// Automatically add argument objects when invoking the callback.
        /// </summary>
        Arguments = 0x4,               /* Automatically add argument objects. */
        /// <summary>
        /// Indicates that the callback is expected to create an object
        /// (e.g. via a method such as System.Int32.Parse).
        /// </summary>
        Create = 0x8,                  /* We expect to create an object (e.g. System.Int32.Parse)? */
        /// <summary>
        /// Dispose of the object if it cannot be fully created and/or
        /// added.
        /// </summary>
        Dispose = 0x10,                /* Dipose the object if it cannot be fully created/added? */
        /// <summary>
        /// Create a command alias for the newly created object.
        /// </summary>
        Alias = 0x20,                  /* Create a command alias for the newly created object? */
        /// <summary>
        /// The command alias refers to the raw <c>[object invokeall]</c>
        /// semantics.
        /// </summary>
        AliasRaw = 0x40,               /* The command alias refers to [object invokeall]. */
        /// <summary>
        /// The command alias refers to the <c>[object invokeall]</c>
        /// semantics.
        /// </summary>
        AliasAll = 0x80,               /* The command alias refers to [object invokeall]. */
        /// <summary>
        /// The command alias holds an object reference.
        /// </summary>
        AliasReference = 0x100,        /* The command alias holds an object reference. */
        /// <summary>
        /// Forcibly convert the object to a string and then discard it.
        /// </summary>
        ToString = 0x200,              /* Forcibly convert the object to a string and discard it? */
        /// <summary>
        /// Enforce strict type checking on ByRef (output) argument values.
        /// </summary>
        ByRefStrict = 0x400,           /* Enforce strict type checking on ByRef argument values? */
        /// <summary>
        /// Complain about any failures that occur when firing events.
        /// </summary>
        Complain = 0x800,              /* Complain about failures that occur when firing events? */
        /// <summary>
        /// Catch any ThreadInterruptedException raised within the
        /// ThreadStart and ParameterizedThreadStart methods and do not re-
        /// throw it; otherwise, catch it, log it, and then re-throw it.
        /// </summary>
        CatchInterrupt = 0x1000,       /* Catch any ThreadInterruptedException within
                                        * the ThreadStart and ParameterizedThreadStart
                                        * methods and do not re-throw it; otherwise,
                                        * catch it, log it, and then re-throw it. */
        /// <summary>
        /// Automatically handle the return value of the callback.
        /// </summary>
        ReturnValue = 0x2000,          /* Automatically handle return values. */
        /// <summary>
        /// Used together with <see cref="ReturnValue" /> to force the
        /// return of the default value (e.g. zero or null) for the method
        /// return type.
        /// </summary>
        DefaultValue = 0x4000,         /* Used with ReturnValue in order to force the return of
                                        * the default value (e.g. 0, null) for the method return
                                        * type. */
        /// <summary>
        /// Add a reference to the callback return value.
        /// </summary>
        AddReference = 0x8000,         /* Add a reference to the callback return value. */
        /// <summary>
        /// Remove a reference from the callback return value.
        /// </summary>
        RemoveReference = 0x10000,     /* Remove a reference from the callback return value. */
        /// <summary>
        /// Call MaybeDisposeThread for delegate types that could be used
        /// as a thread entry point.
        /// </summary>
        DisposeThread = 0x20000,       /* Call MaybeDisposeThread for delegate types that could
                                        * be used as a thread entry point. */
        /// <summary>
        /// Throw an exception if the evaluated script returns an error.
        /// </summary>
        ThrowOnError = 0x40000,        /* Throw an exception if the evaluated script returns an
                                        * error? */
        /// <summary>
        /// The command callback was created via the Utility class.  This
        /// flag is for (core) library use only.
        /// </summary>
        External = 0x80000,            /* The command callback was created via the Utility class.
                                        * This flag is For (core) library use only. */
        /// <summary>
        /// The callback script should be handled by the owner of the
        /// interpreter being used instead of being directly evaluated.
        /// </summary>
        UseOwner = 0x100000,           /* The callback script should be handled by the owner of
                                        * the interpreter being used instead of being directly
                                        * evaluated. */
        /// <summary>
        /// The callback script should be queued asynchronously to the
        /// owner of the interpreter being used.
        /// </summary>
        Asynchronous = 0x200000,       /* The callback script should be queued asynchronously to
                                        * the owner of the interpreter being used. */
        /// <summary>
        /// The callback script should be queued asynchronously to the
        /// owner of the interpreter being used if that owner is busy;
        /// otherwise, it should be sent synchronously.
        /// </summary>
        AsynchronousIfBusy = 0x400000, /* The callback script should be queued asynchronously to
                                        * the owner of the interpreter being used if the owner
                                        * is busy; otherwise, it should be sent synchronously. */
        /// <summary>
        /// Reset the local script cancellation flags for the target
        /// interpreter prior to evaluating the callback script.
        /// </summary>
        ResetCancel = 0x800000,        /* Reset the local script cancellation flags for the target
                                        * interpreter prior to evaluating the callback script. */
        /// <summary>
        /// Be forceful when resetting the script cancellation flags for
        /// the target interpreter prior to evaluating the callback script.
        /// </summary>
        MustResetCancel = 0x1000000,   /* Be forceful when resetting script cancellation flags
                                        * for the target interpreter prior to evaluating the
                                        * callback script. */
        /// <summary>
        /// The callback should be cleaned up automatically after it is
        /// invoked.  This flag is needed for asynchronous callbacks.
        /// </summary>
        FireAndForget = 0x2000000,     /* The callback should be cleaned up automatically after
                                        * it is invoked.  This flag is needed for asynchronous
                                        * callbacks. */
        /// <summary>
        /// The parameter names for the delegate type, if any, should be
        /// used.
        /// </summary>
        UseParameterNames = 0x4000000, /* The parameter names for the delegate type, if any,
                                        * should be used. */

        //
        // NOTE: Default argument handling.
        //
        /// <summary>
        /// Combination mask of <see cref="Arguments" />,
        /// <see cref="Create" />, <see cref="Dispose" />,
        /// <see cref="Alias" />, <see cref="Complain" />,
        /// <see cref="ReturnValue" />, and <see cref="AddReference" />,
        /// representing the default argument handling behavior.
        /// </summary>
        Default = Arguments | Create | Dispose |
                  Alias | Complain | ReturnValue |
                  AddReference
    }

