    /// <summary>
    /// This enumeration specifies the bit flags that control how the core
    /// marshaller converts values between TclTk scripts and the CLR when
    /// binding method arguments and return values.  Because it is a
    /// [Flags] enumeration, its values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("ad5ea8ab-53a1-4055-8db5-5c1bba309cfb")]
    public enum MarshalFlags : ulong
    {
        /// <summary>
        /// No special handling is requested; none of the marshalling flags
        /// are set.
        /// </summary>
        None = 0x0,                             /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of flags; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,                          /* Invalid, do not use. */
        /// <summary>
        /// A canary value reserved for use in mask calculations; callers
        /// should not use this value.
        /// </summary>
        ForMask = 0x2,                          /* Canary, do not use. */
        /// <summary>
        /// Enable verbose error messages during marshalling.
        /// </summary>
        Verbose = 0x4,                          /* Enable [very?] verbose error messages. */
        /// <summary>
        /// Use the default value for a parameter when a scalar variable
        /// does not exist.
        /// </summary>
        DefaultValue = 0x8,                     /* Use the default value for a parameter when a
                                                 * scalar variable does not exist. */
        /// <summary>
        /// Enable aggressive automatic conversions to all variants of the
        /// StringList type.
        /// </summary>
        StringList = 0x10,                      /* Enable aggressive automatic conversions to all
                                                 * variants of the StringList type. */
        /// <summary>
        /// For input or output array types, skip changing the script
        /// variable into an array when the object value is null.
        /// </summary>
        SkipNullSetupValue = 0x20,              /* For input or output array types, skip changing
                                                 * the script variable into an array when the
                                                 * object value is null. */
        /// <summary>
        /// Disable transparent detection and use of all System.Array
        /// backed variables when marshalling arguments to a method.
        /// </summary>
        NoSystemArray = 0x40,                   /* Disable transparent detection and use of all
                                                 * System.Array backed variables when marshalling
                                                 * arguments to a method. */
        /// <summary>
        /// Cause MatchParameterTypes to strictly match the parameter
        /// counts.
        /// </summary>
        StrictMatchCount = 0x80,                /* MatchParameterTypes should strictly match the
                                                 * parameter counts. */
        /// <summary>
        /// Cause MatchParameterTypes to strictly match the parameter
        /// types.
        /// </summary>
        StrictMatchType = 0x100,                /* MatchParameterTypes should strictly match the
                                                 * parameter types. */
        /// <summary>
        /// Force FindMethodsAndFixupArguments to use the specified
        /// parameter type, not the one from the method overload itself.
        /// </summary>
        ForceParameterType = 0x200,             /* Force FindMethodsAndFixupArguments to use the
                                                 * specified parameter type, not the one from the
                                                 * method overload itself. */
        /// <summary>
        /// Reorder the matching methods based on the criteria specified in
        /// the associated <c>ReorderFlags</c>.
        /// </summary>
        ReorderMatches = 0x400,                 /* Reorder the matching methods based on the
                                                 * criteria specified in the ReorderFlags. */
        /// <summary>
        /// Do not attempt to perform any conversions when the target type
        /// is System.Delegate.
        /// </summary>
        NoDelegateCallback = 0x800,             /* Do not attempt to perform any conversions when
                                                 * the target type is System.Delegate. */
        /// <summary>
        /// Prevent use of the GenericCallback type when creating a command
        /// callback.
        /// </summary>
        NoGenericCallback = 0x1000,             /* Prevent use of the GenericCallback type when
                                                 * creating a command callback. */
        /// <summary>
        /// Enable use of the DynamicInvokeCallback when creating a command
        /// callback.
        /// </summary>
        DynamicCallback = 0x2000,               /* Enable use of the DynamicInvokeCallback when
                                                 * creating a command callback. */
        /// <summary>
        /// Populate the parameter names for use with the callback script
        /// (e.g. via <c>[nproc]</c>).
        /// </summary>
        CallbackParameterNames = 0x4000,        /* Populate the parameter names for use with the
                                                 * callback script (e.g. via [nproc]). */
        /// <summary>
        /// Skip throwing exceptions from within the script binder
        /// ChangeType method.
        /// </summary>
        NoChangeTypeThrow = 0x8000,             /* Skip throwing exceptions from within the
                                                 * script binder ChangeType method. */
        /// <summary>
        /// Skip throwing exceptions from within the script binder
        /// BindToField method.
        /// </summary>
        NoBindToFieldThrow = 0x10000,           /* Skip throwing exceptions from within the
                                                 * script binder BindToField method. */
        /// <summary>
        /// Skip calling the ChangeType method of the fallback (and/or
        /// default) binder.
        /// </summary>
        SkipChangeType = 0x20000,               /* Skip calling the ChangeType method of the
                                                 * fallback (and/or default) binder. */
        /// <summary>
        /// Skip calling the BindToField method of the fallback (and/or
        /// default) binder.
        /// </summary>
        SkipBindToField = 0x40000,              /* Skip calling the BindToField method of the
                                                 * fallback (and/or default) binder. */
        /// <summary>
        /// Skip checking reference type equality when coming back from the
        /// ChangeType method.
        /// </summary>
        SkipReferenceTypeCheck = 0x80000,       /* Skip checking reference type equality when
                                                 * coming back from the ChangeType method. */
        /// <summary>
        /// Skip checking value type equality when coming back from the
        /// ChangeType method.
        /// </summary>
        SkipValueTypeCheck = 0x100000,          /* Skip checking value type equality when coming
                                                 * back from the ChangeType method. */
        /// <summary>
        /// Skip parsing per-CommandCallback options.
        /// </summary>
        NoCallbackOptions = 0x200000,           /* Skip parsing per-CommandCallback options. */
        /// <summary>
        /// Ignore per-CommandCallback option values.
        /// </summary>
        IgnoreCallbackOptions = 0x400000,       /* Ignore per-CommandCallback option values. */
        /// <summary>
        /// Throw an exception on delegate binding failures.
        /// </summary>
        ThrowOnBindFailure = 0x800000,          /* Throw an exception on delegate binding
                                                 * failures. */
        /// <summary>
        /// Skip using opaque object handles.
        /// </summary>
        NoHandle = 0x1000000,                   /* Skip using opaque object handles. */
        /// <summary>
        /// When determining if a parameter is "input", use only the
