        SpecialValueType = 0x800000000,         /* EXPERIMENTAL: Enable special handling of
                                                 * the ValueType type when determining if a
                                                 * value can be used with a given type. */
        /// <summary>
        /// EXPERIMENTAL: If an opaque object handle is found, stop further
        /// type conversions.
        /// </summary>
        ForceHandleOnly = 0x1000000000,         /* EXPERIMENTAL: If an opaque object handle is
                                                 * found, stop further type conversions. */
        /// <summary>
        /// EXPERIMENTAL: Allow GetType to be called on transparent proxy
        /// objects.
        /// </summary>
        AllowProxyGetType = 0x2000000000,       /* EXPERIMENTAL: Allow GetType to be called on
                                                 * transparent proxy objects. */
        /// <summary>
        /// EXPERIMENTAL: Force GetType to be called on transparent proxy
        /// objects for types that are not loaded into the AppDomain.
        /// </summary>
        ForceProxyGetType = 0x4000000000,       /* EXPERIMENTAL: Force GetType to be called on
                                                 * transparent proxy objects for types that are
                                                 * not loaded into the AppDomain. */
        /// <summary>
        /// Do not bother calling the IsAllowed method on the IScriptBinder
        /// interface.
        /// </summary>
        AllowAnyMethod = 0x8000000000,          /* Do not bother calling the IsAllowed method
                                                 * on the IScriptBinder interface. */
        /// <summary>
        /// Prefer matching method overloads that have a larger number of
        /// optional parameters.
        /// </summary>
        MinimumOptionalCount = 0x10000000000,   /* Prefer matching method overloads that have
                                                 * a larger number of optional parameters. */
        /// <summary>
        /// Force use of the SelectMethodIndex method even when the method
        /// index was explicitly specified.
        /// </summary>
        SelectMethodIndex = 0x20000000000,      /* Force use of the SelectMethodIndex method
                                                 * even when the method index was explicitly
                                                 * specified. */
        /// <summary>
        /// Sort members in the order that makes the most sense for the
        /// core marshaller, e.g. by name with the least number of
        /// parameters first.
        /// </summary>
        SortMembers = 0x40000000000,            /* Sort members in the order that makes the
                                                 * most sense for the core marshaller, e.g.
                                                 * by name with the least number of parameters
                                                 * first. */
        /// <summary>
        /// Prefer method overloads that accept the greatest number of
        /// parameters.
        /// </summary>
        ReverseOrder = 0x80000000000,           /* Prefer method overloads that accept the
                                                 * greatest number of parameters. */
        /// <summary>
        /// Include non-public members when performing comparisons.
        /// </summary>
        NonPublic = 0x100000000000,             /* Include non-public members when performing
                                                 * comparisons. */
        /// <summary>
        /// When creating a Delegate, return its associated ICallback
        /// instance instead of the raw Delegate instance itself.
        /// </summary>
        ReturnICallback = 0x200000000000,       /* When creating a Delegate, return its
                                                 * associated ICallback instance instead of
                                                 * the raw Delegate instance itself. */
        /// <summary>
        /// When the target type is a Delegate, attempt to look up an
        /// appropriate pre-existing method.
        /// </summary>
        SimpleCallback = 0x400000000000,        /* When the target type is a Delegate, attempt
                                                 * to lookup appropriate pre-existing method. */
        /// <summary>
        /// When handling a parameter with the ParamArray attribute,
        /// flatten any IEnumerable arguments into the final list of format
        /// parameters for the target method, e.g. do not pass an array
        /// value as one of the formal parameters to the target method.
        /// </summary>
        FlattenIntoParamArray = 0x800000000000, /* When handling a parameter with the ParamArray
                                                 * attribute, flatten any IEnumerable arguments
                                                 * into the final list of format parameters for
                                                 * the target method, e.g. do not pass an array
                                                 * value as one of the formal parameters to the
                                                 * target method. */
        /// <summary>
        /// Skip enforcement of parameter counts.  This is intended for
        /// debugging only; do not use this in production code.
        /// </summary>
        NoParameterCounts = 0x1000000000000,    /* Skip enforcement of parameter counts.  This
                                                 * is intended for debugging only, do not use
                                                 * this in production code. */
        /// <summary>
        /// Include the parameters in error messages generated by the core
        /// marshaller.
        /// </summary>
        ShowSignatures = 0x2000000000000,       /* Include the parameters in error messages
                                                 * generated by the core marshaller. */
        /// <summary>
        /// For internal conversions, allow integer values to be widened to
        /// unsigned.
        /// </summary>
        WidenToUnsigned = 0x4000000000000,      /* For internal conversions, allow integer
                                                 * values to be widened to unsigned. */
        /// <summary>
        /// Allow value wrapper classes, e.g. Variant, to be returned from
        /// the conversion routines.
        /// </summary>
        KeepWrapper = 0x8000000000000,          /* Allow value wrapper classes, e.g. Variant,
                                                 * to be returned from the conversion routines. */
        /// <summary>
        /// Only return member names when listing, not full method
        /// signatures, etc.
        /// </summary>
        NamesOnly = 0x10000000000000,           /* Only return member names when listing, not
                                                 * full method signatures, etc. */
        /// <summary>
        /// Only return non-qualified member names.
        /// </summary>
        UnqualifiedNames = 0x20000000000000,    /* Only return non-qualified member names. */
        /// <summary>
        /// Do not use cached CommandCallback instances.
        /// </summary>
        ForceNewCallback = 0x40000000000000,    /* Do not use cached CommandCallback instances. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ReturnICallback" /> and
        /// <see cref="ForMask" />, used to detect errors when building a
        /// simple callback.
        /// </summary>
        SimpleCallbackErrorMask = ReturnICallback | ForMask,

        /// <summary>
        /// Combination mask of <see cref="NoDelegateCallback" />,
        /// <see cref="NoGenericCallback" />,
        /// <see cref="DynamicCallback" />,
        /// <see cref="CallbackParameterNames" />, and
        /// <see cref="ForMask" />, used to detect warnings when building a
        /// simple callback.
        /// </summary>
        SimpleCallbackWarningMask = NoDelegateCallback | NoGenericCallback |
                                    DynamicCallback | CallbackParameterNames |
                                    ForMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Default" />,
        /// <see cref="DynamicCallback" />,
        /// <see cref="ForceNewCallback" />, and <see cref="ForMask" />,
        /// used when hooking methods.
        /// </summary>
        MethodHookMask = Default | DynamicCallback | ForceNewCallback |
                         ForMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="StrictMatchCount" />,
        /// <see cref="StrictMatchType" />, and
        /// <see cref="ThrowOnBindFailure" />, representing the default
        /// marshalling behavior.
        /// </summary>
        Default = StrictMatchCount | StrictMatchType |
                  ThrowOnBindFailure /* LEGACY */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the bit flags that control how the core
    /// marshaller orders candidate method overloads when selecting the
    /// best match for a call.  Because it is a [Flags] enumeration, its
    /// values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("fcec8afc-2e5c-479b-bd55-d20621acbcc5")]
    public enum ReorderFlags
    {
        /// <summary>
        /// No special handling is requested; none of the reorder flags are
        /// set.
        /// </summary>
        None = 0x0,                       /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of flags; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,                    /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Prefer method overloads that accept the fewest number of
        /// parameters.
        /// </summary>
        FewestParametersFirst = 0x2,      /* Prefer method overloads that accept
                                           * the fewest number of parameters. */
        /// <summary>
        /// Prefer method overloads that accept the greatest number of
        /// parameters.
        /// </summary>
        MostParametersFirst = 0x4,        /* Prefer method overloads that accept
                                           * the greatest number of parameters. */
        /// <summary>
        /// Prefer argument types towards the root of the type hierarchy.
        /// </summary>
        ShallowestTypesFirst = 0x8,       /* Prefer argument types towards the
                                           * root of the hierarchy. */
        /// <summary>
        /// Prefer argument types towards the leaves of the type hierarchy.
        /// </summary>
        DeepestTypesFirst = 0x10,         /* Prefer argument types towards the
                                           * leaves of the hierarchy. */
        /// <summary>
        /// Compare the type depths before comparing the parameter counts.
        /// </summary>
        TypeDepthsFirst = 0x20,           /* Compare the type depths before
                                           * comparing the parameter counts. */
        /// <summary>
        /// When comparing type depths, instead of returning a result at
        /// the first non-equal type depth, sum all the type depths to
        /// arrive at the result.  This is useful primarily when the
        /// parameters do not conform to a well-defined order between
        /// method overloads.
        /// </summary>
        TotalTypeDepths = 0x40,           /* When comparing type depths, instead
                                           * of returning a result at the first
                                           * non-equal type depth, sum all the
                                           * type depths to arrive at the result.
                                           * This is useful primarily when the
                                           * parameters do not conform to a
                                           * well-defined order between method
                                           * overloads. */
        /// <summary>
        /// When calculating type depths, use the formal parameter type
        /// instead of the argument type, if doing so would result in a
        /// more accurate type depth.
        /// </summary>
        UseParameterTypes = 0x80,         /* When calculating type depths, use
                                           * the formal parameter type instead
                                           * of the argument type, if doing so
                                           * would result in a more accurate
                                           * type depth. */
        /// <summary>
        /// Consider <c>Array&lt;T&gt;</c> and <c>Nullable&lt;T&gt;</c> as levels
        /// to be traversed when calculating type depths.
        /// </summary>
        SubTypeDepths = 0x100,            /* Consider Array<T> and Nullable<T> as
                                           * levels to be traversed when
                                           * calculating type depths. */
        /// <summary>
        /// Consider all reference types, except "Object" and "ValueType",
        /// as levels to be traversed when calculating type depths.
        /// </summary>
        ValueTypeDepths = 0x200,          /* Consider all reference types, except
                                           * "Object" and "ValueType", as levels
                                           * to be traversed when calculating
                                           * type depths. */
        /// <summary>
        /// Also consider <c>ByRef&lt;T&gt;</c> as a level to be traversed
        /// when calculating type depths.
        /// </summary>
        ByRefTypeDepths = 0x400,          /* Also consider ByRef<T> as a level to
                                           * be traversed when calculating type
                                           * depths. */
        /// <summary>
        /// When an error is encountered (e.g. parameter validation, an
        /// exception, etc.), return "Ok" instead of "Error".  This allows
        /// the default method overload to be called instead of failing the
        /// entire method call operation.
        /// </summary>
        FallbackOkOnError = 0x800,        /* When an error is encountered (e.g.
                                           * parameter validation, exception,
                                           * etc), return "Ok" instead of
                                           * "Error".  This allows the default
                                           * method overload to be called instead
                                           * of failing the entire method call
                                           * operation. */
        /// <summary>
        /// If necessary, take the supplied argument counts into account
        /// when calculating parameter counts.
        /// </summary>
        UseArgumentCounts = 0x1000,       /* If necessary, take the supplied
                                           * arguments counts into account when
                                           * calculating parameter counts. */
        /// <summary>
        /// Bail out on error while querying parameter counts.
        /// </summary>
        StrictParameterCounts = 0x2000,   /* Bail out on error while querying
                                           * parameter counts. */
        /// <summary>
        /// Skip to the next method overload on error while querying
        /// parameter counts.
        /// </summary>
        ContinueParameterCounts = 0x4000, /* Skip to next method overload on
                                           * error while querying parameter
                                           * counts. */
        /// <summary>
        /// Bail out on error while calculating parameter type depths.
        /// </summary>
        StrictTypeDepths = 0x8000,        /* Bail out on error while calculating
                                           * parameter type depths. */
        /// <summary>
        /// Skip to the next method overload on error while calculating
        /// parameter type depths.
        /// </summary>
        ContinueTypeDepths = 0x10000,     /* Skip to next method overload on
                                           * error while calculating parameter
                                           * type depths. */
        /// <summary>
        /// Subtract one level for types that are trivially convertible
        /// from a string (e.g. System.String) when calculating type
        /// depths.
        /// </summary>
        StringTypePenalty = 0x20000,      /* Subtract one level for types that
                                           * are trivially convertible from a
                                           * string (e.g. System.String) when
                                           * calculating type depths. */
        /// <summary>
        /// Add one level for types that are trivially convertible from a
        /// string (e.g. System.String) when calculating type depths.
        /// </summary>
        StringTypeBonus = 0x40000,        /* Add one level for types that are
                                           * trivially convertible from a string
                                           * (e.g. System.String) when calculating
                                           * type depths. */
        /// <summary>
        /// Emit the final sorted list of method overloads to the trace
        /// listeners.
        /// </summary>
        TraceResults = 0x80000,           /* Emit the final sorted list of method
                                           * overloads to the trace listeners. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="FewestParametersFirst" /> and
        /// <see cref="MostParametersFirst" />.
        /// </summary>
        ParameterCountMask = FewestParametersFirst | MostParametersFirst,
        /// <summary>
        /// Combination mask of <see cref="ShallowestTypesFirst" /> and
        /// <see cref="DeepestTypesFirst" />.
        /// </summary>
        ParameterTypeDepthMask = ShallowestTypesFirst | DeepestTypesFirst,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="FewestParametersFirst" />,
        /// <see cref="DeepestTypesFirst" />, <see cref="SubTypeDepths" />,
        /// <see cref="ValueTypeDepths" />, and
        /// <see cref="ByRefTypeDepths" />, representing the default
        /// reordering behavior.
        /// </summary>
        Default = FewestParametersFirst | DeepestTypesFirst |
                  SubTypeDepths | ValueTypeDepths |
                  ByRefTypeDepths /* TODO: Good default? */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the bit flags that describe and classify
    /// a method, including the kinds of policy callbacks it may serve as.
    /// Because it is a [Flags] enumeration, its values may be combined
    /// using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("1e4879b1-f3db-4bda-8637-6f1495a51ec8")]
    public enum MethodFlags
    {
        /// <summary>
        /// No special handling is requested; none of the method flags are
        /// set.
        /// </summary>
        None = 0x0,              /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of flags; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,           /* Invalid, do not use. */
        /// <summary>
        /// The method is owned by the core library and should not be used.
        /// </summary>
        System = 0x2,            /* Method is owned by the core library, do not use. */
        /// <summary>
        /// Methods with this flag will not be automatically used as a
        /// policy callback by the plugin manager.
        /// </summary>
        NoAdd = 0x4,             /* Methods with this flag will not be automatically used as a
                                  * policy callback by the plugin manager. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle plugin loading policies.
        /// </summary>
        PluginPolicy = 0x8,      /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle plugin loading policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle command execution policies.
        /// </summary>
        CommandPolicy = 0x10,    /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle command execution policies. */
        /// <summary>
        /// NOT USED: The method conforms to the ExecuteCallback delegate
        /// type and is used to handle sub-command execution policies.
        /// </summary>
        SubCommandPolicy = 0x20, /* NOT USED: Method conforms to the ExecuteCallback delegate
                                  * type and is used to handle sub-command execution policies. */
        /// <summary>
        /// NOT USED: The method conforms to the ExecuteCallback delegate
        /// type and is used to handle procedure execution policies.
        /// </summary>
        ProcedurePolicy = 0x40,  /* NOT USED: Method conforms to the ExecuteCallback delegate
                                  * type and is used to handle procedure execution policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle IScript object policies.
        /// </summary>
        ScriptPolicy = 0x80,     /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle IScript object policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle script file policies.
        /// </summary>
        FilePolicy = 0x100,      /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle script file policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle script stream policies.
        /// </summary>
        StreamPolicy = 0x200,    /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle script stream policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle "license" policies.
        /// </summary>
        LicensePolicy = 0x400,   /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle "license" policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle "trace" policies.
        /// </summary>
        TracePolicy = 0x800,     /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle "trace" policies. */
        /// <summary>
        /// The method conforms to the ExecuteCallback delegate type and is
        /// used to handle "other" policies.
        /// </summary>
        OtherPolicy = 0x1000,    /* Method conforms to the ExecuteCallback delegate type and is
                                  * used to handle "other" policies. */
        /// <summary>
        /// The method conforms to the TraceCallback delegate type and is
        /// used to handle variable traces.
        /// </summary>
        VariableTrace = 0x2000,  /* Method conforms to the TraceCallback delegate type and is
                                  * used to handle variable traces. */

        /// <summary>
        /// Combination mask of <see cref="PluginPolicy" />,
        /// <see cref="CommandPolicy" />, <see cref="SubCommandPolicy" />,
        /// <see cref="ProcedurePolicy" />, <see cref="ScriptPolicy" />,
        /// <see cref="FilePolicy" />, <see cref="StreamPolicy" />,
        /// <see cref="LicensePolicy" />, <see cref="TracePolicy" />, and
        /// <see cref="OtherPolicy" />, representing all of the policy
        /// method kinds.
        /// </summary>
        PolicyMask = PluginPolicy | CommandPolicy |
                     SubCommandPolicy | ProcedurePolicy |
                     ScriptPolicy | FilePolicy |
                     StreamPolicy | LicensePolicy |
                     TracePolicy | OtherPolicy,
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the bit flags that select which kind of
    /// usage statistic is being queried or manipulated for an entity.
    /// Because it is a [Flags] enumeration, its values may be combined
    /// using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("2000c391-277e-435f-8c29-f5f64f1c6e19")]
    public enum UsageType
    {
        /// <summary>
        /// No usage statistic is selected; none of the flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Select the invocation count usage statistic.
        /// </summary>
        Count = 0x1,
        /// <summary>
        /// Select the elapsed time (in microseconds) usage statistic.
        /// </summary>
        Microseconds = 0x2
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies the bit flags that control how script
    /// snippets are created, stored, matched, and used (e.g. in
    /// conjunction with Harpy).  Because it is a [Flags] enumeration, its
    /// values may be combined using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("51f52e17-9221-4564-8200-bea15464834a")]
    public enum SnippetFlags : ulong
    {
        /// <summary>
        /// No special handling is requested; none of the snippet flags are
        /// set.
        /// </summary>
        None = 0x0,     /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of flags; callers
        /// should not use this value.
        /// </summary>
        Invalid = 0x1,  /* Invalid, do not use. */
        /// <summary>
        /// A reserved value; callers should not use this value.
        /// </summary>
        Reserved = 0x2, /* Reserved, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The snippet cannot be removed via the public interface.
        /// </summary>
        Locked = 0x4,    /* The snippet cannot be removed via the public
                          * interface. */
        /// <summary>
        /// The snippet cannot be fetched via the public interface.
        /// </summary>
        Hidden = 0x8,    /* The snippet cannot be fetched via the public
                          * interface. */
        /// <summary>
        /// The snippet cannot be used via the interpreter host interface.
        /// </summary>
        Disabled = 0x10, /* The snippet cannot be used via the interpreter
                          * host interface. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// When considering signed files to add as snippets, skip (signed)
        /// files that are not scripts.
        /// </summary>
        MustBeScript = 0x100,    /* When considering signed files to add as
                                  * snippets, skip (signed) files that are
                                  * not scripts. */
        /// <summary>
        /// When considering signed files to add as snippets, skip files
        /// that are not script signatures (a.k.a. "certificates").
        /// </summary>
        MustBeSignature = 0x200, /* When considering signed files to add as
                                  * snippets, skip files that are not script
                                  * signatures (a.k.a. "certificates"). */
        /// <summary>
        /// The "Bytes" property value should be used and/or returned
        /// instead of the "Text" property.  This is for use with Harpy, et
        /// al.
        /// </summary>
        UseBytes = 0x400,        /* The "Bytes" property value should be used
                                  * and/or returned instead of the "Text"
                                  * property.  This is for use with Harpy,
                                  * et al. */
#if XML
        /// <summary>
        /// The "Xml" property value should be used and/or returned instead
        /// of the "Text" property.  This is for use with Harpy, et al.
        /// </summary>
        UseXml = 0x800,          /* The "Xml" property value should be used
                                  * and/or returned instead of the "Text"
                                  * property.  This is for use with Harpy,
                                  * et al. */
#endif
        /// <summary>
        /// When creating the snippet name, use the data bytes from the
        /// script file, not the signature file.
        /// </summary>
        HashOtherPath = 0x1000,  /* When creating the snippet name, use the
                                  * data bytes from the script file, not the
                                  * signature file. */
        /// <summary>
        /// Skip setting the attribute-based fields from the constructor.
        /// </summary>
        NoAttributes = 0x2000,   /* Skip setting the attribute-based fields
                                  * from the constructor. */
        /// <summary>
        /// Remove the snippet after it is evaluated, etc.
        /// </summary>
        RemoveOnUse = 0x4000,    /* Remove snippet after it is evaluated,
                                  * etc. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Do not perform any text translations when adding snippets from
        /// files.
        /// </summary>
        ReadAsRawText = 0x10000,    /* Do not perform any text translations
                                     * when adding snippets from files. */
        /// <summary>
        /// Ignore the "safe" interpreter status for certain snippet
        /// operations.
        /// </summary>
        IgnoreSafe = 0x20000,       /* Ignore the "safe" interpreter status
                                     * for certain snippet operations. */
        /// <summary>
        /// Ignore any duplicate snippets when adding an entire directory,
        /// etc.
        /// </summary>
        IgnoreDuplicate = 0x40000,  /* Ignore any duplicate snippets when
                                     * adding an entire directory, etc. */
        /// <summary>
        /// Allow a duplicate snippet to replace an existing one.
        /// </summary>
        AllowDuplicate = 0x80000,   /* Allow a duplicate snippet to replace
                                     * an existing one. */
        /// <summary>
        /// When creating the snippet name, do not use the data bytes from
        /// the script file; use the data bytes from the signature file.
        /// </summary>
        NoHashOtherPath = 0x100000, /* When creating the snippet name, do
                                     * not use the data bytes from the script
                                     * file, use the data bytes from the
                                     * signature file. */
        /// <summary>
        /// When creating a list of snippets to return, make sure that ALL
        /// instance flags match the ones passed to the method; otherwise,
        /// ANY matching instance flag will do.
        /// </summary>
        HasAllFlags = 0x200000,     /* When creating a list of snippets to
                                     * return, make sure that ALL instance
                                     * flags match the ones passed to the
                                     * method; otherwise, ANY matching
                                     * instance flag will do. */
        /// <summary>
        /// Allow an arbitrary hash name to be used for a given text
        /// snippet instead of one that matches its contents.
        /// </summary>
        AllowAnyHash = 0x400000,    /* Allow an arbitrary hash name to be
                                     * used for a given text snippet instead
                                     * of one that matches it contents. */
        /// <summary>
        /// Use the specified (i.e. arbitrary) hash name instead of one
        /// that matches its contents.
        /// </summary>
        UseAnyHash = 0x800000,      /* Use the specified (i.e. arbitrary)
                                     * hash name instead of one that matches
                                     * it contents. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// This flag indicates that this set of flags is part of an
        /// instance.
        /// </summary>
        ForInstance = 0x10000000, /* This flag indicates that this set of
                                   * flags are part of an instance. */
        /// <summary>
        /// This flag indicates that the default flags are (or were?) being
        /// used.
        /// </summary>
        ForDefault = 0x20000000,  /* This flag indicates that the default
                                   * flags are (or were?) being used. */

        ///////////////////////////////////////////////////////////////////////////////////////////

#if XML
        /// <summary>
        /// Equivalent to <see cref="UseXml" /> when XML support is
        /// compiled in; otherwise equivalent to <see cref="None" />.
        /// </summary>
        MaybeUseXml = UseXml,
        /// <summary>
        /// Combination mask of <see cref="UseXml" /> and
        /// <see cref="HasAllFlags" /> when XML support is compiled in.
        /// </summary>
        MaybeUseXmlOnlyMask = UseXml | HasAllFlags,
#else
        /// <summary>
        /// Equivalent to <see cref="None" /> because XML support is not
        /// compiled in.
        /// </summary>
        MaybeUseXml = None,
        /// <summary>
        /// Equivalent to <see cref="None" /> because XML support is not
        /// compiled in.
        /// </summary>
        MaybeUseXmlOnlyMask = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This is the set of flags that are allowed for an instance
        //       of ISnippet.
        //
        /// <summary>
        /// Combination mask of the flags that are allowed for an instance
        /// of ISnippet: <see cref="Locked" />, <see cref="Hidden" />,
        /// <see cref="Disabled" />, <see cref="MustBeScript" />,
        /// <see cref="MustBeSignature" />, <see cref="UseBytes" />,
        /// <see cref="MaybeUseXml" />, <see cref="HashOtherPath" />,
        /// <see cref="NoAttributes" />, and <see cref="RemoveOnUse" />.
        /// </summary>
        InstanceMask = Locked | Hidden | Disabled | MustBeScript |
                       MustBeSignature | UseBytes | MaybeUseXml |
                       HashOtherPath | NoAttributes | RemoveOnUse,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is used when adding snippets containing script
        //       certificates.
        //
        /// <summary>
        /// Equivalent to <see cref="MaybeUseXml" />; used when adding
        /// snippets containing script certificates.
        /// </summary>
        SecurityPackage = MaybeUseXml,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These values are used by the [queryStatus] and/or
        //       [addCertificates] configuration commands provided
        //       by Harpy.
        //
        /// <summary>
        /// Equivalent to <see cref="None" />; used by the
        /// <c>[queryStatus]</c> and/or <c>[addCertificates]</c>
        /// configuration commands provided by Harpy.
        /// </summary>
        QueryStatusMask = None,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllowAnyHash" /> and
        /// <see cref="UseAnyHash" />.
        /// </summary>
        AnyHashMask = AllowAnyHash | UseAnyHash,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="MustBeScript" /> and
        /// <see cref="ReadAsRawText" />.
        /// </summary>
        FileHostMask = MustBeScript | ReadAsRawText,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="FileHostMask" /> and
        /// <see cref="ForDefault" />, representing the default snippet
        /// behavior.
        /// </summary>
        Default = FileHostMask | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that control how the interpreter
    /// locates entities (such as commands, functions, variables,
    /// encodings, plugins, and channels) when performing a lookup by name
    /// or token.  Because it is a bit flags enumeration, multiple values
    /// may be combined to refine the search and to control error
    /// reporting, caching, and wrapper handling.
    /// </summary>
    [Flags()]
    [ObjectId("768b5bd7-cb31-465b-827e-94a12dc46dcd")]
    public enum LookupFlags : ulong
    {
        /// <summary>
        /// No special handling is requested; the lookup behaves in its
        /// most basic form.
        /// </summary>
        None = 0x0,        /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of lookup flags;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,     /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Generic
        /// <summary>
        /// Return the wrapper object that contains the entity rather than
        /// the contained entity itself.
        /// </summary>
        Wrapper = 0x2,      /* Return the wrapper object, not the contained entity. */
        /// <summary>
        /// Validate that the returned object is not null, returning an
        /// error when it is.
        /// </summary>
        Validate = 0x4,     /* Validate that the returned object is not null.  If it
                             * is null, return an error. */
        /// <summary>
        /// Return a verbose error message when the lookup fails.
        /// </summary>
        Verbose = 0x8,      /* Return a verbose error message. */
        /// <summary>
        /// Consider entities that are visible (i.e. non-hidden) when
        /// searching.
        /// </summary>
        Visible = 0x10,     /* Consider "visible" (i.e. non-hidden) entities. */
        /// <summary>
        /// Consider entities that are invisible (i.e. hidden) when
        /// searching.
        /// </summary>
        Invisible = 0x20,   /* Consider "invisible" (i.e. hidden) entities. */
        /// <summary>
        /// Skip the usability check that would otherwise be performed on
        /// candidate entities.
        /// </summary>
        NoUsable = 0x40,    /* Skip usability check for entities. */
        /// <summary>
        /// Do not raise an error when attempting to remove something that
        /// cannot be found.
        /// </summary>
        NoComplain = 0x80,  /* Do not complain when attempting to remove something
                             * that is not found. */
        /// <summary>
        /// Do not satisfy the lookup from any of the available caches.
        /// </summary>
        NoCache = 0x100,    /* Do not lookup based on any caches. */
        /// <summary>
        /// Do not return an object instance that has already been
        /// disposed.
        /// </summary>
        NoDisposed = 0x200, /* Do not return a disposed object instance. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Encoding Specific (For Now)
        /// <summary>
        /// Allow a null encoding to be returned when a null name is
        /// supplied.
        /// </summary>
        AllowNull = 0x1000, /* Allow a null encoding to be returned for a null name. */
        /// <summary>
        /// Always fail when the specified encoding is not registered with
        /// the interpreter.
        /// </summary>
        Strict = 0x2000,    /* Always fail if the specified encoding is not registered
                             * with the interpreter. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Variable Specific
        /// <summary>
        /// Create a dummy variable if necessary; the returned variable may
        /// or may not reside within its call frame.
        /// </summary>
        CreateMissing = 0x4000, /* Create dummy variable if necessary.  The returned
                                 * new variable may or may not reside within its call
                                 * frame. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Plugin Specific
        /// <summary>
        /// Restrict the search to plugins that own one or more commands.
        /// </summary>
        WithCommands = 0x8000,   /* Must own one or more commands. */
        /// <summary>
        /// Restrict the search to plugins that own one or more functions.
        /// </summary>
        WithFunctions = 0x10000, /* Must own one or more functions. */
        /// <summary>
        /// Restrict the search to plugins that own one or more policies.
        /// </summary>
        WithPolicies = 0x20000,  /* Must own one or more policies. */
        /// <summary>
        /// Restrict the search to plugins that own one or more traces.
        /// </summary>
        WithTraces = 0x40000,    /* Must own one or more traces. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Path Specific
        /// <summary>
        /// When searching, make sure that all candidate paths are
        /// considered.
        /// </summary>
        AllPaths = 0x80000,     /* When searching, make sure that
                                 * all paths are considered. */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Future IEntityManager Interface Use
        #region Dead Code
#if DEAD_CODE
        /// <summary>
        /// Reserved for future IEntityManager use by namespace lookups.
        /// </summary>
        Absolute = 0x100000,             /* LookupNamespace */
        /// <summary>
        /// Reserved for future IEntityManager use by namespace creation.
        /// </summary>
        NewFrame = 0x200000,             /* CreateNamespace */
        /// <summary>
        /// Reserved for future IEntityManager use; perform
        /// case-insensitive listing of executables, commands, functions,
        /// procedures, operators, and channels.
        /// </summary>
        NoCase = 0x400000,               /* ListIExecutes, ListCommands,
                                          * ListFunctions, ListProcedures,
                                          * ListOperators, ListChannels */
        /// <summary>
        /// Reserved for future IEntityManager use; raise an error when a
        /// listed entity is unavailable.
        /// </summary>
        ErrorOnUnavailable = 0x800000,   /* ListIExecutes, ListCommands,
                                          * ListFunctions, ListProcedures,
                                          * ListOperators, ListChannels */
        /// <summary>
        /// Reserved for future IEntityManager use by the rename operations
        /// for executables, commands, and procedures.
        /// </summary>
        Delete = 0x1000000,              /* RenameIExecute, RenameCommand,
                                          * RenameProcedure */
        /// <summary>
        /// Reserved for future IEntityManager use by object renaming;
        /// ignore command aliases.
        /// </summary>
        IgnoreAlias = 0x2000000,         /* RenameObject */
        /// <summary>
        /// Reserved for future IEntityManager use by object renaming; do
        /// not consider namespaces.
        /// </summary>
        NoNamespaces = 0x4000000,        /* RenameObject */
        /// <summary>
        /// Reserved for future IEntityManager use by object renaming;
        /// raise an error when renaming an alias.
        /// </summary>
        ErrorOnRenameAlias = 0x8000000,  /* RenameObject */
        /// <summary>
        /// Reserved for future IEntityManager use by object removal;
        /// perform the removal synchronously.
        /// </summary>
        Synchronous = 0x10000000,        /* RemoveObject */
        /// <summary>
        /// Reserved for future IEntityManager use; require that listed
        /// entities have all of the requested attributes.
        /// </summary>
        HasAll = 0x20000000,             /* ListCommands, ListFunctions,
                                          * ListProcedures, ListOperators */
        /// <summary>
        /// Reserved for future IEntityManager use; require that listed
        /// entities lack one or more of the requested attributes.
        /// </summary>
        NotHasAll = 0x40000000,          /* ListCommands, ListFunctions,
                                          * ListProcedures, ListOperators */
        /// <summary>
        /// Reserved for future IEntityManager use by function addition;
        /// raise an error for non-standard functions.
        /// </summary>
        ErrorOnNonStandard = 0x80000000, /* AddFunction */
        /// <summary>
        /// Reserved for future IEntityManager use by channel addition;
        /// open the channel in append mode.
        /// </summary>
        AppendMode = 0x100000000,        /* AddChannel */
        /// <summary>
        /// Reserved for future IEntityManager use by channel addition;
        /// automatically flush the channel.
        /// </summary>
        AutoFlush = 0x200000000,         /* AddChannel */
        /// <summary>
        /// Reserved for future IEntityManager use by channel removal;
        /// flush the channel before removal.
        /// </summary>
        Flush = 0x400000000,             /* RemoveChannel */
        /// <summary>
        /// Reserved for future IEntityManager use by channel removal;
        /// close the channel during removal.
        /// </summary>
        Close = 0x800000000,             /* RemoveChannel */
        /// <summary>
        /// Reserved for future IEntityManager use by channel removal;
        /// raise an error when flushing fails.
        /// </summary>
        ErrorOnFlush = 0x1000000000,     /* RemoveChannel */
        /// <summary>
        /// Reserved for future IEntityManager use by channel removal;
        /// raise an error when closing fails.
        /// </summary>
        ErrorOnClose = 0x2000000000,     /* RemoveChannel */
        /// <summary>
        /// Reserved for future IEntityManager use by the execute-callback
        /// operations; ignore null callbacks.
        /// </summary>
        IgnoreNull = 0x4000000000,       /* AddExecuteCallbacks, RemoveExecuteCallbacks */
        /// <summary>
        /// Reserved for future IEntityManager use by the execute-callback
        /// operations; stop processing on the first error.
        /// </summary>
        StopOnError = 0x8000000000,      /* AddExecuteCallbacks, RemoveExecuteCallbacks */
#endif
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Used by the database connection and transaction accessors to
        /// indicate that no backing object is required.
        /// </summary>
        NoObject = 0x10000000000,        /* GetAnyDbConnection, GetAnyDbTransaction */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        #region Entity Specific Flags
        /// <summary>
        /// The entity must be considered alive; this is primarily relevant
        /// to thread-bound entities.
        /// </summary>
        MustBeAlive = 0x20000000000,      /* THREAD: entity must be considered "alive". */
        /// <summary>
        /// For objects, indicates that transparent proxies are treated as
        /// having a null type.
        /// </summary>
        NullForProxyType = 0x40000000000, /* OBJECT: transparent proxies have "null" type. */
        /// <summary>
        /// For path lookups, perform a recursive search.
        /// </summary>
        Recursive = 0x80000000000,        /* PATH: perform a recursive search? */
        #endregion

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are for use by the Does*Exist() methods of the
        //       Interpreter class only.  These flags may NOT be used by
        //       external components.
        //
        /// <summary>
        /// Combination mask of <see cref="Wrapper" /> and <see
        /// cref="Visible" />, for use by the Does*Exist() methods of the
        /// Interpreter class only.
        /// </summary>
        Exists = Wrapper | Visible,
        /// <summary>
        /// Combination mask of <see cref="Exists" /> and <see
        /// cref="Validate" />, for use by the Does*Exist() methods of the
        /// Interpreter class only.
        /// </summary>
        ExistsAndValid = Exists | Validate,

        //
        // NOTE: These flags are for use by the Remove*() methods of the
        //       Interpreter class only.  These flags may NOT be used by
        //       external components.
        //
        /// <summary>
        /// The <see cref="Default" /> lookup flags with <see
        /// cref="Validate" /> cleared, for use by the Remove*() methods of
        /// the Interpreter class only.
        /// </summary>
        Remove = Default & ~Validate,
        /// <summary>
        /// Same as <see cref="Remove" /> but with <see cref="Verbose" />
        /// cleared.
        /// </summary>
        RemoveNoVerbose = Remove & ~Verbose,

        //
        // NOTE: These flags are for use by the Unload*() methods of the
        //       Interpreter class only.  These flags may NOT be used by
        //       external components.
        //
#if ISOLATED_PLUGINS
        /// <summary>
        /// The <see cref="Default" /> lookup flags, for use by the
        /// Unload*() methods of the Interpreter class only.
        /// </summary>
        Unload = Default,
#endif

        //
        // NOTE: These flags are for use by the Get*Interpreter() methods of
        //       the Interpreter class only.  These flags may NOT be used by
        //       external components.
        //
        /// <summary>
        /// The <see cref="Default" /> lookup flags with <see
        /// cref="Wrapper" /> cleared, for use by the Get*Interpreter()
        /// methods of the Interpreter class only.
        /// </summary>
        Interpreter = Default & ~Wrapper,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: For use by the [string is encoding] sub-command only.
        //
        /// <summary>
        /// The default lookup flags used by the <c>[string is
        /// encoding]</c> sub-command only.
        /// </summary>
        EncodingDefault = Default,
        /// <summary>
        /// Same as <see cref="EncodingDefault" /> but with <see
        /// cref="Verbose" /> cleared.
        /// </summary>
        EncodingNoVerbose = EncodingDefault & ~Verbose,

        //
        // NOTE: These flags are for use by the Engine class only.  These flags
        //       may NOT be used by external components.
        //
        /// <summary>
        /// The default lookup flags used by the Engine class only.
        /// </summary>
        EngineDefault = Default,
        /// <summary>
        /// Same as <see cref="EngineDefault" /> but with <see
        /// cref="Verbose" /> cleared.
        /// </summary>
        EngineNoVerbose = EngineDefault & ~Verbose,

        //
        // NOTE: These flags are for use by the Expression class only.  These
        //       flags may NOT be used by external components.
        //
        /// <summary>
        /// The default lookup flags used by the Expression class only,
        /// with <see cref="Wrapper" /> cleared.
        /// </summary>
        ExpressionDefault = Default & ~Wrapper,
        /// <summary>
        /// Same as <see cref="ExpressionDefault" /> but with <see
        /// cref="Verbose" /> cleared.
        /// </summary>
        ExpressionNoVerbose = ExpressionDefault & ~Verbose,

        //
        // NOTE: These flags are for use by the MarshalOps class only.  These
        //       flags may NOT be used by external components.
        //
        /// <summary>
        /// The default lookup flags used by the MarshalOps class only,
        /// with <see cref="Verbose" /> cleared.
        /// </summary>
        MarshalDefault = Default & ~Verbose,
        /// <summary>
        /// Same as <see cref="MarshalDefault" />, retained for clarity.
        /// </summary>
        MarshalNoVerbose = MarshalDefault,
        /// <summary>
        /// Same as <see cref="MarshalDefault" /> but with <see
        /// cref="Validate" /> cleared.
        /// </summary>
        MarshalAlias = MarshalDefault & ~Validate,

        //
        // NOTE: These flags are for use by the HelpOps class only.  These flags
        //       may NOT be used by external components.
        //
        /// <summary>
        /// The default lookup flags used by the HelpOps class only, with
        /// <see cref="Wrapper" /> cleared.
        /// </summary>
        HelpDefault = Default & ~Wrapper,
        /// <summary>
        /// Same as <see cref="HelpDefault" /> but with <see
        /// cref="Verbose" /> cleared.
        /// </summary>
        HelpNoVerbose = HelpDefault & ~Verbose,

        //
        // NOTE: These flags are for use by the Default host class only.  These
        //       flags may NOT be used by external components.
        //
        /// <summary>
        /// The default lookup flags used by the default host class only,
        /// with <see cref="Verbose" /> cleared.
        /// </summary>
        HostNoVerbose = Default & ~Verbose,

        //
        // NOTE: These flags are for use by the PolicyOps and RuntimeOps classes
        //       only.  These flags may NOT be used by external components.
        //
        /// <summary>
        /// The <see cref="Default" /> lookup flags combined with <see
        /// cref="Invisible" />, for use by the PolicyOps and RuntimeOps
        /// classes only.
        /// </summary>
        PolicyDefault = Default | Invisible,
        /// <summary>
        /// Same as <see cref="PolicyDefault" /> but with <see
        /// cref="Verbose" /> cleared.
        /// </summary>
        PolicyNoVerbose = PolicyDefault & ~Verbose,

        //
        // NOTE: These flags are for use by the GetInterpreterAliasTarget,
        //       HasInterpreterAlias, GetLibraryAliasTarget, GetObjectAliasTarget,
        //       and GetTclAliasTarget methods only.  These flags may NOT be used
        //       by external components.
        //
        /// <summary>
        /// The <see cref="Default" /> lookup flags combined with <see
        /// cref="Invisible" />, for use by the alias-target query methods
        /// only.
        /// </summary>
        AliasDefault = Default | Invisible,
        /// <summary>
        /// Same as <see cref="AliasDefault" /> but with <see
        /// cref="Verbose" /> cleared.
        /// </summary>
        AliasNoVerbose = AliasDefault & ~Verbose,

        //
        // NOTE: These flags are for use by the Interpreter.GetOptions
        //       method only.  These flags may NOT be used by external
        //       components.
        //
        /// <summary>
        /// The default lookup flags used by the Interpreter.GetOptions
        /// method only; equal to <see cref="NoValidate" />.
        /// </summary>
        OptionDefault = NoValidate,

        //
        // NOTE: These flags are used for finally timeout threads only.
        //
        /// <summary>
        /// Combination mask of <see cref="Default" /> and <see
        /// cref="MustBeAlive" />, used for finally-timeout threads only.
        /// </summary>
        FinallyTimeoutThread = Default | MustBeAlive,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags should be used when the caller does not require a
        //       valid (non-null) entity be found (i.e. only that one exists
        //       for the given name or token).  These flags may be used by
        //       external components.
        //
        /// <summary>
        /// Combination mask of <see cref="Wrapper" />, <see
        /// cref="Verbose" />, and <see cref="Visible" />, used when the
        /// caller does not require a valid (non-null) entity to be found.
        /// These flags may be used by external components.
        /// </summary>
        NoValidate = Wrapper | Verbose | Visible,

        //
        // NOTE: These flags should be used when the caller wants direct access
        //       to the entity itself, not any intermediate wrapper object that
        //       may contain it.  These flags may be used by external components.
        //
        /// <summary>
        /// Combination mask of <see cref="Validate" />, <see
        /// cref="Verbose" />, and <see cref="Visible" />, used when the
        /// caller wants direct access to the entity rather than its
        /// wrapper.  These flags may be used by external components.
        /// </summary>
        NoWrapper = Validate | Verbose | Visible,

        //
        // NOTE: These flags should be used when the caller does not require an
        //       error message.  These flags may be used by external components.
        //
        /// <summary>
        /// Combination mask of <see cref="Wrapper" />, <see
        /// cref="Validate" />, and <see cref="Visible" />, used when the
        /// caller does not require an error message.  These flags may be
        /// used by external components.
        /// </summary>
        NoVerbose = Wrapper | Validate | Visible,

        //
        // NOTE: These flags are used internally when looking up an entity when
        //       the cache should not be consulted, e.g. [interp expose] and/or
        //       [interp hide].
        //
        /// <summary>
        /// Combination mask of <see cref="NoVerbose" /> and <see
        /// cref="NoCache" />, used internally when the cache should not be
        /// consulted (e.g. <c>[interp expose]</c> and <c>[interp
        /// hide]</c>).
        /// </summary>
        NoVerboseNoCache = NoVerbose | NoCache,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used (internally) when processing encoding
        //       valued command options.  These flags should not be used by
        //       external components.
        //
        /// <summary>
        /// Mask of the flags used internally when processing
        /// encoding-valued command options; equal to <see
        /// cref="AllowNull" />.
        /// </summary>
        EncodingOptionMask = AllowNull, /* COMPAT: TclTk beta. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These flags are used (internally) when processing GetData
        //       method calls inside the file host class (_Hosts.File).
        //
        /// <summary>
        /// Mask of the flags used internally when processing GetData calls
        /// within the file host class; equal to <see cref="NoVerbose" />.
        /// </summary>
        FileHostMask = NoVerbose,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: These are the default flags for all entity lookups.  These
        //       flags may be used by external components.
        //
        /// <summary>
        /// Combination mask of <see cref="Wrapper" />, <see
        /// cref="Validate" />, <see cref="Verbose" />, and <see
        /// cref="Visible" />; these are the default flags for all entity
        /// lookups and may be used by external components.
        /// </summary>
        Default = Wrapper | Validate | Verbose | Visible
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that describe and control
    /// command aliases, including how their arguments are merged and what
    /// kind of target they refer to.  Because it is a bit flags
    /// enumeration, multiple values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("bd01cdba-63db-4751-9c5e-45504fb336af")]
    public enum AliasFlags
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,                /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of alias flags;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,             /* Invalid, do not use. */
        /// <summary>
        /// Reserved for internal use; callers should not use this value.
        /// </summary>
        System = 0x2,              /* Reserved, do not use. */
        /// <summary>
        /// Merge the current command arguments with the arguments
        /// originally specified when the alias was created, preserving the
        /// overall argument order and combining the options together.
        /// </summary>
        MergeArguments = 0x4,      /* The alias will merge the current command arguments with the
                                    * arguments originally specified during alias creation,
                                    * maintaining the overall argument order and merging the options
                                    * together. */
        /// <summary>
        /// When merging arguments, omit the target command name.
        /// </summary>
        SkipTargetName = 0x8,      /* The merged arguments will not include the target command
                                    * name. */
        /// <summary>
        /// When merging arguments, omit the source command name.
        /// </summary>
        SkipSourceName = 0x10,     /* The merged arguments will not include the source command
                                    * name. */
        /// <summary>
        /// When merging arguments, include all non-option arguments from
        /// the target.
        /// </summary>
        UseTargetRemaining = 0x20, /* The merged arguments will include all non-option arguments
                                    * from the target. */
        /// <summary>
        /// Evaluate the target of the alias rather than executing it
        /// directly.
        /// </summary>
        Evaluate = 0x40,           /* The target of the alias will be evaluated rather than executed
                                    * directly. */
        /// <summary>
        /// Use the global namespace as the execution context.
        /// </summary>
        GlobalNamespace = 0x80,    /* The global namespace should be used as the context. */
        /// <summary>
        /// The alias is being used to support <c>[interp alias]</c>.
        /// </summary>
        CrossCommand = 0x100,      /* The command alias is being used for [interp alias] support. */
        /// <summary>
        /// The alias refers to a managed object.
        /// </summary>
        Object = 0x200,            /* The command alias refers to a managed object. */
        /// <summary>
        /// The alias holds a reference to the managed object.
        /// </summary>
        Reference = 0x400,         /* The command alias holds a reference to the managed object. */
        /// <summary>
        /// The alias is being used to support <c>[namespace]</c>.
        /// </summary>
        Namespace = 0x800,         /* The command alias is being used for [namespace] support. */
        /// <summary>
        /// The alias is being used to support <c>[interp create]</c>.
        /// </summary>
        CrossInterpreter = 0x1000, /* The command alias is being used for [interp create] support. */

#if EMIT && NATIVE && LIBRARY
        /// <summary>
        /// The alias refers to a native library delegate.
        /// </summary>
        Library = 0x2000,          /* The command alias refers to a native library delegate. */
#endif

#if NATIVE && TCL
        /// <summary>
        /// The alias is being used to support <c>[tcl eval]</c>.
        /// </summary>
        TclWrapper = 0x4000,       /* The command alias is being used for [tcl eval] support. */
#endif

        /// <summary>
        /// Combination mask of <see cref="GlobalNamespace" /> and <see
        /// cref="CrossCommand" />, used to support <c>[interp alias]</c>.
        /// </summary>
        CrossCommandAlias = GlobalNamespace | CrossCommand,         /* For [interp alias]
                                                                     * support. */
        /// <summary>
        /// Combination mask of <see cref="GlobalNamespace" /> and <see
        /// cref="CrossInterpreter" />, used to support <c>[interp
        /// create]</c>.
        /// </summary>
        CrossInterpreterAlias = GlobalNamespace | CrossInterpreter, /* For [interp create]
                                                                     * support. */
        /// <summary>
        /// Combination mask of <see cref="SkipSourceName" /> and <see
        /// cref="Namespace" />, used to support <c>[namespace import]</c>.
        /// </summary>
        NamespaceImport = SkipSourceName | Namespace                /* For [namespace import]
                                                                     * support. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that describe and control
    /// sub-commands, including how they are queried, added, reset, and
    /// removed, as well as their safety with respect to untrusted scripts.
    /// Because it is a bit flags enumeration, multiple values may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("b8e02964-4bde-47dc-a873-15cd5cb3633e")]
    public enum SubCommandFlags
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,                  /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of sub-command
        /// flags; callers should not use this value.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */
        /// <summary>
        /// The sub-command is handled by the core library.
        /// </summary>
        Core = 0x2,                  /* The sub-command is handled by the core. */
        /// <summary>
        /// The sub-command is safe to execute for partially trusted and
        /// untrusted scripts.
        /// </summary>
        Safe = 0x4,                  /* Sub-command is "safe" to execute for partially
                                      * trusted and/or untrusted scripts. */
        /// <summary>
        /// The sub-command is not safe to execute for partially trusted
        /// and untrusted scripts.
        /// </summary>
        Unsafe = 0x8,                /* Sub-command is NOT "safe" to execute for
                                      * partially trusted and/or untrusted scripts. */
        /// <summary>
        /// Return the sub-command rather than modifying it, even when the
        /// number of arguments to the command would otherwise suggest a
        /// modification.
        /// </summary>
        ForceQuery = 0x10,           /* Instead of modifying the sub-command, just
                                      * return it (i.e. even if the number of arguments
                                      * to the command would suggest otherwise). */
        /// <summary>
        /// The sub-command must be added rather than modified.
        /// </summary>
        ForceNew = 0x20,             /* The sub-command must be added, not modified. */
        /// <summary>
        /// The sub-command must be re-added during a reset if it does not
        /// already exist.
        /// </summary>
        ForceReset = 0x40,           /* The sub-command must be [re-]added during a
                                      * reset, if it does not already exist. */
        /// <summary>
        /// The sub-command must be removed rather than reset.
        /// </summary>
        ForceDelete = 0x80,          /* The sub-command must be removed, not reset. */
        /// <summary>
        /// The query, add, reset, and remove operations may not raise an
        /// error merely because the sub-command does or does not exist;
        /// queries return an empty string in this case.
        /// </summary>
        NoComplain = 0x100,          /* The query, add, reset, and remove operations
                                      * cannot generate an error just because the
                                      * sub-command may -OR- may not exist.  Queries
                                      * will return an empty string in this case. */
        /// <summary>
        /// Raise an error when any arguments are present, because the
        /// configured script will not process them.
        /// </summary>
        StrictNoArguments = 0x200,   /* If any arguments are present, raise an error
                                      * because the configured script will not process. */
        /// <summary>
        /// Append the IExecute.Execute arguments to the configured script
        /// command before evaluating it.
        /// </summary>
        UseExecuteArguments = 0x400, /* Append the IExecute.Execute arguments to the
                                      * configured script command before evaluating. */
        /// <summary>
        /// When combined with <see cref="UseExecuteArguments" />, omit the
        /// command and sub-command names from the passed arguments.
        /// </summary>
        SkipNameArguments = 0x800,   /* When used with UseExecuteArguments, causes the
                                      * names of the command and sub-command to be
                                      * omitted from the passed arguments. */
        /// <summary>
        /// Skip querying and combining the flags and other attributes from
        /// the underlying managed type.
        /// </summary>
        NoAttributes = 0x1000,       /* Skip querying and combining the flags, etc, from
                                      * the underlying managed type. */

        /// <summary>
        /// The default sub-command flags; equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that describe and control
    /// commands, including their origin, safety, visibility, and special
    /// dispatch behavior.  Because it is a bit flags enumeration, multiple
    /// values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("ae31c0f5-e0a8-44b0-b784-bcdadfc76f0e")]
    public enum CommandFlags : ulong
    {
        /// <summary>
        /// No special handling is requested.
        /// </summary>
        None = 0x0,               /* No special handling. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of command flags;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1,            /* Invalid, do not use. */
        /// <summary>
        /// The command is part of the core command set.
        /// </summary>
        Core = 0x2,               /* This command is part of the core command set.
                                   */
        /// <summary>
        /// The command wraps a delegate provided from an external source.
        /// </summary>
        Delegate = 0x4,           /* This command wraps a delegate provided from
                                   * an external source. */
        /// <summary>
        /// The command wraps zero or more delegates to its available
        /// sub-commands.
        /// </summary>
        SubDelegate = 0x8,        /* This command wraps zero or more delegates to
                                   * its available sub-commands. */
        /// <summary>
        /// The command wraps zero or more delegates to its available
        /// sub-commands via a manually specified mapping or a type.
        /// </summary>
        Automatic = 0x10,         /* This command wraps zero or more delegates to
                                   * its available sub-commands via a manually
                                   * specified mapping -OR- a type. */
#if ISOLATED_PLUGINS
        /// <summary>
        /// The command has been loaded into an isolated application
        /// domain, most likely via its parent plugin.
        /// </summary>
        Isolated = 0x20,          /* The command has been loaded into an isolated
                                   * AppDomain (most likely via its parent plugin).
                                   */
#endif
        /// <summary>
        /// The command may not be executed.
        /// </summary>
        Disabled = 0x40,          /* The command may not be executed. */
        /// <summary>
        /// The command may only be executed when allowed by policy.
        /// </summary>
        Hidden = 0x80,            /* The command may only be executed if allowed
                                   * by policy. */
        /// <summary>
        /// The command may not be modified or removed.
        /// </summary>
        ReadOnly = 0x100,         /* The command may not be modified nor removed. */
        /// <summary>
        /// The command contains, calls, or refers to native code.
        /// </summary>
        NativeCode = 0x200,       /* The command contains, calls, or refers to
                                   * native code. */
        /// <summary>
        /// Break into the debugger before executing the command.
        /// </summary>
        Breakpoint = 0x400,       /* Break into debugger before execution. */
        /// <summary>
        /// The command will not be auto-loaded by the plugin manager.
        /// </summary>
        NoAdd = 0x800,            /* The command will not be auto-loaded by the
                                   * plugin manager. */
        /// <summary>
        /// The command will not be populated by the plugin manager.
        /// </summary>
        NoPopulate = 0x1000,      /* The command will not be populated by the
                                   * plugin manager. */
        /// <summary>
        /// The command is really an alias to another command.
        /// </summary>
        Alias = 0x2000,           /* The command is really an alias to another
                                   * command. */
        /// <summary>
        /// Remove any pre-existing command before adding this one.
        /// </summary>
        Replace = 0x4000,         /* Remove any pre-existing command. */
        /// <summary>
        /// Skip adding commands that already exist (restoration mode).
        /// </summary>
        Restore = 0x8000,         /* Skip over trying to add commands if they
                                   * already exist (restoration mode). */
        /// <summary>
        /// The command is safe to execute for partially trusted and
        /// untrusted scripts.
        /// </summary>
        Safe = 0x10000,           /* Command is "safe" to execute for partially
                                   * trusted and/or untrusted scripts. */
        /// <summary>
        /// The command is not safe to execute for partially trusted and
        /// untrusted scripts.
        /// </summary>
        Unsafe = 0x20000,         /* Command is NOT "safe" to execute for
                                   * partially trusted and/or untrusted scripts.
                                   */
        /// <summary>
        /// The command is largely or completely compatible with an
        /// identically named command from Tcl/Tk 8.4, 8.5, and/or 8.6.
        /// </summary>
        Standard = 0x40000,       /* The command is largely (or completely)
                                   * compatible with an identically named command
                                   * from Tcl/Tk 8.4, 8.5, and/or 8.6. */
        /// <summary>
        /// The command is not present in, or is completely incompatible
        /// with an identically named command from, Tcl/Tk 8.4, 8.5, and/or
        /// 8.6.
        /// </summary>
        NonStandard = 0x80000,    /* The command is not present in Tcl/Tk 8.4,
                                   * 8.5, and/or 8.6 -OR- it is completely
                                   * incompatible with an identically named
                                   * command in Tcl/Tk 8.4, 8.5, and/or 8.6. */
        /// <summary>
        /// Skip handling of the command token via the associated plugin.
        /// </summary>
        NoToken = 0x100000,       /* Skip handling of the command token via the
                                   * associated plugin. */
        /// <summary>
        /// Prevent the command from being renamed.
        /// </summary>
        NoRename = 0x200000,      /* Prevent the command from being renamed. */
        /// <summary>
        /// Prevent the command from being removed.
        /// </summary>
        NoRemove = 0x400000,      /* Prevent the command from being removed. */
        /// <summary>
        /// Skip querying and combining the flags and other attributes from
        /// the underlying managed type.
        /// </summary>
        NoAttributes = 0x800000,  /* Skip querying and combining the flags, etc,
                                   * from the underlying managed type. */
        /// <summary>
        /// The command has been superseded and should not be used for new
        /// development.
        /// </summary>
        Obsolete = 0x1000000,     /* The command has been superseded and should
                                   * not be used for new development. */
        /// <summary>
        /// The command is primarily intended to be used when debugging and
        /// testing the core library; the semantics of its sub-commands are
        /// subject to change, even in stable releases, and should not be
        /// relied upon by any production applications, plugins, or
        /// scripts.
        /// </summary>
        Diagnostic = 0x2000000,   /* The command is primarily intended to be used
                                   * when debugging and/or testing the core
                                   * library.  Also, the semantics of the
                                   * contained sub-commands are subject to
                                   * change, even in stable releases, and should
                                   * not be relied upon by any production
                                   * applications, plugins, or scripts. */
        /// <summary>
        /// The command is an ensemble and may have special dispatch
        /// handling for its supported sub-commands and for unknown
        /// sub-commands.
        /// </summary>
        Ensemble = 0x4000000,     /* The command is an ensemble and may have
                                   * special dispatch handling for its supported
                                   * sub-commands and/or for unknown sub-commands.
                                   */
        /// <summary>
        /// The command is really a sub-command.
        /// </summary>
        SubCommand = 0x8000000,   /* The command is really a sub-command. */
#if SHELL && INTERACTIVE_COMMANDS
        /// <summary>
        /// The command is designed to be used only from within interactive
        /// (REPL) loops.
        /// </summary>
        Interactive = 0x10000000, /* The command is designed to be used from
                                   * within interactive (REPL) loops only. */
#endif
        /// <summary>
        /// The command is needed in order to initialize the minimal script
        /// library (i.e. "init.tcltk").
        /// </summary>
        Initialize = 0x20000000,  /* This command is needed in order to be able
                                   * to initialize the minimal script library,
                                   * i.e. "init.tcltk". */
        /// <summary>
        /// The command is needed in order to use the baseline security
        /// SDK.
        /// </summary>
        SecuritySdk = 0x40000000, /* This command is needed in order to use the
                                   * baseline security SDK. */
        /// <summary>
        /// The command is needed in order to use the baseline license SDK.
        /// </summary>
        LicenseSdk = 0x80000000,  /* This command is needed in order to use the
                                   * baseline license SDK. */
        /// <summary>
        /// The command acts as a proxy for other commands and probably
        /// cannot be created directly.
        /// </summary>
        Proxy = 0x100000000,      /* This command acts as a proxy for other
                                   * commands.  It (probably) cannot be created
                                   * directly. */
        /// <summary>
        /// The command should handle its arguments, including (and
        /// especially) its sub-command names, in a case-insensitive
        /// manner.
        /// </summary>
        NoCase = 0x200000000,     /* This command should handle its arguments
                                   * in a case-insensitive manner, including
                                   * (and especially, and possibly only) its
                                   * sub-command names. */
        /// <summary>
        /// The command is specially marked to make clear that any script
        /// with access to it can easily break out of its safe sandbox, if
        /// any, and gain effectively full access to its containing
        /// process.
        /// </summary>
        Critical = 0x400000000,   /* This command is specially marked so it is
                                   * clear that if any script has access to it,
                                   * it will be able to easily break out of its
                                   * "safe" sandbox, if any, and have what is
                                   * effectively full access to its containing
                                   * process. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the command flags that originate from
        /// attributes on the underlying managed type.
        /// </summary>
        AttributeMask = Core | Delegate |
                        SubDelegate | Automatic |
                        NativeCode | NoAdd |
                        NoPopulate | Alias |
                        Safe | Unsafe |
                        Standard | NonStandard |
                        NoRename | NoRemove |
                        Obsolete | Diagnostic |
                        Ensemble | SubCommand |
#if SHELL && INTERACTIVE_COMMANDS
                        Interactive |
#endif
                        Initialize | SecuritySdk |
                        LicenseSdk | Proxy | NoCase |
                        Critical,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the command flags that apply to an
        /// individual command instance.
        /// </summary>
        InstanceMask =
#if ISOLATED_PLUGINS
            Isolated |
#endif
            Disabled | Hidden |
            ReadOnly | Breakpoint |
            NoToken | NoRename |
            NoRemove | NoAttributes |
            NoCase,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Replace" /> and <see
        /// cref="Restore" />, which do not apply to an individual command
        /// instance.
        /// </summary>
        NonInstanceMask = Replace | Restore
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that control how by-reference
    /// command arguments are handled when marshaling values between
    /// scripts and managed objects.  Because it is a bit flags
    /// enumeration, multiple values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("d2ee28ef-b37e-4f90-a88a-408d8610c33e")]
    public enum ByRefArgumentFlags
    {
        /// <summary>
        /// No special flags are set.
        /// </summary>
        None = 0x0,             /* No special flags. */
        /// <summary>
        /// A reserved sentinel indicating an invalid set of by-reference
        /// argument flags; callers should not use this value.
        /// </summary>
        Invalid = 0x1,          /* Invalid, do not use. */
        /// <summary>
        /// Use fast mode, skipping traces, watches, notifications, and
        /// post-processing primarily for speed.
        /// </summary>
        Fast = 0x2,             /* Fast mode, skip traces, watches, notifications,
                                 * post-processing (primarily for speed), etc. */
        /// <summary>
        /// Use direct mode, bypassing all use of SetVariableValue
        /// primarily for speed; currently this applies only to arrays.
        /// </summary>
        Direct = 0x4,           /* Direct mode, bypass all use of SetVariableValue
                                 * (primarily for speed).  Currently, this option
                                 * only applies to arrays. */
        /// <summary>
        /// Enable strict by-reference argument type handling.
        /// </summary>
        Strict = 0x8,           /* Enable strict by-ref argument type handling. */
        /// <summary>
        /// Indicates that an object is expected to be created (e.g. via
        /// System.Int32.Parse).
        /// </summary>
        Create = 0x10,          /* We expect to create an object (e.g. System.Int32.Parse)? */
        /// <summary>
        /// Dispose of the object when it cannot be fully created or added.
        /// </summary>
        Dispose = 0x20,         /* Dipose the object if it cannot be fully created/added? */
        /// <summary>
        /// Create a command alias for the newly created object.
        /// </summary>
        Alias = 0x40,           /* Create a command alias for the newly created object? */
        /// <summary>
        /// The created command alias refers to <c>[object invokeraw]</c>.
        /// </summary>
        AliasRaw = 0x80,        /* The command alias refers to [object invokeraw]. */
        /// <summary>
        /// The created command alias refers to <c>[object invokeall]</c>.
        /// </summary>
        AliasAll = 0x100,       /* The command alias refers to [object invokeall]. */
        /// <summary>
        /// The created command alias holds an object reference.
        /// </summary>
        AliasReference = 0x200, /* The command alias holds an object reference. */
        /// <summary>
        /// Forcibly convert the object to a string and then discard it.
        /// </summary>
        ToString = 0x400,       /* Forcibly convert the object to a string and discard it? */
        /// <summary>
        /// Use opaque object handles for managed arrays instead of setting
        /// the script array element values.
        /// </summary>
        ArrayAsValue = 0x800,   /* Use opaque object handles for managed arrays instead of
                                 * setting the script array element values. */
        /// <summary>
        /// Use a script variable linked to the underlying array object
        /// instead of copying the data.
        /// </summary>
        ArrayAsLink = 0x1000,   /* Use a script variable linked to the underlying array object
                                 * instead of copying the data. */
        /// <summary>
        /// Skip setting variables for by-reference arguments.
        /// </summary>
        NoSetVariable = 0x2000, /* Skip setting variables for by-ref arguments. */

        /// <summary>
        /// A reserved high-order bit; callers should not use this value.
        /// </summary>
        Reserved = unchecked((int)0x80000000)
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the reasons an object reference may have
    /// been added to an opaque object handle, used to track the lifetime
    /// of managed objects exposed to scripts.  Because it is a bit flags
    /// enumeration, multiple values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("ae93bd6d-556e-4d73-bd51-2a1f4af7bca1")]
    public enum ObjectReferenceType
    {
        /// <summary>
        /// No reference type, or an unknown one; callers should not use
        /// this value.
        /// </summary>
        None = 0x0,    // None or unknown, do not use.
        /// <summary>
        /// A reserved sentinel indicating an invalid reference type;
        /// callers should not use this value.
        /// </summary>
        Invalid = 0x1, // Invalid, do not use.
        /// <summary>
        /// The reference was added when the object handle was created.
        /// </summary>
        Create = 0x2,  // Reference was added at handle creation.
        /// <summary>
        /// The reference was added by an explicit script request.
        /// </summary>
        Demand = 0x4,  // Reference was added by script request.
        /// <summary>
        /// The reference was added via a <c>[set]</c> trace.
        /// </summary>
        Trace = 0x8,   // Reference was added via [set] trace.
        /// <summary>
        /// The reference was added via <c>[return]</c>.
        /// </summary>
        Return = 0x10, // Reference was added via [return].
        /// <summary>
        /// The reference was added for a command (possibly an alias).
        /// </summary>
        Command = 0x20 // Reference was added for a command (alias?).
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe and govern the
    /// handling of opaque object handles created for managed objects
    /// within an interpreter, including reference counting, disposal, type
    /// lookup, and command alias behavior.  Since these values are flags,
    /// they may be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("3aa35d84-3d18-4fb5-a6d1-d1d53108d76f")]
    public enum ObjectFlags : ulong
    {
        /// <summary>
        /// No special handling is requested; use this value with great
        /// care.  If the object does not actually belong to the caller,
        /// use <see cref="NoDispose" /> instead.
        /// </summary>
        None = 0x0,                                /* No special handling.  Be very careful when
                                                    * using this.
                                                    * If the object does not actually belong to
                                                    * the caller, be sure to use the NoDispose
                                                    * flag instead. */
        /// <summary>
        /// Reserved as an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,                             /* Invalid, do not use. */
        /// <summary>
        /// Automatic reference counting does not apply to this object.
        /// </summary>
        Locked = 0x2,                              /* Automatic reference counting does not apply
                                                    * to this object. */
        /// <summary>
        /// This object may be used by safe interpreters without risking
        /// security.
        /// </summary>
        Safe = 0x4,                                /* This object can be used by safe interpreters
                                                    * without risking security. */
        /// <summary>
        /// This object is of a well-known object type.
        /// </summary>
        WellKnown = 0x8,                           /* This is of a well-known object type. */
        /// <summary>
        /// This object is an assembly loaded via <c>[object load]</c>.
        /// </summary>
        Assembly = 0x10,                           /* This is assembly loaded by [object load]. */
        /// <summary>
        /// This object originates from this library (the TclTk runtime).
        /// </summary>
        Runtime = 0x20,                            /* This is an object from this library. */
        /// <summary>
        /// This object originates from the hosting application.
        /// </summary>
        Application = 0x40,                        /* This is an object from the application. */
        /// <summary>
        /// This object is an Interpreter object.
        /// </summary>
        Interpreter = 0x80,                        /* This is an Interpreter object. */
        /// <summary>
        /// This object is an InterpreterSettings object.
        /// </summary>
        InterpreterSettings = 0x100,               /* This is an InterpreterSettings object. */
        /// <summary>
        /// This object is an InterpreterHelper object.
        /// </summary>
        InterpreterHelper = 0x200,                 /* This is a InterpreterHelper object. */
        /// <summary>
        /// This object is an event manager object.
        /// </summary>
        EventManager = 0x400,                      /* This is an event manager object. */
        /// <summary>
        /// This object is a script debugger object.
        /// </summary>
        Debugger = 0x800,                          /* This is a script debugger object. */
        /// <summary>
        /// This object is an IHost object of some type.
        /// </summary>
        Host = 0x1000,                             /* This is an IHost object of some type. */
        /// <summary>
        /// This object is a context manager object.
        /// </summary>
        ContextManager = 0x2000,                   /* This is a context manager object. */
        /// <summary>
        /// This object is an engine context object.
        /// </summary>
        EngineContext = 0x4000,                    /* This is an engine context object. */
        /// <summary>
        /// This object is an interactive context object.
        /// </summary>
        InteractiveContext = 0x8000,               /* This is an interactive context object. */
        /// <summary>
        /// This object is a test context object.
        /// </summary>
        TestContext = 0x10000,                     /* This is a test context object. */
        /// <summary>
        /// This object is a variable context object.
        /// </summary>
        VariableContext = 0x20000,                 /* This is a variable context object. */
        /// <summary>
        /// This object is a namespace object.
        /// </summary>
        Namespace = 0x40000,                       /* This is a namespace object. */
        /// <summary>
        /// This object is a call frame object.
        /// </summary>
        CallFrame = 0x80000,                       /* This is a call frame object. */
        /// <summary>
        /// This object is an entity wrapper object of some type.
        /// </summary>
        Wrapper = 0x100000,                        /* This is an entity wrapper object of some
                                                    * type. */
        /// <summary>
        /// This object is a call stack.
        /// </summary>
        CallStack = 0x200000,                      /* This is a call stack. */
        /// <summary>
        /// This object is a variable.
        /// </summary>
        Variable = 0x400000,                       /* This is a variable. */
#if NATIVE && TCL
        /// <summary>
        /// This object is used for interacting with the native Tcl
        /// wrapper.
        /// </summary>
        NativeTcl = 0x800000,                      /* This is an object for interacting with
                                                    * the native Tcl wrapper. */
#endif
        /// <summary>
        /// This object has an associated command alias.
        /// </summary>
        Alias = 0x1000000,                         /* This object has a command alias. */
        /// <summary>
        /// This object cannot be disposed; <c>[object dispose]</c> becomes
        /// a no-op for it.
        /// </summary>
        NoDispose = 0x2000000,                     /* This object cannot be disposed ([object
                                                    * dispose] is a NOP). */
        /// <summary>
        /// The handle for this object should not be created if one with
        /// the same value already exists, even if an object name has been
        /// specified.
        /// </summary>
        AllowExisting = 0x4000000,                 /* The handle for this object should not be
                                                    * created if one with the same value exists
                                                    * (even if the object name has been
                                                    * specified). */
        /// <summary>
        /// The handle for this object should always be created, even if
        /// one with the same value already exists.
        /// </summary>
        ForceNew = 0x8000000,                      /* The handle for this object should always be
                                                    * created (even if one with the same value
                                                    * exists). */
        /// <summary>
        /// This bridged Tcl command object should be forcibly deleted
        /// during disposal.
        /// </summary>
        ForceDelete = 0x10000000,                  /* This bridged Tcl command object should be
                                                    * forcibly deleted during dispose. */
        /// <summary>
        /// Errors should be ignored when attempting to delete the Tcl
        /// command during bridge disposal.
        /// </summary>
        NoComplain = 0x20000000,                   /* Errors should be ignored when trying to
                                                    * delete the Tcl command during bridge
                                                    * disposal. */
        /// <summary>
        /// Skip querying the Binder property of the interpreter.
        /// </summary>
        NoBinder = 0x40000000,                     /* Skip trying to query the Binder property of
                                                    * the interpreter. */
        /// <summary>
        /// Skip all special type lookup handling for the COM object proxy
        /// type (i.e. <c>System.__ComObject</c>).
        /// </summary>
        NoComObjectLookup = 0x80000000,            /* Skip all special type lookup handling for
                                                    * the COM object proxy type (i.e.
                                                    * "System.__ComObject"). */
        /// <summary>
        /// Skip all special return value handling for the COM object proxy
        /// type (i.e. <c>System.__ComObject</c>).
        /// </summary>
        NoComObjectReturn = 0x100000000,           /* Skip all special return value handling for
                                                    * the COM object proxy type (i.e.
                                                    * "System.__ComObject"). */
        /// <summary>
        /// Ignore the <see cref="Alias" /> flag in FixupReturnValue when
        /// looking up existing objects to use for an opaque object handle.
        /// </summary>
        IgnoreAlias = 0x200000000,                 /* Ignore the Alias flag in FixupReturnValue
                                                    * when looking up existing objects to use for
                                                    * an opaque object handle. */
        /// <summary>
        /// This object cannot be disposed automatically because it may not
        /// be owned by the interpreter.
        /// </summary>
        NoAutoDispose = 0x400000000,               /* The object cannot be disposed automatically
                                                    * because we may not own it. */
        /// <summary>
        /// This object should be disposed automatically.
        /// </summary>
        AutoDispose = 0x800000000,                 /* The object should be disposed automatically.
                                                    */
        /// <summary>
        /// Forbid using the ObjectFlagsAttribute when handling object
        /// return values.
        /// </summary>
        NoAttribute = 0x1000000000,                /* Forbid using the ObjectFlagsAttribute when
                                                    * handling object return values. */
        /// <summary>
        /// Force a non-empty opaque object handle to be returned for null
        /// values when the name is automatically generated.
        /// </summary>
        ForceAutomaticName = 0x2000000000,         /* Force a non-empty opaque object handle to be
                                                    * returned for null values when the name is
                                                    * automatically generated. */
        /// <summary>
        /// Force a non-empty opaque object handle to be returned for null
        /// values when the name is manually specified.
        /// </summary>
        ForceManualName = 0x4000000000,            /* Force a non-empty opaque object handle to be
                                                    * returned for null values when the name is
                                                    * manually specified. */
        /// <summary>
        /// Reserved for use with the "null" opaque object handle only; do
        /// not use it for any other purpose.
        /// </summary>
        NullObject = 0x8000000000,                 /* Reserved for use with the "null" opaque
                                                    * object handle only.  Do NOT use this for any
                                                    * other purpose. */
        /// <summary>
        /// Reserved for use by the AddSharedObject method; do not use it
        /// for any other purpose.
        /// </summary>
        SharedObject = 0x10000000000,              /* Reserved for use by the AddSharedObject
                                                    * method.  Do NOT use this for any other
                                                    * purpose. */
        /// <summary>
        /// Add an initial reference when creating a new opaque object
        /// handle.
        /// </summary>
        AddReference = 0x20000000000,              /* Add an initial reference when creating a new
                                                    * opaque object handle. */
        /// <summary>
        /// Create a command alias if the new object was created via an
        /// object that has this flag set.
        /// </summary>
        StickAlias = 0x40000000000,                /* Create a command alias if the new object was
                                                    * created via an object with this flag set. */
        /// <summary>
        /// Forbid creating a command alias merely because the new object
        /// was created via an object with the <see cref="StickAlias" />
        /// flag set.
        /// </summary>
        UnstickAlias = 0x80000000000,              /* Forbid creating a command alias just because
                                                    * the new object was created via an object with
                                                    * the StickAlias flag set. */
        /// <summary>
        /// Skip adding or removing object references in response to
        /// <c>[return]</c>.
        /// </summary>
        NoReturnReference = 0x100000000000,        /* Skip adding / removing object references in
                                                    * response to [return]. */
        /// <summary>
        /// Consider all object references added by <c>[return]</c> to be
        /// temporary; upon returning to the level 0 call frame these
        /// references are removed, which may dispose the object unless it
        /// has been saved into a variable.
        /// </summary>
        TemporaryReturnReference = 0x200000000000, /* Consider all object references added by
                                                    * [return] to be temporary.  Upon returning to
                                                    * the level 0 call frame, these references will
                                                    * be removed, which may result in the object
                                                    * being disposed (i.e. unless it has been saved
                                                    * into a variable). */
        /// <summary>
        /// Do not complain if an attempt to remove this opaque object
        /// handle fails.
        /// </summary>
        NoRemoveComplain = 0x400000000000,         /* Do not complain if an attempt to remove this
                                                    * opaque object handle fails. */
        /// <summary>
        /// When selecting a type from a list of candidates, prefer the one
        /// that has more members.  This flag only applies to COM interop
        /// objects.
        /// </summary>
        PreferMoreMembers = 0x800000000000,        /* When selecting a type from a list of
                                                    * candidates, prefer the one that has more
                                                    * members.  This flag only applies to COM
                                                    * interop objects. */
        /// <summary>
        /// When selecting a type from a list of candidates, prefer the one
        /// whose name is most similar to the one originally specified.
        /// This flag only applies to COM interop objects.
        /// </summary>
        PreferSimilarName = 0x1000000000000,       /* When selecting a type from a list of
                                                    * candidates, prefer the one that has the name
                                                    * the most similar to the one originally
                                                    * specified.  This flag only applies to COM
                                                    * interop objects. */
        /// <summary>
        /// When selecting a type from a list of candidates, reject them
        /// all if none has a similar name.  This flag only applies to COM
        /// interop objects.
        /// </summary>
        RejectDissimilarNames = 0x2000000000000,   /* When selecting a type from a list of
                                                    * candidates, reject them all if none has a
                                                    * similar name.  This flag only applies to COM
                                                    * interop objects. */
        /// <summary>
        /// Ignore case when comparing strings.  This flag only applies to
        /// COM interop objects.
        /// </summary>
        NoCase = 0x4000000000000,                  /* Ignore case when comparing strings.  This
                                                    * flag only applies to COM interop objects. */
        /// <summary>
        /// When possible, automatically use "flags" enumeration handling
        /// for fields set via <c>[object invoke]</c>.
        /// </summary>
        AutoFlagsEnum = 0x8000000000000,           /* When possible, attempt to automatically use
                                                    * the "flags" enumeration handling for fields
                                                    * set via [object invoke]. */
        /// <summary>
        /// Allow the object to be queried via GetType even if it is a
        /// transparent proxy.
        /// </summary>
        AllowProxyGetType = 0x10000000000000,      /* Allow object to be queried via GetType even
                                                    * if it is a transparent proxy. */
        /// <summary>
        /// Force the object to be queried via GetType even if it is a
        /// transparent proxy based on a type that is not loaded into the
        /// AppDomain.
        /// </summary>
        ForceProxyGetType = 0x20000000000000,      /* Force object to be queried via GetType even
                                                    * if it is a transparent proxy based on a type
                                                    * that is not loaded into the AppDomain. */
        /// <summary>
        /// Fall back to using the value of the -proxytype option if a
        /// transparent proxy is detected.
        /// </summary>
        ManualProxyGetType = 0x40000000000000,     /* Fallback to using the value of the -proxytype
                                                    * option if a transparent proxy is detected. */
        /// <summary>
        /// If an object alias is added, use it as the return value instead
        /// of the object name.
        /// </summary>
        ReturnAlias = 0x80000000000000,            /* If an object alias is added, use it as the
                                                    * return value instead of the object name. */
        /// <summary>
        /// When dealing with an opaque object handle that is a transparent
        /// proxy, ignore the stored IObject type.
        /// </summary>
        NullForProxyType = 0x100000000000000,      /* When dealing with an opaque object handle
                                                    * that is a transparent proxy, ignore the
                                                    * stored IObject type. */
        /// <summary>
        /// Skip querying and combining the flags, etc., from the
        /// underlying managed type.
        /// </summary>
        NoAttributes = 0x200000000000000,          /* Skip querying and combining the flags, etc,
                                                    * from the underlying managed type. */
        /// <summary>
        /// This flag bit is reserved and will not be used outside of this
        /// class.
        /// </summary>
        Reserved1 = 0x400000000000000,             /* This flag bit is reserved and will not be
                                                    * used outside of this class. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="PreferMoreMembers" />,
        /// <see cref="PreferSimilarName" />, and
        /// <see cref="RejectDissimilarNames" />.
        /// </summary>
        SelectTypeMask = PreferMoreMembers | PreferSimilarName | RejectDissimilarNames,

        /// <summary>
        /// Combination mask of <see cref="Runtime" />,
        /// <see cref="WellKnown" />, and <see cref="AllowProxyGetType" />.
        /// </summary>
        AllowProxyGetTypeMask = Runtime | WellKnown | AllowProxyGetType,
        /// <summary>
        /// Combination mask of <see cref="Runtime" />,
        /// <see cref="WellKnown" />, and <see cref="ForceProxyGetType" />.
        /// </summary>
        ForceProxyGetTypeMask = Runtime | WellKnown | ForceProxyGetType,

        /// <summary>
        /// Combination mask of <see cref="Locked" />, <see cref="Safe" />,
        /// and <see cref="NullObject" />, for use when adding the "null"
        /// opaque object handle only.
        /// </summary>
        ForNullObject = Locked | Safe | NullObject, /* This mask is for use when adding the
                                                     * "null" opaque object handle only. */

        /// <summary>
        /// Combination mask of <see cref="NoComObjectLookup" /> and
        /// <see cref="NoComObjectReturn" />, which skips all special
        /// handling for the COM object proxy type (i.e.
        /// <c>System.__ComObject</c>).
        /// </summary>
        NoComObject = NoComObjectLookup | NoComObjectReturn, /* Skip all special handling for
                                                              * the COM object proxy type
                                                              * (i.e. "System.__ComObject").
                                                              */

        /// <summary>
        /// Combination of <see cref="NoDispose" /> and
        /// <see cref="Reserved1" />, the default flags used when creating
        /// a CommandCallback object.
        /// </summary>
        Callback = NoDispose | Reserved1, /* Default flags used when creating a
                                           * CommandCallback object. */

        /// <summary>
        /// Combination of <see cref="ForceDelete" /> and
        /// <see cref="Reserved1" />, the default flags used by <c>[object
        /// create]</c>, <c>[object foreach]</c>, <c>[object get]</c>,
        /// <c>[object invoke]</c>, <c>[object load]</c>, and similar.
        /// </summary>
        Default = ForceDelete | Reserved1 /* Default flags used by [object create], [object
                                           * foreach], [object get], [object invoke], [object
                                           * load], etc. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe and control
    /// the characteristics of a procedure defined within an interpreter,
    /// such as its origin, visibility, safety, argument style, and
    /// call-frame behavior.  Since these values are flags, they may be
    /// combined together.
    /// </summary>
    [Flags()]
    [ObjectId("a82bd131-a778-4856-a03e-d09e470a83c7")]
    public enum ProcedureFlags : ulong
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// Reserved as an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,                 /* Invalid, do not use. */
        /// <summary>
        /// This procedure is included with the runtime.
        /// </summary>
        Core = 0x2,                    /* This procedure is included with the runtime. */
        /// <summary>
        /// This procedure is part of the script library.
        /// </summary>
        Library = 0x4,                 /* This procedure is part of the script library. */
        /// <summary>
        /// This procedure is included with the interactive shell.
        /// </summary>
        Interactive = 0x8,             /* This procedure is included with the interactive shell.
                                        */
        /// <summary>
        /// The procedure may not be executed.
        /// </summary>
        Disabled = 0x10,               /* The procedure may not be executed. */
        /// <summary>
        /// The procedure may only be executed if allowed by policy.
        /// </summary>
        Hidden = 0x20,                 /* The procedure may only be executed if allowed by policy.
                                        */
        /// <summary>
        /// The procedure may not be modified nor removed.
        /// </summary>
        ReadOnly = 0x40,               /* The procedure may not be modified nor removed. */
        /// <summary>
        /// The procedure is "safe" to execute for partially trusted and/or
        /// untrusted scripts.
        /// </summary>
        Safe = 0x80,                   /* Procedure is "safe" to execute for partially trusted
                                        * and/or untrusted scripts. */
        /// <summary>
        /// The procedure is NOT "safe" to execute for partially trusted
        /// and/or untrusted scripts.
        /// </summary>
        Unsafe = 0x100,                /* Procedure is NOT "safe" to execute for partially trusted
                                        * and/or untrusted scripts. */
        /// <summary>
        /// Break into the debugger upon procedure entry and exit.
        /// </summary>
        Breakpoint = 0x200,            /* Break into debugger upon entry and exit. */
        /// <summary>
        /// Use the previously pushed script location when evaluating the
        /// procedure body.
        /// </summary>
        ScriptLocation = 0x400,        /* Use the previously pushed script location when evaluating
                                        * the procedure body. */
        /// <summary>
        /// The procedure may NOT be called from anywhere outside of its
        /// own namespace.
        /// </summary>
        Private = 0x800,               /* The procedure may NOT be called from anywhere outside of
                                        * its own namespace. */
        /// <summary>
        /// The procedure may be executed only from within the file it was
        /// defined in; if it was not defined in a file, it may only be
        /// executed outside the context of a file.
        /// </summary>
        Internal = 0x1000,             /* The procedure may be executed only from within the file
                                        * it was defined in.  If the procedure was not defined in
                                        * a file, it may only be executed outside the context of
                                        * a file. */
        /// <summary>
        /// Attempts to replace the procedure are silently ignored.
        /// </summary>
        NoReplace = 0x2000,            /* Attempts to replace the procedure are silently ignored. */
        /// <summary>
        /// Attempts to rename the procedure are silently ignored.
        /// </summary>
        NoRename = 0x4000,             /* Attempts to rename the procedure are silently ignored. */
        /// <summary>
        /// Attempts to remove the procedure are silently ignored.
        /// </summary>
        NoRemove = 0x8000,             /* Attempts to remove the procedure are silently ignored. */
        /// <summary>
        /// Traces, watchpoints, and similar mechanisms are disabled by
        /// default for all local variables.
        /// </summary>
        Fast = 0x10000,                /* Traces, watchpoints, and similar mechanisms are disabled
                                        * by default for all local variables. */
        /// <summary>
        /// The interpreter lock should be held while the procedure is
        /// running.
        /// </summary>
        Atomic = 0x20000,              /* The interpreter lock should be held while the procedure
                                        * is running. */
        /// <summary>
        /// The procedure uses positional arguments; the special "args"
        /// argument is supported.
        /// </summary>
        PositionalArguments = 0x40000, /* The procedure uses positional arguments.  The special
                                        * "args" argument is supported. */
        /// <summary>
        /// The procedure uses named arguments instead of positional
        /// arguments.  Any named argument with an associated default value
        /// is optional, the special "args" argument is still supported,
        /// and there must be an even number of arguments because they
        /// represent name/value pairs.
        /// </summary>
        NamedArguments = 0x80000,      /* The procedure uses named arguments instead of positional
                                        * arguments.  Any named argument with an associated default
                                        * value is optional.  The special "args" argument is still
                                        * supported.  There must be an even number of arguments to
                                        * call the procedure as they represent name/value pairs. */
        /// <summary>
        /// The procedure has been registered by a plugin; its body and
        /// argument names may be unavailable.
        /// </summary>
        Registered = 0x100000,         /* The procedure has been registered by a plugin (i.e. its
                                        * body and argument names may be unavailable). */
        /// <summary>
        /// The procedure has been obfuscated by a plugin; its body and
        /// argument names will be unavailable.
        /// </summary>
        Obfuscated = 0x200000,         /* The procedure has been obfuscated by a plugin (i.e. its
                                        * body and argument names will be unavailable). */
        /// <summary>
        /// Skip querying and combining the flags, etc., from the
        /// underlying managed type.
        /// </summary>
        NoAttributes = 0x400000,       /* Skip querying and combining the flags, etc, from the
                                        * underlying managed type. */

#if ARGUMENT_CACHE || PARSE_CACHE
        /// <summary>
        /// Disable caching for the body of the procedure.  The exact
        /// cache(s) disabled are unspecified and subject to change in the
        /// future.
        /// </summary>
        NonCaching = 0x800000,         /* Disable caching for the body of the procedure.  The exact
                                        * cache(s) that is/are disabled are unspecified and subject
                                        * to change in the future. */
#endif

        /// <summary>
        /// Enforce type restrictions on local variables; a variable value
        /// can only be changed if it is null or has the same type as the
        /// previous value.
        /// </summary>
        MatchTypes = 0x1000000,        /* Enforce restrictions on local variables that pertain to
                                        * their types.  Variable values can only be changed if they
                                        * are null or have the same type as the previous variable
                                        * value. */

        /// <summary>
        /// Skip creating and pushing a new call frame, using the existing
        /// (current) one instead.  Modified and new variables affect that
        /// call frame, and formal argument names that clash with existing
        /// variables force those variables to be saved before body
        /// evaluation and restored upon completion, leaving them
        /// completely unchanged.
        /// </summary>
        NoPushFrame = 0x2000000,       /* Skip creating (and pushing) a new call frame and use the
                                        * existing (current) one instead.  Modified variables will
                                        * be modified in that call frame, including new variables.
                                        * Formal argument names may clash with variables name in
                                        * the target call frame: this will force those variables
                                        * to be saved just before procedure body evaluation and
                                        * to be restored upon completion, which will leave them
                                        * completely unchanged from their original pre-procedure
                                        * call values.  This means that those variables cannot be
                                        * modified in any "easy" way by the target procedure, even
                                        * on purpose. */

        /// <summary>
        /// Reserved for arbitrary use by the application or script.
        /// </summary>
        UserDefined1 = 0x100000000,
        /// <summary>
        /// Reserved for arbitrary use by the application or script.
        /// </summary>
        UserDefined2 = 0x200000000,
        /// <summary>
        /// Reserved for arbitrary use by the application or script.
        /// </summary>
        UserDefined3 = 0x400000000,
        /// <summary>
        /// Reserved for arbitrary use by the application or script.
        /// </summary>
        UserDefined4 = 0x800000000,
        /// <summary>
        /// Reserved for arbitrary use by the application or script.
        /// </summary>
        UserDefined5 = 0x1000000000,

        /// <summary>
        /// Combination of <see cref="PositionalArguments" /> and
        /// <see cref="ForDefault" />.
        /// </summary>
        DefaultArguments = PositionalArguments | ForDefault,
        /// <summary>
        /// Combination mask of <see cref="PositionalArguments" /> and
        /// <see cref="NamedArguments" />.
        /// </summary>
        TypeOnlyMask = PositionalArguments | NamedArguments,

        /// <summary>
        /// Combination mask of <see cref="UserDefined1" />,
        /// <see cref="UserDefined2" />, <see cref="UserDefined3" />,
        /// <see cref="UserDefined4" />, and <see cref="UserDefined5" />.
        /// </summary>
        UserDefinedMask = UserDefined1 | UserDefined2 |
                          UserDefined3 | UserDefined4 |
                          UserDefined5,

        /// <summary>
        /// Indicates these are the default flags supplied by the runtime.
        /// </summary>
        ForDefault = 0x100000000000,

        /// <summary>
        /// Combination of <see cref="None" /> and
        /// <see cref="ForDefault" />, the default flags for a procedure.
        /// </summary>
        Default = None | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that describe and control
    /// the characteristics of a plugin, including its origin, the kinds of
    /// functionality it provides, its security and signing status, and how
    /// it is loaded and managed.  Since these values are flags, they may
    /// be combined together.
    /// </summary>
    [Flags()]
    [ObjectId("b2e5ed96-4dac-4070-bbf5-51464b28c4d5")]
    public enum PluginFlags : ulong
    {
        /// <summary>
        /// No special handling.
        /// </summary>
        None = 0x0,                               /* No special handling. */
        /// <summary>
        /// Reserved as an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,                            /* Invalid, do not use. */
        /// <summary>
        /// Reserved; do not use it.
        /// </summary>
        Reserved1 = 0x2,                          /* Reserved, do not use. */
        /// <summary>
        /// The plugin is the primary one for the containing assembly.
        /// </summary>
        Primary = 0x4,                            /* The plugin is the primary one
                                                   * for the containing assembly. */
        /// <summary>
        /// The plugin is a system plugin (i.e. part of the TclTk runtime).
        /// </summary>
        System = 0x8,                             /* The plugin is a system plugin
                                                   * (i.e. part of the TclTk
                                                   * runtime). */
        /// <summary>
        /// The plugin contains a custom host.
        /// </summary>
        Host = 0x10,                              /* The plugin contains a custom
                                                   * host. */
        /// <summary>
        /// The plugin contains a script debugger (reserved for future
        /// use).
        /// </summary>
        Debugger = 0x20,                          /* The plugin contains a script
                                                   * debugger (reserved for future
                                                   * use). */
        /// <summary>
        /// The plugin is a user plugin (i.e. from a third-party vendor).
        /// </summary>
        User = 0x40,                              /* The plugin is a user plugin
                                                   * (i.e. from a third-party
                                                   * vendor). */
        /// <summary>
        /// The plugin is part of a commercial product; this implies, but
        /// does not explicitly state, that the plugin is closed source
        /// and/or is not licensed under a Tcl-style license.
        /// </summary>
        Commercial = 0x80,                        /* The plugin is part of a
                                                   * commercial product, this
                                                   * implies but does not explicitly
                                                   * state that the plugin is closed
                                                   * source and/or is not licensed
                                                   * under a Tcl-style license. */
        /// <summary>
        /// The plugin contains proprietary code; this implies, but does
        /// not explicitly state, that the plugin is closed source and/or
        /// is not licensed under a Tcl-style license.
        /// </summary>
        Proprietary = 0x100,                      /* The plugin contains proprietary
                                                   * code, this implies but does not
                                                   * explicitly state that the
                                                   * plugin is closed source and/or
                                                   * is not licensed under a
                                                   * Tcl-style license. */
        /// <summary>
        /// The plugin contains one or more custom commands.
        /// </summary>
        Command = 0x200,                          /* The plugin contains one or more
                                                   * custom commands. */
        /// <summary>
        /// The plugin contains one or more custom <c>[expr]</c> functions.
        /// </summary>
        Function = 0x400,                         /* The plugin contains one or more
                                                   * custom [expr] functions. */
        /// <summary>
        /// The plugin traces variables (interpreter-wide and/or specific
        /// variables).
        /// </summary>
        Trace = 0x800,                            /* The plugin traces variables
                                                   * (interpreter-wide and/or
                                                   * specific variables). */
        /// <summary>
        /// The plugin listens for notifications.
        /// </summary>
        Notify = 0x1000,                          /* The plugin listens for
                                                   * notifications. */
        /// <summary>
        /// The plugin contains one or more policies.  Setting this flag
        /// requires the <see cref="Primary" /> flag to be set as well.
        /// </summary>
        Policy = 0x2000,                          /* The plugin contains one or more
                                                   * policies.  Setting this flag
                                                   * requires the Primary flag to be
                                                   * set as well. */
        /// <summary>
        /// The plugin contains one or more command and/or variable
        /// resolvers.
        /// </summary>
        Resolver = 0x4000,                        /* The plugin contains one or more
                                                   * command and/or variable
                                                   * resolvers. */
        /// <summary>
        /// The plugin was provided "statically" by the application.
        /// </summary>
        Static = 0x8000,                          /* The plugin was provided
                                                   * "statically" by the
                                                   * application. */
        /// <summary>
        /// The plugin was loaded on-demand by the <c>[load]</c> command.
        /// </summary>
        Demand = 0x10000,                         /* The plugin was loaded on-demand
                                                   * by the [load] command. */
        /// <summary>
        /// The plugin contains, calls, or refers to unsafe code.
        /// </summary>
        UnsafeCode = 0x20000,                     /* The plugin contains, calls, or
                                                   * refers to unsafe code. */
        /// <summary>
        /// The plugin contains, calls, or refers to native code.
        /// </summary>
        NativeCode = 0x40000,                     /* The plugin contains, calls, or
                                                   * refers to native code. */
        /// <summary>
        /// The plugin ONLY contains commands that are "safe" when executed
        /// by untrusted or marginally trusted scripts.  Currently this
        /// flag is never set by TclTk itself; plugin authors are
        /// encouraged to set it when all of their functionality is safe
        /// for such use.
        /// </summary>
        SafeCommands = 0x80000,                   /* The plugin ONLY contains
                                                   * commands which are "safe" when
                                                   * executed by untrusted or
                                                   * marginally trusted scripts.
                                                   * Currently, this flag is never
                                                   * set by TclTk itself; however,
                                                   * plugin authors are encouraged
                                                   * to set this flag for their
                                                   * plugins if all their
                                                   * functionality is safe for use
                                                   * by untrusted or marginally
                                                   * trusted scripts.  In the
                                                   * future, TclTk may make more
                                                   * extensive use of this flag.
                                                   */
        /// <summary>
        /// When adding commands from the plugin, ignore those that are
        /// already present.
        /// </summary>
        MergeCommands = 0x100000,                 /* When adding commands from the
                                                   * plugin, ignore those that are
                                                   * already present. */
        /// <summary>
        /// When adding commands, overwrite existing ones.
        /// </summary>
        OverwriteCommands = 0x200000,             /* When adding commands, overwrite
                                                   * existing ones. */
        /// <summary>
        /// When adding procedures from the plugin, ignore those that are
        /// already present.
        /// </summary>
        MergeProcedures = 0x400000,               /* When adding procedures from the
                                                   * plugin, ignore those that are
                                                   * already present. */
        /// <summary>
        /// When adding procedures, overwrite existing ones.
        /// </summary>
        OverwriteProcedures = 0x800000,           /* When adding procedures,
                                                   * overwrite existing ones. */
        /// <summary>
        /// When adding policies from the plugin, ignore those that are
        /// already present.
        /// </summary>
        MergePolicies = 0x1000000,                /* When adding policies from the
                                                   * plugin, ignore those that are
                                                   * already present. */
        /// <summary>
        /// When adding policies, overwrite existing ones.
        /// </summary>
        OverwritePolicies = 0x2000000,            /* When adding policies, overwrite
                                                   * existing ones. */
        /// <summary>
        /// The plugin is primarily for unit testing purposes.
        /// </summary>
        Test = 0x4000000,                         /* The plugin is primarily for
                                                   * unit testing purposes. */
        /// <summary>
        /// The plugin contains a user interface.
        /// </summary>
        UserInterface = 0x8000000,                /* The plugin contains a user
                                                   * interface. */
        /// <summary>
        /// The default plugin should not perform initialization logic on
        /// behalf of the plugin.
        /// </summary>
        NoInitialize = 0x10000000,                /* The default plugin should not
                                                   * perform initialization logic on
                                                   * behalf of the plugin. */
        /// <summary>
        /// The default plugin should not perform termination logic on
        /// behalf of the plugin.
        /// </summary>
        NoTerminate = 0x20000000,                 /* The default plugin should not
                                                   * perform termination logic on
                                                   * behalf of the plugin. */
        /// <summary>
        /// The default plugin should not add commands on behalf of the
        /// plugin.
        /// </summary>
        NoCommands = 0x40000000,                  /* The default plugin should not
                                                   * add commands on behalf of the
                                                   * plugin. */
        /// <summary>
        /// The default plugin should not add functions on behalf of the
        /// plugin.
        /// </summary>
        NoFunctions = 0x80000000,                 /* The default plugin should not
                                                   * add functions on behalf of the
                                                   * plugin. */
        /// <summary>
        /// The default plugin should not add policies on behalf of the
        /// plugin.
        /// </summary>
        NoPolicies = 0x100000000,                 /* The default plugin should not
                                                   * add policies on behalf of the
                                                   * plugin.
                                                   */
        /// <summary>
        /// The default plugin should not add traces on behalf of the
        /// plugin.
        /// </summary>
        NoTraces = 0x200000000,                   /* The default plugin should not
                                                   * add traces on behalf of the
                                                   * plugin. */
        /// <summary>
        /// The notify plugin should not provide the package on behalf of
        /// the plugin.
        /// </summary>
        NoProvide = 0x400000000,                  /* The notify plugin should not
                                                   * provide the package on behalf
                                                   * of the plugin. */
        /// <summary>
        /// The plugin does not have any scripting resources and should not
        /// be queried by the interpreter via any resource manager it may
        /// contain.
        /// </summary>
        NoResources = 0x800000000,                /* The plugin does not have any
                                                   * scripting resources and should
                                                   * not be queried by the
                                                   * interpreter via any resource
                                                   * manager it may contain. */
        /// <summary>
        /// The plugin does not have any auxiliary data and a dictionary
        /// should not be created.
        /// </summary>
        NoAuxiliaryData = 0x1000000000,           /* The plugin does not have any
                                                   * auxiliary data and a dictionary
                                                   * should not be created. */
        /// <summary>
        /// The default plugin should not set or reset the initialized
        /// flag.
        /// </summary>
        NoInitializeFlag = 0x2000000000,          /* The default plugin should not
                                                   * set or reset the initialized
                                                   * flag. */
        /// <summary>
        /// The default plugin should not set the result from within the
        /// IState.Initialize and IState.Terminate methods.
        /// </summary>
        NoResult = 0x4000000000,                  /* The default plugin should not
                                                   * set the result from within the
                                                   * IState.Initialize and
                                                   * IState.Terminate methods. */
        /// <summary>
        /// The core host should not call the GetStream method for the
        /// plugin.
        /// </summary>
        NoGetStream = 0x8000000000,               /* The core host should not call
                                                   * the GetStream method for the
                                                   * plugin. */
        /// <summary>
        /// The core host should not call the GetString method for the
        /// plugin.
        /// </summary>
        NoGetString = 0x10000000000,              /* The core host should not call
                                                   * the GetString method for the
                                                   * plugin. */
        /// <summary>
        /// The plugin assembly has a StrongName signature.  This may not
        /// be 100% reliable.  WARNING: do not set this flag manually and
        /// do not make security decisions based on its presence or
        /// absence.
        /// </summary>
        StrongName = 0x20000000000,               /* The plugin assembly has a
                                                   * StrongName signature.  May not
                                                   * be 100% reliable.  WARNING: DO
                                                   * NOT SET THIS FLAG MANUALLY AND
                                                   * DO NOT MAKE SECURITY DECISIONS
                                                   * BASED ON THE PRESENCE OR
                                                   * ABSENCE OF THIS FLAG. */
        /// <summary>
        /// The StrongName signature has been "verified" via the CLR native
        /// API.  This may not be 100% reliable.  WARNING: do not set this
        /// flag manually and do not make security decisions based on its
        /// presence or absence.
        /// </summary>
        Verified = 0x40000000000,                 /* The StrongName signature has
                                                   * been "verified" via the CLR
                                                   * native API.  May not be 100%
                                                   * reliable.  WARNING: DO NOT SET
                                                   * THIS FLAG MANUALLY AND DO NOT
                                                   * MAKE SECURITY DECISIONS BASED
                                                   * ON THE PRESENCE OR ABSENCE OF
                                                   * THIS FLAG. */
        /// <summary>
        /// The StrongName signature must be "verified" via the CLR native
        /// API before any plugin file can be loaded.  This may not be 100%
        /// reliable.
        /// </summary>
        VerifiedOnly = 0x80000000000,             /* The StrongName signature must
                                                   * be "verified" via the CLR
                                                   * native API before any plugin
                                                   * file can be loaded.  This may
                                                   * not be 100% reliable. */
        /// <summary>
        /// The StrongName signature checking was skipped.
        /// </summary>
        SkipVerified = 0x100000000000,            /* The StrongName signature
                                                   * checking was skipped. */
        /// <summary>
        /// The plugin assembly has an Authenticode signature.  This may
        /// not be 100% reliable.  WARNING: do not set this flag manually
        /// and do not make security decisions based on its presence or
        /// absence.
        /// </summary>
        Authenticode = 0x200000000000,            /* The plugin assembly has an
                                                   * Authenticode signature.  May
                                                   * not be 100% reliable.  WARNING:
                                                   * DO NOT SET THIS FLAG MANUALLY
                                                   * AND DO NOT MAKE SECURITY
                                                   * DECISIONS BASED ON THE PRESENCE
                                                   * OR ABSENCE OF THIS FLAG. */
        /// <summary>
        /// The Authenticode signature and certificate appear to be
        /// "trusted" by the operating system.  This may not be 100%
        /// reliable.  WARNING: do not set this flag manually and do not
        /// make security decisions based on its presence or absence.
        /// </summary>
        Trusted = 0x400000000000,                 /* The Authenticode signature and
                                                   * certificate appear to be
                                                   * "trusted" by the operating
                                                   * system.  May not be 100%
                                                   * reliable.  WARNING: DO NOT SET
                                                   * THIS FLAG MANUALLY AND DO NOT
                                                   * MAKE SECURITY DECISIONS BASED
                                                   * ON THE PRESENCE OR ABSENCE OF
                                                   * THIS FLAG. */
        /// <summary>
        /// The Authenticode signature and certificate must be "trusted" by
        /// the operating system before any plugin file can be loaded.
        /// This may not be 100% reliable.
        /// </summary>
        TrustedOnly = 0x800000000000,             /* The Authenticode signature and
                                                   * certificate must be "trusted"
                                                   * by the operating system before
                                                   * any plugin file can be loaded.
                                                   * This may not be 100% reliable.
                                                   */
        /// <summary>
        /// The Authenticode signature and certificate checking was
        /// skipped.
        /// </summary>
        SkipTrusted = 0x1000000000000,            /* The Authenticode signature and
                                                   * certificate checking was
                                                   * skipped. */
        /// <summary>
        /// The IState.Terminate method should be skipped during the
        /// UnloadPlugin method that accepts an IPlugin instance.
        /// </summary>
        SkipTerminate = 0x2000000000000,          /* The IState.Terminate method
                                                   * should be skipped during the
                                                   * UnloadPlugin method that
                                                   * accepts an IPlugin instance. */
#if ISOLATED_PLUGINS
        /// <summary>
        /// The plugin assembly should be (or has been) loaded into an
        /// isolated AppDomain.
        /// </summary>
        Isolated = 0x4000000000000,               /* The plugin assembly should be
                                                   * (or has been) loaded into an
                                                   * isolated AppDomain. */
        /// <summary>
        /// Prevent the <see cref="Isolated" /> flag from being honored.
        /// </summary>
        NoIsolated = 0x8000000000000,             /* Prevent the Isolated flag from
                                                   * being honored. */
        /// <summary>
        /// The plugin assembly must be loaded into an isolated AppDomain.
        /// This value is only supported when present in the custom
        /// attributes for the plugin assembly or type.
        /// </summary>
        IsolatedOnly = 0x10000000000000,          /* The plugin assembly must be
                                                   * loaded into an isolated
                                                   * AppDomain.  This value is only
                                                   * supported when it is present in
                                                   * the custom attributes for the
                                                   * plugin assembly or type. */
        /// <summary>
        /// Prevent the <see cref="IsolatedOnly" /> flag from being
        /// honored.
        /// </summary>
        NoIsolatedOnly = 0x20000000000000,        /* Prevent the IsolatedOnly flag
                                                   * from being honored. */
        /// <summary>
        /// Disable resetting the value of the entry assembly when creating
        /// a new AppDomain.
        /// </summary>
        NoUseEntryAssembly = 0x40000000000000,    /* Disable resetting the value of
                                                   * the entry assembly when
                                                   * creating a new AppDomain. */
        /// <summary>
        /// Ignore exceptions when forcibly refreshing the entry assembly
        /// in created AppDomains.
        /// </summary>
        OptionalEntryAssembly = 0x80000000000000, /* Ignore exceptions when forcibly
                                                   * refreshing the entry assembly
                                                   * in created AppDomains. */
        /// <summary>
        /// Make sure the AppDomain base directory contains the core
        /// library assembly.
        /// </summary>
        VerifyCoreAssembly = 0x100000000000000,   /* Make sure the AppDomain base
                                                   * directory contains the core
                                                   * library assembly? */
#if SHELL
        /// <summary>
        /// Check for updates to plugins just prior to loading them (i.e.
        /// via their configured "update" URIs).  If the update process
        /// fails, fall back to loading the one already present locally.
        /// </summary>
        UpdateCheck = 0x200000000000000,          /* Check for updates to plugins
                                                   * just prior to loading them
                                                   * (i.e. via their configured
                                                   * "update" URIs).  If the update
                                                   * process fails, just fallback to
                                                   * loading the one that is already
                                                   * present locally. */
        /// <summary>
        /// Prevent the <see cref="UpdateCheck" /> flag from being honored.
        /// </summary>
        NoUpdateCheck = 0x400000000000000,        /* Prevent the UpdateCheck flag
                                                   * from being honored. */
#endif
        /// <summary>
        /// Disable loading plugin assemblies into a "preview" context in
        /// order to determine their metadata (e.g. plugin flags).
        /// </summary>
        NoPreview = 0x800000000000000,            /* Disable loading plugin
                                                   * assemblies into a "preview"
                                                   * context in order to determine
                                                   * their metadata (e.g. plugin
                                                   * flags). */
#endif
        /// <summary>
        /// Enable using the simple plugin name when adding the associated
        /// package.
        /// </summary>
        SimpleName = 0x1000000000000000,          /* Enable using the simple plugin
                                                   * name when adding the associated
                                                   * package. */
        /// <summary>
        /// The plugin is a licensed component and that license has been
        /// verified.
        /// </summary>
        Licensed = 0x2000000000000000,            /* The plugin is a licensed
                                                   * component and that license has
                                                   * been verified. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Allow plugins to be loaded on threads other than the primary
        /// thread for the interpreter.
        /// </summary>
        LoadOnAnyThread = 0x4000000000000000,     /* Allow plugins to be loaded on
                                                   * threads other than the primary
                                                   * thread for the interpreter. */
        /// <summary>
        /// Skip querying and combining the flags, etc., from the
        /// underlying managed type.
        /// </summary>
        NoAttributes = 0x8000000000000000,        /* Skip querying and combining the
                                                   * flags, etc, from the underlying
                                                   * managed type. */
        /// <summary>
        /// Equivalent to <see cref="NoAttributes" />; reserved for future
        /// use and must not be set.
        /// </summary>
        Reserved2 = NoAttributes,                 /* The flag is reserved for future
                                                   * use and must not be set. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="VerifiedOnly" /> and
        /// <see cref="TrustedOnly" />.
        /// </summary>
        VerifiedAndTrustedOnlyMask = VerifiedOnly | TrustedOnly,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if ISOLATED_PLUGINS
#if SHELL
        //
        // NOTE: By default, prevent any plugin update checks from
        //       running unless the interactive loop is invoked.
        //       This could be very important because plugin update
        //       checks could interfere with a script (file?) being
        //       evaluated via the command line.
        //
        /// <summary>
        /// Combination mask of plugin flags applied when running in a
        /// non-interactive context, suppressing behavior (such as update
        /// checks) that could interfere with scripts being evaluated from
        /// the command line.
        /// </summary>
        NonInteractiveMask = OptionalEntryAssembly | NoUpdateCheck | Reserved1,
        /// <summary>
        /// Combination mask that optionally requests verification that the
        /// AppDomain base directory contains the core library assembly.
        /// </summary>
        MaybeVerifyCoreAssembly = VerifyCoreAssembly | Reserved1,
#else
        /// <summary>
        /// Combination mask of plugin flags applied when running in a
        /// non-interactive context, suppressing behavior (such as update
        /// checks) that could interfere with scripts being evaluated from
        /// the command line.
        /// </summary>
        NonInteractiveMask = OptionalEntryAssembly | Reserved1,
        /// <summary>
        /// Combination mask that optionally requests verification that the
        /// AppDomain base directory contains the core library assembly.
        /// </summary>
        MaybeVerifyCoreAssembly = VerifyCoreAssembly | Reserved1,
#endif
#else
        /// <summary>
        /// Combination mask of plugin flags applied when running in a
        /// non-interactive context, suppressing behavior (such as update
        /// checks) that could interfere with scripts being evaluated from
        /// the command line.
        /// </summary>
        NonInteractiveMask = None | Reserved1,
        /// <summary>
        /// Combination mask that optionally requests verification that the
        /// AppDomain base directory contains the core library assembly.
        /// </summary>
        MaybeVerifyCoreAssembly = None | Reserved1,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default plugin flags, derived from
        /// <see cref="NonInteractiveMask" /> and
        /// <see cref="MaybeVerifyCoreAssembly" /> with the
        /// <see cref="Reserved1" /> bit cleared.
        /// </summary>
        Default = (NonInteractiveMask | MaybeVerifyCoreAssembly) & ~Reserved1
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the bit flags that control how package
    /// index scripts are located, evaluated, and tracked by the
    /// interpreter.  Since these values are flags, they may be combined
    /// together.
    /// </summary>
    [Flags()]
    [ObjectId("eb0e3225-f87c-4f47-b30e-6ab38548cd7c")]
    public enum PackageIndexFlags : ulong
    {
        /// <summary>
        /// No special handling.
        /// </summary>
        None = 0x0,                         /* No special handling. */
        /// <summary>
        /// Reserved as an invalid value; do not use it.
        /// </summary>
        Invalid = 0x1,                      /* Invalid, do not use. */
        /// <summary>
        /// Reserved; do not use it.
        /// </summary>
        Reserved = 0x2,                     /* Reserved, do not use. */
        /// <summary>
        /// Check the file system before checking the interpreter host.
        /// </summary>
        PreferFileSystem = 0x4,             /* Check the file system before checking the
                                             * interpreter host. */
        /// <summary>
        /// Check the interpreter host before checking the file system.
        /// </summary>
        PreferHost = 0x8,                   /* Check the interpreter host before checking
                                             * the file system. */
        /// <summary>
        /// Use the interpreter host to find the package index.
        /// </summary>
        Host = 0x10,                        /* Use the interpreter host to find the
                                             * package index. */
        /// <summary>
        /// Use the bundle manager to find package index(es).
        /// </summary>
        Bundle = 0x20,                      /* Use the bundle manager to find package
                                             * index(es). */
#if APPDOMAINS || ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
        /// <summary>
        /// Use the external file system to find candidate plugin
        /// assemblies and probe them for their package indexes.
        /// </summary>
        Plugin = 0x40,                      /* Use the external file system to find
                                             * candidate plugin assemblies and probe
                                             * them for their package indexes. */
#endif
        /// <summary>
        /// Use the external file system to find the package index.
        /// </summary>
        Normal = 0x80,                      /* Use the external file system to find
                                             * the package index. */
        /// <summary>
        /// Forbid using the file system to find the package index.  This
        /// flag is only effective when using the interpreter host to find
        /// the package index.
        /// </summary>
        NoNormal = 0x100,                   /* Forbid using the file system to find
                                             * the package index.  This flag is only
                                             * effective when using the interpreter
                                             * host to find the package index. */
        /// <summary>
        /// Search all sub-directories as well.
        /// </summary>
        Recursive = 0x200,                  /* Search all sub-directories as well? */
        /// <summary>
        /// Force the package index to be re-found and re-evaluated.
        /// </summary>
        Refresh = 0x400,                    /* Force package index to be re-found
                                             * and re-evaluated. */
        /// <summary>
        /// Resolve the fully qualified file name for the package index
        /// script.
        /// </summary>
        Resolve = 0x800,                    /* Resolve the fully qualified file name
                                             * for the package index script. */
        /// <summary>
        /// Enable tracing of key package index operations.
        /// </summary>
        Trace = 0x1000,                     /* Enable tracing of key package index
                                             * operations. */
        /// <summary>
        /// Enable verbose tracing output when processing package index
        /// scripts.
        /// </summary>
        Verbose = 0x2000,                   /* Enable verbose tracing output when
                                             * processing package index scripts. */
        /// <summary>
        /// The package index script was found and processed.
        /// </summary>
        Found = 0x4000,                     /* The package index script was found
                                             * and processed. */
        /// <summary>
        /// This flag is no longer used.
        /// </summary>
        Locked = 0x8000,                    /* This flag is no longer used. */
        /// <summary>
        /// Evaluate the package index script in "safe" mode.
        /// </summary>
        Safe = 0x10000,                     /* Evaluate the package index script in
                                             * "safe" mode. */
        /// <summary>
        /// The package index script was actually evaluated.
        /// </summary>
        Evaluated = 0x20000,                /* The package index script was actually
                                             * evaluated. */
        /// <summary>
        /// If a package index script fails, just ignore the error.
        /// </summary>
        NoComplain = 0x40000,               /* If a package index script fails, just
                                             * ignore the error. */
        /// <summary>
        /// If the GetFiles operation throws an exception, treat it as a
        /// failure rather than propagating the error.
        /// </summary>
        NoFileError = 0x80000,              /* If GetFiles throws an exception, just
                                             * fail. */
#if APPDOMAINS || ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
        /// <summary>
        /// When processing (sub-)package index scripts, stop on the first
        /// error.
        /// </summary>
        StopOnError = 0x100000,             /* When processing (sub?) package index
                                             * scripts, stop on the first error? */
#endif
        /// <summary>
        /// When processing plugin assemblies, do not check whether they
        /// are signed using an Authenticode certificate.
        /// </summary>
        NoTrusted = 0x200000,               /* When processing plugin assemblies, do
                                             * not check if they are signed using an
                                             * Authenticode certificate.
                                             */
        /// <summary>
        /// When processing plugin assemblies, do not check whether they
        /// are signed using a StrongName key.
        /// </summary>
        NoVerified = 0x400000,              /* When processing plugin assemblies, do
                                             * not check if they are signed using a
                                             * StrongName key.*/
        /// <summary>
        /// Skip removing "logically duplicate" package index directory
        /// names when doing a refresh operation.
        /// </summary>
        AllowDuplicateDirectory = 0x800000, /* Skip removing "logically duplicate"
                                             * package index directory names when doing
                                             * a refresh operation. */
        /// <summary>
        /// Skip removing "logically duplicate" package index file names
        /// when doing a refresh operation.
        /// </summary>
        AllowDuplicateFile = 0x1000000,     /* Skip removing "logically duplicate"
                                             * package index file names when doing
                                             * a refresh operation. */
        /// <summary>
        /// Do not sort the package index file names when evaluating them.
        /// </summary>
        NoSort = 0x2000000,                 /* Do not sort the package index file
                                             * names when evaluating them. */
        /// <summary>
        /// Run in "what-if" mode; do not modify any persistent interpreter
        /// state.
        /// </summary>
        WhatIf = 0x4000000,                 /* Running in "what-if" mode, do not
                                             * modify any persistent interpreter
                                             * state. */
        /// <summary>
        /// When processing package indexes, mark all created packages as
        /// temporary.
        /// </summary>
        Temporary = 0x8000000,              /* When processing package indexes, mark
                                             * all the created packages as temporary.
                                             */
        /// <summary>
        /// Include the primary package index file in the file search.
        /// </summary>
        Primary = 0x10000000,               /* Include the primary package index file
                                             * in the file search. */
        /// <summary>
        /// Include the tagged package index files in the file search.
        /// </summary>
        Tagged = 0x20000000,                /* Include the tagged package index files
                                             * in the file search. */
        /// <summary>
        /// Dump all package indexes at the end of each package index scan
        /// operation, whether successful or not.
        /// </summary>
        Dump = 0x40000000,                  /* Be sure to dump all package indexes
                                             * at the end of each package index scan
                                             * operation, successful or otherwise. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Indicates these are the flags used internally by the engine.
        /// </summary>
        ForEngine = 0x1000000000,
        /// <summary>
        /// Indicates these are the default flags supplied by the runtime.
        /// </summary>
        ForDefault = 0x2000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

#if APPDOMAINS || ISOLATED_INTERPRETERS || ISOLATED_PLUGINS
        /// <summary>
        /// Optionally includes the <see cref="Plugin" /> flag when
        /// plugin-based package index probing is available; otherwise no
        /// flags are set.
        /// </summary>
        MaybePlugin = Plugin,
        /// <summary>
        /// Combination mask of <see cref="Host" /> and
        /// <see cref="Normal" />, representing the non-plugin package
        /// index sources.
        /// </summary>
        NonPluginMask = Host | Normal,
#else
        /// <summary>
        /// Optionally includes the <c>Plugin</c> flag when plugin-based
        /// package index probing is available; otherwise no flags are set.
        /// </summary>
        MaybePlugin = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE
        /// <summary>
        /// Optionally includes the <see cref="NoTrusted" /> flag when
        /// native support is available; otherwise no flags are set.
        /// </summary>
        MaybeNoTrusted = NoTrusted,
        /// <summary>
        /// Optionally includes the <see cref="NoVerified" /> flag when
        /// native support is available; otherwise no flags are set.
        /// </summary>
        MaybeNoVerified = NoVerified,
#else
        /// <summary>
        /// Optionally includes the <see cref="NoTrusted" /> flag when
        /// native support is available; otherwise no flags are set.
        /// </summary>
        MaybeNoTrusted = None,
        /// <summary>
        /// Optionally includes the <see cref="NoVerified" /> flag when
        /// native support is available; otherwise no flags are set.
        /// </summary>
        MaybeNoVerified = None,
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Host" /> and
        /// <see cref="Bundle" />.
        /// </summary>
        HostMask = Host | Bundle,
        /// <summary>
        /// Combination mask of <see cref="Normal" /> and
        /// <see cref="MaybePlugin" />.
        /// </summary>
        NonHostMask = Normal | MaybePlugin,
        /// <summary>
        /// Combination mask of <see cref="Host" />, <see cref="Bundle" />,
        /// and <see cref="MaybePlugin" />.
        /// </summary>
        NonNormalMask = Host | Bundle | MaybePlugin,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This is the value used by the auto-path variable trace
        //       callback.
        //
#if DEBUG
        /// <summary>
        /// The flags used by the auto-path variable trace callback,
        /// combining the various host, bundle, file system, and recursion
        /// options used to locate package indexes.
        /// </summary>
        AutoPath = Host | Bundle | Normal | Primary | Tagged |
                   NoNormal | Recursive | MaybeNoTrusted |
                   MaybeNoVerified | NoSort | Dump, /* TODO: Good default? */
#else
        /// <summary>
        /// The flags used by the auto-path variable trace callback,
        /// combining the various host, bundle, file system, and recursion
        /// options used to locate package indexes.
        /// </summary>
        AutoPath = Host | Bundle | Normal | Primary | Tagged |
                   NoNormal | Recursive | NoSort | Dump, /* TODO: Good default? */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="AllowDuplicateDirectory" /> and
        /// <see cref="AllowDuplicateFile" />.
        /// </summary>
        AllowDuplicate = AllowDuplicateDirectory | AllowDuplicateFile,

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is used when finding and loading the Harpy / Badge
        //       package index scripts.  This is only done in response to the
        //       "-security" command line option -OR- by calling the ScriptOps
        //       EnableOrDisableSecurity method.
        //
        /// <summary>
        /// The flags used when finding and loading the Harpy / Badge
        /// package index scripts, derived from <see cref="AutoPath" /> and
        /// <see cref="Safe" /> with the <see cref="Host" /> and
        /// <see cref="Recursive" /> bits cleared.
        /// </summary>
        SecurityPackage = (AutoPath | Safe) & ~(Host | Recursive),

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of flags used when evaluating an individual package
        /// index file, including <see cref="Normal" />,
        /// <see cref="Temporary" />, <see cref="Tagged" />,
        /// <see cref="NoComplain" />, <see cref="NoFileError" />,
        /// <see cref="Dump" />, and <see cref="ForEngine" />.
        /// </summary>
        EvaluateFile = Normal | Temporary | Tagged | NoComplain |
                       NoFileError | Dump | ForEngine,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="NoFileError" />, <see cref="Dump" />,
        /// and <see cref="ForDefault" />, the default package index flags.
        /// </summary>
        Default = NoFileError | Dump | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that describe the origin,
    /// characteristics, and handling rules of a package known to the
    /// interpreter's package database.  Because it is a <c>[Flags]</c>
    /// enumeration, individual values may be combined together using a
    /// bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("753ee5b0-e42b-4c69-b398-960f54ba75dd")]
    public enum PackageFlags : ulong
    {
        /// <summary>
        /// No flags are set; nothing special applies to the package.
        /// </summary>
        None = 0x0,             /* Nothing special. */
        /// <summary>
        /// A reserved sentinel value that is invalid and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,          /* Invalid, do not use. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The package is a system package and should not be used
        /// directly.
        /// </summary>
        System = 0x2,           /* The package is a system package, do not use. */
        /// <summary>
        /// The package is currently being loaded via <c>[package
        /// require]</c>.
        /// </summary>
        Loading = 0x4,          /* The package is currently being loaded via
                                 * PackageRequire. */
        /// <summary>
        /// The package was provided statically rather than via a script
        /// file.
        /// </summary>
        Static = 0x8,           /* The package was provided statically. */
        /// <summary>
        /// The package is included with the runtime core.
        /// </summary>
        Core = 0x10,            /* The package is included with the runtime. */
        /// <summary>
        /// The package was provided by a plugin.
        /// </summary>
        Plugin = 0x20,          /* The package was provided by a plugin. */
        /// <summary>
        /// The package is part of the script library.
        /// </summary>
        Library = 0x40,         /* The package is part of the script library. */
        /// <summary>
        /// The package is included with the interactive shell.
        /// </summary>
        Interactive = 0x80,     /* The package is included with the interactive
                                 * shell. */
        /// <summary>
        /// The package was added to the interpreter automatically.
        /// </summary>
        Automatic = 0x100,      /* The package was added to the interpreter
                                 * automatically. */
        /// <summary>
        /// The package is locked and cannot be replaced via the
        /// <c>[package ifneeded]</c> sub-command.
        /// </summary>
        Locked = 0x200,         /* The package is locked and cannot be replaced
                                 * via the [package ifneeded] sub-command. */
        /// <summary>
        /// When combined with <see cref="Locked" />, causes an error to be
        /// generated by the <c>[package ifneeded]</c> sub-command.
        /// </summary>
        Rejected = 0x400,       /* When used with the Locked flag, this flag
                                 * will cause an error to be generated by the
                                 * [package ifneeded] sub-command. */
        /// <summary>
        /// The package was added automatically as the result of core
        /// script file evaluation.
        /// </summary>
        Temporary = 0x800,      /* The package was added automatically via core
                                 * script file evaluation. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Skip updating the package flags when the package is provided.
        /// </summary>
        NoUpdate = 0x1000,      /* Skip updating package flags upon provide. */
        /// <summary>
        /// The <c>[package provide]</c> sub-command should always do
        /// nothing for this package.
        /// </summary>
        NoProvide = 0x2000,     /* The [package provide] sub-command should
                                 * always do nothing. */
        /// <summary>
        /// The <c>[package vsatisfies]</c> sub-command should always
        /// return true for this package.
        /// </summary>
        AlwaysSatisfy = 0x4000, /* The [package vsatisfies] sub-command should
                                 * always return true. */
        /// <summary>
        /// The <c>[package ifneeded]</c> sub-command should preserve
        /// existing package information.
        /// </summary>
        KeepExisting = 0x8000,  /* The [package ifneeded] sub-command should
                                 * preserve existing package information. */
        /// <summary>
        /// The <c>[package ifneeded]</c> sub-command should fail if
        /// existing package information is present.
        /// </summary>
        FailExisting = 0x10000, /* The [package ifneeded] sub-command should
                                 * fail if existing package information is
                                 * present. */
        /// <summary>
        /// Skip querying and combining the flags and other attributes from
        /// the underlying managed type.
        /// </summary>
        NoAttributes = 0x20000, /* Skip querying and combining the flags,
                                 * etc, from the underlying managed type. */
        /// <summary>
        /// Enable automatic use of <c>[package scan]</c> in cases where
        /// <c>[package require]</c> fails.
        /// </summary>
        AutoScan = 0x1000000,   /* Enable (automatic) use of [package scan]
                                 * in cases where [package require] fails. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Disable the use of package aliases during package resolution.
        /// </summary>
        NoAlias = 0x100000,     /* Disable use of package aliases during
                                 * package resolution. */
        /// <summary>
        /// An existing package (or alias) entry should be overwritten if
        /// necessary.
        /// </summary>
        Overwrite = 0x200000,   /* An existing package (alias?) entry should
                                 * be overwritten, if necessary. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The package (or alias) has been explicitly disabled.
        /// </summary>
        Disabled = 0x400000,    /* The package (alias?) has been explicitly
                                 * disabled. */
        /// <summary>
        /// The -exact option was used for the <c>[package]</c> command, et
        /// al.
        /// </summary>
        Exact = 0x800000,       /* The -exact option was used for [package],
                                 * et al. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        //
        // NOTE: This value is used when evaluating the Harpy / Badge package
        //       indexes prior to the interpreter being initialized.  This is
        //       only done in response to the "-security" command line option
        //       -OR- by calling the ScriptOps.EnableOrDisableSecurity method.
        //
        /// <summary>
        /// Combination mask used when evaluating the Harpy / Badge package
        /// indexes prior to interpreter initialization, made up of <see
        /// cref="NoProvide" /> and <see cref="AlwaysSatisfy" />.
        /// </summary>
        SecurityPackageMask = NoProvide | AlwaysSatisfy,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the flags that affect package management
        /// actions, namely <see cref="NoUpdate" />, <see cref="NoProvide"
        /// />, <see cref="AlwaysSatisfy" />, <see cref="KeepExisting" />,
        /// <see cref="FailExisting" />, <see cref="NoAttributes" />, <see
        /// cref="AutoScan" />, <see cref="NoAlias" />, and <see
        /// cref="Overwrite" />.
        /// </summary>
        ActionMask = NoUpdate | NoProvide | AlwaysSatisfy |
                     KeepExisting | FailExisting | NoAttributes |
                     AutoScan | NoAlias | Overwrite,

        /// <summary>
        /// Combination mask of the per-instance package flags, namely <see
        /// cref="System" />, <see cref="Loading" />, <see cref="Static"
        /// />, <see cref="Core" />, <see cref="Plugin" />, <see
        /// cref="Library" />, <see cref="Interactive" />, <see
        /// cref="Automatic" />, <see cref="Locked" />, <see
        /// cref="Rejected" />, and <see cref="Temporary" />.
        /// </summary>
        InstanceMask = System | Loading | Static | Core |
                       Plugin | Library | Interactive |
                       Automatic | Locked | Rejected |
                       Temporary,

        /// <summary>
        /// Combination mask of the package alias flags, namely <see
        /// cref="Disabled" /> and <see cref="Exact" />.
        /// </summary>
        AliasMask = Disabled | Exact,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default set of package flags, equivalent to <see
        /// cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how the interpreter
    /// waits for and processes events, for example while servicing the
    /// <c>[vwait]</c> command or the event loop.  Because it is a
    /// <c>[Flags]</c> enumeration, individual values may be combined
    /// together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("864f7d71-9202-4e44-aa42-0d1c9d3468ff")]
    public enum EventWaitFlags
    {
        /// <summary>
        /// No flags are set; default event waiting behavior is used.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel value that is invalid and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Do not report background errors that occur while waiting.
        /// </summary>
        NoBgError = 0x2,
        /// <summary>
        /// Do not process events owned by the event manager while waiting.
        /// </summary>
        NoManagerEvents = 0x4,
        /// <summary>
        /// Do not impose a timeout on the wait operation.
        /// </summary>
        NoTimeout = 0x8,
        /// <summary>
        /// Do not honor script cancellation while waiting.
        /// </summary>
        NoCancel = 0x10,
        /// <summary>
        /// Do not honor global (interpreter-wide) script cancellation
        /// while waiting.
        /// </summary>
        NoGlobalCancel = 0x20,
        /// <summary>
        /// Stop waiting if an error is encountered.
        /// </summary>
        StopOnError = 0x40,
        /// <summary>
        /// Treat an empty event queue as an error condition.
        /// </summary>
        ErrorOnEmpty = 0x80,
        /// <summary>
        /// Process user-interface events while waiting.
        /// </summary>
        UserInterface = 0x100,
        /// <summary>
        /// Do not process user-interface events while waiting.
        /// </summary>
        NoUserInterface = 0x200,
        /// <summary>
        /// Do not process any events while waiting.
        /// </summary>
        NoEvents = 0x400,
        /// <summary>
        /// Do not process Windows messages while waiting.
        /// </summary>
        NoWindows = 0x800,
        /// <summary>
        /// Return immediately rather than blocking to wait for events.
        /// </summary>
        NoWait = 0x1000,
        /// <summary>
        /// Do not sleep between event processing iterations.
        /// </summary>
        NoSleep = 0x2000,
        /// <summary>
        /// Suppress complaints raised while waiting.
        /// </summary>
        NoComplain = 0x4000,
        /// <summary>
        /// Stop waiting if a complaint is raised.
        /// </summary>
        StopOnComplain = 0x8000,
        /// <summary>
        /// Stop waiting if a global (interpreter-wide) complaint is
        /// raised.
        /// </summary>
        StopOnGlobalComplain = 0x10000,
        /// <summary>
        /// Process only events associated with variables that are being
        /// waited on.
        /// </summary>
        OnlyWaiting = 0x20000,
        /// <summary>
        /// Process the wait only if the associated variable exists.
        /// </summary>
        OnlyExists = 0x40000,
        /// <summary>
        /// Process a single event per iteration of the wait loop.
        /// </summary>
        DoOneEvent = 0x80000,
        /// <summary>
        /// Follow variable links when determining what is being waited on.
        /// </summary>
        FollowLink = 0x100000,
        /// <summary>
        /// Enable diagnostic tracing of the wait operation.
        /// </summary>
        Trace = 0x200000,

#if NATIVE && TCL
        /// <summary>
        /// Process a single native Tcl event per iteration of the wait
        /// loop.
        /// </summary>
        TclDoOneEvent = 0x400000,
        /// <summary>
        /// Wait for a native Tcl event.  This flag should rarely, if ever,
        /// be used.
        /// </summary>
        TclWaitEvent = 0x800000, // NOTE: This flag should rarely, if ever, be used.
        /// <summary>
        /// Process all pending native Tcl events while waiting.
        /// </summary>
        TclAllEvents = 0x1000000,
#endif

        /// <summary>
        /// Marks the flags that contribute to the default wait behavior.
        /// </summary>
        ForDefault = 0x2000000,

        /// <summary>
        /// Combination mask of <see cref="StopOnComplain" /> and <see
        /// cref="StopOnGlobalComplain" />.
        /// </summary>
        StopOnAnyComplain = StopOnComplain | StopOnGlobalComplain,
        /// <summary>
        /// Combination mask of <see cref="StopOnError" />, <see
        /// cref="StopOnComplain" />, and <see cref="StopOnGlobalComplain"
        /// />.
        /// </summary>
        StopOnAny = StopOnError | StopOnComplain | StopOnGlobalComplain,

        /// <summary>
        /// The default set of event wait flags, a combination of <see
        /// cref="DoOneEvent" />, <see cref="FollowLink" />, and <see
        /// cref="ForDefault" />.
        /// </summary>
        Default = DoOneEvent | FollowLink | ForDefault
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that describe the state of a
    /// variable as well as the behavior of the various variable management
    /// operations (e.g. get, set, and unset).  Because it is a
    /// <c>[Flags]</c> enumeration, individual values may be combined
    /// together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("c5c70166-aa98-4f6f-8d08-1e9099b0aa11")]
    public enum VariableFlags : ulong
    {
        /* general flags (instanced) */

        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel value that is invalid and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,            /* Invalid, do not use. */
        /// <summary>
        /// The variable is an array.
        /// </summary>
        Array = 0x2,              /* variable is an array */
        /// <summary>
        /// The variable cannot be modified by a script.
        /// </summary>
        ReadOnly = 0x4,           /* cannot be modified by a script */
        /// <summary>
        /// The variable cannot be read by a script.
        /// </summary>
        WriteOnly = 0x8,          /* cannot be read by a script */
        /// <summary>
        /// The variable is virtual and cannot be used with <c>[array
        /// get]</c>, <c>[array names]</c>, <c>[array values]</c>,
        /// <c>[array set]</c>, <c>[array size]</c>, <c>[array
        /// startsearch]</c>, or <c>[array unset]</c>.
        /// </summary>
        Virtual = 0x10,           /* cannot be used with [array get], [array names],
                                   * [array values], [array set], [array size],
                                   * [array startsearch], or [array unset]. */
        /// <summary>
        /// The variable is a pre-defined script library variable.
        /// </summary>
        System = 0x20,            /* pre-defined script library variable */
        /// <summary>
        /// The variable cannot be modified by a script (reserved).
        /// </summary>
        Invariant = 0x40,         /* cannot be modified by a script (reserved) */
        /// <summary>
        /// The variable can be modified even within an immutable
        /// interpreter.
        /// </summary>
        Mutable = 0x80,           /* variable can be modified even in an immutable
                                   * interpreter. */
        /// <summary>
        /// The variable can be used within a "safe" interpreter.
        /// </summary>
        Safe = 0x100,             /* variable can be used in a "safe" interpreter. */
        /// <summary>
        /// The variable cannot be used within a "safe" interpreter.
        /// </summary>
        Unsafe = 0x200,           /* variable CANNOT be used in a "safe" interpreter. */
        /// <summary>
        /// The variable is a global or upvar alias (link).
        /// </summary>
        Link = 0x400,             /* global or upvar alias */
        /// <summary>
        /// The variable was declared via global or upvar but has not yet
        /// been set.
        /// </summary>
        Undefined = 0x800,        /* declared via global or upvar but not yet set */
        /// <summary>
        /// The variable is a formal procedure argument.
        /// </summary>
        Argument = 0x1000,        /* variable is a formal procedure argument */
        /// <summary>
        /// The variable is global.
        /// </summary>
        Global = 0x2000,          /* variable is global */
        /// <summary>
        /// The variable is local to the current procedure.
        /// </summary>
        Local = 0x4000,           /* variable is local to the current procedure */
        /// <summary>
        /// The variable is being waited on by the interpreter.
        /// </summary>
        Wait = 0x8000,            /* variable is being waited on by the interpreter. */
        /// <summary>
        /// The dirty bit; the variable has changed, including being unset.
        /// </summary>
        Dirty = 0x10000,          /* dirty bit, variable has changed (including unset) */
        /// <summary>
        /// Disable variable watches (watchpoints) for this variable.
        /// </summary>
        NoWatchpoint = 0x20000,   /* disable watches for this variable. */
        /// <summary>
        /// Disable read/write traces for this variable.
        /// </summary>
        NoTrace = 0x40000,        /* disable read/write traces for this variable. */
        /// <summary>
        /// Disable event notifications for this variable.
        /// </summary>
        NoNotify = 0x80000,       /* disable event notifications for this variabe. */
        /// <summary>
        /// Disable post-processing of the variable value.
        /// </summary>
        NoPostProcess = 0x100000, /* disable post-processing of the variable value. */
        /// <summary>
        /// Break into the debugger upon get access to the variable.
        /// </summary>
        BreakOnGet = 0x200000,    /* break into debugger on get access */
        /// <summary>
        /// Break into the debugger upon set access to the variable.
        /// </summary>
        BreakOnSet = 0x400000,    /* break into debugger on set access */
        /// <summary>
        /// Break into the debugger upon unset access to the variable.
        /// </summary>
        BreakOnUnset = 0x800000,  /* break into debugger on unset access */
        /// <summary>
        /// Perform <c>[subst]</c> on the variable value prior to returning
        /// it.
        /// </summary>
        Substitute = 0x1000000,   /* subst the variable value prior to returning it */
        /// <summary>
        /// Evaluate the variable value prior to returning it.
        /// </summary>
        Evaluate = 0x2000000,     /* eval the variable value prior to returning it */

        /* "action" and/or "result" flags (non-instanced) */

        /// <summary>
        /// The variable was searched for but was not found; otherwise, the
        /// variable was not searched for because the name was invalid.
        /// </summary>
        NotFound = 0x4000000,                 /* the variable was searched for, but was not found;
                                               * otherwise, the variable was not searched for
                                               * because the name was invalid */
        /// <summary>
        /// Do not create a new variable, only modify an existing one.
        /// </summary>
        NoCreate = 0x8000000,                 /* do not create a new variable, only modify
                                               * existing an existing one */
        /// <summary>
        /// Get or set the variable only within the global call frame.
        /// </summary>
        GlobalOnly = 0x10000000,              /* get or set variable only within the global call
                                               * frame */
        /// <summary>
        /// The variable name cannot refer to an array.
        /// </summary>
        NoArray = 0x20000000,                 /* variable name cannot refer to an array */
        /// <summary>
        /// The variable name cannot be an array element reference.
        /// </summary>
        NoElement = 0x40000000,               /* variable name cannot be an element reference */
        /// <summary>
        /// Unset the variable without raising "does not exist" errors.
        /// </summary>
        NoComplain = 0x80000000,              /* unset without raising "does not exist" errors */
        /// <summary>
        /// Append to the variable value instead of replacing it.
        /// </summary>
        AppendValue = 0x100000000,            /* append to the value instead of setting */
        /// <summary>
        /// Append to the variable list instead of replacing it.
        /// </summary>
        AppendElement = 0x200000000,          /* append to the list instead of setting */
        /// <summary>
        /// Operate on the variable link itself rather than the linked
        /// variable.
        /// </summary>
        NoFollowLink = 0x400000000,           /* operate on variable link, not the variable itself */
        /// <summary>
        /// Reset the variable value or values to null when unset.
        /// </summary>
        ResetValue = 0x800000000,             /* reset value(s) to null when unset */

#if !MONO && NATIVE && WINDOWS
        /// <summary>
        /// Upon unset, forcibly zero strings that may contain sensitive
        /// data.  This is not guaranteed to work reliably on all
        /// platforms; extreme care should be exercised when handling any
        /// sensitive data.
        /// </summary>
        ZeroString = 0x1000000000,            /* Upon [unset], enable forcibly zeroing strings
                                               * that may contain "sensitive" data?  WARNING: THIS
                                               * IS NOT GUARANTEED TO WORK RELIABLY ON ALL PLATFORMS.
                                               * EXTREME CARE SHOULD BE EXERCISED WHEN HANDLING
                                               * ANY SENSITIVE DATA, INCLUDING TESTING THAT THIS
                                               * FLAG WORKS WITHIN THE SPECIFIC TARGET APPLICATION
                                               * AND ON THE SPECIFIC TARGET PLATFORM. */
#endif

        /// <summary>
        /// Purge deleted variables in the call frame upon unset.
        /// </summary>
        Purge = 0x2000000000,                 /* purge deleted variables in call frame on unset */
        /// <summary>
        /// Skip splitting the variable name from the array element index.
        /// </summary>
        NoSplit = 0x4000000000,               /* skip splitting the variable name from the array
                                               * element index. */
        /// <summary>
        /// Skip the check that determines whether the interpreter is
        /// ready.
        /// </summary>
        NoReady = 0x8000000000,               /* force skip of check if interpreter is ready */
        /// <summary>
        /// Do not remove the variable from the call frame.
        /// </summary>
        NoRemove = 0x10000000000,             /* do not remove variable from the call frame */
        /// <summary>
        /// Do not validate the variable as an array or non-array.
        /// </summary>
        NoGetArray = 0x20000000000,           /* do not validate the variable as an array or
                                               * non-array */
        /// <summary>
        /// The variable cannot have a valid link index.
        /// </summary>
        NoLinkIndex = 0x40000000000,          /* variable cannot have a valid link index. */
        /// <summary>
        /// The variable has a valid link index and it should not (i.e. an
        /// alias to an array element is not wanted).
        /// </summary>
        HasLinkIndex = 0x80000000000,         /* the variable has a valid link index and it should
                                               * not (i.e. we do not want an alias to an array
                                               * element). */
        /// <summary>
        /// Validate that the variable is not undefined.
        /// </summary>
        Defined = 0x100000000000,             /* validate that the variable is not undefined */
        /// <summary>
        /// Skip opaque object handle processing.
        /// </summary>
        NoObject = 0x200000000000,            /* skip opaque object handle processing. */
        /// <summary>
        /// Skip all variable breakpoints for the duration of this method
        /// call.
        /// </summary>
        SkipWatchpoint = 0x400000000000,      /* skip all variable breakpoints for the duration of
                                               * this method call. */
        /// <summary>
        /// Skip all variable traces for the duration of this method call.
        /// </summary>
        SkipTrace = 0x800000000000,           /* skip all variable traces for the duration of this
                                               * method call. */
        /// <summary>
        /// Skip all event notifications for the duration of this method
        /// call.
        /// </summary>
        SkipNotify = 0x1000000000000,         /* skip all event notifications for the duration of
                                               * this method call. */
        /// <summary>
        /// Skip post-processing of the variable value for this method
        /// call.
        /// </summary>
        SkipPostProcess = 0x2000000000000,    /* skip post-processing the variable value for this
                                               * method call.  */
        /// <summary>
        /// Allow variable resolvers to return a null variable along with a
        /// successful return code.
        /// </summary>
        ResolveNull = 0x4000000000000,        /* allow variable resolvers to return a null
                                               * variable along with a successful return code. */
        /// <summary>
        /// Disallow returning virtual variables.
        /// </summary>
        NonVirtual = 0x8000000000000,         /* disallow returning virtual variables. */
        /// <summary>
        /// The variable was virtual and it should not have been.
        /// </summary>
        WasVirtual = 0x10000000000000,        /* the variable was virtual and it should not be. */
        /// <summary>
        /// The variable name refers to an array element.
        /// </summary>
        WasElement = 0x20000000000000,        /* the variable name refers to an array element. */
        /// <summary>
        /// Force the creation of a new TraceInfo object instead of using
        /// the pre-allocated one for the thread.
        /// </summary>
        NewTraceInfo = 0x40000000000000,      /* force the creation of a new TraceInfo object
                                               * instead of using the pre-allocated one for the
                                               * thread. */
        /// <summary>
        /// Skip converting the variable value to a string before it is
        /// returned.
        /// </summary>
        SkipToString = 0x80000000000000,      /* skip converting the variable value to be returned
                                               * to a string. */
        /// <summary>
        /// Force conversion of the variable value to a string prior to it
        /// being returned.
        /// </summary>
        ForceToString = 0x100000000000000,    /* force conversion of the variable value to string
                                               * prior to being returned. */
        /// <summary>
        /// As a fallback, when used with <see cref="SkipToString" />,
        /// allow the variable value to be returned as a string if it does
        /// not conform to a supported type.
        /// </summary>
        FallbackToString = 0x200000000000000, /* as a fallback, when used with SkipToString, allow
                                               * the variable value to be returned as a string if
                                               * it does not conform to a supported type. */
        /// <summary>
        /// Create the variable if it is missing, but do not add it to the
        /// target call frame.
        /// </summary>
        CreateMissing = 0x400000000000000,    /* Create the variable if it is missing, but do not
                                               * add it to the target call frame. */
        /// <summary>
        /// The variable was missing from the call frame and a new (dummy)
        /// variable was returned.
        /// </summary>
        WasMissing = 0x800000000000000,       /* The variable was missing from the call frame and
                                               * a new (dummy) variable was returned. */
        /// <summary>
        /// Skip checking whether the variable is actually usable from the
        /// current thread.
        /// </summary>
        NoUsable = 0x1000000000000000,        /* skip checking if the variable is actually usable
                                               * from the current thread. */
        /// <summary>
        /// The caller is indicating that the outer logical operation that
        /// triggered the variable trace was completely successful.
        /// </summary>
        Success = 0x2000000000000000,         /* The caller is stating that the current (outer)
                                               * logical operation that triggered the variable
                                               * trace was completely successful. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved value; do not use.
        /// </summary>
        Reserved1 = 0x4000000000000000,       /* Reserved value, do not use. */
        /// <summary>
        /// A reserved value; do not use.
        /// </summary>
        Reserved2 = 0x8000000000000000,       /* Reserved value, do not use. */
        /// <summary>
        /// Combination mask of <see cref="Reserved1" /> and <see
        /// cref="Reserved2" />.
        /// </summary>
        ReservedMask = Reserved1 | Reserved2,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /* internal library use only */

        /// <summary>
        /// Combination mask reserved for internal library use, made up of
        /// <see cref="System" /> and <see cref="GlobalOnly" />.
        /// </summary>
        LibraryMask = System | GlobalOnly,

        /* virtual / system mask (instanced) */

        /// <summary>
        /// Combination mask of <see cref="Virtual" /> and <see
        /// cref="System" />.
        /// </summary>
        VirtualOrSystemMask = Virtual | System,

        /* watch flags mask (instanced) */

        /// <summary>
        /// Combination mask of <see cref="BreakOnGet" />, <see
        /// cref="BreakOnSet" />, and <see cref="BreakOnUnset" />.
        /// </summary>
        BreakOnAny = BreakOnGet | BreakOnSet | BreakOnUnset,
        /// <summary>
        /// Combination mask of <see cref="BreakOnAny" /> and <see
        /// cref="Mutable" /> used for variable watchpoints.
        /// </summary>
        WatchpointMask = BreakOnAny | Mutable,

        /* no watch/trace/notify/post-process flags (instanced and non-instanced) */

        /// <summary>
        /// Combination mask of <see cref="NoWatchpoint" /> and <see
        /// cref="SkipWatchpoint" />.
        /// </summary>
        NonWatchpoint = NoWatchpoint | SkipWatchpoint,
        /// <summary>
        /// Combination mask of <see cref="NoTrace" /> and <see
        /// cref="SkipTrace" />.
        /// </summary>
        NonTrace = NoTrace | SkipTrace,
        /// <summary>
        /// Combination mask of <see cref="NoNotify" /> and <see
        /// cref="SkipNotify" />.
        /// </summary>
        NonNotify = NoNotify | SkipNotify,
        /// <summary>
        /// Combination mask of <see cref="NoPostProcess" /> and <see
        /// cref="SkipPostProcess" />.
        /// </summary>
        NonPostProcess = NoPostProcess | SkipPostProcess,

        /* "action" and/or "result" flags (non-instanced) */

        /// <summary>
        /// Combination mask of the "action" and/or "result" flags that are
        /// not stored on the variable instance itself.
        /// </summary>
        NonInstanceMask = NotFound | NoCreate | GlobalOnly | NoArray |
                          NoElement | NoComplain | AppendValue | AppendElement |
                          NoFollowLink | ResetValue |
#if !MONO && NATIVE && WINDOWS
                          ZeroString |
#endif
                          Purge | NoSplit | NoReady |
                          NoRemove | NoGetArray | NoLinkIndex | HasLinkIndex |
                          Defined | NoObject | SkipWatchpoint | SkipTrace |
                          SkipNotify | SkipPostProcess | ResolveNull | NonVirtual |
                          WasVirtual | WasElement | NewTraceInfo | SkipToString |
                          ForceToString | FallbackToString | CreateMissing | WasMissing |
                          NoUsable | Success | ReservedMask,

        /* flags not allowed when adding variables */

        /// <summary>
        /// Combination mask of the flags that are not allowed when adding
        /// variables, including <see cref="Link" />, <see cref="Global"
        /// />, <see cref="Local" />, <see cref="Dirty" />, and <see
        /// cref="NonInstanceMask" />.
        /// </summary>
        NonAddMask = Link | Global | Local | Dirty |
                     NonInstanceMask,

        /* flags not allowed when setting variable values */

        /// <summary>
        /// Combination mask of the flags that are not allowed when setting
        /// variable values, including <see cref="Array" />, <see
        /// cref="Virtual" />, <see cref="Undefined" />, and <see
        /// cref="NonAddMask" />.
        /// </summary>
        NonSetMask = Array | Virtual | Undefined | NonAddMask,

        /* flags masked off when a variable is recycled */

        /// <summary>
        /// Combination mask of the flags that are masked off when a
        /// variable is recycled.
        /// </summary>
        NonDefinedMask = ReadOnly | WriteOnly | System | Invariant |
                         Mutable | Safe | Unsafe | Argument |
                         Wait | Dirty | NoWatchpoint | NoTrace |
                         NoNotify | NoPostProcess | BreakOnGet | BreakOnSet |
                         BreakOnUnset | Substitute | Evaluate | NonSetMask,

        /* flags used when querying/setting a raw variable value */

        /// <summary>
        /// Combination mask of the flags used when querying or setting a
        /// raw variable value, made up of <see cref="Reserved1" /> and
        /// <see cref="None" />.
        /// </summary>
        DirectValueMask = Reserved1 | None,
        /// <summary>
        /// Combination mask used when directly getting a raw variable
        /// value, made up of <see cref="DirectValueMask" /> and <see
        /// cref="SkipToString" />.
        /// </summary>
        DirectGetValueMask = DirectValueMask | SkipToString,
        /// <summary>
        /// Combination mask used when directly setting a raw variable
        /// value, equivalent to <see cref="DirectValueMask" />.
        /// </summary>
        DirectSetValueMask = DirectValueMask,

        /* flags when the variable is being get/set automatically via a
         * property setter method, the engine, or the interactive loop. */

        /// <summary>
        /// Flags used when the variable is get or set automatically via a
        /// property setter method, equivalent to <see cref="NoReady" />.
        /// </summary>
        ViaProperty = NoReady,
        /// <summary>
        /// Flags used when the variable is get or set automatically via
        /// the interactive shell, equivalent to <see cref="NoReady" />.
        /// </summary>
        ViaShell = NoReady,
        /// <summary>
        /// Flags used when the variable is get or set automatically via
        /// the engine, equivalent to <see cref="NoReady" />.
        /// </summary>
        ViaEngine = NoReady,
        /// <summary>
        /// Flags used when the variable is get or set automatically via
        /// the interactive prompt, made up of <see cref="GlobalOnly" />
        /// and <see cref="NoReady" />.
        /// </summary>
        ViaPrompt = GlobalOnly | NoReady,

        /* flags allowed when the interpreter is read-only and/or immutable */

        /// <summary>
        /// Combination mask of the flags allowed when the interpreter is
        /// read-only, equivalent to <see cref="System" />.
        /// </summary>
        ReadOnlyMask = System,
        /// <summary>
        /// Combination mask of the flags allowed when the interpreter is
        /// immutable, made up of <see cref="System" /> and <see
        /// cref="Mutable" />.
        /// </summary>
        ImmutableMask = System | Mutable,

        /* used for [array], etc. */

        /// <summary>
        /// Combination mask of <see cref="Defined" /> and <see
        /// cref="NonVirtual" /> used by variable-related commands.
        /// </summary>
        CommonCommandMask = Defined | NonVirtual,
        /// <summary>
        /// Combination mask used by the <c>[array]</c> command, made up of
        /// <see cref="CommonCommandMask" />, <see cref="NoElement" />, and
        /// <see cref="NoLinkIndex" />.
        /// </summary>
        ArrayCommandMask = CommonCommandMask | NoElement | NoLinkIndex,

        /* used for GetVariable result flags checking (failure reason) */

        /// <summary>
        /// Combination mask used when checking GetVariable result flags
        /// for the failure reason, made up of <see cref="NotFound" /> and
        /// <see cref="HasLinkIndex" />.
        /// </summary>
        ArrayErrorMask = NotFound | HasLinkIndex,

        /* these flags are set and cleared by GetVariable */

        /// <summary>
        /// Combination mask of the flags set and cleared by GetVariable,
        /// made up of <see cref="ArrayErrorMask" /> and <see
        /// cref="WasVirtual" />.
        /// </summary>
        ErrorMask = ArrayErrorMask | WasVirtual,

        /* flags for maximum performance at the expense of everything else */

        /// <summary>
        /// Combination mask used for maximum performance at the expense of
        /// everything else, made up of <see cref="NoWatchpoint" />, <see
        /// cref="NoTrace" />, <see cref="NoNotify" />, and <see
        /// cref="NoPostProcess" />.
        /// </summary>
        FastMask = NoWatchpoint | NoTrace | NoNotify |
                   NoPostProcess,

        /// <summary>
        /// Combination mask used for fast variable tracing, made up of
        /// <see cref="NoWatchpoint" />, <see cref="NoNotify" />, and <see
        /// cref="NoPostProcess" />.
        /// </summary>
        FastTraceMask = NoWatchpoint | NoNotify | NoPostProcess,

        /* flags for use by [unset -zerostring] / [unset -maybezerostring] */

#if !MONO && NATIVE && WINDOWS
        /// <summary>
        /// Combination mask used by <c>[unset -zerostring]</c> and
        /// <c>[unset -maybezerostring]</c>, made up of <see
        /// cref="ResetValue" /> and <see cref="ZeroString" />.
        /// </summary>
        ZeroStringMask = ResetValue | ZeroString,
#endif

        /* flags for use with the "null" variable only. */

        /// <summary>
        /// Combination mask used for the "null" variable only, made up of
        /// <see cref="ReadOnly" /> and <see cref="Invariant" />.
        /// </summary>
        NullMask = ReadOnly | Invariant,

        /* flags for use by [namespace which] */

        /// <summary>
        /// Combination mask used by <c>[namespace which]</c>, made up of
        /// <see cref="NoElement" /> and <see cref="Defined" />.
        /// </summary>
        NamespaceWhichMask = NoElement | Defined,
        /// <summary>
        /// Combination mask used by <c>[namespace which]</c> at global
        /// scope, made up of <see cref="GlobalOnly" /> and <see
        /// cref="NamespaceWhichMask" />.
        /// </summary>
        GlobalNamespaceWhichMask = GlobalOnly | NamespaceWhichMask,

        /* non-instanced flags for maximum performance */

        /// <summary>
        /// Combination mask of the non-instanced flags used for maximum
        /// performance, made up of <see cref="NoSplit" />, <see
        /// cref="SkipWatchpoint" />, <see cref="SkipTrace" />, <see
        /// cref="SkipNotify" />, and <see cref="SkipPostProcess" />.
        /// </summary>
        FastNonInstanceMask = NoSplit | SkipWatchpoint | SkipTrace |
                              SkipNotify | SkipPostProcess,

        /// <summary>
        /// Combination mask of the non-instanced flags used for fast
        /// tracing, made up of <see cref="NoSplit" />, <see
        /// cref="SkipWatchpoint" />, <see cref="SkipNotify" />, and <see
        /// cref="SkipPostProcess" />.
        /// </summary>
        FastNonInstanceTraceMask = NoSplit | SkipWatchpoint | SkipNotify |
                                   SkipPostProcess
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that describe the kind,
    /// ownership, and special handling of a call frame on the
    /// interpreter's call stack.  Because it is a <c>[Flags]</c>
    /// enumeration, individual values may be combined together using a
    /// bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("8ed86944-4396-4106-ae22-6c0a0e95c7fc")]
    public enum CallFrameFlags : ulong
    {
        /// <summary>
        /// No special handling applies to the call frame.
        /// </summary>
        None = 0x0,                  /* No special handling. */
        /// <summary>
        /// A reserved sentinel value that is invalid and should not be
        /// used.
        /// </summary>
        Invalid = 0x1,               /* Invalid, do not use. */
        /// <summary>
        /// This call frame is being used for a core script library
        /// procedure.
        /// </summary>
        Library = 0x2,               /* This call frame is being used for a
                                      * core script library procedure. */
        /// <summary>
        /// This call frame should not be freed via the Free() method
        /// unless the "global" parameter is true.  This flag may be set or
        /// unset by the resolver.
        /// </summary>
        NoFree = 0x8,                /* This call frame should not be freed
                                      * via the Free() method unless the
                                      * "global" parameter is true.  This
                                      * flag may be set or unset by the
                                      * resolver. */
        /// <summary>
        /// Indicates a call frame that was pushed by the engine.
        /// </summary>
        Engine = 0x10,               /* Used to indicate a call frame pushed
                                      * by the engine. */
        /// <summary>
        /// Indicates the outermost call frame.
        /// </summary>
        Global = 0x20,               /* Used to indicate the outermost call
                                      * frame. */
        /// <summary>
        /// Used to support the <c>[scope global]</c> sub-command and its
        /// associated code.
        /// </summary>
        GlobalScope = 0x40,          /* Used for supporting the [scope global]
                                      * sub-command and its associated code. */
        /// <summary>
        /// Used when a procedure body is being evaluated.
        /// </summary>
        Procedure = 0x80,            /* Used when a procedure body is being
                                      * evaluated. */
        /// <summary>
        /// Used for the <c>[after]</c> command.
        /// </summary>
        After = 0x100,               /* Used for the [after] command. */
        /// <summary>
        /// Used for the <c>[uplevel]</c> command.
        /// </summary>
        Uplevel = 0x200,             /* Used for the [uplevel] command. */
        /// <summary>
        /// Used for the <c>[downlevel]</c> command.
        /// </summary>
        Downlevel = 0x400,           /* Used for the [downlevel] command. */
        /// <summary>
        /// Used for the <c>[apply]</c> command.
        /// </summary>
        Lambda = 0x800,              /* Used for the [apply] command. */
        /// <summary>
        /// Used for the <c>[namespace]</c> command.
        /// </summary>
        Namespace = 0x1000,          /* Used for the [namespace] command. */
        /// <summary>
        /// Used for the <c>[scope]</c> command.
        /// </summary>
        Scope = 0x2000,              /* Used for the [scope] command. */
        /// <summary>
        /// Used for the <c>[debug lockeval]</c>, <c>[eval]</c>, <c>[interp
        /// eval]</c>, and <c>[namespace eval]</c> commands as well as the
        /// -locked option to the <c>[vwait]</c> command.
        /// </summary>
        Evaluate = 0x4000,           /* Used for the [debug lockeval],
                                      * [eval], [interp eval], and
                                      * [namespace eval] commands as well
                                      * as the -locked option to the
                                      * [vwait] command. */
        /// <summary>
        /// Used for the <c>[namespace inscope]</c> command.
        /// </summary>
        InScope = 0x8000,            /* Used for the [namespace inscope]
                                      * command. */
        /// <summary>
        /// Used for the <c>[source]</c> command.
        /// </summary>
        Source = 0x10000,            /* Used for the [source] command. */
        /// <summary>
        /// Used for the <c>[subst]</c> command.
        /// </summary>
        Substitute = 0x20000,        /* Used for the [subst] command. */
        /// <summary>
        /// Used for the <c>[expr]</c> command.
        /// </summary>
        Expression = 0x40000,        /* Used for the [expr] command. */
        /// <summary>
        /// Used for the <c>[bgerror]</c> command.
        /// </summary>
        BackgroundError = 0x80000,   /* Used for the [bgerror] command. */
        /// <summary>
        /// Used for the <c>[try]</c> command.
        /// </summary>
        Try = 0x100000,              /* Used for the [try] command. */
        /// <summary>
        /// Used for the <c>[catch]</c> command.
        /// </summary>
        Catch = 0x200000,            /* Used for the [catch] command. */
        /// <summary>
        /// Used for the <c>[interp]</c> command.
        /// </summary>
        Interpreter = 0x400000,      /* Used for the [interp] command. */
        /// <summary>
        /// Used for the <c>[test1]</c> and <c>[test2]</c> commands and the
        /// dedicated test class.
        /// </summary>
        Test = 0x800000,             /* Used for the [test1] / [test2]
                                      * commands and the dedicated test
                                      * class. */
        /// <summary>
        /// Used for interactive extension command execution.
        /// </summary>
        Interactive = 0x1000000,     /* Used for interactive extension
                                      * command execution. */
        /// <summary>
        /// Used for aliases.
        /// </summary>
        Alias = 0x2000000,           /* Used for aliases. */
        /// <summary>
        /// Used for the finally block of a <c>[try]</c> command.
        /// </summary>
        Finally = 0x4000000,         /* Used for the finally block of a
                                      * [try] command. */
        /// <summary>
        /// The script or file is being evaluated via Tcl.
        /// </summary>
        Tcl = 0x8000000,             /* The script or file is being
                                      * evaluated via Tcl. */
        /// <summary>
        /// Indicates the frame is for executing commands from external
        /// components (i.e. those outside of the engine).
        /// </summary>
        External = 0x10000000,       /* Used to indicate the frame is for
                                      * executing commands from external
                                      * components (i.e. those outside of
                                      * the engine). */
        /// <summary>
        /// Indicates the frame is for tracking purposes.
        /// </summary>
        Tracking = 0x20000000,       /* Used to indicate the frame is for
                                      * tracking purposes. */
        /// <summary>
        /// Indicates the frame points to a namespace with variables in the
        /// call frame owned by that namespace.
        /// </summary>
        UseNamespace = 0x40000000,   /* Used to indicate the frame points to
                                      * a namespace with variables in the
                                      * call frame owned by that namespace.
                                      */
        /// <summary>
        /// Indicates the frame should be skipped for <c>[uplevel]</c>.
        /// </summary>
        Invisible = 0x80000000,      /* Used to indicate the frame should be
                                      * skipped for [uplevel]. */
        /// <summary>
        /// Indicates the frame should be able to see other frames that
        /// have been marked as invisible (e.g. via <c>[info level]</c>).
        /// </summary>
        NoInvisible = 0x100000000,   /* Used to indicate the frame should be
                                      * able to see other frames that have
                                      * been marked as invisible (e.g. via
                                      * [info level]). */
        /// <summary>
        /// Used during call frame variable cleanup to indicate that all
        /// variables belonging to the call frame are now undefined.
        /// </summary>
        Undefined = 0x200000000,     /* Used in call frame variable cleanup,
                                      * indicates that all variables
                                      * belonging to the call frame are now
                                      * undefined. */
        /// <summary>
        /// Used exclusively by the engine code to detect call frames that
        /// should be automatically popped upon exiting from the core
        /// execution routine.
        /// </summary>
        Automatic = 0x400000000,     /* This flag is used exclusively by the
                                      * engine code to detect call frames
                                      * that should be automatically popped
                                      * upon exiting from the core execution
                                      * routine. */
        /// <summary>
        /// This call frame disables variable tracing and other things
        /// (e.g. debug watches) that can potentially take a long time.
        /// </summary>
        Fast = 0x800000000,          /* This call frame disables variable
                                      * tracing and other things (e.g. debug
                                      * watches, etc) which can potentially
                                      * take a long time.*/
        /// <summary>
        /// Used for special sub-command execution.
        /// </summary>
        SubCommand = 0x1000000000,   /* Used for special sub-command execution.
                                      */
        /// <summary>
        /// Used for special command execution.
        /// </summary>
        Command = 0x2000000000,      /* Used for special command execution. */
        /// <summary>
        /// Used by the script debugger.
        /// </summary>
        Debugger = 0x4000000000,     /* Used by the script debugger. */
        /// <summary>
        /// Special restrictions are applied to evaluated scripts; some
        /// scripts may not work.
        /// </summary>
        Restricted = 0x8000000000,   /* Special restrictions are applied to
                                      * evaluated scripts, some scripts may
                                      * not work. */
        /// <summary>
        /// Variables within this call frame can only accept new values
        /// that have the same basic type.
        /// </summary>
        MatchTypes = 0x10000000000,  /* Variables within this call frame can
                                      * only accept new values that have the
                                      * same basic type. */
        /// <summary>
        /// A reserved application-defined flag.
        /// </summary>
        Application = 0x20000000000, /* Reserved application-defined flag. */
        /// <summary>
        /// A reserved user-defined flag.
        /// </summary>
        User = 0x40000000000,        /* Reserved user-defined flag. */

        /* these flags are toggled when marking/unmarking global scope frames */

        /// <summary>
        /// Combination mask toggled when marking or unmarking global scope
        /// frames, made up of <see cref="NoFree" /> and <see
        /// cref="GlobalScope" />.
        /// </summary>
        GlobalScopeMask = NoFree | GlobalScope,

        /* these frame types MAY "own" variables */

        /// <summary>
        /// Combination mask of the frame types that may "own" variables,
        /// namely <see cref="Global" />, <see cref="Procedure" />, <see
        /// cref="Lambda" />, <see cref="Namespace" />, <see cref="Scope"
        /// />, and <see cref="GlobalScope" />.
        /// </summary>
        Variables = Global | Procedure | Lambda | Namespace | Scope | GlobalScope,

        /* these frame types MAY be counted for [info level] */

        /// <summary>
        /// Combination mask of the frame types that may be counted for
        /// <c>[info level]</c>, derived from <see cref="Variables" /> with
        /// <see cref="Global" />, <see cref="GlobalScope" />, and <see
        /// cref="Lambda" /> removed.
        /// </summary>
        InfoLevel = Variables & ~(Global | GlobalScope | Lambda),

        /* these frame types MAY NOT "own" variables */

        /// <summary>
        /// Combination mask of the frame types that may not "own"
        /// variables, namely <see cref="Engine" /> and <see
        /// cref="Tracking" />.
        /// </summary>
        NoVariables = Engine | Tracking
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control which categories of
    /// information are included when generating detailed diagnostic and
    /// status output for an interpreter and its various subsystems.
    /// Because it is a [Flags] enumeration, multiple values may be
    /// combined together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("35136e42-f080-484a-9e4f-871888d49e2b")]
    public enum DetailFlags : ulong
    {
        /// <summary>
        /// No detail flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid set of detail flags;
        /// it should not be used.
        /// </summary>
        Invalid = 0x1,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Emit section headers even when the corresponding section has no
        /// content.
        /// </summary>
        EmptySection = 0x2,
        /// <summary>
        /// Emit content entries even when they are empty.
        /// </summary>
        EmptyContent = 0x4,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include additional, verbose section headers in the generated
        /// output.
        /// </summary>
        VerboseSection = 0x8,
        /// <summary>
        /// Include additional, verbose content in the generated output.
        /// </summary>
        VerboseContent = 0x10,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// When describing an ICallFrame, include only its name rather
        /// than its full details.
        /// </summary>
        ICallFrameNameOnly = 0x20,
        /// <summary>
        /// When describing an ICallFrame, include all of its details,
        /// formatted as a list.
        /// </summary>
        ICallFrameToListAll = 0x40,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include information about call frames that are linked to other
        /// call frames.
        /// </summary>
        CallFrameLinked = 0x80,
        /// <summary>
        /// Include information about special (non-procedure) call frames.
        /// </summary>
        CallFrameSpecial = 0x100,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include the variables contained within each call frame.
        /// </summary>
        CallFrameVariables = 0x200,
        /// <summary>
        /// Include every frame of the call stack, not just the active one.
        /// </summary>
        CallStackAllFrames = 0x400,
        /// <summary>
        /// Include information about the configured script debugger
        /// breakpoints.
        /// </summary>
        DebuggerBreakpoints = 0x800,
        /// <summary>
        /// Include the host's reported screen and buffer dimensions.
        /// </summary>
        HostDimensions = 0x1000,
        /// <summary>
        /// Include the host's text formatting capabilities.
        /// </summary>
        HostFormatting = 0x2000,
        /// <summary>
        /// Include the host's color settings.
        /// </summary>
        HostColors = 0x4000,
        /// <summary>
        /// Include the names associated with the host.
        /// </summary>
        HostNames = 0x8000,
        /// <summary>
        /// Include the current state of the host.
        /// </summary>
        HostState = 0x10000,
        /// <summary>
        /// Include information about the engine's native (unmanaged)
        /// integration.
        /// </summary>
        EngineNative = 0x20000,
        /// <summary>
        /// Include cached tracing information.
        /// </summary>
        TraceCached = 0x40000,
        /// <summary>
        /// Include information about variable links (e.g. those created by
        /// upvar or global).
        /// </summary>
        VariableLinks = 0x80000,
        /// <summary>
        /// Include information about active array searches.
        /// </summary>
        VariableSearches = 0x100000,
        /// <summary>
        /// Include the individual elements of array variables.
        /// </summary>
        VariableElements = 0x200000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include detail about exceptions raised because the interpreter
        /// was disposed.
        /// </summary>
        InterpreterDisposedException = 0x400000,
        /// <summary>
        /// Include detail about the list operations subsystem.
        /// </summary>
        ListOps = 0x800000,
        /// <summary>
        /// Include detail about command callbacks.
        /// </summary>
        CommandCallback = 0x1000000,
        /// <summary>
        /// Include detail about command callback wrappers.
        /// </summary>
        CommandCallbackWrapper = 0x2000000,
        /// <summary>
        /// Include detail about parser operations data.
        /// </summary>
        ParserOpsData = 0x4000000,
        /// <summary>
        /// Include detail about the engine thread.
        /// </summary>
        EngineThread = 0x8000000,
        /// <summary>
        /// Include detail about factory operations.
        /// </summary>
        FactoryOps = 0x10000000,
        /// <summary>
        /// Include detail about hashing operations.
        /// </summary>
        HashOps = 0x20000000,
        /// <summary>
        /// Include detail about process operations.
        /// </summary>
        ProcessOps = 0x40000000,
        /// <summary>
        /// Include detail about thread operations.
        /// </summary>
        ThreadOps = 0x80000000,
        /// <summary>
        /// Include detail about setup operations.
        /// </summary>
        SetupOps = 0x100000000,
        /// <summary>
        /// Include detail about tracing operations.
        /// </summary>
        TraceOps = 0x200000000,
        /// <summary>
        /// Include detail about the configured trace limits.
        /// </summary>
        TraceLimits = 0x400000000,
        /// <summary>
        /// Include detail about script operations.
        /// </summary>
        ScriptOps = 0x800000000,
        /// <summary>
        /// Include detail about exceptions raised during script
        /// evaluation.
        /// </summary>
        ScriptException = 0x1000000000,
        /// <summary>
        /// Include detail about syntax operations.
        /// </summary>
        SyntaxOps = 0x2000000000,
        /// <summary>
        /// Include detail about configuration operations.
        /// </summary>
        ConfigurationOps = 0x4000000000,
        /// <summary>
        /// Include detail about the test operations subsystem.
        /// </summary>
        TestOps = 0x8000000000,
#if WINFORMS
        /// <summary>
        /// Include detail about the Windows Forms status form operations.
        /// </summary>
        StatusFormOps = 0x10000000000,
#endif
#if ARGUMENT_CACHE || LIST_CACHE || PARSE_CACHE || TYPE_CACHE || COM_TYPE_CACHE
        /// <summary>
        /// Include detail about the configuration of the various caches.
        /// </summary>
        CacheConfiguration = 0x20000000000,
#if NATIVE
        /// <summary>
        /// Include detail about cache configuration related to native
        /// memory load.
        /// </summary>
        CacheConfigurationMemoryLoad = 0x40000000000,
#endif
#endif
#if NATIVE && WINDOWS
        /// <summary>
        /// Include detail about the native Windows console integration.
        /// </summary>
        NativeConsole = 0x80000000000,
#endif
#if DEBUGGER
        /// <summary>
        /// Include detail about the script debugger.
        /// </summary>
        Debugger = 0x100000000000,
#endif
#if NATIVE && TCL && NATIVE_PACKAGE
        /// <summary>
        /// Include detail about the native Tcl package integration.
        /// </summary>
        NativePackage = 0x200000000000,
#endif
#if NATIVE && NATIVE_UTILITY
        /// <summary>
        /// Include detail about the native utility library integration.
        /// </summary>
        NativeUtility = 0x400000000000,
#endif
#if NATIVE
        /// <summary>
        /// Include detail about native stack checking.
        /// </summary>
        NativeStack = 0x800000000000,
#endif
#if XML
        /// <summary>
        /// Include detail about XML script operations.
        /// </summary>
        ScriptXmlOps = 0x1000000000000,
#endif
#if TEST
        /// <summary>
        /// Include detail about exceptions captured during tracing.
        /// </summary>
        TraceException = 0x2000000000000,
#endif
#if NETWORK
        /// <summary>
        /// Include detail about network and web operations.
        /// </summary>
        WebOps = 0x4000000000000,
        /// <summary>
        /// Include detail about socket operations.
        /// </summary>
        SocketOps = 0x8000000000000,
#endif
        /// <summary>
        /// Include detail about array operations.
        /// </summary>
        ArrayOps = 0x10000000000000,
        /// <summary>
        /// Include detail about path operations.
        /// </summary>
        PathOps = 0x20000000000000,
        /// <summary>
        /// Include detail about host operations.
        /// </summary>
        HostOps = 0x40000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include information about the current thread.
        /// </summary>
        ThreadInfo = 0x80000000000000,
#if HISTORY
        /// <summary>
        /// Include command history information.
        /// </summary>
        HistoryInfo = 0x100000000000000,
#endif
#if ARGUMENT_CACHE || LIST_CACHE || PARSE_CACHE || EXECUTE_CACHE || TYPE_CACHE || COM_TYPE_CACHE
        /// <summary>
        /// Include information about the list cache.
        /// </summary>
        ListCacheInfo = 0x200000000000000,
#endif
#if (CACHE_ARGUMENTLIST_TOSTRING || CACHE_STRINGLIST_TOSTRING) && CACHE_STATISTICS
        /// <summary>
        /// Include statistics about the string cache.
        /// </summary>
        StringCacheInfo = 0x400000000000000,
#endif
        /// <summary>
        /// Include information about the certificate cache.
        /// </summary>
        CertificateCacheInfo = 0x800000000000000,
        /// <summary>
        /// Include information about the StringBuilder cache.
        /// </summary>
        StringBuilderCacheInfo = 0x1000000000000000,
        /// <summary>
        /// Include information about the StringBuilder factory.
        /// </summary>
        StringBuilderFactoryInfo = 0x2000000000000000,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Include extra information that is only useful when debugging.
        /// </summary>
        Debug = 0x4000000000000000,
        /// <summary>
        /// Indicates that the detail flags have been explicitly set by the
        /// user rather than defaulted.
        /// </summary>
        User = 0x8000000000000000,      /* Indicates that the detail flags have been explicitly
                                         * set by the user. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask covering all of the per-subsystem section
        /// flags, ranging from <see cref="InterpreterDisposedException" />
        /// through <see cref="HostOps" />.
        /// </summary>
        SectionMask = InterpreterDisposedException | ListOps |
                      CommandCallback | CommandCallbackWrapper | ParserOpsData |
                      EngineThread | FactoryOps | HashOps | ProcessOps | ThreadOps |
                      SetupOps | TraceOps | TraceLimits | ScriptOps | SyntaxOps |
                      ConfigurationOps | TestOps | ScriptException |
#if WINFORMS
                      StatusFormOps |
#endif
#if ARGUMENT_CACHE || LIST_CACHE || PARSE_CACHE || TYPE_CACHE || COM_TYPE_CACHE
                      CacheConfiguration |
#if NATIVE
                      CacheConfigurationMemoryLoad |
#endif
#endif
#if NATIVE && WINDOWS
                      NativeConsole |
#endif
#if DEBUGGER
                      Debugger |
#endif
#if NATIVE && TCL && NATIVE_PACKAGE
                      NativePackage |
#endif
#if NATIVE && NATIVE_UTILITY
                      NativeUtility |
#endif
#if NATIVE
                      NativeStack |
#endif
#if XML
                      ScriptXmlOps |
#endif
#if TEST
                      TraceException |
#endif
#if NETWORK
                      WebOps | SocketOps |
#endif
                      ArrayOps | PathOps | HostOps,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="StringBuilderCacheInfo" /> and
        /// <see cref="StringBuilderFactoryInfo" />.
        /// </summary>
        StringBuilderMask = StringBuilderCacheInfo |
                            StringBuilderFactoryInfo,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of the extra-information flags, including <see
        /// cref="ThreadInfo" />, <see cref="CertificateCacheInfo" />, and
        /// <see cref="StringBuilderMask" />.
        /// </summary>
        ExtraInfoMask = ThreadInfo |
#if HISTORY
                        HistoryInfo |
#endif
#if ARGUMENT_CACHE || LIST_CACHE || PARSE_CACHE || EXECUTE_CACHE || TYPE_CACHE || COM_TYPE_CACHE
                        ListCacheInfo |
#endif
#if (CACHE_ARGUMENTLIST_TOSTRING || CACHE_STRINGLIST_TOSTRING) && CACHE_STATISTICS
                        StringCacheInfo |
#endif
                        CertificateCacheInfo |
                        StringBuilderMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ICallFrameNameOnly" /> and <see
        /// cref="ICallFrameToListAll" />.
        /// </summary>
        ICallFrameMask = ICallFrameNameOnly | ICallFrameToListAll,

        /// <summary>
        /// Combination mask of <see cref="CallFrameLinked" /> and <see
        /// cref="CallFrameSpecial" />.
        /// </summary>
        CallFrameMask = CallFrameLinked | CallFrameSpecial,

        /// <summary>
        /// Combination mask of <see cref="EmptySection" /> and <see
        /// cref="EmptyContent" />.
        /// </summary>
        EmptyMask = EmptySection | EmptyContent,

        /// <summary>
        /// Combination mask of <see cref="VerboseSection" /> and <see
        /// cref="VerboseContent" />.
        /// </summary>
        VerboseMask = VerboseSection | VerboseContent,

        /// <summary>
        /// Combination mask of the content-detail flags, including <see
        /// cref="CallFrameVariables" />, <see cref="CallStackAllFrames"
        /// />, and the various host and variable flags.
        /// </summary>
        ContentMask = CallFrameVariables | CallStackAllFrames | DebuggerBreakpoints |
                      HostDimensions | HostFormatting | HostColors |
                      HostNames | HostState | EngineNative | TraceCached |
                      VariableLinks | VariableSearches | VariableElements,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="EmptyContent" /> and <see
        /// cref="VerboseContent" /> appropriate for script-only contexts.
        /// </summary>
        ScriptOnly = EmptyContent | VerboseContent,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="EmptyContent" /> and <see
        /// cref="VerboseContent" /> used when emitting debug trace output.
        /// </summary>
        DebugTrace = EmptyContent | VerboseContent,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination of <see cref="EmptyContent" /> and <see
        /// cref="VerboseContent" /> used in interactive-only contexts.
        /// </summary>
        InteractiveOnly = EmptyContent | VerboseContent,
        /// <summary>
        /// Combination of <see cref="EmptyContent" />, <see
        /// cref="VerboseContent" />, and <see cref="ContentMask" /> used
        /// for full interactive output.
        /// </summary>
        InteractiveAll = EmptyContent | VerboseContent | ContentMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="EmptyMask" />, <see
        /// cref="VerboseMask" />, <see cref="ContentMask" />, <see
        /// cref="SectionMask" />, and <see cref="ExtraInfoMask" />.
        /// </summary>
        All = EmptyMask | VerboseMask | ContentMask | SectionMask | ExtraInfoMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The standard set of detail flags; equal to <see
        /// cref="InteractiveAll" />.
        /// </summary>
        Standard = InteractiveAll,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The default detail flags; equal to <see cref="None" />.
        /// </summary>
        Default = None
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that control how an enumerated
    /// (or similar) value is formatted as a string.  Because it is a
    /// [Flags] enumeration, multiple values may be combined together using
    /// a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("f3d19d7d-e026-435b-9a1b-3ac2dd969fc6")]
    public enum ToStringFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Format the value using both its name and its numeric value.
        /// </summary>
        NameAndValue = 0x2,
        /// <summary>
        /// Format the value using its name and, when applicable, its
        /// default value.
        /// </summary>
        NameAndDefault = 0x4,
        /// <summary>
        /// Produce a decorated string representation.
        /// </summary>
        Decorated = 0x8,
        /// <summary>
        /// A reserved value that should not be used.
        /// </summary>
        Reserved = unchecked((int)0x80000000)
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that describe the properties of
    /// a script result and control how results are copied, reset, and
    /// cloned.  Because it is a [Flags] enumeration, multiple values may
    /// be combined together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("87619eee-2103-4488-a2ce-59cc8d94059e")]
    public enum ResultFlags : ulong
    {
        /// <summary>
        /// No extra flags are set.
        /// </summary>
        None = 0x0,                     /* No extra flags. */
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,                  /* Invalid, do not use. */
        /// <summary>
        /// Reserved; do not use.
        /// </summary>
        Reserved1 = 0x2,                /* Reserved, do not use. */
        /// <summary>
        /// The result is globally scoped.
        /// </summary>
        Global = 0x4,                   /* The result is globally scoped? */
        /// <summary>
        /// The result is locally scoped.
        /// </summary>
        Local = 0x8,                    /* The result is locally scoped? */
        /// <summary>
        /// The result is a string (currently always true).
        /// </summary>
        String = 0x10,                  /* Result is a string (always true for now) */
        /// <summary>
        /// The result carries an associated exception instance.
        /// </summary>
        Exception = 0x20,               /* The result has an exception instance */
        /// <summary>
        /// The result carries error information.
        /// </summary>
        Error = 0x40,                   /* The result has error information? */
        /// <summary>
        /// An application-defined flag.
        /// </summary>
        Application = 0x80,             /* Application-defined flag. */
        /// <summary>
        /// A user-defined flag.
        /// </summary>
        User = 0x100,                   /* User-defined flag. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// When cloning, also copy the client data, if any.
        /// </summary>
        ClientData = 0x1000,            /* When cloning, copy the client data, if
                                         * any. */
        /// <summary>
        /// When cloning, also copy the value data, if any.
        /// </summary>
        ValueData = 0x2000,             /* When cloning, copy the value data, if
                                         * any. */
        /// <summary>
        /// When cloning, also copy the extra data, if any.
        /// </summary>
        ExtraData = 0x4000,             /* When cloning, copy the extra data, if
                                         * any. */
        /// <summary>
        /// When cloning, also copy the call frame, if any.
        /// </summary>
        CallFrame = 0x8000,             /* When cloning, copy the call frame, if
                                         * any. */
        /// <summary>
        /// When cloning, also copy the engine data, if any.
        /// </summary>
        EngineData = 0x10000,           /* When cloning, copy the engine data, if
                                         * any. */
        /// <summary>
        /// When cloning, also copy the stack trace, if any.
        /// </summary>
        StackTrace = 0x20000,           /* When cloning, copy the stack trace, if
                                         * any. */
        /// <summary>
        /// When cloning, use the new value even when the source and
        /// destination types do not match.
        /// </summary>
        IgnoreType = 0x40000,           /* When cloning, use new value even if the
                                         * types do not match. */
        /// <summary>
        /// When cloning, also copy the full string, if any.
        /// </summary>
        FullString = 0x80000,           /* When cloning, copy the full string, if
                                         * any. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Used by the ResultList class.
        /// </summary>
        ForList = 0x100000,             /* Used for the ResultList class. */
        /// <summary>
        /// Used by the Copy methods.
        /// </summary>
        ForCopy = 0x200000,             /* Used for the Copy methods. */
        /// <summary>
        /// Used by the Result reset methods.
        /// </summary>
        ForReset = 0x400000,            /* Used for the Result methods. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// ResultList only: when adding a nested ResultList, add it as a
        /// range of values rather than as a single value.
        /// </summary>
        AddRange = 0x1000000,           /* ResultList only: when adding a nested
                                         * ResultList, add as a range of values,
                                         * not as a single value. */
        /// <summary>
        /// ResultList only: when adding a nested ResultList, add it as a
        /// single value rather than as a range of values.
        /// </summary>
        NoAddRange = 0x2000000,         /* ResultList only: when adding a nested
                                         * ResultList, add as a single value, not
                                         * as a range of values. */
        /// <summary>
        /// ResultList only: collapse zero- and one-element lists into an
        /// empty string or the single element itself.
        /// </summary>
        Squash = 0x4000000,             /* ResultList only: collapse zero and one
                                         * element lists into empty string and/or
                                         * just the element itself. */
        /// <summary>
        /// ResultList only: the opposite of <see cref="Squash" />.
        /// </summary>
        NoSquash = 0x8000000,           /* ResultList only: opposite of Squash. */
        /// <summary>
        /// ResultList only: skip null values, null strings, and empty
        /// strings when converting the list to a string.
        /// </summary>
        SkipEmpty = 0x10000000,         /* ResultList only: skip null values, null
                                         * strings, and empty string values when
                                         * converting the list of a string. */
        /// <summary>
        /// ResultList only: the opposite of <see cref="SkipEmpty" />.
        /// </summary>
        NoSkipEmpty = 0x20000000,       /* ResultList only: opposite of SkipEmpty. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Permit the associated argument to be null even when the
        /// NoNullArgument flag has been set.
        /// </summary>
        ForceNullArgument = 0x40000000, /* The script engine should permit the
                                         * associated argument to be null, even if
                                         * the NoNullArgument flag has been set. */
        /// <summary>
        /// Transform this result into a null result object.
        /// </summary>
        ForceNullResult = 0x80000000,   /* The script engine should transform this
                                         * result into a null result object. */

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Squash" />, <see
        /// cref="SkipEmpty" />, and <see cref="ForList" />.
        /// </summary>
        CompactListMask = Squash | SkipEmpty | ForList,
        /// <summary>
        /// Combination mask of <see cref="NoSquash" />, <see
        /// cref="NoSkipEmpty" />, and <see cref="ForList" />.
        /// </summary>
        FullListMask = NoSquash | NoSkipEmpty | ForList,
        /// <summary>
        /// Combination mask of <see cref="None" /> and <see cref="ForList"
        /// />.
        /// </summary>
        DefaultListMask = None | ForList,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="Error" />, <see
        /// cref="StackTrace" />, and <see cref="FullString" />.
        /// </summary>
        Complaint = Error | StackTrace | FullString,
        /// <summary>
        /// Combination mask of <see cref="EngineData" />, <see
        /// cref="StackTrace" />, and <see cref="FullString" />.
        /// </summary>
        InternalMask = EngineData | StackTrace | FullString,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="String" />, <see cref="Error"
        /// />, <see cref="ClientData" />, <see cref="ValueData" />, <see
        /// cref="ExtraData" />, <see cref="CallFrame" />, and <see
        /// cref="InternalMask" />.
        /// </summary>
        AllMask = String | Error | ClientData |
                  ValueData | ExtraData | CallFrame |
                  InternalMask,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="String" /> and <see
        /// cref="ForCopy" />.
        /// </summary>
        CopyValue = String | ForCopy,
        /// <summary>
        /// Combination mask of <see cref="Error" /> and <see
        /// cref="ForCopy" />.
        /// </summary>
        CopyError = Error | ForCopy,
        /// <summary>
        /// Combination mask of <see cref="String" />, <see cref="Error"
        /// />, and <see cref="ForCopy" />.
        /// </summary>
        CopyObject = String | Error | ForCopy,
        /// <summary>
        /// Combination mask of <see cref="AllMask" /> and <see
        /// cref="ForCopy" />.
        /// </summary>
        CopyAll = AllMask | ForCopy,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="String" /> and <see
        /// cref="ForReset" />.
        /// </summary>
        ResetValue = String | ForReset,
        /// <summary>
        /// Combination mask of <see cref="Error" /> and <see
        /// cref="ForReset" />.
        /// </summary>
        ResetError = Error | ForReset,
        /// <summary>
        /// Combination mask of <see cref="String" />, <see cref="Error"
        /// />, and <see cref="ForReset" />.
        /// </summary>
        ResetObject = String | Error | ForReset,
        /// <summary>
        /// Combination mask of <see cref="AllMask" /> and <see
        /// cref="ForReset" />.
        /// </summary>
        ResetAll = AllMask | ForReset,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of <see cref="ForceNullArgument" /> and <see
        /// cref="ForceNullResult" />.
        /// </summary>
        ForceNullMask = ForceNullArgument | ForceNullResult,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved value that should not be used.
        /// </summary>
        Reserved = 0x8000000000000000
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines bit flags that describe the properties of
    /// a command or procedure argument and control how it is formatted as
    /// a string.  Because it is a [Flags] enumeration, multiple values may
    /// be combined together using a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("ca16c0e6-08b0-414d-9c1b-d09af3d98a7c")]
    public enum ArgumentFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid value; it should not
        /// be used.
        /// </summary>
        Invalid = 0x1,        // invalid, do not use.
        /// <summary>
        /// Reserved; do not use.
        /// </summary>
        Reserved1 = 0x2,      // reserved, do not use.
        /// <summary>
        /// Reserved for argument expansion; this is not implemented.
        /// </summary>
        Expand = 0x4,         // NOT IMPLEMENTED
        /// <summary>
        /// The argument has a default value.
        /// </summary>
        HasDefault = 0x8,     // argument has a default value.
        /// <summary>
        /// The argument is a named argument (e.g. as used by
        /// <c>[nproc]</c> and <c>[napply]</c>).
        /// </summary>
        Named = 0x10,         // named argument, e.g. [nproc], [napply], etc.
        /// <summary>
        /// When the argument has no default value, include both its name
        /// and value when performing ToString().
        /// </summary>
        WithName = 0x20,      // if no default value, argument should use name and value
                              // when doing ToString().
        /// <summary>
        /// The argument belongs to the call frame only.
        /// </summary>
        FrameOnly = 0x40,     // argument belongs to the frame.
        /// <summary>
        /// The argument is part of an "args" argument list.
        /// </summary>
        List = 0x80,          // argument is part of an "args" argument list.
        /// <summary>
        /// The argument should include both its name and value when
        /// performing ToString().
        /// </summary>
        Debug = 0x100,        // argument should use name and value when doing ToString().
        /// <summary>
        /// The argument should include only its name when performing
        /// ToString().
        /// </summary>
        NameOnly = 0x200,     // argument should use name only when doing ToString().
        /// <summary>
        /// An application-defined flag.
        /// </summary>
        Application = 0x400,  // application-defined flag.
        /// <summary>
        /// A user-defined flag.
        /// </summary>
        User = 0x800,         // user-defined flag.

        /// <summary>
        /// Force fields to zero instead of using their default values.
        /// </summary>
        Zero = 0x10000,       // force zero for fields instead of using default values.

        /// <summary>
        /// Reset the argument using its default values; equal to <see
        /// cref="Reserved1" />.
        /// </summary>
        ResetWithDefault = Reserved1,
        /// <summary>
        /// Reset the argument using zeroed fields; combination of <see
        /// cref="Reserved1" /> and <see cref="Zero" />.
        /// </summary>
        ResetWithZero = Reserved1 | Zero,

        /// <summary>
        /// A reserved value that should not be used.
        /// </summary>
        Reserved = unchecked((int)0x80000000),

        /// <summary>
        /// Combination mask of the flags that affect ToString(): <see
        /// cref="Debug" /> and <see cref="NameOnly" />.
        /// </summary>
        ToStringMask = Debug | NameOnly /* flags that impact ToString(). */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY || NOTIFY_OBJECT
    /// <summary>
    /// This enumeration identifies the category of entity or subsystem to
    /// which a notification event pertains.  Because it is a [Flags]
    /// enumeration, multiple values may be combined together using a
    /// bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("0c443008-9aec-477d-ab7a-894ad71e4acb")]
    public enum NotifyType : ulong
    {
        /// <summary>
        /// A reserved value that represents a null event; no notification
        /// type is set.
        /// </summary>
        None = 0x0,                    /* This is a reserved event value that represents a null
                                        * event. */
        /// <summary>
        /// The value that represents an invalid event.
        /// </summary>
        Invalid = 0x1,                 /* The value that represents an invalid event. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Types
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// The event pertains to an IInterpreter object.
        /// </summary>
        Interpreter = 0x2,             /* The event pertains to an IInterpreter object. */
        /// <summary>
        /// The event pertains to an ICallFrame object.
        /// </summary>
        CallFrame = 0x4,               /* The event pertains to an ICallFrame object. */
        /// <summary>
        /// The event pertains to the resolver (an abstract component).
        /// </summary>
        Resolver = 0x8,                /* The event pertains to the resolver (abstract component). */
        /// <summary>
        /// The event pertains to the engine (an abstract component).
        /// </summary>
        Engine = 0x10,                 /* The event pertains to the engine (abstract component). */
        /// <summary>
        /// The event pertains to a stream.
        /// </summary>
        Stream = 0x20,                 /* The event pertains to a stream. */
        /// <summary>
        /// The event pertains to a file.
        /// </summary>
        File = 0x40,                   /* The event pertains to a file. */

#if XML
        /// <summary>
        /// The event pertains to XML integration.
        /// </summary>
        Xml = 0x80,                    /* The event pertains to XML integration. */
        /// <summary>
        /// The event pertains to an XML script block.
        /// </summary>
        XmlBlock = 0x100,              /* The event pertains to an XML script block. */
#endif

        /// <summary>
        /// The event pertains to an expression.
        /// </summary>
        Expression = 0x200,            /* The event pertains to an expression. */
        /// <summary>
        /// The event pertains to a script.
        /// </summary>
        Script = 0x400,                /* The event pertains to a script. */
        /// <summary>
        /// The event pertains to a string.
        /// </summary>
        String = 0x800,                /* The event pertains to a string. */

#if DEBUGGER
        /// <summary>
        /// The event pertains to the script debugger (an abstract
        /// component).
        /// </summary>
        Debugger = 0x1000,             /* The event pertains to the script debugger (abstract
                                        * component). */
#endif

        /// <summary>
        /// The event pertains to an IVariable object.
        /// </summary>
        Variable = 0x2000,             /* The event pertains to an IVariable object. */
        /// <summary>
        /// The event pertains to an IAlias object.
        /// </summary>
        Alias = 0x4000,                /* The event pertains to an IAlias object. */
        /// <summary>
        /// The event pertains to an IExecute object.
        /// </summary>
        IExecute = 0x8000,             /* The event pertains to an IExecute object. */
        /// <summary>
        /// The event pertains to a hidden IExecute object.
        /// </summary>
        HiddenIExecute = 0x10000,      /* The event pertains to an IExecute object. */
        /// <summary>
        /// The event pertains to an IProcedure object.
        /// </summary>
        Procedure = 0x20000,           /* The event pertains to an IProcedure object. */
        /// <summary>
        /// The event pertains to a hidden IProcedure object.
        /// </summary>
        HiddenProcedure = 0x40000,     /* The event pertains to an IProcedure object. */
        /// <summary>
        /// The event pertains to an ICommand object.
        /// </summary>
        Command = 0x80000,             /* The event pertains to an ICommand object. */
        /// <summary>
        /// The event pertains to a hidden ICommand object.
        /// </summary>
        HiddenCommand = 0x100000,      /* The event pertains to an ICommand object. */
        /// <summary>
        /// The event pertains to an ISubCommand object.
        /// </summary>
        SubCommand = 0x200000,         /* The event pertains to an ISubCommand object. */
        /// <summary>
        /// The event pertains to an IOperator object.
        /// </summary>
        Operator = 0x400000,           /* The event pertains to an IOperator object. */
        /// <summary>
        /// The event pertains to an IFunction object.
        /// </summary>
        Function = 0x800000,           /* The event pertains to an IFunction object. */
        /// <summary>
        /// The event pertains to an IPlugin object.
        /// </summary>
        Plugin = 0x1000000,            /* The event pertains to an IPlugin object. */
        /// <summary>
        /// The event pertains to an IPackage object.
        /// </summary>
        Package = 0x2000000,           /* The event pertains to an IPackage object. */
        /// <summary>
        /// The event pertains to an IResolve object.
        /// </summary>
        Resolve = 0x4000000,           /* The event pertains to an IResolve object. */

#if DATA
        /// <summary>
        /// The event pertains to an IDbConnection object.
        /// </summary>
        Connection = 0x8000000,        /* The event pertains to an IDbConnection object. */
        /// <summary>
        /// The event pertains to an IDbTransaction object.
        /// </summary>
        Transaction = 0x10000000,      /* The event pertains to an IDbTransaction object. */
#endif

        /// <summary>
        /// The event pertains to an ICallback object.
        /// </summary>
        Callback = 0x20000000,         /* The event pertains to an ICallback object. */

#if EMIT && NATIVE && LIBRARY
        /// <summary>
        /// The event pertains to an IModule object.
        /// </summary>
        Module = 0x40000000,           /* The event pertains to an IModule object. */
        /// <summary>
        /// The event pertains to an IDelegate object.
        /// </summary>
        Delegate = 0x80000000,         /* The event pertains to an IDelegate object. */
#endif

        /// <summary>
        /// The event pertains to an idle IEvent object.
        /// </summary>
        Idle = 0x100000000,            /* The event pertains to an idle IEvent object. */
        /// <summary>
        /// The event pertains to an IEvent object.
        /// </summary>
        Event = 0x200000000,           /* The event pertains to an IEvent object. */
        /// <summary>
        /// The event pertains to an IObject object.
        /// </summary>
        Object = 0x400000000,          /* The event pertains to an IObject object. */

#if NATIVE && TCL
        /// <summary>
        /// The event pertains to Tcl integration.
        /// </summary>
        Tcl = 0x800000000,             /* The event pertains to Tcl integration. */
#endif

#if HISTORY
        /// <summary>
        /// The event pertains to command history.
        /// </summary>
        History = 0x1000000000,        /* The event pertains to command history. */
#endif

        /// <summary>
        /// The event pertains to a policy.
        /// </summary>
        Policy = 0x2000000000,         /* The event pertains to a policy. */
        /// <summary>
        /// The event pertains to a trace.
        /// </summary>
        Trace = 0x4000000000,          /* The event pertains to a trace. */

#if NATIVE && TCL && TCL_THREADS
        /// <summary>
        /// The event pertains to a thread.
        /// </summary>
        Thread = 0x8000000000,         /* The event pertains to a thread. */
#endif

#if APPDOMAINS
        /// <summary>
        /// The event pertains to an application domain.
        /// </summary>
        AppDomain = 0x10000000000,     /* The event pertains to an AppDomain. */
#endif

        /// <summary>
        /// The event pertains to the script library.
        /// </summary>
        Library = 0x20000000000,       /* The event pertains to the script library. */

#if SHELL
        /// <summary>
        /// The event pertains to the interactive shell.
        /// </summary>
        Shell = 0x40000000000,         /* The event pertains to the interactive shell. */
#endif

        /// <summary>
        /// The event pertains to a runtime option.
        /// </summary>
        RuntimeOption = 0x80000000000, /* The event pertains to a runtime option. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Masks
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Mask of the bits reserved for flags; equal to <see
        /// cref="Invalid" />.
        /// </summary>
        FlagsMask = Invalid,
        /// <summary>
        /// Mask used when validating notification types; equal to <see
        /// cref="All" />.
        /// </summary>
        CheckMask = All,

        ///////////////////////////////////////////////////////////////////////////////////////////
        // All
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the defined notification types,
        /// ranging from <see cref="Interpreter" /> through <see
        /// cref="RuntimeOption" />.
        /// </summary>
        All = Interpreter |
              CallFrame |
              Resolver |
              Engine |
              Stream |
              File |

#if XML
              Xml |
              XmlBlock |
#endif

              Expression |
              Script |
              String |

#if DEBUGGER
              Debugger |
#endif

              Variable |
              Alias |
              IExecute |
              HiddenIExecute |
              Procedure |
              HiddenProcedure |
              Command |
              HiddenCommand |
              SubCommand |
              Operator |
              Function |
              Plugin |
              Package |
              Resolve |

#if DATA
              Connection |
              Transaction |
#endif

              Callback |

#if EMIT && NATIVE && LIBRARY
              Module |
              Delegate |
#endif

              Idle |
              Event |
              Object |

#if NATIVE && TCL
              Tcl |
#endif

#if HISTORY
              History |
#endif

              Policy |
              Trace |

#if NATIVE && TCL && TCL_THREADS
              Thread |
#endif

#if APPDOMAINS
              AppDomain |
#endif

              Library |

#if SHELL
              Shell |
#endif

              RuntimeOption,

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Reserved
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved value that should not be used.
        /// </summary>
        Reserved = 0x8000000000000000 /* Reserved value, do not use. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the specific kind of notification event
    /// being delivered, covering entity lifecycle, engine core, debugger,
    /// asynchronous event, and input/output transitions.  Because it is a
    /// [Flags] enumeration, multiple values may be combined together using
    /// a bitwise OR.
    /// </summary>
    [Flags()]
    [ObjectId("17e7f251-9140-486f-83ad-5ef4d88c386f")]
    public enum NotifyFlags : ulong
    {
        /// <summary>
        /// A reserved value that represents a null event; no flags are
        /// set.
        /// </summary>
        None = 0x0,            /* This is a reserved event value that represents a null event. */
        /// <summary>
        /// The value that represents an invalid event.
        /// </summary>
        Invalid = 0x1,         /* The value that represents an invalid event. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Flags
        ///////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY || NOTIFY_OBJECT
        /// <summary>
        /// When set, all notifications are temporarily disabled.
        /// </summary>
        NoNotify = 0x2,        /* If this flag is set, ALL notifications are temporarily
                                * disabled. */
#endif

        /// <summary>
        /// An entity is hidden.
        /// </summary>
        Hidden = 0x4,          /* An entity is hidden. */
        /// <summary>
        /// The operation on the named entity was forced by the caller.
        /// </summary>
        Force = 0x8,           /* The operation on the named entity was forced by the caller. */
        /// <summary>
        /// The notification should be sent to all interpreters, regardless
        /// of their thread affinity.
        /// </summary>
        Broadcast = 0x10,      /* The notification should be sent to all interpreters, regardless
                                * of their thread affinity. */
        /// <summary>
        /// The notification may be sent to "safe" interpreters.
        /// </summary>
        Safe = 0x20,           /* The notification may be sent to "safe" interpreters. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Lifetime
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// An entity or subsystem has been reset.
        /// </summary>
        Reset = 0x40,          /* An entity or subsystem has been reset. */
        /// <summary>
        /// An interpreter entity has been pre-initialized.
        /// </summary>
        PreInitialized = 0x80, /* An entity has been initialized [interpreter]. */
        /// <summary>
        /// An interpreter entity has been set up.
        /// </summary>
        Setup = 0x100,         /* An entity has been setup [interpreter]. */
        /// <summary>
        /// An entity has been initialized.
        /// </summary>
        Initialized = 0x200,   /* An entity has been initialized (IState?). */
        /// <summary>
        /// An entity has been terminated.
        /// </summary>
        Terminated = 0x400,    /* An entity has been terminated (IState?). */
        /// <summary>
        /// The exit property of the interpreter was changed (the
        /// interpreter may be exiting).
        /// </summary>
        Exit = 0x800,          /* The exit property of the interpreter was changed (we may
                                * be exiting). */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Engine Entity
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A named entity has been located by the resolver.
        /// </summary>
        Matched = 0x1000,      /* A named entity has been located [by the resolver]. */
        /// <summary>
        /// A named entity could not be located by the resolver.
        /// </summary>
        NotFound = 0x2000,     /* A named entity could not be located [by the resolver]. */
        /// <summary>
        /// A named entity has been executed.
        /// </summary>
        Executed = 0x4000,     /* A named entity has been executed.*/
        /// <summary>
        /// An exception was caught while executing a named entity.
        /// </summary>
        Exception = 0x8000,    /* An exception has been caught while executing a named entity. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Interpreter Entity
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A named entity has been added to the interpreter or application
        /// domain.
        /// </summary>
        Added = 0x10000,      /* A named entity has been added [to the interpreter or AppDomain]. */
        /// <summary>
        /// A named entity has been copied to the interpreter or
        /// application domain.
        /// </summary>
        Copied = 0x20000,     /* A named entity has been copied [to the interpreter or AppDomain]. */
        /// <summary>
        /// A named entity has been renamed.
        /// </summary>
        Renamed = 0x40000,    /* A named entity has been renamed. */
        /// <summary>
        /// A named entity has been updated.
        /// </summary>
        Updated = 0x80000,    /* A named entity has been updated. */
        /// <summary>
        /// A named entity has been replaced.
        /// </summary>
        Replaced = 0x100000,  /* A named entity has been replaced. */
        /// <summary>
        /// A named entity has been removed from the interpreter or
        /// application domain.
        /// </summary>
        Removed = 0x200000,   /* A named entity has been removed [from the interpreter or AppDomain]. */
        /// <summary>
        /// A named entity has been pushed (interpreter or call frame).
        /// </summary>
        Pushed = 0x400000,    /* A named entity has been pushed [Interpreter or CallFrame]. */
        /// <summary>
        /// A named entity has been popped (interpreter or call frame).
        /// </summary>
        Popped = 0x800000,    /* A named entity has been popped [Interpreter or callFrame]. */
        /// <summary>
        /// A named entity has been deleted (call frame).
        /// </summary>
        Deleted = 0x1000000,  /* A named entity has been deleted [CallFrame]. */
        /// <summary>
        /// A named entity (object) has been disposed.
        /// </summary>
        Disposed = 0x2000000, /* A named entity has been disposed [object]. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Engine Core
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A string has been substituted.
        /// </summary>
        Substituted = 0x4000000,   /* A string has been substituted. */
        /// <summary>
        /// A script or expression has been evaluated.
        /// </summary>
        Evaluated = 0x8000000,     /* A script or expression has been evaluated. */
        /// <summary>
        /// A script or expression has been evaluated at the outermost
        /// level.
        /// </summary>
        Completed = 0x10000000,    /* A script or expression has been evaluated at the outermost
                                    * level. */
        /// <summary>
        /// A script or asynchronous event is about to be canceled.
        /// </summary>
        PreCanceled = 0x20000000,  /* A script or asynchronous event is about to be canceled. */
        /// <summary>
        /// A script or asynchronous event was canceled.
        /// </summary>
        Canceled = 0x40000000,     /* A script or asynchronous event was canceled. */
        /// <summary>
        /// A script or asynchronous event was unwound.
        /// </summary>
        Unwound = 0x80000000,      /* A script or asynchronous event was unwound. */
        /// <summary>
        /// A script is about to be halted; this is used primarily to
        /// unwind nested instances of the interactive loop.
        /// </summary>
        PreHalted = 0x100000000,   /* A script is about to be halted.  This is used primarily
                                    * [by the interactive user] to unwind nested instances of
                                    * the interactive loop. */
        /// <summary>
        /// A script was halted; this is used primarily to unwind nested
        /// instances of the interactive loop.
        /// </summary>
        Halted = 0x200000000,      /* A script was halted.  This is used primarily [by the
                                    * interactive user] to unwind nested instances of the
                                    * interactive loop. */
        /// <summary>
        /// A script was interrupted in some way.
        /// </summary>
        Interrupted = 0x400000000, /* A script was interrupted in some way. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Debugger
        ///////////////////////////////////////////////////////////////////////////////////////////

#if DEBUGGER
        /// <summary>
        /// A breakpoint is about to be triggered.
        /// </summary>
        PreBreakpoint = 0x800000000,  /* A breakpoint is about to be triggered. */
        /// <summary>
        /// A breakpoint was triggered.
        /// </summary>
        Breakpoint = 0x1000000000,    /* A breakpoint was triggered. */
        /// <summary>
        /// A variable watch breakpoint is about to be triggered.
        /// </summary>
        PreWatchpoint = 0x2000000000, /* A variable watch breakpoint is about to be triggered. */
        /// <summary>
        /// A variable watch breakpoint was triggered.
        /// </summary>
        Watchpoint = 0x4000000000,    /* A variable watch breakpoint was triggered. */
#endif

        /// <summary>
        /// A variable trace breakpoint was triggered.
        /// </summary>
        Trace = 0x8000000000,         /* A variable trace breakpoint was triggered. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Asynchronous Events
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// An asynchronous event has been queued to the interpreter.
        /// </summary>
        Queued = 0x10000000000,    /* An asynchronous event has been queued to the interpreter. */
        /// <summary>
        /// An asynchronous event has been dequeued from the interpreter.
        /// </summary>
        Dequeued = 0x20000000000,  /* An asynchronous event has been dequeued from the interpreter. */
        /// <summary>
        /// An asynchronous event has been discarded by the interpreter.
        /// </summary>
        Discarded = 0x40000000000, /* An asynchronous event has been discarded by the interpreter. */
        /// <summary>
        /// All asynchronous events have been cleared for the interpreter.
        /// </summary>
        Cleared = 0x80000000000,   /* All asynchronous events have been cleared for the interpreter. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Input/Output Events
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Data has been read.
        /// </summary>
        Read = 0x100000000000,     /* Data has been read. */
        /// <summary>
        /// Data has been written.
        /// </summary>
        Write = 0x200000000000,    /* Data has been written. */

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Tcl Variable Events
        ///////////////////////////////////////////////////////////////////////////////////////////

#if NATIVE && TCL
        /// <summary>
        /// The value of a Tcl variable was fetched.
        /// </summary>
        GetVariable = 0x400000000000,    /* The Tcl variable value was fetched. */
        /// <summary>
        /// A Tcl variable was set.
        /// </summary>
        SetVariable = 0x800000000000,    /* A Tcl variable was set. */
        /// <summary>
        /// A Tcl variable was unset.
        /// </summary>
        UnsetVariable = 0x1000000000000, /* A Tcl variable was unset. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Load/Unload Events
        ///////////////////////////////////////////////////////////////////////////////////////////

#if NOTIFY
        /// <summary>
        /// A plugin or other loadable module is about to be loaded.
        /// </summary>
        PreLoad = 0x2000000000000,   /* A plugin or other loadable module is about to be loaded. */
        /// <summary>
        /// A plugin or other loadable module is about to be unloaded.
        /// </summary>
        PreUnload = 0x4000000000000, /* A plugin or other loadable module is about to be unloaded. */
        /// <summary>
        /// A plugin or other loadable module has been loaded.
        /// </summary>
        Load = 0x8000000000000,      /* A plugin or other loadable module has been loaded. */
        /// <summary>
        /// A plugin or other loadable module has been unloaded.
        /// </summary>
        Unload = 0x10000000000000,   /* A plugin or other loadable module has been unloaded. */
#endif

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Masks
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Mask of the bits reserved for flags, including <see
        /// cref="Invalid" />, <see cref="Hidden" />, <see cref="Force" />,
        /// <see cref="Broadcast" />, and <see cref="Safe" />.
        /// </summary>
        FlagsMask = Invalid |

#if NOTIFY || NOTIFY_OBJECT
                    NoNotify |
#endif

                    Hidden | Force | Broadcast | Safe,

        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Mask used when validating notification flags; equal to <see
        /// cref="All" />.
        /// </summary>
        CheckMask = All,

        ///////////////////////////////////////////////////////////////////////////////////////////
        // All
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// Combination mask of all of the notification event flags,
        /// ranging from <see cref="Reset" /> through the load and unload
        /// events.
        /// </summary>
        All = Reset |
              PreInitialized |
              Setup |
              Initialized |
              Terminated |
              Exit |
              Matched |
              NotFound |
              Executed |
              Exception |
              Added |
              Copied |
              Renamed |
              Updated |
              Replaced |
              Removed |
              Pushed |
              Popped |
              Deleted |
              Disposed |
              Substituted |
              Evaluated |
              Completed |
              PreCanceled |
              Canceled |
              Unwound |
              PreHalted |
              Halted |

#if DEBUGGER
              PreBreakpoint |
              Breakpoint |
              PreWatchpoint |
              Watchpoint |
#endif

              Trace |
              Queued |
              Dequeued |
              Discarded |
              Cleared |
              Read |
              Write |

#if NOTIFY
              PreLoad |
              PreUnload |
              Load |
              Unload |
#endif

              None,

        ///////////////////////////////////////////////////////////////////////////////////////////
        // Reserved
        ///////////////////////////////////////////////////////////////////////////////////////////

        /// <summary>
        /// A reserved value that should not be used.
        /// </summary>
        Reserved = 0x8000000000000000 /* Reserved value, do not use. */
    }
#endif

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies how a particular version of a package should
    /// be selected when more than one version is available for loading.  It
    /// controls whether the latest version, the latest stable version, or some
    /// default policy is used to resolve the package request.
    /// </summary>
    [ObjectId("6b6288ac-4c47-45e6-bea1-8a54b072aea3")]
    public enum PackagePreference
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized package
        /// preference; callers should not use this value.
        /// </summary>
        Invalid = -1,  /* invalid, do not use. */
        /// <summary>
        /// No package preference handling has been specified; this value is
        /// reserved and should not be used.
        /// </summary>
        None = 0x0,    /* handling is unspecified, do not use. */
        /// <summary>
        /// No specific preference is expressed; the default package selection
        /// handling should be used.
        /// </summary>
        Default = 0x1, /* no specific preference, use default handling. */
        /// <summary>
        /// Always favor the very latest version of the package, even if that
        /// version is an alpha or beta release.
        /// </summary>
        Latest = 0x2,  /* always favor the VERY latest package version, even if alpha or beta. */
        /// <summary>
        /// Always favor the latest stable (non-alpha, non-beta) version of the
        /// package.
        /// </summary>
        Stable = 0x4   /* always favor the latest stable version. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies how the body of an XML script block should
    /// be interpreted, i.e. whether its content is plain text, Base64-encoded
    /// data, a URI that locates the actual content, or should be detected
    /// automatically.
    /// </summary>
    [ObjectId("7ef0e3e3-d336-4a9f-baf1-69c2553f69d3")]
    public enum XmlBlockType
    {
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized XML block
        /// type; callers should not use this value.
        /// </summary>
        Invalid = -1,
        /// <summary>
        /// No XML block type has been specified.
        /// </summary>
        None = 0,
        /// <summary>
        /// The type of the XML block content should be detected automatically.
        /// </summary>
        Automatic = 1,
        /// <summary>
        /// The XML block content is plain, literal text.
        /// </summary>
        Text = 2,
        /// <summary>
        /// The XML block content is Base64-encoded data that must be decoded
        /// before use.
        /// </summary>
        Base64 = 3,
        /// <summary>
        /// The XML block content is a URI that locates the actual content to be
        /// used.
        /// </summary>
        Uri = 4
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration specifies which kinds of token substitution should be
    /// performed when processing a script or string -- backslash sequences,
    /// variable references, and embedded command invocations.  Since this is a
    /// bit flags enumeration, its values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("acdb88e0-517b-4dd1-8b95-cb81ebf0dcae")]
    public enum SubstitutionFlags
    {
        /// <summary>
        /// No flags are set; no substitution should be performed.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized set of
        /// substitution flags; callers should not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// Perform backslash sequence substitution.
        /// </summary>
        Backslashes = 0x2,
        /// <summary>
        /// Perform variable reference substitution.
        /// </summary>
        Variables = 0x4,
        /// <summary>
        /// Perform embedded command substitution.
        /// </summary>
        Commands = 0x8,

        /// <summary>
        /// Combination mask of <see cref="Backslashes" />,
        /// <see cref="Variables" />, and <see cref="Commands" /> that enables
        /// all kinds of substitution.
        /// </summary>
        All = Backslashes | Variables | Commands,
        /// <summary>
        /// The default set of substitution flags, equal to <see cref="All" />.
        /// </summary>
        Default = All
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration controls how expressions are processed by the
    /// expression engine, including which substitution and mathematical
    /// features are enabled and how boolean and string operands are coerced to
    /// integers.  Since this is a bit flags enumeration, its values may be
    /// combined.
    /// </summary>
    [Flags()]
    [ObjectId("d9f761f8-bfd1-4102-819a-0e583609c45f")]
    public enum ExpressionFlags
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized set of
        /// expression flags; callers should not use this value.
        /// </summary>
        Invalid = 0x1,

#if EXPRESSION_FLAGS
        /// <summary>
        /// Enable backslash sequence substitution within expressions.
        /// </summary>
        Backslashes = 0x2,
        /// <summary>
        /// Enable variable reference substitution within expressions.
        /// </summary>
        Variables = 0x4,
        /// <summary>
        /// Enable embedded command substitution within expressions.
        /// </summary>
        Commands = 0x8,
        /// <summary>
        /// Enable the use of operators within expressions.
        /// </summary>
        Operators = 0x10,
        /// <summary>
        /// Enable the use of functions within expressions.
        /// </summary>
        Functions = 0x20,
#endif

        /// <summary>
        /// Permit boolean operands to be converted to integer values.
        /// </summary>
        BooleanToInteger = 0x40,
        /// <summary>
        /// Permit string operands to be converted to integer values.
        /// </summary>
        StringToInteger = 0x80,

#if EXPRESSION_FLAGS
        /// <summary>
        /// Combination mask of <see cref="Backslashes" />,
        /// <see cref="Variables" />, and <see cref="Commands" /> that enables
        /// all forms of substitution within expressions.
        /// </summary>
        Substitutions = Backslashes | Variables | Commands,
        /// <summary>
        /// Combination mask of <see cref="Operators" /> and
        /// <see cref="Functions" /> that enables all mathematical features
        /// within expressions.
        /// </summary>
        Mathematics = Operators | Functions,
        /// <summary>
        /// Combination mask of <see cref="Substitutions" /> and
        /// <see cref="Mathematics" /> that enables all expression features.
        /// </summary>
        All = Substitutions | Mathematics,
#else
        /// <summary>
        /// When the extended expression flags are not compiled in, this is
        /// equal to <see cref="None" />.
        /// </summary>
        All = None,
#endif

        /// <summary>
        /// The default set of expression flags, equal to <see cref="All" />.
        /// </summary>
        Default = All
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration defines the flags that control the behavior of the
    /// TclTk script engine while it evaluates, substitutes, and reads scripts.
    /// The flags govern entity lookup, hidden command handling, stack and
    /// readiness checking, policy and cancellation enforcement, error handling,
    /// caching, and numerous related behaviors.  Since this is a bit flags
    /// enumeration, its values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("7f46620d-7f45-469b-a4e7-6bbcd644aeee")]
    public enum EngineFlags : ulong
    {
        /// <summary>
        /// No flags are set; the default engine behavior is used.
        /// </summary>
        None = 0x0,                             /* Default flags (i.e. none). */
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized set of
        /// engine flags; callers should not use this value.
        /// </summary>
        Invalid = 0x1,                          /* Invalid, do not use. */
        /// <summary>
        /// The current command should be terminated by a close bracket.
        /// </summary>
        BracketTerminator = 0x2,                /* Current command should be
                                                 * terminated by a close bracket. */
        /// <summary>
        /// Use <c>IExecute</c> objects during evaluation.
        /// </summary>
        UseIExecutes = 0x4,                     /* Use IExecute objects during
                                                 * evaluation? */
        /// <summary>
        /// Use <c>ICommand</c> objects during evaluation.
        /// </summary>
        UseCommands = 0x8,                      /* Use ICommand objects during
                                                 * evaluation? */
        /// <summary>
        /// Use <c>IProcedure</c> objects during evaluation.
        /// </summary>
        UseProcedures = 0x10,                   /* Use IProcedure objects during
                                                 * evaluation? */
        /// <summary>
        /// Use the list of hidden <c>IExecute</c>, <c>ICommand</c>, or
        /// <c>IProcedure</c> entities.
        /// </summary>
        UseHidden = 0x20,                       /* Use the list of hidden IExecute,
                                                 * ICommand, or IProcedure entities. */
        /// <summary>
        /// An entity is being looked up so that it can be executed (via the
        /// <c>IExecute</c> interface).  This flag is for use by the engine only.
        /// </summary>
        ToExecute = 0x40,                       /* We are looking up an entity to
                                                 * execute it (via the IExecute
                                                 * interface).  This flag is for
                                                 * use by the Engine class only. */
        /// <summary>
        /// Do not match non-exact command and procedure names.
        /// </summary>
        ExactMatch = 0x80,                      /* Do not match non-exact command
                                                 * and procedure names? */
        /// <summary>
        /// Allow fetching of hidden commands and/or procedures.
        /// </summary>
        GetHidden = 0x100,                      /* Allow fetching of hidden
                                                 * commands and/or procedures? */
        /// <summary>
        /// Allow matching of hidden commands and/or procedures.
        /// </summary>
        MatchHidden = 0x200,                    /* Allow matching of hidden
                                                 * commands and/or procedures? */
        /// <summary>
        /// Totally ignore the hidden command and procedure flags.
        /// </summary>
        IgnoreHidden = 0x400,                   /* Totally ignore the hidden
                                                 * command/procedure flags? */
        /// <summary>
        /// Allow execution of hidden commands and/or procedures.
        /// </summary>
        InvokeHidden = 0x800,                   /* Allow execution of hidden
                                                 * commands and/or procedures? */
        /// <summary>
        /// Enable native stack space checking during interpreter readiness
        /// checks.
        /// </summary>
        CheckStack = 0x1000,                    /* Enable stack space checking
                                                 * during interpreter readiness
                                                 * checks? */
        /// <summary>
        /// Force native stack space checking during interpreter readiness
        /// checks.
        /// </summary>
        ForceStack = 0x2000,                    /* Force stack space checking
                                                 * during interpreter readiness
                                                 * checks? */
        /// <summary>
        /// Check native stack space for thread pool threads as well.
        /// </summary>
        ForcePoolStack = 0x4000,                /* Check native stack space for
                                                 * thread pool threads as well. */
        /// <summary>
        /// The engine should never read past a "soft" end-of-file, even when
        /// policy checking is enabled.
        /// </summary>
        ForceSoftEof = 0x8000,                  /* The engine should never read
                                                 * past a "soft" end-of-file,
                                                 * even with policy checking
                                                 * enabled. */
        /// <summary>
        /// Do not fall back on the <c>unknown</c> command or procedure for
        /// unknown commands.
        /// </summary>
        NoUnknown = 0x10000,                    /* Do not fallback on the
                                                 * "unknown" command/procedure
                                                 * for unknown commands? */
        /// <summary>
        /// Skip script cancellation checking during interpreter readiness
        /// checks.
        /// </summary>
        NoCancel = 0x20000,                     /* Skip script cancellation
                                                 * checking during interpreter
                                                 * readiness checks? */
        /// <summary>
        /// Disable interpreter readiness checks.
        /// </summary>
        NoReady = 0x40000,                      /* Disable interpreter
                                                 * readiness checks? */
        /// <summary>
        /// Disable all policy checking within the script engine.
        /// </summary>
        NoPolicy = 0x80000,                     /* Disable all policy checking
                                                 * within the script engine? */
#if DEBUGGER
        /// <summary>
        /// Disable all debugger breakpoints.
        /// </summary>
        NoBreakpoint = 0x100000,                /* Disable all debugger
                                                 * breakpoints? */
        /// <summary>
        /// Disable all variable watches (watchpoints).
        /// </summary>
        NoWatchpoint = 0x200000,                /* Disable all variable
                                                 * watches? */
#endif
        /// <summary>
        /// Disable all asynchronous event processing.
        /// </summary>
        NoEvent = 0x400000,                     /* Disable all asynchronous
                                                 * event processing? */
        /// <summary>
        /// Totally disable all script evaluation.
        /// </summary>
        NoEvaluate = 0x800000,                  /* Totally disable all script
                                                 * evaluation? */
        /// <summary>
        /// Totally disable all token substitution.
        /// </summary>
        NoSubstitute = 0x1000000,               /* Totally disable all token
                                                 * substitution? */
        /// <summary>
        /// Skip resetting the interpreter result.
        /// </summary>
        NoResetResult = 0x2000000,              /* Skip resetting the
                                                 * interpreter result? */
        /// <summary>
        /// Skip resetting the error-related engine flags.
        /// </summary>
        NoResetError = 0x4000000,               /* Skip resetting the error
                                                 * related engine flags? */
        /// <summary>
        /// Indicates that the script cancellation flag should be forcibly
        /// reset.
        /// </summary>
        ResetCancel = 0x8000000,                /* Used to determine if the
                                                 * cancel flag should be
                                                 * forcibly reset. */
        /// <summary>
        /// Indicates that the last return code should be forcibly reset.
        /// </summary>
        ResetReturnCode = 0x10000000,           /* Used to determine if the
                                                 * last return code should
                                                 * be forcibly reset. */
        /// <summary>
        /// Evaluate the script in the global scope without regard to the
        /// current scope.
        /// </summary>
        EvaluateGlobal = 0x20000000,            /* Evaluate script in the
                                                 * global scope without regard
                                                 * to the current scope? */
        /// <summary>
        /// Error information is being logged as the call stack unwinds.
        /// </summary>
        ErrorInProgress = 0x40000000,           /* Error information is being
                                                 * logged as the stack unwinds. */
        /// <summary>
        /// Error information has already been logged for the current call.
        /// </summary>
        ErrorAlreadyLogged = 0x80000000,        /* Error information has
                                                 * already been logged for the
                                                 * current call. */
        /// <summary>
        /// The error code has been set for the current call.
        /// </summary>
        ErrorCodeSet = 0x100000000,             /* Error code has been set for
                                                 * the current call. */
#if NOTIFY || NOTIFY_OBJECT
        /// <summary>
        /// Disable all notifications for the script.
        /// </summary>
        NoNotify = 0x200000000,                 /* Disable all notifications
                                                 * for the script? */
#endif
#if HISTORY
        /// <summary>
        /// Disable command history for the script.
        /// </summary>
        NoHistory = 0x400000000,                /* Disable command history
                                                 * for the script? */
#endif
#if CALLBACK_QUEUE
        /// <summary>
        /// Disable the evaluation engine callback queue.
        /// </summary>
        NoCallbackQueue = 0x800000000,          /* Disable the evaluation
                                                 * engine callback queue? */
#endif
        /// <summary>
        /// The script is being evaluated by an interactive user.
        /// </summary>
        Interactive = 0x1000000000,             /* Script is being evaluated
                                                 * by an interactive user? */
        /// <summary>
        /// Do not fall back on using a matching host script.
        /// </summary>
        NoHost = 0x2000000000,                  /* Do not fallback on using a
                                                 * matching host script? */
        /// <summary>
        /// Disallow evaluating remote script files.
        /// </summary>
        NoRemote = 0x4000000000,                /* Disallow evaluating remote
                                                 * script files? */
#if XML
        /// <summary>
        /// Disable auto-detection and evaluation of scripts that conform to the
        /// TclTk XML schema.
        /// </summary>
        NoXml = 0x8000000000,                   /* Disable auto-detection and
                                                 * evaluation of scripts that
                                                 * conform to our XML schema?
                                                 */
#endif
        /// <summary>
        /// Only consider thread-local script cancellation flags.
        /// </summary>
        NoGlobalCancel = 0x10000000000,         /* Only consider thread-local
                                                 * script cancellation flags.
                                                 */
        /// <summary>
        /// Allow all functions to be executed in safe interpreters, including
        /// those that are not marked as "safe".
        /// </summary>
        NoSafeFunction = 0x20000000000,         /* Allow all functions to be
                                                 * executed in safe interpreters,
                                                 * include those that are NOT
                                                 * marked as "safe". */
        /// <summary>
        /// An external execution context is active and still needs to be
        /// removed.
        /// </summary>
        ExternalExecution = 0x40000000000,      /* An external execution context
                                                 * is active and still needs to
                                                 * be removed. */
#if DEBUGGER && DEBUGGER_ARGUMENTS
        /// <summary>
        /// Skip setting the command name and arguments for use by the debugger.
        /// </summary>
        NoDebuggerArguments = 0x80000000000,    /* Skip setting the command name
                                                 * and arguments for use by the
                                                 * debugger. */
#endif
        /// <summary>
        /// Skip looking up executable entities (e.g. commands, procedures, etc)
        /// in the cache.
        /// </summary>
        NoCache = 0x100000000000,               /* Skip looking up executable
                                                 * entities in the cache (e.g.
                                                 * commands, procedures, etc). */
        /// <summary>
        /// Force the command to be looked up in the global namespace.
        /// </summary>
        GlobalOnly = 0x200000000000,            /* Force command to be looked
                                                 * up in the global namespace. */
        /// <summary>
        /// When applicable, combine these engine flags with the ones from the
        /// provided interpreter.
        /// </summary>
        UseInterpreter = 0x400000000000,        /* When applicable, combine
                                                 * engine flags with the
                                                 * ones from the provided
                                                 * interpreter. */
        /// <summary>
        /// Force extra <c>BeforeScript</c> policy checks in the
        /// <c>ReadScriptStream</c> and <c>ReadScriptFile</c> methods due to
        /// being passed an external <c>IScript</c>.
        /// </summary>
        ExternalScript = 0x800000000000,        /* Force extra BeforeScript
                                                 * policy checks in the
                                                 * ReadScriptStream and
                                                 * ReadScriptFile methods
                                                 * due to being passed an
                                                 * external IScript. */
        /// <summary>
        /// The engine should push and pop an "extra" call frame when processing
        /// within the <c>EvaluateStream</c>, <c>EvaluateFile</c>,
        /// <c>SubstituteStream</c>, and <c>SubstituteFile</c> methods.
        /// </summary>
        ExtraCallFrame = 0x1000000000000,       /* The engine should push and
                                                 * pop an "extra" call frame
                                                 * when processing within the
                                                 * EvaluateStream, EvaluateFile,
                                                 * SubstituteStream, and
                                                 * SubstituteFile methods.
                                                 */
#if TEST
        /// <summary>
        /// The engine should automatically set up the necessary remote URI
        /// security protocols.
        /// </summary>
        SetSecurityProtocol = 0x2000000000000,  /* The engine should automatically
                                                 * setup the necessary remote URI
                                                 * security protocols. */
#endif
        /// <summary>
        /// Allow searching alternate file names even when the original file name
        /// was a fully qualified path.
        /// </summary>
        IgnoreRootedFileName = 0x4000000000000, /* Allow searching alternate
                                                 * file names even when the
                                                 * original file name was a
                                                 * fully qualified path.
                                                 * COMPAT: TclTk beta. */
        /// <summary>
        /// Disallow use of <c>Path.GetFileName</c> by the engine.
        /// </summary>
        NoFileNameOnly = 0x8000000000000,       /* Disallow use of
                                                 * Path.GetFileName by the
                                                 * Engine class. */
        /// <summary>
        /// Disallow use of raw names by the engine.
        /// </summary>
        NoRawName = 0x10000000000000,           /* Disallow use of raw names
                                                 * by the Engine class. */
        /// <summary>
        /// Return all errors seen while trying to locate a script file to
        /// evaluate.
        /// </summary>
        AllErrors = 0x20000000000000,           /* Return all errors seen
                                                 * while trying to locate a
                                                 * script [file?] to evaluate. */
        /// <summary>
        /// Return the detailed error (if possible) that is seen while trying to
        /// locate a script file to evaluate.
        /// </summary>
        NoDefaultError = 0x40000000000000,      /* Return the detailed error
                                                 * (if possible) that is seen
                                                 * while trying to locate a
                                                 * script [file?] to evaluate. */
#if PARSE_CACHE
        /// <summary>
        /// EXPERIMENTAL: Prevent the engine from caching <c>ParseState</c>
        /// object instances.  This flag may be removed in later releases.
        /// </summary>
        NoCacheParseState = 0x80000000000000,   /* EXPERIMENTAL: Prevent the
                                                 * engine from caching
                                                 * ParseState object instances.
                                                 * This flag may be removed in
                                                 * later releases. */
#endif
#if ARGUMENT_CACHE
        /// <summary>
        /// EXPERIMENTAL: Prevent the engine from caching <c>Argument</c> object
        /// instances.  This flag may be removed in later releases.
        /// </summary>
        NoCacheArgument = 0x100000000000000,    /* EXPERIMENTAL: Prevent the
                                                 * engine from caching Argument
                                                 * object instances.  This flag
                                                 * may be removed in later
                                                 * releases. */
#endif
        /// <summary>
        /// When reading a script file, also read the post-script bytes after the
        /// current "soft" end-of-file character.
        /// </summary>
        PostScriptBytes = 0x200000000000000,    /* When reading a script file,
                                                 * also read the post-script
                                                 * bytes after the current
                                                 * "soft" end-of-file
                                                 * character. */
        /// <summary>
        /// The engine should seek to the next "soft" end-of-file prior to
        /// reading post-script bytes from a stream.
        /// </summary>
        SeekSoftEof = 0x400000000000000,        /* The engine should seek to
                                                 * the next "soft" end-of-file,
                                                 * prior to reading post-script
                                                 * bytes from a stream. */
        /// <summary>
        /// Do not keep track of usage data for executable entities.
        /// </summary>
        NoUsageData = 0x800000000000000,        /* Do not keep track of usage
                                                 * data for executable entities.
                                                 */
        /// <summary>
        /// Do not use a null command result to create an argument to pass to a
        /// subsequent command.
        /// </summary>
        NoNullArgument = 0x1000000000000000,    /* Do not use a null command
                                                 * result to create an argument
                                                 * to pass to a subsequent
                                                 * command. */
        /// <summary>
        /// Do not use <c>Thread.ResetAbort</c> when an engine thread is aborted
        /// via <c>Thread.Abort</c>.
        /// </summary>
        NoResetAbort = 0x2000000000000000,      /* Do not use Thread.ResetAbort
                                                 * when an engine thread is
                                                 * aborted via Thread.Abort. */
#if PREVIOUS_RESULT
        /// <summary>
        /// Skip all "previous result" handling within the script engine.
        /// </summary>
        NoPreviousResult = 0x4000000000000000,  /* Skip all "previous result"
                                                 * handling within the script
                                                 * engine. */
#endif

        //
        // NOTE: This is used to help with the -package option to
        //       the [interp readorgetscriptfile] sub-command.
        //
        /// <summary>
        /// Combination mask of <see cref="NoFileNameOnly" /> and
        /// <see cref="NoRawName" /> used to help with the <c>-package</c> option
        /// to the <c>[interp readorgetscriptfile]</c> sub-command.
        /// </summary>
        PackageMask = NoFileNameOnly | NoRawName,

        //
        // NOTE: Stack checking related engine flags.
        //
        /// <summary>
        /// Combination mask of <see cref="CheckStack" /> and
        /// <see cref="ForcePoolStack" /> covering the basic stack-checking
        /// engine flags.
        /// </summary>
        BaseStackMask = CheckStack | ForcePoolStack,
        /// <summary>
        /// Combination mask of <see cref="CheckStack" />,
        /// <see cref="ForceStack" />, and <see cref="ForcePoolStack" /> covering
        /// the full set of stack-checking engine flags.
        /// </summary>
        FullStackMask = CheckStack | ForceStack | ForcePoolStack,

        //
        // NOTE: For use by the EvaluatePromptScript method only.
        //
        /// <summary>
        /// Combination mask used by the <c>EvaluatePromptScript</c> method only.
        /// </summary>
        ForPromptMask = NoCancel
#if DEBUGGER
            | NoDebuggerMask
#endif
            ,

        //
        // NOTE: Engine flags allowed for use with [interp readorgetscriptfile]
        //       sub-command.
        //
        /// <summary>
        /// Combination mask of the engine flags that are allowed for use with
        /// the <c>[interp readorgetscriptfile]</c> sub-command.
        /// </summary>
        ReadOrGetScriptFileMask = ForceSoftEof | NoPolicy | NoNotify |
                                  NoHost | NoRemote |
#if XML
                                  NoXml |
#endif
                                  ExternalScript | NoFileNameOnly | NoRawName |
                                  AllErrors | NoDefaultError,

#if DEBUGGER
        //
        // NOTE: Used when evaluating an interpreter or shell startup script
        //       in the debugger.
        //
        /// <summary>
        /// Combination mask of <see cref="NoBreakpoint" /> and
        /// <see cref="NoWatchpoint" /> used when evaluating an interpreter or
        /// shell startup script in the debugger.
        /// </summary>
        NoDebuggerMask = NoBreakpoint | NoWatchpoint,
#endif

        //
        // HACK: Enable this mask to make the script engine run at maximum
        //       speed (i.e. and sacrificing any extra features in order to
        //       do so).
        //
        /// <summary>
        /// Combination mask that makes the script engine run at maximum speed,
        /// sacrificing any extra features in order to do so.
        /// </summary>
        FastMask = NoReady |
#if DEBUGGER
                   NoDebuggerMask |
#endif
#if DEBUGGER && DEBUGGER_ARGUMENTS
                   NoDebuggerArguments |
#endif
#if NOTIFY || NOTIFY_OBJECT
                   NoNotify |
#endif
#if CALLBACK_QUEUE
                   NoCallbackQueue |
#endif
#if ARGUMENT_CACHE
                   NoCacheArgument |
#endif
                   NoUsageData |
#if PREVIOUS_RESULT
                   NoPreviousResult |
#endif
                   None,

        //
        // NOTE: When looking up entities to execute, use all available entity
        //       types.
        //
        /// <summary>
        /// Combination mask of <see cref="UseCommands" />,
        /// <see cref="UseProcedures" />, and <see cref="UseIExecutes" /> that
        /// uses all available entity types when looking up entities to execute.
        /// </summary>
        UseAllMask = UseCommands | UseProcedures | UseIExecutes,

        //
        // NOTE: All the error handling related flags.
        //
        /// <summary>
        /// Combination mask of <see cref="ErrorInProgress" />,
        /// <see cref="ErrorAlreadyLogged" />, and <see cref="ErrorCodeSet" />
        /// covering all the error-handling related flags.
        /// </summary>
        ErrorMask = ErrorInProgress | ErrorAlreadyLogged | ErrorCodeSet,

        //
        // NOTE: All enabled/disabled related flags.
        //
        /// <summary>
        /// Combination mask of <see cref="NoEvaluate" /> and
        /// <see cref="NoSubstitute" /> covering all the enabled/disabled related
        /// flags.
        /// </summary>
        EnabledMask = NoEvaluate | NoSubstitute,

        //
        // NOTE: For use by the HaveScriptFlags class only.  Do not use.
        //
        /// <summary>
        /// For use by the <c>HaveScriptFlags</c> class only; equal to
        /// <see cref="Reserved" />.  Do not use.
        /// </summary>
        Default = Reserved,

        //
        // NOTE: The high-bit is reserved, please do not use it.
        //
        /// <summary>
        /// The high-bit is reserved; this value should not be used.
        /// </summary>
        Reserved = 0x8000000000000000 /* Reserved value, do not use. */
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration classifies a character according to its syntactic role
    /// during script parsing, e.g. whitespace, a command terminator, the start
    /// of a substitution, a quote, or a closing delimiter.  Since this is a bit
    /// flags enumeration, its values may be combined.
    /// </summary>
    [Flags()]
    [ObjectId("6572cb04-c5c9-48ff-b0e1-60ace408f8cb")]
    public enum CharacterType
    {
        /// <summary>
        /// No flags are set.
        /// </summary>
        None = 0x0,
        /// <summary>
        /// A reserved sentinel indicating an invalid or uninitialized character
        /// type; callers should not use this value.
        /// </summary>
        Invalid = 0x1,
        /// <summary>
        /// A normal character with no special syntactic meaning; equal to
        /// <see cref="None" />.
        /// </summary>
        Normal = None,
        /// <summary>
        /// A whitespace (space) character.
        /// </summary>
        Space = 0x2,
        /// <summary>
        /// A character that terminates the current command.
        /// </summary>
        CommandTerminator = 0x4,
        /// <summary>
        /// A character that introduces a substitution.
        /// </summary>
        Substitution = 0x8,
        /// <summary>
        /// A quotation mark character.
        /// </summary>
        Quote = 0x10,
        /// <summary>
        /// A closing parenthesis character.
        /// </summary>
        CloseParenthesis = 0x20,
        /// <summary>
        /// A closing bracket character.
        /// </summary>
        CloseBracket = 0x40,
        /// <summary>
        /// A brace character.
        /// </summary>
        Brace = 0x80
    }

    ///////////////////////////////////////////////////////////////////////////////////////////////

    /// <summary>
    /// This enumeration identifies the individual lexical tokens (lexemes)
    /// recognized by the expression parser, including literals, identifiers,
    /// grouping delimiters, and the full set of unary, binary numeric, string,
    /// list, and assignment operators.
    /// </summary>
    [ObjectId("ce29fc68-cc0d-4eb1-98c6-7d02b6d0bbd5")]
    public enum Lexeme
    {
        /*
         * Basic lexemes:
         */

        /// <summary>
        /// An unknown or unrecognized lexeme.
        /// </summary>
        Unknown,
        /// <summary>
        /// An unknown or unrecognized character.
        /// </summary>
        UnknownCharacter,
        /// <summary>
        /// A literal value.
        /// </summary>
        Literal,
        /// <summary>
        /// An identifier name.
        /// </summary>
        IdentifierName,
        /// <summary>
        /// An opening bracket (<c>[</c>).
        /// </summary>
        OpenBracket,
        /// <summary>
        /// An opening brace (<c>{</c>).
        /// </summary>
        OpenBrace,
        /// <summary>
        /// An opening parenthesis (<c>(</c>).
        /// </summary>
        OpenParenthesis,
        /// <summary>
        /// A closing parenthesis (<c>)</c>).
        /// </summary>
        CloseParenthesis,
        /// <summary>
        /// A dollar sign (<c>$</c>), used to introduce a variable reference.
        /// </summary>
        DollarSign,
        /// <summary>
        /// A quotation mark (<c>"</c>).
        /// </summary>
        QuotationMark,
        /// <summary>
        /// A comma (<c>,</c>).
        /// </summary>
        Comma,
        /// <summary>
        /// The end of the input.
        /// </summary>
        End,

        /*
         * Binary numeric operators:
         */

        /// <summary>
        /// The exponentiation operator (<c>**</c>).
        /// </summary>
        Exponent,
        /// <summary>
        /// The multiplication operator (<c>*</c>).
        /// </summary>
        Multiply,
        /// <summary>
        /// The division operator (<c>/</c>).
        /// </summary>
        Divide,
        /// <summary>
        /// The modulus (remainder) operator (<c>%</c>).
        /// </summary>
        Modulus,

        /// <summary>
        /// The addition operator (<c>+</c>); also used as the unary plus
        /// operator.
        /// </summary>
        Plus,  // NOTE: Also unary.
        /// <summary>
        /// The subtraction operator (<c>-</c>); also used as the unary minus
        /// operator.
        /// </summary>
        Minus, // NOTE: Also unary.

        /// <summary>
        /// The left shift operator (<c>&lt;&lt;</c>).
        /// </summary>
        LeftShift,
        /// <summary>
        /// The right shift operator (<c>&gt;&gt;</c>).
        /// </summary>
        RightShift,
        /// <summary>
        /// The left rotate operator.
        /// </summary>
        LeftRotate,
        /// <summary>
        /// The right rotate operator.
        /// </summary>
        RightRotate,

        /// <summary>
        /// The less-than comparison operator (<c>&lt;</c>).
        /// </summary>
        LessThan,
        /// <summary>
        /// The greater-than comparison operator (<c>&gt;</c>).
        /// </summary>
        GreaterThan,
        /// <summary>
        /// The less-than-or-equal-to comparison operator (<c>&lt;=</c>).
        /// </summary>
        LessThanOrEqualTo,
        /// <summary>
        /// The greater-than-or-equal-to comparison operator (<c>&gt;=</c>).
        /// </summary>
        GreaterThanOrEqualTo,

        /// <summary>
        /// The equality comparison operator (<c>==</c>).
        /// </summary>
        Equal,
        /// <summary>
        /// The inequality comparison operator (<c>!=</c>).
        /// </summary>
        NotEqual,

        /// <summary>
        /// The bitwise AND operator (<c>&amp;</c>).
        /// </summary>
        BitwiseAnd,
        /// <summary>
        /// The bitwise exclusive-OR operator (<c>^</c>).
        /// </summary>
        BitwiseXor,
        /// <summary>
        /// The bitwise OR operator (<c>|</c>).
        /// </summary>
        BitwiseOr,
        /// <summary>
        /// The bitwise equivalence operator.
        /// </summary>
        BitwiseEqv,
        /// <summary>
        /// The bitwise implication operator.
        /// </summary>
        BitwiseImp,

        /// <summary>
        /// The logical AND operator (<c>&amp;&amp;</c>).
        /// </summary>
        LogicalAnd,
        /// <summary>
        /// The logical exclusive-OR operator.
        /// </summary>
        LogicalXor,
        /// <summary>
        /// The logical OR operator (<c>||</c>).
        /// </summary>
        LogicalOr,
        /// <summary>
        /// The logical equivalence operator.
        /// </summary>
        LogicalEqv,
        /// <summary>
        /// The logical implication operator.
        /// </summary>
        LogicalImp,

        /*
         * The ternary "if" operator.
         */

        /// <summary>
        /// The question mark (<c>?</c>) of the ternary conditional operator.
        /// </summary>
        Question,
        /// <summary>
        /// The colon (<c>:</c>) of the ternary conditional operator.
        /// </summary>
        Colon,

        /*
         * Unary operators. Unary minus and plus are represented by the (binary)
         * lexemes "Minus" and "Plus" (above).
         */

        /// <summary>
        /// The logical NOT operator (<c>!</c>).
        /// </summary>
        LogicalNot,
        /// <summary>
        /// The bitwise NOT (complement) operator (<c>~</c>).
        /// </summary>
        BitwiseNot,

        /*
         * Binary string operators:
         */

        /// <summary>
        /// The string greater-than comparison operator.
        /// </summary>
        StringGreaterThan,
        /// <summary>
        /// The string greater-than-or-equal-to comparison operator.
        /// </summary>
        StringGreaterThanOrEqualTo,
        /// <summary>
        /// The string less-than comparison operator.
        /// </summary>
        StringLessThan,
        /// <summary>
        /// The string less-than-or-equal-to comparison operator.
        /// </summary>
        StringLessThanOrEqualTo,

        /// <summary>
        /// The string equality comparison operator (<c>eq</c>).
        /// </summary>
        StringEqual,
        /// <summary>
        /// The string inequality comparison operator (<c>ne</c>).
        /// </summary>
        StringNotEqual,

        /*
         * Binary list operators:
         */

        /// <summary>
        /// The list membership operator (<c>in</c>).
        /// </summary>
        ListIn,
        /// <summary>
        /// The list non-membership operator (<c>ni</c>).
        /// </summary>
        ListNotIn,

        /*
         * Binary assignment operators:
         */

        /// <summary>
        /// The variable assignment operator.
        /// </summary>
        VariableAssignment,

        /*
         * Operator value bounds:
         */

        /// <summary>
        /// The minimum lexeme value, equal to <see cref="Unknown" />.
        /// </summary>
        Minimum = Unknown,
        /// <summary>
        /// The maximum lexeme value, equal to <see cref="VariableAssignment" />.
        /// </summary>
        Maximum = VariableAssignment
    }
}
